if ( ! function_exists( 'quorlyx_normalize_active_plugins_option' ) ) {
	/**
	 * Normalizes active plugins option values into an array.
	 *
	 * @param mixed $value Raw active_plugins option value.
	 * @return array
	 */
	function quorlyx_normalize_active_plugins_option( $value ) {
		if ( is_array( $value ) ) {
			return $value;
		}

		if ( is_string( $value ) ) {
			$maybe_unserialized = maybe_unserialize( $value );
			if ( is_array( $maybe_unserialized ) ) {
				return $maybe_unserialized;
			}

			$trimmed = trim( $value );
			if ( '' === $trimmed ) {
				return array();
			}

			if ( false !== strpos( $trimmed, '.php' ) ) {
				$plugins = preg_split( '/[\s,]+/', $trimmed );
				$plugins = is_array( $plugins ) ? array_filter(
					array_map( 'trim', $plugins ),
					function ( $plugin ) {
						return is_string( $plugin ) && false !== strpos( $plugin, '.php' );
					}
				) : array();

				return array_values( $plugins );
			}
		}

		return array();
	}
}

if ( ! function_exists( 'quorlyx_normalize_sitewide_plugins_option' ) ) {
	/**
	 * Normalizes network active sitewide plugins option values into an array.
	 *
	 * @param mixed $value Raw active_sitewide_plugins option value.
	 * @return array
	 */
	function quorlyx_normalize_sitewide_plugins_option( $value ) {
		if ( is_array( $value ) ) {
			return $value;
		}

		if ( is_string( $value ) ) {
			$maybe_unserialized = maybe_unserialize( $value );
			if ( is_array( $maybe_unserialized ) ) {
				return $maybe_unserialized;
			}
		}

		return array();
	}
}

if ( ! function_exists( 'quorlyx_maybe_repair_active_plugins_option' ) ) {
	/**
	 * Repairs malformed active_plugins option values in the database.
	 *
	 * @return void
	 */
	function quorlyx_maybe_repair_active_plugins_option() {
		global $wpdb;

		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Legacy option repair must inspect the raw stored value before option filters normalize it.
		$raw_value = $wpdb->get_var(
			$wpdb->prepare(
				"SELECT option_value FROM {$wpdb->options} WHERE option_name = %s LIMIT 1",
				'active_plugins'
			)
		);

		if ( null === $raw_value ) {
			update_option( 'quorlyx_active_plugins_repair_checked', 1, false );
			return;
		}

		$maybe_unserialized = maybe_unserialize( $raw_value );
		if ( is_array( $maybe_unserialized ) ) {
			update_option( 'quorlyx_active_plugins_repair_checked', 1, false );
			return;
		}

		update_option( 'active_plugins', quorlyx_normalize_active_plugins_option( $raw_value ) );
		update_option( 'quorlyx_active_plugins_repair_checked', 1, false );
	}
}

