if ( ! function_exists( 'quorlyx_mask_secret_for_display' ) ) {
	/**
	 * Masks stored secrets before rendering admin forms.
	 *
	 * @param string $secret Secret value.
	 * @return string
	 */
	function quorlyx_mask_secret_for_display( $secret ) {
		$secret = trim( (string) $secret );
		$length = strlen( $secret );

		if ( 0 === $length ) {
			return '';
		}

		if ( $length <= 8 ) {
			return str_repeat( '*', max( 4, $length ) );
		}

		$mask_length = min( 12, max( 6, $length - 8 ) );

		return substr( $secret, 0, 4 ) . str_repeat( '*', $mask_length ) . substr( $secret, -4 );
	}
}

if ( ! function_exists( 'quorlyx_sanitize_secret_input' ) ) {
	/**
	 * Sanitizes a submitted secret while preserving the saved value when the field is blank.
	 *
	 * @param mixed  $input    Submitted value.
	 * @param string $fallback Existing value.
	 * @return string
	 */
	function quorlyx_sanitize_secret_input( $input, $fallback = '' ) {
		if ( ! is_scalar( $input ) ) {
			return sanitize_text_field( (string) $fallback );
		}

		$input = trim( (string) wp_unslash( $input ) );

		if ( '' === $input ) {
			return sanitize_text_field( (string) $fallback );
		}

		return sanitize_text_field( $input );
	}
}

if ( ! function_exists( 'quorlyx_get_plugin_asset_url' ) ) {
	/**
	 * Builds plugin asset URLs with the site's configured scheme.
	 *
	 * @param string $relative_path Plugin-relative asset path.
	 * @return string
	 */
	function quorlyx_get_plugin_asset_url( $relative_path ) {
		$relative_path = ltrim( (string) $relative_path, '/' );
		$url           = plugins_url( $relative_path, __FILE__ );
		$scheme        = wp_parse_url( home_url(), PHP_URL_SCHEME );

		if ( ! is_string( $scheme ) || '' === $scheme ) {
			$scheme = is_ssl() ? 'https' : 'http';
		}

		return set_url_scheme( $url, $scheme );
	}
}

if ( ! function_exists( 'quorlyx_admin_capability' ) ) {
	/**
	 * Returns the capability required to manage Quorlyx.
	 *
	 * @return string
	 */
	function quorlyx_admin_capability() {
		$capability = (string) apply_filters( 'quorlyx_admin_capability', QUORLYX_ADMIN_CAPABILITY );

		return '' !== $capability ? $capability : QUORLYX_ADMIN_CAPABILITY;
	}
}

if ( ! function_exists( 'quorlyx_grant_admin_capability' ) ) {
	/**
	 * Grants the Quorlyx admin capability to administrator roles.
	 *
	 * @return void
	 */
	function quorlyx_grant_admin_capability() {
		$capability = quorlyx_admin_capability();
		$role       = get_role( 'administrator' );
		if ( $role && empty( $role->capabilities[ $capability ] ) ) {
			$role->add_cap( $capability, true );
		}
	}
}

if ( ! function_exists( 'quorlyx_user_has_admin_capability' ) ) {
	/**
	 * Maps the plugin-specific admin capability to existing administrator access.
	 *
	 * @param array<string,bool> $allcaps All capabilities for the user.
	 * @param string[]           $caps    Primitive capabilities being checked.
	 * @param array              $args    Current capability check arguments.
	 * @param WP_User            $user    Current user object.
	 * @return array<string,bool>
	 */
	function quorlyx_user_has_admin_capability( $allcaps, $caps, $args, $user ) {
		$capability = quorlyx_admin_capability();
		if ( ! in_array( $capability, (array) $caps, true ) && ( $args[0] ?? '' ) !== $capability ) {
			return $allcaps;
		}

		if ( ! empty( $allcaps[ $capability ] ) ) {
			return $allcaps;
		}

		$user_id       = isset( $args[1] ) ? absint( $args[1] ) : 0;
		$is_super_user = $user_id && function_exists( 'is_super_admin' ) && is_super_admin( $user_id );
		$is_admin_role = is_object( $user ) && ! empty( $user->roles ) && in_array( 'administrator', (array) $user->roles, true );

		if ( $is_super_user || $is_admin_role || ! empty( $allcaps['manage_options'] ) ) {
			$allcaps[ $capability ] = true;
		}

		return $allcaps;
	}
}

if ( ! function_exists( 'quorlyx_current_user_can_manage' ) ) {
	/**
	 * Checks whether the current user can manage Quorlyx.
	 *
	 * @return bool
	 */
	function quorlyx_current_user_can_manage() {
		return current_user_can( quorlyx_admin_capability() );
	}
}

add_action( 'init', 'quorlyx_grant_admin_capability', 1 );
add_filter( 'user_has_cap', 'quorlyx_user_has_admin_capability', 10, 4 );
add_filter( 'option_page_capability_quorlyx_settings_group', 'quorlyx_admin_capability' );

if ( ! function_exists( 'quorlyx_get_current_site_domain' ) ) {
	/**
	 * Returns a normalized domain fingerprint for the current site.
	 *
	 * @return string
	 */
	function quorlyx_get_current_site_domain() {
		$site_url = home_url( '/' );
		$host     = strtolower( (string) wp_parse_url( $site_url, PHP_URL_HOST ) );
		$path     = trim( (string) wp_parse_url( $site_url, PHP_URL_PATH ), '/' );

		if ( '' === $host ) {
			return '';
		}

		$fingerprint = $host;
		if ( '' !== $path ) {
			$fingerprint .= '/' . $path;
		}

		return sanitize_text_field( $fingerprint );
	}
}

/**
 * Centralized runtime logger for Quorlyx admin and frontend events.
 */
class Quorlyx_Pro_Logger {
	/**
	 * Option name used to persist log entries.
	 *
	 * @var string
	 */
	private static $log_option_name = 'quorlyx_event_log';

	/**
	 * Maximum number of log entries to keep.
	 *
	 * @var int
	 */
	private static $max_log_entries = 1000;

	/**
	 * Previously registered PHP error handler.
	 *
	 * @var callable|array<string>|null
	 */
	private static $previous_error_handler = null;

	/**
	 * Previously registered PHP exception handler.
	 *
	 * @var callable|array<string>|null
	 */
	private static $previous_exception_handler = null;

	/**
	 * Register PHP/shutdown handlers for runtime diagnostics.
	 *
	 * @return void
	 */
	public static function init() {
		add_action( 'shutdown', array( __CLASS__, 'shutdown_handler' ) );
		if ( null === self::$previous_error_handler ) {
			// phpcs:ignore WordPress.PHP.DevelopmentFunctions.error_log_set_error_handler -- Intentional runtime diagnostics hook for plugin self-monitoring.
			self::$previous_error_handler = set_error_handler( array( __CLASS__, 'php_error_handler' ) );
		}
		if ( null === self::$previous_exception_handler ) {
			self::$previous_exception_handler = set_exception_handler( array( __CLASS__, 'exception_handler' ) );
		}
	}

	/**
	 * Check whether a file belongs to this plugin directory.
	 *
	 * @param string $file File path.
	 * @return bool
	 */
	private static function is_plugin_file( $file ) {
		$file        = wp_normalize_path( (string) $file );
		$plugin_root = wp_normalize_path( trailingslashit( __DIR__ ) );

		return '' !== $file && 0 === strpos( $file, $plugin_root );
	}

	/**
	 * Capture fatal errors on shutdown and persist them to the event log.
	 *
	 * @return void
	 */
	public static function shutdown_handler() {
		$error = error_get_last();
		if ( ! $error || ! in_array( $error['type'], array( E_ERROR, E_PARSE, E_CORE_ERROR, E_COMPILE_ERROR ), true ) ) {
			return;
		}

		$error_file = isset( $error['file'] ) ? (string) $error['file'] : '';
		if ( ! self::is_plugin_file( $error_file ) ) {
			return;
		}

		$error['error_type_name'] = self::php_error_type_to_name( (int) $error['type'] );
		self::log( 'critical', 'Fatal Error Detected', $error );
	}

	/**
	 * Handle recoverable PHP runtime errors and forward to the event log.
	 *
	 * @param int    $errno   PHP error number.
	 * @param string $errstr  PHP error message.
	 * @param string $errfile File path where the error occurred.
	 * @param int    $errline Line number where the error occurred.
	 * @return bool
	 */
	public static function php_error_handler( $errno, $errstr, $errfile, $errline ) {
		// phpcs:ignore WordPress.PHP.DevelopmentFunctions.prevent_path_disclosure_error_reporting,WordPress.PHP.DiscouragedPHPFunctions.runtime_configuration_error_reporting -- Checks current reporting mask only; does not change runtime config.
		if ( 0 === ( error_reporting() & (int) $errno ) ) {
			return self::call_previous_error_handler( $errno, $errstr, $errfile, $errline );
		}

		$file = (string) $errfile;
		if ( self::is_plugin_file( $file ) && ! in_array( (int) $errno, array( E_DEPRECATED, E_USER_DEPRECATED, E_NOTICE, E_USER_NOTICE ), true ) ) {
			$type = in_array( (int) $errno, array( E_WARNING, E_USER_WARNING ), true ) ? 'warning' : 'error';
			self::log(
				$type,
				'PHP Runtime Error',
				array(
					'errno'           => (int) $errno,
					'error_type_name' => self::php_error_type_to_name( (int) $errno ),
					'message'         => (string) $errstr,
					'file'            => $file,
					'line'            => (int) $errline,
				)
			);
		}

		return self::call_previous_error_handler( $errno, $errstr, $errfile, $errline );
	}

	/**
	 * Handle uncaught exceptions and persist plugin-related failures.
	 *
	 * @param mixed $exception Thrown exception object.
	 * @return void
	 */
	public static function exception_handler( $exception ) {
		if ( $exception instanceof Throwable ) {
			$file = (string) $exception->getFile();
			if ( self::is_plugin_file( $file ) ) {
				self::log(
					'critical',
					'Uncaught Exception',
					array(
						'exception_class' => get_class( $exception ),
						'message'         => $exception->getMessage(),
						'file'            => $file,
						'line'            => (int) $exception->getLine(),
						'trace'           => explode( "\n", $exception->getTraceAsString() ),
					)
				);
			}
		}

		if ( is_callable( self::$previous_exception_handler ) ) {
			call_user_func( self::$previous_exception_handler, $exception );
		}
	}

	/**
	 * Invoke any previously registered PHP error handler.
	 *
	 * @param int    $errno   PHP error number.
	 * @param string $errstr  PHP error message.
	 * @param string $errfile File path where the error occurred.
	 * @param int    $errline Line number where the error occurred.
	 * @return bool
	 */
	private static function call_previous_error_handler( $errno, $errstr, $errfile, $errline ) {
		if ( is_callable( self::$previous_error_handler ) && array( __CLASS__, 'php_error_handler' ) !== self::$previous_error_handler ) {
			return (bool) call_user_func( self::$previous_error_handler, $errno, $errstr, $errfile, $errline );
		}

		return false;
	}

	/**
	 * Build request context metadata for each log entry.
	 *
	 * @return array<string,mixed>
	 */
	private static function get_request_context() {
		$request_uri    = '';
		$request_method = '';
		$referer        = '';

		if ( isset( $_SERVER['REQUEST_URI'] ) ) {
			$request_uri = sanitize_text_field( wp_unslash( $_SERVER['REQUEST_URI'] ) );
		}
		if ( isset( $_SERVER['REQUEST_METHOD'] ) ) {
			$request_method = sanitize_text_field( wp_unslash( $_SERVER['REQUEST_METHOD'] ) );
		}
		if ( isset( $_SERVER['HTTP_REFERER'] ) ) {
			$referer = esc_url_raw( wp_unslash( $_SERVER['HTTP_REFERER'] ) );
		}

		return array(
			'request_uri'    => $request_uri,
			'request_method' => $request_method,
			'referer'        => $referer,
			'is_admin'       => is_admin(),
			'is_ajax'        => function_exists( 'wp_doing_ajax' ) ? wp_doing_ajax() : false,
			'user_id'        => get_current_user_id(),
		);
	}

	/**
	 * Normalize arbitrary details to a safe, serializable structure.
	 *
	 * @param mixed $details Detail payload to normalize.
	 * @param int   $depth   Current recursion depth.
	 * @return mixed
	 */
	private static function normalize_details( $details, $depth = 0 ) {
		if ( $depth > 4 ) {
			return '[max-depth-reached]';
		}

		if ( $details instanceof WP_Error ) {
			return array(
				'error_code'    => $details->get_error_code(),
				'error_message' => $details->get_error_message(),
				'error_data'    => self::normalize_details( $details->get_error_data(), $depth + 1 ),
			);
		}

		if ( $details instanceof Throwable ) {
			return array(
				'exception_class' => get_class( $details ),
				'message'         => $details->getMessage(),
				'file'            => $details->getFile(),
				'line'            => (int) $details->getLine(),
			);
		}

		if ( is_array( $details ) ) {
			$normalized = array();
			foreach ( $details as $key => $value ) {
				$normalized_key = is_string( $key ) ? sanitize_key( $key ) : (string) $key;
				if ( '' === $normalized_key ) {
					$normalized_key = 'key_' . count( $normalized );
				}
				$normalized[ $normalized_key ] = self::normalize_details( $value, $depth + 1 );
			}
			return $normalized;
		}

		if ( is_object( $details ) ) {
			return self::normalize_details( get_object_vars( $details ), $depth + 1 );
		}

		if ( is_bool( $details ) || is_int( $details ) || is_float( $details ) || null === $details ) {
			return $details;
		}

		if ( is_string( $details ) ) {
			return $details;
		}

		return '[unsupported-detail-type]';
	}

	/**
	 * Convert a PHP error number to a stable symbolic name.
	 *
	 * @param int $errno PHP error number.
	 * @return string
	 */
	private static function php_error_type_to_name( $errno ) {
		switch ( (int) $errno ) {
			case E_ERROR:
				return 'E_ERROR';
			case E_WARNING:
				return 'E_WARNING';
			case E_PARSE:
				return 'E_PARSE';
			case E_NOTICE:
				return 'E_NOTICE';
			case E_CORE_ERROR:
				return 'E_CORE_ERROR';
			case E_CORE_WARNING:
				return 'E_CORE_WARNING';
			case E_COMPILE_ERROR:
				return 'E_COMPILE_ERROR';
			case E_COMPILE_WARNING:
				return 'E_COMPILE_WARNING';
			case E_USER_ERROR:
				return 'E_USER_ERROR';
			case E_USER_WARNING:
				return 'E_USER_WARNING';
			case E_USER_NOTICE:
				return 'E_USER_NOTICE';
			case E_RECOVERABLE_ERROR:
				return 'E_RECOVERABLE_ERROR';
			case E_DEPRECATED:
				return 'E_DEPRECATED';
			case E_USER_DEPRECATED:
				return 'E_USER_DEPRECATED';
			default:
				return 'E_UNKNOWN';
		}
	}

	/**
	 * Add an event log entry.
	 *
	 * @param string              $type    Event level.
	 * @param string              $message Event message.
	 * @param array<string,mixed> $details Event details.
	 * @return void
	 */
	public static function log( $type, $message, $details = array() ) {
		$allowed_types      = array( 'info', 'warning', 'error', 'critical' );
		$normalized_type    = sanitize_key( (string) $type );
		$normalized_message = sanitize_text_field( (string) $message );

		if ( ! in_array( $normalized_type, $allowed_types, true ) ) {
			$normalized_type = 'info';
		}
		if ( '' === $normalized_message ) {
			$normalized_message = 'Log entry';
		}

		$normalized_details = self::normalize_details( $details );
		if ( ! is_array( $normalized_details ) ) {
			$normalized_details = array(
				'value' => $normalized_details,
			);
		}
		$normalized_details['_context'] = self::get_request_context();

		$log_entry = array(
			'id'        => uniqid( 'log_', true ),
			'timestamp' => time(),
			'type'      => $normalized_type,
			'message'   => $normalized_message,
			'details'   => $normalized_details,
		);
		$log       = get_option( self::$log_option_name, array() );
		if ( ! is_array( $log ) ) {
			$log = array();
		}
		array_unshift( $log, $log_entry );
		if ( count( $log ) > self::$max_log_entries ) {
			$log = array_slice( $log, 0, self::$max_log_entries );
		}
		update_option( self::$log_option_name, $log, false ); // Do not autoload logs.
	}

	/**
	 * Delete selected log entries.
	 *
	 * @param array<int,string> $ids Log entry IDs.
	 * @return void
	 */
	public static function delete_logs( $ids ) {
		$log = get_option( self::$log_option_name, array() );
		if ( ! is_array( $log ) ) {
			return;
		}

		$log = array_filter(
			$log,
			function ( $entry ) use ( $ids ) {
				return ! isset( $entry['id'] ) || ! in_array( $entry['id'], $ids, true );
			}
		);

		update_option( self::$log_option_name, array_values( $log ), false );
	}

	/**
	 * Get all persisted log entries.
	 *
	 * @return array<int,array<string,mixed>>
	 */
	public static function get_logs() {
		return get_option( self::$log_option_name, array() );
	}

	/**
	 * Clear all persisted logs.
	 *
	 * @return void
	 */
	public static function clear_logs() {
		delete_option( self::$log_option_name );
	}
}
Quorlyx_Pro_Logger::init();

/**
 * Get behavior engine schema version.
 *
 * @return string
 */
