/**
 * Create or upgrade the behavior engine analytics table.
 *
 * @param bool $force_upgrade Whether to force schema reconciliation.
 * @return void
 */
function quorlyx_maybe_install_behavior_engine_table( $force_upgrade = false ) {
	$schema_version   = quorlyx_get_behavior_engine_schema_version();
	$installed_schema = sanitize_text_field( (string) get_option( 'quorlyx_behavior_engine_schema_version', '' ) );

	if ( ! $force_upgrade && $installed_schema === $schema_version ) {
		$verified_schema = sanitize_text_field( (string) get_option( 'quorlyx_behavior_engine_schema_verified', '' ) );
		if ( $verified_schema === $schema_version ) {
			return;
		}

		if ( quorlyx_behavior_engine_table_has_required_columns() ) {
			update_option( 'quorlyx_behavior_engine_schema_verified', $schema_version, false );
			return;
		}

		$force_upgrade = true;
	}

	global $wpdb;

	$table_name      = quorlyx_get_behavior_engine_table_name();
	$charset_collate = $wpdb->get_charset_collate();

	if ( ! function_exists( 'dbDelta' ) ) {
		require_once ABSPATH . 'wp-admin/includes/upgrade.php';
	}

	$sql = "CREATE TABLE {$table_name} (
		id bigint(20) unsigned NOT NULL AUTO_INCREMENT,
		session_id varchar(128) NOT NULL DEFAULT '',
		profile_hash varchar(64) NOT NULL DEFAULT '',
		pattern_tag varchar(50) NOT NULL DEFAULT '',
		visited_path text NOT NULL,
		traffic_source varchar(20) NOT NULL DEFAULT 'direct',
		traffic_source_score smallint(5) unsigned NOT NULL DEFAULT 1,
		product_id bigint(20) unsigned NOT NULL DEFAULT 0,
		visit_frequency int(10) unsigned NOT NULL DEFAULT 0,
		pages_viewed int(10) unsigned NOT NULL DEFAULT 0,
		dwell_time_avg int(10) unsigned NOT NULL DEFAULT 0,
		cart_activity int(10) unsigned NOT NULL DEFAULT 0,
		scroll_depth smallint(5) unsigned NOT NULL DEFAULT 0,
		conversion_status varchar(20) NOT NULL DEFAULT 'unknown',
		source_post_id bigint(20) unsigned NOT NULL DEFAULT 0,
		content_key varchar(64) NOT NULL DEFAULT '',
		last_post_id bigint(20) unsigned NOT NULL DEFAULT 0,
		last_content_key varchar(64) NOT NULL DEFAULT '',
		category_breakdown varchar(255) NOT NULL DEFAULT '{}',
		abandonment_stage varchar(50) NOT NULL DEFAULT '',
		started_chat tinyint(1) unsigned NOT NULL DEFAULT 0,
		sampled_non_converter tinyint(1) unsigned NOT NULL DEFAULT 0,
		created_at datetime NOT NULL,
		updated_at datetime NOT NULL,
		PRIMARY KEY  (id),
		KEY profile_hash (profile_hash),
		KEY pattern_tag (pattern_tag),
		KEY product_id (product_id),
		KEY source_post_id (source_post_id),
		KEY content_key (content_key),
		KEY updated_at (updated_at)
	) {$charset_collate};";

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.SchemaChange -- dbDelta is required for install/upgrade table schema.
	dbDelta( $sql );

	$trigger_events_table = quorlyx_get_trigger_analytics_events_table_name();
	$trigger_events_sql   = "CREATE TABLE {$trigger_events_table} (
		id bigint(20) unsigned NOT NULL AUTO_INCREMENT,
		trigger_id varchar(64) NOT NULL DEFAULT '',
		event_name varchar(64) NOT NULL DEFAULT '',
		event_date date NOT NULL,
		event_count bigint(20) unsigned NOT NULL DEFAULT 0,
		created_at datetime NOT NULL,
		updated_at datetime NOT NULL,
		PRIMARY KEY  (id),
		UNIQUE KEY trigger_event_day (trigger_id,event_name,event_date),
		KEY trigger_id (trigger_id),
		KEY event_name (event_name),
		KEY event_date (event_date),
		KEY updated_at (updated_at)
	) {$charset_collate};";

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.SchemaChange -- dbDelta is required for install/upgrade table schema.
	dbDelta( $trigger_events_sql );

	$virtual_analytics_table = quorlyx_get_virtual_analytics_table_name();
	$virtual_analytics_sql   = "CREATE TABLE {$virtual_analytics_table} (
		content_key varchar(64) NOT NULL DEFAULT '',
		meta_key varchar(64) NOT NULL DEFAULT '',
		metric_value bigint(20) NOT NULL DEFAULT 0,
		updated_at datetime NOT NULL,
		PRIMARY KEY  (content_key,meta_key),
		KEY updated_at (updated_at)
	) {$charset_collate};";

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.SchemaChange -- dbDelta is required for install/upgrade table schema.
	dbDelta( $virtual_analytics_sql );

	$conversations_table = quorlyx_get_conversations_table_name();
	$conversations_sql   = "CREATE TABLE {$conversations_table} (
		id bigint(20) unsigned NOT NULL AUTO_INCREMENT,
		post_id bigint(20) unsigned NOT NULL DEFAULT 0,
		persistent_user_id varchar(128) NOT NULL DEFAULT '',
		variation varchar(1) NOT NULL DEFAULT 'a',
		source varchar(20) NOT NULL DEFAULT 'normal',
		trigger_id varchar(64) NOT NULL DEFAULT '',
		trigger_name varchar(191) NOT NULL DEFAULT '',
		trigger_type varchar(64) NOT NULL DEFAULT '',
		message_count int(10) unsigned NOT NULL DEFAULT 0,
		conversions_count int(10) unsigned NOT NULL DEFAULT 0,
		conversion_details longtext NULL,
		lead_interest varchar(191) NOT NULL DEFAULT '',
		lead_status varchar(80) NOT NULL DEFAULT '',
		lead_urgency varchar(80) NOT NULL DEFAULT '',
		user_agent varchar(255) NOT NULL DEFAULT '',
		ip_hash varchar(64) NOT NULL DEFAULT '',
		device varchar(20) NOT NULL DEFAULT '',
		country varchar(8) NOT NULL DEFAULT '',
		city varchar(120) NOT NULL DEFAULT '',
		location varchar(191) NOT NULL DEFAULT '',
		created_at datetime NOT NULL,
		updated_at datetime NOT NULL,
		last_activity bigint(20) unsigned NOT NULL DEFAULT 0,
		PRIMARY KEY  (id),
		UNIQUE KEY post_id (post_id),
		KEY persistent_user_last (persistent_user_id,last_activity),
		KEY ip_hash_last (ip_hash,last_activity),
		KEY variation_source (variation,source),
		KEY trigger_id (trigger_id),
		KEY last_activity (last_activity)
	) {$charset_collate};";

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.SchemaChange -- dbDelta is required for install/upgrade table schema.
	dbDelta( $conversations_sql );

	$messages_table = quorlyx_get_conversation_messages_table_name();
	$messages_sql   = "CREATE TABLE {$messages_table} (
		id bigint(20) unsigned NOT NULL AUTO_INCREMENT,
		conversation_id bigint(20) unsigned NOT NULL DEFAULT 0,
		conversation_post_id bigint(20) unsigned NOT NULL DEFAULT 0,
		sequence_num int(10) unsigned NOT NULL DEFAULT 0,
		role varchar(20) NOT NULL DEFAULT '',
		message_text longtext NULL,
		message_json longtext NULL,
		created_at datetime NOT NULL,
		PRIMARY KEY  (id),
		UNIQUE KEY conversation_sequence (conversation_post_id,sequence_num),
		KEY conversation_id_sequence (conversation_id,sequence_num),
		KEY role (role),
		KEY created_at (created_at)
	) {$charset_collate};";

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.SchemaChange -- dbDelta is required for install/upgrade table schema.
	dbDelta( $messages_sql );

	$submissions_table = quorlyx_get_submissions_table_name();
	$submissions_sql   = "CREATE TABLE {$submissions_table} (
		id bigint(20) unsigned NOT NULL AUTO_INCREMENT,
		post_id bigint(20) unsigned NOT NULL DEFAULT 0,
		conversation_id bigint(20) unsigned NOT NULL DEFAULT 0,
		conversation_post_id bigint(20) unsigned NOT NULL DEFAULT 0,
		email varchar(191) NOT NULL DEFAULT '',
		email_hash varchar(64) NOT NULL DEFAULT '',
		phone varchar(80) NOT NULL DEFAULT '',
		phone_hash varchar(64) NOT NULL DEFAULT '',
		interest varchar(191) NOT NULL DEFAULT '',
		purpose varchar(191) NOT NULL DEFAULT '',
		status varchar(80) NOT NULL DEFAULT '',
		urgency varchar(80) NOT NULL DEFAULT '',
		tags text NULL,
		ab_variation varchar(1) NOT NULL DEFAULT 'a',
		source_url text NULL,
		trigger_id varchar(64) NOT NULL DEFAULT '',
		trigger_name varchar(191) NOT NULL DEFAULT '',
		trigger_type varchar(64) NOT NULL DEFAULT '',
		created_at datetime NOT NULL,
		updated_at datetime NOT NULL,
		PRIMARY KEY  (id),
		UNIQUE KEY post_id (post_id),
		KEY conversation_post_id (conversation_post_id),
		KEY conversation_id (conversation_id),
		KEY email_hash (email_hash),
		KEY phone_hash (phone_hash),
		KEY status (status),
		KEY trigger_id (trigger_id),
		KEY created_at (created_at)
	) {$charset_collate};";

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.SchemaChange -- dbDelta is required for install/upgrade table schema.
	dbDelta( $submissions_sql );

	update_option( 'quorlyx_behavior_engine_schema_version', $schema_version, false );
	update_option( 'quorlyx_behavior_engine_schema_verified', $schema_version, false );
}

/**
 * Verify the behavior engine table contains required columns.
 *
 * @return bool
 */
function quorlyx_behavior_engine_table_has_required_columns() {
	if ( ! quorlyx_behavior_engine_table_exists() ) {
		return false;
	}

	global $wpdb;

	$table_name = quorlyx_get_behavior_engine_table_name();
	$required   = array(
		'session_id',
		'profile_hash',
		'pattern_tag',
		'visited_path',
		'traffic_source',
		'traffic_source_score',
		'product_id',
		'visit_frequency',
		'pages_viewed',
		'dwell_time_avg',
		'cart_activity',
		'scroll_depth',
		'conversion_status',
		'source_post_id',
		'content_key',
		'last_post_id',
		'last_content_key',
		'category_breakdown',
		'abandonment_stage',
		'started_chat',
		'sampled_non_converter',
		'created_at',
		'updated_at',
	);

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Schema introspection for migration safety.
	$column_rows = $wpdb->get_results( "SHOW COLUMNS FROM {$table_name}", ARRAY_A );
	if ( ! is_array( $column_rows ) ) {
		return false;
	}

	$existing = array();
	foreach ( $column_rows as $column_row ) {
		$field_name = sanitize_key( (string) ( $column_row['Field'] ?? '' ) );
		if ( '' !== $field_name ) {
			$existing[] = $field_name;
		}
	}

	$missing = array_diff( $required, $existing );

	return empty( $missing );
}

/**
 * Ensure behavior table schema exists on admin loads.
