add_action( 'admin_init', 'quorlyx_bootstrap_db_first_analytics_migration', 6 );
add_action( 'admin_init', 'quorlyx_migrate_legacy_cpt_storage_to_tables', 7 );

/**
 * Ensure the lightweight runtime storage tables exist before frontend tracking writes.
 *
