register_activation_hook( __FILE__, 'quorlyx_pro_activate' );
register_deactivation_hook( __FILE__, 'quorlyx_pro_deactivate' );
register_uninstall_hook( __FILE__, 'quorlyx_pro_uninstall' );

/**
 * Plugin activation bootstrap.
 *
 * @return void
 */
function quorlyx_pro_activate() {
	quorlyx_maybe_repair_active_plugins_option();
	quorlyx_grant_admin_capability();

	if ( ! get_option( 'quorlyx_pro_activated_before' ) ) {
		add_option( 'quorlyx_do_activation_redirect', true );
		add_option( 'quorlyx_pro_activated_before', true );
	}
	quorlyx_maybe_install_behavior_engine_table( true );
	quorlyx_migrate_legacy_cpt_storage_to_tables();
	quorlyx_reschedule_post_generation_event();
	quorlyx_maybe_schedule_retention_cleanup();
}

/**
 * Plugin deactivation cleanup.
 *
 * @return void
 */
function quorlyx_pro_deactivate() {
	wp_clear_scheduled_hook( 'quorlyx_check_finished_conversations' );
	wp_clear_scheduled_hook( 'quorlyx_generate_posts_event' );
	wp_clear_scheduled_hook( 'quorlyx_recalculate_stats_event' );
	wp_clear_scheduled_hook( 'quorlyx_retention_cleanup_event' );
}

/**
 * Plugin uninstall cleanup.
 *
 * @return void
 */
function quorlyx_pro_uninstall() {
	if ( ! get_option( 'quorlyx_delete_data_on_uninstall', false ) ) {
		return;
	}

	quorlyx_delete_all_plugin_data();
}

/**
 * Get all scheduled hooks owned by Quorlyx.
 *
 * @return string[]
 */
function quorlyx_get_scheduled_hooks() {
	return array(
		'quorlyx_check_finished_conversations',
		'quorlyx_generate_posts_event',
		'quorlyx_recalculate_stats_event',
		'quorlyx_retention_cleanup_event',
	);
}

/**
 * Clear scheduled events owned by Quorlyx.
 *
 * @return void
 */
function quorlyx_clear_scheduled_events() {
	foreach ( quorlyx_get_scheduled_hooks() as $hook ) {
		wp_clear_scheduled_hook( $hook );
	}
}

/**
 * Get database tables owned by Quorlyx.
 *
 * @return string[]
 */
function quorlyx_get_owned_table_names() {
	global $wpdb;

	return array_values(
		array_unique(
			array_filter(
				array(
					quorlyx_get_behavior_engine_table_name(),
					quorlyx_get_trigger_analytics_events_table_name(),
					quorlyx_get_virtual_analytics_table_name(),
					quorlyx_get_conversations_table_name(),
					quorlyx_get_conversation_messages_table_name(),
					quorlyx_get_submissions_table_name(),
				)
			)
		)
	);
}

/**
 * Delete private plugin post records without touching customer content generated by Quorlyx.
 *
 * @return int Number of deleted posts.
 */
function quorlyx_delete_private_plugin_posts() {
	global $wpdb;

	$post_types    = array( 'quorlyx_submission', 'quorlyx_conversation' );
	$deleted_count = 0;

	do {
		$placeholders = implode( ',', array_fill( 0, count( $post_types ), '%s' ) );
		// phpcs:ignore WordPress.DB.PreparedSQLPlaceholders.UnfinishedPrepare,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Explicit destructive cleanup for plugin-owned private CPTs.
		$post_ids = $wpdb->get_col( $wpdb->prepare( "SELECT ID FROM {$wpdb->posts} WHERE post_type IN ({$placeholders}) LIMIT 500", ...$post_types ) );
		if ( empty( $post_ids ) ) {
			break;
		}

		$post_ids     = array_map( 'absint', $post_ids );
		$ids_sql      = implode( ',', $post_ids );
		$comment_ids  = $wpdb->get_col( "SELECT comment_ID FROM {$wpdb->comments} WHERE comment_post_ID IN ({$ids_sql})" ); // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- IDs are absint-normalized above.
		$comments_sql = ! empty( $comment_ids ) ? implode( ',', array_map( 'absint', $comment_ids ) ) : '';

		if ( '' !== $comments_sql ) {
			$wpdb->query( "DELETE FROM {$wpdb->commentmeta} WHERE comment_id IN ({$comments_sql})" ); // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- IDs are absint-normalized above.
			$wpdb->query( "DELETE FROM {$wpdb->comments} WHERE comment_ID IN ({$comments_sql})" ); // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- IDs are absint-normalized above.
		}

		$wpdb->query( "DELETE FROM {$wpdb->postmeta} WHERE post_id IN ({$ids_sql})" ); // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- IDs are absint-normalized above.
		$wpdb->query( "DELETE FROM {$wpdb->term_relationships} WHERE object_id IN ({$ids_sql})" ); // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- IDs are absint-normalized above.
		$wpdb->query( "DELETE FROM {$wpdb->posts} WHERE ID IN ({$ids_sql})" ); // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- IDs are absint-normalized above.

		$deleted_count += count( $post_ids );
	} while ( true );

	return $deleted_count;
}

/**
 * Delete all data owned by Quorlyx.
 *
 * This intentionally does not delete normal WordPress posts/products that may
 * have been generated with Quorlyx, because those are site content.
 *
 * @return array<string,int>
 */
function quorlyx_delete_all_plugin_data() {
	global $wpdb;

	quorlyx_clear_scheduled_events();
	$deleted_posts = quorlyx_delete_private_plugin_posts();

	$like_quorlyx = $wpdb->esc_like( 'quorlyx_' ) . '%';
	$like_trans   = $wpdb->esc_like( '_transient_quorlyx_' ) . '%';
	$like_tout    = $wpdb->esc_like( '_transient_timeout_quorlyx_' ) . '%';
	$like_site    = $wpdb->esc_like( '_site_transient_quorlyx_' ) . '%';
	$like_stout   = $wpdb->esc_like( '_site_transient_timeout_quorlyx_' ) . '%';

	// phpcs:disable WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Explicit destructive admin/uninstall cleanup.
	$deleted_options = (int) $wpdb->query(
		$wpdb->prepare(
			"DELETE FROM {$wpdb->options} WHERE option_name LIKE %s OR option_name LIKE %s OR option_name LIKE %s OR option_name LIKE %s OR option_name LIKE %s",
			$like_quorlyx,
			$like_trans,
			$like_tout,
			$like_site,
			$like_stout
		)
	);
	$deleted_postmeta = (int) $wpdb->query( $wpdb->prepare( "DELETE FROM {$wpdb->postmeta} WHERE meta_key LIKE %s", $like_quorlyx ) );
	$deleted_usermeta = (int) $wpdb->query( $wpdb->prepare( "DELETE FROM {$wpdb->usermeta} WHERE meta_key LIKE %s", $like_quorlyx ) );
	if ( property_exists( $wpdb, 'termmeta' ) && $wpdb->termmeta ) {
		$wpdb->query( $wpdb->prepare( "DELETE FROM {$wpdb->termmeta} WHERE meta_key LIKE %s", $like_quorlyx ) );
	}

	$dropped_tables = 0;
	foreach ( quorlyx_get_owned_table_names() as $table_name ) {
		if ( ! is_string( $table_name ) || '' === $table_name || 0 !== strpos( $table_name, $wpdb->prefix . 'quorlyx_' ) ) {
			continue;
		}
		$wpdb->query( "DROP TABLE IF EXISTS {$table_name}" ); // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Table name is generated by trusted helpers and prefix-checked above.
		$dropped_tables++;
	}
	// phpcs:enable WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching

	$capability = quorlyx_admin_capability();
	foreach ( array( 'administrator' ) as $role_name ) {
		$role = get_role( $role_name );
		if ( $role ) {
			$role->remove_cap( $capability );
		}
	}

	wp_cache_flush();

	return array(
		'options'   => max( 0, $deleted_options ),
		'postmeta'  => max( 0, $deleted_postmeta ),
		'usermeta'  => max( 0, $deleted_usermeta ),
		'posts'     => $deleted_posts,
		'tables'    => $dropped_tables,
		'schedules' => count( quorlyx_get_scheduled_hooks() ),
	);
}

add_action( 'admin_init', 'quorlyx_activation_redirect' );

/**
 * Redirect first-time activations to the dashboard welcome state.
 *
 * @return void
 */
function quorlyx_activation_redirect() {
	if ( get_option( 'quorlyx_do_activation_redirect', false ) ) {
		delete_option( 'quorlyx_do_activation_redirect' );
		// phpcs:ignore WordPress.Security.NonceVerification.Recommended -- Activation redirect flag from core.
		if ( ! isset( $_GET['activate-multi'] ) && quorlyx_current_user_can_manage() ) {
			wp_safe_redirect( admin_url( 'admin.php?page=quorlyx-dashboard&welcome=1' ) );
			exit;
		}
	}
}

