/**
 * Keep frontend variation payloads free of provider secrets and server-only prompts.
 *
 * @param array<string,mixed> $variation Variation settings.
 * @return array<string,mixed>
 */
function quorlyx_get_frontend_variation_settings( $variation ) {
	$variation = array_replace( quorlyx_get_variation_defaults(), is_array( $variation ) ? $variation : array() );
	$allowed   = array(
		'chat_enabled',
		'welcome_message',
		'loading_message',
		'knowledge_base_include_current_page',
		'bot_name',
		'primary_color',
		'floating_logo',
		'floating_label',
		'floating_button_size',
		'floating_label_color',
		'floating_label_font_size',
		'floating_label_width',
		'floating_label_gap',
		'chat_width',
		'chat_height',
		'mobile_panel_width_percent',
		'mobile_panel_full_width_percent',
		'mobile_panel_height_percent',
		'mobile_panel_full_height_percent',
		'mobile_panel_horizontal_align',
		'mobile_panel_vertical_align',
		'header_text_color',
		'user_message_bg_color',
		'user_message_text_color',
		'chat_border_radius',
		'actions',
		'quick_actions_position',
		'ai_generates_buttons',
	);

	return array_intersect_key( $variation, array_flip( $allowed ) );
}

/**
 * Normalize quick-reply button data from a textarea or structured array.
 *
 * Textarea format: Label | message sent to AI | optional AI rule/context.
 *
 * @param mixed  $raw    Raw quick reply payload.
 * @param string $prefix Stable ID prefix.
 * @return array<int,array<string,string>>
 */
function quorlyx_normalize_quick_reply_buttons( $raw, $prefix = 'quick_reply' ) {
	$items = array();

	if ( is_string( $raw ) ) {
		$lines = preg_split( '/\r\n|\r|\n/', $raw );
		foreach ( (array) $lines as $line ) {
			$line = trim( (string) $line );
			if ( '' === $line ) {
				continue;
			}

			$parts   = array_map( 'trim', explode( '|', $line, 3 ) );
			$items[] = array(
				'label'   => $parts[0] ?? '',
				'message' => $parts[1] ?? ( $parts[0] ?? '' ),
				'context' => $parts[2] ?? '',
			);
		}
	} elseif ( is_array( $raw ) ) {
		$items = $raw;
	}

	$normalized = array();
	foreach ( $items as $item ) {
		if ( ! is_array( $item ) ) {
			continue;
		}

		$label   = sanitize_text_field( (string) ( $item['label'] ?? '' ) );
		$message = sanitize_text_field( (string) ( $item['message'] ?? $label ) );
		$context = sanitize_textarea_field( (string) ( $item['context'] ?? '' ) );
		if ( '' === $label ) {
			continue;
		}
		if ( '' === $message ) {
			$message = $label;
		}

		$id = sanitize_key( (string) ( $item['id'] ?? '' ) );
		if ( '' === $id ) {
			$id = sanitize_key( $prefix . '_' . substr( md5( $label . '|' . $message ), 0, 12 ) );
		}

		$normalized[] = array(
			'id'      => $id,
			'label'   => $label,
			'message' => $message,
			'context' => $context,
		);

		if ( count( $normalized ) >= 8 ) {
			break;
		}
	}

	return $normalized;
}

/**
 * Detects quick-reply rows that are really admin instructions, not button copy.
 *
 * @param mixed $reply Quick reply row.
 * @return bool
 */
function quorlyx_quick_reply_looks_like_instruction( $reply ) {
	if ( ! is_array( $reply ) ) {
		return false;
	}

	$label   = trim( sanitize_text_field( (string) ( $reply['label'] ?? '' ) ) );
	$message = trim( sanitize_text_field( (string) ( $reply['message'] ?? '' ) ) );
	$text    = strtolower( $label . ' ' . $message . ' ' . sanitize_textarea_field( (string) ( $reply['context'] ?? '' ) ) );

	if ( strlen( $label ) > 90 ) {
		return true;
	}

	$instruction_markers = array(
		'treat this visitor',
		'keep answers',
		'do not invent',
		'do not ask',
		'do not discuss',
		'if they ask',
		'if the visitor',
		'ask for their email',
		'request their email',
		'admin follow-up',
		'follow-up instructions',
	);

	foreach ( $instruction_markers as $marker ) {
		if ( false !== strpos( $text, $marker ) ) {
			return true;
		}
	}

	return false;
}

/**
 * Returns only visitor-facing trigger quick replies.
 *
 * @param mixed $raw Raw quick replies.
 * @return array<int,array<string,string>>
 */
function quorlyx_get_public_trigger_quick_replies( $raw ) {
	$public = array();
	foreach ( quorlyx_normalize_quick_reply_buttons( $raw, 'trigger_reply' ) as $reply ) {
		if ( quorlyx_quick_reply_looks_like_instruction( $reply ) ) {
			continue;
		}
		$public[] = $reply;
	}

	return $public;
}

/**
 * Convert normalized quick replies back to textarea rows for admin editing.
 *
 * @param mixed $raw Raw quick reply payload.
 * @return string
 */
function quorlyx_quick_reply_buttons_to_admin_text( $raw ) {
	$rows = array();
	foreach ( quorlyx_normalize_quick_reply_buttons( $raw ) as $reply ) {
		$row = (string) $reply['label'];
		if ( '' !== (string) $reply['message'] && (string) $reply['message'] !== (string) $reply['label'] ) {
			$row .= ' | ' . (string) $reply['message'];
		}
		if ( '' !== (string) $reply['context'] ) {
			if ( false === strpos( $row, ' | ' ) ) {
				$row .= ' | ' . (string) $reply['message'];
			}
			$row .= ' | ' . (string) $reply['context'];
		}
		$rows[] = $row;
	}

	return implode( "\n", $rows );
}

/**
 * Build prompt rules for admin-defined quick replies with explicit context.
 *
 * @param array<int,array<string,mixed>> $items Quick reply/action items.
 * @param bool                          $message_only Require type=message.
 * @return string
 */
function quorlyx_build_quick_reply_prompt_rules( $items, $message_only = false ) {
	if ( ! is_array( $items ) || empty( $items ) ) {
		return '';
	}

	$rules = array();
	foreach ( $items as $item ) {
		if ( ! is_array( $item ) ) {
			continue;
		}
		if ( $message_only && 'message' !== sanitize_key( (string) ( $item['type'] ?? '' ) ) ) {
			continue;
		}

		$label   = sanitize_text_field( (string) ( $item['label'] ?? '' ) );
		$message = sanitize_text_field( (string) ( $item['message'] ?? $label ) );
		$context = trim( sanitize_textarea_field( (string) ( $item['context'] ?? '' ) ) );
		if ( '' === $label || '' === $context ) {
			continue;
		}
		if ( '' === $message ) {
			$message = $label;
		}

		$rules[] = '- If the visitor chooses "' . $label . '" or sends "' . $message . '": ' . $context;
		if ( count( $rules ) >= 8 ) {
			break;
		}
	}

	return implode( "\n", $rules );
}

