/**
 * Collect WooCommerce coupon codes for trigger recovery UI options.
 *
 * @param int $limit Maximum coupons to query.
 * @return array<int,string>
 */
function quorlyx_get_coupon_codes_for_trigger_ui( $limit = 200 ) {
	$limit        = max( 1, min( 500, absint( $limit ) ) );
	$coupon_codes = array();

	if ( post_type_exists( 'shop_coupon' ) ) {
		$coupon_ids = get_posts(
			array(
				'post_type'              => 'shop_coupon',
				'post_status'            => array( 'publish', 'private' ),
				'posts_per_page'         => $limit,
				'orderby'                => 'title',
				'order'                  => 'ASC',
				'fields'                 => 'ids',
				'no_found_rows'          => true,
				'update_post_meta_cache' => false,
				'update_post_term_cache' => false,
			)
		);

		if ( is_array( $coupon_ids ) ) {
			foreach ( $coupon_ids as $coupon_id ) {
				$code = trim( (string) get_the_title( $coupon_id ) );
				if ( '' !== $code ) {
					$coupon_codes[] = $code;
				}
			}
		}
	}

	if ( empty( $coupon_codes ) && function_exists( 'wc_get_coupons' ) ) {
		$coupons = wc_get_coupons(
			array(
				'limit'   => $limit,
				'orderby' => 'title',
				'order'   => 'ASC',
			)
		);

		if ( is_array( $coupons ) ) {
			foreach ( $coupons as $coupon ) {
				if ( is_object( $coupon ) && method_exists( $coupon, 'get_code' ) ) {
					$code = trim( (string) $coupon->get_code() );
					if ( '' !== $code ) {
						$coupon_codes[] = $code;
					}
				}
			}
		}
	}

	$coupon_codes = array_values( array_unique( $coupon_codes ) );
	natcasesort( $coupon_codes );

	return array_values( $coupon_codes );
}

