/**
 * Sanitize a trigger payload from admin settings.
 *
 * @param array<string,mixed> $trigger Raw trigger payload.
 * @return array<string,mixed>
 */
function quorlyx_sanitize_trigger_settings( $trigger ) {
	$defaults                     = quorlyx_get_trigger_defaults();
	$trigger                      = is_array( $trigger ) ? $trigger : array();
	$trigger                      = array_replace( $defaults, $trigger );
	$valid_types                        = array( 'time_on_page', 'scroll_depth', 'exit_intent', 'inactivity', 'click_intent', 'cart_abandonment', 'return_visitor', 'page_depth', 'utm_referrer', 'behavior_pattern' );
	$valid_freq                         = array( 'once_per_session', 'once_per_page', 'once_per_day', 'once_per_n_days', 'unlimited' );
	$valid_mode                         = array( 'once_per_session', 'once_per_page', 'once_per_day', 'once_per_n_days', 'disabled' );
	$valid_format_modes                 = array( 'free_ai', 'template_locked', 'hybrid_required_tokens' );
	$valid_missing_placeholder_policies = array( 'hide', 'fallback_text', 'use_fallback_message' );
	$valid_quick_replies_positions      = array( 'message', 'chat_bar', 'both', 'hidden' );
	$valid_window                       = array( '7d', '30d' );
	$valid_segment_page_type            = array( 'any', 'homepage', 'product', 'post', 'page' );
	$valid_segment_device               = array( 'any', 'mobile', 'desktop' );
	$valid_segment_traffic_source       = array( 'any', 'direct', 'search', 'social', 'paid', 'email', 'referral' );
	$valid_segment_behavior_pattern     = array( 'any', 'fast_leaver', 'medium_leaver', 'slow_leaver', 'comparison_shopper', 'fast_closer', 'discoverer_closer', 'unknown' );
	$valid_segment_predicted_next_step  = array( 'any', 'likely_take_action', 'likely_leave', 'continue_browsing', 'checkout_dropout_risk', 'unknown' );
	$segment_page_type_map              = array(
		'any'           => 'any',
		'home'          => 'homepage',
		'homepage'      => 'homepage',
		'product'       => 'product',
		'cart_checkout' => 'page',
		'blog'          => 'post',
		'post'          => 'post',
		'content'       => 'page',
		'other'         => 'page',
		'page'          => 'page',
	);
	$segment_page_type            = sanitize_key( $trigger['segment_page_type'] ?? '' );
	$segment_page_type            = $segment_page_type_map[ $segment_page_type ] ?? $segment_page_type;
	$segment_page_type            = in_array( $segment_page_type, $valid_segment_page_type, true ) ? $segment_page_type : 'any';
	$trigger_type                 = sanitize_key( $trigger['type'] ?? '' );
	if ( 'section_view' === $trigger_type ) {
		$trigger_type = 'behavior_pattern';
	}

	$sanitized_trigger = array(
		'id'                                => sanitize_text_field( ! empty( $trigger['id'] ) ? $trigger['id'] : ( 'trigger_' . uniqid() ) ),
		'name'                              => sanitize_text_field( $trigger['name'] ),
		'is_active'                         => ! empty( $trigger['is_active'] ),
		'ab_scope'                          => in_array( $trigger['ab_scope'], array( 'all', 'a', 'b' ), true ) ? $trigger['ab_scope'] : 'all',
		'type'                              => in_array( $trigger_type, $valid_types, true ) ? $trigger_type : 'time_on_page',
		'target_page_url'                   => sanitize_text_field( $trigger['target_page_url'] ),
		'target_section_selector'           => sanitize_text_field( $trigger['target_section_selector'] ?? '' ),
		'exclude_page_urls'                 => sanitize_textarea_field( $trigger['exclude_page_urls'] ),
		'proactive_message'                 => sanitize_textarea_field( $trigger['proactive_message'] ),
		'time_delay'                        => absint( $trigger['time_delay'] ),
		'scroll_depth'                      => max( 1, min( 100, absint( $trigger['scroll_depth'] ) ) ),
		'inactivity_seconds'                => max( 5, min( 3600, absint( $trigger['inactivity_seconds'] ) ) ),
		'inactivity_exclude_selectors'      => sanitize_textarea_field( $trigger['inactivity_exclude_selectors'] ),
		'inactivity_mobile_enabled'         => ! empty( $trigger['inactivity_mobile_enabled'] ),
		'warn_on_exit'                      => ! empty( $trigger['warn_on_exit'] ),
		'click_intent_match_mode'           => in_array( $trigger['click_intent_match_mode'], array( 'url_contains', 'css_selector', 'button_id' ), true ) ? $trigger['click_intent_match_mode'] : 'url_contains',
		'click_intent_target'               => sanitize_text_field( $trigger['click_intent_target'] ),
		'click_intent_debounce_ms'          => max( 100, min( 10000, absint( $trigger['click_intent_debounce_ms'] ) ) ),
		'cart_abandonment_delay'            => max( 1, min( 600, absint( $trigger['cart_abandonment_delay'] ) ) ),
