		'quick_replies_position'            => in_array( sanitize_key( $trigger['quick_replies_position'] ?? 'message' ), $valid_quick_replies_positions, true ) ? sanitize_key( $trigger['quick_replies_position'] ?? 'message' ) : 'message',
		'capture_submissions_enabled'       => ! empty( $trigger['capture_submissions_enabled'] ) || ! empty( $trigger['capture_unsupported_feature_leads'] ),
		'capture_unsupported_feature_leads' => ! empty( $trigger['capture_unsupported_feature_leads'] ),
		'capture_submission_purpose'        => sanitize_text_field( $trigger['capture_submission_purpose'] ?? 'Triggered Chat Lead' ),
		'capture_submission_status'         => sanitize_text_field( $trigger['capture_submission_status'] ?? 'Captured' ),
		'capture_submission_tags'           => sanitize_text_field( $trigger['capture_submission_tags'] ?? '' ),
		'ai_temperature'                    => max( 0, min( 1, is_numeric( $trigger['ai_temperature'] ) ? floatval( $trigger['ai_temperature'] ) : 0.5 ) ),
		'ai_max_tokens'                     => max( 32, absint( $trigger['ai_max_tokens'] ) ),
