		'ai_audit_save'                     => ! empty( $trigger['ai_audit_save'] ),
		'ai_format_mode'                    => in_array( sanitize_key( $trigger['ai_format_mode'] ?? 'free_ai' ), $valid_format_modes, true ) ? sanitize_key( $trigger['ai_format_mode'] ) : 'free_ai',
		'ai_message_template'               => sanitize_textarea_field( $trigger['ai_message_template'] ?? '' ),
		'ai_required_placeholders'          => sanitize_textarea_field( $trigger['ai_required_placeholders'] ?? '' ),
		'ai_slot_instructions'              => sanitize_textarea_field( $trigger['ai_slot_instructions'] ?? '' ),
		'ai_missing_placeholder_policy'     => in_array( sanitize_key( $trigger['ai_missing_placeholder_policy'] ?? 'use_fallback_message' ), $valid_missing_placeholder_policies, true ) ? sanitize_key( $trigger['ai_missing_placeholder_policy'] ) : 'use_fallback_message',
		'ai_template_max_words'             => max( 5, min( 120, absint( $trigger['ai_template_max_words'] ?? 45 ) ) ),
