		'fake_exit_button_enabled'          => ! empty( $trigger['fake_exit_button_enabled'] ),
		'fake_exit_button_text'             => sanitize_text_field( $trigger['fake_exit_button_text'] ),
		'fake_exit_button_position'         => sanitize_key( $trigger['fake_exit_button_position'] ),
		'fake_exit_button_size'             => absint( $trigger['fake_exit_button_size'] ),
		'override_priority'                 => ! empty( $trigger['override_priority'] ),
		'priority_score'                    => max( 1, min( 1000, absint( $trigger['priority_score'] ) ) ),
		'created_at'                        => max( 0, absint( $trigger['created_at'] ) ),
		'firing_frequency'                  => in_array( $trigger['firing_frequency'], $valid_freq, true ) ? $trigger['firing_frequency'] : 'once_per_session',
		'cooldown_mode'                     => in_array( $trigger['cooldown_mode'], $valid_mode, true ) ? $trigger['cooldown_mode'] : 'once_per_session',
		'cooldown_days'                     => max( 1, min( 365, absint( $trigger['cooldown_days'] ) ) ),
		'dismiss_suppression_limit'         => max( 0, absint( $trigger['dismiss_suppression_limit'] ) ),
		'schedule_enabled'                  => ! empty( $trigger['schedule_enabled'] ),
		'schedule_start_date'               => sanitize_text_field( $trigger['schedule_start_date'] ),
		'schedule_end_date'                 => sanitize_text_field( $trigger['schedule_end_date'] ),
		'schedule_days'                     => sanitize_text_field( $trigger['schedule_days'] ),
		'schedule_time_start'               => sanitize_text_field( $trigger['schedule_time_start'] ),
		'schedule_time_end'                 => sanitize_text_field( $trigger['schedule_time_end'] ),
		'trigger_goal'                      => sanitize_text_field( $trigger['trigger_goal'] ),
		'qa_preview_only'                   => ! empty( $trigger['qa_preview_only'] ),
		'only_if_cart_empty'                => ! empty( $trigger['only_if_cart_empty'] ),
		'suppress_if_visited_url_contains'  => sanitize_textarea_field( $trigger['suppress_if_visited_url_contains'] ),
		'insights_gate_enabled'             => ! empty( $trigger['insights_gate_enabled'] ),
		'insights_gate_window'              => in_array( $trigger['insights_gate_window'], $valid_window, true ) ? $trigger['insights_gate_window'] : '30d',
		'insights_gate_refresh_interval'    => in_array( $trigger['insights_gate_refresh_interval'] ?? '7d', array( '1d', '7d', '30d', 'never' ), true ) ? $trigger['insights_gate_refresh_interval'] : '7d',
		'insights_gate_views_op'            => in_array( $trigger['insights_gate_views_op'] ?? '>=', array( '>=', '<=', 'any' ), true ) ? $trigger['insights_gate_views_op'] : '>=',
		'insights_gate_min_views'           => max( 0, absint( $trigger['insights_gate_min_views'] ) ),
		'insights_gate_conversions_op'      => in_array( $trigger['insights_gate_conversions_op'] ?? '<=', array( '>=', '<=', 'any' ), true ) ? $trigger['insights_gate_conversions_op'] : '<=',
		'insights_gate_max_conversions'     => max( 0, absint( $trigger['insights_gate_max_conversions'] ) ),
		'insights_gate_conversion_rate_op'  => in_array( $trigger['insights_gate_conversion_rate_op'] ?? '<=', array( '>=', '<=', 'any' ), true ) ? $trigger['insights_gate_conversion_rate_op'] : '<=',
		'insights_gate_max_conversion_rate' => max( 0, is_numeric( $trigger['insights_gate_max_conversion_rate'] ) ? floatval( $trigger['insights_gate_max_conversion_rate'] ) : 2.0 ),
		'insights_gate_avg_time_op'         => in_array( $trigger['insights_gate_avg_time_op'] ?? 'any', array( '>=', '<=', 'any' ), true ) ? $trigger['insights_gate_avg_time_op'] : 'any',
		'insights_gate_min_avg_time'        => max( 0, absint( $trigger['insights_gate_min_avg_time'] ?? 0 ) ),
		'insights_gate_scroll_op'           => in_array( $trigger['insights_gate_scroll_op'] ?? 'any', array( '>=', '<=', 'any' ), true ) ? $trigger['insights_gate_scroll_op'] : 'any',
		'insights_gate_min_scroll_depth'    => max( 0, min( 100, absint( $trigger['insights_gate_min_scroll_depth'] ?? 0 ) ) ),
		'insights_gate_add_to_cart_op'      => in_array( $trigger['insights_gate_add_to_cart_op'] ?? 'any', array( '>=', '<=', 'any' ), true ) ? $trigger['insights_gate_add_to_cart_op'] : 'any',
		'insights_gate_min_add_to_cart'     => max( 0, absint( $trigger['insights_gate_min_add_to_cart'] ?? 0 ) ),
		'insights_gate_checkout_flow_op'    => in_array( $trigger['insights_gate_checkout_flow_op'] ?? 'any', array( '>=', '<=', 'any' ), true ) ? $trigger['insights_gate_checkout_flow_op'] : 'any',
		'insights_gate_min_checkout_flow'   => max( 0, min( 100, is_numeric( $trigger['insights_gate_min_checkout_flow'] ?? 0 ) ? floatval( $trigger['insights_gate_min_checkout_flow'] ) : 0 ) ),
		'segment_page_type'                 => $segment_page_type,
		'segment_device'                    => in_array( sanitize_key( $trigger['segment_device'] ), $valid_segment_device, true ) ? sanitize_key( $trigger['segment_device'] ) : 'any',
		'segment_traffic_source'            => in_array( sanitize_key( $trigger['segment_traffic_source'] ), $valid_segment_traffic_source, true ) ? sanitize_key( $trigger['segment_traffic_source'] ) : 'any',
		'segment_behavior_pattern'          => in_array( sanitize_key( $trigger['segment_behavior_pattern'] ), $valid_segment_behavior_pattern, true ) ? sanitize_key( $trigger['segment_behavior_pattern'] ) : 'any',
		'segment_predicted_next_step'       => in_array( sanitize_key( $trigger['segment_predicted_next_step'] ), $valid_segment_predicted_next_step, true ) ? sanitize_key( $trigger['segment_predicted_next_step'] ) : 'any',
		'segment_include_url_patterns'      => sanitize_textarea_field( $trigger['segment_include_url_patterns'] ),
		'segment_exclude_url_patterns'      => sanitize_textarea_field( $trigger['segment_exclude_url_patterns'] ),
		'opportunity_threshold'             => max( 0, min( 100, absint( $trigger['opportunity_threshold'] ) ) ),
		'hysteresis_buffer'                 => max( 0, min( 100, absint( $trigger['hysteresis_buffer'] ) ) ),
	);

	if ( $sanitized_trigger['created_at'] <= 0 ) {
		$sanitized_trigger['created_at'] = time();
	}

	return array_replace( $defaults, $sanitized_trigger );
}

/**
 * Ensures each trigger has a stable unique ID inside one trigger collection.
 *
 * Duplicate IDs make frontend cooldowns and listener cleanup treat separate
 * triggers as the same trigger, so normalize them before saving and rendering.
 *
 * @param array<int,mixed> $triggers Raw or sanitized trigger settings.
 * @return array<int,mixed>
 */
function quorlyx_normalize_trigger_ids( $triggers ) {
	if ( ! is_array( $triggers ) ) {
		return array();
	}

	$normalized = array();
	$seen       = array();

	foreach ( $triggers as $index => $trigger ) {
		if ( ! is_array( $trigger ) ) {
			continue;
		}

		$base_id = sanitize_key( (string) ( $trigger['id'] ?? '' ) );
		if ( '' === $base_id ) {
			$base_id = 'trigger_' . substr(
				md5(
					wp_json_encode(
						array(
							'index'                   => $index,
							'name'                    => (string) ( $trigger['name'] ?? '' ),
							'type'                    => (string) ( $trigger['type'] ?? '' ),
							'target_page_url'         => (string) ( $trigger['target_page_url'] ?? '' ),
							'target_section_selector' => (string) ( $trigger['target_section_selector'] ?? '' ),
							'created_at'              => (string) ( $trigger['created_at'] ?? '' ),
						)
					)
				),
				0,
				12
			);
		}

		$trigger_id = $base_id;
		if ( isset( $seen[ $trigger_id ] ) ) {
			$seed = wp_json_encode(
				array(
					'base_id'                 => $base_id,
					'index'                   => $index,
					'name'                    => (string) ( $trigger['name'] ?? '' ),
					'type'                    => (string) ( $trigger['type'] ?? '' ),
					'target_page_url'         => (string) ( $trigger['target_page_url'] ?? '' ),
					'target_section_selector' => (string) ( $trigger['target_section_selector'] ?? '' ),
					'segment_page_type'       => (string) ( $trigger['segment_page_type'] ?? '' ),
					'created_at'              => (string) ( $trigger['created_at'] ?? '' ),
				)
			);
			$suffix = substr( md5( (string) $seed ), 0, 10 );
			$prefix = substr( $base_id, 0, 64 );
			$try    = 1;

			$trigger_id = $prefix . '_' . $suffix;
			while ( isset( $seen[ $trigger_id ] ) ) {
				$trigger_id = $prefix . '_' . substr( md5( (string) $seed . '|' . $try ), 0, 10 );
				$try++;
			}
		}

		$trigger['id']          = $trigger_id;
		$seen[ $trigger_id ]    = true;
		$normalized[ $index ]   = $trigger;
	}

	return array_values( $normalized );
}

/**
 * Return placeholders supported by locked AI message templates.
 *
 * @return array<string,bool>
 */
function quorlyx_get_ai_message_placeholder_registry() {
	static $registry = null;

	if ( null !== $registry ) {
		return $registry;
	}

	$registry = array_fill_keys(
		array(
			'site_name',
			'site_url',
			'current_url',
			'page_title',
			'post_title',
			'post_type',
			'language',
			'product_name',
			'product_price',
			'product_category',
			'product_sku',
			'cart_count',
			'cart_total',
			'coupon_code',
			'checkout_url',
			'cart_url',
			'trigger_name',
			'trigger_type',
			'behavior_pattern',
			'predicted_next_step',
			'traffic_source',
			'utm_source',
			'utm_medium',
			'utm_campaign',
			'referrer_domain',
			'button_url',
			'button_label',
			'user_question',
			'ai_answer',
			'ai_help_offer',
			'ai_question',
			'ai_reassurance',
			'ai_next_step',
			'ai_button_label',
		),
		true
	);

	return $registry;
}

/**
 * Return the placeholders that AI may fill as short slot values.
 *
 * @return array<string,bool>
 */
function quorlyx_get_ai_message_slot_registry() {
	return array_fill_keys(
		array(
			'ai_help_offer',
			'ai_question',
			'ai_reassurance',
			'ai_next_step',
			'ai_button_label',
		),
		true
	);
}

/**
 * Normalize admin-friendly placeholder spelling to canonical snake_case.
 *
 * @param string $name Raw placeholder name.
 * @return string
 */
function quorlyx_normalize_ai_message_placeholder_name( $name ) {
	$name = strtolower( trim( (string) $name ) );
	$name = trim( $name, "{} \t\n\r\0\x0B" );
	$name = str_replace( array( '-', ' ' ), '_', $name );
	$name = preg_replace( '/[^a-z0-9_]+/', '_', $name );
	$name = preg_replace( '/_+/', '_', (string) $name );
	$name = trim( (string) $name, '_' );

	$aliases = array(
		'product'       => 'product_name',
		'product_title' => 'product_name',
		'page'          => 'page_title',
		'page_name'     => 'page_title',
		'title'         => 'page_title',
		'post'          => 'post_title',
		'post_name'     => 'post_title',
		'campaign'      => 'utm_campaign',
		'source'        => 'utm_source',
		'medium'        => 'utm_medium',
		'url'           => 'current_url',
		'question'      => 'user_question',
		'answer'        => 'ai_answer',
		'chat_answer'   => 'ai_answer',
	);

	return $aliases[ $name ] ?? $name;
}

/**
 * Extract placeholders from a template string.
 *
 * @param string $template Template text.
 * @return array<int,string>
 */
function quorlyx_extract_ai_message_placeholders( $template ) {
	$placeholders = array();

	if ( preg_match_all( '/\{([^{}\r\n]{1,64})\}/', (string) $template, $matches ) ) {
		foreach ( $matches[1] as $raw_name ) {
			$name = quorlyx_normalize_ai_message_placeholder_name( $raw_name );
			if ( '' !== $name ) {
				$placeholders[] = $name;
			}
		}
	}

	return array_values( array_unique( $placeholders ) );
}

/**
 * Parse a comma, space, or newline separated placeholder list.
 *
 * @param string $value Raw placeholder list.
 * @return array<int,string>
 */
function quorlyx_parse_ai_message_placeholder_list( $value ) {
	$items = preg_split( '/[\s,]+/', (string) $value );
	$out   = array();

	foreach ( (array) $items as $item ) {
		$name = quorlyx_normalize_ai_message_placeholder_name( $item );
		if ( '' !== $name ) {
			$out[] = $name;
		}
	}

	return array_values( array_unique( $out ) );
}

/**
 * Determine whether a runtime URL points to the public site homepage.
 *
 * @param string $url Runtime URL.
 * @return bool
 */
function quorlyx_url_is_site_home( $url ) {
	$url = trim( (string) $url );
	if ( '' === $url ) {
		return false;
	}

	$candidate = wp_parse_url( esc_url_raw( $url ) );
	$home      = wp_parse_url( home_url( '/' ) );

	if ( ! is_array( $candidate ) || ! is_array( $home ) ) {
		return false;
	}

	$candidate_host = strtolower( (string) ( $candidate['host'] ?? '' ) );
	$home_host      = strtolower( (string) ( $home['host'] ?? '' ) );

	if ( '' !== $candidate_host && '' !== $home_host && $candidate_host !== $home_host ) {
		return false;
	}

	$candidate_path = '/' . trim( (string) ( $candidate['path'] ?? '/' ), '/' );
	$home_path      = '/' . trim( (string) ( $home['path'] ?? '/' ), '/' );

	if ( '/' !== $candidate_path ) {
		$candidate_path = untrailingslashit( $candidate_path );
	}
	if ( '/' !== $home_path ) {
		$home_path = untrailingslashit( $home_path );
	}

	return $candidate_path === $home_path;
}

/**
 * Get the best title for runtime homepage placeholders.
 *
 * @return string
 */
function quorlyx_get_runtime_homepage_title() {
	$title = '';

	if ( 'page' === get_option( 'show_on_front' ) ) {
		$front_page_id = absint( get_option( 'page_on_front' ) );
		if ( $front_page_id > 0 ) {
			$title = wp_strip_all_tags( (string) get_the_title( $front_page_id ) );
		}
	}

	if ( '' === trim( $title ) ) {
		$title = wp_strip_all_tags( (string) get_bloginfo( 'name' ) );
	}

	return trim( $title );
}

/**
 * Get the best title for the posts index page.
 *
 * @return string
 */
function quorlyx_get_runtime_posts_index_title() {
	$title         = '';
	$posts_page_id = absint( get_option( 'page_for_posts' ) );

	if ( $posts_page_id > 0 ) {
		$title = wp_strip_all_tags( (string) get_the_title( $posts_page_id ) );
	}

	if ( '' === trim( $title ) ) {
		$title = wp_strip_all_tags( (string) get_bloginfo( 'name' ) );
	}

	return trim( $title );
}

/**
 * Build headers for Gemini requests made from the WordPress server.
 *
 * Google HTTP referrer key restrictions check the outbound request's Referer
 * header. Server-side wp_remote_* calls do not include one by default.
 *
 * @param array<string,string> $headers Existing headers.
 * @return array<string,string>
 */
function quorlyx_get_gemini_request_headers( $headers = array() ) {
	$headers = is_array( $headers ) ? $headers : array();
	$referer = esc_url_raw( home_url( '/' ) );
	$parts   = wp_parse_url( $referer );

	if ( $referer ) {
		$headers['Referer'] = $referer;
	}

	if ( is_array( $parts ) && ! empty( $parts['scheme'] ) && ! empty( $parts['host'] ) ) {
		$origin = strtolower( (string) $parts['scheme'] ) . '://' . strtolower( (string) $parts['host'] );
		if ( ! empty( $parts['port'] ) ) {
			$origin .= ':' . absint( $parts['port'] );
		}
		$headers['Origin'] = $origin;
	}

	return $headers;
}

/**
 * Normalize Google model IDs for the Gemini Developer API.
 *
 * @param string $model Model ID from settings or model picker.
 * @return string
 */
function quorlyx_normalize_google_gemini_model_id( $model ) {
	$model = trim( (string) $model );
	foreach ( array( 'publishers/google/models/', 'models/' ) as $prefix ) {
		if ( 0 === strpos( $model, $prefix ) ) {
			$model = substr( $model, strlen( $prefix ) );
		}
	}

	return rawurlencode( $model );
}

/**
 * Determine whether a Google model is unsuitable for generateContent chat calls.
 *
 * @param string $model Model ID from settings or model picker.
 * @return bool
 */
function quorlyx_google_model_requires_interactions_api( $model ) {
	$model = strtolower( trim( rawurldecode( (string) $model ) ) );
	foreach ( array( 'publishers/google/models/', 'models/' ) as $prefix ) {
		if ( 0 === strpos( $model, $prefix ) ) {
			$model = substr( $model, strlen( $prefix ) );
		}
	}

	return 0 === strpos( $model, 'deep-research-' );
}

/**
 * Create a clear error when a Google model cannot be used with generateContent.
 *
 * @return WP_Error
 */
function quorlyx_google_interactions_model_error() {
	return new WP_Error(
		'unsupported_google_interactions_model',
		'The selected Google model requires the Interactions API. Choose a generateContent-compatible Gemini model such as gemini-2.5-flash or gemini-2.5-pro.',
		array(
			'status'      => 400,
			'details'     => 'This model only supports Interactions API.',
			'retry_after' => 0,
		)
	);
}

/**
 * Build a Gemini Developer API generateContent URL.
 *
 * @param string $api_key  API key.
 * @param string $model    Model ID.
 * @return string
 */
function quorlyx_get_google_gemini_generate_content_url( $api_key, $model ) {
	$model   = quorlyx_normalize_google_gemini_model_id( $model );
	$api_key = rawurlencode( (string) $api_key );

	return "https://generativelanguage.googleapis.com/v1beta/models/{$model}:generateContent?key={$api_key}";
}

/**
 * Build safe placeholder context for a trigger message.
 *
 * @param array<string,mixed> $trigger Trigger settings.
 * @param array<string,mixed> $params  Runtime request params.
 * @return array<string,string>
 */
function quorlyx_build_trigger_ai_message_context( $trigger, $params = array() ) {
	$trigger = is_array( $trigger ) ? $trigger : array();
	$params  = is_array( $params ) ? $params : array();

	$url        = esc_url_raw( (string) ( $params['url'] ?? '' ) );
	$product_id = absint( $params['product_id'] ?? 0 );
	$post_id    = 0;

	if ( $url ) {
		$post_id = absint( url_to_postid( $url ) );
	}

	if ( $product_id > 0 ) {
		$post_id = $product_id;
	} elseif ( $post_id > 0 && 'product' === get_post_type( $post_id ) ) {
		$product_id = $post_id;
	}

	$post_title = '';
	$page_title = '';
	$post_type  = '';
	if ( $post_id > 0 ) {
		$post_title = wp_strip_all_tags( (string) get_the_title( $post_id ) );
		$page_title = $post_title;
		$post_type  = sanitize_key( (string) get_post_type( $post_id ) );
	}

	if ( '' === $page_title && ( quorlyx_url_is_site_home( $url ) || is_front_page() ) ) {
		$page_title = quorlyx_get_runtime_homepage_title();
	}
	if ( '' === $page_title && is_home() ) {
		$page_title = quorlyx_get_runtime_posts_index_title();
	}
	if ( '' === $page_title && is_string( get_the_title() ) ) {
		$page_title = wp_strip_all_tags( (string) get_the_title() );
	}
	if ( '' === $page_title && ! empty( $params['page_title'] ) && is_scalar( $params['page_title'] ) ) {
		$page_title = wp_strip_all_tags( (string) $params['page_title'] );
	}
	if ( '' === $page_title ) {
		$document_title = function_exists( 'wp_get_document_title' ) ? wp_strip_all_tags( (string) wp_get_document_title() ) : '';
		$page_title     = trim( $document_title );
	}
	if ( '' === $page_title && ( is_front_page() || is_home() ) ) {
		$page_title = is_home() ? quorlyx_get_runtime_posts_index_title() : quorlyx_get_runtime_homepage_title();
	}
	if ( '' === $page_title && $url ) {
		$url_path = wp_parse_url( $url, PHP_URL_PATH );
		if ( is_string( $url_path ) ) {
			$slug = trim( basename( untrailingslashit( $url_path ) ) );
			if ( '' !== $slug ) {
				$page_title = ucwords( str_replace( array( '-', '_' ), ' ', rawurldecode( $slug ) ) );
			}
		}
	}

	$query_args = array();
	$query      = wp_parse_url( $url, PHP_URL_QUERY );
	if ( is_string( $query ) && '' !== $query ) {
		parse_str( $query, $query_args );
	}
	$utm_source   = isset( $query_args['utm_source'] ) && ! is_array( $query_args['utm_source'] ) ? (string) $query_args['utm_source'] : '';
	$utm_medium   = isset( $query_args['utm_medium'] ) && ! is_array( $query_args['utm_medium'] ) ? (string) $query_args['utm_medium'] : '';
	$utm_campaign = isset( $query_args['utm_campaign'] ) && ! is_array( $query_args['utm_campaign'] ) ? (string) $query_args['utm_campaign'] : '';

	$referrer = sanitize_text_field( (string) ( $params['referrer'] ?? '' ) );
	if ( '' === $referrer && isset( $_SERVER['HTTP_REFERER'] ) ) {
		$referrer = esc_url_raw( wp_unslash( $_SERVER['HTTP_REFERER'] ) );
	}

	$referrer_domain = '';
	if ( '' !== $referrer ) {
		$referrer_host   = wp_parse_url( $referrer, PHP_URL_HOST );
		$referrer_domain = is_string( $referrer_host ) ? sanitize_text_field( $referrer_host ) : '';
	}

	$checkout_url = function_exists( 'wc_get_checkout_url' ) ? esc_url_raw( (string) wc_get_checkout_url() ) : '';
	$cart_url     = function_exists( 'wc_get_cart_url' ) ? esc_url_raw( (string) wc_get_cart_url() ) : '';
	$button_url   = $url ? $url : home_url( '/' );
	$button_label = 'Learn more';

	$product_name     = '';
	$product_price    = '';
	$product_category = '';
	$product_sku      = '';
	if ( $product_id > 0 && function_exists( 'wc_get_product' ) ) {
		$product = wc_get_product( $product_id );
		if ( $product ) {
			$product_name  = wp_strip_all_tags( (string) $product->get_name() );
			$product_price = wp_strip_all_tags( (string) $product->get_price_html() );
			$product_sku   = sanitize_text_field( (string) $product->get_sku() );
			$product_link  = get_permalink( $product_id );
			if ( $product_link ) {
				$button_url = esc_url_raw( $product_link );
			}
			$button_label = 'View Product';

			$terms = wp_get_post_terms( $product_id, 'product_cat', array( 'fields' => 'names' ) );
			if ( ! is_wp_error( $terms ) && ! empty( $terms ) ) {
				$product_category = sanitize_text_field( implode( ', ', array_slice( $terms, 0, 3 ) ) );
			}
		}
	}

	$cart_count = '';
	$cart_total = '';
	if ( function_exists( 'WC' ) && WC() && WC()->cart ) {
		$cart = WC()->cart;
		if ( method_exists( $cart, 'get_cart_contents_count' ) ) {
			$cart_count = (string) (int) $cart->get_cart_contents_count();
		}
		if ( method_exists( $cart, 'get_total' ) ) {
			$cart_total = wp_strip_all_tags( (string) $cart->get_total() );
		}
	}

	$coupon_code = sanitize_text_field( (string) ( $trigger['recovery_cta_coupon_code'] ?? '' ) );
	if ( 'cart_abandonment' === sanitize_key( (string) ( $trigger['type'] ?? '' ) ) && $checkout_url ) {
		$button_url   = $checkout_url;
		$button_label = 'Resume Checkout';
	}
	if ( ! empty( $trigger['recovery_cta_custom_url'] ) ) {
		$button_url = esc_url_raw( (string) $trigger['recovery_cta_custom_url'] );
	}
	if ( ! empty( $trigger['recovery_cta_custom_label'] ) ) {
		$button_label = sanitize_text_field( (string) $trigger['recovery_cta_custom_label'] );
	}

	$trigger_type = sanitize_key( (string) ( $trigger['type'] ?? '' ) );
	$context      = array(
		'site_name'           => sanitize_text_field( (string) get_bloginfo( 'name' ) ),
		'site_url'            => esc_url_raw( home_url( '/' ) ),
		'current_url'         => $url,
		'page_title'          => sanitize_text_field( $page_title ),
		'post_title'          => sanitize_text_field( $post_title ),
		'post_type'           => $post_type,
		'language'            => sanitize_text_field( (string) ( $params['lang'] ?? get_locale() ) ),
		'product_name'        => sanitize_text_field( $product_name ),
		'product_price'       => sanitize_text_field( $product_price ),
		'product_category'    => sanitize_text_field( $product_category ),
		'product_sku'         => sanitize_text_field( $product_sku ),
		'cart_count'          => sanitize_text_field( $cart_count ),
		'cart_total'          => sanitize_text_field( $cart_total ),
		'coupon_code'         => $coupon_code,
		'checkout_url'        => $checkout_url,
		'cart_url'            => $cart_url,
		'trigger_name'        => sanitize_text_field( (string) ( $trigger['name'] ?? '' ) ),
		'trigger_type'        => ucwords( str_replace( '_', ' ', $trigger_type ) ),
		'behavior_pattern'    => 'any' !== ( $trigger['segment_behavior_pattern'] ?? 'any' ) ? sanitize_text_field( (string) $trigger['segment_behavior_pattern'] ) : '',
		'predicted_next_step' => 'any' !== ( $trigger['segment_predicted_next_step'] ?? 'any' ) ? sanitize_text_field( (string) $trigger['segment_predicted_next_step'] ) : '',
		'traffic_source'      => 'any' !== ( $trigger['segment_traffic_source'] ?? 'any' ) ? sanitize_text_field( (string) $trigger['segment_traffic_source'] ) : '',
		'utm_source'          => sanitize_text_field( $utm_source ),
		'utm_medium'          => sanitize_text_field( $utm_medium ),
		'utm_campaign'        => sanitize_text_field( $utm_campaign ),
		'referrer_domain'     => $referrer_domain,
		'button_url'          => esc_url_raw( $button_url ),
		'button_label'        => sanitize_text_field( $button_label ),
	);

	return $context;
}

/**
 * Render placeholders in a message template.
 *
 * @param string               $template Template text.
 * @param array<string,string> $context  Placeholder context.
 * @param array<string,string> $ai_slots AI slot values.
 * @param array<string,mixed>  $args     Render options.
 * @return array<string,mixed>
 */
function quorlyx_render_ai_message_template_text( $template, $context, $ai_slots = array(), $args = array() ) {
	$registry       = quorlyx_get_ai_message_placeholder_registry();
	$missing_policy = sanitize_key( $args['missing_policy'] ?? 'use_fallback_message' );
	$fallback_text  = sanitize_text_field( (string) ( $args['missing_fallback_text'] ?? '' ) );
	$unresolved     = array();
	$unsupported    = array();

	$message = preg_replace_callback(
		'/\{([^{}\r\n]{1,64})\}/',
		function ( $matches ) use ( $context, $ai_slots, $registry, $missing_policy, $fallback_text, &$unresolved, &$unsupported ) {
			$name = quorlyx_normalize_ai_message_placeholder_name( $matches[1] ?? '' );
			if ( '' === $name || empty( $registry[ $name ] ) ) {
				$unsupported[] = $name;
				return '';
			}

			$value = '';
			if ( array_key_exists( $name, $ai_slots ) ) {
				$value = (string) $ai_slots[ $name ];
			} elseif ( array_key_exists( $name, $context ) ) {
				$value = (string) $context[ $name ];
			}

			$value = trim( wp_strip_all_tags( $value ) );
			if ( '' !== $value ) {
				return $value;
			}

			$unresolved[] = $name;
			return 'fallback_text' === $missing_policy ? $fallback_text : '';
		},
		(string) $template
	);

	$message = preg_replace( '/[ \t]+/', ' ', (string) $message );
	$message = preg_replace( '/[ \t]+([,.!?;:])/', '$1', (string) $message );
	if ( ! empty( $args['preserve_linebreaks'] ) ) {
		$message = preg_replace( "/[ \t]*\r?\n[ \t]*/", "\n", (string) $message );
		$message = preg_replace( "/\n{3,}/", "\n\n", (string) $message );
	} else {
		$message = preg_replace( '/\s{2,}/', ' ', (string) $message );
	}

	return array(
		'message'     => trim( (string) $message ),
		'unresolved'  => array_values( array_unique( array_filter( $unresolved ) ) ),
		'unsupported' => array_values( array_unique( array_filter( $unsupported ) ) ),
	);
}

/**
 * Validate a rendered trigger message before display.
 *
 * @param string              $message       Rendered message.
 * @param array<string,mixed> $render_result Render metadata.
 * @param int                 $max_words     Maximum words.
 * @param string              $missing_policy Missing placeholder policy.
 * @return array<string,mixed>
 */
function quorlyx_validate_ai_message_template_output( $message, $render_result = array(), $max_words = 45, $missing_policy = 'use_fallback_message' ) {
	$errors     = array();
	$plain_text = trim( wp_strip_all_tags( (string) $message ) );

	if ( '' === $plain_text ) {
		$errors[] = 'empty_message';
	}
	if ( ! empty( $render_result['unsupported'] ) ) {
		$errors[] = 'unsupported_placeholder';
	}
	if ( 'use_fallback_message' === $missing_policy && ! empty( $render_result['unresolved'] ) ) {
		$errors[] = 'unresolved_placeholder';
	}
	if ( preg_match( '/\{[^{}]+\}/', (string) $message ) ) {
		$errors[] = 'raw_placeholder_left';
	}
	if ( preg_match( '/<[^>]+>/', (string) $message ) ) {
		$errors[] = 'html_not_allowed';
	}

	$words = preg_split( '/\s+/', $plain_text, -1, PREG_SPLIT_NO_EMPTY );
	if ( $max_words > 0 && count( (array) $words ) > $max_words ) {
		$errors[] = 'too_long';
	}

	if ( preg_match_all( '/\[(BUTTON|SEARCH):[^\]]+\]\(([^)]+)\)/i', (string) $message, $button_matches ) && count( $button_matches[0] ) > 1 ) {
		$errors[] = 'too_many_buttons';
	}

	if ( preg_match( '/\b(I watched|I tracked|I know you are leaving|I saw you|your behavior tells me)\b/i', (string) $message ) ) {
		$errors[] = 'creepy_tracking_language';
	}
	if ( preg_match( '/\b(guaranteed delivery|guaranteed results|guaranteed discount|guaranteed stock|definitely in stock)\b/i', (string) $message ) ) {
		$errors[] = 'unsafe_claim';
	}

	return array(
		'valid'  => empty( $errors ),
		'errors' => array_values( array_unique( $errors ) ),
	);
}

/**
 * Parse provider output for template AI slots.
 *
 * @param string $response Raw AI response.
 * @return array<string,string>
 */
function quorlyx_parse_ai_message_slot_response( $response ) {
	$response = trim( (string) $response );
	$response = preg_replace( '/^```(?:json)?\s*/i', '', $response );
	$response = preg_replace( '/\s*```$/', '', (string) $response );

	if ( preg_match( '/\{.*\}/s', (string) $response, $match ) ) {
		$response = $match[0];
	}

	$decoded = json_decode( (string) $response, true );
	if ( ! is_array( $decoded ) ) {
		return array();
	}

	$allowed = quorlyx_get_ai_message_slot_registry();
	$slots   = array();
	foreach ( $decoded as $key => $value ) {
		$name = quorlyx_normalize_ai_message_placeholder_name( (string) $key );
		if ( empty( $allowed[ $name ] ) ) {
			continue;
		}

		$value = wp_strip_all_tags( (string) $value );
		$value = preg_replace( '/\[(BUTTON|SEARCH):[^\]]+\]\(([^)]+)\)/i', '', (string) $value );
		$value = preg_replace( '/\s+/', ' ', (string) $value );
		$value = trim( (string) $value );
		if ( '' !== $value ) {
			$slots[ $name ] = substr( sanitize_text_field( $value ), 0, 180 );
		}
	}

	return $slots;
}

/**
 * Ask AI for JSON slot values used by a locked message template.
 *
 * @param string               $provider          AI provider.
 * @param string               $api_key           Provider API key.
 * @param string               $model             Provider model.
 * @param string               $persona           Admin persona.
 * @param array<string,string> $context           Placeholder context.
 * @param array<int,string>    $slots             Slot names.
 * @param string               $slot_instructions Admin slot instructions.
 * @param string               $site_context      Site context text.
 * @param float                $temperature       AI temperature.
 * @param string               $repair_note       Optional repair note.
 * @return array<string,string>|WP_Error
 */
function quorlyx_generate_ai_message_slots( $provider, $api_key, $model, $persona, $context, $slots, $slot_instructions, $site_context = '', $temperature = 0.3, $repair_note = '', $args = array() ) {
	$allowed = quorlyx_get_ai_message_slot_registry();
	$slots   = array_values(
		array_filter(
			array_unique( array_map( 'quorlyx_normalize_ai_message_placeholder_name', (array) $slots ) ),
			function ( $slot ) use ( $allowed ) {
				return ! empty( $allowed[ $slot ] );
			}
		)
	);

	if ( empty( $slots ) ) {
		return array();
	}

	$default_slot_rules = array(
		'ai_help_offer'   => 'one short helpful offer under 12 words',
		'ai_question'     => 'one short question topic under 10 words',
		'ai_reassurance'  => 'one short reassurance phrase under 12 words',
		'ai_next_step'    => 'one short next-step phrase under 10 words',
		'ai_button_label' => 'one button label, 2 to 4 words',
	);

	$slot_schema = array();
	foreach ( $slots as $slot ) {
		$slot_schema[ $slot ] = $default_slot_rules[ $slot ] ?? 'short safe text';
	}

	$context_json = wp_json_encode(
		array_filter(
			$context,
			function ( $value ) {
				return '' !== trim( (string) $value );
			}
		),
		JSON_UNESCAPED_SLASHES
	);
	$schema_json  = wp_json_encode( $slot_schema, JSON_UNESCAPED_SLASHES );
	$repair_block = '' !== trim( $repair_note ) ? "\nRepair note: " . sanitize_text_field( $repair_note ) : '';
	$purpose      = sanitize_text_field( (string) ( $args['purpose'] ?? 'a proactive chat message' ) );
	$user_question = sanitize_textarea_field( (string) ( $args['user_question'] ?? '' ) );
	$user_question_block = '' !== $user_question ? "\nUser question:\n{$user_question}\n" : '';
	$persona      = trim( (string) $persona );
	if ( '' === $persona ) {
		$persona = 'You are a concise website assistant.';
	}

	$system_prompt = $persona . "\n\nFill only the requested JSON slots for {$purpose}. Do not write the final message. Do not include HTML, markdown, URLs, discounts, deadlines, prices, stock claims, delivery promises, or private user assumptions unless those facts are present in context. Keep every value short and natural.\n{$user_question_block}\nRuntime context JSON:\n{$context_json}\n\nSite context:\n{$site_context}\n\nRequired JSON keys and rules:\n{$schema_json}\n\nAdmin slot instructions:\n" . trim( (string) $slot_instructions ) . $repair_block;
	$history       = array(
		array(
			'role'  => 'user',
			'parts' => array(
				array(
					'text' => 'Return JSON only for the requested slots. No prose before or after the JSON.',
				),
			),
		),
	);

	$response = quorlyx_call_ai_api_with_retry( $provider, $api_key, $model, $system_prompt, $history, $temperature );
	if ( is_wp_error( $response ) ) {
		return $response;
	}

	return quorlyx_parse_ai_message_slot_response( $response );
}

/**
 * Build a sanitized fallback message for trigger AI output.
 *
 * @param array<string,mixed>  $trigger            Trigger settings.
 * @param array<string,string> $context            Placeholder context.
 * @param string               $default_button_url Default button URL.
 * @return string
 */
function quorlyx_get_trigger_ai_message_fallback( $trigger, $context, $default_button_url = '' ) {
	$fallback = (string) ( $trigger['ai_fallback_message'] ?? '' );
	if ( '' === trim( $fallback ) ) {
		$fallback = (string) ( $trigger['proactive_message'] ?? '' );
	}
	if ( '' === trim( $fallback ) ) {
		$fallback = 'Can I help with a quick question before you continue?';
	}

	$rendered = quorlyx_render_ai_message_template_text(
		$fallback,
		$context,
		array(),
		array(
			'missing_policy' => 'hide',
		)
	);

	return quorlyx_sanitize_ai_output( $rendered['message'], $default_button_url );
}

/**
 * Normalize optional normal-chat response format settings.
 *
 * @param array<string,mixed> $settings Variation settings.
 * @return array<string,mixed>
 */
function quorlyx_get_chat_response_format_settings( $settings ) {
	$settings                         = is_array( $settings ) ? $settings : array();
	$valid_modes                      = array( 'free_ai', 'template_locked', 'hybrid_required_tokens' );
	$valid_missing_placeholder_policy = array( 'use_fallback_message', 'hide', 'fallback_text' );
	$mode                             = sanitize_key( (string) ( $settings['chat_format_mode'] ?? 'free_ai' ) );
	if ( ! in_array( $mode, $valid_modes, true ) ) {
		$mode = 'free_ai';
	}

	$missing_policy = sanitize_key( (string) ( $settings['chat_missing_placeholder_policy'] ?? 'use_fallback_message' ) );
	if ( ! in_array( $missing_policy, $valid_missing_placeholder_policy, true ) ) {
		$missing_policy = 'use_fallback_message';
	}

	$template              = trim( sanitize_textarea_field( (string) ( $settings['chat_message_template'] ?? '' ) ) );
	$required_placeholders = trim( sanitize_textarea_field( (string) ( $settings['chat_required_placeholders'] ?? '' ) ) );
	$slot_instructions     = trim( sanitize_textarea_field( (string) ( $settings['chat_slot_instructions'] ?? '' ) ) );
	$max_words             = max( 10, min( 800, absint( $settings['chat_template_max_words'] ?? 220 ) ) );
	$enabled               = ( 'template_locked' === $mode && '' !== $template )
		|| ( 'hybrid_required_tokens' === $mode && '' !== $required_placeholders );

	return array(
		'enabled'                    => $enabled,
		'mode'                       => $mode,
		'message_template'           => $template,
		'required_placeholders'      => $required_placeholders,
		'slot_instructions'          => $slot_instructions,
		'missing_placeholder_policy' => $missing_policy,
		'template_max_words'         => $max_words,
		'signature'                  => $enabled ? md5( wp_json_encode( array( $mode, $template, $required_placeholders, $slot_instructions, $missing_policy, $max_words ) ) ) : 'free',
	);
}

/**
 * Build safe placeholder context for normal chat response templates.
 *
 * @param array<string,mixed> $request_body  Public chat request body.
 * @param string              $user_question User question.
 * @param string              $ai_answer     Assistant answer.
 * @return array<string,string>
 */
function quorlyx_build_chat_response_format_context( $request_body, $user_question, $ai_answer = '' ) {
	$request_body = is_array( $request_body ) ? $request_body : array();
	$product_id   = absint( $request_body['product_id'] ?? 0 );
	if ( $product_id <= 0 && isset( $request_body['woo'] ) && is_array( $request_body['woo'] ) ) {
		$product_id = absint( $request_body['woo']['product_id'] ?? 0 );
	}

	$context = quorlyx_build_trigger_ai_message_context(
		array(),
		array(
			'url'        => esc_url_raw( (string) ( $request_body['url'] ?? '' ) ),
			'product_id' => $product_id,
			'page_title' => sanitize_text_field( (string) ( $request_body['page_title'] ?? '' ) ),
			'lang'       => get_locale(),
		)
	);

	$context['user_question'] = trim( wp_strip_all_tags( (string) $user_question ) );
	$context['ai_answer']     = trim( (string) $ai_answer );

	return $context;
}

/**
 * Append optional Hybrid normal-chat placeholder requirements to the answer prompt.
 *
 * @param string              $system_prompt   Existing prompt.
 * @param array<string,mixed> $format_settings Chat format settings.
 * @param array<string,mixed> $request_body    Public chat request body.
 * @param string              $user_question   User question.
 * @return string
 */
function quorlyx_apply_chat_hybrid_format_prompt( $system_prompt, $format_settings, $request_body, $user_question ) {
	if ( empty( $format_settings['enabled'] ) || 'hybrid_required_tokens' !== ( $format_settings['mode'] ?? 'free_ai' ) ) {
		return $system_prompt;
	}

	$context  = quorlyx_build_chat_response_format_context( $request_body, $user_question, '' );
	$registry = quorlyx_get_ai_message_placeholder_registry();
	$lines    = array();
	foreach ( quorlyx_parse_ai_message_placeholder_list( (string) ( $format_settings['required_placeholders'] ?? '' ) ) as $placeholder ) {
		if ( 'ai_answer' === $placeholder || empty( $registry[ $placeholder ] ) ) {
			continue;
		}
		$value = trim( (string) ( $context[ $placeholder ] ?? '' ) );
		if ( '' !== $value ) {
			$lines[] = '- {' . $placeholder . '}: ' . $value;
		}
	}

	if ( empty( $lines ) ) {
		return $system_prompt;
	}

	return $system_prompt . "\n\nADMIN RESPONSE FORMAT REQUIREMENT:\nInclude these resolved values naturally in the answer when relevant. Do not invent missing values, prices, stock, discounts, delivery dates, or guarantees.\n" . implode( "\n", $lines );
}

/**
 * Apply a locked normal-chat response template after the regular answer is generated.
 *
 * @param string              $content         Assistant answer.
 * @param array<string,mixed> $format_settings Chat format settings.
 * @param array<string,mixed> $request_body    Public chat request body.
 * @param string              $user_question   User question.
 * @param string              $provider        AI provider.
 * @param string              $api_key         Provider API key.
 * @param string              $model           Provider model.
 * @param string              $persona         Persona prompt.
 * @param string              $site_context    Site context.
 * @param float               $temperature     Temperature.
 * @return string
 */
function quorlyx_apply_chat_response_format_template( $content, $format_settings, $request_body, $user_question, $provider, $api_key, $model, $persona, $site_context = '', $temperature = 0.3 ) {
	if ( empty( $format_settings['enabled'] ) || 'template_locked' !== ( $format_settings['mode'] ?? 'free_ai' ) ) {
		return $content;
	}

	$template = trim( (string) ( $format_settings['message_template'] ?? '' ) );
	if ( '' === $template ) {
		return $content;
	}

	$template_placeholders = quorlyx_extract_ai_message_placeholders( $template );
	if ( ! in_array( 'ai_answer', $template_placeholders, true ) ) {
		Quorlyx_Pro_Logger::log(
			'warning',
			'Normal chat response template skipped because it does not include {ai_answer}.',
			array(
				'component' => 'chat_format',
				'operation' => 'normal_chat_template',
			)
		);
		return $content;
	}

	$context       = quorlyx_build_chat_response_format_context( $request_body, $user_question, $content );
	$slot_registry = quorlyx_get_ai_message_slot_registry();
	$slot_names    = array_values(
		array_filter(
			$template_placeholders,
			function ( $placeholder ) use ( $slot_registry ) {
				return ! empty( $slot_registry[ $placeholder ] );
			}
		)
	);
	$slot_values   = array();

	if ( ! empty( $slot_names ) && ! empty( $api_key ) && ! empty( $model ) ) {
		$generated_slots = quorlyx_generate_ai_message_slots(
			$provider,
			$api_key,
			$model,
			$persona,
			$context,
			$slot_names,
			(string) ( $format_settings['slot_instructions'] ?? '' ),
			$site_context,
			$temperature,
			'',
			array(
				'purpose'       => 'a normal chat response template',
				'user_question' => $user_question,
			)
		);
		if ( is_wp_error( $generated_slots ) ) {
			Quorlyx_Pro_Logger::log(
				'warning',
				'Normal chat response template AI slot generation failed; using the original answer.',
				array(
					'component' => 'chat_format',
					'operation' => 'normal_chat_slot_generation',
					'error'     => $generated_slots->get_error_code(),
				)
			);
			return $content;
		}
		$slot_values = is_array( $generated_slots ) ? $generated_slots : array();
	}

	$missing_policy = sanitize_key( (string) ( $format_settings['missing_placeholder_policy'] ?? 'use_fallback_message' ) );
	$rendered       = quorlyx_render_ai_message_template_text(
		$template,
		$context,
		$slot_values,
		array(
			'missing_policy'        => $missing_policy,
			'missing_fallback_text' => 'this page',
			'preserve_linebreaks'   => true,
		)
	);
	$default_button_url = $context['button_url'] ?? '';
	$message            = quorlyx_sanitize_ai_output( $rendered['message'], $default_button_url );
	$validation         = quorlyx_validate_ai_message_template_output(
		$message,
		$rendered,
		max( 10, min( 800, absint( $format_settings['template_max_words'] ?? 220 ) ) ),
		$missing_policy
	);
	$validation_errors = array_diff( (array) ( $validation['errors'] ?? array() ), array( 'too_many_buttons' ) );
	if ( empty( $message ) || ! empty( $validation_errors ) ) {
		Quorlyx_Pro_Logger::log(
			'warning',
			'Normal chat response template failed validation; using the original answer.',
			array(
				'component' => 'chat_format',
				'operation' => 'normal_chat_template_validation',
				'errors'    => array_values( $validation_errors ),
			)
		);
		return $content;
	}

	return $message;
}

/**
 * Normalize trigger roadmap settings against defaults.
 *
 * @param array<string,mixed> $options Plugin options array.
 * @return array<string,mixed>
 */
function quorlyx_get_normalized_trigger_roadmap_settings( $options = array() ) {
	$defaults = quorlyx_get_trigger_roadmap_defaults();
	$current  = array();

	if ( is_array( $options ) && isset( $options['trigger_roadmap'] ) && is_array( $options['trigger_roadmap'] ) ) {
		$current = $options['trigger_roadmap'];
	}

	$settings = array_replace_recursive( $defaults, $current );

	$settings['cooldown_mode']                          = in_array( $settings['cooldown_mode'], array( 'once_per_session', 'once_per_page', 'once_per_day', 'once_per_n_days', 'disabled' ), true ) ? $settings['cooldown_mode'] : 'once_per_session';
	$settings['cooldown_days']                          = max( 1, min( 365, absint( $settings['cooldown_days'] ) ) );
	$settings['dismiss_suppression_limit']              = max( 0, absint( $settings['dismiss_suppression_limit'] ) );
	$settings['priority_tie_breaker']                   = in_array( $settings['priority_tie_breaker'], array( 'specificity', 'created_at' ), true ) ? $settings['priority_tie_breaker'] : 'specificity';
	$settings['scheduling_enabled']                     = ! empty( $settings['scheduling_enabled'] );
	$settings['qa_preview_enabled']                     = ! empty( $settings['qa_preview_enabled'] );
	$settings['new_trigger_types_enabled']              = ! empty( $settings['new_trigger_types_enabled'] );
	$settings['insights_gate']['enabled']               = ! empty( $settings['insights_gate']['enabled'] );
	$settings['insights_gate']['window']                = in_array( $settings['insights_gate']['window'], array( '7d', '30d' ), true ) ? $settings['insights_gate']['window'] : '30d';
	$settings['insights_gate']['min_views']             = max( 0, absint( $settings['insights_gate']['min_views'] ) );
	$settings['insights_gate']['max_conversions']       = max( 0, absint( $settings['insights_gate']['max_conversions'] ) );
	$settings['insights_gate']['max_conversion_rate']   = max( 0, is_numeric( $settings['insights_gate']['max_conversion_rate'] ) ? floatval( $settings['insights_gate']['max_conversion_rate'] ) : 2.0 );
	$settings['insights_gate']['segmentation_enabled']  = ! empty( $settings['insights_gate']['segmentation_enabled'] );
	$settings['insights_gate']['opportunity_threshold'] = max( 0, min( 100, absint( $settings['insights_gate']['opportunity_threshold'] ) ) );
	$settings['insights_gate']['hysteresis_enabled']    = ! empty( $settings['insights_gate']['hysteresis_enabled'] );

	return $settings;
}

/**
 * Migrate stored trigger roadmap settings to the latest normalized shape.
 *
 * @return void
 */
function quorlyx_maybe_migrate_trigger_roadmap_options() {
	if ( ! is_admin() ) {
		return;
	}

	$defaults = quorlyx_get_global_defaults();
	$options  = get_option( 'quorlyx_options', $defaults );
	$options  = array_replace_recursive( $defaults, is_array( $options ) ? $options : array() );

	$before = wp_json_encode( $options );

	$options['trigger_roadmap'] = quorlyx_get_normalized_trigger_roadmap_settings( $options );

	$normalized_triggers = array();
	$triggers            = is_array( $options['triggers'] ?? null ) ? $options['triggers'] : array();
	foreach ( $triggers as $trigger ) {
		if ( ! is_array( $trigger ) ) {
			continue;
		}
		$normalized_triggers[] = quorlyx_sanitize_trigger_settings( $trigger );
	}
	$options['triggers'] = quorlyx_normalize_trigger_ids( $normalized_triggers );

	$after = wp_json_encode( $options );
	if ( $before !== $after ) {
		update_option( 'quorlyx_options', $options );
	}
}
add_action( 'admin_init', 'quorlyx_maybe_migrate_trigger_roadmap_options', 5 );

