/**
 * Determine whether the current admin screen belongs to Quorlyx.
 *
 * @return bool
 */
function quorlyx_is_plugin_admin_screen() {
	if ( ! is_admin() ) {
		return false;
	}

	if ( function_exists( 'get_current_screen' ) ) {
		$screen = get_current_screen();
		if ( $screen && is_string( $screen->id ) && false !== strpos( $screen->id, 'quorlyx' ) ) {
			return true;
		}
	}

	// phpcs:disable WordPress.Security.NonceVerification.Recommended -- Read-only admin screen context resolution.
	$page = isset( $_GET['page'] ) ? sanitize_key( wp_unslash( $_GET['page'] ) ) : '';
	if ( '' !== $page && 0 === strpos( $page, 'quorlyx-' ) ) {
		return true;
	}

	$post_type = isset( $_GET['post_type'] ) ? sanitize_key( wp_unslash( $_GET['post_type'] ) ) : '';
	// phpcs:enable WordPress.Security.NonceVerification.Recommended
	return in_array( $post_type, array( 'quorlyx_submission', 'quorlyx_conversation' ), true );
}

