/**
 * Return trigger configuration by trigger ID.
 *
 * @param string $trigger_id Trigger ID.
 * @return array<string,string>
 */
function quorlyx_get_trigger_definition_by_id( $trigger_id ) {
	$trigger_id = sanitize_key( (string) $trigger_id );
	if ( '' === $trigger_id ) {
		return array();
	}

	static $trigger_map = null;
	if ( null === $trigger_map ) {
		$trigger_map = array();
		$defaults    = quorlyx_get_global_defaults();
		$options     = get_option( 'quorlyx_options', $defaults );
		$options     = array_replace_recursive( $defaults, is_array( $options ) ? $options : array() );
		$triggers    = quorlyx_normalize_trigger_ids( is_array( $options['triggers'] ?? null ) ? $options['triggers'] : array() );

		foreach ( $triggers as $trigger ) {
			if ( ! is_array( $trigger ) ) {
				continue;
			}

			$id = sanitize_key( (string) ( $trigger['id'] ?? '' ) );
			if ( '' === $id ) {
				continue;
			}

			$trigger_map[ $id ] = array(
				'id'   => $id,
				'name' => sanitize_text_field( (string) ( $trigger['name'] ?? $id ) ),
				'type' => sanitize_key( (string) ( $trigger['type'] ?? '' ) ),
			);
		}
	}

	return isset( $trigger_map[ $trigger_id ] ) ? $trigger_map[ $trigger_id ] : array();
}

/**
 * Get normalized source value for a conversation.
 *
 * @param int $post_id Conversation post ID.
 * @return string
 */
function quorlyx_get_conversation_source_value( $post_id ) {
	$post_id = absint( $post_id );
	if ( $post_id <= 0 ) {
		return 'normal';
	}

	$row    = quorlyx_get_conversation_record_by_post_id( $post_id );
	$source = sanitize_key( (string) ( $row['source'] ?? '' ) );
	if ( '' === $source ) {
		$source = sanitize_key( (string) get_post_meta( $post_id, 'quorlyx_source', true ) );
	}
	if ( '' === $source ) {
		$trigger_id = sanitize_key( (string) ( $row['trigger_id'] ?? get_post_meta( $post_id, 'quorlyx_trigger_id', true ) ) );
		$source     = '' !== $trigger_id ? 'trigger' : 'normal';
	}

	if ( ! in_array( $source, array( 'normal', 'trigger' ), true ) ) {
		$source = 'normal';
	}

	return $source;
}

/**
 * Resolve conversation origin details for rendering/export.
 *
 * @param int $post_id Conversation post ID.
 * @return array<string,string>
 */
function quorlyx_get_conversation_origin_details( $post_id ) {
	$post_id      = absint( $post_id );
	$source       = quorlyx_get_conversation_source_value( $post_id );
	$row          = quorlyx_get_conversation_record_by_post_id( $post_id );
	$trigger_id   = sanitize_key( (string) ( $row['trigger_id'] ?? '' ) );
	$trigger_name = sanitize_text_field( (string) ( $row['trigger_name'] ?? '' ) );
	$trigger_type = sanitize_key( (string) ( $row['trigger_type'] ?? '' ) );
	if ( '' === $trigger_id ) {
		$trigger_id = sanitize_key( (string) get_post_meta( $post_id, 'quorlyx_trigger_id', true ) );
	}
	if ( '' === $trigger_name ) {
		$trigger_name = sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_trigger_name', true ) );
	}
	if ( '' === $trigger_type ) {
		$trigger_type = sanitize_key( (string) get_post_meta( $post_id, 'quorlyx_trigger_type', true ) );
	}

	if ( 'trigger' === $source && '' !== $trigger_id && ( '' === $trigger_name || '' === $trigger_type ) ) {
		$trigger_meta = quorlyx_get_trigger_definition_by_id( $trigger_id );
		if ( '' === $trigger_name && ! empty( $trigger_meta['name'] ) ) {
			$trigger_name = sanitize_text_field( (string) $trigger_meta['name'] );
		}
		if ( '' === $trigger_type && ! empty( $trigger_meta['type'] ) ) {
			$trigger_type = sanitize_key( (string) $trigger_meta['type'] );
		}
	}

	if ( 'trigger' !== $source ) {
		$trigger_id   = '';
		$trigger_name = '';
		$trigger_type = '';
	}

	return array(
		'source'       => $source,
		'source_label' => 'trigger' === $source ? 'Trigger' : 'Normal',
		'trigger_id'   => $trigger_id,
		'trigger_name' => $trigger_name,
		'trigger_type' => $trigger_type,
	);
}

/**
 * Hash sensitive identifiers for indexed lookups without storing raw values.
 *
 * @param string $value Raw value.
 * @return string
 */
function quorlyx_hash_storage_identifier( $value ) {
	$value = trim( (string) $value );
	if ( '' === $value ) {
		return '';
	}

	return hash( 'sha256', strtolower( $value ) . '|' . wp_salt( 'auth' ) );
}

/**
 * Hash an IP address for conversation matching.
 *
 * @param string $ip Raw IP address.
 * @return string
 */
function quorlyx_hash_ip_address( $ip ) {
	$ip = trim( (string) $ip );
	if ( '' === $ip ) {
		return '';
	}

	return quorlyx_hash_storage_identifier( $ip );
}

/**
 * Extract message text from a Gemini-style history entry.
 *
 * @param array<string,mixed> $message Message payload.
 * @return string
 */
function quorlyx_get_history_message_text( $message ) {
	if ( ! is_array( $message ) ) {
		return '';
	}

	$text = $message['parts'][0]['text'] ?? '';

	return is_scalar( $text ) ? (string) $text : '';
}

/**
 * Normalize one stored message row back into a chat history entry.
 *
 * @param array<string,mixed> $message Message payload.
 * @return array<string,mixed>
 */
function quorlyx_normalize_history_message_for_storage( $message ) {
	$role = sanitize_key( (string) ( $message['role'] ?? 'user' ) );
	if ( ! in_array( $role, array( 'user', 'model' ), true ) ) {
		$role = 'user';
	}

	$normalized = array(
		'role'  => $role,
		'parts' => array(
			array(
				'text' => quorlyx_get_history_message_text( $message ),
			),
		),
	);

	if ( ! empty( $message['routing'] ) ) {
		$normalized['routing'] = 1;
	}
	if ( ! empty( $message['local'] ) ) {
		$normalized['local'] = 1;
	}

	return $normalized;
}

/**
 * Get a table-backed conversation row by mirrored post ID.
 *
 * @param int $post_id Conversation CPT post ID.
 * @return array<string,mixed>
 */
function quorlyx_get_conversation_record_by_post_id( $post_id ) {
	$post_id = absint( $post_id );
	if ( $post_id <= 0 || ! quorlyx_conversations_table_exists() ) {
		return array();
	}

	global $wpdb;
	$table_name = quorlyx_get_conversations_table_name();

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Table name is a trusted plugin table helper.
	$row = $wpdb->get_row(
		$wpdb->prepare(
			"SELECT * FROM {$table_name} WHERE post_id = %d LIMIT 1",
			$post_id
		),
		ARRAY_A
	);

	return is_array( $row ) ? $row : array();
}

/**
 * Insert or update the compact conversation summary row.
 *
 * @param int                 $post_id Conversation CPT post ID.
 * @param array<string,mixed> $data    Conversation fields.
 * @return int Table row ID, or 0 on failure.
 */
function quorlyx_upsert_conversation_record( $post_id, $data = array() ) {
	$post_id = absint( $post_id );
	if ( $post_id <= 0 || ! quorlyx_conversations_table_exists() ) {
		return 0;
	}

	global $wpdb;
	$table_name = quorlyx_get_conversations_table_name();
	$existing   = quorlyx_get_conversation_record_by_post_id( $post_id );
	$now        = gmdate( 'Y-m-d H:i:s' );

	$record = array(
		'post_id'             => $post_id,
		'persistent_user_id'  => sanitize_text_field( (string) ( $data['persistent_user_id'] ?? ( $existing['persistent_user_id'] ?? '' ) ) ),
		'variation'           => sanitize_key( (string) ( $data['variation'] ?? ( $existing['variation'] ?? 'a' ) ) ),
		'source'              => sanitize_key( (string) ( $data['source'] ?? ( $existing['source'] ?? 'normal' ) ) ),
		'trigger_id'          => sanitize_key( (string) ( $data['trigger_id'] ?? ( $existing['trigger_id'] ?? '' ) ) ),
		'trigger_name'        => sanitize_text_field( (string) ( $data['trigger_name'] ?? ( $existing['trigger_name'] ?? '' ) ) ),
		'trigger_type'        => sanitize_key( (string) ( $data['trigger_type'] ?? ( $existing['trigger_type'] ?? '' ) ) ),
		'message_count'       => absint( $data['message_count'] ?? ( $existing['message_count'] ?? 0 ) ),
		'conversions_count'   => absint( $data['conversions_count'] ?? ( $existing['conversions_count'] ?? 0 ) ),
		'conversion_details'  => isset( $data['conversion_details'] ) ? wp_json_encode( $data['conversion_details'] ) : ( $existing['conversion_details'] ?? '' ),
		'lead_interest'       => sanitize_text_field( (string) ( $data['lead_interest'] ?? ( $existing['lead_interest'] ?? '' ) ) ),
		'lead_status'         => sanitize_text_field( (string) ( $data['lead_status'] ?? ( $existing['lead_status'] ?? '' ) ) ),
		'lead_urgency'        => sanitize_text_field( (string) ( $data['lead_urgency'] ?? ( $existing['lead_urgency'] ?? '' ) ) ),
		'user_agent'          => sanitize_text_field( (string) ( $data['user_agent'] ?? ( $existing['user_agent'] ?? '' ) ) ),
		'ip_hash'             => sanitize_text_field( (string) ( $data['ip_hash'] ?? ( $existing['ip_hash'] ?? '' ) ) ),
		'device'              => sanitize_key( (string) ( $data['device'] ?? ( $existing['device'] ?? '' ) ) ),
		'country'             => strtoupper( sanitize_text_field( (string) ( $data['country'] ?? ( $existing['country'] ?? '' ) ) ) ),
		'city'                => sanitize_text_field( (string) ( $data['city'] ?? ( $existing['city'] ?? '' ) ) ),
		'location'            => sanitize_text_field( (string) ( $data['location'] ?? ( $existing['location'] ?? '' ) ) ),
		'created_at'          => sanitize_text_field( (string) ( $existing['created_at'] ?? $now ) ),
		'updated_at'          => $now,
		'last_activity'       => absint( $data['last_activity'] ?? ( $existing['last_activity'] ?? time() ) ),
	);

	if ( 'b' !== $record['variation'] ) {
		$record['variation'] = 'a';
	}
	if ( ! in_array( $record['source'], array( 'normal', 'trigger' ), true ) ) {
		$record['source'] = 'normal';
	}

	if ( ! empty( $existing['id'] ) ) {
		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Compact summary table update for conversation hot path.
		$result = $wpdb->update(
			$table_name,
			$record,
			array( 'id' => absint( $existing['id'] ) )
		);

		return false === $result ? 0 : absint( $existing['id'] );
	}

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery -- Compact summary table insert for conversation hot path.
	$result = $wpdb->insert( $table_name, $record );

	return false === $result ? 0 : absint( $wpdb->insert_id );
}

/**
 * Find a recent conversation using indexed custom-table identifiers.
 *
 * @param string $persistent_user_id Persistent browser user ID.
 * @param string $ip_hash            Hashed IP fallback.
 * @return int Conversation CPT post ID.
 */
function quorlyx_find_recent_conversation_post_id( $persistent_user_id = '', $ip_hash = '' ) {
	if ( ! quorlyx_conversations_table_exists() ) {
		return 0;
	}

	$persistent_user_id = sanitize_text_field( (string) $persistent_user_id );
	$ip_hash            = sanitize_text_field( (string) $ip_hash );
	$recent_threshold   = time() - DAY_IN_SECONDS;

	global $wpdb;
	$table_name = quorlyx_get_conversations_table_name();

	if ( '' !== $persistent_user_id ) {
		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Table name is a trusted plugin table helper.
		$post_id = $wpdb->get_var(
			$wpdb->prepare(
				"SELECT post_id FROM {$table_name} WHERE persistent_user_id = %s AND last_activity > %d ORDER BY last_activity DESC LIMIT 1",
				$persistent_user_id,
				$recent_threshold
			)
		);
		if ( $post_id ) {
			return absint( $post_id );
		}
	}

	if ( '' === $ip_hash ) {
		return 0;
	}

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Table name is a trusted plugin table helper.
	$post_id = $wpdb->get_var(
		$wpdb->prepare(
			"SELECT post_id FROM {$table_name} WHERE ip_hash = %s AND last_activity > %d ORDER BY last_activity DESC LIMIT 1",
			$ip_hash,
			$recent_threshold
		)
	);

	return $post_id ? absint( $post_id ) : 0;
}

/**
 * Load conversation history from the message table.
 *
 * @param int $post_id Conversation CPT post ID.
 * @return array<int,array<string,mixed>>
 */
function quorlyx_get_conversation_history_from_db( $post_id ) {
	$post_id = absint( $post_id );
	if ( $post_id <= 0 || ! quorlyx_conversation_messages_table_exists() ) {
		return array();
	}

	global $wpdb;
	$table_name = quorlyx_get_conversation_messages_table_name();

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Message history read for one indexed conversation.
	$rows = $wpdb->get_results(
		$wpdb->prepare(
			"SELECT role, message_text, message_json FROM {$table_name} WHERE conversation_post_id = %d ORDER BY sequence_num ASC",
			$post_id
		),
		ARRAY_A
	);

	$history = array();
	foreach ( (array) $rows as $row ) {
		$decoded = json_decode( (string) ( $row['message_json'] ?? '' ), true );
		if ( ! is_array( $decoded ) ) {
			$decoded = array(
				'role'  => sanitize_key( (string) ( $row['role'] ?? 'user' ) ),
				'parts' => array(
					array(
						'text' => (string) ( $row['message_text'] ?? '' ),
					),
				),
			);
		}
		$history[] = quorlyx_normalize_history_message_for_storage( $decoded );
	}

	return $history;
}

/**
 * Load conversation history from DB-first storage with postmeta fallback.
 *
 * @param int $post_id Conversation CPT post ID.
 * @return array<int,array<string,mixed>>
 */
function quorlyx_get_conversation_history( $post_id ) {
	$post_id = absint( $post_id );
	if ( $post_id <= 0 ) {
		return array();
	}

	$history = quorlyx_get_conversation_history_from_db( $post_id );
	if ( ! empty( $history ) ) {
		return $history;
	}

	$legacy = get_post_meta( $post_id, 'quorlyx_chat_history', true );

	return is_array( $legacy ) ? $legacy : array();
}

/**
 * Persist conversation history into the message table, with legacy fallback.
 *
 * @param int                       $post_id Conversation CPT post ID.
 * @param array<int,array<string,mixed>> $history Chat history.
 * @return bool
 */
function quorlyx_store_conversation_history( $post_id, $history ) {
	$post_id = absint( $post_id );
	if ( $post_id <= 0 || ! is_array( $history ) ) {
		return false;
	}

	$history = array_values( array_map( 'quorlyx_normalize_history_message_for_storage', $history ) );

	if ( ! quorlyx_conversation_store_available() ) {
		update_post_meta( $post_id, 'quorlyx_chat_history', $history );
		update_post_meta( $post_id, 'quorlyx_message_count', count( $history ) );
		return true;
	}

	global $wpdb;
	$conversation_id = quorlyx_upsert_conversation_record(
		$post_id,
		array(
			'message_count' => count( $history ),
			'last_activity' => time(),
		)
	);
	$messages_table  = quorlyx_get_conversation_messages_table_name();
	$current_history = quorlyx_get_conversation_history_from_db( $post_id );
	$current_count   = count( $current_history );
	$can_append      = count( $history ) >= $current_count;

	if ( $can_append && $current_count > 0 ) {
		for ( $i = 0; $i < $current_count; $i++ ) {
			if ( wp_json_encode( $current_history[ $i ] ) !== wp_json_encode( $history[ $i ] ) ) {
				$can_append = false;
				break;
			}
		}
	}

	if ( ! $can_append ) {
		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Replace rows when history was truncated or legacy data changed.
		$wpdb->query(
			$wpdb->prepare(
				"DELETE FROM {$messages_table} WHERE conversation_post_id = %d",
				$post_id
			)
		);
		$current_count = 0;
	}

	$write_failed = false;
	for ( $i = $current_count; $i < count( $history ); $i++ ) {
		$message      = $history[ $i ];
		$message_text = quorlyx_get_history_message_text( $message );
		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery -- Append-only hot path into compact message table.
		$inserted = $wpdb->insert(
			$messages_table,
			array(
				'conversation_id'      => $conversation_id,
				'conversation_post_id' => $post_id,
				'sequence_num'         => $i + 1,
				'role'                 => sanitize_key( (string) ( $message['role'] ?? '' ) ),
				'message_text'         => $message_text,
				'message_json'         => wp_json_encode( $message ),
				'created_at'           => gmdate( 'Y-m-d H:i:s' ),
			)
		);
		if ( false === $inserted ) {
			$write_failed = true;
			break;
		}
	}

	update_post_meta( $post_id, 'quorlyx_message_count', count( $history ) );
	if ( $write_failed ) {
		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Remove partial write so legacy fallback remains authoritative.
		$wpdb->query(
			$wpdb->prepare(
				"DELETE FROM {$messages_table} WHERE conversation_post_id = %d",
				$post_id
			)
		);
		update_post_meta( $post_id, 'quorlyx_chat_history', $history );
	} else {
		delete_post_meta( $post_id, 'quorlyx_chat_history' );
	}

	return ! $write_failed;
}

/**
 * Get table-backed submissions linked to a conversation.
 *
 * @param int $conversation_post_id Conversation CPT post ID.
 * @return array<int,array<string,mixed>>
 */
function quorlyx_get_submission_records_for_conversation( $conversation_post_id ) {
	$conversation_post_id = absint( $conversation_post_id );
	if ( $conversation_post_id <= 0 || ! quorlyx_submissions_table_exists() ) {
		return array();
	}

	global $wpdb;
	$table_name = quorlyx_get_submissions_table_name();

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Indexed admin read for one conversation.
	$rows = $wpdb->get_results(
		$wpdb->prepare(
			"SELECT * FROM {$table_name} WHERE conversation_post_id = %d ORDER BY created_at DESC",
			$conversation_post_id
		),
		ARRAY_A
	);

	return is_array( $rows ) ? $rows : array();
}

/**
 * Find an existing captured submission by conversation and contact hash.
 *
 * @param int    $conversation_post_id Conversation CPT post ID.
 * @param string $email                Email address.
 * @param string $phone                Phone number.
 * @return int Mirrored submission CPT post ID.
 */
function quorlyx_find_existing_submission_record( $conversation_post_id, $email, $phone ) {
	$conversation_post_id = absint( $conversation_post_id );
	if ( $conversation_post_id <= 0 || ! quorlyx_submissions_table_exists() ) {
		return 0;
	}

	$email_hash = quorlyx_hash_storage_identifier( sanitize_email( (string) $email ) );
	$phone_hash = quorlyx_hash_storage_identifier( preg_replace( '/\s+/', '', (string) $phone ) );
	if ( '' === $email_hash && '' === $phone_hash ) {
		return 0;
	}

	global $wpdb;
	$table_name = quorlyx_get_submissions_table_name();
	$where      = array( 'conversation_post_id = %d' );
	$args       = array( $conversation_post_id );
	if ( '' !== $email_hash ) {
		$where[] = 'email_hash = %s';
		$args[]  = $email_hash;
	}
	if ( '' !== $phone_hash ) {
		$where[] = 'phone_hash = %s';
		$args[]  = $phone_hash;
	}

	// phpcs:ignore WordPress.DB.PreparedSQLPlaceholders.ReplacementsWrongNumber,WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Dynamic WHERE is built from fixed fragments.
	$post_id = $wpdb->get_var(
		$wpdb->prepare(
			"SELECT post_id FROM {$table_name} WHERE " . implode( ' AND ', $where ) . ' ORDER BY id DESC LIMIT 1',
			$args
		)
	);

	return $post_id ? absint( $post_id ) : 0;
}

/**
 * Insert or update a compact captured submission row.
 *
 * @param int                 $post_id              Mirrored submission CPT post ID.
 * @param int                 $conversation_post_id Conversation CPT post ID.
 * @param array<string,mixed> $data                 Submission fields.
 * @return int Table row ID, or 0 on failure.
 */
function quorlyx_upsert_submission_record( $post_id, $conversation_post_id, $data ) {
	$post_id              = absint( $post_id );
	$conversation_post_id = absint( $conversation_post_id );
	if ( $post_id <= 0 || $conversation_post_id <= 0 || ! quorlyx_submissions_table_exists() ) {
		return 0;
	}

	global $wpdb;
	$table_name = quorlyx_get_submissions_table_name();
	$conv_row   = quorlyx_get_conversation_record_by_post_id( $conversation_post_id );
	$now        = gmdate( 'Y-m-d H:i:s' );
	$email      = sanitize_email( (string) ( $data['email'] ?? '' ) );
	$phone      = sanitize_text_field( (string) ( $data['phone'] ?? '' ) );
	$tags       = $data['tags'] ?? array();
	$tags       = is_array( $tags ) ? array_values( array_unique( array_map( 'sanitize_key', $tags ) ) ) : array();

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Indexed lookup by mirrored post ID.
	$existing = $wpdb->get_row(
		$wpdb->prepare(
			"SELECT * FROM {$table_name} WHERE post_id = %d LIMIT 1",
			$post_id
		),
		ARRAY_A
	);
	$existing = is_array( $existing ) ? $existing : array();

	$record = array(
		'post_id'              => $post_id,
		'conversation_id'      => absint( $conv_row['id'] ?? 0 ),
		'conversation_post_id' => $conversation_post_id,
		'email'                => $email,
		'email_hash'           => quorlyx_hash_storage_identifier( $email ),
		'phone'                => $phone,
		'phone_hash'           => quorlyx_hash_storage_identifier( preg_replace( '/\s+/', '', $phone ) ),
		'interest'             => sanitize_text_field( (string) ( $data['interest'] ?? '' ) ),
		'purpose'              => sanitize_text_field( (string) ( $data['purpose'] ?? '' ) ),
		'status'               => sanitize_text_field( (string) ( $data['status'] ?? '' ) ),
		'urgency'              => sanitize_text_field( (string) ( $data['urgency'] ?? '' ) ),
		'tags'                 => wp_json_encode( $tags ),
		'ab_variation'         => sanitize_key( (string) ( $data['ab_variation'] ?? 'a' ) ),
		'source_url'           => esc_url_raw( (string) ( $data['source_url'] ?? '' ) ),
		'trigger_id'           => sanitize_key( (string) ( $data['trigger_id'] ?? '' ) ),
		'trigger_name'         => sanitize_text_field( (string) ( $data['trigger_name'] ?? '' ) ),
		'trigger_type'         => sanitize_key( (string) ( $data['trigger_type'] ?? '' ) ),
		'created_at'           => sanitize_text_field( (string) ( $existing['created_at'] ?? $now ) ),
		'updated_at'           => $now,
	);

	if ( 'b' !== $record['ab_variation'] ) {
		$record['ab_variation'] = 'a';
	}

	if ( ! empty( $existing['id'] ) ) {
		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Compact submission table update.
		$result = $wpdb->update(
			$table_name,
			$record,
			array( 'id' => absint( $existing['id'] ) )
		);

		return false === $result ? 0 : absint( $existing['id'] );
	}

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery -- Compact submission table insert.
	$result = $wpdb->insert( $table_name, $record );

	return false === $result ? 0 : absint( $wpdb->insert_id );
}

/**
 * Migrate legacy CPT/postmeta storage into compact custom tables in small batches.
 *
 * @return void
 */
function quorlyx_migrate_legacy_cpt_storage_to_tables() {
	if ( ! quorlyx_conversation_store_available() ) {
		return;
	}

	$conversation_query = new WP_Query(
		array(
			'post_type'              => 'quorlyx_conversation',
			'post_status'            => 'private',
			'posts_per_page'         => 100,
			'fields'                 => 'ids',
			'no_found_rows'          => true,
			'update_post_meta_cache' => true,
			'update_post_term_cache' => false,
			// phpcs:ignore WordPress.DB.SlowDBQuery.slow_db_query_meta_query -- Bounded one-time compatibility migration.
			'meta_query'             => array(
				array(
					'key'     => 'quorlyx_table_migrated',
					'compare' => 'NOT EXISTS',
				),
			),
		)
	);

	foreach ( $conversation_query->posts as $post_id ) {
		$post_id = absint( $post_id );
		if ( $post_id <= 0 ) {
			continue;
		}

		$ip          = sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_ip', true ) );
		$details     = get_post_meta( $post_id, 'quorlyx_conversions', true );
		$last_active = absint( get_post_meta( $post_id, 'quorlyx_last_activity', true ) );
		if ( $last_active <= 0 ) {
			$last_active = strtotime( (string) get_post_field( 'post_modified_gmt', $post_id ) ) ?: time();
		}

		quorlyx_upsert_conversation_record(
			$post_id,
			array(
				'persistent_user_id' => sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_persistent_user_id', true ) ),
				'variation'          => sanitize_key( (string) get_post_meta( $post_id, 'quorlyx_ab_variation', true ) ),
				'source'             => quorlyx_get_conversation_source_value( $post_id ),
				'trigger_id'         => sanitize_key( (string) get_post_meta( $post_id, 'quorlyx_trigger_id', true ) ),
				'trigger_name'       => sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_trigger_name', true ) ),
				'trigger_type'       => sanitize_key( (string) get_post_meta( $post_id, 'quorlyx_trigger_type', true ) ),
				'message_count'      => absint( get_post_meta( $post_id, 'quorlyx_message_count', true ) ),
				'conversions_count'  => absint( get_post_meta( $post_id, 'quorlyx_conversions_count', true ) ),
				'conversion_details' => is_array( $details ) ? $details : array(),
				'lead_interest'      => sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_lead_interest', true ) ),
				'lead_status'        => sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_lead_status', true ) ),
				'lead_urgency'       => sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_lead_urgency', true ) ),
				'user_agent'         => sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_user_agent', true ) ),
				'ip_hash'            => quorlyx_hash_ip_address( $ip ),
				'device'             => sanitize_key( (string) get_post_meta( $post_id, 'quorlyx_device', true ) ),
				'country'            => strtoupper( sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_country', true ) ) ),
				'city'               => sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_city', true ) ),
				'location'           => sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_location', true ) ),
				'last_activity'      => $last_active,
			)
		);

		$history = get_post_meta( $post_id, 'quorlyx_chat_history', true );
		if ( is_array( $history ) ) {
			quorlyx_store_conversation_history( $post_id, $history );
		}
		update_post_meta( $post_id, 'quorlyx_table_migrated', '1' );
	}
	wp_reset_postdata();

	if ( ! quorlyx_submissions_table_exists() ) {
		return;
	}

	$submission_query = new WP_Query(
		array(
			'post_type'              => 'quorlyx_submission',
			'post_status'            => 'publish',
			'posts_per_page'         => 100,
			'fields'                 => 'ids',
			'no_found_rows'          => true,
			'update_post_meta_cache' => true,
			'update_post_term_cache' => false,
			// phpcs:ignore WordPress.DB.SlowDBQuery.slow_db_query_meta_query -- Bounded one-time compatibility migration.
			'meta_query'             => array(
				array(
					'key'     => 'quorlyx_table_migrated',
					'compare' => 'NOT EXISTS',
				),
			),
		)
	);

	foreach ( $submission_query->posts as $post_id ) {
		$post_id              = absint( $post_id );
		$conversation_post_id = absint( get_post_meta( $post_id, 'quorlyx_conversation_id', true ) );
		if ( $post_id <= 0 || $conversation_post_id <= 0 ) {
			continue;
		}

		$tags = get_post_meta( $post_id, 'quorlyx_tags', true );
		quorlyx_upsert_submission_record(
			$post_id,
			$conversation_post_id,
			array(
				'email'        => sanitize_email( (string) get_post_meta( $post_id, 'quorlyx_email', true ) ),
				'phone'        => sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_phone', true ) ),
				'interest'     => sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_interest', true ) ),
				'purpose'      => sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_capture_purpose', true ) ),
				'status'       => sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_status', true ) ),
				'urgency'      => sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_urgency', true ) ),
				'tags'         => is_array( $tags ) ? $tags : array(),
				'ab_variation' => sanitize_key( (string) get_post_meta( $post_id, 'quorlyx_ab_variation', true ) ),
				'source_url'   => esc_url_raw( (string) get_post_meta( $post_id, 'quorlyx_source_url', true ) ),
				'trigger_id'   => sanitize_key( (string) get_post_meta( $post_id, 'quorlyx_trigger_id', true ) ),
				'trigger_name' => sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_trigger_name', true ) ),
				'trigger_type' => sanitize_key( (string) get_post_meta( $post_id, 'quorlyx_trigger_type', true ) ),
			)
		);
		update_post_meta( $post_id, 'quorlyx_table_migrated', '1' );
	}
	wp_reset_postdata();
}

/**
 * Resolve conversation origin details using current request attribution.
 *
 * @return array<string,string>
 */
function quorlyx_get_conversation_origin_from_request() {
	$trigger_id = '';
	if ( ! empty( $_COOKIE['quorlyx_attribution_trigger_id'] ) ) {
		$trigger_id = sanitize_key( wp_unslash( $_COOKIE['quorlyx_attribution_trigger_id'] ) );
	}

	if ( '' === $trigger_id ) {
		return array(
			'source'       => 'normal',
			'source_label' => 'Normal',
			'trigger_id'   => '',
			'trigger_name' => '',
			'trigger_type' => '',
		);
	}

	$trigger_meta = quorlyx_get_trigger_definition_by_id( $trigger_id );

	return array(
		'source'       => 'trigger',
		'source_label' => 'Trigger',
		'trigger_id'   => $trigger_id,
		'trigger_name' => sanitize_text_field( (string) ( $trigger_meta['name'] ?? $trigger_id ) ),
		'trigger_type' => sanitize_key( (string) ( $trigger_meta['type'] ?? '' ) ),
	);
}

/**
 * Build extra normal-chat instructions inherited from the active trigger.
 *
 * @param array<string,string> $origin Conversation origin data.
 * @return string
 */
function quorlyx_get_trigger_chat_followup_prompt( $origin ) {
	if ( ! is_array( $origin ) || 'trigger' !== sanitize_key( (string) ( $origin['source'] ?? '' ) ) ) {
		return '';
	}

	$trigger_id = sanitize_key( (string) ( $origin['trigger_id'] ?? '' ) );
	if ( '' === $trigger_id ) {
		return '';
	}

	$trigger = quorlyx_get_trigger_definition_by_id( $trigger_id );
	if ( empty( $trigger ) || ! is_array( $trigger ) ) {
		return '';
	}

	$lines = array();
	$custom_instructions = trim( sanitize_textarea_field( (string) ( $trigger['chat_followup_instructions'] ?? '' ) ) );
	if ( '' !== $custom_instructions ) {
		$lines[] = "Admin follow-up instructions for this trigger:\n" . $custom_instructions;
	}

	$quick_reply_rules = quorlyx_build_quick_reply_prompt_rules( quorlyx_normalize_quick_reply_buttons( $trigger['quick_replies'] ?? array(), 'trigger_reply' ), false );
	if ( '' !== $quick_reply_rules ) {
		$lines[] = "Trigger quick reply rules:\n" . $quick_reply_rules;
	}

	if ( ! empty( $trigger['capture_submissions_enabled'] ) || ! empty( $trigger['capture_unsupported_feature_leads'] ) ) {
		$purpose = sanitize_text_field( (string) ( $trigger['capture_submission_purpose'] ?? 'Triggered Chat Lead' ) );
		$lines[] = "Submission capture flow for this trigger:\n- Capture purpose: {$purpose}.\n- When the visitor shows relevant intent for this purpose, ask naturally for the minimum contact details needed, such as email or phone.\n- If the visitor asks for a feature, product, integration, offer, or detail that is not available in the supplied site facts, say it is not available right now, offer the closest alternative when possible, then ask whether they want to leave contact details for follow-up.\n- This can be used for feature requests, product requests, waitlists, offer claims, demos, quotes, callbacks, custom requests, or other lead/data collection flows.\n- After contact details are provided, confirm that the request was logged and keep the response aligned with the site's brand voice.\n- Do not promise availability, discounts, deadlines, integrations, or follow-up timing unless those facts appear in site facts.";
	}

	if ( empty( $lines ) ) {
		return '';
	}

	return "TRIGGER FOLLOW-UP RULES:\n---\n" . implode( "\n\n", $lines ) . "\n---\n";
}

/**
 * Build extra prompt rules for main chat quick message buttons.
 *
 * @param array<string,mixed> $variation_settings Variation settings.
 * @return string
 */
function quorlyx_get_main_chat_quick_reply_prompt( $variation_settings ) {
	if ( ! is_array( $variation_settings ) ) {
		return '';
	}

	$rules = quorlyx_build_quick_reply_prompt_rules( $variation_settings['actions'] ?? array(), true );
	if ( '' === $rules ) {
		return '';
	}

	return "MAIN CHAT QUICK REPLY RULES:\n---\n" . $rules . "\n---\n";
}

/**
 * Extract the first email address from text.
 *
 * @param string $text Text to scan.
 * @return string
 */
function quorlyx_extract_email_from_text( $text ) {
	if ( ! preg_match( '/[A-Z0-9._%+\-]+@[A-Z0-9.\-]+\.[A-Z]{2,}/i', (string) $text, $matches ) ) {
		return '';
	}
	return sanitize_email( (string) $matches[0] );
}

/**
 * Extract the first likely phone number from text.
 *
 * @param string $text Text to scan.
 * @return string
 */
function quorlyx_extract_phone_from_text( $text ) {
	if ( ! preg_match( '/(?:\+?\d[\d\s().-]{6,}\d)/', (string) $text, $matches ) ) {
		return '';
	}
	$phone = preg_replace( '/[^\d+]/', '', (string) $matches[0] );
	$digits = preg_replace( '/\D/', '', (string) $phone );
	if ( strlen( (string) $digits ) < 7 ) {
		return '';
	}
	return sanitize_text_field( (string) $phone );
}

/**
 * Infer requested feature/interest from recent conversation messages.
 *
 * @param array<int,array<string,mixed>> $history Conversation history.
 * @return string
 */
function quorlyx_infer_submission_interest_from_history( $history, $fallback = 'Chat Submission' ) {
	if ( ! is_array( $history ) ) {
		return '';
	}

	$user_messages = array();
	foreach ( array_reverse( $history ) as $message ) {
		if ( 'user' !== (string) ( $message['role'] ?? '' ) ) {
			continue;
		}
		$text = trim( wp_strip_all_tags( (string) ( $message['parts'][0]['text'] ?? '' ) ) );
		if ( '' === $text || '' !== quorlyx_extract_email_from_text( $text ) ) {
			continue;
		}
		$user_messages[] = $text;
		if ( count( $user_messages ) >= 4 ) {
			break;
		}
	}

	foreach ( $user_messages as $text ) {
		if ( preg_match( '/\b(?:support|have|offer|include|integrate(?:s|d|ion)?|connect(?:s|ed|ion)?|work(?:s)? with|feature for)\s+([A-Za-z0-9][A-Za-z0-9 ._+&\/-]{2,80})/i', $text, $matches ) ) {
			$interest = trim( (string) $matches[1], " \t\n\r\0\x0B?.!,:" );
			if ( '' !== $interest ) {
				return sanitize_text_field( ucwords( strtolower( $interest ) ) );
			}
		}
		if ( preg_match( '/\b(?:demo|quote|callback|call back|offer|discount|deal|consultation|pricing|price|plan|request|interested in|want)\b/i', $text ) ) {
			return sanitize_text_field( wp_trim_words( $text, 8, '' ) );
		}
	}

	return isset( $user_messages[0] ) ? sanitize_text_field( wp_trim_words( $user_messages[0], 8, '' ) ) : sanitize_text_field( $fallback );
}

/**
 * Infer urgency label from recent conversation text.
 *
 * @param array<int,array<string,mixed>> $history Conversation history.
 * @return string
 */
function quorlyx_infer_submission_urgency_from_history( $history ) {
	$combined = '';
	if ( is_array( $history ) ) {
		foreach ( array_slice( $history, -8 ) as $message ) {
			$combined .= ' ' . (string) ( $message['parts'][0]['text'] ?? '' );
		}
	}
	$combined = strtolower( $combined );

	if ( preg_match( '/\b(urgent|asap|immediately|must have|need this|blocking|deal breaker|critical|right now)\b/i', $combined ) ) {
		return 'High';
	}
	if ( preg_match( '/\b(soon|important|really want|would buy|interested|priority)\b/i', $combined ) ) {
		return 'Medium';
	}
	return 'Low';
}

/**
 * Decide whether the conversation looks like a lead/data capture flow.
 *
 * @param array<int,array<string,mixed>> $history Conversation history.
 * @return bool
 */
function quorlyx_history_has_submission_capture_intent( $history ) {
	if ( ! is_array( $history ) ) {
		return false;
	}

	$combined = '';
	foreach ( array_slice( $history, -10 ) as $message ) {
		$combined .= ' ' . (string) ( $message['parts'][0]['text'] ?? '' );
	}

	return (bool) preg_match( '/\b(unsupported|not currently (available|supported)|not available|not supported|do not support|don\'t support|waitlist|notify|notification|when it is supported|when supported|integration|feature request|demo|quote|callback|call back|contact me|email me|phone|offer|discount|deal|consultation|pricing|interested|sign me up|subscribe|book|schedule|request)\b/i', $combined );
}

/**
 * Store a captured chat submission and link it to conversation.
 *
 * @param int                  $conversation_post_id Conversation post ID.
 * @param array<int,array<string,mixed>> $history Conversation history.
 * @param array<string,string> $origin Conversation origin details.
 * @param string               $variation_key A/B variation.
 * @param string               $source_url Current URL.
 * @return int
 */
function quorlyx_maybe_capture_chat_submission( $conversation_post_id, $history, $origin, $variation_settings = array(), $variation_key = 'a', $source_url = '' ) {
	$conversation_post_id = absint( $conversation_post_id );
	if ( $conversation_post_id <= 0 || ! is_array( $history ) ) {
		return 0;
	}

	$trigger_id = sanitize_key( (string) ( $origin['trigger_id'] ?? '' ) );
	$trigger    = $trigger_id ? quorlyx_get_trigger_definition_by_id( $trigger_id ) : array();
	$is_trigger_capture = 'trigger' === sanitize_key( (string) ( $origin['source'] ?? '' ) )
		&& ( ! empty( $trigger['capture_submissions_enabled'] ) || ! empty( $trigger['capture_unsupported_feature_leads'] ) );
	$is_main_capture = ! empty( $variation_settings['chat_capture_enabled'] );

	if ( ! $is_trigger_capture && ! $is_main_capture ) {
		return 0;
	}

	$email = '';
	$phone = '';
	foreach ( array_reverse( $history ) as $message ) {
		if ( 'user' !== (string) ( $message['role'] ?? '' ) ) {
			continue;
		}
		$text = (string) ( $message['parts'][0]['text'] ?? '' );
		if ( '' === $email ) {
			$email = quorlyx_extract_email_from_text( $text );
		}
		if ( '' === $phone ) {
			$phone = quorlyx_extract_phone_from_text( $text );
		}
		if ( '' !== $email || '' !== $phone ) {
			break;
		}
	}
	if ( '' === $email && '' === $phone ) {
		return 0;
	}
	$existing_record_id = quorlyx_find_existing_submission_record( $conversation_post_id, $email, $phone );
	if ( $existing_record_id > 0 ) {
		return $existing_record_id;
	}
	$existing_ids = get_post_meta( $conversation_post_id, 'quorlyx_submission_ids', true );
	$existing_ids = is_array( $existing_ids ) ? array_map( 'absint', $existing_ids ) : array();
	$legacy_ids   = get_post_meta( $conversation_post_id, 'quorlyx_waitlist_submission_ids', true );
	if ( is_array( $legacy_ids ) ) {
		$existing_ids = array_merge( $existing_ids, array_map( 'absint', $legacy_ids ) );
	}
	foreach ( $existing_ids as $existing_id ) {
		if ( $existing_id <= 0 ) {
			continue;
		}
		$existing_email = sanitize_email( (string) get_post_meta( $existing_id, 'quorlyx_email', true ) );
		$existing_phone = sanitize_text_field( (string) get_post_meta( $existing_id, 'quorlyx_phone', true ) );
		if ( ( '' !== $email && $email === $existing_email ) || ( '' !== $phone && $phone === $existing_phone ) ) {
			return $existing_id;
		}
	}

	$purpose = $is_trigger_capture
		? sanitize_text_field( (string) ( $trigger['capture_submission_purpose'] ?? 'Triggered Chat Lead' ) )
		: sanitize_text_field( (string) ( $variation_settings['chat_capture_purpose'] ?? 'General Chat Lead' ) );
	$status = $is_trigger_capture
		? sanitize_text_field( (string) ( $trigger['capture_submission_status'] ?? 'Captured' ) )
		: sanitize_text_field( (string) ( $variation_settings['chat_capture_status'] ?? 'Captured' ) );
	$raw_tags = $is_trigger_capture
		? (string) ( $trigger['capture_submission_tags'] ?? '' )
		: (string) ( $variation_settings['chat_capture_tags'] ?? '' );
	$interest = quorlyx_infer_submission_interest_from_history( $history, $purpose );
	$urgency  = quorlyx_infer_submission_urgency_from_history( $history );
	$status   = '' !== $status ? $status : 'Captured';
	$tags     = preg_split( '/[\s,]+/', $raw_tags, -1, PREG_SPLIT_NO_EMPTY );
	$tags     = is_array( $tags ) ? array_map( 'sanitize_key', $tags ) : array();
	$tags[]   = 'chat_capture';
	$tags[]   = sanitize_title( $purpose );
	$tags[]   = sanitize_title( $interest );
	$tags     = array_values( array_unique( array_filter( $tags ) ) );

	$post_id = wp_insert_post(
		array(
			'post_type'    => 'quorlyx_submission',
			'post_status'  => 'publish',
			'post_title'   => sprintf( '%s - %s - %s', $purpose, $interest, $email ? $email : $phone ),
			'post_content' => sprintf(
				"Email: %s\nPhone: %s\nInterest: %s\nPurpose: %s\nStatus: %s\nUrgency: %s\nConversation: %s",
				$email,
				$phone,
				$interest,
				$purpose,
				$status,
				$urgency,
				admin_url( 'post.php?post=' . $conversation_post_id . '&action=edit' )
			),
		),
		true
	);

	if ( is_wp_error( $post_id ) || ! $post_id ) {
		return 0;
	}

	update_post_meta( $post_id, 'quorlyx_email', $email );
	update_post_meta( $post_id, 'quorlyx_phone', $phone );
	update_post_meta( $post_id, 'quorlyx_interest', $interest );
	update_post_meta( $post_id, 'quorlyx_capture_purpose', $purpose );
	update_post_meta( $post_id, 'quorlyx_status', $status );
	update_post_meta( $post_id, 'quorlyx_urgency', $urgency );
	update_post_meta( $post_id, 'quorlyx_tags', $tags );
	update_post_meta( $post_id, 'quorlyx_conversation_id', $conversation_post_id );
	update_post_meta( $post_id, 'quorlyx_ab_variation', sanitize_key( $variation_key ) );
	update_post_meta( $post_id, 'quorlyx_source_url', esc_url_raw( $source_url ) );
	update_post_meta( $post_id, 'quorlyx_trigger_id', $trigger_id );
	update_post_meta( $post_id, 'quorlyx_trigger_name', sanitize_text_field( (string) ( $origin['trigger_name'] ?? '' ) ) );
	update_post_meta( $post_id, 'quorlyx_trigger_type', sanitize_key( (string) ( $origin['trigger_type'] ?? '' ) ) );
	quorlyx_upsert_submission_record(
		$post_id,
		$conversation_post_id,
		array(
			'email'        => $email,
			'phone'        => $phone,
			'interest'     => $interest,
			'purpose'      => $purpose,
			'status'       => $status,
			'urgency'      => $urgency,
			'tags'         => $tags,
			'ab_variation' => sanitize_key( $variation_key ),
			'source_url'   => esc_url_raw( $source_url ),
			'trigger_id'   => $trigger_id,
			'trigger_name' => sanitize_text_field( (string) ( $origin['trigger_name'] ?? '' ) ),
			'trigger_type' => sanitize_key( (string) ( $origin['trigger_type'] ?? '' ) ),
		)
	);

	$existing_ids[] = absint( $post_id );
	update_post_meta( $conversation_post_id, 'quorlyx_submission_ids', array_values( array_unique( array_filter( $existing_ids ) ) ) );
	update_post_meta( $conversation_post_id, 'quorlyx_lead_interest', $interest );
	update_post_meta( $conversation_post_id, 'quorlyx_lead_status', $status );
	update_post_meta( $conversation_post_id, 'quorlyx_lead_urgency', $urgency );
	quorlyx_upsert_conversation_record(
		$conversation_post_id,
		array(
			'lead_interest' => $interest,
			'lead_status'   => $status,
			'lead_urgency'  => $urgency,
		)
	);

	return absint( $post_id );
}

