		$new['quorlyx_variation']     = __( 'A/B' );
		$new['quorlyx_messages']      = __( 'Messages' );
		$new['quorlyx_conv']          = __( 'Conversions' );
		$new['quorlyx_source']        = __( 'Source' );
		$new['quorlyx_trigger']       = __( 'Trigger' );
		$new['quorlyx_user']          = __( 'User ID' );
		$new['quorlyx_device']        = __( 'Device' );
		$new['quorlyx_location']      = __( 'Location' );
		$new['quorlyx_last_activity'] = __( 'Last Activity' );
