add_action(
	'manage_quorlyx_submission_posts_custom_column',
	function ( $col, $post_id ) {
		switch ( $col ) {
			case 'quorlyx_email':
				$email = sanitize_email( (string) get_post_meta( $post_id, 'quorlyx_email', true ) );
				echo $email ? '<a href="mailto:' . esc_attr( $email ) . '">' . esc_html( $email ) . '</a>' : '&mdash;';
				break;
			case 'quorlyx_phone':
				$phone = sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_phone', true ) );
				echo $phone ? esc_html( $phone ) : '&mdash;';
				break;
			case 'quorlyx_purpose':
				$purpose = sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_capture_purpose', true ) );
				echo $purpose ? esc_html( $purpose ) : '&mdash;';
				break;
			case 'quorlyx_interest':
				$interest = sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_interest', true ) );
				echo $interest ? esc_html( $interest ) : '&mdash;';
				break;
			case 'quorlyx_status':
				$status = sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_status', true ) );
				echo $status ? '<span class="qux-badge qux-badge-source">' . esc_html( $status ) . '</span>' : '&mdash;';
				break;
			case 'quorlyx_urgency':
				$urgency = sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_urgency', true ) );
				echo $urgency ? '<span class="qux-badge qux-badge-conv">' . esc_html( $urgency ) . '</span>' : '&mdash;';
				break;
			case 'quorlyx_tags':
				$tags = get_post_meta( $post_id, 'quorlyx_tags', true );
				if ( is_array( $tags ) ) {
					$tags = implode( ', ', array_map( 'sanitize_text_field', $tags ) );
				}
				echo $tags ? esc_html( (string) $tags ) : '&mdash;';
				break;
			case 'quorlyx_conversation':
				$conversation_id = absint( get_post_meta( $post_id, 'quorlyx_conversation_id', true ) );
				if ( $conversation_id && 'quorlyx_conversation' === get_post_type( $conversation_id ) ) {
					echo '<a href="' . esc_url( admin_url( 'post.php?post=' . $conversation_id . '&action=edit' ) ) . '">' . esc_html( get_the_title( $conversation_id ) ) . '</a>';
				} else {
					echo '&mdash;';
				}
				break;
			case 'quorlyx_trigger':
				$trigger_name = sanitize_text_field( (string) get_post_meta( $post_id, 'quorlyx_trigger_name', true ) );
				$trigger_type = sanitize_key( (string) get_post_meta( $post_id, 'quorlyx_trigger_type', true ) );
				if ( $trigger_name || $trigger_type ) {
					echo esc_html( $trigger_name ? $trigger_name : $trigger_type );
					if ( $trigger_type ) {
						echo '<br><small>' . esc_html( ucwords( str_replace( '_', ' ', $trigger_type ) ) ) . '</small>';
					}
				} else {
					echo '&mdash;';
				}
				break;
		}
	},
	10,
	2
);

add_action(
	'manage_quorlyx_conversation_posts_custom_column',
	function ( $col, $post_id ) {
		$conversation_record = quorlyx_get_conversation_record_by_post_id( $post_id );
		switch ( $col ) {
			case 'quorlyx_variation':
				$v = $conversation_record['variation'] ?? get_post_meta( $post_id, 'quorlyx_ab_variation', true );
				$v = $v ? strtoupper( $v ) : "\xE2\x80\x94";
				echo '<span class="qux-badge qux-badge-variation">' . esc_html( $v ) . '</span>';
				break;
			case 'quorlyx_messages':
				$m = (int) ( $conversation_record['message_count'] ?? get_post_meta( $post_id, 'quorlyx_message_count', true ) );
				echo '<strong>' . intval( $m ) . '</strong>';
				break;
			case 'quorlyx_user':
				$uid = $conversation_record['persistent_user_id'] ?? get_post_meta( $post_id, 'quorlyx_persistent_user_id', true );
				echo $uid ? '<code>' . esc_html( $uid ) . '</code>' : "\xE2\x80\x94";
				break;
			case 'quorlyx_device':
				$d = $conversation_record['device'] ?? get_post_meta( $post_id, 'quorlyx_device', true );
				if ( ! $d ) {
					$d = "\xE2\x80\x94";
				}
				echo '<span class="qux-badge qux-badge-device">' . esc_html( ucfirst( $d ) ) . '</span>';
				break;
			case 'quorlyx_location':
				$loc = $conversation_record['location'] ?? get_post_meta( $post_id, 'quorlyx_location', true );
				if ( ! $loc ) {

					$country = $conversation_record['country'] ?? get_post_meta( $post_id, 'quorlyx_country', true );
					$country = $country ? strtoupper( $country ) : '';
					$city    = $conversation_record['city'] ?? get_post_meta( $post_id, 'quorlyx_city', true );

					if ( empty( $city ) ) {
						$ip = get_post_meta( $post_id, 'quorlyx_ip', true );
						if ( ! empty( $ip ) && class_exists( 'WC_Geolocation' ) ) {
							try {
								$geo = WC_Geolocation::geolocate_ip( $ip, true, false );
								if ( is_array( $geo ) ) {
									if ( empty( $country ) && ! empty( $geo['country'] ) ) {
										$country = strtoupper( $geo['country'] );
									}
									if ( ! empty( $geo['city'] ) ) {
										$city = $geo['city'];
									}
								}
							} catch ( Throwable $e ) {
								// Ignore geolocation failures; continue with available data.
								unset( $e );
							}
						}
					}

					$parts = array();
					if ( $country ) {
						$parts[] = $country; }
					if ( $city ) {
						$parts[] = $city; }
					$loc = implode( ',', $parts );
				}
				echo $loc ? '<span class="qux-badge qux-badge-location">' . esc_html( $loc ) . '</span>' : "\xE2\x80\x94";
				break;
			case 'quorlyx_conv':
				$cnt     = (int) ( $conversation_record['conversions_count'] ?? get_post_meta( $post_id, 'quorlyx_conversions_count', true ) );
				$details = get_post_meta( $post_id, 'quorlyx_conversions', true );
				if ( ! is_array( $details ) && ! empty( $conversation_record['conversion_details'] ) ) {
					$decoded = json_decode( (string) $conversation_record['conversion_details'], true );
					$details = is_array( $decoded ) ? $decoded : array();
				}
				$label   = $cnt > 0 ? number_format_i18n( $cnt ) : '0';
				$goals   = array();
				if ( is_array( $details ) ) {
					foreach ( $details as $d ) {
						if ( ! empty( $d['goal_name'] ) ) {
							$goals[] = sanitize_text_field( $d['goal_name'] ); }
					}
				}
				$goals = array_unique( array_filter( $goals ) );
				$text  = $label;
				if ( ! empty( $goals ) ) {
					$text .= " \xE2\x80\x94 " . esc_html( implode( ', ', array_slice( $goals, 0, 3 ) ) ); }
				echo $cnt > 0
				? '<span class="qux-badge qux-badge-conv">' . esc_html( $text ) . '</span>'
				: "\xE2\x80\x94";
				break;
			case 'quorlyx_source':
				$origin = quorlyx_get_conversation_origin_details( $post_id );
				echo '<span class="qux-badge qux-badge-source">' . esc_html( $origin['source_label'] ) . '</span>';
				break;
			case 'quorlyx_trigger':
				$origin       = quorlyx_get_conversation_origin_details( $post_id );
				$trigger_name = (string) $origin['trigger_name'];
				$trigger_id   = (string) $origin['trigger_id'];
				$trigger_type = (string) $origin['trigger_type'];

				if ( 'trigger' !== (string) $origin['source'] ) {
					echo '&mdash;';
					break;
				}

				if ( '' === $trigger_name && '' !== $trigger_id ) {
					$trigger_name = $trigger_id;
				}

				if ( '' === $trigger_name ) {
					echo '&mdash;';
					break;
				}

				echo '<strong>' . esc_html( $trigger_name ) . '</strong>';
				if ( '' !== $trigger_id ) {
					echo '<br><small>' . esc_html( $trigger_id ) . '</small>';
				}
				if ( '' !== $trigger_type ) {
					echo '<br><small>' . esc_html( ucwords( str_replace( '_', ' ', $trigger_type ) ) ) . '</small>';
				}
				break;
			case 'quorlyx_last_activity':
				$t = (int) ( $conversation_record['last_activity'] ?? get_post_meta( $post_id, 'quorlyx_last_activity', true ) );
				echo $t ? esc_html( human_time_diff( $t, time() ) . ' ago' ) : "\xE2\x80\x94";
				break;
		}
	},
	10,
	2
);

