add_action(
	'pre_get_posts',
	function ( $query ) {
		if ( ! is_admin() || ! $query->is_main_query() ) {
			return;
		}
		$screen = get_current_screen();
		if ( ! $screen || 'quorlyx_conversation' !== $screen->post_type ) {
			if ( ! $screen || 'quorlyx_submission' !== $screen->post_type ) {
				return;
			}

			$meta_query = (array) $query->get( 'meta_query' );
			// phpcs:disable WordPress.Security.NonceVerification.Recommended -- Read-only admin filters.
			if ( ! empty( $_GET['qux_submission_status'] ) ) {
				$meta_query[] = array(
					'key'     => 'quorlyx_status',
					'value'   => sanitize_text_field( wp_unslash( $_GET['qux_submission_status'] ) ),
					'compare' => '=',
				);
			}
			if ( ! empty( $_GET['qux_submission_urgency'] ) ) {
				$meta_query[] = array(
					'key'     => 'quorlyx_urgency',
					'value'   => sanitize_text_field( wp_unslash( $_GET['qux_submission_urgency'] ) ),
					'compare' => '=',
				);
			}
			// phpcs:enable WordPress.Security.NonceVerification.Recommended
			if ( ! empty( $meta_query ) ) {
				$meta_query['relation'] = 'AND';
				$query->set( 'meta_query', $meta_query );
			}
			return;
		}

		$orderby = $query->get( 'orderby' );
		if ( 'quorlyx_message_count' === $orderby ) {
			$query->set( 'meta_key', 'quorlyx_message_count' );
			$query->set( 'orderby', 'meta_value_num' );
		} elseif ( 'quorlyx_last_activity' === $orderby ) {
			$query->set( 'meta_key', 'quorlyx_last_activity' );
			$query->set( 'orderby', 'meta_value_num' );
		}

		$meta_query = (array) $query->get( 'meta_query' );
		// phpcs:disable WordPress.Security.NonceVerification.Recommended -- Read-only admin filters.
		if ( ! empty( $_GET['qux_filter_variation'] ) ) {
			$meta_query[] = array(
				'key'     => 'quorlyx_ab_variation',
				'value'   => sanitize_text_field( wp_unslash( $_GET['qux_filter_variation'] ) ),
				'compare' => '=',
			);
		}
		if ( ! empty( $_GET['qux_filter_device'] ) ) {
			$meta_query[] = array(
				'key'     => 'quorlyx_device',
				'value'   => sanitize_text_field( wp_unslash( $_GET['qux_filter_device'] ) ),
				'compare' => '=',
			);
		}
		if ( ! empty( $_GET['qux_filter_source'] ) ) {
			$source_filter = sanitize_key( wp_unslash( $_GET['qux_filter_source'] ) );
			if ( 'trigger' === $source_filter ) {
				$meta_query[] = array(
					'key'     => 'quorlyx_source',
					'value'   => 'trigger',
					'compare' => '=',
				);
			} elseif ( 'normal' === $source_filter ) {
				$meta_query[] = array(
					'relation' => 'OR',
					array(
						'key'     => 'quorlyx_source',
						'value'   => 'normal',
						'compare' => '=',
					),
					array(
						'key'     => 'quorlyx_source',
						'compare' => 'NOT EXISTS',
					),
				);
			}
		}
		// phpcs:enable WordPress.Security.NonceVerification.Recommended
		if ( ! empty( $meta_query ) ) {
			$meta_query['relation'] = 'AND';
			$query->set( 'meta_query', $meta_query );
		}
	}
);

/**
 * Get the plugin logo URL used in admin UI.
