function quorlyx_get_plugin_logo_url() {
	return quorlyx_get_plugin_asset_url( 'assets/logo.png' );
}

/**
 * Render the main plugin dashboard screen.
 *
 * @return void
 */
function quorlyx_pro_render_dashboard() {
	wp_enqueue_style( 'quorlyx-dashboard-css', plugin_dir_url( __FILE__ ) . 'dist/dashboard.min.css', array(), '1.6.8' );
	$options = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$perf    = $options['performance'] ?? array();
	$options = array_replace_recursive( quorlyx_get_global_defaults(), $options );

	$ab_goal_names = array();
	if ( ! empty( $options['conversion_goals'] ) && is_array( $options['conversion_goals'] ) ) {
		foreach ( $options['conversion_goals'] as $goal ) {
			if ( ! empty( $goal['is_ab_goal'] ) ) {
				$ab_goal_names[] = $goal['name'];
			}
		}
	}
	$ab_test_title = ! empty( $ab_goal_names ) ? implode( ', ', $ab_goal_names ) : 'No Goal Selected';

	// Keep dashboard conversation cards accurate even when WP-Cron is delayed.
	quorlyx_maybe_refresh_conversation_stats();

	$ab_stats        = array_replace_recursive(
		array(
			'a' => array(
				'views'       => 0,
				'conversions' => 0,
			),
			'b' => array(
				'views'       => 0,
				'conversions' => 0,
			),
		),
		get_option( 'quorlyx_ab_stats', array() )
	);
	$conv_stats      = array_replace_recursive(
		array(
			'a' => array(
				'total'          => 0,
				'avg_messages'   => 0,
				'source_trigger' => 0,
				'source_normal'  => 0,
			),
			'b' => array(
				'total'          => 0,
				'avg_messages'   => 0,
				'source_trigger' => 0,
				'source_normal'  => 0,
			),
		),
		get_option( 'quorlyx_conversation_stats', array() )
	);
	$rate_a          = ( $ab_stats['a']['views'] > 0 ) ? ( $ab_stats['a']['conversions'] / $ab_stats['a']['views'] ) * 100 : 0;
	$rate_b          = ( $ab_stats['b']['views'] > 0 ) ? ( $ab_stats['b']['conversions'] / $ab_stats['b']['views'] ) * 100 : 0;
	$confidence_data = quorlyx_calculate_ab_confidence( $ab_stats );
	$goal_stats      = get_option( 'quorlyx_conversion_goal_stats', array() );
	arsort( $goal_stats );

	$action_stats = get_option( 'quorlyx_action_click_stats', array() );
	arsort( $action_stats );
	$action_labels = array();
	$all_actions   = array_merge( $options['variation_a']['actions'] ?? array(), $options['variation_b']['actions'] ?? array() );
	foreach ( $all_actions as $action ) {
		if ( isset( $action['id'] ) && isset( $action['label'] ) ) {
			$action_labels[ $action['id'] ] = $action['label'];
		}
	}

	$export_url             = add_query_arg(
		array(
			'quorlyx_export' => 'ab_results',
			'_wpnonce'       => wp_create_nonce( 'quorlyx_export_ab_results' ),
		),
		admin_url( 'admin.php' )
	);
	$trigger_export_url     = add_query_arg(
		array(
			'quorlyx_export' => 'trigger_analytics',
			'_wpnonce'       => wp_create_nonce( 'quorlyx_export_trigger_analytics' ),
		),
		admin_url( 'admin.php' )
	);
	$trigger_analytics_rows = quorlyx_get_trigger_analytics_rows( $options );
	$last_gen               = get_option( 'quorlyx_last_generation', array( 'status' => 'none' ) );
	$keyword_count          = count( array_filter( array_map( 'trim', explode( "\n", $options['post_generator']['keywords'] ?? '' ) ) ) );
	$pg_scope               = $options['post_generator']['ai_provider_scope'] ?? 'general';
	if ( 'independent' === $pg_scope ) {
		$provider_slug  = $options['post_generator']['ai_provider'] ?? '';
		$has_key        = ! empty( $options['post_generator']['ai_api_key'] );
		$provider_label = ( $provider_slug ? ucfirst( $provider_slug ) : 'Provider not set' ) . ' (Independent)';
	} else {
		$provider_slug  = $options['variation_a']['ai_provider'];
		$has_key        = ! empty( $options['variation_a']['api_keys'][ $provider_slug ] ?? '' );
		$provider_label = ( $provider_slug ? ucfirst( $provider_slug ) : 'Provider not set' ) . ' (General)';
	}
	?>
	<div class="wrap" id="quorlyx-dashboard-page">
		<?php
		// phpcs:disable WordPress.Security.NonceVerification.Recommended -- Read-only welcome banner.
		if ( isset( $_GET['welcome'] ) && 1 === absint( wp_unslash( $_GET['welcome'] ) ) ) :
			?>
		<div class="notice notice-success is-dismissible">
			<p><strong>Thanks for installing Quorlyx!</strong> We appreciate your business. Configure your settings below to get started.</p>
		</div>
		<?php endif; ?>
		<?php // phpcs:enable WordPress.Security.NonceVerification.Recommended ?>
		<div class="quorlyx-page-header">
			<div class="quorlyx-brand">
				<img class="quorlyx-brand-logo" src="<?php echo esc_url( quorlyx_get_plugin_logo_url() ); ?>" alt="Quorlyx" />
				<div class="quorlyx-titles">
					<h1>Quorlyx Dashboard</h1>
					<p class="subtitle">Optimize your chatbot with A/B testing and engagement insights</p>
				</div>
			</div>
			<div class="quorlyx-dashboard-actions">
				<a href="<?php echo esc_url( $export_url ); ?>" id="tour-step-export" class="button"><span class="dashicons dashicons-download"></span> Download Results (CSV)</a>
				<a href="<?php echo esc_url( $trigger_export_url ); ?>" class="button"><span class="dashicons dashicons-download"></span> Trigger Analytics CSV</a>
				<button class="button" id="quorlyx-restart-tour"><span class="dashicons dashicons-editor-help"></span> Restart Tour</button>
			</div>
		</div>

		<div class="quorlyx-dashboard-grid">
			<div class="postbox quorlyx-card ab-test-card" id="tour-step-dashboard-ab">
				<h2 class="hndle"><span><span class="dashicons dashicons-chart-bar"></span> A/B Test Results (Goals: <?php echo esc_html( $ab_test_title ); ?>)</span></h2>
				<div class="inside">
					<div class="ab-test-stats-grid">
						<div class="ab-test-stat-card">
							<h3>Variation A</h3>
							<p class="stat-views"><?php echo esc_html( number_format_i18n( $ab_stats['a']['views'] ) ); ?> Views</p>
							<p class="stat-conversions"><?php echo esc_html( number_format_i18n( $ab_stats['a']['conversions'] ) ); ?> Conversions</p>
							<div class="stat-rate-wrapper">
								<div class="stat-rate-bar"><div style="width: <?php echo esc_attr( number_format_i18n( $rate_a, 2 ) ); ?>%;"></div></div>
								<p class="stat-rate"><?php echo esc_html( number_format_i18n( $rate_a, 2 ) ); ?>%</p>
							</div>
							<p class="stat-desc">Conversion Rate</p>
							<div class="conversation-stats">
								<p class="stat-convos"><span><?php echo esc_html( number_format_i18n( $conv_stats['a']['total'] ) ); ?></span> Conversations</p>
								<p class="stat-avg-msg"><span><?php echo esc_html( number_format_i18n( $conv_stats['a']['avg_messages'], 1 ) ); ?></span> Avg. Msgs</p>
								<p class="stat-source-trigger"><span><?php echo esc_html( number_format_i18n( (int) ( $conv_stats['a']['source_trigger'] ?? 0 ) ) ); ?></span> Trigger</p>
								<p class="stat-source-normal"><span><?php echo esc_html( number_format_i18n( (int) ( $conv_stats['a']['source_normal'] ?? 0 ) ) ); ?></span> Normal</p>
							</div>
							<?php if ( 'a' === $confidence_data['winner'] ) : ?>
								<form method="post" action="">
									<?php wp_nonce_field( 'quorlyx_declare_winner_action', 'quorlyx_declare_winner_nonce' ); ?>
									<input type="hidden" name="winner_variation" value="a">
									<button type="submit" name="quorlyx_declare_winner" class="button button-primary"><span class="dashicons dashicons-thumbs-up"></span> Use This Version</button>
								</form>
							<div id="quorlyx-csv-mapping-ui" style="display:none; margin-top: 15px; border-top: 1px solid #eee; padding-top: 15px;">
								<h4 style="margin-top:0;">Map CSV Columns to Quorlyx Fields</h4>
								<table class="form-table" style="margin-bottom: 15px;">
									<tbody id="quorlyx-csv-mapping-rows">
										<!-- Populated by JS -->
									</tbody>
								</table>
								<p class="submit" style="margin:0;"><button type="button" class="button button-primary" id="quorlyx-csv-finalize-btn">Finalize Import</button></p>
							</div>
							<?php endif; ?>
						</div>

						<div class="ab-test-stat-card">
							<h3>Variation B</h3>
							<p class="stat-views"><?php echo esc_html( number_format_i18n( $ab_stats['b']['views'] ) ); ?> Views</p>
							<p class="stat-conversions"><?php echo esc_html( number_format_i18n( $ab_stats['b']['conversions'] ) ); ?> Conversions</p>
							<div class="stat-rate-wrapper">
								<div class="stat-rate-bar"><div style="width: <?php echo esc_attr( number_format_i18n( $rate_b, 2 ) ); ?>%;"></div></div>
								<p class="stat-rate"><?php echo esc_html( number_format_i18n( $rate_b, 2 ) ); ?>%</p>
							</div>
							<p class="stat-desc">Conversion Rate</p>
							<div class="conversation-stats">
								<p class="stat-convos"><span><?php echo esc_html( number_format_i18n( $conv_stats['b']['total'] ) ); ?></span> Conversations</p>
								<p class="stat-avg-msg"><span><?php echo esc_html( number_format_i18n( $conv_stats['b']['avg_messages'], 1 ) ); ?></span> Avg. Msgs</p>
								<p class="stat-source-trigger"><span><?php echo esc_html( number_format_i18n( (int) ( $conv_stats['b']['source_trigger'] ?? 0 ) ) ); ?></span> Trigger</p>
								<p class="stat-source-normal"><span><?php echo esc_html( number_format_i18n( (int) ( $conv_stats['b']['source_normal'] ?? 0 ) ) ); ?></span> Normal</p>
