/**
 * Get public post type objects that can be tracked by Content Insights.
 *
 * @return array<string,WP_Post_Type>
 */
function quorlyx_get_content_insights_post_types() {
	$post_types = get_post_types( array( 'public' => true ), 'objects' );
	unset( $post_types['attachment'] );

	return $post_types;
}

/**
 * Build selectable content item labels for Content Insights configuration.
 *
 * @param array<int,int|string> $selected_ids Already selected item IDs.
 * @return array<int,string>
 */
function quorlyx_get_content_insights_item_choices( $selected_ids = array() ) {
	$selected_ids = array_values( array_unique( array_filter( array_map( 'absint', (array) $selected_ids ) ) ) );
	$post_types   = array_keys( quorlyx_get_content_insights_post_types() );
	$recent_ids   = array();

	if ( ! empty( $post_types ) ) {
		$recent_ids = get_posts(
			array(
				'post_type'              => $post_types,
				'post_status'            => array( 'publish', 'private', 'draft', 'pending', 'future' ),
				// phpcs:ignore WordPress.WP.PostsPerPage.posts_per_page_posts_per_page -- Admin selector needs broad recent coverage across tracked post types.
				'posts_per_page'         => 200,
				'orderby'                => 'date',
				'order'                  => 'DESC',
				'fields'                 => 'ids',
				'ignore_sticky_posts'    => true,
				'no_found_rows'          => true,
				'update_post_meta_cache' => false,
				'update_post_term_cache' => false,
			)
		);
	}

	$item_ids = array_values( array_unique( array_merge( $selected_ids, $recent_ids ) ) );
	if ( empty( $item_ids ) ) {
		return array();
	}

	$items = get_posts(
		array(
			'post_type'              => 'any',
			'post_status'            => array( 'publish', 'private', 'draft', 'pending', 'future' ),
			'posts_per_page'         => count( $item_ids ),
			'post__in'               => $item_ids,
			'orderby'                => 'post__in',
			'ignore_sticky_posts'    => true,
			'no_found_rows'          => true,
			'update_post_meta_cache' => false,
			'update_post_term_cache' => false,
		)
	);

	$choices = array();
	foreach ( $items as $item ) {
		$post_type_object = get_post_type_object( $item->post_type );
		$type_label       = $post_type_object->labels->singular_name ?? $item->post_type;
		$status_object    = get_post_status_object( $item->post_status );
		$status_label     = $status_object->label ?? ucfirst( $item->post_status );
		$title            = get_the_title( $item );
		if ( '' === $title ) {
			$title = sprintf( 'Untitled #%d', (int) $item->ID );
		}

		$choices[ $item->ID ] = sprintf( '%1$s (%2$s, %3$s)', $title, $type_label, $status_label );
	}

	return $choices;
}

/**
 * Normalize include or exclude rule input into a clean string list.
 *
 * @param mixed $value Rule input from settings fields.
 * @return array<int,string>
 */
function quorlyx_sanitize_content_insights_rule_list( $value ) {
	$parts      = array();
	$raw_values = is_array( $value ) ? $value : array( $value );

	array_walk_recursive(
		$raw_values,
		static function ( $item ) use ( &$parts ) {
			$split = preg_split( '/[\r\n,]+/', (string) $item );
			if ( is_array( $split ) ) {
				$parts = array_merge( $parts, $split );
			}
		}
	);

	return array_values(
		array_filter(
			array_map(
				static function ( $part ) {
					return sanitize_text_field( trim( (string) $part ) );
				},
				(array) $parts
			)
		)
	);
}

/**
 * Determine whether a URL matches configured include rules.
 *
 * @param string              $post_url URL to evaluate.
 * @param array<string,mixed> $settings Content Insights settings.
 * @return bool
 */
function quorlyx_content_insights_url_matches_rules( $post_url, $settings ) {
	$exact_rules    = array_values( array_unique( array_filter( array_map( 'trim', (array) ( $settings['target_page_urls'] ?? array() ) ) ) ) );
	$contains_rules = array_values( array_unique( array_filter( array_map( 'trim', (array) ( $settings['target_url_contains'] ?? array() ) ) ) ) );

	if ( empty( $exact_rules ) && empty( $contains_rules ) ) {
		return false;
	}

	$post_url        = (string) $post_url;
	$post_path       = (string) wp_parse_url( $post_url, PHP_URL_PATH );
	$post_query      = (string) wp_parse_url( $post_url, PHP_URL_QUERY );
	$post_relative   = $post_path . ( $post_query ? '?' . $post_query : '' );
	$post_candidates = array_values(
		array_unique(
			array_filter(
				array(
					untrailingslashit( $post_url ),
					untrailingslashit( $post_relative ),
					ltrim( untrailingslashit( $post_relative ), '/' ),
				)
			)
		)
	);

	foreach ( $exact_rules as $rule ) {
		$normalized_rule = untrailingslashit( $rule );
		if ( in_array( $normalized_rule, $post_candidates, true ) || in_array( ltrim( $normalized_rule, '/' ), $post_candidates, true ) ) {
			return true;
		}
	}

	foreach ( $contains_rules as $rule ) {
		if ( false !== stripos( $post_url, $rule ) || false !== stripos( $post_relative, $rule ) ) {
			return true;
		}
	}

	return false;
}

/**
 * Determine whether a URL matches configured exclusion rules.
 *
 * @param string              $post_url URL to evaluate.
 * @param array<string,mixed> $settings Content Insights settings.
 * @return bool
 */
function quorlyx_content_insights_url_matches_exclusions( $post_url, $settings ) {
	$exact_rules    = array_values( array_unique( array_filter( array_map( 'trim', (array) ( $settings['excluded_page_urls'] ?? array() ) ) ) ) );
	$contains_rules = array_values( array_unique( array_filter( array_map( 'trim', (array) ( $settings['excluded_url_contains'] ?? array() ) ) ) ) );

	if ( empty( $exact_rules ) && empty( $contains_rules ) ) {
		return false;
	}

	return quorlyx_content_insights_url_matches_rules(
		$post_url,
		array(
			'target_page_urls'    => $exact_rules,
			'target_url_contains' => $contains_rules,
		)
	);
}

/**
 * Resolve Content Insights settings from payload or saved options.
 *
 * @param array<string,mixed>|null $settings Optional settings payload.
 * @return array<string,mixed>
 */
function quorlyx_get_content_insights_settings( $settings = null ) {
	if ( is_array( $settings ) ) {
		return $settings;
	}

	$options = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$options = array_replace_recursive( quorlyx_get_global_defaults(), is_array( $options ) ? $options : array() );

	return isset( $options['content_insights'] ) && is_array( $options['content_insights'] ) ? $options['content_insights'] : array();
}

/**
 * Determine whether DB-first data processing is enabled globally.
 *
 * @param array<string,mixed>|null $settings Optional Content Insights settings payload.
 * @return bool
 */
function quorlyx_should_use_global_db_processing( $settings = null ) {
	$insights_settings = quorlyx_get_content_insights_settings( $settings );

	return ! empty( $insights_settings['prefer_db_processing_global'] );
}

/**
 * Determine whether Content Insights is enabled.
 *
 * @param array<string,mixed>|null $settings Optional settings payload.
 * @return bool
 */
function quorlyx_content_insights_is_enabled( $settings = null ) {
	$insights_settings = quorlyx_get_content_insights_settings( $settings );

	return ! empty( $insights_settings['enabled'] );
}

/**
 * Resolve which conversion signals Content Insights should count.
 *
 * @param array<string,mixed>|null $settings Optional Content Insights settings payload.
 * @return string
 */
function quorlyx_get_content_insights_conversion_tracking_mode( $settings = null ) {
	$insights_settings = quorlyx_get_content_insights_settings( $settings );
	$mode              = sanitize_key( (string) ( $insights_settings['conversion_tracking_mode'] ?? 'any' ) );

	return in_array( $mode, array( 'any', 'conversion_goals' ), true ) ? $mode : 'any';
}

/**
 * Determine whether generic conversion signals should feed Content Insights.
 *
 * @param array<string,mixed>|null $settings Optional Content Insights settings payload.
 * @return bool
 */
function quorlyx_content_insights_tracks_any_conversions( $settings = null ) {
	return 'any' === quorlyx_get_content_insights_conversion_tracking_mode( $settings );
}

/**
 * Increment the Content Insights conversion metric for the current attribution source.
 *
 * @param int    $post_id     Optional analytics post ID.
 * @param string $content_key Optional virtual content key.
 * @return bool
 */
function quorlyx_increment_content_insights_attributed_conversion( $post_id = 0, $content_key = '' ) {
	$post_id     = quorlyx_get_canonical_analytics_post_id( absint( $post_id ) );
	$content_key = sanitize_key( (string) $content_key );

	if ( $post_id <= 0 && '' === $content_key ) {
		$attribution_source = quorlyx_get_attribution_source_from_request();
		$post_id            = quorlyx_get_canonical_analytics_post_id( absint( $attribution_source['post_id'] ?? 0 ) );
		$content_key        = sanitize_key( (string) ( $attribution_source['content_key'] ?? '' ) );
	}

	if ( $post_id > 0 ) {
		$content_key = '';
	}

	if ( $post_id <= 0 && '' === $content_key ) {
		return false;
	}

	quorlyx_increment_analytics_metric( $post_id, '_quorlyx_analytics_conversions', 1, $content_key );
	return true;
}

/**
 * Check whether a post should be included in Content Insights reporting.
 *
 * @param int                 $post_id   Post ID.
 * @param array<string,mixed> $settings  Content Insights settings.
 * @return bool
 */
function quorlyx_content_insights_post_matches_settings( $post_id, $settings ) {
	if ( ! quorlyx_content_insights_is_enabled( $settings ) ) {
		return false;
	}

	$post = get_post( $post_id );
	if ( ! $post instanceof WP_Post ) {
		return false;
	}

	$post_type_object = get_post_type_object( $post->post_type );
	if ( ! $post_type_object || empty( $post_type_object->public ) ) {
		return false;
	}

	$tracked_post_types = array_values( array_unique( array_map( 'sanitize_key', (array) ( $settings['tracked_post_types'] ?? array() ) ) ) );
	$excluded_types     = array_values( array_unique( array_map( 'sanitize_key', (array) ( $settings['excluded_post_types'] ?? array() ) ) ) );
	$post_url           = get_permalink( $post_id );

	if ( in_array( $post->post_type, $excluded_types, true ) || quorlyx_content_insights_url_matches_exclusions( $post_url, $settings ) ) {
		return false;
	}

	$tracking_mode = sanitize_key( $settings['tracking_mode'] ?? 'all_public' );
	if ( 'specific_items' === $tracking_mode && ! quorlyx_content_insights_url_matches_rules( $post_url, $settings ) ) {
		return false;
	}
	if ( 'post_types' === $tracking_mode && ! in_array( $post->post_type, $tracked_post_types, true ) ) {
		return false;
	}

	$source_mode  = sanitize_key( $settings['content_source'] ?? 'any' );
	$is_generated = '1' === (string) get_post_meta( $post_id, '_quorlyx_generated', true );
	$is_improved  = quorlyx_is_content_improved( $post_id );
	if ( 'ai_generated' === $source_mode && ! $is_generated ) {
		return false;
	}
	if ( 'manual' === $source_mode && $is_generated ) {
		return false;
	}

	$improvement_status = sanitize_key( $settings['improvement_status'] ?? 'any' );
	if ( 'improved' === $improvement_status && ! $is_improved ) {
		return false;
	}
	if ( 'not_improved' === $improvement_status && $is_improved ) {
		return false;
	}

	return true;
}

/**
 * Get default thresholds used in Content Insights recommendations.
 *
 * @return array<string,int|float>
 */
function quorlyx_get_content_insights_thresholds() {
	return array(
		'min_views'           => 50,
		'min_conversion_rate' => 2.0,
		'min_avg_time'        => 45,
		'min_scroll_depth'    => 80,
	);
}

/**
 * Build SEO status metrics for a content item.
 *
 * @param int    $post_id     Post ID.
 * @param string $content_key Virtual content key when no post exists.
 * @return array<string,int|bool|string>
 */
function quorlyx_get_content_insight_seo_status( $post_id, $content_key = '' ) {
	$post_id     = absint( $post_id );
	$content_key = sanitize_key( $content_key );

	if ( $post_id <= 0 ) {
		return array(
			'eligible'            => false,
			'has_schema'          => false,
			'internal_link_count' => 0,
			'word_count'          => 0,
			'age_days'            => 0,
			'content_key'         => $content_key,
		);
	}

	$post = get_post( $post_id );
	if ( ! $post instanceof WP_Post ) {
		return array(
			'eligible'            => false,
			'has_schema'          => false,
			'internal_link_count' => 0,
			'word_count'          => 0,
			'age_days'            => 0,
			'content_key'         => $content_key,
		);
	}

	$raw_content         = (string) $post->post_content;
	$plain_content       = trim( wp_strip_all_tags( $raw_content ) );
	$schema              = (string) get_post_meta( $post_id, '_quorlyx_generated_schema', true );
	$internal_link_count = 0;

	if ( preg_match_all( '/<a\s[^>]*href=["\']([^"\']+)["\'][^>]*>/i', $raw_content, $matches ) ) {
		$home_variants = array(
			untrailingslashit( home_url() ),
			trailingslashit( home_url() ),
		);

		foreach ( (array) $matches[1] as $href ) {
			$href = (string) $href;
			if ( 0 === strpos( $href, '/' ) ) {
				++$internal_link_count;
				continue;
			}

			foreach ( $home_variants as $home_variant ) {
				if ( '' !== $home_variant && 0 === strpos( $href, $home_variant ) ) {
					++$internal_link_count;
					break;
				}
			}
		}
	}

	$post_date = get_post_time( 'U', true, $post );
	$age_days  = $post_date ? (int) max( 0, floor( ( time() - $post_date ) / DAY_IN_SECONDS ) ) : 0;

	return array(
		'eligible'            => true,
		'has_schema'          => '' !== trim( $schema ),
		'internal_link_count' => $internal_link_count,
		'word_count'          => str_word_count( $plain_content ),
		'age_days'            => $age_days,
		'content_key'         => $content_key,
	);
}

/**
 * Generate SEO-specific recommendations for an insight row.
 *
 * @param array<string,mixed>     $row        Insight row data.
 * @param array<string,int|float> $thresholds Recommendation thresholds.
 * @return array<int,array<string,string>>
 */
function quorlyx_get_content_insight_seo_recommendations( $row, $thresholds ) {
	$post_id    = absint( $row['post_id'] ?? 0 );
	$seo_status = (array) ( $row['seo_status'] ?? quorlyx_get_content_insight_seo_status( $post_id, $row['content_key'] ?? '' ) );
	if ( empty( $seo_status['eligible'] ) ) {
		return array();
	}

	$recommendations   = array();
	$views             = (int) ( $row['views'] ?? 0 );
	$min_views         = (int) ( $thresholds['min_views'] ?? 50 );
	$age_days          = (int) ( $seo_status['age_days'] ?? 0 );
	$internal_links    = (int) ( $seo_status['internal_link_count'] ?? 0 );
	$word_count        = (int) ( $seo_status['word_count'] ?? 0 );
	$has_schema        = ! empty( $seo_status['has_schema'] );
	$post_type         = sanitize_text_field( (string) ( $row['post_type'] ?? 'content' ) );
	$is_low_visibility = $views < ( $min_views * 2 );

	if ( $age_days >= 45 && $is_low_visibility ) {
		$recommendations[] = array(
			'type'    => 'seo',
			'label'   => 'Refresh this older content for SEO',
			'details' => 'This older ' . $post_type . ' is not attracting enough visits. Run the SEO improvement planner to refresh search intent, related keywords, headings, and snippet copy.',
		);
	}

	if ( ! $has_schema ) {
		$recommendations[] = array(
			'type'    => 'seo',
			'label'   => 'Generate schema markup',
			'details' => 'No saved schema markup was found for this item. Use Quorlyx SEO tools to generate structured data that matches the page type.',
		);
	}

	if ( $internal_links < 2 && $is_low_visibility ) {
		$recommendations[] = array(
			'type'    => 'seo',
			'label'   => 'Suggest internal links',
			'details' => 'This page likely needs more internal link support. Use Quorlyx internal-link suggestions and add links from related posts, pages, or products.',
		);
	}

	if ( $word_count > 0 && $word_count < 500 && $is_low_visibility ) {
		$recommendations[] = array(
			'type'    => 'seo',
			'label'   => 'Expand related keyword coverage',
			'details' => 'The content is relatively short for search discovery. Add related keywords, missing questions, and supporting sections around the main topic.',
		);
	}

	return $recommendations;
}

/**
 * Get a synthetic homepage item when front page displays latest posts.
 *
 * @return array<string,mixed>|null
 */
function quorlyx_get_content_insights_homepage_item() {
	if ( 'posts' !== get_option( 'show_on_front' ) ) {
		return null;
	}

	return array(
		'content_key'  => 'homepage',
		'title'        => 'Homepage',
		'url'          => home_url( '/' ),
		'post_type'    => 'homepage',
		'is_generated' => false,
		'edit_url'     => '',
	);
}

/**
 * Determine whether homepage analytics should be included.
 *
 * @param array<string,mixed> $settings Content Insights settings.
 * @return bool
 */
function quorlyx_content_insights_homepage_matches_settings( $settings ) {
	if ( ! quorlyx_content_insights_is_enabled( $settings ) ) {
		return false;
	}

	$homepage_item = quorlyx_get_content_insights_homepage_item();
	if ( empty( $homepage_item ) ) {
		$homepage_item = array(
			'content_key'  => 'homepage',
			'title'        => 'Homepage',
			'url'          => home_url( '/' ),
			'post_type'    => 'homepage',
			'is_generated' => false,
			'edit_url'     => '',
		);
	}

	$tracking_mode = sanitize_key( $settings['tracking_mode'] ?? 'all_public' );
	if ( 'post_types' === $tracking_mode ) {
		$tracked_post_types = array_values( array_unique( array_map( 'sanitize_key', (array) ( $settings['tracked_post_types'] ?? array() ) ) ) );
		if ( ! in_array( 'post', $tracked_post_types, true ) && ! in_array( 'page', $tracked_post_types, true ) ) {
			return false;
		}
	}

	if ( quorlyx_content_insights_url_matches_exclusions( $homepage_item['url'], $settings ) ) {
		return false;
	}

	if ( 'specific_items' === $tracking_mode && ! quorlyx_content_insights_url_matches_rules( $homepage_item['url'], $settings ) ) {
		return false;
	}

	$source_mode = sanitize_key( $settings['content_source'] ?? 'any' );
	if ( 'ai_generated' === $source_mode ) {
		return false;
	}

	$improvement_status = sanitize_key( $settings['improvement_status'] ?? 'any' );
	if ( 'improved' === $improvement_status ) {
		return false;
	}

	return true;
}

/**
 * Get the virtual analytics storage payload.
 *
 * @return array<string,mixed>
 */
function quorlyx_get_virtual_analytics_store() {
	if ( quorlyx_should_use_global_db_processing() && quorlyx_virtual_analytics_table_exists() ) {
		quorlyx_migrate_virtual_analytics_option_to_table();

		global $wpdb;
		$table_name = quorlyx_get_virtual_analytics_table_name();

		// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Full-row table read used to reconstruct compatibility payload.
		$rows = $wpdb->get_results( "SELECT content_key, meta_key, metric_value FROM {$table_name}", ARRAY_A );
		$store = array();

		foreach ( (array) $rows as $row ) {
			$content_key = sanitize_key( (string) ( $row['content_key'] ?? '' ) );
			$meta_key    = sanitize_key( (string) ( $row['meta_key'] ?? '' ) );
			$value       = (int) ( $row['metric_value'] ?? 0 );

			if ( '' === $content_key || '' === $meta_key ) {
				continue;
			}

			if ( ! isset( $store[ $content_key ] ) || ! is_array( $store[ $content_key ] ) ) {
				$store[ $content_key ] = array();
			}

			$store[ $content_key ][ $meta_key ] = $value;
		}

		return $store;
	}

	$store = get_option( 'quorlyx_virtual_analytics', array() );

	return is_array( $store ) ? $store : array();
}

/**
 * Resolve the DB-first analytics key for post-backed or virtual content.
 *
 * @param int    $post_id     Post ID.
 * @param string $content_key Virtual content key.
 * @return string
 */
function quorlyx_get_db_analytics_content_key( $post_id, $content_key = '' ) {
	$post_id     = absint( $post_id );
	$content_key = sanitize_key( (string) $content_key );

	if ( $post_id > 0 ) {
		return 'post_' . $post_id;
	}

	return $content_key;
}

/**
 * Read an analytics metric from post meta or virtual analytics storage.
 *
 * @param int    $post_id     Post ID.
 * @param string $meta_key    Analytics key.
 * @param string $content_key Virtual content key.
 * @return int
 */
function quorlyx_get_analytics_metric( $post_id, $meta_key, $content_key = '' ) {
	$post_id  = absint( $post_id );
	$meta_key = sanitize_key( (string) $meta_key );
	$db_key   = quorlyx_get_db_analytics_content_key( $post_id, $content_key );

	if ( '' !== $db_key && quorlyx_should_use_global_db_processing() && quorlyx_virtual_analytics_table_exists() ) {
		global $wpdb;
		$table_name = quorlyx_get_virtual_analytics_table_name();

		// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Point lookup against dedicated analytics table.
		$value = $wpdb->get_var(
			$wpdb->prepare(
				"SELECT metric_value FROM {$table_name} WHERE content_key = %s AND meta_key = %s LIMIT 1",
				$db_key,
				$meta_key
			)
		);

		if ( null !== $value ) {
			return (int) $value;
		}
		if ( $post_id > 0 ) {
			return (int) get_post_meta( $post_id, $meta_key, true );
		}
		return 0;
	}

	if ( $post_id > 0 ) {
		return (int) get_post_meta( $post_id, $meta_key, true );
	}

	$content_key = sanitize_key( (string) $content_key );

	if ( '' === $content_key ) {
		return 0;
	}

	$store = quorlyx_get_virtual_analytics_store();

	return (int) ( $store[ $content_key ][ $meta_key ] ?? 0 );
}

/**
 * Bump the analytics updated timestamp and return its value.
 *
 * @return int
 */
function quorlyx_touch_content_analytics_updated_at() {
	$next_updated_at = time();
	$previous_value  = absint( get_option( 'quorlyx_content_analytics_updated_at', 0 ) );
	if ( $next_updated_at <= $previous_value ) {
		$next_updated_at = $previous_value + 1;
	}

	update_option( 'quorlyx_content_analytics_updated_at', $next_updated_at, false );

	return $next_updated_at;
}

/**
 * Get the combined insights-gate data version marker.
 *
 * @return int
 */
function quorlyx_get_insights_gate_data_version() {
	$trigger_analytics = quorlyx_get_trigger_analytics_store();
	$trigger_updated   = absint( $trigger_analytics['updated_at'] ?? 0 );
	$content_updated   = absint( get_option( 'quorlyx_content_analytics_updated_at', 0 ) );

	return max( 1, $trigger_updated, $content_updated );
}

/**
 * Get metric keys used by Content Insights analytics.
 *
 * @return array<int,string>
 */
function quorlyx_get_content_insights_metric_keys() {
	return array(
		'_quorlyx_analytics_views',
		'_quorlyx_analytics_time_on_page',
		'_quorlyx_analytics_scroll_depth',
		'_quorlyx_analytics_scroll_depth_total',
		'_quorlyx_analytics_scroll_depth_count',
		'_quorlyx_analytics_add_to_cart',
		'_quorlyx_analytics_checkout_visits',
		'_quorlyx_analytics_checkout_success',
		'_quorlyx_analytics_conversions',
	);
}

/**
 * Check whether a metric key should only move upward.
 *
 * @param string $meta_key Analytics key.
 * @return bool
 */
function quorlyx_is_non_decreasing_analytics_metric( $meta_key ) {
	$meta_key = sanitize_key( (string) $meta_key );

	$non_decreasing_keys = array_diff(
		quorlyx_get_content_insights_metric_keys(),
		array( '_quorlyx_analytics_scroll_depth' )
	);

	return in_array( $meta_key, $non_decreasing_keys, true );
}

/**
 * Reset Content Insights post-meta metrics for one or more post types.
 *
 * @param array<int,string> $post_types Post type slugs.
 * @return int Deleted meta rows.
 */
function quorlyx_reset_content_insight_post_metrics_by_type( $post_types ) {
	$post_types = array_values(
		array_unique(
			array_filter(
				array_map( 'sanitize_key', (array) $post_types ),
				'post_type_exists'
			)
		)
	);

	if ( empty( $post_types ) ) {
		return 0;
	}

	$metric_keys = quorlyx_get_content_insights_metric_keys();

	global $wpdb;

	$post_type_placeholders = implode( ', ', array_fill( 0, count( $post_types ), '%s' ) );
	$meta_key_placeholders  = implode( ', ', array_fill( 0, count( $metric_keys ), '%s' ) );
	$post_ids               = get_posts(
		array(
			'post_type'              => $post_types,
			'post_status'            => 'any',
			// phpcs:ignore WordPress.WP.PostsPerPage.posts_per_page_posts_per_page -- Explicit admin reset needs all matching content IDs for cache invalidation.
			'posts_per_page'         => -1,
			'fields'                 => 'ids',
			'ignore_sticky_posts'    => true,
			'no_found_rows'          => true,
			'update_post_meta_cache' => false,
			'update_post_term_cache' => false,
		)
	);

	if ( empty( $post_ids ) ) {
		return 0;
	}

	$query = $wpdb->prepare(
		"DELETE pm FROM {$wpdb->postmeta} pm INNER JOIN {$wpdb->posts} p ON p.ID = pm.post_id WHERE p.post_type IN ({$post_type_placeholders}) AND pm.meta_key IN ({$meta_key_placeholders})",
		array_merge( $post_types, $metric_keys )
	);

	// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Explicit admin reset operation for analytics post meta.
	$deleted = $wpdb->query( $query );

	if ( quorlyx_virtual_analytics_table_exists() ) {
		$table_name = quorlyx_get_virtual_analytics_table_name();
		foreach ( array_chunk( array_map( 'absint', $post_ids ), 500 ) as $post_id_chunk ) {
			$content_keys = array_map(
				function ( $post_id ) {
					return 'post_' . absint( $post_id );
				},
				$post_id_chunk
			);
			$content_key_placeholders = implode( ', ', array_fill( 0, count( $content_keys ), '%s' ) );
			$metric_key_placeholders  = implode( ', ', array_fill( 0, count( $metric_keys ), '%s' ) );
			// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Explicit admin reset operation for DB-first analytics rows.
			$db_deleted = $wpdb->query(
				$wpdb->prepare(
					"DELETE FROM {$table_name} WHERE content_key IN ({$content_key_placeholders}) AND meta_key IN ({$metric_key_placeholders})",
					array_merge( $content_keys, $metric_keys )
				)
			);
			if ( false !== $db_deleted ) {
				$deleted += (int) $db_deleted;
			}
		}
	}

	foreach ( $post_ids as $post_id ) {
		wp_cache_delete( absint( $post_id ), 'post_meta' );
	}

	return max( 0, (int) $deleted );
}

/**
 * Reset virtual/non-post Content Insights metrics.
 *
 * @return int Deleted virtual metric rows.
 */
function quorlyx_reset_virtual_content_insight_metrics() {
	$deleted = 0;

	if ( quorlyx_virtual_analytics_table_exists() ) {
		global $wpdb;
		$table_name = quorlyx_get_virtual_analytics_table_name();

		// phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Table name comes from trusted helper with wpdb prefix.
		$result = $wpdb->query( "DELETE FROM {$table_name} WHERE content_key NOT LIKE 'post\\_%'" );
		if ( false !== $result ) {
			$deleted += (int) $result;
		}
	}

	$store = get_option( 'quorlyx_virtual_analytics', array() );
	if ( is_array( $store ) && ! empty( $store ) ) {
		foreach ( $store as $metrics ) {
			$deleted += is_array( $metrics ) ? count( $metrics ) : 1;
		}
		delete_option( 'quorlyx_virtual_analytics' );
	}

	return max( 0, $deleted );
}

/**
 * Update an analytics metric in post meta or virtual storage.
 *
 * @param int    $post_id      Post ID.
 * @param string $meta_key     Metric key.
 * @param int    $value        Metric value.
 * @param string $content_key  Virtual content key.
 * @param bool   $force_replace Whether to bypass non-decreasing checks.
 * @return void
 */
function quorlyx_update_analytics_metric( $post_id, $meta_key, $value, $content_key = '', $force_replace = false ) {
	$post_id                = absint( $post_id );
	$meta_key               = sanitize_key( (string) $meta_key );
	$value                  = (int) $value;
	$content_key            = sanitize_key( (string) $content_key );
	$force_replace          = (bool) $force_replace;
	$enforce_non_decreasing = ( ! $force_replace ) && quorlyx_is_non_decreasing_analytics_metric( $meta_key );
	$db_key                 = quorlyx_get_db_analytics_content_key( $post_id, $content_key );

	if ( '' === $db_key ) {
		return;
	}

	if ( quorlyx_should_use_global_db_processing() && quorlyx_virtual_analytics_table_exists() ) {
		global $wpdb;

		$table_name = quorlyx_get_virtual_analytics_table_name();
		$updated_at = gmdate( 'Y-m-d H:i:s' );

		if ( $enforce_non_decreasing ) {
			// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Atomic upsert keeps non-decreasing metrics monotonic.
			$result = $wpdb->query(
				$wpdb->prepare(
					"INSERT INTO {$table_name} (content_key, meta_key, metric_value, updated_at) VALUES (%s, %s, %d, %s)
					ON DUPLICATE KEY UPDATE
						metric_value = GREATEST(metric_value, VALUES(metric_value)),
						updated_at = VALUES(updated_at)",
					$db_key,
					$meta_key,
					(int) $value,
					$updated_at
				)
			);
		} else {
			// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Atomic upsert for virtual analytics metrics.
			$result = $wpdb->query(
				$wpdb->prepare(
					"INSERT INTO {$table_name} (content_key, meta_key, metric_value, updated_at) VALUES (%s, %s, %d, %s)
					ON DUPLICATE KEY UPDATE
						metric_value = VALUES(metric_value),
						updated_at = VALUES(updated_at)",
					$db_key,
					$meta_key,
					(int) $value,
					$updated_at
				)
			);
		}

		if ( false !== $result ) {
			quorlyx_touch_content_analytics_updated_at();
			return;
		}
	}

	if ( $post_id > 0 ) {
		if ( $enforce_non_decreasing ) {
			$current_value = (int) get_post_meta( $post_id, $meta_key, true );
			if ( $current_value > $value ) {
				$value = $current_value;
			}
		}

		update_post_meta( $post_id, $meta_key, (int) $value );
		quorlyx_touch_content_analytics_updated_at();
		return;
	}

	$store = quorlyx_get_virtual_analytics_store();
	if ( ! isset( $store[ $content_key ] ) || ! is_array( $store[ $content_key ] ) ) {
		$store[ $content_key ] = array();
	}

	if ( $enforce_non_decreasing ) {
		$current_value = (int) ( $store[ $content_key ][ $meta_key ] ?? 0 );
		if ( $current_value > $value ) {
			$value = $current_value;
		}
	}

	$store[ $content_key ][ $meta_key ] = (int) $value;
	update_option( 'quorlyx_virtual_analytics', $store, false );
	quorlyx_touch_content_analytics_updated_at();
}

/**
 * Increment an analytics metric without the usual read-modify-write race.
 *
 * @param int    $post_id     Post ID.
 * @param string $meta_key    Metric key.
 * @param int    $delta       Amount to add.
 * @param string $content_key Virtual content key.
 * @return int Updated metric value.
 */
function quorlyx_increment_analytics_metric( $post_id, $meta_key, $delta = 1, $content_key = '' ) {
	$post_id     = absint( $post_id );
	$meta_key    = sanitize_key( (string) $meta_key );
	$delta       = (int) $delta;
	$content_key = sanitize_key( (string) $content_key );
	$db_key      = quorlyx_get_db_analytics_content_key( $post_id, $content_key );

	if ( '' === $meta_key || 0 === $delta ) {
		return quorlyx_get_analytics_metric( $post_id, $meta_key, $content_key );
	}

	if ( '' !== $db_key && quorlyx_should_use_global_db_processing() && quorlyx_virtual_analytics_table_exists() ) {
		global $wpdb;

		$table_name = quorlyx_get_virtual_analytics_table_name();
		$updated_at = gmdate( 'Y-m-d H:i:s' );

		// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Atomic upsert increments analytics counters.
		$result = $wpdb->query(
			$wpdb->prepare(
				"INSERT INTO {$table_name} (content_key, meta_key, metric_value, updated_at) VALUES (%s, %s, %d, %s)
				ON DUPLICATE KEY UPDATE
					metric_value = metric_value + VALUES(metric_value),
					updated_at = VALUES(updated_at)",
				$db_key,
				$meta_key,
				$delta,
				$updated_at
			)
		);

		if ( false !== $result ) {
			quorlyx_touch_content_analytics_updated_at();
			return quorlyx_get_analytics_metric( $post_id, $meta_key, $content_key );
		}
	}

	if ( $post_id > 0 ) {
		global $wpdb;

		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Atomic counter update avoids dropped tracking increments.
		$meta_id = $wpdb->get_var(
			$wpdb->prepare(
				"SELECT meta_id FROM {$wpdb->postmeta} WHERE post_id = %d AND meta_key = %s ORDER BY meta_id ASC LIMIT 1",
				$post_id,
				$meta_key
			)
		);

		if ( $meta_id ) {
			// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Atomic counter update avoids dropped tracking increments.
			$wpdb->query(
				$wpdb->prepare(
					"UPDATE {$wpdb->postmeta} SET meta_value = CAST(meta_value AS SIGNED) + %d WHERE meta_id = %d",
					$delta,
					absint( $meta_id )
				)
			);
			wp_cache_delete( $post_id, 'post_meta' );
		} else {
			add_post_meta( $post_id, $meta_key, max( 0, $delta ), true );
		}

		quorlyx_touch_content_analytics_updated_at();
		return quorlyx_get_analytics_metric( $post_id, $meta_key, $content_key );
	}

	if ( '' === $content_key ) {
		return 0;
	}

	$store = quorlyx_get_virtual_analytics_store();
	if ( ! isset( $store[ $content_key ] ) || ! is_array( $store[ $content_key ] ) ) {
		$store[ $content_key ] = array();
	}

	$current_value                       = (int) ( $store[ $content_key ][ $meta_key ] ?? 0 );
	$store[ $content_key ][ $meta_key ] = max( 0, $current_value + $delta );
	update_option( 'quorlyx_virtual_analytics', $store, false );
	quorlyx_touch_content_analytics_updated_at();

	return (int) $store[ $content_key ][ $meta_key ];
}

/**
 * Resolve a canonical analytics post ID for supported content types.
 *
 * @param int $post_id Raw post ID.
 * @return int
 */
function quorlyx_get_canonical_analytics_post_id( $post_id ) {
	$post_id = absint( $post_id );
	if ( $post_id <= 0 ) {
		return 0;
	}

	if ( 'product_variation' === get_post_type( $post_id ) ) {
		$parent_id = wp_get_post_parent_id( $post_id );
		if ( $parent_id > 0 && 'product' === get_post_type( $parent_id ) ) {
			return absint( $parent_id );
		}
	}

	return $post_id;
}

/**
 * Resolve attribution source from request/query/cookies.
 *
 * @return array<string,int|string>
 */
function quorlyx_get_attribution_source_from_request() {
	$post_id     = 0;
	$content_key = '';

	// phpcs:disable WordPress.Security.NonceVerification.Recommended -- Read-only attribution lookup from URL parameters.
	if ( isset( $_GET['quorlyx_src'] ) ) {
		$src = sanitize_text_field( wp_unslash( $_GET['quorlyx_src'] ) );
		if ( ctype_digit( (string) $src ) ) {
			$post_id = absint( $src );
		} else {
			$content_key = sanitize_key( $src );
		}
	}
	// phpcs:enable WordPress.Security.NonceVerification.Recommended

	if ( $post_id <= 0 && '' === $content_key && isset( $_SERVER['HTTP_REFERER'] ) ) {
		$referrer = esc_url_raw( wp_unslash( $_SERVER['HTTP_REFERER'] ) );
		if ( '' !== $referrer ) {
			$ref_query = (string) wp_parse_url( $referrer, PHP_URL_QUERY );
			if ( '' !== $ref_query ) {
				parse_str( $ref_query, $ref_params );
				if ( isset( $ref_params['quorlyx_src'] ) ) {
					$ref_src = sanitize_text_field( (string) $ref_params['quorlyx_src'] );
					if ( ctype_digit( (string) $ref_src ) ) {
						$post_id = absint( $ref_src );
					} else {
						$content_key = sanitize_key( $ref_src );
					}
				}
			}
		}
	}

	if ( $post_id <= 0 && isset( $_COOKIE['quorlyx_attribution_post_id'] ) ) {
		$post_id = absint( wp_unslash( $_COOKIE['quorlyx_attribution_post_id'] ) );
	}

	if ( $post_id <= 0 && '' === $content_key && isset( $_COOKIE['quorlyx_attribution_content_key'] ) ) {
		$content_key = sanitize_key( wp_unslash( $_COOKIE['quorlyx_attribution_content_key'] ) );
	}

	if ( $post_id > 0 ) {
		$post_id     = quorlyx_get_canonical_analytics_post_id( $post_id );
		$content_key = '';
	}

	if ( $post_id <= 0 && '' === $content_key ) {
		return array(
			'post_id'     => 0,
			'content_key' => '',
		);
	}

	return array(
		'post_id'     => $post_id,
		'content_key' => $content_key,
	);
}

/**
 * Normalize custom conversion rules for behavior pattern settings.
 *
 * @param mixed $custom_conversions Raw custom conversion rules.
 * @return array<int,array<string,string>>
 */
function quorlyx_normalize_behavior_custom_conversions( $custom_conversions ) {
	$normalized = array();

	if ( ! is_array( $custom_conversions ) ) {
		return $normalized;
	}

	foreach ( $custom_conversions as $custom_conversion ) {
		if ( ! is_array( $custom_conversion ) ) {
			continue;
		}

		$conversion_type   = sanitize_key( (string) ( $custom_conversion['type'] ?? '' ) );
		$conversion_target = sanitize_text_field( (string) ( $custom_conversion['target'] ?? '' ) );
		$conversion_target = trim( $conversion_target );

		if ( ! in_array( $conversion_type, array( 'form_submit', 'click', 'event' ), true ) || '' === $conversion_target ) {
			continue;
		}

		$normalized[] = array(
			'type'   => $conversion_type,
			'target' => $conversion_target,
		);
	}

	return array_values( array_unique( $normalized, SORT_REGULAR ) );
}

/**
 * Normalize behavior-pattern settings and map legacy conversion fields.
 *
 * @param mixed                    $behavior_settings Raw behavior settings.
 * @param array<string,mixed>|null $defaults          Optional defaults.
 * @return array<string,mixed>
 */
function quorlyx_normalize_behavior_pattern_settings( $behavior_settings, $defaults = null ) {
	$defaults = is_array( $defaults ) ? $defaults : (array) ( quorlyx_get_global_defaults()['content_insights']['behavior_patterns'] ?? array() );
	$settings = is_array( $behavior_settings ) ? array_replace( $defaults, $behavior_settings ) : $defaults;

	$legacy_action_type  = sanitize_key( (string) ( $settings['conversion_action_type'] ?? 'buy' ) );
	$legacy_form_target  = sanitize_text_field( (string) ( $settings['track_form_selector'] ?? 'form' ) );
	$legacy_form_target  = '' !== trim( $legacy_form_target ) ? trim( $legacy_form_target ) : 'form';

	if ( ! array_key_exists( 'track_woocommerce_purchase', $settings ) ) {
		$settings['track_woocommerce_purchase'] = ! in_array( $legacy_action_type, array( 'form_submit' ), true );
	} else {
		$settings['track_woocommerce_purchase'] = ! empty( $settings['track_woocommerce_purchase'] );
	}

	$settings['custom_conversions'] = quorlyx_normalize_behavior_custom_conversions( $settings['custom_conversions'] ?? array() );

	if ( empty( $settings['custom_conversions'] ) && in_array( $legacy_action_type, array( 'form_submit', 'buy_or_form' ), true ) ) {
		$settings['custom_conversions'][] = array(
			'type'   => 'form_submit',
			'target' => $legacy_form_target,
		);
	}

	$settings['use_reference_matching']        = ! empty( $settings['use_reference_matching'] );
	$settings['prefer_db_processing']          = ! empty( $settings['prefer_db_processing'] );
	$settings['reference_error_tolerance_pct'] = max( 0, min( 50, absint( $settings['reference_error_tolerance_pct'] ?? 15 ) ) );
	$settings['reference_min_profiles']        = max( 5, min( 10000, absint( $settings['reference_min_profiles'] ?? 20 ) ) );
	$settings['reference_min_pattern_samples'] = max( 1, min( 100, absint( $settings['reference_min_pattern_samples'] ?? 3 ) ) );
	$settings['reference_fallback_to_rules']   = ! empty( $settings['reference_fallback_to_rules'] );
	$weight_defaults                           = array(
		'visit_frequency' => 1.0,
		'pages_viewed'    => 1.0,
		'dwell_time_avg'  => 1.0,
		'cart_activity'   => 1.0,
		'scroll_depth'    => 1.0,
		'started_chat'    => 1.0,
		'checkout_flow'   => 1.0,
		'traffic_source'  => 1.0,
	);
	$weight_settings                           = is_array( $settings['pattern_metric_weights'] ?? null ) ? $settings['pattern_metric_weights'] : array();
	$settings['pattern_metric_weights']        = array();

	foreach ( $weight_defaults as $metric_key => $metric_default ) {
		$raw_weight = array_key_exists( $metric_key, $weight_settings ) ? (float) $weight_settings[ $metric_key ] : (float) $metric_default;
		$settings['pattern_metric_weights'][ $metric_key ] = max( 0.1, min( 10.0, round( $raw_weight, 2 ) ) );
	}

	$settings['non_converter_sample_rate']     = 100;

	return $settings;
}

/**
 * Resolve behavior-pattern settings from Content Insights payload or saved options.
 *
 * @param array<string,mixed>|null $content_insights_settings Optional Content Insights settings payload.
 * @return array<string,mixed>
 */
function quorlyx_get_behavior_pattern_settings( $content_insights_settings = null ) {
	$defaults = (array) ( quorlyx_get_global_defaults()['content_insights']['behavior_patterns'] ?? array() );

	if ( is_array( $content_insights_settings ) ) {
		if ( isset( $content_insights_settings['behavior_patterns'] ) && is_array( $content_insights_settings['behavior_patterns'] ) ) {
			return quorlyx_normalize_behavior_pattern_settings( $content_insights_settings['behavior_patterns'], $defaults );
		}

		if ( array_key_exists( 'enabled', $content_insights_settings ) ) {
			return quorlyx_normalize_behavior_pattern_settings( $content_insights_settings, $defaults );
		}
	}

	$options   = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$options   = array_replace_recursive( quorlyx_get_global_defaults(), is_array( $options ) ? $options : array() );
	$insights  = is_array( $options['content_insights'] ?? null ) ? $options['content_insights'] : array();
	$behavior  = is_array( $insights['behavior_patterns'] ?? null ) ? $insights['behavior_patterns'] : array();

	return quorlyx_normalize_behavior_pattern_settings( $behavior, $defaults );
}

/**
 * Determine whether Behavior Pattern collection is effectively enabled.
 *
 * Behavior is a child feature of Content Insights. A saved nested behavior
 * toggle should not collect data, feed AI context, or enable behavior reports
 * while the parent Content Insights switch is off.
 *
 * @param array<string,mixed>|null $content_insights_settings Optional Content Insights settings payload.
 * @return bool
 */
function quorlyx_behavior_patterns_are_enabled( $content_insights_settings = null ) {
	$insights_settings = quorlyx_get_content_insights_settings( $content_insights_settings );
	if ( empty( $insights_settings['enabled'] ) ) {
		return false;
	}

	$behavior_settings = quorlyx_get_behavior_pattern_settings( $insights_settings );

	return ! empty( $behavior_settings['enabled'] );
}

/**
 * Convert a behavior pattern key to a readable label.
 *
 * @param string $pattern_tag Pattern key.
 * @return string
 */
function quorlyx_get_behavior_pattern_label( $pattern_tag ) {
	$pattern_tag = sanitize_key( (string) $pattern_tag );

	$labels = array(
		'fast_leaver'        => 'Fast Leaver',
		'medium_leaver'      => 'Medium Leaver',
		'slow_leaver'        => 'Slow Leaver',
		'comparison_shopper' => 'Comparison Shopper',
		'fast_closer'        => 'Fast Closer',
		'discoverer_closer'  => 'Discoverer Closer',
		'fast_buyer'         => 'Fast Closer',
		'discoverer_buyer'   => 'Discoverer Closer',
		'unknown'            => 'Unknown',
	);

	return $labels[ $pattern_tag ] ?? 'Unknown';
}

/**
 * Return a concise optimization focus note for a behavior pattern.
 *
 * @param string $pattern_tag Pattern key.
 * @return string
 */
function quorlyx_get_behavior_pattern_focus_note( $pattern_tag ) {
	$pattern_tag = sanitize_key( (string) $pattern_tag );

	$focus_notes = array(
		'fast_leaver'        => 'Strengthen first-screen value and a single clear CTA.',
		'medium_leaver'      => 'Clarify offer and reduce friction in mid-page journey.',
		'slow_leaver'        => 'Improve trust signals and close-page conversion prompts.',
		'comparison_shopper' => 'Add differentiation, proof, and cart-recovery nudges.',
		'fast_closer'        => 'Scale winning page structure and trigger timing to similar pages.',
		'discoverer_closer'  => 'Support research journey with stronger path-to-action paths.',
		'fast_buyer'         => 'Scale winning page structure and trigger timing to similar pages.',
		'discoverer_buyer'   => 'Support research journey with stronger path-to-action paths.',
	);

	return $focus_notes[ $pattern_tag ] ?? 'Collect more profile data to determine next action.';
}

/**
 * Evaluate a behavior rule where all enabled checks must pass.
 *
 * @param array<int,array<string,mixed>> $checks Rule checks.
 * @return bool
 */
function quorlyx_behavior_rule_all_match( $checks ) {
	$enabled_count = 0;

	foreach ( (array) $checks as $check ) {
		$enabled = ! empty( $check['enabled'] );
		if ( ! $enabled ) {
			continue;
		}

		++$enabled_count;
		if ( empty( $check['pass'] ) ) {
			return false;
		}
	}

	return $enabled_count > 0;
}

/**
 * Evaluate a behavior rule where any enabled check may pass.
 *
 * @param array<int,array<string,mixed>> $checks Rule checks.
 * @return bool
 */
function quorlyx_behavior_rule_any_match( $checks ) {
	foreach ( (array) $checks as $check ) {
		if ( ! empty( $check['enabled'] ) && ! empty( $check['pass'] ) ) {
			return true;
		}
	}

	return false;
}

/**
 * Normalize behavior pattern keys across legacy and current variants.
 *
 * @param string $pattern_tag Pattern key.
 * @return string
 */
function quorlyx_normalize_behavior_pattern_key( $pattern_tag ) {
	$pattern_tag = sanitize_key( (string) $pattern_tag );

	if ( 'fast_buyer' === $pattern_tag ) {
		$pattern_tag = 'fast_closer';
	} elseif ( 'discoverer_buyer' === $pattern_tag ) {
		$pattern_tag = 'discoverer_closer';
	}

	$allowed = array( 'fast_leaver', 'medium_leaver', 'slow_leaver', 'comparison_shopper', 'fast_closer', 'discoverer_closer', 'unknown' );

	if ( in_array( $pattern_tag, $allowed, true ) ) {
		return $pattern_tag;
	}

	return 'unknown';
}

/**
 * Normalize behavior conversion status across legacy and transport variants.
 *
 * @param mixed $conversion_status Raw conversion status value.
 * @return string
 */
function quorlyx_normalize_behavior_conversion_status( $conversion_status ) {
	if ( is_bool( $conversion_status ) ) {
		return $conversion_status ? 'closer' : 'non_converter';
	}

	if ( is_int( $conversion_status ) || is_float( $conversion_status ) ) {
		return ( (float) $conversion_status ) > 0 ? 'closer' : 'non_converter';
	}

	$conversion_status = sanitize_key( (string) $conversion_status );

	if ( in_array( $conversion_status, array( '1', 'true', 'yes', 'buyer', 'closer', 'converted', 'conversion', 'purchase', 'purchased', 'order_completed', 'completed' ), true ) ) {
		return 'closer';
	}

	if ( in_array( $conversion_status, array( '0', 'false', 'no', 'non_converter', 'non-converter', 'nonconverter', 'not_converted', 'notconverted', 'abandoned', 'visitor', 'lead' ), true ) ) {
		return 'non_converter';
	}

	if ( 'unknown' === $conversion_status ) {
		return 'unknown';
	}

	return 'unknown';
}

/**
 * Determine whether a normalized behavior pattern is a closer pattern.
 *
 * @param string $pattern_tag Pattern key.
 * @return bool
 */
function quorlyx_is_closer_behavior_pattern( $pattern_tag ) {
	$pattern_tag = quorlyx_normalize_behavior_pattern_key( (string) $pattern_tag );

	return in_array( $pattern_tag, array( 'fast_closer', 'discoverer_closer' ), true );
}

/**
 * Resolve enabled behavior metrics from settings payload.
 *
 * @param array<string,mixed>|null $behavior_settings Behavior settings.
 * @return array<string,bool>
 */
function quorlyx_get_behavior_pattern_metric_flags( $behavior_settings ) {
	$behavior_settings = is_array( $behavior_settings ) ? $behavior_settings : quorlyx_get_behavior_pattern_settings();
	$metric_defaults   = array(
		'visit_frequency' => true,
		'pages_viewed'    => true,
		'dwell_time_avg'  => true,
		'cart_activity'   => true,
		'scroll_depth'    => true,
		'started_chat'    => true,
		'checkout_flow'   => true,
		'traffic_source'  => true,
	);
	$metric_settings   = is_array( $behavior_settings['pattern_metrics'] ?? null ) ? $behavior_settings['pattern_metrics'] : array();
	$metrics           = array();

	foreach ( $metric_defaults as $metric_key => $metric_default ) {
		$metrics[ $metric_key ] = array_key_exists( $metric_key, $metric_settings ) ? ! empty( $metric_settings[ $metric_key ] ) : $metric_default;
	}

	return $metrics;
}

/**
 * Resolve per-metric behavior weights used by reference matching.
 *
 * @param array<string,mixed>|null $behavior_settings Behavior settings.
 * @return array<string,float>
 */
function quorlyx_get_behavior_pattern_metric_weights( $behavior_settings ) {
	$behavior_settings = is_array( $behavior_settings ) ? $behavior_settings : quorlyx_get_behavior_pattern_settings();
	$weight_defaults   = array(
		'visit_frequency' => 1.0,
		'pages_viewed'    => 1.0,
		'dwell_time_avg'  => 1.0,
		'cart_activity'   => 1.0,
		'scroll_depth'    => 1.0,
		'started_chat'    => 1.0,
		'checkout_flow'   => 1.0,
		'traffic_source'  => 1.0,
	);
	$weight_settings   = is_array( $behavior_settings['pattern_metric_weights'] ?? null ) ? $behavior_settings['pattern_metric_weights'] : array();
	$weights           = array();

	foreach ( $weight_defaults as $metric_key => $weight_default ) {
		$raw_weight = array_key_exists( $metric_key, $weight_settings ) ? (float) $weight_settings[ $metric_key ] : (float) $weight_default;
		$weights[ $metric_key ] = max( 0.1, min( 10.0, round( $raw_weight, 2 ) ) );
	}

	return $weights;
}

/**
 * Build weighted reference score (0-100) from metric values.
 *
 * @param array<string,float|int> $metric_values     Raw metric values.
 * @param array<string,mixed>     $behavior_settings Behavior settings.
 * @return int
 */
function quorlyx_calculate_behavior_reference_weighted_score( $metric_values, $behavior_settings = null ) {
	$metrics = quorlyx_get_behavior_pattern_metric_flags( $behavior_settings );
	$weights = quorlyx_get_behavior_pattern_metric_weights( $behavior_settings );

	$weighted_total = 0.0;
	$weight_total   = 0.0;

	foreach ( $metrics as $metric_key => $enabled ) {
		if ( ! $enabled ) {
			continue;
		}

		$metric_weight = (float) ( $weights[ $metric_key ] ?? 1.0 );
		if ( $metric_weight <= 0 ) {
			continue;
		}

		$metric_value  = (float) ( $metric_values[ $metric_key ] ?? 0 );
		$metric_ratio  = quorlyx_get_behavior_metric_score_ratio( $metric_key, $metric_value );
		$weighted_total += ( $metric_ratio * $metric_weight );
		$weight_total   += $metric_weight;
	}

	if ( $weight_total <= 0 ) {
		return 0;
	}

	return (int) round( ( $weighted_total / $weight_total ) * 100 );
}

/**
 * Calculate normalized distance between a live behavior vector and a reference prototype.
 *
 * Unlike the display score, this compares each enabled metric independently so very
 * different profiles cannot match just because their collapsed 0-100 scores are close.
 *
 * @param array<string,float|int> $live_metric_values      Live metric values.
 * @param array<string,float|int> $prototype_metric_values Reference prototype metric values.
 * @param array<string,mixed>     $behavior_settings       Behavior settings.
 * @return int Distance percentage where 0 is identical and 100 is maximally different.
 */
function quorlyx_calculate_behavior_reference_distance_pct( $live_metric_values, $prototype_metric_values, $behavior_settings = null ) {
	$metrics = quorlyx_get_behavior_pattern_metric_flags( $behavior_settings );
	$weights = quorlyx_get_behavior_pattern_metric_weights( $behavior_settings );

	$weighted_distance = 0.0;
	$weight_total      = 0.0;

	foreach ( $metrics as $metric_key => $enabled ) {
		if ( ! $enabled ) {
			continue;
		}

		$metric_weight = (float) ( $weights[ $metric_key ] ?? 1.0 );
		if ( $metric_weight <= 0 ) {
			continue;
		}

		$live_ratio      = quorlyx_get_behavior_metric_score_ratio( $metric_key, (float) ( $live_metric_values[ $metric_key ] ?? 0 ) );
		$prototype_ratio = quorlyx_get_behavior_metric_score_ratio( $metric_key, (float) ( $prototype_metric_values[ $metric_key ] ?? 0 ) );

		$weighted_distance += min( 1.0, abs( $live_ratio - $prototype_ratio ) ) * $metric_weight;
		$weight_total      += $metric_weight;
	}

	if ( $weight_total <= 0 ) {
		return 100;
	}

	return max( 0, min( 100, (int) round( ( $weighted_distance / $weight_total ) * 100 ) ) );
}

/**
 * Convert one behavior metric to a normalized 0-1 ratio used by scoring.
 *
 * @param string     $metric_key   Metric key.
 * @param int|float  $metric_value Metric value.
 * @return float
 */
function quorlyx_get_behavior_metric_score_ratio( $metric_key, $metric_value ) {
	$metric_key   = sanitize_key( (string) $metric_key );
	$metric_value = (float) $metric_value;

	if ( $metric_value < 0 ) {
		$metric_value = 0;
	}

	switch ( $metric_key ) {
		case 'visit_frequency':
			return min( 1.0, $metric_value / 6.0 );
		case 'pages_viewed':
			return min( 1.0, $metric_value / 8.0 );
		case 'dwell_time_avg':
			return min( 1.0, $metric_value / 300.0 );
		case 'cart_activity':
			return min( 1.0, $metric_value / 3.0 );
		case 'scroll_depth':
			return min( 1.0, min( 100.0, $metric_value ) / 100.0 );
		case 'started_chat':
			return min( 1.0, $metric_value );
		case 'checkout_flow':
			return min( 1.0, $metric_value );
		case 'traffic_source':
			return min( 1.0, $metric_value / 6.0 );
	}

	return 0.0;
}

/**
 * Normalize tracked traffic source value.
 *
 * @param string $traffic_source Raw traffic source.
 * @return string
 */
function quorlyx_normalize_traffic_source_segment( $traffic_source ) {
	$traffic_source = sanitize_key( (string) $traffic_source );
	$allowed        = array( 'direct', 'search', 'social', 'paid', 'email', 'referral' );

	if ( in_array( $traffic_source, $allowed, true ) ) {
		return $traffic_source;
	}

	return 'direct';
}

/**
 * Convert traffic source segment to numeric score used in behavior weighting.
 *
 * @param string $traffic_source Traffic source segment.
 * @return int
 */
function quorlyx_get_traffic_source_segment_score( $traffic_source ) {
	$traffic_source = quorlyx_normalize_traffic_source_segment( $traffic_source );
	$score_map      = array(
		'direct'   => 1,
		'search'   => 2,
		'social'   => 3,
		'paid'     => 4,
		'email'    => 5,
		'referral' => 6,
	);

	return absint( $score_map[ $traffic_source ] ?? 1 );
}

/**
 * Build a rounded behavior score (0-100) from current profile metrics.
 *
 * @param int                 $visit_frequency   Visit frequency.
 * @param int                 $pages_viewed      Pages viewed.
 * @param int                 $dwell_time_avg    Average dwell time in seconds.
 * @param int                 $cart_activity     Cart activity count.
 * @param int                 $scroll_depth      Scroll depth percentage.
 * @param string              $conversion_status Conversion status.
 * @param array<string,mixed> $behavior_settings Behavior settings.
 * @param array<string,mixed> $behavior_context  Optional context payload.
 * @return int
 */
function quorlyx_calculate_behavior_overall_score( $visit_frequency, $pages_viewed, $dwell_time_avg, $cart_activity, $scroll_depth, $conversion_status, $behavior_settings = null, $behavior_context = array() ) {
	$visit_frequency   = max( 0, absint( $visit_frequency ) );
	$pages_viewed      = max( 0, absint( $pages_viewed ) );
	$dwell_time_avg    = max( 0, absint( $dwell_time_avg ) );
	$cart_activity     = max( 0, absint( $cart_activity ) );
	$scroll_depth      = max( 0, min( 100, absint( $scroll_depth ) ) );
	$conversion_status = quorlyx_normalize_behavior_conversion_status( $conversion_status );
	$metrics           = quorlyx_get_behavior_pattern_metric_flags( $behavior_settings );

	$started_chat_value = array_key_exists( 'started_chat_score', $behavior_context ) ? (float) $behavior_context['started_chat_score'] : ( ! empty( $behavior_context['started_chat'] ) ? 1.0 : 0.0 );
	if ( $started_chat_value < 0 ) {
		$started_chat_value = 0.0;
	}
	if ( $started_chat_value > 1 ) {
		$started_chat_value = 1.0;
	}

	if ( array_key_exists( 'checkout_flow_score', $behavior_context ) ) {
		$checkout_flow_value = (float) $behavior_context['checkout_flow_score'];
	} else {
		$abandonment_stage   = sanitize_key( (string) ( $behavior_context['abandonment_stage'] ?? '' ) );
		$checkout_flow_value = in_array( $abandonment_stage, array( 'viewed_cart', 'abandoned_checkout' ), true ) ? 1.0 : 0.0;
	}
	if ( $checkout_flow_value < 0 ) {
		$checkout_flow_value = 0.0;
	}
	if ( $checkout_flow_value > 1 ) {
		$checkout_flow_value = 1.0;
	}

	$weights = array(
		'visit_frequency' => 20,
		'pages_viewed'    => 20,
		'dwell_time_avg'  => 20,
		'cart_activity'   => 15,
		'scroll_depth'    => 15,
		'started_chat'    => 5,
		'checkout_flow'   => 5,
	);

	$metric_values = array(
		'visit_frequency' => $visit_frequency,
		'pages_viewed'    => $pages_viewed,
		'dwell_time_avg'  => $dwell_time_avg,
		'cart_activity'   => $cart_activity,
		'scroll_depth'    => $scroll_depth,
		'started_chat'    => $started_chat_value,
		'checkout_flow'   => $checkout_flow_value,
	);

	$total_weight = 0;
	$score_sum    = 0.0;

	foreach ( $weights as $metric_key => $weight ) {
		if ( empty( $metrics[ $metric_key ] ) ) {
			continue;
		}

		$ratio        = quorlyx_get_behavior_metric_score_ratio( $metric_key, $metric_values[ $metric_key ] ?? 0 );
		$score_sum   += $ratio * (float) $weight;
		$total_weight += $weight;
	}

	if ( $total_weight <= 0 ) {
		return 0;
	}

	$score = ( $score_sum / (float) $total_weight ) * 100.0;

	if ( 'closer' === $conversion_status ) {
		$score = min( 100.0, $score + 8.0 );
	}

	return max( 0, min( 100, (int) round( $score ) ) );
}

/**
 * Write throttled behavior-engine log entries to avoid noisy repetition.
 *
 * @param string              $cache_key Stable key used for deduplication.
 * @param string              $type      Log level.
 * @param string              $message   Log message.
 * @param array<string,mixed> $details   Optional log metadata.
 * @param int                 $ttl       Deduplication window in seconds.
 * @return void
 */
function quorlyx_behavior_log_event_once( $cache_key, $type, $message, $details = array(), $ttl = 900 ) {
	if ( ! class_exists( 'Quorlyx_Pro_Logger' ) ) {
		return;
	}

	$cache_key = (string) $cache_key;
	$ttl       = max( 60, absint( $ttl ) );

	if ( '' === trim( $cache_key ) ) {
		$cache_key = 'behavior_event';
	}

	$transient_key = 'quorlyx_blog_' . substr( md5( $cache_key ), 0, 20 );
	if ( false !== get_transient( $transient_key ) ) {
		return;
	}

	set_transient( $transient_key, 1, $ttl );

	$details = is_array( $details ) ? $details : array();
	if ( empty( $details['component'] ) ) {
		$details['component'] = 'behavior_engine';
	}

	Quorlyx_Pro_Logger::log( $type, $message, $details );
}

/**
 * Match a live profile to stored pattern references for the same source.
 *
 * @param int                 $visit_frequency   Visit frequency.
 * @param int                 $pages_viewed      Pages viewed.
 * @param int                 $dwell_time_avg    Average dwell time in seconds.
 * @param int                 $cart_activity     Cart activity count.
 * @param int                 $scroll_depth      Scroll depth percentage.
 * @param string              $conversion_status Conversion status.
 * @param array<string,mixed> $behavior_settings Behavior settings.
 * @param array<string,mixed> $behavior_context  Optional context payload.
 * @return array<string,mixed>
 */
function quorlyx_match_behavior_pattern_by_reference( $visit_frequency, $pages_viewed, $dwell_time_avg, $cart_activity, $scroll_depth, $conversion_status, $behavior_settings, $behavior_context = array() ) {
	$behavior_settings = is_array( $behavior_settings ) ? $behavior_settings : quorlyx_get_behavior_pattern_settings();
	$conversion_status = quorlyx_normalize_behavior_conversion_status( $conversion_status );
	$source_post_id    = quorlyx_get_canonical_analytics_post_id( absint( $behavior_context['source_post_id'] ?? 0 ) );
	$content_key       = sanitize_key( (string) ( $behavior_context['content_key'] ?? '' ) );
	$min_profiles      = max( 5, absint( $behavior_settings['reference_min_profiles'] ?? 20 ) );
	$min_pattern_rows  = max( 1, absint( $behavior_settings['reference_min_pattern_samples'] ?? 3 ) );
	$tolerance_pct     = max( 0, min( 50, absint( $behavior_settings['reference_error_tolerance_pct'] ?? 15 ) ) );

	$result = array(
		'matched'              => false,
		'pattern_tag'          => 'unknown',
		'pattern_source'       => 'reference',
		'insufficient_data'    => false,
		'insufficient_reason'  => '',
		'live_score'           => 0,
		'prototype_score'      => 0,
		'match_error_pct'      => 100,
		'tolerance_pct'        => $tolerance_pct,
		'total_profiles'       => 0,
		'required_profiles'    => $min_profiles,
		'min_pattern_samples'  => $min_pattern_rows,
	);

	if ( $source_post_id <= 0 && '' === $content_key ) {
		$result['insufficient_data']   = true;
		$result['insufficient_reason'] = 'missing_source';

		quorlyx_behavior_log_event_once(
			'reference_missing_source',
			'warning',
			'Behavior reference matching skipped: missing source attribution',
			array(
				'component'           => 'behavior_engine',
				'operation'           => 'reference_matching',
				'phase'               => 'validate_source',
				'insufficient_reason' => 'missing_source',
			)
		);

		return $result;
	}

	$live_checkout_flow = in_array( sanitize_key( (string) ( $behavior_context['abandonment_stage'] ?? '' ) ), array( 'viewed_cart', 'abandoned_checkout' ), true ) ? 1.0 : 0.0;
	$live_traffic_score = (float) quorlyx_get_traffic_source_segment_score( (string) ( $behavior_context['traffic_source'] ?? 'direct' ) );
	$live_metric_values = array(
		'visit_frequency' => max( 0, (float) $visit_frequency ),
		'pages_viewed'    => max( 0, (float) $pages_viewed ),
		'dwell_time_avg'  => max( 0, (float) $dwell_time_avg ),
		'cart_activity'   => max( 0, (float) $cart_activity ),
		'scroll_depth'    => max( 0, min( 100, (float) $scroll_depth ) ),
		'started_chat'    => ! empty( $behavior_context['started_chat'] ) ? 1.0 : 0.0,
		'checkout_flow'   => $live_checkout_flow,
		'traffic_source'  => $live_traffic_score,
	);
	$live_score         = quorlyx_calculate_behavior_reference_weighted_score( $live_metric_values, $behavior_settings );
	$result['live_score'] = $live_score;

	global $wpdb;
	$table_name = quorlyx_get_behavior_engine_table_name();

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Aggregate count for behavior reference eligibility.
	// phpcs:disable WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Table name comes from trusted helper with wpdb prefix.
	$total_profiles_query = $wpdb->get_var(
		$wpdb->prepare(
			"SELECT COUNT(DISTINCT profile_hash) FROM {$table_name} WHERE source_post_id = %d AND content_key = %s",
			$source_post_id,
			$content_key
		)
	);

	if ( null === $total_profiles_query && '' !== (string) $wpdb->last_error ) {
		$result['insufficient_data']   = true;
		$result['insufficient_reason'] = 'reference_query_failed';

		quorlyx_behavior_log_event_once(
			'reference_query_failed_total|' . $source_post_id . '|' . $content_key,
			'error',
			'Behavior reference matching query failed (total profiles)',
			array(
				'component'           => 'behavior_engine',
				'operation'           => 'reference_matching',
				'phase'               => 'count_profiles',
				'source_post_id'      => $source_post_id,
				'content_key'         => $content_key,
				'insufficient_reason' => 'reference_query_failed',
				'db_error'            => sanitize_text_field( (string) $wpdb->last_error ),
			),
			1800
		);

		return $result;
	}

	$total_profiles = absint( $total_profiles_query );

	if ( $total_profiles < $min_profiles ) {
		$result['insufficient_data']   = true;
		$result['insufficient_reason'] = 'min_profiles_not_met';

		quorlyx_behavior_log_event_once(
			'reference_min_profiles_not_met|' . $source_post_id . '|' . $content_key,
			'warning',
			'Behavior reference matching skipped: minimum profiles not met',
			array(
				'component'           => 'behavior_engine',
				'operation'           => 'reference_matching',
				'phase'               => 'eligibility_check',
				'source_post_id'      => $source_post_id,
				'content_key'         => $content_key,
				'total_profiles'      => $total_profiles,
				'required_profiles'   => $min_profiles,
				'insufficient_reason' => 'min_profiles_not_met',
			)
		);

		return $result;
	}

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Aggregate prototype query for dynamic behavior matching.
	// phpcs:disable WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Table name comes from trusted helper with wpdb prefix.
	$prototype_rows = $wpdb->get_results(
			$wpdb->prepare(
				"SELECT pattern_tag, COUNT(*) AS sample_count, AVG(visit_frequency) AS avg_visit_frequency, AVG(pages_viewed) AS avg_pages_viewed, AVG(dwell_time_avg) AS avg_dwell_time_avg, AVG(cart_activity) AS avg_cart_activity, AVG(scroll_depth) AS avg_scroll_depth, AVG(started_chat) AS avg_started_chat_rate, AVG(CASE WHEN abandonment_stage IN ('viewed_cart','abandoned_checkout') THEN 1 ELSE 0 END) AS avg_checkout_flow_rate, AVG(traffic_source_score) AS avg_traffic_source_score FROM {$table_name} WHERE source_post_id = %d AND content_key = %s GROUP BY pattern_tag",
				$source_post_id,
				$content_key
			),
			ARRAY_A
		);
	// phpcs:enable WordPress.DB.PreparedSQL.InterpolatedNotPrepared

	if ( null === $prototype_rows && '' !== (string) $wpdb->last_error ) {
		$result['insufficient_data']   = true;
		$result['insufficient_reason'] = 'reference_query_failed';

		quorlyx_behavior_log_event_once(
			'reference_query_failed_prototype|' . $source_post_id . '|' . $content_key,
			'error',
			'Behavior reference matching query failed (pattern prototypes)',
			array(
				'component'           => 'behavior_engine',
				'operation'           => 'reference_matching',
				'phase'               => 'load_prototypes',
				'source_post_id'      => $source_post_id,
				'content_key'         => $content_key,
				'insufficient_reason' => 'reference_query_failed',
				'db_error'            => sanitize_text_field( (string) $wpdb->last_error ),
			),
			1800
		);

		return $result;
	}

	$result['total_profiles'] = $total_profiles;

	$best_pattern   = 'unknown';
	$best_error_pct = 101;
	$best_score     = 0;
	$eligible_rows  = 0;

	foreach ( (array) $prototype_rows as $prototype_row ) {
		$pattern_tag  = quorlyx_normalize_behavior_pattern_key( (string) ( $prototype_row['pattern_tag'] ?? '' ) );
		$sample_count = absint( $prototype_row['sample_count'] ?? 0 );
		$pattern_is_closer = quorlyx_is_closer_behavior_pattern( $pattern_tag );

		if ( 'unknown' === $pattern_tag || $sample_count < $min_pattern_rows ) {
			continue;
		}

		if ( ( 'closer' === $conversion_status && ! $pattern_is_closer ) || ( 'closer' !== $conversion_status && $pattern_is_closer ) ) {
			continue;
		}

		++$eligible_rows;

		$prototype_metric_values = array(
			'visit_frequency' => max( 0, (float) ( $prototype_row['avg_visit_frequency'] ?? 0 ) ),
			'pages_viewed'    => max( 0, (float) ( $prototype_row['avg_pages_viewed'] ?? 0 ) ),
			'dwell_time_avg'  => max( 0, (float) ( $prototype_row['avg_dwell_time_avg'] ?? 0 ) ),
			'cart_activity'   => max( 0, (float) ( $prototype_row['avg_cart_activity'] ?? 0 ) ),
			'scroll_depth'    => max( 0, min( 100, (float) ( $prototype_row['avg_scroll_depth'] ?? 0 ) ) ),
			'started_chat'    => max( 0, min( 1, (float) ( $prototype_row['avg_started_chat_rate'] ?? 0 ) ) ),
			'checkout_flow'   => max( 0, min( 1, (float) ( $prototype_row['avg_checkout_flow_rate'] ?? 0 ) ) ),
			'traffic_source'  => max( 1, min( 6, (float) ( $prototype_row['avg_traffic_source_score'] ?? 1 ) ) ),
		);
		$prototype_score         = quorlyx_calculate_behavior_reference_weighted_score( $prototype_metric_values, $behavior_settings );
		$error_pct               = quorlyx_calculate_behavior_reference_distance_pct( $live_metric_values, $prototype_metric_values, $behavior_settings );

		if ( $error_pct < $best_error_pct ) {
			$best_error_pct = $error_pct;
			$best_pattern   = $pattern_tag;
			$best_score     = $prototype_score;
		}
	}

	if ( $eligible_rows <= 0 ) {
		$result['insufficient_data']   = true;
		$result['insufficient_reason'] = 'min_pattern_samples_not_met';

		quorlyx_behavior_log_event_once(
			'reference_min_pattern_samples_not_met|' . $source_post_id . '|' . $content_key,
			'warning',
			'Behavior reference matching skipped: minimum pattern samples not met',
			array(
				'component'           => 'behavior_engine',
				'operation'           => 'reference_matching',
				'phase'               => 'prototype_eligibility',
				'source_post_id'      => $source_post_id,
				'content_key'         => $content_key,
				'min_pattern_samples' => $min_pattern_rows,
				'insufficient_reason' => 'min_pattern_samples_not_met',
			)
		);

		return $result;
	}

	$result['pattern_tag']     = $best_pattern;
	$result['prototype_score'] = $best_score;
	$result['match_error_pct'] = max( 0, min( 100, $best_error_pct ) );

	if ( $best_error_pct <= $tolerance_pct ) {
		$result['matched'] = true;
		return $result;
	}

	$result['insufficient_reason'] = 'tolerance_exceeded';

	quorlyx_behavior_log_event_once(
		'reference_tolerance_exceeded|' . $source_post_id . '|' . $content_key . '|' . $best_pattern,
		'info',
		'Behavior reference matching out of tolerance; using fallback/unknown path',
		array(
			'component'           => 'behavior_engine',
			'operation'           => 'reference_matching',
			'phase'               => 'match_evaluation',
			'source_post_id'      => $source_post_id,
			'content_key'         => $content_key,
			'pattern_tag'         => $best_pattern,
			'match_error_pct'     => max( 0, min( 100, $best_error_pct ) ),
			'tolerance_pct'       => $tolerance_pct,
			'insufficient_reason' => 'tolerance_exceeded',
		),
		1200
	);

	return $result;
}

/**
 * Classify a visitor profile using static rules.
 *
 * @param int                 $visit_frequency   Visit frequency.
 * @param int                 $pages_viewed      Pages viewed.
 * @param int                 $dwell_time_avg    Average dwell time in seconds.
 * @param int                 $cart_activity     Cart activity count.
 * @param int                 $scroll_depth      Scroll depth percentage.
 * @param string              $conversion_status Conversion status.
 * @param array<string,mixed> $behavior_settings Behavior settings.
 * @param array<string,mixed> $behavior_context  Optional context payload.
 * @return string
 */
function quorlyx_classify_behavior_pattern_legacy( $visit_frequency, $pages_viewed, $dwell_time_avg, $cart_activity, $scroll_depth, $conversion_status, $behavior_settings = null, $behavior_context = array() ) {
	$visit_frequency   = max( 0, absint( $visit_frequency ) );
	$pages_viewed      = max( 0, absint( $pages_viewed ) );
	$dwell_time_avg    = max( 0, absint( $dwell_time_avg ) );
	$cart_activity     = max( 0, absint( $cart_activity ) );
	$scroll_depth      = max( 0, min( 100, absint( $scroll_depth ) ) );
	$conversion_status = quorlyx_normalize_behavior_conversion_status( $conversion_status );
	$behavior_settings = is_array( $behavior_settings ) ? $behavior_settings : quorlyx_get_behavior_pattern_settings();
	$metrics           = quorlyx_get_behavior_pattern_metric_flags( $behavior_settings );

	$started_chat      = ! empty( $behavior_context['started_chat'] );
	$abandonment_stage = sanitize_key( (string) ( $behavior_context['abandonment_stage'] ?? '' ) );
	$checkout_flow_hit = in_array( $abandonment_stage, array( 'viewed_cart', 'abandoned_checkout' ), true );

	if ( 'closer' === $conversion_status ) {
		$fast_closer = quorlyx_behavior_rule_all_match(
			array(
				array(
					'enabled' => $metrics['visit_frequency'],
					'pass'    => $visit_frequency <= 2,
				),
				array(
					'enabled' => $metrics['pages_viewed'],
					'pass'    => $pages_viewed <= 3,
				),
				array(
					'enabled' => $metrics['dwell_time_avg'],
					'pass'    => $dwell_time_avg <= 120,
				),
			)
		);

		if ( $fast_closer ) {
			return 'fast_closer';
		}

		return 'discoverer_closer';
	}

	if ( 'non_converter' !== $conversion_status ) {
		return 'unknown';
	}

	$comparison_from_cart = quorlyx_behavior_rule_all_match(
		array(
			array(
				'enabled' => $metrics['cart_activity'],
				'pass'    => $cart_activity > 0,
			),
		)
	);

	$comparison_from_research = quorlyx_behavior_rule_all_match(
		array(
			array(
				'enabled' => $metrics['pages_viewed'],
				'pass'    => $pages_viewed >= 4,
			),
			array(
				'enabled' => $metrics['dwell_time_avg'],
				'pass'    => $dwell_time_avg >= 90,
			),
		)
	);

	$comparison_from_checkout = quorlyx_behavior_rule_all_match(
		array(
			array(
				'enabled' => $metrics['checkout_flow'] && ! empty( $behavior_settings['include_checkout_flow'] ),
				'pass'    => $checkout_flow_hit,
			),
		)
	);

	$comparison_from_chat = quorlyx_behavior_rule_all_match(
		array(
			array(
				'enabled' => $metrics['started_chat'],
				'pass'    => $started_chat,
			),
		)
	);

	if ( $comparison_from_cart || $comparison_from_research || $comparison_from_checkout || $comparison_from_chat ) {
		return 'comparison_shopper';
	}

	$fast_leaver = quorlyx_behavior_rule_all_match(
		array(
			array(
				'enabled' => $metrics['dwell_time_avg'],
				'pass'    => $dwell_time_avg <= 30,
			),
			array(
				'enabled' => $metrics['scroll_depth'],
				'pass'    => $scroll_depth < 35,
			),
			array(
				'enabled' => $metrics['pages_viewed'],
				'pass'    => $pages_viewed <= 2,
			),
		)
	);

	if ( $fast_leaver ) {
		return 'fast_leaver';
	}

	// Medium leavers require BOTH conditions to be true (all_match) to avoid misclassifying
	// slow_leavers who spent time on site but only viewed a few pages in a single session.
	$medium_leaver = quorlyx_behavior_rule_all_match(
		array(
			array(
				'enabled' => $metrics['dwell_time_avg'],
				'pass'    => $dwell_time_avg <= 120,
			),
			array(
				'enabled' => $metrics['pages_viewed'],
				'pass'    => $pages_viewed <= 3,
			),
		)
	);

	if ( $medium_leaver ) {
		return 'medium_leaver';
	}

	return 'slow_leaver';
}

/**
 * Classify a visitor profile and include trace metadata.
 *
 * @param int                 $visit_frequency   Visit frequency.
 * @param int                 $pages_viewed      Pages viewed.
 * @param int                 $dwell_time_avg    Average dwell time in seconds.
 * @param int                 $cart_activity     Cart activity count.
 * @param int                 $scroll_depth      Scroll depth percentage.
 * @param string              $conversion_status Conversion status.
 * @param array<string,mixed> $behavior_settings Optional behavior settings.
 * @param array<string,mixed> $behavior_context  Optional context payload.
 * @return array<string,mixed>
 */
function quorlyx_classify_behavior_pattern_with_meta( $visit_frequency, $pages_viewed, $dwell_time_avg, $cart_activity, $scroll_depth, $conversion_status, $behavior_settings = null, $behavior_context = array() ) {
	$behavior_settings = is_array( $behavior_settings ) ? $behavior_settings : quorlyx_get_behavior_pattern_settings();
	$conversion_status = quorlyx_normalize_behavior_conversion_status( $conversion_status );
	$reference_enabled = ! empty( $behavior_settings['use_reference_matching'] );
	$fallback_to_rules = ! empty( $behavior_settings['reference_fallback_to_rules'] );
	$reference_result  = null;

	if ( $reference_enabled ) {
		$reference_result = quorlyx_match_behavior_pattern_by_reference(
			$visit_frequency,
			$pages_viewed,
			$dwell_time_avg,
			$cart_activity,
			$scroll_depth,
			$conversion_status,
			$behavior_settings,
			$behavior_context
		);

		if ( ! empty( $reference_result['matched'] ) ) {
			$resolved_pattern = quorlyx_normalize_behavior_pattern_key( (string) ( $reference_result['pattern_tag'] ?? 'unknown' ) );

			return array(
				'pattern_tag' => $resolved_pattern,
				'meta'        => array(
					'pattern_source'      => 'reference',
					'insufficient_data'   => false,
					'insufficient_reason' => '',
					'match_error_pct'     => absint( $reference_result['match_error_pct'] ?? 0 ),
					'tolerance_pct'       => absint( $reference_result['tolerance_pct'] ?? 0 ),
					'live_score'          => absint( $reference_result['live_score'] ?? 0 ),
					'prototype_score'     => absint( $reference_result['prototype_score'] ?? 0 ),
					'total_profiles'      => absint( $reference_result['total_profiles'] ?? 0 ),
					'required_profiles'   => absint( $reference_result['required_profiles'] ?? 0 ),
				),
			);
		}

		if ( ! $fallback_to_rules ) {
			return array(
				'pattern_tag' => 'unknown',
				'meta'        => array(
					'pattern_source'      => 'reference_unmatched',
					'insufficient_data'   => ! empty( $reference_result['insufficient_data'] ),
					'insufficient_reason' => sanitize_key( (string) ( $reference_result['insufficient_reason'] ?? '' ) ),
					'match_error_pct'     => absint( $reference_result['match_error_pct'] ?? 0 ),
					'tolerance_pct'       => absint( $reference_result['tolerance_pct'] ?? 0 ),
					'live_score'          => absint( $reference_result['live_score'] ?? 0 ),
					'prototype_score'     => absint( $reference_result['prototype_score'] ?? 0 ),
					'total_profiles'      => absint( $reference_result['total_profiles'] ?? 0 ),
					'required_profiles'   => absint( $reference_result['required_profiles'] ?? 0 ),
				),
			);
		}
	}

	$legacy_pattern = quorlyx_classify_behavior_pattern_legacy(
		$visit_frequency,
		$pages_viewed,
		$dwell_time_avg,
		$cart_activity,
		$scroll_depth,
		$conversion_status,
		$behavior_settings,
		$behavior_context
	);

	return array(
		'pattern_tag' => quorlyx_normalize_behavior_pattern_key( $legacy_pattern ),
		'meta'        => array(
			'pattern_source'      => $reference_enabled ? 'rule_fallback' : 'rule',
			'insufficient_data'   => ! empty( $reference_result['insufficient_data'] ),
			'insufficient_reason' => sanitize_key( (string) ( $reference_result['insufficient_reason'] ?? '' ) ),
			'match_error_pct'     => absint( $reference_result['match_error_pct'] ?? 0 ),
			'tolerance_pct'       => absint( $reference_result['tolerance_pct'] ?? 0 ),
			'live_score'          => absint( $reference_result['live_score'] ?? 0 ),
			'prototype_score'     => absint( $reference_result['prototype_score'] ?? 0 ),
			'total_profiles'      => absint( $reference_result['total_profiles'] ?? 0 ),
			'required_profiles'   => absint( $reference_result['required_profiles'] ?? 0 ),
		),
	);
}

/**
 * Classify a visitor profile into one of the six behavior patterns.
 *
 * @param int        $visit_frequency   Visit frequency.
 * @param int        $pages_viewed      Pages viewed.
 * @param int        $dwell_time_avg    Average dwell time in seconds.
 * @param int        $cart_activity     Cart activity count.
 * @param int        $scroll_depth      Scroll depth percentage.
 * @param string     $conversion_status Conversion status.
 * @param array|null $behavior_settings Optional behavior settings.
 * @param array      $behavior_context  Optional context payload.
 * @return string
 */
function quorlyx_classify_behavior_pattern( $visit_frequency, $pages_viewed, $dwell_time_avg, $cart_activity, $scroll_depth, $conversion_status, $behavior_settings = null, $behavior_context = array() ) {
	$classified = quorlyx_classify_behavior_pattern_with_meta(
		$visit_frequency,
		$pages_viewed,
		$dwell_time_avg,
		$cart_activity,
		$scroll_depth,
		$conversion_status,
		$behavior_settings,
		$behavior_context
	);

	return quorlyx_normalize_behavior_pattern_key( (string) ( $classified['pattern_tag'] ?? 'unknown' ) );
}

/**
 * Predict the next likely step for a live visitor profile.
 *
 * @param string $pattern_tag        Classified behavior pattern.
 * @param int    $visit_frequency    Visit frequency.
 * @param int    $pages_viewed       Pages viewed.
 * @param int    $dwell_time_avg     Average dwell time in seconds.
 * @param int    $cart_activity      Cart activity count.
 * @param int    $scroll_depth       Scroll depth percentage.
 * @param string $conversion_status  Conversion status.
 * @param array  $behavior_context   Optional behavior context.
 * @return array<string,mixed>
 */
function quorlyx_predict_behavior_next_step( $pattern_tag, $visit_frequency, $pages_viewed, $dwell_time_avg, $cart_activity, $scroll_depth, $conversion_status, $behavior_context = array() ) {
	$pattern_tag       = quorlyx_normalize_behavior_pattern_key( (string) $pattern_tag );
	$visit_frequency   = max( 0, absint( $visit_frequency ) );
	$pages_viewed      = max( 0, absint( $pages_viewed ) );
	$dwell_time_avg    = max( 0, absint( $dwell_time_avg ) );
	$cart_activity     = max( 0, absint( $cart_activity ) );
	$scroll_depth      = max( 0, min( 100, absint( $scroll_depth ) ) );
	$conversion_status = quorlyx_normalize_behavior_conversion_status( $conversion_status );

	$abandonment_stage  = sanitize_key( (string) ( $behavior_context['abandonment_stage'] ?? '' ) );
	$started_chat       = ! empty( $behavior_context['started_chat'] );
	if ( 'closer' === $conversion_status ) {
		$abandonment_stage = '';
	}

	switch ( $pattern_tag ) {
		case 'fast_closer':
			$baseline_action_probability = 88;
			$baseline_exit_probability   = 5;
			break;
		case 'discoverer_closer':
			$baseline_action_probability = 76;
			$baseline_exit_probability   = 8;
			break;
		case 'comparison_shopper':
			$baseline_action_probability = 52;
			$baseline_exit_probability   = 22;
			break;
		case 'slow_leaver':
			$baseline_action_probability = 18;
			$baseline_exit_probability   = 44;
			break;
		case 'medium_leaver':
			$baseline_action_probability = 12;
			$baseline_exit_probability   = 58;
			break;
		case 'fast_leaver':
			$baseline_action_probability = 4;
			$baseline_exit_probability   = 82;
			break;
		default:
			$baseline_action_probability = 20;
			$baseline_exit_probability   = 40;
			break;
	}

	$action_probability = $baseline_action_probability;
	$exit_probability   = $baseline_exit_probability;

	$settings       = quorlyx_get_behavior_pattern_settings();
	$min_profiles   = max( 1, absint( $settings['min_profiles_calibration'] ?? 10 ) );
	$lookback_days  = max( 1, absint( $settings['calibration_lookback_days'] ?? 30 ) );

	$calibrated              = false;
	$calibration_sample_size = 0;
	$calibration_action_rate = null;
	if ( ! empty( $settings['enabled'] ) && 'unknown' !== $pattern_tag && quorlyx_behavior_engine_table_exists() ) {
		global $wpdb;
		$table_name    = quorlyx_get_behavior_engine_table_name();
		$lookback_time = gmdate( 'Y-m-d H:i:s', time() - ( $lookback_days * DAY_IN_SECONDS ) );

		// "Action" cannot be calibrated from converter rate alone because closer/non-converter
		// labels are already part of pattern classification. Use observable action signals instead.
		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared
		$stats = $wpdb->get_row(
			$wpdb->prepare(
				"SELECT COUNT(*) AS total, SUM(action_signal) AS action_profiles FROM (SELECT profile_hash, MAX(CASE WHEN conversion_status IN ('closer', 'buyer') OR started_chat > 0 OR cart_activity > 0 OR abandonment_stage IN ('viewed_cart','abandoned_checkout') THEN 1 ELSE 0 END) AS action_signal FROM {$table_name} WHERE pattern_tag = %s AND updated_at >= %s GROUP BY profile_hash) AS pattern_profiles",
				$pattern_tag,
				$lookback_time
			),
			ARRAY_A
		);

		$total_profiles = absint( $stats['total'] ?? 0 );
		if ( $total_profiles >= $min_profiles ) {
			$action_profiles         = absint( $stats['action_profiles'] ?? 0 );
			$observed_action_rate    = max( 0, min( 100, (int) round( ( $action_profiles / $total_profiles ) * 100 ) ) );
			$observed_exit_rate      = 100 - $observed_action_rate;
			$action_probability      = (int) round( ( $baseline_action_probability * 0.35 ) + ( $observed_action_rate * 0.65 ) );
			$exit_probability        = (int) round( ( $baseline_exit_probability * 0.55 ) + ( $observed_exit_rate * 0.45 ) );
			$calibrated              = true;
			$calibration_sample_size = $total_profiles;
			$calibration_action_rate = $observed_action_rate;
		}
	}

	if ( $started_chat ) {
		$action_probability += 8;
		$exit_probability   -= 4;
	}

	if ( $cart_activity > 0 ) {
		$action_probability += 8;
		$exit_probability   -= 3;
	}

	if ( 'viewed_cart' === $abandonment_stage ) {
		// Viewed cart is a positive purchase-intent signal; only boost action probability.
		$action_probability += 5;
	} elseif ( 'abandoned_checkout' === $abandonment_stage ) {
		// Being at checkout stage is a peak intent signal, but with higher drop-off risk if they stall.
		$action_probability += 15;
		$exit_probability   += 12;
	}

	if ( $scroll_depth >= 70 ) {
		$action_probability += 4;
	}

	if ( $dwell_time_avg >= 180 ) {
		$action_probability += 2;
		$exit_probability   -= 3;
	}

	if ( $visit_frequency >= 4 && 'closer' !== $conversion_status ) {
		$action_probability -= 5;
		$exit_probability   += 5;
	}

	if ( $pages_viewed >= 6 ) {
		$exit_probability -= 2;
	}

	if ( 'closer' === $conversion_status ) {
		$action_probability = max( $action_probability, 85 );
		$exit_probability   = min( $exit_probability, 8 );
	}

	if ( ! in_array( $conversion_status, array( 'closer', 'non_converter' ), true ) ) {
		$action_probability = (int) round( $action_probability * 0.9 );
		$exit_probability   = (int) round( $exit_probability * 0.9 );
	}

	$action_probability = max( 1, min( 95, (int) $action_probability ) );
	$exit_probability   = max( 1, min( 95, (int) $exit_probability ) );

	$combined = $action_probability + $exit_probability;
	if ( $combined > 95 ) {
		$scale              = 95 / $combined;
		$action_probability = max( 1, min( 95, (int) round( $action_probability * $scale ) ) );
		$exit_probability   = max( 1, min( 95, (int) round( $exit_probability * $scale ) ) );
	}

	$continue_probability = max( 0, 100 - ( $action_probability + $exit_probability ) );

	$next_step       = 'continue_browsing';
	$next_step_label = 'Likely to continue browsing.';

	if ( $action_probability >= $exit_probability && $action_probability >= $continue_probability ) {
		$next_step       = 'likely_take_action';
		$next_step_label = 'Likely to take an action soon.';
	} elseif ( $exit_probability >= $action_probability && $exit_probability >= $continue_probability ) {
		$next_step       = 'likely_leave';
		$next_step_label = 'Likely to leave without taking action.';
	}

	if ( 'abandoned_checkout' === $abandonment_stage && $exit_probability >= 40 ) {
		$next_step       = 'checkout_dropout_risk';
		$next_step_label = 'High risk of checkout drop-off.';
	}

	$probability_ranking = array( $action_probability, $exit_probability, $continue_probability );
	rsort( $probability_ranking );
	$prediction_margin     = absint( $probability_ranking[0] - $probability_ranking[1] );
	
	if ( $calibrated ) {
		$calc_confidence = max( 70, min( 99, 65 + $prediction_margin ) ); // Calibrated yields higher base confidence
	} else {
		$calc_confidence = max( 50, min( 95, 55 + $prediction_margin ) );
	}
	
	$confidence_threshold  = max( 50, absint( $settings['prediction_confidence'] ?? 80 ) );
	$confidence_met        = $calc_confidence >= $confidence_threshold;

	return array(
		'next_step'            => $next_step,
		'next_step_label'      => $next_step_label,
		'action_probability'   => $action_probability,
		'exit_probability'     => $exit_probability,
		'continue_probability' => $continue_probability,
		'prediction_confidence' => $calc_confidence,
		'confidence_met'       => $confidence_met,
		'calibrated_dynamically' => $calibrated,
		'calibration_sample_size' => $calibration_sample_size,
		'calibration_action_rate' => null === $calibration_action_rate ? null : absint( $calibration_action_rate ),
		'pattern_tag'          => $pattern_tag,
		'pattern_label'        => quorlyx_get_behavior_pattern_label( $pattern_tag ),
	);
}

/**
 * Deterministically sample non-converter profiles by hash bucket.
 *
 * @param string $profile_hash Profile hash.
 * @param int    $source_post_id Source post ID.
 * @param string $content_key Content key.
 * @param int    $sample_rate Sample rate percentage.
 * @return bool
 */
function quorlyx_behavior_engine_should_sample_non_converter( $profile_hash, $source_post_id, $content_key, $sample_rate ) {
	$sample_rate = max( 0, min( 100, absint( $sample_rate ) ) );
	if ( 100 === $sample_rate ) {
		return true;
	}
	if ( 0 === $sample_rate ) {
		return false;
	}

	$seed   = sanitize_text_field( (string) $profile_hash ) . '|' . absint( $source_post_id ) . '|' . sanitize_key( (string) $content_key );
	$bucket = absint( sprintf( '%u', crc32( $seed ) ) ) % 100;

	return $bucket < $sample_rate;
}

/**
 * Periodically prune stale behavior-engine rows by retention policy.
 *
 * @param int $retention_days Retention period in days.
 * @return void
 */
function quorlyx_maybe_prune_behavior_engine_rows( $retention_days ) {
	$retention_days = max( 7, min( 365, absint( $retention_days ) ) );
	$now            = time();
	$last_prune     = absint( get_option( 'quorlyx_behavior_engine_last_prune', 0 ) );

	if ( $last_prune > 0 && ( $now - $last_prune ) < HOUR_IN_SECONDS ) {
		return;
	}

	global $wpdb;
	$table_name = quorlyx_get_behavior_engine_table_name();
	$cutoff     = gmdate( 'Y-m-d H:i:s', $now - ( $retention_days * DAY_IN_SECONDS ) );

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Maintenance delete for expired behavior rows.
	// phpcs:disable WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Table name comes from trusted helper with wpdb prefix.
	$deleted = $wpdb->query(
		$wpdb->prepare(
			"DELETE FROM {$table_name} WHERE updated_at < %s",
			$cutoff
		)
	);
	// phpcs:enable WordPress.DB.PreparedSQL.InterpolatedNotPrepared

	if ( false === $deleted ) {
		quorlyx_behavior_log_event_once(
			'behavior_prune_failed|' . $retention_days,
			'error',
			'Behavior engine retention prune failed',
			array(
				'component'      => 'behavior_engine',
				'operation'      => 'prune_rows',
				'phase'          => 'delete_expired',
				'retention_days' => $retention_days,
				'cutoff'         => $cutoff,
				'db_error'       => sanitize_text_field( (string) $wpdb->last_error ),
			),
			1800
		);

		return;
	}

	update_option( 'quorlyx_behavior_engine_last_prune', $now, false );
}

/**
 * Sanitize a potentially nested payload array.
 *
 * @param mixed $value Input value.
 * @return array<string|int,mixed>
 */
function quorlyx_sanitize_array( $value ) {
	if ( is_string( $value ) ) {
		$decoded = json_decode( $value, true );
		if ( is_array( $decoded ) ) {
			$value = $decoded;
		}
	}

	if ( ! is_array( $value ) ) {
		return array();
	}

	$sanitized = array();
	foreach ( $value as $key => $item ) {
		$sanitized_key = is_int( $key ) ? $key : sanitize_key( (string) $key );

		if ( is_array( $item ) ) {
			$sanitized[ $sanitized_key ] = quorlyx_sanitize_array( $item );
			continue;
		}

		if ( is_bool( $item ) ) {
			$sanitized[ $sanitized_key ] = $item;
			continue;
		}

		if ( is_numeric( $item ) ) {
			$sanitized[ $sanitized_key ] = $item + 0;
			continue;
		}

		$sanitized[ $sanitized_key ] = sanitize_text_field( (string) $item );
	}

	return $sanitized;
}

/**
 * Insert or update one behavior-engine snapshot row.
 *
 * @param array<string,mixed> $snapshot Snapshot payload.
 * @return bool
 */
function quorlyx_upsert_behavior_engine_snapshot( $snapshot ) {
	global $wpdb;

	$table_name = quorlyx_get_behavior_engine_table_name();

	$profile_hash      = sanitize_text_field( (string) ( $snapshot['profile_hash'] ?? '' ) );
	$source_post_id    = quorlyx_get_canonical_analytics_post_id( absint( $snapshot['source_post_id'] ?? 0 ) );
	$content_key       = sanitize_key( (string) ( $snapshot['content_key'] ?? '' ) );
	$last_post_id      = quorlyx_get_canonical_analytics_post_id( absint( $snapshot['last_post_id'] ?? 0 ) );
	$last_content_key  = sanitize_key( (string) ( $snapshot['last_content_key'] ?? '' ) );
	$abandonment_stage = sanitize_key( (string) ( $snapshot['abandonment_stage'] ?? '' ) );
	$traffic_source    = quorlyx_normalize_traffic_source_segment( (string) ( $snapshot['traffic_source'] ?? 'direct' ) );
	$traffic_source_score = quorlyx_get_traffic_source_segment_score( $traffic_source );
	$product_id        = absint( $snapshot['product_id'] ?? 0 );
	$visit_frequency   = max( 0, absint( $snapshot['visit_frequency'] ?? 0 ) );
	$pages_viewed      = max( 0, absint( $snapshot['pages_viewed'] ?? 0 ) );
	$dwell_time_avg    = max( 0, absint( $snapshot['dwell_time_avg'] ?? 0 ) );
	$cart_activity     = max( 0, absint( $snapshot['cart_activity'] ?? 0 ) );
	$scroll_depth      = max( 0, min( 100, absint( $snapshot['scroll_depth'] ?? 0 ) ) );
	$conversion_status = quorlyx_normalize_behavior_conversion_status( $snapshot['conversion_status'] ?? 'unknown' );
	$started_chat      = ! empty( $snapshot['started_chat'] ) ? 1 : 0;
	$sampled_non_conv  = ! empty( $snapshot['sampled_non_converter'] ) ? 1 : 0;
	$session_id        = sanitize_text_field( (string) ( $snapshot['session_id'] ?? '' ) );
	$visited_path_raw  = $snapshot['visited_path'] ?? '[]';
	$visited_path      = is_string( $visited_path_raw ) ? sanitize_textarea_field( $visited_path_raw ) : wp_json_encode( quorlyx_sanitize_array( $visited_path_raw ) );
	$raw_breakdown     = $snapshot['category_breakdown'] ?? '{}';
	$category_breakdown = '{}';

	if ( is_array( $raw_breakdown ) ) {
		$encoded_breakdown = wp_json_encode( $raw_breakdown );
		$category_breakdown = is_string( $encoded_breakdown ) && '' !== $encoded_breakdown ? $encoded_breakdown : '{}';
	} else {
		$category_breakdown = sanitize_text_field( (string) $raw_breakdown );
		if ( '' === $category_breakdown ) {
			$category_breakdown = '{}';
		}
	}

	if ( '' === $profile_hash || ( $source_post_id <= 0 && '' === $content_key ) ) {
		quorlyx_behavior_log_event_once(
			'behavior_snapshot_invalid_payload|' . ( '' !== $profile_hash ? 'hash_present' : 'hash_missing' ) . '|' . $source_post_id . '|' . $content_key,
			'warning',
			'Behavior snapshot skipped due to invalid payload',
			array(
				'component'      => 'behavior_engine',
				'operation'      => 'upsert_snapshot',
				'phase'          => 'validate_payload',
				'has_profile_id' => '' !== $profile_hash,
				'source_post_id' => $source_post_id,
				'content_key'    => $content_key,
			)
		);

		return false;
	}

	if ( ! in_array( $abandonment_stage, array( '', 'viewed_cart', 'abandoned_checkout' ), true ) ) {
		$abandonment_stage = '';
	}

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Row-level lookup for upsert behavior snapshot.
	// phpcs:disable WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Table name comes from trusted helper with wpdb prefix.
	$existing = $wpdb->get_row(
		$wpdb->prepare(
			"SELECT id, source_post_id, content_key, product_id, visit_frequency, pages_viewed, dwell_time_avg, cart_activity, scroll_depth, conversion_status, last_post_id, last_content_key, category_breakdown, abandonment_stage, started_chat, traffic_source, visited_path FROM {$table_name} WHERE profile_hash = %s AND session_id = %s ORDER BY updated_at DESC, id DESC LIMIT 1",
			$profile_hash,
			$session_id
		),
		ARRAY_A
	);
	// phpcs:enable WordPress.DB.PreparedSQL.InterpolatedNotPrepared

	if ( null === $existing && '' !== (string) $wpdb->last_error ) {
		quorlyx_behavior_log_event_once(
			'behavior_snapshot_lookup_failed|' . $source_post_id . '|' . $content_key . '|' . $product_id,
			'error',
			'Behavior snapshot lookup failed before upsert',
			array(
				'component'      => 'behavior_engine',
				'operation'      => 'upsert_snapshot',
				'phase'          => 'lookup_existing',
				'source_post_id' => $source_post_id,
				'content_key'    => $content_key,
				'product_id'     => $product_id,
				'db_error'       => sanitize_text_field( (string) $wpdb->last_error ),
			),
			1800
		);

		return false;
	}

	if ( is_array( $existing ) ) {
		$existing_source_post_id = quorlyx_get_canonical_analytics_post_id( absint( $existing['source_post_id'] ?? 0 ) );
		$existing_content_key    = sanitize_key( (string) ( $existing['content_key'] ?? '' ) );
		if ( $existing_source_post_id > 0 || '' !== $existing_content_key ) {
			$source_post_id = $existing_source_post_id;
			$content_key    = $existing_content_key;
		}

		$existing_product_id = quorlyx_get_canonical_analytics_post_id( absint( $existing['product_id'] ?? 0 ) );
		if ( $existing_product_id > 0 ) {
			$product_id = $existing_product_id;
		}

		$visit_frequency = max( $visit_frequency, absint( $existing['visit_frequency'] ?? 0 ) );
		$pages_viewed    = max( $pages_viewed, absint( $existing['pages_viewed'] ?? 0 ) );
		$cart_activity   = max( $cart_activity, absint( $existing['cart_activity'] ?? 0 ) );

		$existing_path = json_decode( $existing['visited_path'] ?? '[]', true );
		$new_path      = json_decode( $visited_path, true );
		if ( is_array( $existing_path ) && is_array( $new_path ) ) {
			$visited_path = wp_json_encode( array_values( array_unique( array_merge( $existing_path, $new_path ) ) ) );
		}

		// JS now sends session-aggregated metrics. We trust the incoming payload for the current session state.
		// No manual averaging is required here as it would distort the already-aggregated session values.
		$scroll_depth   = max( $scroll_depth, absint( $existing['scroll_depth'] ?? 0 ) );
		$dwell_time_avg = max( $dwell_time_avg, absint( $existing['dwell_time_avg'] ?? 0 ) );

		$existing_status = quorlyx_normalize_behavior_conversion_status( $existing['conversion_status'] ?? 'unknown' );
		if ( 'closer' === $existing_status || 'closer' === $conversion_status ) {
			$conversion_status = 'closer';
		} elseif ( 'non_converter' === $existing_status || 'non_converter' === $conversion_status ) {
			$conversion_status = 'non_converter';
		} else {
			$conversion_status = 'unknown';
		}

		if ( ! empty( $existing['started_chat'] ) ) {
			$started_chat = 1;
		}

		if ( $last_post_id <= 0 && '' === $last_content_key ) {
			$last_post_id     = quorlyx_get_canonical_analytics_post_id( absint( $existing['last_post_id'] ?? 0 ) );
			$last_content_key = sanitize_key( (string) ( $existing['last_content_key'] ?? '' ) );
		}

		$existing_breakdown = sanitize_text_field( (string) ( $existing['category_breakdown'] ?? '' ) );
		if ( '{}' === $category_breakdown || '' === $category_breakdown ) {
			$category_breakdown = '' !== $existing_breakdown ? $existing_breakdown : '{}';
		}

		$existing_stage = sanitize_key( (string) ( $existing['abandonment_stage'] ?? '' ) );
		if ( 'abandoned_checkout' === $existing_stage || ( '' === $abandonment_stage && 'viewed_cart' === $existing_stage ) ) {
			$abandonment_stage = $existing_stage;
		}

		$existing_traffic_source = quorlyx_normalize_traffic_source_segment( (string) ( $existing['traffic_source'] ?? '' ) );
		if ( '' === sanitize_key( (string) ( $snapshot['traffic_source'] ?? '' ) ) && '' !== $existing_traffic_source ) {
			$traffic_source = $existing_traffic_source;
			$traffic_source_score = quorlyx_get_traffic_source_segment_score( $traffic_source );
		}
	}

	if ( 'closer' === $conversion_status ) {
		$abandonment_stage = '';
	}

	$behavior_settings = quorlyx_get_behavior_pattern_settings();
	$pattern_tag       = quorlyx_classify_behavior_pattern(
		$visit_frequency,
		$pages_viewed,
		$dwell_time_avg,
		$cart_activity,
		$scroll_depth,
		$conversion_status,
		$behavior_settings,
		array(
			'started_chat'     => $started_chat,
			'source_post_id'   => $source_post_id,
			'content_key'      => $content_key,
			'product_id'       => $product_id,
			'traffic_source'   => $traffic_source,
			'abandonment_stage' => $abandonment_stage,
		)
	);
	$timestamp   = current_time( 'mysql' );

	$data = array(
		'session_id'            => $session_id,
		'profile_hash'          => $profile_hash,
		'pattern_tag'           => $pattern_tag,
		'visited_path'          => $visited_path,
		'traffic_source'        => $traffic_source,
		'traffic_source_score'  => $traffic_source_score,
		'product_id'            => $product_id,
		'visit_frequency'       => $visit_frequency,
		'pages_viewed'          => $pages_viewed,
		'dwell_time_avg'        => $dwell_time_avg,
		'cart_activity'         => $cart_activity,
		'scroll_depth'          => $scroll_depth,
		'conversion_status'     => $conversion_status,
		'source_post_id'        => $source_post_id,
		'content_key'           => $content_key,
		'last_post_id'          => $last_post_id,
		'last_content_key'      => $last_content_key,
		'category_breakdown'    => $category_breakdown,
		'abandonment_stage'     => $abandonment_stage,
		'started_chat'          => $started_chat,
		'sampled_non_converter' => $sampled_non_conv,
		'updated_at'            => $timestamp,
	);

	if ( is_array( $existing ) && ! empty( $existing['id'] ) ) {
		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Row update for behavior snapshot.
		$updated = $wpdb->update(
			$table_name,
			$data,
			array( 'id' => absint( $existing['id'] ) ),
			array( '%s', '%s', '%s', '%s', '%s', '%d', '%d', '%d', '%d', '%d', '%d', '%d', '%s', '%d', '%s', '%d', '%s', '%s', '%s', '%d', '%d', '%s' ),
			array( '%d' )
		);

		if ( false === $updated ) {
			quorlyx_behavior_log_event_once(
				'behavior_snapshot_update_failed|' . $source_post_id . '|' . $content_key . '|' . $product_id,
				'error',
				'Behavior snapshot update failed',
				array(
					'component'      => 'behavior_engine',
					'operation'      => 'upsert_snapshot',
					'phase'          => 'update_row',
					'source_post_id' => $source_post_id,
					'content_key'    => $content_key,
					'product_id'     => $product_id,
					'pattern_tag'    => $pattern_tag,
					'db_error'       => sanitize_text_field( (string) $wpdb->last_error ),
				),
				1800
			);

			return false;
		}
	} else {
		$data['created_at'] = $timestamp;

		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Row insert for behavior snapshot.
		$inserted = $wpdb->insert(
			$table_name,
			$data,
			array( '%s', '%s', '%s', '%s', '%s', '%d', '%d', '%d', '%d', '%d', '%d', '%d', '%s', '%d', '%s', '%d', '%s', '%s', '%s', '%d', '%d', '%s', '%s' )
		);

		if ( false === $inserted ) {
			quorlyx_behavior_log_event_once(
				'behavior_snapshot_insert_failed|' . $source_post_id . '|' . $content_key . '|' . $product_id,
				'error',
				'Behavior snapshot insert failed',
				array(
					'component'      => 'behavior_engine',
					'operation'      => 'upsert_snapshot',
					'phase'          => 'insert_row',
					'source_post_id' => $source_post_id,
					'content_key'    => $content_key,
					'product_id'     => $product_id,
					'pattern_tag'    => $pattern_tag,
					'db_error'       => sanitize_text_field( (string) $wpdb->last_error ),
				),
				1800
			);

			return false;
		}
	}

	quorlyx_touch_content_analytics_updated_at();

	return true;
}

/**
 * Fetch distinct behavior-engine attribution sources ordered by most recent activity.
 *
 * @return array<int,array<string,int|string>>
 */
function quorlyx_get_behavior_engine_sources() {
	global $wpdb;

	$table_name = quorlyx_get_behavior_engine_table_name();

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Aggregate source list for behavior insights rendering.
	// phpcs:disable WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Table name comes from trusted helper with wpdb prefix.
	$source_rows = $wpdb->get_results(
		"SELECT source_post_id, content_key, MAX(updated_at) AS last_seen FROM {$table_name} WHERE source_post_id > 0 OR content_key <> '' GROUP BY source_post_id, content_key ORDER BY last_seen DESC",
		ARRAY_A
	);
	// phpcs:enable WordPress.DB.PreparedSQL.InterpolatedNotPrepared

	$sources = array();
	foreach ( (array) $source_rows as $source_row ) {
		$post_id     = quorlyx_get_canonical_analytics_post_id( absint( $source_row['source_post_id'] ?? 0 ) );
		$content_key = sanitize_key( (string) ( $source_row['content_key'] ?? '' ) );

		if ( $post_id <= 0 && '' === $content_key ) {
			continue;
		}

		$sources[] = array(
			'post_id'     => $post_id,
			'content_key' => $content_key,
		);
	}

	return $sources;
}

/**
 * Check whether a database table exists.
 *
 * @param string $table_name Table name.
 * @return bool
 */
function quorlyx_db_table_exists( $table_name ) {
	$table_name = sanitize_text_field( (string) $table_name );
	if ( '' === $table_name ) {
		return false;
	}

	global $wpdb;

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Fast capability probe for known Quorlyx tables.
	$table_check = $wpdb->get_var(
		$wpdb->prepare(
			'SHOW TABLES LIKE %s',
			$table_name
		)
	);

	return is_string( $table_check ) && $table_name === $table_check;
}

/**
 * Check whether the behavior engine table exists.
 *
 * @return bool
 */
function quorlyx_behavior_engine_table_exists() {
	static $table_exists = null;

	if ( null !== $table_exists ) {
		return (bool) $table_exists;
	}

	$table_exists = quorlyx_db_table_exists( quorlyx_get_behavior_engine_table_name() );

	return (bool) $table_exists;
}

