/**
 * Migrate legacy option-based virtual analytics into DB table.
 *
 * @return void
 */
function quorlyx_migrate_virtual_analytics_option_to_table() {
	static $migration_checked = false;

	if ( $migration_checked ) {
		return;
	}

	$migration_checked = true;

	if ( ! quorlyx_virtual_analytics_table_exists() ) {
		return;
	}

	$legacy_store = get_option( 'quorlyx_virtual_analytics', array() );
	if ( ! is_array( $legacy_store ) || empty( $legacy_store ) ) {
		return;
	}

	global $wpdb;
	$table_name = quorlyx_get_virtual_analytics_table_name();

	$updated_at = gmdate( 'Y-m-d H:i:s' );
	foreach ( $legacy_store as $content_key => $metrics ) {
		$content_key = sanitize_key( (string) $content_key );
		if ( '' === $content_key || ! is_array( $metrics ) ) {
			continue;
		}

		foreach ( $metrics as $meta_key => $metric_value ) {
			$meta_key = sanitize_key( (string) $meta_key );
			if ( '' === $meta_key ) {
				continue;
			}

			// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- One-time migration upsert from legacy option payload.
			$wpdb->query(
				$wpdb->prepare(
					"INSERT INTO {$table_name} (content_key, meta_key, metric_value, updated_at) VALUES (%s, %s, %d, %s)
					ON DUPLICATE KEY UPDATE metric_value = GREATEST(metric_value, VALUES(metric_value)), updated_at = VALUES(updated_at)",
					$content_key,
					$meta_key,
					(int) $metric_value,
					$updated_at
				)
			);
		}
	}
}

/**
 * Migrate legacy postmeta Content Insights counters into DB-first analytics rows.
 *
 * @return void
 */
function quorlyx_migrate_post_analytics_meta_to_table() {
	static $migration_checked = false;

	if ( $migration_checked ) {
		return;
	}

	$migration_checked = true;

	if ( ! quorlyx_virtual_analytics_table_exists() ) {
		return;
	}

	global $wpdb;
	$metric_keys      = quorlyx_get_content_insights_metric_keys();
	$metric_ph        = implode( ', ', array_fill( 0, count( $metric_keys ), '%s' ) );
	$migrated_key     = '_quorlyx_analytics_db_migrated';
	$postmeta_table   = $wpdb->postmeta;
	$analytics_table  = quorlyx_get_virtual_analytics_table_name();
	$updated_at       = gmdate( 'Y-m-d H:i:s' );
	$select_arguments = array_merge( array( $migrated_key ), $metric_keys );

	// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Bounded one-time migration query over postmeta.
	$post_ids = $wpdb->get_col(
		$wpdb->prepare(
			"SELECT DISTINCT pm.post_id
			FROM {$postmeta_table} pm
			LEFT JOIN {$postmeta_table} migrated ON migrated.post_id = pm.post_id AND migrated.meta_key = %s
			WHERE pm.meta_key IN ({$metric_ph})
			AND migrated.post_id IS NULL
			ORDER BY pm.post_id ASC
			LIMIT 250",
			$select_arguments
		)
	);

	foreach ( array_map( 'absint', (array) $post_ids ) as $post_id ) {
		if ( $post_id <= 0 ) {
			continue;
		}

		$content_key = quorlyx_get_db_analytics_content_key( $post_id, '' );
		foreach ( $metric_keys as $meta_key ) {
			$value = (int) get_post_meta( $post_id, $meta_key, true );
			if ( 0 === $value ) {
				continue;
			}

			// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- One-time migration upsert from legacy postmeta counters.
			$wpdb->query(
				$wpdb->prepare(
					"INSERT INTO {$analytics_table} (content_key, meta_key, metric_value, updated_at) VALUES (%s, %s, %d, %s)
					ON DUPLICATE KEY UPDATE metric_value = GREATEST(metric_value, VALUES(metric_value)), updated_at = VALUES(updated_at)",
					$content_key,
					$meta_key,
					$value,
					$updated_at
				)
			);
		}

		update_post_meta( $post_id, $migrated_key, '1' );
	}
}

/**
 * Migrate legacy option-based trigger analytics into DB table.
 *
 * @return void
 */
function quorlyx_migrate_trigger_analytics_option_to_table() {
	static $migration_checked = false;

	if ( $migration_checked ) {
		return;
	}

	$migration_checked = true;

	if ( ! quorlyx_trigger_analytics_events_table_exists() ) {
		return;
	}

	$legacy_store = get_option( 'quorlyx_trigger_analytics', array() );
	if ( ! is_array( $legacy_store ) || empty( $legacy_store ) ) {
		return;
	}

	global $wpdb;
	$table_name = quorlyx_get_trigger_analytics_events_table_name();

	// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Row-count probe avoids re-importing already-migrated rows.
	$existing_rows = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$table_name}" );
	if ( $existing_rows > 0 ) {
		return;
	}

	$daily_data       = is_array( $legacy_store['daily'] ?? null ) ? $legacy_store['daily'] : array();
	$totals_data      = is_array( $legacy_store['totals'] ?? null ) ? $legacy_store['totals'] : array();
	$allowed_events   = quorlyx_get_trigger_analytics_events();
	$updated_at_epoch = absint( $legacy_store['updated_at'] ?? 0 );
	$updated_at       = gmdate( 'Y-m-d H:i:s', max( 1, $updated_at_epoch ) );
	$had_daily_rows   = false;

	foreach ( $daily_data as $date_key => $trigger_rows ) {
		$date_key = sanitize_text_field( (string) $date_key );
		if ( ! preg_match( '/^\d{4}-\d{2}-\d{2}$/', $date_key ) ) {
			continue;
		}

		if ( ! is_array( $trigger_rows ) ) {
			continue;
		}

		foreach ( $trigger_rows as $trigger_id => $event_counts ) {
			$trigger_id = sanitize_key( (string) $trigger_id );
			if ( '' === $trigger_id || ! is_array( $event_counts ) ) {
				continue;
			}

			foreach ( $event_counts as $event_name => $count ) {
				$event_name = sanitize_key( (string) $event_name );
				$count      = max( 0, (int) $count );

				if ( 0 === $count || ! in_array( $event_name, $allowed_events, true ) ) {
					continue;
				}

				// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- One-time migration upsert from legacy option payload.
				$wpdb->query(
					$wpdb->prepare(
						"INSERT INTO {$table_name} (trigger_id, event_name, event_date, event_count, created_at, updated_at)
						VALUES (%s, %s, %s, %d, %s, %s)
						ON DUPLICATE KEY UPDATE event_count = event_count + VALUES(event_count), updated_at = VALUES(updated_at)",
						$trigger_id,
						$event_name,
						$date_key,
						$count,
						$updated_at,
						$updated_at
					)
				);
				$had_daily_rows = true;
			}
		}
	}

	if ( $had_daily_rows ) {
		return;
	}

	$fallback_date = '1970-01-01';
	foreach ( $totals_data as $trigger_id => $event_counts ) {
		$trigger_id = sanitize_key( (string) $trigger_id );
		if ( '' === $trigger_id || ! is_array( $event_counts ) ) {
			continue;
		}

		foreach ( $event_counts as $event_name => $count ) {
			$event_name = sanitize_key( (string) $event_name );
			$count      = max( 0, (int) $count );

			if ( 0 === $count || ! in_array( $event_name, $allowed_events, true ) ) {
				continue;
			}

			// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Totals fallback migration when legacy daily rows are unavailable.
			$wpdb->query(
				$wpdb->prepare(
					"INSERT INTO {$table_name} (trigger_id, event_name, event_date, event_count, created_at, updated_at)
					VALUES (%s, %s, %s, %d, %s, %s)
					ON DUPLICATE KEY UPDATE event_count = event_count + VALUES(event_count), updated_at = VALUES(updated_at)",
					$trigger_id,
					$event_name,
					$fallback_date,
					$count,
					$updated_at,
					$updated_at
				)
			);
		}
	}
}

/**
 * Bootstrap one-time migrations for DB-first analytics mode.
 *
 * @return void
 */
function quorlyx_bootstrap_db_first_analytics_migration() {
	if ( ! quorlyx_should_use_global_db_processing() ) {
		return;
	}

	quorlyx_migrate_virtual_analytics_option_to_table();
	quorlyx_migrate_post_analytics_meta_to_table();
	quorlyx_migrate_trigger_analytics_option_to_table();
}

/**
 * Resolve whether behavior analytics should prefer database-native profile selection.
 *
 * @param array<string,mixed>|null $behavior_settings Optional behavior settings.
 * @return bool
 */
function quorlyx_should_use_behavior_db_processing( $behavior_settings = null ) {
	$settings = is_array( $behavior_settings ) ? $behavior_settings : quorlyx_get_behavior_pattern_settings();
	$prefer_db = ! empty( $settings['prefer_db_processing'] ) || quorlyx_should_use_global_db_processing();

	if ( ! $prefer_db ) {
		return false;
	}

	return quorlyx_behavior_engine_table_exists();
}

/**
 * Fetch behavior rows directly in SQL for a source/content pair.
 *
 * @param int    $post_id     Source post ID.
 * @param string $content_key Source content key.
 * @return array<int,array<string,mixed>>|null
 */
function quorlyx_get_behavior_engine_latest_profile_rows_from_db( $post_id, $content_key = '' ) {
	global $wpdb;

	$post_id     = quorlyx_get_canonical_analytics_post_id( absint( $post_id ) );
	$content_key = sanitize_key( (string) $content_key );

	if ( $post_id <= 0 && '' === $content_key ) {
		return array();
	}

	$table_name = quorlyx_get_behavior_engine_table_name();

	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- DB-first latest-profile selection avoids loading historical duplicates into PHP.
	// phpcs:disable WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Table name comes from trusted helper with wpdb prefix.
	$latest_rows = $wpdb->get_results(
		$wpdb->prepare(
			"SELECT id, profile_hash, pattern_tag, conversion_status, started_chat, visit_frequency, pages_viewed, dwell_time_avg, cart_activity, scroll_depth, category_breakdown, last_post_id, last_content_key, abandonment_stage, traffic_source, visited_path FROM {$table_name} WHERE source_post_id = %d AND content_key = %s ORDER BY updated_at DESC, id DESC",
			$post_id,
			$content_key
		),
		ARRAY_A
	);
	// phpcs:enable WordPress.DB.PreparedSQL.InterpolatedNotPrepared

	if ( null === $latest_rows && '' !== (string) $wpdb->last_error ) {
		quorlyx_behavior_log_event_once(
			'behavior_snapshot_latest_profile_db_query_failed|' . $post_id . '|' . $content_key,
			'error',
			'Behavior DB-first latest-profile query failed; falling back to PHP aggregation',
			array(
				'component'      => 'behavior_engine',
				'operation'      => 'snapshot_aggregate',
				'phase'          => 'latest_profile_query',
				'source_post_id' => $post_id,
				'content_key'    => $content_key,
				'db_error'       => sanitize_text_field( (string) $wpdb->last_error ),
			),
			1800
		);

		return null;
	}

	return is_array( $latest_rows ) ? $latest_rows : array();
}

/**
 * Merge behavior snapshot rows into one profile summary per profile hash.
 *
 * @param array<int,array<string,mixed>> $detail_rows Raw snapshot rows.
 * @param array<string,mixed>|null $behavior_settings Optional behavior settings.
 * @param int $post_id Source post ID.
 * @param string $content_key Source content key.
 * @return array<int,array<string,mixed>>
 */
function quorlyx_merge_behavior_snapshot_rows( $detail_rows, $behavior_settings = null, $post_id = 0, $content_key = '' ) {
	$behavior_settings = quorlyx_get_behavior_pattern_settings( $behavior_settings );
	$min_sessions      = max( 1, absint( $behavior_settings['min_sessions_for_classification'] ?? 1 ) );
	$profile_groups    = array();

	foreach ( (array) $detail_rows as $detail_row ) {
		if ( ! is_array( $detail_row ) ) {
			continue;
		}

		$profile_hash = sanitize_text_field( (string) ( $detail_row['profile_hash'] ?? '' ) );
		$profile_key  = '' !== $profile_hash ? $profile_hash : 'row_' . absint( $detail_row['id'] ?? 0 );

		if ( ! isset( $profile_groups[ $profile_key ] ) ) {
			$profile_groups[ $profile_key ] = array(
				'profile_hash'      => $profile_hash,
				'pattern_tag'       => quorlyx_normalize_behavior_pattern_key( (string) ( $detail_row['pattern_tag'] ?? 'unknown' ) ),
				'conversion_status' => quorlyx_normalize_behavior_conversion_status( $detail_row['conversion_status'] ?? 'unknown' ),
				'started_chat'      => absint( $detail_row['started_chat'] ?? 0 ) > 0 ? 1 : 0,
				'visit_frequency'   => 0,
				'pages_viewed'      => 0,
				'dwell_time_total'  => 0.0,
				'dwell_weight'      => 0,
				'cart_activity'     => 0,
				'scroll_depth_total' => 0.0,
				'scroll_weight'     => 0,
				'product_id'        => quorlyx_get_canonical_analytics_post_id( absint( $detail_row['product_id'] ?? 0 ) ),
				'traffic_source'    => quorlyx_normalize_traffic_source_segment( (string) ( $detail_row['traffic_source'] ?? 'direct' ) ),
				'last_post_id'      => quorlyx_get_canonical_analytics_post_id( absint( $detail_row['last_post_id'] ?? 0 ) ),
				'last_content_key'  => sanitize_key( (string) ( $detail_row['last_content_key'] ?? '' ) ),
				'abandonment_stage' => sanitize_key( (string) ( $detail_row['abandonment_stage'] ?? '' ) ),
				'visited_path'      => array(),
				'category_totals'   => array(),
				'category_weight'   => 0,
				'source_post_id'    => quorlyx_get_canonical_analytics_post_id( absint( $detail_row['source_post_id'] ?? $post_id ) ),
				'content_key'       => sanitize_key( (string) ( $detail_row['content_key'] ?? $content_key ) ),
				'latest_id'         => absint( $detail_row['id'] ?? 0 ),
			);
		}

		$group = $profile_groups[ $profile_key ];

		$group['visit_frequency'] += max( 0, absint( $detail_row['visit_frequency'] ?? 0 ) );

		$row_pages_viewed = max( 0, absint( $detail_row['pages_viewed'] ?? 0 ) );
		$row_weight       = max( 1, $row_pages_viewed );
		$group['pages_viewed'] += $row_pages_viewed;

		$group['dwell_time_total'] += (float) ( $detail_row['dwell_time_avg'] ?? 0 ) * $row_weight;
		$group['dwell_weight']    += $row_weight;
		$group['cart_activity']   += max( 0, absint( $detail_row['cart_activity'] ?? 0 ) );
		$group['scroll_depth_total'] += (float) max( 0, min( 100, absint( $detail_row['scroll_depth'] ?? 0 ) ) ) * $row_weight;
		$group['scroll_weight']      += $row_weight;

		if ( absint( $detail_row['started_chat'] ?? 0 ) > 0 ) {
			$group['started_chat'] = 1;
		}

		$row_pattern_tag = quorlyx_normalize_behavior_pattern_key( (string) ( $detail_row['pattern_tag'] ?? 'unknown' ) );
		if ( 'unknown' === $group['pattern_tag'] && 'unknown' !== $row_pattern_tag ) {
			$group['pattern_tag'] = $row_pattern_tag;
		}

		$row_status = quorlyx_normalize_behavior_conversion_status( $detail_row['conversion_status'] ?? 'unknown' );
		if ( 'closer' === $row_status ) {
			$group['conversion_status'] = 'closer';
		} elseif ( 'non_converter' === $row_status && 'closer' !== $group['conversion_status'] ) {
			$group['conversion_status'] = 'non_converter';
		}

		$row_traffic_source = quorlyx_normalize_traffic_source_segment( (string) ( $detail_row['traffic_source'] ?? 'direct' ) );
		if ( 'direct' === $group['traffic_source'] && 'direct' !== $row_traffic_source ) {
			$group['traffic_source'] = $row_traffic_source;
		}

		$row_last_post_id = quorlyx_get_canonical_analytics_post_id( absint( $detail_row['last_post_id'] ?? 0 ) );
		if ( $row_last_post_id > 0 ) {
			$group['last_post_id'] = $row_last_post_id;
		}

		$row_last_content_key = sanitize_key( (string) ( $detail_row['last_content_key'] ?? '' ) );
		if ( '' !== $row_last_content_key ) {
			$group['last_content_key'] = $row_last_content_key;
		}

		$row_abandonment_stage = sanitize_key( (string) ( $detail_row['abandonment_stage'] ?? '' ) );
		if ( 'abandoned_checkout' === $row_abandonment_stage || ( 'viewed_cart' === $row_abandonment_stage && 'abandoned_checkout' !== $group['abandonment_stage'] ) ) {
			$group['abandonment_stage'] = $row_abandonment_stage;
		}

		$group['product_id'] = max( $group['product_id'], quorlyx_get_canonical_analytics_post_id( absint( $detail_row['product_id'] ?? 0 ) ) );

		$visited_path = json_decode( (string) ( $detail_row['visited_path'] ?? '[]' ), true );
		if ( is_array( $visited_path ) ) {
			foreach ( $visited_path as $path_value ) {
				$path_value = sanitize_text_field( (string) $path_value );
				if ( '' !== $path_value ) {
					$group['visited_path'][ $path_value ] = true;
				}
			}
		}

		$breakdown_raw = sanitize_text_field( (string) ( $detail_row['category_breakdown'] ?? '' ) );
		if ( '' !== $breakdown_raw ) {
			$decoded_breakdown = json_decode( $breakdown_raw, true );
			if ( is_array( $decoded_breakdown ) ) {
				foreach ( $decoded_breakdown as $type_key => $pct_value ) {
					$type_key = sanitize_key( (string) $type_key );
					$pct_value = max( 0, min( 100, (float) $pct_value ) );
					if ( '' === $type_key || $pct_value <= 0 ) {
						continue;
					}

					$group['category_totals'][ $type_key ] = (float) ( $group['category_totals'][ $type_key ] ?? 0 ) + ( $pct_value * $row_weight );
				}

				$group['category_weight'] += $row_weight;
			}
		}

		$profile_groups[ $profile_key ] = $group;
	}

	$merged_rows = array();
	foreach ( $profile_groups as $group ) {
		if ( absint( $group['visit_frequency'] ?? 0 ) < $min_sessions ) {
			continue;
		}

		$dwell_weight   = max( 1, absint( $group['dwell_weight'] ?? 0 ) );
		$scroll_weight  = max( 1, absint( $group['scroll_weight'] ?? 0 ) );
		$dwell_time_avg = (int) round( (float) ( $group['dwell_time_total'] ?? 0 ) / $dwell_weight );
		$scroll_depth   = (int) round( (float) ( $group['scroll_depth_total'] ?? 0 ) / $scroll_weight );
		$category_breakdown = array();
		$category_weight = max( 1, absint( $group['category_weight'] ?? 0 ) );

		foreach ( (array) ( $group['category_totals'] ?? array() ) as $type_key => $total_value ) {
			$type_key = sanitize_key( (string) $type_key );
			$total_value = max( 0.0, (float) $total_value );
			if ( '' === $type_key || $total_value <= 0 ) {
				continue;
			}

			$category_breakdown[ $type_key ] = (int) round( $total_value / $category_weight );
		}

		$visited_path = array_keys( array_filter( (array) ( $group['visited_path'] ?? array() ) ) );

		$merged_rows[] = array(
			'id'                 => absint( $group['latest_id'] ?? 0 ),
			'profile_hash'       => sanitize_text_field( (string) ( $group['profile_hash'] ?? '' ) ),
			'pattern_tag'        => quorlyx_normalize_behavior_pattern_key( (string) ( $group['pattern_tag'] ?? 'unknown' ) ),
			'conversion_status'   => quorlyx_normalize_behavior_conversion_status( $group['conversion_status'] ?? 'unknown' ),
			'started_chat'       => absint( $group['started_chat'] ?? 0 ),
			'visit_frequency'    => absint( $group['visit_frequency'] ?? 0 ),
			'pages_viewed'       => absint( $group['pages_viewed'] ?? 0 ),
			'dwell_time_avg'     => $dwell_time_avg,
			'cart_activity'      => absint( $group['cart_activity'] ?? 0 ),
			'scroll_depth'       => max( 0, min( 100, $scroll_depth ) ),
			'category_breakdown' => ! empty( $category_breakdown ) ? wp_json_encode( $category_breakdown ) : '{}',
			'last_post_id'       => quorlyx_get_canonical_analytics_post_id( absint( $group['last_post_id'] ?? 0 ) ),
			'last_content_key'   => sanitize_key( (string) ( $group['last_content_key'] ?? '' ) ),
			'abandonment_stage'  => sanitize_key( (string) ( $group['abandonment_stage'] ?? '' ) ),
			'traffic_source'     => quorlyx_normalize_traffic_source_segment( (string) ( $group['traffic_source'] ?? 'direct' ) ),
			'visited_path'       => wp_json_encode( $visited_path ),
			'source_post_id'     => quorlyx_get_canonical_analytics_post_id( absint( $group['source_post_id'] ?? $post_id ) ),
			'content_key'        => sanitize_key( (string) ( $group['content_key'] ?? $content_key ) ),
			'product_id'         => quorlyx_get_canonical_analytics_post_id( absint( $group['product_id'] ?? 0 ) ),
		);
	}

	return $merged_rows;
}

/**
 * Resolve a behavior content source into a normalized page type key.
 *
 * @param int    $post_id     Post ID.
 * @param string $content_key Content key.
 * @return string
 */
function quorlyx_get_behavior_content_type_key( $post_id = 0, $content_key = '' ) {
	$post_id     = quorlyx_get_canonical_analytics_post_id( absint( $post_id ) );
	$content_key = sanitize_key( (string) $content_key );

	if ( $post_id > 0 ) {
		$post_type = get_post_type( $post_id );
		if ( is_string( $post_type ) && '' !== $post_type ) {
			return sanitize_key( $post_type );
		}
	}

	if ( 'homepage' === $content_key ) {
		return 'homepage';
	}

	if ( in_array( $content_key, array( 'cart', 'checkout', 'product', 'post', 'page' ), true ) ) {
		return $content_key;
	}

	if ( '' !== $content_key && 0 === strpos( $content_key, 'route_' ) ) {
		return 'page';
	}

	return 'unknown';
}

/**
 * Build a readable type-mix label from type counts.
 *
 * @param array<string,int|float> $type_counts Type counts.
 * @return string
 */
function quorlyx_get_behavior_type_mix_label( $type_counts ) {
	if ( ! is_array( $type_counts ) || empty( $type_counts ) ) {
		return 'N/A';
	}

	$normalized_counts = array();
	$total             = 0.0;

	foreach ( $type_counts as $type_key => $type_count ) {
		$normalized_key = sanitize_key( (string) $type_key );
		$count          = max( 0.0, (float) $type_count );
		if ( '' === $normalized_key || $count <= 0 ) {
			continue;
		}

		$normalized_counts[ $normalized_key ] = (float) ( $normalized_counts[ $normalized_key ] ?? 0 ) + $count;
		$total                              += $count;
	}

	if ( $total <= 0 || empty( $normalized_counts ) ) {
		return 'N/A';
	}

	arsort( $normalized_counts );
	$parts = array();
	foreach ( $normalized_counts as $type_key => $type_count ) {
		$pct = (int) round( ( $type_count / $total ) * 100 );
		if ( $pct <= 0 ) {
			continue;
		}

		$parts[] = ucwords( str_replace( '_', ' ', (string) $type_key ) ) . ' ' . $pct . '%';
		if ( count( $parts ) >= 4 ) {
			break;
		}
	}

	return ! empty( $parts ) ? implode( ' ', $parts ) : 'N/A';
}

/**
 * Build category breakdown label from averaged type totals.
 *
 * @param array<string,int|float> $type_totals  Accumulated type percentages.
 * @param int                     $type_samples Number of samples.
 * @return string
 */
function quorlyx_get_behavior_category_breakdown_label( $type_totals, $type_samples ) {
	if ( ! is_array( $type_totals ) || empty( $type_totals ) || absint( $type_samples ) <= 0 ) {
		return 'N/A';
	}

	arsort( $type_totals );
	$parts = array();
	foreach ( $type_totals as $type_key => $type_total ) {
		$avg_pct = (int) round( (float) $type_total / max( 1, absint( $type_samples ) ) );
		if ( $avg_pct <= 0 ) {
			continue;
		}

		$parts[] = ucwords( str_replace( '_', ' ', sanitize_key( (string) $type_key ) ) ) . ' ' . $avg_pct . '%';
		if ( count( $parts ) >= 4 ) {
			break;
		}
	}

	return ! empty( $parts ) ? implode( ' ', $parts ) : 'N/A';
}

/**
 * Build checkout flow label from checkout-stage counts.
 *
 * @param array<string,int|float> $checkout_flow_counts Checkout stage counts.
 * @return string
 */
function quorlyx_get_behavior_checkout_flow_label( $checkout_flow_counts ) {
	$checkout_flow_counts = is_array( $checkout_flow_counts ) ? $checkout_flow_counts : array();
	$parts                = array();

	if ( absint( $checkout_flow_counts['viewed_cart'] ?? 0 ) > 0 ) {
		$parts[] = 'Viewed Cart: ' . number_format_i18n( (int) $checkout_flow_counts['viewed_cart'] );
	}
	if ( absint( $checkout_flow_counts['abandoned_checkout'] ?? 0 ) > 0 ) {
		$parts[] = 'Abandoned Checkout: ' . number_format_i18n( (int) $checkout_flow_counts['abandoned_checkout'] );
	}

	return ! empty( $parts ) ? implode( ' | ', $parts ) : 'No checkout flow data';
}

/**
 * Build traffic source mix label from source counts.
 *
 * @param array<string,int|float> $traffic_source_totals Traffic source counts.
 * @return string
 */
function quorlyx_get_behavior_traffic_source_mix_label( $traffic_source_totals ) {
	$traffic_source_totals = is_array( $traffic_source_totals ) ? $traffic_source_totals : array();
	$traffic_total         = array_sum( array_map( 'floatval', $traffic_source_totals ) );
	if ( $traffic_total <= 0 ) {
		return 'No source data';
	}

	arsort( $traffic_source_totals );
	$parts = array();
	foreach ( $traffic_source_totals as $source_key => $source_count ) {
		$count = max( 0.0, (float) $source_count );
		if ( $count <= 0 ) {
			continue;
		}

		$pct = (int) round( ( $count / $traffic_total ) * 100 );
		if ( $pct <= 0 ) {
			continue;
		}

		$parts[] = ucfirst( sanitize_key( (string) $source_key ) ) . ' ' . $pct . '%';
		if ( count( $parts ) >= 4 ) {
			break;
		}
	}

	return ! empty( $parts ) ? implode( ' ', $parts ) : 'No source data';
}

/**
 * Build behavior snapshot aggregates for a tracked content item.
 *
 * @param int    $post_id Post ID.
 * @param string $content_key Content key.
 * @return array<string,mixed>
 */
function quorlyx_get_behavior_snapshot_for_content( $post_id, $content_key = '' ) {
	global $wpdb;

	$post_id     = quorlyx_get_canonical_analytics_post_id( absint( $post_id ) );
	$content_key = sanitize_key( (string) $content_key );

	if ( $post_id <= 0 && '' === $content_key ) {
		return array(
			'has_data'             => false,
			'total_profiles'       => 0,
			'closers'              => 0,
			'buyers'               => 0,
			'non_converters'       => 0,
			'started_chat_profiles' => 0,
			'checkout_flow_label'  => 'No checkout flow data',
			'traffic_source_mix_label' => 'No source data',
			'avg_visit_frequency'  => 0,
			'avg_pages_viewed'     => 0,
			'avg_dwell_time'       => 0,
			'avg_scroll_depth'     => 0,
			'category_breakdown_label' => 'N/A',
			'category_breakdown_raw' => '{}',
			'first_page_type_label' => 'N/A',
			'last_page_type_label' => 'N/A',
			'first_page_type_counts' => array(),
			'last_page_type_counts' => array(),
			'first_source_raw'    => '',
			'last_page_raw'       => '',
			'last_page_label'      => 'N/A',
			'top_pattern'          => 'unknown',
			'top_pattern_label'    => 'Unknown',
			'pattern_counts'       => array(),
			'pattern_rows'         => array(),
		);
	}

	$table_name = quorlyx_get_behavior_engine_table_name();
	$behavior_settings = quorlyx_get_behavior_pattern_settings();
	$use_db_processing = quorlyx_should_use_behavior_db_processing( $behavior_settings );
	$detail_rows = array();

	if ( $use_db_processing ) {
		$db_latest_rows = quorlyx_get_behavior_engine_latest_profile_rows_from_db( $post_id, $content_key );
		if ( is_array( $db_latest_rows ) ) {
			$detail_rows = $db_latest_rows;
		} else {
			$use_db_processing = false;
		}
	}

	if ( ! $use_db_processing ) {
		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Aggregate per-pattern metrics, breakdown, and last-page details for behavior insights table.
		// phpcs:disable WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Table name comes from trusted helper with wpdb prefix.
		$detail_rows = $wpdb->get_results(
			$wpdb->prepare(
				"SELECT id, profile_hash, pattern_tag, conversion_status, started_chat, visit_frequency, pages_viewed, dwell_time_avg, cart_activity, scroll_depth, category_breakdown, last_post_id, last_content_key, abandonment_stage, traffic_source, visited_path FROM {$table_name} WHERE source_post_id = %d AND content_key = %s ORDER BY updated_at DESC, id DESC",
				$post_id,
				$content_key
			),
			ARRAY_A
		);
		// phpcs:enable WordPress.DB.PreparedSQL.InterpolatedNotPrepared

		if ( null === $detail_rows && '' !== (string) $wpdb->last_error ) {
			quorlyx_behavior_log_event_once(
				'behavior_snapshot_detail_query_failed|' . $post_id . '|' . $content_key,
				'error',
				'Behavior snapshot detail query failed',
				array(
					'component'      => 'behavior_engine',
					'operation'      => 'snapshot_aggregate',
					'phase'          => 'detail_query',
					'source_post_id' => $post_id,
					'content_key'    => $content_key,
					'db_error'       => sanitize_text_field( (string) $wpdb->last_error ),
				),
				1800
			);

			$detail_rows = array();
		}
	}

	$latest_detail_rows = quorlyx_merge_behavior_snapshot_rows( $detail_rows, $behavior_settings, $post_id, $content_key );

	$total_profiles = count( $latest_detail_rows );
	if ( $total_profiles <= 0 ) {
		return array(
			'has_data'             => false,
			'total_profiles'       => 0,
			'closers'              => 0,
			'buyers'               => 0,
			'non_converters'       => 0,
			'started_chat_profiles' => 0,
			'checkout_flow_label'  => 'No checkout flow data',
			'traffic_source_mix_label' => 'No source data',
			'avg_visit_frequency'  => 0,
			'avg_pages_viewed'     => 0,
			'avg_dwell_time'       => 0,
			'avg_scroll_depth'     => 0,
			'category_breakdown_label' => 'N/A',
			'category_breakdown_raw' => '{}',
			'first_page_type_label' => 'N/A',
			'last_page_type_label' => 'N/A',
			'first_page_type_counts' => array(),
			'last_page_type_counts' => array(),
			'first_source_raw'    => '',
			'last_page_raw'       => '',
			'last_page_label'      => 'N/A',
			'top_pattern'          => 'unknown',
			'top_pattern_label'    => 'Unknown',
			'pattern_counts'       => array(),
			'pattern_rows'         => array(),
		);
	}

	$type_totals          = array();
	$type_samples         = 0;
	$summary_closers      = 0;
	$summary_non_converters = 0;
	$summary_started_chat = 0;
	$summary_sum_visit_frequency = 0.0;
	$summary_sum_pages_viewed    = 0.0;
	$summary_sum_dwell_time      = 0.0;
	$summary_sum_scroll_depth    = 0.0;
	$entry_type_counts    = array();
	$last_type_counts     = array();
	$last_post_id_raw     = 0;
	$last_content_key_raw = '';
	$latest_breakdown_raw = '{}';
	$entry_type_key       = quorlyx_get_behavior_content_type_key( $post_id, $content_key );
	$checkout_flow_counts = array(
		'viewed_cart'        => 0,
		'abandoned_checkout' => 0,
	);
	$traffic_source_totals = array(
		'direct'   => 0,
		'search'   => 0,
		'social'   => 0,
		'paid'     => 0,
		'email'    => 0,
		'referral' => 0,
	);
	$pattern_aggregates   = array();

	foreach ( $latest_detail_rows as $detail_row ) {
		$conversion_status = quorlyx_normalize_behavior_conversion_status( $detail_row['conversion_status'] ?? 'unknown' );
		$started_chat      = absint( $detail_row['started_chat'] ?? 0 ) > 0;
		$abandonment_stage = sanitize_key( (string) ( $detail_row['abandonment_stage'] ?? '' ) );
		$pattern_tag = quorlyx_normalize_behavior_pattern_key( (string) ( $detail_row['pattern_tag'] ?? 'unknown' ) );

		if ( quorlyx_is_closer_behavior_pattern( $pattern_tag ) && 'closer' !== $conversion_status ) {
			$pattern_tag = quorlyx_classify_behavior_pattern_legacy(
				absint( $detail_row['visit_frequency'] ?? 0 ),
				absint( $detail_row['pages_viewed'] ?? 0 ),
				absint( $detail_row['dwell_time_avg'] ?? 0 ),
				absint( $detail_row['cart_activity'] ?? 0 ),
				absint( $detail_row['scroll_depth'] ?? 0 ),
				$conversion_status,
				null,
				array(
					'started_chat'      => $started_chat,
					'abandonment_stage' => $abandonment_stage,
				)
			);
			$pattern_tag = quorlyx_normalize_behavior_pattern_key( $pattern_tag );
		}

		if ( ! isset( $pattern_aggregates[ $pattern_tag ] ) ) {
			$pattern_aggregates[ $pattern_tag ] = array(
				'total_profiles'       => 0,
				'closers'              => 0,
				'non_converters'       => 0,
				'started_chat_profiles' => 0,
				'sum_visit_frequency'  => 0.0,
				'sum_pages_viewed'     => 0.0,
				'sum_dwell_time'       => 0.0,
				'sum_scroll_depth'     => 0.0,
				'type_totals'          => array(),
				'type_samples'         => 0,
				'entry_type_counts'    => array(),
				'last_type_counts'     => array(),
				'checkout_flow_counts' => array(
					'viewed_cart'        => 0,
					'abandoned_checkout' => 0,
				),
				'traffic_source_totals' => array(
					'direct'   => 0,
					'search'   => 0,
					'social'   => 0,
					'paid'     => 0,
					'email'    => 0,
					'referral' => 0,
				),
			);
		}

		++$pattern_aggregates[ $pattern_tag ]['total_profiles'];

		if ( 'closer' === $conversion_status ) {
			++$summary_closers;
			++$pattern_aggregates[ $pattern_tag ]['closers'];
		} elseif ( 'non_converter' === $conversion_status ) {
			++$summary_non_converters;
			++$pattern_aggregates[ $pattern_tag ]['non_converters'];
		}

		if ( $started_chat ) {
			++$summary_started_chat;
			++$pattern_aggregates[ $pattern_tag ]['started_chat_profiles'];
		}

		$visit_frequency_value = (float) ( $detail_row['visit_frequency'] ?? 0 );
		$pages_viewed_value    = (float) ( $detail_row['pages_viewed'] ?? 0 );
		$dwell_time_value      = (float) ( $detail_row['dwell_time_avg'] ?? 0 );
		$scroll_depth_value    = (float) ( $detail_row['scroll_depth'] ?? 0 );

		$summary_sum_visit_frequency += $visit_frequency_value;
		$summary_sum_pages_viewed    += $pages_viewed_value;
		$summary_sum_dwell_time      += $dwell_time_value;
		$summary_sum_scroll_depth    += $scroll_depth_value;

		$pattern_aggregates[ $pattern_tag ]['sum_visit_frequency'] += $visit_frequency_value;
		$pattern_aggregates[ $pattern_tag ]['sum_pages_viewed']    += $pages_viewed_value;
		$pattern_aggregates[ $pattern_tag ]['sum_dwell_time']      += $dwell_time_value;
		$pattern_aggregates[ $pattern_tag ]['sum_scroll_depth']    += $scroll_depth_value;

		$entry_type_counts[ $entry_type_key ] = (int) ( $entry_type_counts[ $entry_type_key ] ?? 0 ) + 1;
		$pattern_aggregates[ $pattern_tag ]['entry_type_counts'][ $entry_type_key ] = (int) ( $pattern_aggregates[ $pattern_tag ]['entry_type_counts'][ $entry_type_key ] ?? 0 ) + 1;

		$last_type_key = quorlyx_get_behavior_content_type_key(
			quorlyx_get_canonical_analytics_post_id( absint( $detail_row['last_post_id'] ?? 0 ) ),
			sanitize_key( (string) ( $detail_row['last_content_key'] ?? '' ) )
		);
		$last_type_counts[ $last_type_key ] = (int) ( $last_type_counts[ $last_type_key ] ?? 0 ) + 1;
		$pattern_aggregates[ $pattern_tag ]['last_type_counts'][ $last_type_key ] = (int) ( $pattern_aggregates[ $pattern_tag ]['last_type_counts'][ $last_type_key ] ?? 0 ) + 1;

		if ( isset( $checkout_flow_counts[ $abandonment_stage ] ) ) {
			++$checkout_flow_counts[ $abandonment_stage ];
		}
		if ( isset( $pattern_aggregates[ $pattern_tag ]['checkout_flow_counts'][ $abandonment_stage ] ) ) {
			++$pattern_aggregates[ $pattern_tag ]['checkout_flow_counts'][ $abandonment_stage ];
		}

		$traffic_source = quorlyx_normalize_traffic_source_segment( (string) ( $detail_row['traffic_source'] ?? 'direct' ) );
		if ( isset( $traffic_source_totals[ $traffic_source ] ) ) {
			++$traffic_source_totals[ $traffic_source ];
		}
		if ( isset( $pattern_aggregates[ $pattern_tag ]['traffic_source_totals'][ $traffic_source ] ) ) {
			++$pattern_aggregates[ $pattern_tag ]['traffic_source_totals'][ $traffic_source ];
		}

		$breakdown_raw = sanitize_text_field( (string) ( $detail_row['category_breakdown'] ?? '' ) );
		if ( '{}' === $latest_breakdown_raw || '' === $latest_breakdown_raw ) {
			$latest_breakdown_raw = '' !== $breakdown_raw ? $breakdown_raw : '{}';
			$last_post_id_raw     = quorlyx_get_canonical_analytics_post_id( absint( $detail_row['last_post_id'] ?? 0 ) );
			$last_content_key_raw = sanitize_key( (string) ( $detail_row['last_content_key'] ?? '' ) );
		}

		if ( '' !== $breakdown_raw ) {
			$decoded = json_decode( $breakdown_raw, true );
			if ( is_array( $decoded ) ) {
				$used_sample         = false;
				$pattern_used_sample = false;
				foreach ( $decoded as $type_key => $pct_value ) {
					$type_key = sanitize_key( (string) $type_key );
					$pct      = max( 0, min( 100, (float) $pct_value ) );
					if ( '' === $type_key || $pct <= 0 ) {
						continue;
					}

					$type_totals[ $type_key ] = (float) ( $type_totals[ $type_key ] ?? 0 ) + $pct;
					$pattern_aggregates[ $pattern_tag ]['type_totals'][ $type_key ] = (float) ( $pattern_aggregates[ $pattern_tag ]['type_totals'][ $type_key ] ?? 0 ) + $pct;
					$used_sample              = true;
					$pattern_used_sample      = true;
				}

				if ( $used_sample ) {
					++$type_samples;
				}
				if ( $pattern_used_sample ) {
					++$pattern_aggregates[ $pattern_tag ]['type_samples'];
				}
			}
		}
	}

	$pattern_counts = array();
	$top_pattern    = 'unknown';
	$top_count      = 0;

	foreach ( $pattern_aggregates as $pattern_key => $pattern_aggregate ) {
		$count = absint( $pattern_aggregate['total_profiles'] ?? 0 );
		if ( $count <= 0 ) {
			continue;
		}

		$pattern_counts[ $pattern_key ] = $count;
		if ( $count > $top_count ) {
			$top_count   = $count;
			$top_pattern = $pattern_key;
		}
	}

	arsort( $pattern_counts );

	$category_breakdown_label = quorlyx_get_behavior_category_breakdown_label( $type_totals, $type_samples );

	$closers = absint( $summary_closers );
	$first_source_raw = $post_id > 0 ? 'post:' . (string) $post_id : 'key:' . $content_key;
	$last_page_raw    = $last_post_id_raw > 0 ? 'post:' . (string) $last_post_id_raw : ( '' !== $last_content_key_raw ? 'key:' . $last_content_key_raw : 'none' );
	$checkout_flow_label    = quorlyx_get_behavior_checkout_flow_label( $checkout_flow_counts );
	$traffic_source_mix_label = quorlyx_get_behavior_traffic_source_mix_label( $traffic_source_totals );
	$first_page_type_label  = quorlyx_get_behavior_type_mix_label( $entry_type_counts );
	$last_page_type_label   = quorlyx_get_behavior_type_mix_label( $last_type_counts );

	$pattern_rows_data = array();
	$ordered_pattern_tags = array_keys( $pattern_counts );
	foreach ( array_keys( $pattern_aggregates ) as $pattern_tag ) {
		if ( ! in_array( $pattern_tag, $ordered_pattern_tags, true ) ) {
			$ordered_pattern_tags[] = $pattern_tag;
		}
	}

	foreach ( $ordered_pattern_tags as $pattern_tag ) {
		if ( ! isset( $pattern_aggregates[ $pattern_tag ] ) ) {
			continue;
		}

		$pattern_aggregate = is_array( $pattern_aggregates[ $pattern_tag ] ) ? $pattern_aggregates[ $pattern_tag ] : array();
		$pattern_total     = max( 1, absint( $pattern_aggregate['total_profiles'] ?? 0 ) );

		$pattern_type_totals              = is_array( $pattern_aggregate['type_totals'] ?? null ) ? $pattern_aggregate['type_totals'] : array();
		$pattern_type_samples             = absint( $pattern_aggregate['type_samples'] ?? 0 );
		$pattern_category_breakdown_label = quorlyx_get_behavior_category_breakdown_label( $pattern_type_totals, $pattern_type_samples );
		$pattern_checkout_counts = is_array( $pattern_aggregate['checkout_flow_counts'] ?? null ) ? $pattern_aggregate['checkout_flow_counts'] : array();
		$pattern_checkout_flow_label = quorlyx_get_behavior_checkout_flow_label( $pattern_checkout_counts );
		$pattern_traffic_totals = is_array( $pattern_aggregate['traffic_source_totals'] ?? null ) ? $pattern_aggregate['traffic_source_totals'] : array();
		$pattern_traffic_source_mix_label = quorlyx_get_behavior_traffic_source_mix_label( $pattern_traffic_totals );
		$pattern_entry_type_counts        = is_array( $pattern_aggregate['entry_type_counts'] ?? null ) ? $pattern_aggregate['entry_type_counts'] : array();
		$pattern_last_type_counts         = is_array( $pattern_aggregate['last_type_counts'] ?? null ) ? $pattern_aggregate['last_type_counts'] : array();
		$pattern_first_page_type_label    = quorlyx_get_behavior_type_mix_label( $pattern_entry_type_counts );
		$pattern_last_page_type_label     = quorlyx_get_behavior_type_mix_label( $pattern_last_type_counts );

		$pattern_rows_data[] = array(
			'pattern_tag'          => $pattern_tag,
			'pattern_label'        => quorlyx_get_behavior_pattern_label( $pattern_tag ),
			'total_profiles'       => absint( $pattern_aggregate['total_profiles'] ?? 0 ),
			'share_pct'            => $total_profiles > 0 ? (int) round( ( (int) ( $pattern_aggregate['total_profiles'] ?? 0 ) / $total_profiles ) * 100 ) : 0,
			'closers'              => absint( $pattern_aggregate['closers'] ?? 0 ),
			'non_converters'       => absint( $pattern_aggregate['non_converters'] ?? 0 ),
			'started_chat_profiles' => absint( $pattern_aggregate['started_chat_profiles'] ?? 0 ),
			'checkout_flow_label'  => $pattern_checkout_flow_label,
			'traffic_source_mix_label' => $pattern_traffic_source_mix_label,
			'avg_visit_frequency'  => (int) round( (float) ( $pattern_aggregate['sum_visit_frequency'] ?? 0 ) / $pattern_total ),
			'avg_pages_viewed'     => (int) round( (float) ( $pattern_aggregate['sum_pages_viewed'] ?? 0 ) / $pattern_total ),
			'avg_dwell_time'       => (int) round( (float) ( $pattern_aggregate['sum_dwell_time'] ?? 0 ) / $pattern_total ),
			'avg_scroll_depth'     => (int) round( (float) ( $pattern_aggregate['sum_scroll_depth'] ?? 0 ) / $pattern_total ),
			'category_breakdown_label' => $pattern_category_breakdown_label,
			'first_page_type_label' => $pattern_first_page_type_label,
			'last_page_type_label'  => $pattern_last_page_type_label,
			'entry_type_counts'     => $pattern_entry_type_counts,
			'last_type_counts'      => $pattern_last_type_counts,
			'type_totals'           => $pattern_type_totals,
			'type_samples'          => $pattern_type_samples,
			'checkout_flow_counts'  => $pattern_checkout_counts,
			'traffic_source_totals' => $pattern_traffic_totals,
			'last_page_label'       => $pattern_last_page_type_label,
		);
	}

	return array(
		'has_data'             => true,
		'total_profiles'       => $total_profiles,
		'closers'              => $closers,
		'buyers'               => $closers,
		'non_converters'       => absint( $summary_non_converters ),
		'started_chat_profiles' => absint( $summary_started_chat ),
		'checkout_flow_label'  => $checkout_flow_label,
		'traffic_source_mix_label' => $traffic_source_mix_label,
		'avg_visit_frequency'  => (int) round( $summary_sum_visit_frequency / max( 1, $total_profiles ) ),
		'avg_pages_viewed'     => (int) round( $summary_sum_pages_viewed / max( 1, $total_profiles ) ),
		'avg_dwell_time'       => (int) round( $summary_sum_dwell_time / max( 1, $total_profiles ) ),
		'avg_scroll_depth'     => (int) round( $summary_sum_scroll_depth / max( 1, $total_profiles ) ),
		'category_breakdown_label' => $category_breakdown_label,
		'category_breakdown_raw' => $latest_breakdown_raw,
		'first_page_type_label' => $first_page_type_label,
		'last_page_type_label'  => $last_page_type_label,
		'first_page_type_counts' => $entry_type_counts,
		'last_page_type_counts'  => $last_type_counts,
		'first_source_raw'    => $first_source_raw,
		'last_page_raw'       => $last_page_raw,
		'last_page_label'      => $last_page_type_label,
		'top_pattern'          => $top_pattern,
		'top_pattern_label'    => quorlyx_get_behavior_pattern_label( $top_pattern ),
		'pattern_counts'       => $pattern_counts,
		'pattern_rows'         => $pattern_rows_data,
	);
}

/**
 * Consolidate Behavior Snapshot rows into a pattern-centric table model.
 *
 * @param array<int,array<string,mixed>> $insight_rows Insight dataset rows.
 * @return array<int,array<string,mixed>>
 */
function quorlyx_get_behavior_pattern_display_rows( $insight_rows ) {
	$pattern_totals       = array();
	$total_profile_volume = 0;

	foreach ( (array) $insight_rows as $row ) {
		$behavior     = is_array( $row['behavior_snapshot'] ?? null ) ? $row['behavior_snapshot'] : array();
		$pattern_rows = is_array( $behavior['pattern_rows'] ?? null ) ? $behavior['pattern_rows'] : array();

		if ( empty( $pattern_rows ) ) {
			$fallback_pattern_tag = quorlyx_normalize_behavior_pattern_key( (string) ( $behavior['top_pattern'] ?? ( $row['behavior_primary_pattern'] ?? 'unknown' ) ) );
			$pattern_rows[]       = array(
				'pattern_tag'           => $fallback_pattern_tag,
				'total_profiles'        => absint( $behavior['total_profiles'] ?? 0 ),
				'closers'               => absint( $behavior['closers'] ?? ( $behavior['buyers'] ?? 0 ) ),
				'non_converters'        => absint( $behavior['non_converters'] ?? 0 ),
				'started_chat_profiles' => absint( $behavior['started_chat_profiles'] ?? 0 ),
				'avg_visit_frequency'   => (int) ( $behavior['avg_visit_frequency'] ?? 0 ),
				'avg_pages_viewed'      => (int) ( $behavior['avg_pages_viewed'] ?? 0 ),
				'avg_dwell_time'        => (int) ( $behavior['avg_dwell_time'] ?? 0 ),
				'avg_scroll_depth'      => (int) ( $behavior['avg_scroll_depth'] ?? 0 ),
				'entry_type_counts'     => is_array( $behavior['first_page_type_counts'] ?? null ) ? $behavior['first_page_type_counts'] : array(),
				'last_type_counts'      => is_array( $behavior['last_page_type_counts'] ?? null ) ? $behavior['last_page_type_counts'] : array(),
				'type_totals'           => array(),
				'type_samples'          => 0,
				'checkout_flow_counts'  => array(),
				'traffic_source_totals' => array(),
			);
		}

		foreach ( $pattern_rows as $pattern_row ) {
			$pattern_tag   = quorlyx_normalize_behavior_pattern_key( (string) ( $pattern_row['pattern_tag'] ?? 'unknown' ) );
			$profile_count = absint( $pattern_row['total_profiles'] ?? 0 );

			if ( $profile_count <= 0 ) {
				continue;
			}

			if ( ! isset( $pattern_totals[ $pattern_tag ] ) ) {
				$pattern_totals[ $pattern_tag ] = array(
					'total_profiles'        => 0,
					'closers'               => 0,
					'non_converters'        => 0,
					'started_chat_profiles' => 0,
					'sum_visit_frequency'   => 0.0,
					'sum_pages_viewed'      => 0.0,
					'sum_dwell_time'        => 0.0,
					'sum_scroll_depth'      => 0.0,
					'entry_type_counts'     => array(),
					'last_type_counts'      => array(),
					'type_totals'           => array(),
					'type_samples'          => 0,
					'checkout_flow_counts'  => array(
						'viewed_cart'        => 0,
						'abandoned_checkout' => 0,
					),
					'traffic_source_totals' => array(
						'direct'   => 0,
						'search'   => 0,
						'social'   => 0,
						'paid'     => 0,
						'email'    => 0,
						'referral' => 0,
					),
				);
			}

			$pattern_totals[ $pattern_tag ]['total_profiles'] += $profile_count;
			$total_profile_volume                             += $profile_count;

			$pattern_totals[ $pattern_tag ]['closers']               += absint( $pattern_row['closers'] ?? 0 );
			$pattern_totals[ $pattern_tag ]['non_converters']        += absint( $pattern_row['non_converters'] ?? 0 );
			$pattern_totals[ $pattern_tag ]['started_chat_profiles'] += absint( $pattern_row['started_chat_profiles'] ?? 0 );

			$pattern_totals[ $pattern_tag ]['sum_visit_frequency'] += (float) ( $pattern_row['avg_visit_frequency'] ?? 0 ) * $profile_count;
			$pattern_totals[ $pattern_tag ]['sum_pages_viewed']    += (float) ( $pattern_row['avg_pages_viewed'] ?? 0 ) * $profile_count;
			$pattern_totals[ $pattern_tag ]['sum_dwell_time']      += (float) ( $pattern_row['avg_dwell_time'] ?? 0 ) * $profile_count;
			$pattern_totals[ $pattern_tag ]['sum_scroll_depth']    += (float) ( $pattern_row['avg_scroll_depth'] ?? 0 ) * $profile_count;

			$entry_type_counts = is_array( $pattern_row['entry_type_counts'] ?? null ) ? $pattern_row['entry_type_counts'] : array();
			foreach ( $entry_type_counts as $type_key => $type_count ) {
				$normalized_type = sanitize_key( (string) $type_key );
				$count_value     = max( 0, absint( $type_count ) );
				if ( '' === $normalized_type || $count_value <= 0 ) {
					continue;
				}

				$pattern_totals[ $pattern_tag ]['entry_type_counts'][ $normalized_type ] = (int) ( $pattern_totals[ $pattern_tag ]['entry_type_counts'][ $normalized_type ] ?? 0 ) + $count_value;
			}

			$last_type_counts = is_array( $pattern_row['last_type_counts'] ?? null ) ? $pattern_row['last_type_counts'] : array();
			foreach ( $last_type_counts as $type_key => $type_count ) {
				$normalized_type = sanitize_key( (string) $type_key );
				$count_value     = max( 0, absint( $type_count ) );
				if ( '' === $normalized_type || $count_value <= 0 ) {
					continue;
				}

				$pattern_totals[ $pattern_tag ]['last_type_counts'][ $normalized_type ] = (int) ( $pattern_totals[ $pattern_tag ]['last_type_counts'][ $normalized_type ] ?? 0 ) + $count_value;
			}

			$type_totals = is_array( $pattern_row['type_totals'] ?? null ) ? $pattern_row['type_totals'] : array();
			foreach ( $type_totals as $type_key => $type_total ) {
				$normalized_type = sanitize_key( (string) $type_key );
				$total_value     = max( 0.0, (float) $type_total );
				if ( '' === $normalized_type || $total_value <= 0 ) {
					continue;
				}

				$pattern_totals[ $pattern_tag ]['type_totals'][ $normalized_type ] = (float) ( $pattern_totals[ $pattern_tag ]['type_totals'][ $normalized_type ] ?? 0 ) + $total_value;
			}

			$type_samples = absint( $pattern_row['type_samples'] ?? 0 );
			if ( $type_samples <= 0 && ! empty( $type_totals ) ) {
				$type_samples = 1;
			}
			$pattern_totals[ $pattern_tag ]['type_samples'] += $type_samples;

			$checkout_flow_counts = is_array( $pattern_row['checkout_flow_counts'] ?? null ) ? $pattern_row['checkout_flow_counts'] : array();
			foreach ( $checkout_flow_counts as $stage_key => $stage_count ) {
				$stage_key   = sanitize_key( (string) $stage_key );
				$count_value = max( 0, absint( $stage_count ) );
				if ( ! isset( $pattern_totals[ $pattern_tag ]['checkout_flow_counts'][ $stage_key ] ) || $count_value <= 0 ) {
					continue;
				}

				$pattern_totals[ $pattern_tag ]['checkout_flow_counts'][ $stage_key ] += $count_value;
			}

			$traffic_source_totals = is_array( $pattern_row['traffic_source_totals'] ?? null ) ? $pattern_row['traffic_source_totals'] : array();
			foreach ( $traffic_source_totals as $source_key => $source_count ) {
				$source_key  = sanitize_key( (string) $source_key );
				$count_value = max( 0, absint( $source_count ) );
				if ( ! isset( $pattern_totals[ $pattern_tag ]['traffic_source_totals'][ $source_key ] ) || $count_value <= 0 ) {
					continue;
				}

				$pattern_totals[ $pattern_tag ]['traffic_source_totals'][ $source_key ] += $count_value;
			}
		}
	}

	if ( empty( $pattern_totals ) || $total_profile_volume <= 0 ) {
		return array();
	}

	uasort(
		$pattern_totals,
		static function ( $a, $b ) {
			return absint( $b['total_profiles'] ?? 0 ) <=> absint( $a['total_profiles'] ?? 0 );
		}
	);

	$display_rows = array();
	foreach ( $pattern_totals as $pattern_tag => $pattern_total ) {
		$profiles = max( 1, absint( $pattern_total['total_profiles'] ?? 0 ) );

		$display_rows[] = array(
			'pattern_tag'             => $pattern_tag,
			'pattern_label'           => quorlyx_get_behavior_pattern_label( $pattern_tag ),
			'total_profiles'          => absint( $pattern_total['total_profiles'] ?? 0 ),
			'share_pct'               => (int) round( ( absint( $pattern_total['total_profiles'] ?? 0 ) / $total_profile_volume ) * 100 ),
			'closers'                 => absint( $pattern_total['closers'] ?? 0 ),
			'non_converters'          => absint( $pattern_total['non_converters'] ?? 0 ),
			'started_chat_profiles'   => absint( $pattern_total['started_chat_profiles'] ?? 0 ),
			'checkout_flow_label'     => quorlyx_get_behavior_checkout_flow_label( $pattern_total['checkout_flow_counts'] ?? array() ),
			'traffic_source_mix_label' => quorlyx_get_behavior_traffic_source_mix_label( $pattern_total['traffic_source_totals'] ?? array() ),
			'avg_visit_frequency'     => (int) round( (float) ( $pattern_total['sum_visit_frequency'] ?? 0 ) / $profiles ),
			'avg_pages_viewed'        => (int) round( (float) ( $pattern_total['sum_pages_viewed'] ?? 0 ) / $profiles ),
			'avg_dwell_time'          => (int) round( (float) ( $pattern_total['sum_dwell_time'] ?? 0 ) / $profiles ),
			'avg_scroll_depth'        => (int) round( (float) ( $pattern_total['sum_scroll_depth'] ?? 0 ) / $profiles ),
			'category_breakdown_label' => quorlyx_get_behavior_category_breakdown_label( $pattern_total['type_totals'] ?? array(), absint( $pattern_total['type_samples'] ?? 0 ) ),
			'first_page_type_label'   => quorlyx_get_behavior_type_mix_label( $pattern_total['entry_type_counts'] ?? array() ),
			'last_page_type_label'    => quorlyx_get_behavior_type_mix_label( $pattern_total['last_type_counts'] ?? array() ),
		);
	}

	return $display_rows;
}

/**
 * Build a concise behavior context block for AI prompts.
 *
 * @param int    $post_id Post ID.
 * @param string $content_key Content key.
 * @return string
 */
function quorlyx_get_behavior_prompt_context( $post_id, $content_key = '' ) {
	$snapshot = quorlyx_get_behavior_snapshot_for_content( $post_id, $content_key );
	if ( empty( $snapshot['has_data'] ) ) {
		return '';
	}

	$lines = array(
		'Behavior profile summary for this content:',
		'- Total profiles: ' . number_format_i18n( (int) ( $snapshot['total_profiles'] ?? 0 ) ),
		'- Top pattern: ' . sanitize_text_field( (string) ( $snapshot['top_pattern_label'] ?? 'Unknown' ) ),
		'- Closers: ' . number_format_i18n( (int) ( $snapshot['closers'] ?? ( $snapshot['buyers'] ?? 0 ) ) ),
		'- Non-converters: ' . number_format_i18n( (int) ( $snapshot['non_converters'] ?? 0 ) ),
		'- Avg visit frequency: ' . number_format_i18n( (int) ( $snapshot['avg_visit_frequency'] ?? 0 ) ),
		'- Avg pages viewed: ' . number_format_i18n( (int) ( $snapshot['avg_pages_viewed'] ?? 0 ) ),
		'- Avg dwell time (seconds): ' . number_format_i18n( (int) ( $snapshot['avg_dwell_time'] ?? 0 ) ),
		'- Avg scroll depth (%): ' . number_format_i18n( (int) ( $snapshot['avg_scroll_depth'] ?? 0 ) ),
	);

	return implode( "\n", $lines );
}

add_action( 'woocommerce_add_to_cart', 'quorlyx_track_woocommerce_add_to_cart', 10, 6 );
/**
 * Increment add-to-cart analytics for attributed content sessions.
 *
 * @param string $cart_item_key Cart item key.
 * @param int    $product_id    Product ID.
 * @param int    $quantity      Quantity added.
 * @param int    $variation_id  Variation ID.
 * @param array  $variation     Variation attributes.
 * @param array  $cart_item_data Additional cart item data.
 * @return void
 */
function quorlyx_track_woocommerce_add_to_cart( $cart_item_key, $product_id, $quantity, $variation_id, $variation, $cart_item_data ) { // phpcs:ignore Generic.CodeAnalysis.UnusedFunctionParameter.FoundAfterLastUsed -- WooCommerce action signature requires all parameters.
	if ( ! class_exists( 'WooCommerce' ) || is_admin() ) {
		return;
	}

	if ( ! quorlyx_content_insights_is_enabled() ) {
		return;
	}

	// AJAX adds are already tracked in frontend analytics via the added_to_cart event.
	if ( function_exists( 'wp_doing_ajax' ) && wp_doing_ajax() ) {
		return;
	}

	$source      = quorlyx_get_attribution_source_from_request();
	$post_id     = absint( $source['post_id'] ?? 0 );
	$content_key = sanitize_key( $source['content_key'] ?? '' );

	if ( $post_id <= 0 && '' === $content_key ) {
		return;
	}

	quorlyx_increment_analytics_metric( $post_id, '_quorlyx_analytics_add_to_cart', 1, $content_key );
}

/**
 * Track checkout visits once per attributed source per browser session.
 *
 * @return void
 */
function quorlyx_maybe_track_checkout_visit_from_attribution() {
	if ( is_admin() || ! class_exists( 'WooCommerce' ) || ! function_exists( 'is_checkout' ) ) {
		return;
	}

	if ( ! quorlyx_content_insights_is_enabled() ) {
		return;
	}

	if ( ! is_checkout() ) {
		return;
	}

	if ( function_exists( 'is_order_received_page' ) && is_order_received_page() ) {
		return;
	}

	$source      = quorlyx_get_attribution_source_from_request();
	$post_id     = absint( $source['post_id'] ?? 0 );
	$content_key = sanitize_key( $source['content_key'] ?? '' );

	if ( $post_id <= 0 && '' === $content_key ) {
		return;
	}

	$source_token = $post_id > 0 ? 'p_' . $post_id : 'k_' . $content_key;
	$cookie_name  = 'qu_ci_ck_' . substr( md5( $source_token ), 0, 12 );

	if ( ! empty( $_COOKIE[ $cookie_name ] ) ) {
		return;
	}

	quorlyx_increment_analytics_metric( $post_id, '_quorlyx_analytics_checkout_visits', 1, $content_key );

	if ( ! headers_sent() ) {
		setcookie( $cookie_name, '1', 0, '/' );
	}
	$_COOKIE[ $cookie_name ] = '1';
}

/**
 * Build prioritized optimization recommendations for an insight row.
 *
 * @param array<string,mixed> $row      Insight row data.
 * @param array<string,mixed> $settings Content Insights settings.
 * @return array<int,array<string,string>>
 */
function quorlyx_get_content_insights_recommendations( $row, $settings ) {
	$settings         = is_array( $settings ) ? $settings : array();
	$thresholds       = quorlyx_get_content_insights_thresholds();
	$recommendations  = array();
	$seo_suggestions  = quorlyx_get_content_insight_seo_recommendations( $row, $thresholds );
	$min_views        = $thresholds['min_views'];
	$min_avg_time     = $thresholds['min_avg_time'];
	$min_conversion   = $thresholds['min_conversion_rate'];
	$min_scroll_depth = $thresholds['min_scroll_depth'];
	$scroll_depth     = (int) ( $row['scroll_depth'] ?? 0 );
	$views            = (int) ( $row['views'] ?? 0 );
	$avg_time         = (int) ( $row['avg_time'] ?? 0 );
	$conversions      = (int) ( $row['conversions'] ?? 0 );
	$add_to_cart      = (int) ( $row['add_to_cart'] ?? 0 );
	$checkout_visits  = (int) ( $row['checkout_visits'] ?? 0 );
	$checkout_success = (int) ( $row['checkout_success'] ?? 0 );
	$conversion_rate  = (float) ( $row['conversion_rate'] ?? 0 );

	if ( $views < $min_views ) {
		$recommendations[] = array(
			'type'    => 'observe',
			'label'   => 'Collect more traffic first',
			'details' => sprintf( 'Wait until this page reaches at least %d views before changing triggers or chat behavior.', $min_views ),
		);
		return array_slice( array_merge( $seo_suggestions, $recommendations ), 0, 3 );
	}

	if ( $scroll_depth >= $min_scroll_depth && $conversion_rate < $min_conversion && 0 === $add_to_cart ) {
		$recommendations[] = array(
			'type'    => 'trigger',
			'label'   => 'Add a scroll-depth trigger',
			'details' => sprintf( 'Readers finish the page but do not act. Fire a scroll trigger around %d%% with a direct CTA or offer.', max( 70, min( 95, $scroll_depth - 5 ) ) ),
		);
	}

	if ( $avg_time >= $min_avg_time && $scroll_depth < ( $min_scroll_depth - 15 ) ) {
		$delay_seconds     = max( 10, min( 60, (int) round( $avg_time * 0.6 ) ) );
		$recommendations[] = array(
			'type'    => 'chat_setting',
			'label'   => 'Use a time-on-page opener',
			'details' => sprintf( 'Visitors stay but do not reach the end. Trigger chat after about %d seconds with a summary or navigation help.', $delay_seconds ),
		);
	}

	if ( $add_to_cart > 0 && 0 === $checkout_visits ) {
		$recommendations[] = array(
			'type'    => 'checkout',
			'label'   => 'Improve cart to checkout flow',
			'details' => 'Users add items to cart but do not reach checkout. Simplify handoff to checkout and add reassurance before cart exit.',
		);
	}

	if ( $checkout_visits > 0 && 0 === $checkout_success ) {
		$recommendations[] = array(
			'type'    => 'checkout',
			'label'   => 'Reduce checkout drop-off',
			'details' => 'Visitors are reaching checkout but not completing. Review shipping clarity, trust signals, and payment friction.',
		);
	}

	if ( $add_to_cart > 0 && 0 === $conversions ) {
		$recommendations[] = array(
			'type'    => 'trigger',
			'label'   => 'Add exit-intent reassurance',
			'details' => 'Visitors show buying intent but do not convert. Use exit-intent or cart-focused reassurance with shipping, pricing, or trust answers.',
		);
	}

	if ( $checkout_success > 0 ) {
		$recommendations[] = array(
			'type'    => 'scale',
			'label'   => 'Checkout flow is working',
			'details' => 'This item is producing completed checkouts. Reuse this page structure and message pattern for similar content.',
		);
	}

	if ( $views >= ( $min_views * 2 ) && $avg_time < max( 10, (int) floor( $min_avg_time / 2 ) ) ) {
		$recommendations[] = array(
			'type'    => 'chat_setting',
			'label'   => 'Shorten the first message',
			'details' => 'Traffic is healthy but attention is shallow. Reduce the opening message length and focus on one clear next step.',
		);
	}

	if ( $conversion_rate >= $min_conversion && $conversions > 0 ) {
		$recommendations[] = array(
			'type'    => 'scale',
			'label'   => 'Reuse this setup elsewhere',
			'details' => 'This page is already converting. Reuse its trigger timing and message structure on similar pages.',
		);
	}

	$recommendations = array_merge( $recommendations, $seo_suggestions );

	if ( empty( $recommendations ) ) {
		$recommendations[] = array(
			'type'    => 'watch',
			'label'   => 'Keep current settings and monitor',
			'details' => 'Signals are mixed. Watch another traffic cycle before making a large trigger or messaging change.',
		);
	}

	return array_slice( $recommendations, 0, 3 );
}

/**
 * Classify a content item into a decision label and rationale.
 *
 * @param int                 $views            Total views.
 * @param int                 $avg_time         Average time on page.
 * @param int                 $conversions      Conversion count.
 * @param array<string,mixed> $settings         Content Insights settings.
 * @param int                 $scroll_depth     Average scroll depth.
 * @param int                 $add_to_cart      Add-to-cart count.
 * @param int                 $checkout_visits  Checkout visit count.
 * @param int                 $checkout_success Successful checkout count.
 * @return array<string,string>
 */
function quorlyx_get_content_insights_decision( $views, $avg_time, $conversions, $settings, $scroll_depth = 0, $add_to_cart = 0, $checkout_visits = 0, $checkout_success = 0 ) {
	$thresholds          = quorlyx_get_content_insights_thresholds();
	$min_views           = $thresholds['min_views'];
	$min_conversion_rate = $thresholds['min_conversion_rate'];
	$min_avg_time        = $thresholds['min_avg_time'];
	$min_scroll_depth    = $thresholds['min_scroll_depth'];
	$conversion_rate     = $views > 0 ? ( $conversions / $views ) * 100 : 0;

	if ( $views < $min_views ) {
		return array(
			'label'  => 'Collect More Data',
			'reason' => sprintf( 'Needs at least %d views before deciding.', $min_views ),
		);
	}

	if ( $scroll_depth >= $min_scroll_depth && $conversion_rate < $min_conversion_rate ) {
		return array(
			'label'  => 'Trigger Opportunity',
			'reason' => 'Readers reach the end but do not convert consistently.',
		);
	}

	if ( $add_to_cart > 0 && 0 === $conversions ) {
		if ( $checkout_visits > 0 && 0 === $checkout_success ) {
			return array(
				'label'  => 'Checkout Drop-Off',
				'reason' => 'Users reach checkout but do not complete purchase.',
			);
		}

		if ( 0 === $checkout_visits ) {
			return array(
				'label'  => 'Checkout Funnel Leak',
				'reason' => 'Users add to cart but do not proceed to checkout.',
			);
		}

		return array(
			'label'  => 'Recover Drop-Off',
			'reason' => 'Cart intent is present but final conversion is missing.',
		);
	}

	$strong_conversion = $conversion_rate >= $min_conversion_rate;
	$strong_engagement = $avg_time >= $min_avg_time;

	if ( $strong_conversion ) {
		return array(
			'label'  => 'Promote',
			'reason' => 'Conversion rate is strong and this page is a good candidate for more traffic or reuse.',
		);
	}

	if ( $strong_engagement ) {
		return array(
			'label'  => 'Support',
			'reason' => 'Visitors stay on the page. Improve prompts or CTAs to convert that attention into action.',
		);
	}

	if ( $conversion_rate < ( $min_conversion_rate / 2 ) && $avg_time < $min_avg_time ) {
		return array(
			'label'  => 'Improve',
			'reason' => 'Low engagement and weak conversion signals.',
		);
	}

	return array(
		'label'  => 'Watch',
		'reason' => 'Performance is mixed. Keep monitoring before making a big change.',
	);
}

/**
 * Compute a normalized opportunity score for content optimization.
 *
 * @param int|float $views           Views count.
 * @param int|float $conversion_rate Conversion rate percentage.
 * @param int|float $avg_time        Average time on page.
 * @param int|float $scroll_depth    Scroll depth percentage.
 * @param int|float $cart_drop_off   Cart drop-off count.
 * @param int|float $add_to_cart     Add-to-cart count.
 * @return int
 */
function quorlyx_calculate_content_opportunity_score( $views, $conversion_rate, $avg_time, $scroll_depth, $cart_drop_off = 0, $add_to_cart = 0 ) {
	$views           = max( 0, (int) $views );
	$conversion_rate = max( 0, (float) $conversion_rate );
	$avg_time        = max( 0, (float) $avg_time );
	$scroll_depth    = max( 0, min( 100, (float) $scroll_depth ) );
	$cart_drop_off   = max( 0, (int) $cart_drop_off );
	$add_to_cart     = max( 0, (int) $add_to_cart );

	$views_component          = min( 35, log( $views + 1, 10 ) * 16 );
	$low_conversion_component = min( 35, max( 0, 8 - $conversion_rate ) * 4 );
	$time_norm                = min( 1, $avg_time / 180 );
	$scroll_norm              = $scroll_depth / 100;
	$engagement_component     = min( 30, ( ( $time_norm * 0.5 ) + ( $scroll_norm * 0.5 ) ) * 30 );

	$drop_off_component = 0;
	if ( $add_to_cart > 0 ) {
		$drop_rate          = min( 100, ( $cart_drop_off / $add_to_cart ) * 100 );
		$drop_off_component = min( 15, $drop_rate * 0.15 );
	}

	$score = $views_component + $low_conversion_component + $engagement_component + $drop_off_component;

	return (int) max( 0, min( 100, round( $score ) ) );
}

/**
 * Summarize trigger performance impact for a content URL.
 *
 * @param string $public_url Public URL.
 * @return array<string,int|float|bool>
 */
function quorlyx_get_content_trigger_impact_snapshot( $public_url ) {
	$public_url = trim( (string) $public_url );
	$empty      = array(
		'has_data'     => false,
		'before_rate'  => 0,
		'after_rate'   => 0,
		'delta_pp'     => 0,
		'before_fired' => 0,
		'after_fired'  => 0,
	);

	if ( '' === $public_url ) {
		return $empty;
	}

	static $target_trigger_map      = null;
	static $analytics_windows_cache = array();

	if ( null === $target_trigger_map ) {
		$target_trigger_map = array();
		$options            = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
		$options            = array_replace_recursive( quorlyx_get_global_defaults(), is_array( $options ) ? $options : array() );
		$triggers           = is_array( $options['triggers'] ?? null ) ? $options['triggers'] : array();

		foreach ( $triggers as $trigger ) {
			if ( ! is_array( $trigger ) ) {
				continue;
			}

			$target     = trim( (string) ( $trigger['target_page_url'] ?? '' ) );
			$trigger_id = sanitize_key( (string) ( $trigger['id'] ?? '' ) );
			if ( '' === $target || '' === $trigger_id ) {
				continue;
			}

			if ( ! isset( $target_trigger_map[ $target ] ) ) {
				$target_trigger_map[ $target ] = array();
			}

			$target_trigger_map[ $target ][] = $trigger_id;
		}
	}

	$target_rule = quorlyx_get_trigger_target_rule_from_url( $public_url );
	if ( '' === $target_rule || empty( $target_trigger_map[ $target_rule ] ) ) {
		return $empty;
	}

	$before_fired     = 0;
	$before_converted = 0;
	$after_fired      = 0;
	$after_converted  = 0;

	foreach ( array_unique( (array) $target_trigger_map[ $target_rule ] ) as $trigger_id ) {
		if ( ! isset( $analytics_windows_cache[ $trigger_id ] ) ) {
			$analytics_windows_cache[ $trigger_id ] = quorlyx_get_trigger_analytics_windows( $trigger_id );
		}

		$windows           = $analytics_windows_cache[ $trigger_id ];
		$before_fired     += (int) ( $windows['30d']['trigger_fired'] ?? 0 );
		$before_converted += (int) ( $windows['30d']['trigger_converted'] ?? 0 );
		$after_fired      += (int) ( $windows['7d']['trigger_fired'] ?? 0 );
		$after_converted  += (int) ( $windows['7d']['trigger_converted'] ?? 0 );
	}

	$before_rate = $before_fired > 0 ? ( $before_converted / $before_fired ) * 100 : 0;
	$after_rate  = $after_fired > 0 ? ( $after_converted / $after_fired ) * 100 : 0;

	return array(
		'has_data'     => ( $before_fired > 0 || $after_fired > 0 ),
		'before_rate'  => $before_rate,
		'after_rate'   => $after_rate,
		'delta_pp'     => $after_rate - $before_rate,
		'before_fired' => $before_fired,
		'after_fired'  => $after_fired,
	);
}

/**
 * Build a normalized content insight row for a post or virtual key.
 *
 * @param array<string,mixed> $settings    Content Insights settings.
 * @param int                 $post_id     Post ID.
 * @param string              $content_key Virtual content key.
 * @param bool                $ignore_scope Whether to bypass tracking-scope checks.
 * @return array<string,mixed>|null
 */
function quorlyx_get_content_insight_row( $settings, $post_id = 0, $content_key = '', $ignore_scope = false ) {
	$post_id     = absint( $post_id );
	$content_key = sanitize_key( $content_key );
	$ignore_scope = (bool) $ignore_scope;

	if ( $post_id > 0 ) {
		if ( ! $ignore_scope && ! quorlyx_content_insights_post_matches_settings( $post_id, $settings ) ) {
			return null;
		}

		$post = get_post( $post_id );
		if ( ! $post instanceof WP_Post ) {
			return null;
		}

		$title        = get_the_title( $post_id );
		$post_type    = $post->post_type;
		$edit_url     = get_edit_post_link( $post_id );
		$public_url   = get_permalink( $post_id );
		$is_generated = '1' === (string) get_post_meta( $post_id, '_quorlyx_generated', true );
		$source_label = $is_generated ? 'AI' : 'Manual';
		$seo_status   = quorlyx_get_content_insight_seo_status( $post_id );
	} elseif ( 'homepage' === $content_key ) {
		// Behavior Engine special case: If behavior tracking is effectively enabled, always show the homepage row,
		// as it serves as the default entry point for many sessions even if omitted from specific rules.
		$is_behavior_enabled = quorlyx_behavior_patterns_are_enabled( $settings );
		
		if ( ! $ignore_scope && ! $is_behavior_enabled && ! quorlyx_content_insights_homepage_matches_settings( $settings ) ) {
			return null;
		}

		$homepage_item = quorlyx_get_content_insights_homepage_item();
		if ( empty( $homepage_item ) ) {
			$homepage_item = array(
				'content_key'  => 'homepage',
				'title'        => 'Homepage',
				'url'          => home_url( '/' ),
				'post_type'    => 'homepage',
				'is_generated' => false,
				'edit_url'     => '',
			);
		}

		$title        = $homepage_item['title'];
		$post_type    = $homepage_item['post_type'];
		$edit_url     = $homepage_item['edit_url'];
		$public_url   = $homepage_item['url'];
		$is_generated = false;
		$source_label = 'Manual';
		$seo_status   = quorlyx_get_content_insight_seo_status( 0, $content_key );
	} else {
		return null;
	}

	$views                 = quorlyx_get_analytics_metric( $post_id, '_quorlyx_analytics_views', $content_key );
	$total_time            = quorlyx_get_analytics_metric( $post_id, '_quorlyx_analytics_time_on_page', $content_key );
	$avg_time              = $views > 0 ? (int) round( $total_time / $views ) : 0;
	$scroll_depth          = quorlyx_get_analytics_metric( $post_id, '_quorlyx_analytics_scroll_depth', $content_key );
	$add_to_cart           = quorlyx_get_analytics_metric( $post_id, '_quorlyx_analytics_add_to_cart', $content_key );
	$checkout_visits       = quorlyx_get_analytics_metric( $post_id, '_quorlyx_analytics_checkout_visits', $content_key );
	$checkout_success      = quorlyx_get_analytics_metric( $post_id, '_quorlyx_analytics_checkout_success', $content_key );
	$checkout_drop_off     = max( 0, $checkout_visits - $checkout_success );
	$cart_drop_off         = max( 0, $add_to_cart - $checkout_visits );
	$conversions           = quorlyx_get_analytics_metric( $post_id, '_quorlyx_analytics_conversions', $content_key );
	$conversion_rate       = $views > 0 ? ( $conversions / $views ) * 100 : 0;
	$opportunity_score     = quorlyx_calculate_content_opportunity_score( $views, $conversion_rate, $avg_time, $scroll_depth, $cart_drop_off, $add_to_cart );
	$opportunity_threshold = max( 0, min( 100, absint( $settings['opportunity_score_threshold'] ?? 60 ) ) );
	$trigger_impact        = quorlyx_get_content_trigger_impact_snapshot( (string) $public_url );
	$behavior_snapshot     = quorlyx_get_behavior_snapshot_for_content( $post_id, $content_key );
	$decision              = quorlyx_get_content_insights_decision( $views, $avg_time, $conversions, $settings, $scroll_depth, $add_to_cart, $checkout_visits, $checkout_success );
	$recommendations       = quorlyx_get_content_insights_recommendations(
		array(
			'post_id'           => $post_id,
			'content_key'       => $content_key,
			'title'             => $title,
			'post_type'         => $post_type,
			'public_url'        => $public_url,
			'views'             => $views,
			'avg_time'          => $avg_time,
			'scroll_depth'      => $scroll_depth,
			'add_to_cart'       => $add_to_cart,
			'checkout_visits'   => $checkout_visits,
			'checkout_success'  => $checkout_success,
			'checkout_drop_off' => $checkout_drop_off,
			'cart_drop_off'     => $cart_drop_off,
			'conversions'       => $conversions,
			'conversion_rate'   => $conversion_rate,
			'seo_status'        => $seo_status,
		),
		$settings
	);

	return array(
		'post_id'                 => $post_id,
		'content_key'             => $content_key,
		'title'                   => $title,
		'post_type'               => $post_type,
		'edit_url'                => $edit_url ? $edit_url : '',
		'public_url'              => $public_url ? $public_url : '',
		'views'                   => $views,
		'avg_time'                => $avg_time,
		'scroll_depth'            => $scroll_depth,
		'add_to_cart'             => $add_to_cart,
		'checkout_visits'         => $checkout_visits,
		'checkout_success'        => $checkout_success,
		'checkout_drop_off'       => $checkout_drop_off,
		'cart_drop_off'           => $cart_drop_off,
		'conversions'             => $conversions,
		'conversion_rate'         => $conversion_rate,
		'opportunity_score'       => $opportunity_score,
		'is_generated'            => $is_generated,
		'source_label'            => $source_label,
		'seo_status'              => $seo_status,
		'decision'                => $decision,
		'recommendations'         => $recommendations,
		'opportunity_is_eligible' => $opportunity_score >= $opportunity_threshold,
		'trigger_impact'          => $trigger_impact,
		'behavior_snapshot'       => $behavior_snapshot,
		'behavior_primary_pattern' => sanitize_key( (string) ( $behavior_snapshot['top_pattern'] ?? 'unknown' ) ),
	);
}

/**
 * Convert a public URL into a normalized trigger target rule string.
 *
 * @param string $url Public URL.
 * @return string
 */
function quorlyx_get_trigger_target_rule_from_url( $url ) {
	$url   = trim( (string) $url );
	$path  = (string) wp_parse_url( $url, PHP_URL_PATH );
	$query = (string) wp_parse_url( $url, PHP_URL_QUERY );

	if ( '' === $path ) {
		return '';
	}

	$target = '/' === $path ? '/' : untrailingslashit( $path );
	if ( $query ) {
		$target .= '?' . $query;
	}

	return sanitize_text_field( $target );
}

/**
 * Build a preconfigured trigger template from an insight action mode.
 *
 * @param string $mode           Template mode.
 * @param string $target_page_url Target page URL.
 * @param string $content_title  Optional content title.
 * @return array<string,mixed>
 */
function quorlyx_get_insight_trigger_template( $mode, $target_page_url, $content_title = '' ) {
	$mode          = sanitize_key( $mode );
	$target_page   = sanitize_text_field( (string) $target_page_url );
	$content_title = sanitize_text_field( (string) $content_title );
	$content_label = '' !== $content_title ? $content_title : 'Selected page';
	$defaults      = quorlyx_get_trigger_defaults();

	if ( 'cart_recovery' === $mode ) {
		return array_replace(
			$defaults,
			array(
				'id'                               => 'trigger_' . uniqid(),
				'name'                             => sprintf( 'Checkout Recovery - %s', $content_label ),
				'type'                             => 'exit_intent',
				'target_page_url'                  => $target_page,
				'proactive_message'                => 'Before you leave, can I help you finish checkout? I can quickly answer shipping, pricing, or payment questions.',
				'open_style'                       => 'center',
				'use_ai_message'                   => true,
				'ai_persona'                       => 'You are a concise checkout assistant focused on reducing purchase drop-off. Keep replies under 45 words and end with one direct next step.',
				'ai_temperature'                   => 0.4,
				'ai_cache_ttl'                     => 20,
				'ai_fallback_message'              => 'Need help completing checkout? I can clarify shipping, payment options, or return policy in one message.',
				'require_cart_not_empty'           => true,
				'min_time_on_page'                 => 12,
				'override_priority'                => true,
				'suppress_if_visited_url_contains' => '/thank-you' . "\n" . '/order-received',
			)
		);
	}

	return array_replace(
		$defaults,
		array(
			'id'                  => 'trigger_' . uniqid(),
			'name'                => sprintf( 'Insight Trigger - %s', $content_label ),
			'type'                => 'time_on_page',
			'target_page_url'     => $target_page,
			'proactive_message'   => 'Would you like a quick summary and the fastest next step for this page?',
			'time_delay'          => 18,
			'scroll_depth'        => 55,
			'use_ai_message'      => true,
			'ai_persona'          => 'You are a concise conversion assistant. Keep messages under 35 words with one clear call to action.',
			'ai_temperature'      => 0.5,
			'ai_cache_ttl'        => 60,
			'ai_fallback_message' => 'Can I help with a quick recommendation before you continue?',
		)
	);
}

/**
 * Handle admin action to create a trigger from a Content Insights row.
 *
 * @return void
 */
function quorlyx_handle_create_insight_trigger() {
	if ( ! quorlyx_current_user_can_manage() ) {
		wp_die( esc_html__( 'You are not allowed to perform this action.', 'quorlyx' ) );
	}

	check_admin_referer( 'quorlyx_create_insight_trigger' );

	$mode            = isset( $_GET['mode'] ) ? sanitize_key( wp_unslash( $_GET['mode'] ) ) : 'suggested';
	$target_page_url = isset( $_GET['target_page_url'] ) ? sanitize_text_field( wp_unslash( $_GET['target_page_url'] ) ) : '';
	$content_title   = isset( $_GET['content_title'] ) ? sanitize_text_field( wp_unslash( $_GET['content_title'] ) ) : '';

	$mode = in_array( $mode, array( 'suggested', 'cart_recovery' ), true ) ? $mode : 'suggested';

	$redirect = add_query_arg(
		array(
			'page' => 'quorlyx-settings',
			'tab'  => 'chatbot',
		),
		admin_url( 'admin.php' )
	);

	if ( '' === $target_page_url ) {
		wp_safe_redirect( add_query_arg( 'quorlyx_insight_trigger', 'missing_target', $redirect ) . '#tour-step-triggers' );
		exit;
	}

	$options  = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$options  = array_replace_recursive( quorlyx_get_global_defaults(), is_array( $options ) ? $options : array() );
	$triggers = is_array( $options['triggers'] ?? null ) ? $options['triggers'] : array();

	$new_trigger = quorlyx_get_insight_trigger_template( $mode, $target_page_url, $content_title );

	foreach ( $triggers as $trigger ) {
		$existing_type = sanitize_key( (string) ( $trigger['type'] ?? '' ) );
		$existing_page = sanitize_text_field( (string) ( $trigger['target_page_url'] ?? '' ) );
		if ( $existing_type === $new_trigger['type'] && $existing_page === $new_trigger['target_page_url'] ) {
			wp_safe_redirect( add_query_arg( 'quorlyx_insight_trigger', 'exists', $redirect ) . '#tour-step-triggers' );
			exit;
		}
	}

	$triggers[]          = $new_trigger;
	$options['triggers'] = quorlyx_normalize_trigger_ids( $triggers );
	update_option( 'quorlyx_options', $options );

	wp_safe_redirect( add_query_arg( 'quorlyx_insight_trigger', 'created', $redirect ) . '#tour-step-triggers' );
	exit;
}
add_action( 'admin_post_quorlyx_create_insight_trigger', 'quorlyx_handle_create_insight_trigger' );

/**
 * Render transient admin notice after an insight-trigger action.
 *
 * @return void
 */
function quorlyx_render_insight_trigger_admin_notice() {
	// phpcs:disable WordPress.Security.NonceVerification.Recommended -- Read-only status message rendering based on query args.
	if ( empty( $_GET['quorlyx_insight_trigger'] ) || empty( $_GET['page'] ) ) {
		return;
	}

	$page = sanitize_key( wp_unslash( $_GET['page'] ) );
	if ( ! in_array( $page, array( 'quorlyx-settings', 'quorlyx-content-insights' ), true ) ) {
		return;
	}

	$status = sanitize_key( wp_unslash( $_GET['quorlyx_insight_trigger'] ) );
	// phpcs:enable WordPress.Security.NonceVerification.Recommended
	$message = '';
	$class   = 'notice notice-success is-dismissible';

	if ( 'created' === $status ) {
		$message = 'Trigger created from Insights. You can fine-tune it below.';
	} elseif ( 'exists' === $status ) {
		$class   = 'notice notice-info is-dismissible';
		$message = 'A similar trigger already exists for this page and trigger type.';
	} elseif ( 'missing_target' === $status ) {
		$class   = 'notice notice-error is-dismissible';
		$message = 'Could not create trigger because no target page URL was available.';
	}

	if ( '' === $message ) {
		return;
	}

	echo '<div class="' . esc_attr( $class ) . '"><p>' . esc_html( $message ) . '</p></div>';
}
add_action( 'admin_notices', 'quorlyx_render_insight_trigger_admin_notice' );

/**
 * Build the paginated Content Insights dataset for admin rendering.
 *
 * @param array<string,mixed> $settings   Content Insights settings.
 * @param string              $sort       Sort key.
 * @param int                 $paged      Current page.
 * @param int                 $per_page   Rows per page.
 * @param string              $tab_filter Tab filter slug.
 * @return array<string,mixed>
 */
function quorlyx_get_content_insights_dataset( $settings, $sort = 'conversion_rate_desc', $paged = 1, $per_page = 10, $tab_filter = 'all' ) {
	if ( ! quorlyx_content_insights_is_enabled( $settings ) ) {
		return array(
			'rows'                  => array(),
			'current_page'          => max( 1, (int) $paged ),
			'total_items'           => 0,
			'total_pages'           => 1,
			'total_views'           => 0,
			'total_conversions'     => 0,
			'avg_views_per_item'    => 0,
			'avg_time_per_item'     => 0,
			'avg_scroll_depth'      => 0,
			'generated_count'       => 0,
			'manual_count'          => 0,
			'recommendation_counts' => array(),
			'source_mode'           => sanitize_key( $settings['content_source'] ?? 'any' ),
		);
	}

	$post_types = quorlyx_get_content_insights_post_types();
	$scope      = sanitize_key( $settings['tracking_mode'] ?? 'all_public' );
	$source     = sanitize_key( $settings['content_source'] ?? 'any' );
	$candidate_limit = max( 100, min( 5000, absint( $settings['dataset_candidate_limit'] ?? 1000 ) ) );
	$candidate_sources = array();

	if ( 'behavior' === $tab_filter ) {
		foreach ( quorlyx_get_behavior_engine_sources() as $behavior_source ) {
			$candidate_sources[] = array(
				'post_id'      => absint( $behavior_source['post_id'] ?? 0 ),
				'content_key'  => sanitize_key( (string) ( $behavior_source['content_key'] ?? '' ) ),
				'ignore_scope' => true,
			);
		}
	} elseif ( 'specific_items' === $scope ) {
		$candidate_ids = get_posts(
			array(
				'post_type'              => array_keys( $post_types ),
				'post_status'            => array( 'publish', 'private', 'draft', 'pending', 'future' ),
				'posts_per_page'         => $candidate_limit,
				'orderby'                => 'date',
				'order'                  => 'DESC',
				'fields'                 => 'ids',
				'ignore_sticky_posts'    => true,
				'no_found_rows'          => true,
				'update_post_meta_cache' => false,
				'update_post_term_cache' => false,
			)
		);

		foreach ( (array) $candidate_ids as $candidate_id ) {
			$candidate_sources[] = array(
				'post_id'      => absint( $candidate_id ),
				'content_key'  => '',
				'ignore_scope' => false,
			);
		}
	} else {
		$query_types = array_keys( $post_types );
		if ( 'post_types' === $scope ) {
			$query_types = array_values( array_intersect( $query_types, array_map( 'sanitize_key', (array) ( $settings['tracked_post_types'] ?? array() ) ) ) );
		}

		if ( empty( $query_types ) ) {
			$candidate_ids = array();
		} else {
			$candidate_ids = get_posts(
				array(
					'post_type'              => $query_types,
					'post_status'            => array( 'publish', 'private', 'draft', 'pending', 'future' ),
					'posts_per_page'         => $candidate_limit,
					'orderby'                => 'date',
					'order'                  => 'DESC',
					'fields'                 => 'ids',
					'ignore_sticky_posts'    => true,
					'no_found_rows'          => true,
					'update_post_meta_cache' => false,
					'update_post_term_cache' => false,
				)
			);
		}

		foreach ( (array) $candidate_ids as $candidate_id ) {
			$candidate_sources[] = array(
				'post_id'      => absint( $candidate_id ),
				'content_key'  => '',
				'ignore_scope' => false,
			);
		}
	}

	$rows                  = array();
	$total_views           = 0;
	$total_conversions     = 0;
	$total_avg_time        = 0;
	$total_scroll_depth    = 0;
	$generated_count       = 0;
	$recommendation_counts = array();

	foreach ( $candidate_sources as $candidate_source ) {
		$candidate_post_id     = absint( $candidate_source['post_id'] ?? 0 );
		$candidate_content_key = sanitize_key( (string) ( $candidate_source['content_key'] ?? '' ) );
		$ignore_scope          = ! empty( $candidate_source['ignore_scope'] );

		$row = quorlyx_get_content_insight_row( $settings, $candidate_post_id, $candidate_content_key, $ignore_scope );
		if ( ! is_array( $row ) ) {
			continue;
		}

		if ( 'products' === $tab_filter && ! in_array( (string) ( $row['post_type'] ?? '' ), array( 'product', 'product_variation' ), true ) ) {
			continue;
		}
		if ( 'content' === $tab_filter && in_array( (string) ( $row['post_type'] ?? '' ), array( 'product', 'product_variation' ), true ) ) {
			continue;
		}
		if ( 'behavior' === $tab_filter && empty( $row['behavior_snapshot']['has_data'] ) ) {
			continue;
		}

		$rows[]              = $row;
		$total_views        += $row['views'];
		$total_conversions  += $row['conversions'];
		$total_avg_time     += ( $row['avg_time'] * $row['views'] );
		$total_scroll_depth += ( $row['scroll_depth'] * $row['views'] );
		if ( ! empty( $row['is_generated'] ) ) {
			++$generated_count;
		}
		foreach ( $row['recommendations'] as $recommendation ) {
			$key                           = sanitize_key( $recommendation['label'] );
			$recommendation_counts[ $key ] = ( $recommendation_counts[ $key ] ?? 0 ) + 1;
		}
	}

	if ( 'behavior' !== $tab_filter ) {
		$row = quorlyx_get_content_insight_row( $settings, 0, 'homepage' );
		if ( is_array( $row ) ) {
			$include_homepage = true;
			if ( 'products' === $tab_filter ) {
				$include_homepage = false;
			}

			if ( $include_homepage ) {
				$rows[]              = $row;
				$total_views        += $row['views'];
				$total_conversions  += $row['conversions'];
				$total_avg_time     += ( $row['avg_time'] * $row['views'] );
				$total_scroll_depth += ( $row['scroll_depth'] * $row['views'] );
				foreach ( $row['recommendations'] as $recommendation ) {
					$key                           = sanitize_key( $recommendation['label'] );
					$recommendation_counts[ $key ] = ( $recommendation_counts[ $key ] ?? 0 ) + 1;
				}
			}
		}
	}

	usort(
		$rows,
		function ( $left, $right ) use ( $sort ) {
			$left_title  = (string) ( $left['title'] ?? '' );
			$right_title = (string) ( $right['title'] ?? '' );
			$left_views  = (int) ( $left['views'] ?? 0 );
			$right_views = (int) ( $right['views'] ?? 0 );

			$tie_by_title = static function () use ( $left_title, $right_title ) {
				return strcasecmp( $left_title, $right_title );
			};

			switch ( $sort ) {
				case 'opportunity_asc':
					if ( ( $left['opportunity_score'] ?? 0 ) === ( $right['opportunity_score'] ?? 0 ) ) {
						return $left_views <=> $right_views;
					}
					return ( $left['opportunity_score'] ?? 0 ) <=> ( $right['opportunity_score'] ?? 0 );
				case 'opportunity_desc':
					if ( ( $left['opportunity_score'] ?? 0 ) === ( $right['opportunity_score'] ?? 0 ) ) {
						return $right_views <=> $left_views;
					}
					return ( $right['opportunity_score'] ?? 0 ) <=> ( $left['opportunity_score'] ?? 0 );
				case 'source_asc':
					$source_cmp = strcasecmp( (string) ( $left['source_label'] ?? '' ), (string) ( $right['source_label'] ?? '' ) );
					return 0 !== $source_cmp ? $source_cmp : $tie_by_title();
				case 'source_desc':
					$source_cmp = strcasecmp( (string) ( $left['source_label'] ?? '' ), (string) ( $right['source_label'] ?? '' ) );
					return 0 !== $source_cmp ? ( 0 - $source_cmp ) : $tie_by_title();
				case 'type_asc':
					$type_cmp = strcasecmp( (string) ( $left['post_type'] ?? '' ), (string) ( $right['post_type'] ?? '' ) );
					return 0 !== $type_cmp ? $type_cmp : $tie_by_title();
				case 'type_desc':
					$type_cmp = strcasecmp( (string) ( $left['post_type'] ?? '' ), (string) ( $right['post_type'] ?? '' ) );
					return 0 !== $type_cmp ? ( 0 - $type_cmp ) : $tie_by_title();
				case 'views_asc':
					if ( $left_views === $right_views ) {
						return $tie_by_title();
					}
					return $left_views <=> $right_views;
				case 'views_desc':
					if ( $left_views === $right_views ) {
						return $tie_by_title();
					}
					return $right_views <=> $left_views;
				case 'time_asc':
					if ( ( $left['avg_time'] ?? 0 ) === ( $right['avg_time'] ?? 0 ) ) {
						return $tie_by_title();
					}
					return ( $left['avg_time'] ?? 0 ) <=> ( $right['avg_time'] ?? 0 );
				case 'time_desc':
					if ( ( $left['avg_time'] ?? 0 ) === ( $right['avg_time'] ?? 0 ) ) {
						return $tie_by_title();
					}
					return $right['avg_time'] <=> $left['avg_time'];
				case 'scroll_asc':
					if ( ( $left['scroll_depth'] ?? 0 ) === ( $right['scroll_depth'] ?? 0 ) ) {
						return $tie_by_title();
					}
					return ( $left['scroll_depth'] ?? 0 ) <=> ( $right['scroll_depth'] ?? 0 );
				case 'scroll_desc':
					if ( ( $left['scroll_depth'] ?? 0 ) === ( $right['scroll_depth'] ?? 0 ) ) {
						return $tie_by_title();
					}
					return $right['scroll_depth'] <=> $left['scroll_depth'];
				case 'add_to_cart_asc':
					if ( ( $left['add_to_cart'] ?? 0 ) === ( $right['add_to_cart'] ?? 0 ) ) {
						return $tie_by_title();
					}
					return ( $left['add_to_cart'] ?? 0 ) <=> ( $right['add_to_cart'] ?? 0 );
				case 'add_to_cart_desc':
					if ( ( $left['add_to_cart'] ?? 0 ) === ( $right['add_to_cart'] ?? 0 ) ) {
						return $tie_by_title();
					}
					return ( $right['add_to_cart'] ?? 0 ) <=> ( $left['add_to_cart'] ?? 0 );
				case 'checkout_flow_asc':
					$left_checkout_flow  = ( (int) ( $left['checkout_visits'] ?? 0 ) * 1000000 ) + (int) ( $left['checkout_success'] ?? 0 );
					$right_checkout_flow = ( (int) ( $right['checkout_visits'] ?? 0 ) * 1000000 ) + (int) ( $right['checkout_success'] ?? 0 );
					if ( $left_checkout_flow === $right_checkout_flow ) {
						return $tie_by_title();
					}
					return $left_checkout_flow <=> $right_checkout_flow;
				case 'checkout_flow_desc':
					$left_checkout_flow  = ( (int) ( $left['checkout_visits'] ?? 0 ) * 1000000 ) + (int) ( $left['checkout_success'] ?? 0 );
					$right_checkout_flow = ( (int) ( $right['checkout_visits'] ?? 0 ) * 1000000 ) + (int) ( $right['checkout_success'] ?? 0 );
					if ( $left_checkout_flow === $right_checkout_flow ) {
						return $tie_by_title();
					}
					return $right_checkout_flow <=> $left_checkout_flow;
				case 'conversions_asc':
					if ( ( $left['conversions'] ?? 0 ) === ( $right['conversions'] ?? 0 ) ) {
						return $tie_by_title();
					}
					return ( $left['conversions'] ?? 0 ) <=> ( $right['conversions'] ?? 0 );
				case 'conversions_desc':
					if ( ( $left['conversions'] ?? 0 ) === ( $right['conversions'] ?? 0 ) ) {
						return $tie_by_title();
					}
					return $right['conversions'] <=> $left['conversions'];
				case 'title_asc':
					return $tie_by_title();
				case 'title_desc':
					return strcasecmp( $right_title, $left_title );
				case 'conversion_rate_asc':
					if ( $left['conversion_rate'] === $right['conversion_rate'] ) {
						return $tie_by_title();
					}
					return $left['conversion_rate'] <=> $right['conversion_rate'];
				case 'conversion_rate_desc':
				default:
					if ( $left['conversion_rate'] === $right['conversion_rate'] ) {
						return $right_views <=> $left_views;
					}
					return $right['conversion_rate'] <=> $left['conversion_rate'];
			}
		}
	);

	$total_items = count( $rows );
	$total_pages = $per_page > 0 ? (int) ceil( $total_items / $per_page ) : 1;
	$total_pages = max( 1, $total_pages );
	$paged       = max( 1, min( (int) $paged, $total_pages ) );
	$offset      = max( 0, ( $paged - 1 ) * $per_page );

	arsort( $recommendation_counts );

	return array(
		'rows'                  => array_slice( $rows, $offset, $per_page ),
		'current_page'          => $paged,
		'total_items'           => $total_items,
		'total_pages'           => $total_pages,
		'total_views'           => $total_views,
		'total_conversions'     => $total_conversions,
		'avg_views_per_item'    => $total_items > 0 ? round( $total_views / $total_items ) : 0,
		'avg_time_per_item'     => $total_views > 0 ? round( $total_avg_time / $total_views ) : 0,
		'avg_scroll_depth'      => $total_views > 0 ? round( $total_scroll_depth / $total_views ) : 0,
		'generated_count'       => $generated_count,
		'manual_count'          => max( 0, $total_items - $generated_count ),
		'recommendation_counts' => $recommendation_counts,
		'source_mode'           => $source,
	);
}

/**
 * Validate that the selected Content Insights scope has required values.
 *
 * @param array<string,mixed> $settings Content Insights settings.
 * @return bool
 */
function quorlyx_content_insights_scope_is_configured( $settings ) {
	$scope = sanitize_key( $settings['tracking_mode'] ?? 'all_public' );

	if ( 'post_types' === $scope ) {
		return ! empty( array_filter( array_map( 'sanitize_key', (array) ( $settings['tracked_post_types'] ?? array() ) ) ) );
	}

	if ( 'specific_items' === $scope ) {
		$exact_rules    = array_filter( array_map( 'trim', (array) ( $settings['target_page_urls'] ?? array() ) ) );
		$contains_rules = array_filter( array_map( 'trim', (array) ( $settings['target_url_contains'] ?? array() ) ) );

		return ! empty( $exact_rules ) || ! empty( $contains_rules );
	}

	return true;
}

/**
 * Render the Content Insights settings section in the chatbot settings tab.
 *
 * @param array<string,mixed> $settings Content Insights settings.
 * @return void
 */
function quorlyx_render_content_insights_settings_ui( $settings ) {
	$saved_enabled = quorlyx_content_insights_is_enabled();
	if ( ! is_array( $settings ) ) {
		$settings = array();
	}
	$settings['enabled'] = $saved_enabled;

	$post_types     = quorlyx_get_content_insights_post_types();
	$target_urls    = implode( "\n", array_map( 'trim', (array) ( $settings['target_page_urls'] ?? array() ) ) );
	$url_rules      = implode( "\n", array_map( 'trim', (array) ( $settings['target_url_contains'] ?? array() ) ) );
	$excluded_urls  = implode( "\n", array_map( 'trim', (array) ( $settings['excluded_page_urls'] ?? array() ) ) );
	$excluded_rules = implode( "\n", array_map( 'trim', (array) ( $settings['excluded_url_contains'] ?? array() ) ) );
	$conversion_tracking_mode = quorlyx_get_content_insights_conversion_tracking_mode( $settings );
	$behavior_settings = quorlyx_normalize_behavior_pattern_settings(
		is_array( $settings['behavior_patterns'] ?? null ) ? $settings['behavior_patterns'] : array(),
		quorlyx_get_global_defaults()['content_insights']['behavior_patterns']
	);
	$track_woocommerce_purchase = ! empty( $behavior_settings['track_woocommerce_purchase'] );
	$custom_conversion_lines    = array();
	foreach ( (array) ( $behavior_settings['custom_conversions'] ?? array() ) as $custom_conversion_rule ) {
		if ( ! is_array( $custom_conversion_rule ) ) {
			continue;
		}

		$conversion_type   = sanitize_key( (string) ( $custom_conversion_rule['type'] ?? '' ) );
		$conversion_target = sanitize_text_field( (string) ( $custom_conversion_rule['target'] ?? '' ) );
		$conversion_target = trim( $conversion_target );

		if ( '' === $conversion_type || '' === $conversion_target ) {
			continue;
		}

		$custom_conversion_lines[] = $conversion_type . ':' . $conversion_target;
	}
	$custom_conversion_input = implode( "\n", $custom_conversion_lines );
	?>
