/**
 * Render the dedicated Content Insights admin page.
 *
 * @return void
 */
function quorlyx_render_content_insights_page() {
	wp_enqueue_style( 'quorlyx-dashboard-css', plugin_dir_url( __FILE__ ) . 'dist/dashboard.min.css', array(), '1.6.8' );

	$options              = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$options              = array_replace_recursive( quorlyx_get_global_defaults(), $options );
	$settings             = $options['content_insights'];
	$behavior_pattern_settings = quorlyx_get_behavior_pattern_settings( $settings );
	$tracking_mode_labels = array(
		'all_public'     => 'All public content',
		'post_types'     => 'Selected post types',
		'specific_items' => 'Target page URLs',
	);
	$conversion_mode_labels = array(
		'any'              => 'Any conversion signal',
		'conversion_goals' => 'Only configured Conversion Goals',
	);
	$conversion_tracking_mode = quorlyx_get_content_insights_conversion_tracking_mode( $settings );

	// phpcs:disable WordPress.Security.NonceVerification.Recommended -- Read-only sorting and pagination controls.
	$paged = isset( $_GET['insights_paged'] ) ? max( 1, absint( wp_unslash( $_GET['insights_paged'] ) ) ) : 1;
	$sort  = isset( $_GET['insights_sort'] ) ? sanitize_key( wp_unslash( $_GET['insights_sort'] ) ) : 'conversion_rate_desc';
	// phpcs:enable WordPress.Security.NonceVerification.Recommended

	$allowed_sorts = array(
		'opportunity_asc',
		'opportunity_desc',
		'source_asc',
		'source_desc',
		'type_asc',
		'type_desc',
		'views_asc',
		'conversion_rate_desc',
		'conversion_rate_asc',
		'conversions_asc',
		'conversions_desc',
		'views_desc',
		'time_asc',
		'time_desc',
		'scroll_asc',
		'scroll_desc',
		'add_to_cart_asc',
		'add_to_cart_desc',
		'checkout_flow_asc',
		'checkout_flow_desc',
		'title_asc',
		'title_desc',
	);
	if ( ! in_array( $sort, $allowed_sorts, true ) ) {
		$sort = 'conversion_rate_desc';
	}

	// phpcs:disable WordPress.Security.NonceVerification.Recommended -- Read-only tab selection.
	$current_tab = isset( $_GET['insight_tab'] ) ? sanitize_key( wp_unslash( $_GET['insight_tab'] ) ) : 'products';
	// phpcs:enable WordPress.Security.NonceVerification.Recommended
	if ( ! in_array( $current_tab, array( 'products', 'content', 'behavior', 'import' ), true ) ) {
		$current_tab = 'products';
	}

	$settings_url              = admin_url( 'admin.php?page=quorlyx-settings&tab=chatbot#tour-step-content-insights-settings' );
	$content_insights_enabled  = quorlyx_content_insights_is_enabled( $settings );
	if ( ! $content_insights_enabled ) {
		?>
		<div class="wrap" id="quorlyx-content-insights-page">
			<div class="quorlyx-page-header">
				<div class="quorlyx-brand">
					<img class="quorlyx-brand-logo" src="<?php echo esc_url( quorlyx_get_plugin_logo_url() ); ?>" alt="Quorlyx" />
					<div class="quorlyx-titles">
						<h1>Content Insights</h1>
						<p class="subtitle">Tracking and behavior reports are paused until Content Insights is enabled.</p>
					</div>
				</div>
				<div class="quorlyx-dashboard-actions">
					<a href="<?php echo esc_url( $settings_url ); ?>" class="button button-primary"><span class="dashicons dashicons-admin-generic"></span> Enable Content Insights</a>
				</div>
			</div>
			<div class="notice notice-warning inline"><p>Content Insights is disabled. Quorlyx will not collect content analytics or behavior snapshots while this switch is off.</p></div>
			<div class="postbox quorlyx-card">
				<h2 class="hndle"><span><span class="dashicons dashicons-lock"></span> Reports Paused</span></h2>
				<div class="inside">
					<p>Enable <strong>Content Insights &amp; Behavior</strong> in Settings to collect fresh data and reopen the products, posts, behavior, and import reports.</p>
					<p><a href="<?php echo esc_url( $settings_url ); ?>" class="button button-primary">Open Settings</a></p>
				</div>
			</div>
		</div>
		<?php
		return;
	}

	$dataset            = quorlyx_get_content_insights_dataset( $settings, $sort, $paged, 10, $current_tab );
	$all_items_dataset  = quorlyx_get_content_insights_dataset( $settings, $sort, 1, 1, 'all' );
	$insight_rows       = $dataset['rows'];
	$current_page       = (int) ( $dataset['current_page'] ?? $paged );
	$items_on_page      = count( $insight_rows );
	$total_items        = $dataset['total_items'];
	$avg_views_per_item = $dataset['avg_views_per_item'];
	$avg_time_per_item  = $dataset['avg_time_per_item'];
	$avg_scroll_depth   = $dataset['avg_scroll_depth'];
	$top_recommendation = ! empty( $dataset['recommendation_counts'] ) ? key( $dataset['recommendation_counts'] ) : '';
	$has_scope_rules    = quorlyx_content_insights_scope_is_configured( $settings );
	$has_any_items      = (int) $all_items_dataset['total_items'] > 0;
	?>
	<div class="wrap" id="quorlyx-content-insights-page">
		<div class="quorlyx-page-header">
			<div class="quorlyx-brand">
				<img class="quorlyx-brand-logo" src="<?php echo esc_url( quorlyx_get_plugin_logo_url() ); ?>" alt="Quorlyx" />
				<div class="quorlyx-titles">
					<h1>Content Insights</h1>
					<p class="subtitle">Track posts, products, and target page URLs, then use simple decision labels to guide your next move.</p>
				</div>
			</div>
			<div class="quorlyx-dashboard-actions">
				<a href="<?php echo esc_url( $settings_url ); ?>" class="button button-primary"><span class="dashicons dashicons-admin-generic"></span> Configure Tracking</a>
			</div>
		</div>

		<div class="quorlyx-dashboard-grid">
			<div class="postbox quorlyx-card">
				<h2 class="hndle"><span><span class="dashicons dashicons-analytics"></span> Tracking Summary</span></h2>
				<div class="inside">
					<ul class="quorlyx-list">
						<li><strong>Status:</strong> <?php echo esc_html( ! empty( $settings['enabled'] ) ? 'Enabled' : 'Disabled' ); ?></li>
						<li><strong>Data mode:</strong> <?php echo esc_html( ! empty( $settings['prefer_db_processing_global'] ) ? 'DB-first' : 'Standard' ); ?></li>
						<li><strong>Tracking mode:</strong> <?php echo esc_html( $tracking_mode_labels[ $settings['tracking_mode'] ] ?? 'All public content' ); ?></li>
						<li><strong>Conversion counting:</strong> <?php echo esc_html( $conversion_mode_labels[ $conversion_tracking_mode ] ?? $conversion_mode_labels['any'] ); ?></li>
						<li><strong>Content source:</strong> <?php echo esc_html( ucwords( str_replace( '_', ' ', $dataset['source_mode'] ) ) ); ?></li>
						<li><strong>Opportunity threshold:</strong> <?php echo esc_html( number_format_i18n( (int) ( $settings['opportunity_score_threshold'] ?? 60 ) ) ); ?>/100</li>
						<li><strong>Most common recommendation:</strong> <?php echo esc_html( $top_recommendation ? ucwords( str_replace( '_', ' ', $top_recommendation ) ) : 'No recommendation yet' ); ?></li>
					</ul>
				</div>
			</div>
			<div class="postbox quorlyx-card">
				<h2 class="hndle"><span><span class="dashicons dashicons-chart-bar"></span> Portfolio Snapshot</span></h2>
				<div class="inside">
					<ul class="quorlyx-list">
						<li><strong>Items on this page:</strong> <?php echo esc_html( number_format_i18n( $items_on_page ) ); ?></li>
						<li><strong>Total tracked items:</strong> <?php echo esc_html( number_format_i18n( $total_items ) ); ?></li>
						<li><strong>Total views:</strong> <?php echo esc_html( number_format_i18n( $dataset['total_views'] ) ); ?></li>
						<li><strong>Total conversions:</strong> <?php echo esc_html( number_format_i18n( $dataset['total_conversions'] ) ); ?></li>
						<li><strong>Avg. views per item:</strong> <?php echo esc_html( number_format_i18n( $avg_views_per_item ) ); ?></li>
						<li><strong>Avg. time per item:</strong> <?php echo esc_html( number_format_i18n( $avg_time_per_item ) ); ?>s</li>
						<li><strong>Avg. scroll depth:</strong> <?php echo esc_html( number_format_i18n( $avg_scroll_depth ) ); ?>%</li>
						<li><strong>AI vs manual:</strong> <?php echo esc_html( number_format_i18n( $dataset['generated_count'] ) ); ?> AI / <?php echo esc_html( number_format_i18n( $dataset['manual_count'] ) ); ?> manual</li>
					</ul>
				</div>
			</div>
		</div>

		<div class="postbox quorlyx-card">
			<h2 class="hndle"><span><span class="dashicons dashicons-chart-line"></span> Decision Support Report</span></h2>
			<div class="inside">
									<h2 class="nav-tab-wrapper quorlyx-insight-tabs" style="margin-bottom: 20px;">
						<a href="<?php echo esc_url( add_query_arg( 'insight_tab', 'products', admin_url( 'admin.php?page=quorlyx-content-insights' ) ) ); ?>" class="nav-tab <?php echo 'products' === $current_tab ? 'nav-tab-active' : ''; ?>"><span class="dashicons dashicons-cart" style="line-height: 1.5; margin-right: 5px;"></span> Products Checkout Funnel</a>
						<a href="<?php echo esc_url( add_query_arg( 'insight_tab', 'content', admin_url( 'admin.php?page=quorlyx-content-insights' ) ) ); ?>" class="nav-tab <?php echo 'content' === $current_tab ? 'nav-tab-active' : ''; ?>"><span class="dashicons dashicons-media-document" style="line-height: 1.5; margin-right: 5px;"></span> Posts & Pages Performance</a>
						<a href="<?php echo esc_url( add_query_arg( 'insight_tab', 'behavior', admin_url( 'admin.php?page=quorlyx-content-insights' ) ) ); ?>" class="nav-tab <?php echo 'behavior' === $current_tab ? 'nav-tab-active' : ''; ?>"><span class="dashicons dashicons-groups" style="line-height: 1.5; margin-right: 5px;"></span> Behavior Patterns</a>
						<a href="<?php echo esc_url( add_query_arg( 'insight_tab', 'import', admin_url( 'admin.php?page=quorlyx-content-insights' ) ) ); ?>" class="nav-tab <?php echo 'import' === $current_tab ? 'nav-tab-active' : ''; ?>"><span class="dashicons dashicons-download" style="line-height: 1.5; margin-right: 5px;"></span> Import Historical Data</a>
					</h2>

<form method="get" action="<?php echo esc_url( admin_url( 'admin.php' ) ); ?>" style="display:<?php echo 'import' === $current_tab ? 'none' : 'flex'; ?>; gap:10px; align-items:center; flex-wrap:wrap; margin-bottom:15px;">
					<input type="hidden" name="page" value="quorlyx-content-insights">
					<input type="hidden" name="insight_tab" value="<?php echo esc_attr( $current_tab ); ?>">
					<select name="insights_sort">
						<option value="opportunity_asc" <?php selected( $sort, 'opportunity_asc' ); ?>>Lowest opportunity score</option>
						<option value="opportunity_desc" <?php selected( $sort, 'opportunity_desc' ); ?>>Highest opportunity score</option>
						<option value="source_asc" <?php selected( $sort, 'source_asc' ); ?>>Source A-Z</option>
						<option value="source_desc" <?php selected( $sort, 'source_desc' ); ?>>Source Z-A</option>
						<option value="type_asc" <?php selected( $sort, 'type_asc' ); ?>>Type A-Z</option>
						<option value="type_desc" <?php selected( $sort, 'type_desc' ); ?>>Type Z-A</option>
						<option value="views_asc" <?php selected( $sort, 'views_asc' ); ?>>Fewest views</option>
						<option value="conversion_rate_desc" <?php selected( $sort, 'conversion_rate_desc' ); ?>>Best conversion rate</option>
						<option value="conversion_rate_asc" <?php selected( $sort, 'conversion_rate_asc' ); ?>>Lowest conversion rate</option>
						<option value="conversions_asc" <?php selected( $sort, 'conversions_asc' ); ?>>Fewest conversions</option>
						<option value="conversions_desc" <?php selected( $sort, 'conversions_desc' ); ?>>Most conversions</option>
						<option value="views_desc" <?php selected( $sort, 'views_desc' ); ?>>Most views</option>
						<option value="time_asc" <?php selected( $sort, 'time_asc' ); ?>>Shortest average time</option>
						<option value="time_desc" <?php selected( $sort, 'time_desc' ); ?>>Longest average time</option>
						<option value="scroll_asc" <?php selected( $sort, 'scroll_asc' ); ?>>Lowest scroll depth</option>
						<option value="scroll_desc" <?php selected( $sort, 'scroll_desc' ); ?>>Highest scroll depth</option>
						<?php if ( 'products' === $current_tab ) : ?>
						<option value="add_to_cart_asc" <?php selected( $sort, 'add_to_cart_asc' ); ?>>Fewest add to cart</option>
						<option value="add_to_cart_desc" <?php selected( $sort, 'add_to_cart_desc' ); ?>>Most add to cart</option>
						<option value="checkout_flow_asc" <?php selected( $sort, 'checkout_flow_asc' ); ?>>Lowest checkout flow</option>
						<option value="checkout_flow_desc" <?php selected( $sort, 'checkout_flow_desc' ); ?>>Highest checkout flow</option>
						<?php endif; ?>
						<option value="title_asc" <?php selected( $sort, 'title_asc' ); ?>>Title A-Z</option>
						<option value="title_desc" <?php selected( $sort, 'title_desc' ); ?>>Title Z-A</option>
					</select>
					<button type="submit" class="button">Apply</button>
				</form>

				<?php if ( ! $has_any_items && 'import' !== $current_tab ) : ?>
					<?php if ( ! $has_scope_rules ) : ?>
						<p>No tracked items are configured yet. Add post types or target page URL rules in Settings to start this report.</p>
					<?php elseif ( 'import' !== $current_tab ) : ?>
						<p>No insights data is available yet for your tracked content. Keep Content Insights enabled and collect visitor activity, then refresh this report.</p>
					<?php endif; ?>
				<?php else : ?>
					<?php
					$product_rows = array();
					$content_rows = array();
					foreach ( $insight_rows as $row ) {
						if ( in_array( (string) ( $row['post_type'] ?? '' ), array( 'product', 'product_variation' ), true ) ) {
							$product_rows[] = $row;
						} else {
							$content_rows[] = $row;
						}
					}
					?>

					

					<?php if ( 'products' === $current_tab ) : ?>
					<div class="quorlyx-insight-tab-panel">
						<h3 style="margin:0 0 8px;"><span class="dashicons dashicons-cart" style="line-height:1.4;"></span> Product Checkout Insights</h3>
						<p class="description" style="margin:0 0 10px;">Commerce-focused rows with cart and checkout funnel metrics.</p>
						<?php if ( empty( $product_rows ) ) : ?>
							<p style="margin:0 0 18px;">No products found.</p>
						<?php else : ?>
						<div class="quorlyx-table-wrap quorlyx-insights-table-wrap">
						<table class="widefat striped">
							<thead>
								<tr>
									<th>Product</th>
									<th>Source <button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="1" data-sort-type="text" data-sort-dir="asc" title="Sort A to Z">&uarr;</button><button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="1" data-sort-type="text" data-sort-dir="desc" title="Sort Z to A">&darr;</button></th>
									<th>Type <button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="2" data-sort-type="text" data-sort-dir="asc" title="Sort A to Z">&uarr;</button><button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="2" data-sort-type="text" data-sort-dir="desc" title="Sort Z to A">&darr;</button></th>
									<th>Views <button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="3" data-sort-type="number" data-sort-dir="asc" title="Sort low to high">&uarr;</button><button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="3" data-sort-type="number" data-sort-dir="desc" title="Sort high to low">&darr;</button></th>
									<th>Avg. Time <button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="4" data-sort-type="number" data-sort-dir="asc" title="Sort low to high">&uarr;</button><button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="4" data-sort-type="number" data-sort-dir="desc" title="Sort high to low">&darr;</button></th>
									<th>Scroll <button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="5" data-sort-type="number" data-sort-dir="asc" title="Sort low to high">&uarr;</button><button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="5" data-sort-type="number" data-sort-dir="desc" title="Sort high to low">&darr;</button></th>
									<th>Add to Cart <button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="6" data-sort-type="number" data-sort-dir="asc" title="Sort low to high">&uarr;</button><button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="6" data-sort-type="number" data-sort-dir="desc" title="Sort high to low">&darr;</button></th>
									<th>Checkout Flow <button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="7" data-sort-type="checkout" data-sort-dir="asc" title="Sort low to high">&uarr;</button><button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="7" data-sort-type="checkout" data-sort-dir="desc" title="Sort high to low">&darr;</button></th>
									<th>Conversions <button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="8" data-sort-type="number" data-sort-dir="asc" title="Sort low to high">&uarr;</button><button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="8" data-sort-type="number" data-sort-dir="desc" title="Sort high to low">&darr;</button></th>
									<th>Conv. Rate <button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="9" data-sort-type="number" data-sort-dir="asc" title="Sort low to high">&uarr;</button><button type="button" class="button-link quorlyx-sort-arrow" data-sort-index="9" data-sort-type="number" data-sort-dir="desc" title="Sort high to low">&darr;</button></th>
									<th>Opportunity</th>
									<th>Before/After Trigger</th>
									<th>Decision</th>
									<th>Suggested Change</th>
								</tr>
							</thead>
							<tbody>
								<?php foreach ( $product_rows as $row ) : ?>
									<?php
									$target_rule               = quorlyx_get_trigger_target_rule_from_url( (string) ( $row['public_url'] ?? '' ) );
									$suggested_trigger_url     = '';
									$cart_recovery_trigger_url = '';
									if ( '' !== $target_rule ) {
										$suggested_trigger_url     = wp_nonce_url(
