/**
 * Approximate the Gauss error function.
 *
 * @param float $x Input value.
 * @return float
 */
function quorlyx_erf( $x ) {
	$a1   = 0.254829592;
	$a2   = -0.284496736;
	$a3   = 1.421413741;
	$a4   = -1.453152027;
	$a5   = 1.061405429;
	$p    = 0.3275911;
	$sign = 1;
	if ( $x < 0 ) {
		$sign = -1;
	}
	$x = abs( $x );
	$t = 1.0 / ( 1.0 + $p * $x );
	$y = 1.0 - ( ( ( ( ( ( $a5 * $t + $a4 ) * $t ) + $a3 ) * $t + $a2 ) * $t + $a1 ) * $t * exp( -$x * $x ) );
	return $sign * $y;
}

/**
 * Convert a z-score to a two-tailed p-value approximation.
 *
 * @param float $z Z-score.
 * @return float
 */
function quorlyx_get_p_value_from_z_score( $z ) {
	return 1.0 - quorlyx_erf( abs( $z ) / sqrt( 2.0 ) );
}

/**
 * Calculate A/B winner confidence using a pooled z-test approximation.
 *
 * @param array<string,array<string,int>> $stats A/B views and conversions.
 * @return array<string,int|float|string>
 */
function quorlyx_calculate_ab_confidence( $stats ) {
	$views_a = $stats['a']['views'];
	$conv_a  = $stats['a']['conversions'];
	$views_b = $stats['b']['views'];
	$conv_b  = $stats['b']['conversions'];

	if ( $views_a < 20 || $views_b < 20 ) {
		return array(
			'winner'          => 'none',
			'winner_text'     => 'Testing... (more data needed)',
			'confidence'      => 0,
			'confidence_text' => 'N/A',
		);
	}

	$p1 = ( $views_a > 0 ) ? $conv_a / $views_a : 0;
	$p2 = ( $views_b > 0 ) ? $conv_b / $views_b : 0;

	if ( abs( $p1 - $p2 ) < 1.0e-9 ) {
		return array(
			'winner'          => 'none',
			'winner_text'     => 'Currently a tie',
			'confidence'      => 50,
			'confidence_text' => '~50%',
		);
	}

	$p_pooled = ( $conv_a + $conv_b ) / ( $views_a + $views_b );
	if ( 0.0 === $p_pooled || 1.0 === $p_pooled ) {
		return array(
			'winner'          => 'none',
			'winner_text'     => 'Testing...',
			'confidence'      => 0,
			'confidence_text' => 'N/A',
		);
	}

	$se = sqrt( $p_pooled * ( 1 - $p_pooled ) * ( 1 / $views_a + 1 / $views_b ) );
	if ( 0.0 === $se ) {
		return array(
			'winner'          => 'none',
			'winner_text'     => 'Testing...',
			'confidence'      => 0,
			'confidence_text' => 'N/A',
		);
	}

	$z_score    = ( $p1 - $p2 ) / $se;
	$p_value    = quorlyx_get_p_value_from_z_score( $z_score );
	$confidence = ( 1 - $p_value ) * 100;

	$winner      = 'none';
	$winner_text = 'Testing...';
	if ( $confidence >= 95 ) {
		$winner      = ( $p1 > $p2 ) ? 'a' : 'b';
		$winner_text = 'Winner: ' . strtoupper( $winner );
	}

	return array(
		'winner'          => $winner,
		'winner_text'     => $winner_text,
		'confidence'      => $confidence,
		'confidence_text' => number_format_i18n( $confidence, 2 ) . '%',
	);
}

/**
 * Refresh cached conversation statistics when stale or forced.
 *
 * @param bool $force Whether to bypass the staleness window.
 * @return void
 */
function quorlyx_maybe_refresh_conversation_stats( $force = false ) {
	$max_age_seconds = 60;
	$last_updated    = absint( get_option( 'quorlyx_conversation_stats_updated_at', 0 ) );
	if ( ! $force && $last_updated > 0 && ( time() - $last_updated ) < $max_age_seconds ) {
		return;
	}

	quorlyx_calculate_conversation_stats();
}

/**
 * Recompute conversation statistics for dashboard cards.
 *
 * @return void
 */
function quorlyx_calculate_conversation_stats() {
	global $wpdb;
	$stats = array(
		'a' => array(
			'total'          => 0,
			'avg_messages'   => 0,
			'source_trigger' => 0,
			'source_normal'  => 0,
		),
		'b' => array(
			'total'          => 0,
			'avg_messages'   => 0,
			'source_trigger' => 0,
			'source_normal'  => 0,
		),
	);

	if ( quorlyx_conversations_table_exists() ) {
		$table_name = quorlyx_get_conversations_table_name();
		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Aggregate over compact indexed Quorlyx table.
		$rows = $wpdb->get_results(
			"SELECT
				CASE WHEN LOWER(variation) = 'b' THEN 'b' ELSE 'a' END AS variation,
				COUNT(id) AS total_convos,
				SUM(message_count) AS total_messages,
				SUM(CASE WHEN LOWER(source) = 'trigger' THEN 1 ELSE 0 END) AS trigger_convos,
				SUM(CASE WHEN LOWER(source) = 'trigger' THEN 0 ELSE 1 END) AS normal_convos
			FROM {$table_name}
			GROUP BY variation"
		);

		foreach ( (array) $rows as $row ) {
			$variation = ( 'b' === $row->variation ) ? 'b' : 'a';
			$total     = (int) $row->total_convos;

			$stats[ $variation ]['total']          = $total;
			$stats[ $variation ]['avg_messages']   = $total > 0 ? ( (int) $row->total_messages / $total ) : 0;
			$stats[ $variation ]['source_trigger'] = (int) $row->trigger_convos;
			$stats[ $variation ]['source_normal']  = (int) $row->normal_convos;
		}

		update_option( 'quorlyx_conversation_stats', $stats, false );
		update_option( 'quorlyx_conversation_stats_updated_at', time(), false );
		return;
	}

	$sql_convos = "SELECT
			CASE
				WHEN LOWER(COALESCE(v.meta_value, 'a')) = 'b' THEN 'b'
				ELSE 'a'
			END as variation,
			COUNT(p.ID) as total_convos,
			SUM(
				CASE
					WHEN LOWER(COALESCE(s.meta_value, 'normal')) = 'trigger' THEN 1
					ELSE 0
				END
			) as trigger_convos,
			SUM(
				CASE
					WHEN LOWER(COALESCE(s.meta_value, 'normal')) = 'trigger' THEN 0
					ELSE 1
				END
			) as normal_convos
		FROM {$wpdb->posts} as p
		LEFT JOIN {$wpdb->postmeta} as v ON p.ID = v.post_id AND v.meta_key = 'quorlyx_ab_variation'
		LEFT JOIN {$wpdb->postmeta} as s ON p.ID = s.post_id AND s.meta_key = 'quorlyx_source'
		WHERE p.post_type = 'quorlyx_conversation'
		AND p.post_status = 'private'
		GROUP BY variation";
	// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared, WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Aggregation requires custom query.
	$convo_results = $wpdb->get_results( $sql_convos );

	$sql_messages = "SELECT
			CASE
				WHEN LOWER(COALESCE(v.meta_value, 'a')) = 'b' THEN 'b'
				ELSE 'a'
			END as variation,
			SUM(
				CASE
					WHEN m.meta_value REGEXP '^[0-9]+$' THEN CAST(m.meta_value AS UNSIGNED)
					ELSE 0
				END
			) as total_messages
		FROM {$wpdb->posts} as p
		LEFT JOIN {$wpdb->postmeta} as v ON p.ID = v.post_id AND v.meta_key = 'quorlyx_ab_variation'
		LEFT JOIN {$wpdb->postmeta} as m ON p.ID = m.post_id AND m.meta_key = 'quorlyx_message_count'
		WHERE p.post_type = 'quorlyx_conversation'
		AND p.post_status = 'private'
		GROUP BY variation";
	// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared, WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Aggregation requires custom query.
	$message_results = $wpdb->get_results( $sql_messages );

	$total_convos_map = array();
	foreach ( $convo_results as $row ) {
		if ( 'a' === $row->variation || 'b' === $row->variation ) {
			$stats[ $row->variation ]['total']          = (int) $row->total_convos;
			$stats[ $row->variation ]['source_trigger'] = isset( $row->trigger_convos ) ? (int) $row->trigger_convos : 0;
			$stats[ $row->variation ]['source_normal']  = isset( $row->normal_convos ) ? (int) $row->normal_convos : 0;
			$total_convos_map[ $row->variation ]        = (int) $row->total_convos;
		}
	}

	foreach ( $message_results as $row ) {
		if ( 'a' === $row->variation || 'b' === $row->variation ) {
				$total_messages                       = (int) $row->total_messages;
				$total_convos                         = $total_convos_map[ $row->variation ] ?? 0;
			$stats[ $row->variation ]['avg_messages'] = ( $total_convos > 0 ) ? $total_messages / $total_convos : 0;
		}
	}

	update_option( 'quorlyx_conversation_stats', $stats, false );
	update_option( 'quorlyx_conversation_stats_updated_at', time(), false );
}
add_action( 'admin_init', 'quorlyx_handle_dashboard_actions' );

/**
 * Process dashboard POST actions such as declaring an A/B winner.
 *
 * @return void
 */
function quorlyx_handle_dashboard_actions() {
	if ( isset( $_POST['quorlyx_declare_winner'] ) && check_admin_referer( 'quorlyx_declare_winner_action', 'quorlyx_declare_winner_nonce' ) ) {
		$winner = isset( $_POST['winner_variation'] ) ? sanitize_key( wp_unslash( $_POST['winner_variation'] ) ) : '';
		if ( 'a' === $winner || 'b' === $winner ) {
			$options                       = get_option( 'quorlyx_options', array() );
			$options['variation_a']        = $options[ "variation_{$winner}" ] ?? array();
			$options['variation_b']        = $options[ "variation_{$winner}" ] ?? array();
			$options['ab_testing_enabled'] = false;
			update_option( 'quorlyx_options', $options );
			add_action(
				'admin_notices',
				function () use ( $winner ) {
					$message = sprintf(
						'Variation %s has been implemented and the A/B test has been concluded.',
						strtoupper( $winner )
					);
					echo '<div class="notice notice-success is-dismissible"><p>' . esc_html( $message ) . '</p></div>';
				}
			);
		}
	}
}

/**
 * Queue a stats recalculation when conversation posts change lifecycle state.
 *
 * @param int $post_id Post ID.
 * @return void
 */
function quorlyx_handle_conversation_post_change( $post_id ) {
	if ( 'quorlyx_conversation' === get_post_type( $post_id ) ) {
		wp_schedule_single_event( time(), 'quorlyx_recalculate_stats_event' );
	}
}
add_action( 'trashed_post', 'quorlyx_handle_conversation_post_change' );
add_action( 'untrashed_post', 'quorlyx_handle_conversation_post_change' );
add_action( 'deleted_post', 'quorlyx_handle_conversation_post_change' );

/**
 * Execute deferred conversation stat recalculation event.
 *
 * @return void
 */
function quorlyx_run_recalculation() {
	quorlyx_calculate_conversation_stats();
}
add_action( 'quorlyx_recalculate_stats_event', 'quorlyx_run_recalculation' );

/**
 * Resolve the post types selected as Knowledge Base sources.
 *
 * A missing key means legacy/default settings, so Pages remain the default.
 * An explicitly empty saved value means the admin unchecked every post type.
 *
 * @param array<string,mixed> $settings Variation settings.
 * @return array<int,string>
 */
function quorlyx_get_selected_knowledge_base_post_types( $settings ) {
	$settings  = is_array( $settings ) ? $settings : array();
	$raw_types = array_key_exists( 'knowledge_base_post_types', $settings )
		? $settings['knowledge_base_post_types']
		: array( 'page' );

	if ( ! is_array( $raw_types ) ) {
		$raw_types = array( $raw_types );
	}

	$blocked_types = array( 'attachment', 'quorlyx_submission', 'quorlyx_conversation' );
	$types         = array();

	foreach ( $raw_types as $raw_type ) {
		$post_type = sanitize_key( (string) $raw_type );
		if ( '' === $post_type || in_array( $post_type, $blocked_types, true ) || ! post_type_exists( $post_type ) ) {
			continue;
		}

		$post_type_object = get_post_type_object( $post_type );
		if ( ! $post_type_object || empty( $post_type_object->public ) ) {
			continue;
		}

		$types[] = $post_type;
	}

	return array_values( array_unique( $types ) );
}

/**
 * Resolve uploaded attachment IDs selected as Knowledge Base sources.
 *
 * @param array<string,mixed> $settings Variation settings.
 * @param bool                $ensure_private Whether to require private file storage.
 * @return array<int,int>
 */
function quorlyx_get_selected_knowledge_base_file_ids( $settings, $ensure_private = false ) {
	$settings       = is_array( $settings ) ? $settings : array();
	$raw_ids        = $settings['knowledge_base_file_ids'] ?? array();
	$ensure_private = (bool) $ensure_private;

	if ( is_string( $raw_ids ) ) {
		$raw_ids = preg_split( '/[\s,]+/', $raw_ids );
	}
	if ( ! is_array( $raw_ids ) ) {
		$raw_ids = array( $raw_ids );
	}

	$file_ids = array();
	foreach ( $raw_ids as $raw_id ) {
		$file_id = absint( $raw_id );
		if ( $file_id <= 0 || 'attachment' !== get_post_type( $file_id ) ) {
			continue;
		}

		if ( ! quorlyx_is_allowed_knowledge_base_file_mime( (string) get_post_mime_type( $file_id ) ) ) {
			continue;
		}

		if ( $ensure_private && ! quorlyx_ensure_knowledge_base_attachment_private( $file_id ) ) {
			continue;
		}

		$file_ids[] = $file_id;
	}

	return array_values( array_unique( $file_ids ) );
}

/**
 * Check whether an attachment MIME type can be used as uploaded KB context.
 *
 * @param string $mime MIME type.
 * @return bool
 */
function quorlyx_is_allowed_knowledge_base_file_mime( $mime ) {
	$mime    = strtolower( trim( (string) $mime ) );
	$allowed = array(
		'application/pdf',
		'text/plain',
		'text/markdown',
		'text/x-markdown',
		'text/csv',
		'application/csv',
		'application/json',
		'text/html',
		'application/xml',
		'text/xml',
	);

	return in_array( $mime, $allowed, true );
}

/**
 * Get the private Knowledge Base storage directory.
 *
 * @return string
 */
function quorlyx_get_private_knowledge_base_dir() {
	$root = defined( 'ABSPATH' ) ? dirname( untrailingslashit( ABSPATH ) ) : WP_CONTENT_DIR;
	$dir  = trailingslashit( $root ) . 'quorlyx-private-kb';

	return untrailingslashit( wp_normalize_path( (string) apply_filters( 'quorlyx_private_knowledge_base_dir', $dir ) ) );
}

/**
 * Prepare private Knowledge Base storage.
 *
 * @return string Empty string when private storage is unavailable.
 */
function quorlyx_prepare_private_knowledge_base_dir() {
	$dir = quorlyx_get_private_knowledge_base_dir();
	if ( '' === $dir ) {
		return '';
	}

	if ( ! wp_mkdir_p( $dir ) || ! is_dir( $dir ) || ! is_writable( $dir ) ) {
		return '';
	}

	$index_path = trailingslashit( $dir ) . 'index.php';
	if ( ! file_exists( $index_path ) ) {
		@file_put_contents( $index_path, "<?php\n// Silence is golden.\n" ); // phpcs:ignore WordPress.PHP.NoSilencedErrors.Discouraged, WordPress.WP.AlternativeFunctions.file_system_operations_file_put_contents
	}

	$htaccess_path = trailingslashit( $dir ) . '.htaccess';
	if ( ! file_exists( $htaccess_path ) ) {
		@file_put_contents( $htaccess_path, "Require all denied\nDeny from all\n" ); // phpcs:ignore WordPress.PHP.NoSilencedErrors.Discouraged, WordPress.WP.AlternativeFunctions.file_system_operations_file_put_contents
	}

	$web_config_path = trailingslashit( $dir ) . 'web.config';
	if ( ! file_exists( $web_config_path ) ) {
		@file_put_contents( $web_config_path, "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<configuration><system.webServer><authorization><deny users=\"*\" /></authorization></system.webServer></configuration>\n" ); // phpcs:ignore WordPress.PHP.NoSilencedErrors.Discouraged, WordPress.WP.AlternativeFunctions.file_system_operations_file_put_contents
	}

	return $dir;
}

/**
 * Check whether a path lives inside a directory.
 *
 * @param string $path File path.
 * @param string $dir  Directory path.
 * @return bool
 */
function quorlyx_path_is_inside_dir( $path, $dir ) {
	$path_real = realpath( (string) $path );
	$dir_real  = realpath( (string) $dir );

	if ( false === $path_real || false === $dir_real ) {
		return false;
	}

	$path_real = trailingslashit( wp_normalize_path( $path_real ) );
	$dir_real  = trailingslashit( wp_normalize_path( $dir_real ) );

	return 0 === strpos( $path_real, $dir_real );
}

/**
 * Log a private Knowledge Base storage failure when the logger is available.
 *
 * @param int                 $attachment_id Attachment ID.
 * @param string              $reason        Failure reason.
 * @param array<string,mixed> $details       Extra details.
 * @return void
 */
function quorlyx_log_private_knowledge_base_failure( $attachment_id, $reason, $details = array() ) {
	if ( ! class_exists( 'Quorlyx_Pro_Logger' ) ) {
		return;
	}

	$details                   = is_array( $details ) ? $details : array();
	$details['component']      = 'knowledge_base';
	$details['operation']      = 'private_file_storage';
	$details['attachment_id']  = absint( $attachment_id );
	$details['failure_reason'] = sanitize_key( (string) $reason );

	Quorlyx_Pro_Logger::log(
		'warning',
		'Knowledge Base file was not added because private storage is unavailable',
		$details
	);
}

/**
 * Check whether a Knowledge Base attachment is already private.
 *
 * @param int $attachment_id Attachment ID.
 * @return bool
 */
function quorlyx_is_knowledge_base_attachment_private( $attachment_id ) {
	$attachment_id = absint( $attachment_id );
	if ( $attachment_id <= 0 ) {
		return false;
	}

	$file_path   = get_attached_file( $attachment_id );
	$private_dir = quorlyx_get_private_knowledge_base_dir();

	return is_string( $file_path ) && '' !== $file_path && quorlyx_path_is_inside_dir( $file_path, $private_dir );
}

/**
 * Move a Knowledge Base attachment out of the public uploads directory.
 *
 * @param int $attachment_id Attachment ID.
 * @return bool
 */
function quorlyx_ensure_knowledge_base_attachment_private( $attachment_id ) {
	$attachment_id = absint( $attachment_id );
	if ( $attachment_id <= 0 || 'attachment' !== get_post_type( $attachment_id ) ) {
		return false;
	}

	if ( ! quorlyx_is_allowed_knowledge_base_file_mime( (string) get_post_mime_type( $attachment_id ) ) ) {
		return false;
	}

	$file_path = get_attached_file( $attachment_id );
	if ( ! is_string( $file_path ) || '' === $file_path || ! file_exists( $file_path ) || ! is_readable( $file_path ) ) {
		quorlyx_log_private_knowledge_base_failure( $attachment_id, 'source_unreadable' );
		return false;
	}

	$private_dir = quorlyx_prepare_private_knowledge_base_dir();
	if ( '' === $private_dir ) {
		quorlyx_log_private_knowledge_base_failure( $attachment_id, 'private_dir_unavailable' );
		return false;
	}

	if ( quorlyx_path_is_inside_dir( $file_path, $private_dir ) ) {
		update_post_meta( $attachment_id, '_quorlyx_kb_private', 1 );
		if ( 'private' !== get_post_status( $attachment_id ) ) {
			wp_update_post(
				array(
					'ID'          => $attachment_id,
					'post_status' => 'private',
				)
			);
		}
		return true;
	}

	$attachment_dir = trailingslashit( $private_dir ) . $attachment_id;
	if ( ! wp_mkdir_p( $attachment_dir ) || ! is_dir( $attachment_dir ) || ! is_writable( $attachment_dir ) ) {
		quorlyx_log_private_knowledge_base_failure( $attachment_id, 'attachment_dir_unavailable' );
		return false;
	}

	$filename = sanitize_file_name( wp_basename( $file_path ) );
	if ( '' === $filename ) {
		$filename = 'knowledge-base-file-' . $attachment_id;
	}

	$target_filename = wp_unique_filename( $attachment_dir, $attachment_id . '-' . $filename );
	$target_path     = trailingslashit( $attachment_dir ) . $target_filename;
	$moved           = @rename( $file_path, $target_path ); // phpcs:ignore WordPress.PHP.NoSilencedErrors.Discouraged, WordPress.WP.AlternativeFunctions.rename_rename

	if ( ! $moved ) {
		$copied = @copy( $file_path, $target_path ); // phpcs:ignore WordPress.PHP.NoSilencedErrors.Discouraged, WordPress.WP.AlternativeFunctions.file_system_operations_copy
		if ( $copied ) {
			if ( ! @unlink( $file_path ) ) { // phpcs:ignore WordPress.PHP.NoSilencedErrors.Discouraged, WordPress.WP.AlternativeFunctions.unlink_unlink
				@unlink( $target_path ); // phpcs:ignore WordPress.PHP.NoSilencedErrors.Discouraged, WordPress.WP.AlternativeFunctions.unlink_unlink
				quorlyx_log_private_knowledge_base_failure( $attachment_id, 'source_delete_failed' );
				return false;
			}
			$moved = true;
		}
	}

	if ( ! $moved || ! file_exists( $target_path ) || ! is_readable( $target_path ) ) {
		quorlyx_log_private_knowledge_base_failure( $attachment_id, 'move_failed' );
		return false;
	}

	@chmod( $target_path, 0640 ); // phpcs:ignore WordPress.PHP.NoSilencedErrors.Discouraged, WordPress.WP.AlternativeFunctions.file_system_operations_chmod
	update_attached_file( $attachment_id, $target_path );
	update_post_meta( $attachment_id, '_quorlyx_kb_private', 1 );
	update_post_meta( $attachment_id, '_quorlyx_kb_private_at', time() );
	if ( 'private' !== get_post_status( $attachment_id ) ) {
		wp_update_post(
			array(
				'ID'          => $attachment_id,
				'post_status' => 'private',
			)
		);
	}
	clean_post_cache( $attachment_id );

	return true;
}

/**
 * Merge saved options with defaults while preserving explicit empty KB sources.
 *
 * array_replace_recursive() keeps numeric default array values when the saved
 * value is an empty array, so handle Knowledge Base post types separately.
 *
 * @param mixed $options Raw saved options.
 * @return array<string,mixed>
 */
function quorlyx_merge_global_options( $options ) {
	$defaults = quorlyx_get_global_defaults();
	$raw      = is_array( $options ) ? $options : array();
	$merged   = array_replace_recursive( $defaults, $raw );
	$allowed_provider_keys = array( 'gemini', 'openai', 'anthropic', 'grok', 'mistral', 'deepseek' );

	foreach ( array( 'variation_a', 'variation_b' ) as $variation_key ) {
		if (
			isset( $raw[ $variation_key ] )
			&& is_array( $raw[ $variation_key ] )
			&& array_key_exists( 'knowledge_base_post_types', $raw[ $variation_key ] )
			&& is_array( $raw[ $variation_key ]['knowledge_base_post_types'] )
			&& empty( $raw[ $variation_key ]['knowledge_base_post_types'] )
		) {
			$merged[ $variation_key ]['knowledge_base_post_types'] = array();
		}

		$variation_provider = sanitize_key( $merged[ $variation_key ]['ai_provider'] ?? 'gemini' );
		if ( ! in_array( $variation_provider, $allowed_provider_keys, true ) ) {
			$merged[ $variation_key ]['ai_provider'] = 'gemini';
		}
		if ( isset( $merged[ $variation_key ]['api_keys'] ) && is_array( $merged[ $variation_key ]['api_keys'] ) ) {
			$merged[ $variation_key ]['api_keys'] = array_replace(
				$defaults[ $variation_key ]['api_keys'],
				array_intersect_key( $merged[ $variation_key ]['api_keys'], array_flip( $allowed_provider_keys ) )
			);
		}
	}

	if ( isset( $merged['post_generator'] ) && is_array( $merged['post_generator'] ) ) {
		$postgen_provider = sanitize_key( $merged['post_generator']['ai_provider'] ?? 'gemini' );
		if ( ! in_array( $postgen_provider, $allowed_provider_keys, true ) ) {
			$merged['post_generator']['ai_provider'] = 'gemini';
		}
	}

	if ( isset( $merged['performance'] ) && is_array( $merged['performance'] ) ) {
		foreach ( array( 'model_routing_provider', 'fallback_provider' ) as $provider_key ) {
			$performance_provider = sanitize_key( $merged['performance'][ $provider_key ] ?? '' );
			if ( '' !== $performance_provider && ! in_array( $performance_provider, $allowed_provider_keys, true ) ) {
				$merged['performance'][ $provider_key ] = '';
			}
		}
	}

	return $merged;
}

/**
 * Build optional behavior-pattern context as a Knowledge Base source.
 *
 * @return string
 */
function quorlyx_get_behavior_knowledge_base_context() {
	if ( ! quorlyx_behavior_patterns_are_enabled() ) {
		return '';
	}

	global $wpdb;

	$table_name = quorlyx_get_behavior_engine_table_name();

	// phpcs:disable WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Aggregate behavior context powers optional KB source; table name comes from trusted helper with wpdb prefix.
	$summary = $wpdb->get_row(
		"SELECT COUNT(*) AS total_profiles, SUM(CASE WHEN conversion_status IN ('closer','buyer') THEN 1 ELSE 0 END) AS closers, SUM(CASE WHEN conversion_status = 'non_converter' THEN 1 ELSE 0 END) AS non_converters, SUM(CASE WHEN started_chat = 1 THEN 1 ELSE 0 END) AS started_chat_profiles FROM {$table_name}",
		ARRAY_A
	);
	// phpcs:enable WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared

	if ( ! is_array( $summary ) && '' !== (string) $wpdb->last_error ) {
		quorlyx_behavior_log_event_once(
			'behavior_kb_summary_query_failed',
			'error',
			'Behavior Knowledge Base context query failed',
			array(
				'component' => 'behavior_engine',
				'operation' => 'behavior_kb_context',
				'phase'     => 'summary_query',
				'db_error'  => sanitize_text_field( (string) $wpdb->last_error ),
			),
			1800
		);

		return '';
	}

	$total_profiles = absint( $summary['total_profiles'] ?? 0 );
	if ( $total_profiles <= 0 ) {
		return '';
	}

	// phpcs:disable WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Aggregate behavior context powers optional KB source; table name comes from trusted helper with wpdb prefix.
	$pattern_rows = $wpdb->get_results(
		"SELECT pattern_tag, COUNT(*) AS total FROM {$table_name} GROUP BY pattern_tag ORDER BY total DESC",
		ARRAY_A
	);
	// phpcs:enable WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared

	if ( null === $pattern_rows && '' !== (string) $wpdb->last_error ) {
		quorlyx_behavior_log_event_once(
			'behavior_kb_pattern_query_failed',
			'error',
			'Behavior Knowledge Base pattern mix query failed',
			array(
				'component' => 'behavior_engine',
				'operation' => 'behavior_kb_context',
				'phase'     => 'pattern_mix_query',
				'db_error'  => sanitize_text_field( (string) $wpdb->last_error ),
			),
			1800
		);

		$pattern_rows = array();
	}

	$pattern_mix = array();
	$top_pattern = 'unknown';
	$top_count   = 0;

	foreach ( (array) $pattern_rows as $pattern_row ) {
		$pattern_tag = sanitize_key( (string) ( $pattern_row['pattern_tag'] ?? 'unknown' ) );
		$count       = absint( $pattern_row['total'] ?? 0 );
		if ( $count <= 0 ) {
			continue;
		}

		if ( $count > $top_count ) {
			$top_count   = $count;
			$top_pattern = $pattern_tag;
		}

		$pattern_mix[] = quorlyx_get_behavior_pattern_label( $pattern_tag ) . ': ' . number_format_i18n( $count );
		if ( count( $pattern_mix ) >= 5 ) {
			break;
		}
	}

	$lines = array(
		'BEHAVIOR PATTERN KNOWLEDGE SOURCE',
		'- Total tracked profiles: ' . number_format_i18n( $total_profiles ),
		'- Closers: ' . number_format_i18n( absint( $summary['closers'] ?? 0 ) ),
		'- Non-converters: ' . number_format_i18n( absint( $summary['non_converters'] ?? 0 ) ),
		'- Started chats: ' . number_format_i18n( absint( $summary['started_chat_profiles'] ?? 0 ) ),
		'- Top pattern: ' . quorlyx_get_behavior_pattern_label( $top_pattern ),
	);

	if ( ! empty( $pattern_mix ) ) {
		$lines[] = '- Pattern mix: ' . implode( ' | ', $pattern_mix );
	}

	$focus_note = quorlyx_get_behavior_pattern_focus_note( $top_pattern );
	if ( '' !== trim( $focus_note ) ) {
		$lines[] = '- Optimization focus: ' . sanitize_text_field( $focus_note );
	}

	return implode( "\n", $lines );
}

/**
 * Convert rendered HTML into compact visible text for Knowledge Base context.
 *
 * @param string $html      Rendered HTML.
 * @param int    $max_chars Maximum returned characters.
 * @return string
 */
function quorlyx_extract_visible_text_from_html( $html, $max_chars = 5000 ) {
	$html = is_string( $html ) ? trim( $html ) : '';
	if ( '' === $html ) {
		return '';
	}

	$html = preg_replace( '#<(script|style|noscript|svg|canvas|iframe|form)\b[^>]*>.*?</\1>#is', ' ', $html );
	$html = preg_replace( '#</?(p|div|section|article|header|footer|li|ul|ol|h[1-6]|tr|td|th)\b[^>]*>|<br\s*/?>#i', "\n", $html );

	$charset = get_bloginfo( 'charset' );
	$text    = html_entity_decode( wp_strip_all_tags( (string) $html ), ENT_QUOTES | ENT_HTML5, $charset ? $charset : 'UTF-8' );
	$text    = preg_replace( '/[ \t\r\f\v]+/', ' ', $text );
	$text    = preg_replace( '/ *\n */', "\n", $text );
	$text    = preg_replace( '/\n{3,}/', "\n\n", $text );
	$text    = trim( (string) $text );

	$max_chars = max( 500, absint( $max_chars ) );
	if ( function_exists( 'mb_substr' ) ) {
		return mb_substr( $text, 0, $max_chars );
	}

	return substr( $text, 0, $max_chars );
}

/**
 * Extract a rendered HTML element by id from a page document.
 *
 * @param string $html       Rendered HTML document.
 * @param string $element_id Element id.
 * @return string
 */
function quorlyx_extract_html_element_by_id( $html, $element_id ) {
	$html       = is_string( $html ) ? $html : '';
	$element_id = sanitize_key( $element_id );
	if ( '' === $html || '' === $element_id ) {
		return '';
	}

	$pattern = '#<([a-z0-9:-]+)\b(?=[^>]*\bid\s*=\s*([\'"])' . preg_quote( $element_id, '#' ) . '\2)[^>]*>.*?</\1>#is';
	if ( preg_match( $pattern, $html, $matches ) ) {
		return (string) $matches[0];
	}

	return '';
}

/**
 * Fetch a rendered front-page section so theme-template content can be used as KB context.
 *
 * @param string              $section_id Front-page section id.
 * @param string              $label      Human-readable section label.
 * @param array<string,mixed> $perf       Performance settings.
 * @param int                 $max_chars  Maximum visible text characters.
 * @return string
 */
function quorlyx_get_rendered_front_page_section_context( $section_id, $label, $perf, $max_chars = 4500 ) {
	$section_id = sanitize_key( $section_id );
	$label      = trim( wp_strip_all_tags( (string) $label ) );
	if ( '' === $section_id || '' === $label ) {
		return '';
	}

	$home_url  = home_url( '/' );
	$cache_ttl = max( 60, absint( $perf['context_cache_ttl'] ?? HOUR_IN_SECONDS ) );
	$cache_key = 'quorlyx_home_section_' . md5( $home_url . '|' . $section_id . '|' . get_stylesheet() . '|' . get_template() );
	$cached    = quorlyx_cache_get( $cache_key, $perf, 'quorlyx_ctx' );
	if ( false !== $cached ) {
		return $cached;
	}

	$response = wp_remote_get(
		$home_url,
		array(
			'timeout'     => 4,
			'redirection' => 3,
			'headers'     => array(
				'Accept'                    => 'text/html',
				'X-Quorlyx-Knowledge-Base' => '1',
			),
			'sslverify'  => (bool) apply_filters( 'https_local_ssl_verify', false ),
		)
	);

	if ( is_wp_error( $response ) ) {
		quorlyx_cache_set( $cache_key, '', min( $cache_ttl, 10 * MINUTE_IN_SECONDS ), $perf, 'quorlyx_ctx' );
		return '';
	}

	$status_code = (int) wp_remote_retrieve_response_code( $response );
	if ( $status_code < 200 || $status_code >= 300 ) {
		quorlyx_cache_set( $cache_key, '', min( $cache_ttl, 10 * MINUTE_IN_SECONDS ), $perf, 'quorlyx_ctx' );
		return '';
	}

	$content_type = wp_remote_retrieve_header( $response, 'content-type' );
	if ( is_array( $content_type ) ) {
		$content_type = implode( ', ', $content_type );
	}
	if ( $content_type && false === stripos( (string) $content_type, 'text/html' ) ) {
		quorlyx_cache_set( $cache_key, '', min( $cache_ttl, 10 * MINUTE_IN_SECONDS ), $perf, 'quorlyx_ctx' );
		return '';
	}

	$html = wp_remote_retrieve_body( $response );
	if ( ! is_string( $html ) || '' === trim( $html ) ) {
		quorlyx_cache_set( $cache_key, '', min( $cache_ttl, 10 * MINUTE_IN_SECONDS ), $perf, 'quorlyx_ctx' );
		return '';
	}

	$section_html = quorlyx_extract_html_element_by_id( $html, $section_id );
	$text         = quorlyx_extract_visible_text_from_html( $section_html ? $section_html : $html, $max_chars );
	if ( '' === $text ) {
		quorlyx_cache_set( $cache_key, '', min( $cache_ttl, 10 * MINUTE_IN_SECONDS ), $perf, 'quorlyx_ctx' );
		return '';
	}

	$context  = strtoupper( $label ) . " (rendered front page section)\n";
	$context .= "URL: {$home_url}#{$section_id}\n";
	$context .= "Source: rendered active theme output. Use this for facts from theme options, hardcoded homepage sections, or other visible content that may not exist in WordPress page/post content.\n";
	$context .= "Visible text:\n" . $text;

	quorlyx_cache_set( $cache_key, $context, $cache_ttl, $perf, 'quorlyx_ctx' );
	return $context;
}

/**
 * Check whether a PHP function can be called in the current hosting environment.
 *
 * @param string $function Function name.
 * @return bool
 */
function quorlyx_function_available( $function ) {
	$function = trim( (string) $function );
	if ( '' === $function || ! function_exists( $function ) ) {
		return false;
	}

	$disabled = array_map( 'trim', explode( ',', (string) ini_get( 'disable_functions' ) ) );
	return ! in_array( $function, $disabled, true );
}

/**
 * Try extracting PDF text through the host's pdftotext binary when available.
 *
 * @param string $file_path Attachment path.
 * @param int    $max_chars Maximum returned characters.
 * @return string
 */
function quorlyx_extract_pdf_text_with_pdftotext( $file_path, $max_chars = 6000 ) {
	$file_path = (string) $file_path;
	if ( '' === $file_path || ! is_readable( $file_path ) || ! quorlyx_function_available( 'shell_exec' ) ) {
		return '';
	}

	$check_command = ( '\\' === DIRECTORY_SEPARATOR ) ? 'where pdftotext 2>NUL' : 'command -v pdftotext 2>/dev/null';
	$binary        = trim( (string) shell_exec( $check_command ) );
	if ( '' === $binary ) {
		return '';
	}

	$binary = preg_split( '/\r\n|\r|\n/', $binary );
	$binary = is_array( $binary ) ? trim( (string) $binary[0] ) : 'pdftotext';
	if ( '' === $binary ) {
		$binary = 'pdftotext';
	}

	$command = escapeshellarg( $binary ) . ' -layout -enc UTF-8 ' . escapeshellarg( $file_path ) . ' - 2>' . ( '\\' === DIRECTORY_SEPARATOR ? 'NUL' : '/dev/null' );
	$output  = shell_exec( $command );
	if ( ! is_string( $output ) || '' === trim( $output ) ) {
		return '';
	}

	$text = preg_replace( '/[ \t\r\f\v]+/', ' ', $output );
	$text = preg_replace( '/ *\n */', "\n", (string) $text );
	$text = preg_replace( '/\n{3,}/', "\n\n", (string) $text );
	$text = trim( (string) $text );

	$max_chars = max( 500, absint( $max_chars ) );
	return function_exists( 'mb_substr' ) ? mb_substr( $text, 0, $max_chars ) : substr( $text, 0, $max_chars );
}

/**
 * Extract text from an uploaded Knowledge Base attachment.
 *
 * @param int                 $attachment_id Attachment ID.
 * @param array<string,mixed> $perf          Performance settings.
 * @param int                 $max_chars     Maximum returned characters.
 * @return string
 */
function quorlyx_extract_knowledge_base_attachment_text( $attachment_id, $perf, $max_chars = 3000 ) {
	$attachment_id = absint( $attachment_id );
	if ( $attachment_id <= 0 || 'attachment' !== get_post_type( $attachment_id ) ) {
		return '';
	}

	$mime = strtolower( (string) get_post_mime_type( $attachment_id ) );
	if ( ! quorlyx_is_allowed_knowledge_base_file_mime( $mime ) ) {
		return '';
	}

	$file_path = get_attached_file( $attachment_id );
	if ( ! is_string( $file_path ) || '' === $file_path || ! is_readable( $file_path ) ) {
		return '';
	}

	$modified  = (string) get_post_modified_time( 'U', true, $attachment_id );
	$file_size = (int) @filesize( $file_path ); // phpcs:ignore WordPress.PHP.NoSilencedErrors.Discouraged -- Size lookup failure should not block KB context.
	$cache_ttl = max( 60, absint( $perf['context_cache_ttl'] ?? HOUR_IN_SECONDS ) );
	$cache_key = 'quorlyx_kb_file_' . md5( $attachment_id . '|' . $mime . '|' . $modified . '|' . $file_size . '|' . absint( $max_chars ) . '|' . QUORLYX_KB_CONTEXT_VERSION );
	$cached    = quorlyx_cache_get( $cache_key, $perf, 'quorlyx_ctx' );
	if ( false !== $cached ) {
		return (string) $cached;
	}

	$text      = '';
	$max_chars = max( 500, absint( $max_chars ) );

	if ( 'application/pdf' === $mime ) {
		$text = quorlyx_extract_pdf_text_with_pdftotext( $file_path, $max_chars );
	} else {
		$bytes_to_read = min( max( $max_chars * 4, 4096 ), 1024 * 1024 );
		$raw           = file_get_contents( $file_path, false, null, 0, $bytes_to_read );
		if ( is_string( $raw ) && '' !== $raw ) {
			if ( preg_match( '/html|xml/i', $mime ) ) {
				$text = quorlyx_extract_visible_text_from_html( $raw, $max_chars );
			} else {
				$text = html_entity_decode( wp_strip_all_tags( $raw ), ENT_QUOTES | ENT_HTML5, get_bloginfo( 'charset' ) ?: 'UTF-8' );
				$text = preg_replace( '/[ \t\r\f\v]+/', ' ', (string) $text );
				$text = preg_replace( '/ *\n */', "\n", (string) $text );
				$text = preg_replace( '/\n{3,}/', "\n\n", (string) $text );
				$text = trim( (string) $text );
				$text = function_exists( 'mb_substr' ) ? mb_substr( $text, 0, $max_chars ) : substr( $text, 0, $max_chars );
			}
		}
	}

	quorlyx_cache_set( $cache_key, $text, '' === $text ? min( $cache_ttl, 10 * MINUTE_IN_SECONDS ) : $cache_ttl, $perf, 'quorlyx_ctx' );
	return $text;
}

/**
 * Extract query keywords for lightweight KB file relevance scoring.
 *
 * @param string $user_question User question.
 * @return array<int,string>
 */
function quorlyx_get_context_query_terms( $user_question ) {
	$user_question = strtolower( wp_strip_all_tags( (string) $user_question ) );
	$parts         = preg_split( '/[^a-z0-9]+/i', $user_question, -1, PREG_SPLIT_NO_EMPTY );
	$stop_words    = array_flip(
		array(
			'about',
			'after',
			'again',
			'also',
			'and',
			'any',
			'are',
			'can',
			'could',
			'does',
			'for',
			'from',
			'give',
			'has',
			'have',
			'hello',
			'help',
			'how',
			'info',
			'information',
			'into',
			'its',
			'know',
			'like',
			'much',
			'need',
			'please',
			'show',
			'site',
			'tell',
			'that',
			'the',
			'their',
			'this',
			'what',
			'when',
			'where',
			'which',
			'with',
			'you',
			'your',
		)
	);
	$terms         = array();

	foreach ( (array) $parts as $part ) {
		$part = trim( (string) $part );
		if ( strlen( $part ) < 3 || isset( $stop_words[ $part ] ) ) {
			continue;
		}
		$terms[] = $part;
	}

	return array_values( array_unique( $terms ) );
}

/**
 * Build uploaded Knowledge Base files context.
 *
 * @param array<string,mixed> $settings      Variation settings.
 * @param string              $user_question User question.
 * @param array<string,mixed> $perf          Performance settings.
 * @return string
 */
function quorlyx_get_uploaded_knowledge_base_files_context( $settings, $user_question, $perf ) {
	$file_ids = quorlyx_get_selected_knowledge_base_file_ids( $settings, true );
	if ( empty( $file_ids ) || ! quorlyx_should_include_rendered_home_context( $user_question ) ) {
		return '';
	}

	$limit     = max( 1, min( 10, absint( $perf['knowledge_file_context_limit'] ?? 3 ) ) );
	$max_chars = max( 500, min( 20000, absint( $perf['knowledge_file_excerpt_chars'] ?? 3000 ) ) );
	$terms     = quorlyx_get_context_query_terms( $user_question );
	$items     = array();

	foreach ( $file_ids as $file_id ) {
		$title = get_the_title( $file_id );
		$mime  = (string) get_post_mime_type( $file_id );
		$text  = quorlyx_extract_knowledge_base_attachment_text( $file_id, $perf, $max_chars );

		$haystack = strtolower( $title . "\n" . $text );
		$score    = 0;
		foreach ( $terms as $term ) {
			if ( false !== strpos( $haystack, $term ) ) {
				++$score;
			}
		}

		$items[] = array(
			'id'    => $file_id,
			'title' => $title,
			'mime'  => $mime,
			'text'  => $text,
			'score' => $score,
		);
	}

	usort(
		$items,
		function ( $left, $right ) {
			if ( (int) $left['score'] === (int) $right['score'] ) {
				return (int) $left['id'] <=> (int) $right['id'];
			}
			return (int) $right['score'] <=> (int) $left['score'];
		}
	);

	$has_positive_match = false;
	foreach ( $items as $item ) {
		if ( (int) $item['score'] > 0 ) {
			$has_positive_match = true;
			break;
		}
	}

	$rows = array();
	foreach ( $items as $item ) {
		if ( count( $rows ) >= $limit ) {
			break;
		}
		if ( $has_positive_match && (int) $item['score'] <= 0 ) {
			continue;
		}

		$row  = 'File: ' . sanitize_text_field( (string) $item['title'] ) . "\n";
		$row .= 'MIME: ' . sanitize_text_field( (string) $item['mime'] ) . "\n";
		$row .= "Private source: uploaded Knowledge Base file. Do not reveal or link to this file. Use only the extracted text for answers.\n";
		if ( '' !== (string) $item['text'] ) {
			$row .= "Extracted text:\n" . (string) $item['text'];
		} else {
			$row .= 'Extracted text: unavailable. For PDFs, install the server pdftotext utility or upload a TXT/Markdown version for full Knowledge Base answers.';
		}
		$rows[] = $row;
	}

	if ( empty( $rows ) ) {
		return '';
	}

	return "UPLOADED KNOWLEDGE BASE FILES (PRIVATE, DO NOT LINK)\n" . implode( "\n\n", $rows );
}

/**
 * Check whether a URL is safe to fetch as public rendered Knowledge Base context.
 *
 * @param string $url Candidate URL.
 * @return bool
 */
function quorlyx_is_safe_rendered_knowledge_url( $url ) {
	$url = esc_url_raw( (string) $url );
	if ( '' === $url ) {
		return false;
	}

	$allowed_hosts = array_filter(
		array(
			wp_parse_url( home_url(), PHP_URL_HOST ),
			wp_parse_url( site_url(), PHP_URL_HOST ),
		)
	);
	$allowed_hosts = array_map( 'strtolower', $allowed_hosts );
	$url_host      = wp_parse_url( $url, PHP_URL_HOST );
	if ( ! $url_host || ! in_array( strtolower( $url_host ), $allowed_hosts, true ) ) {
		return false;
	}

	$path = (string) wp_parse_url( $url, PHP_URL_PATH );
	if ( preg_match( '#/(checkout|cart|account|my-account|wp-admin|wp-login|order|payment)(/|$)#i', $path ) ) {
		return false;
	}

	return true;
}

/**
 * Fetch visible text from a public same-site URL.
 *
 * @param string              $url       Public URL.
 * @param array<string,mixed> $perf      Performance settings.
 * @param int                 $max_chars Maximum visible text characters.
 * @return string
 */
function quorlyx_get_rendered_public_url_text( $url, $perf, $max_chars = 6000 ) {
	$url = esc_url_raw( (string) $url );
	if ( ! quorlyx_is_safe_rendered_knowledge_url( $url ) ) {
		return '';
	}

	$cache_ttl = max( 60, absint( $perf['context_cache_ttl'] ?? HOUR_IN_SECONDS ) );
	$cache_key = 'quorlyx_rendered_url_' . md5( $url . '|' . get_stylesheet() . '|' . get_template() . '|' . QUORLYX_KB_CONTEXT_VERSION );
	$cached    = quorlyx_cache_get( $cache_key, $perf, 'quorlyx_ctx' );
	if ( false !== $cached ) {
		return (string) $cached;
	}

	$response = wp_remote_get(
		$url,
		array(
			'timeout'     => 4,
			'redirection' => 3,
			'headers'     => array(
				'Accept'                    => 'text/html',
				'X-Quorlyx-Knowledge-Base' => '1',
			),
			'sslverify'  => (bool) apply_filters( 'https_local_ssl_verify', false ),
		)
	);

	if ( is_wp_error( $response ) ) {
		quorlyx_cache_set( $cache_key, '', min( $cache_ttl, 10 * MINUTE_IN_SECONDS ), $perf, 'quorlyx_ctx' );
		return '';
	}

	$status_code = (int) wp_remote_retrieve_response_code( $response );
	if ( $status_code < 200 || $status_code >= 300 ) {
		quorlyx_cache_set( $cache_key, '', min( $cache_ttl, 10 * MINUTE_IN_SECONDS ), $perf, 'quorlyx_ctx' );
		return '';
	}

	$content_type = wp_remote_retrieve_header( $response, 'content-type' );
	if ( is_array( $content_type ) ) {
		$content_type = implode( ', ', $content_type );
	}
	if ( $content_type && false === stripos( (string) $content_type, 'text/html' ) ) {
		quorlyx_cache_set( $cache_key, '', min( $cache_ttl, 10 * MINUTE_IN_SECONDS ), $perf, 'quorlyx_ctx' );
		return '';
	}

	$html = wp_remote_retrieve_body( $response );
	$text = quorlyx_extract_visible_text_from_html( is_string( $html ) ? $html : '', $max_chars );
	quorlyx_cache_set( $cache_key, $text, '' === $text ? min( $cache_ttl, 10 * MINUTE_IN_SECONDS ) : $cache_ttl, $perf, 'quorlyx_ctx' );

	return $text;
}

/**
 * Build rendered public-page context from a same-site URL.
 *
 * @param string              $url       Public URL.
 * @param string              $label     Context label.
 * @param string              $source    Source note.
 * @param array<string,mixed> $perf      Performance settings.
 * @param int                 $max_chars Maximum visible text characters.
 * @return string
 */
function quorlyx_get_rendered_public_url_context( $url, $label, $source, $perf, $max_chars = 6000 ) {
	$url    = esc_url_raw( (string) $url );
	$label  = trim( wp_strip_all_tags( (string) $label ) );
	$source = trim( wp_strip_all_tags( (string) $source ) );
	if ( '' === $url || '' === $label ) {
		return '';
	}

	$text = quorlyx_get_rendered_public_url_text( $url, $perf, $max_chars );
	if ( '' === $text ) {
		return '';
	}

	$context  = strtoupper( $label ) . " (rendered public page)\n";
	$context .= "URL: {$url}\n";
	$context .= "Source: " . ( '' !== $source ? $source : 'rendered active theme output' ) . "\n";
	$context .= "Use this for facts from visible page content, theme templates, page builders, blocks, shortcodes, custom fields, and other output that may not exist in raw WordPress post content.\n";
	$context .= "Visible text:\n" . $text;

	return $context;
}

/**
 * Build rendered context for a public post object.
 *
 * @param int                 $post_id   Post ID.
 * @param array<string,mixed> $perf      Performance settings.
 * @param int                 $max_chars Maximum visible text characters.
 * @return string
 */
function quorlyx_get_rendered_public_post_context( $post_id, $perf, $max_chars = 2200 ) {
	$post_id = absint( $post_id );
	if ( $post_id <= 0 || 'publish' !== get_post_status( $post_id ) ) {
		return '';
	}

	$post_type_object = get_post_type_object( get_post_type( $post_id ) );
	if ( ! $post_type_object || empty( $post_type_object->public ) ) {
		return '';
	}

	$url = get_permalink( $post_id );
	if ( ! $url ) {
		return '';
	}

	return quorlyx_get_rendered_public_url_context(
		$url,
		get_the_title( $post_id ),
		'rendered public ' . ( $post_type_object->labels->singular_name ?? 'content' ) . ' output',
		$perf,
		$max_chars
	);
}

/**
 * Determine whether the user question needs broad visible site/page context.
 *
 * @param string $user_question User question.
 * @return bool
 */
function quorlyx_should_include_rendered_home_context( $user_question ) {
	$user_question = trim( (string) $user_question );
	if ( '' === $user_question ) {
		return false;
	}

	if ( preg_match( '/^\s*(hi|hello|hey|thanks|thank you|ok|okay|good morning|good afternoon|good evening)[!. ]*$/i', $user_question ) ) {
		return false;
	}

	if ( preg_match( '/\b(what|who|when|where|why|how|tell me|explain|describe|details?|info|information|feature|features|pricing|price|prices|cost|costs|plan|plans|tier|tiers|service|services|product|products|about|contact|support|faq|help|trial|demo|license|licence|refund|return|guarantee|offer|deal|discount|shipping|delivery|hours|location|booking|appointment|menu|integration|integrations|security|setup|install|homepage|home page|landing page)\b/i', $user_question ) ) {
		return true;
	}

	$words = preg_split( '/\s+/', $user_question, -1, PREG_SPLIT_NO_EMPTY );
	return is_array( $words ) && count( $words ) >= 3;
}

/**
 * Determine whether a message is only a simple greeting.
 *
 * @param string $message User message.
 * @return bool
 */
function quorlyx_is_simple_greeting_message( $message ) {
	$message = strtolower( trim( wp_strip_all_tags( (string) $message ) ) );
	$message = preg_replace( '/[^\p{L}\p{N}\s]+/u', ' ', (string) $message );
	$message = trim( preg_replace( '/\s+/', ' ', (string) $message ) );
	if ( '' === $message ) {
		return false;
	}

	return (bool) preg_match( '/^(hi|hello|hey|yo|salam|thanks|thank you|good morning|good afternoon|good evening)( there| team| quorlyx| bot| assistant)?$/i', $message );
}

/**
 * Build a local no-API greeting reply.
 *
 * @param array<string,mixed> $settings      Variation settings.
 * @param array<string,mixed> $request_body  Runtime request params.
 * @param string              $user_question User message text.
 * @return string
 */
function quorlyx_get_local_greeting_reply( $settings, $request_body = array(), $user_question = '' ) {
	$settings     = is_array( $settings ) ? $settings : array();
	$request_body = is_array( $request_body ) ? $request_body : array();
	$default      = 'Hello! How can I assist you today?';
	$message      = trim( (string) ( $settings['welcome_message'] ?? '' ) );
	if ( '' === $message ) {
		$message = $default;
	}

	$context = quorlyx_build_trigger_ai_message_context( array(), $request_body );
	if ( empty( $context['page_title'] ) && ! empty( $context['site_name'] ) ) {
		$context['page_title'] = $context['site_name'];
	}
	if ( empty( $context['post_title'] ) && ! empty( $context['page_title'] ) ) {
		$context['post_title'] = $context['page_title'];
	}
	$context['user_question'] = sanitize_text_field( (string) $user_question );

	$rendered = quorlyx_render_ai_message_template_text(
		$message,
		$context,
		array(),
		array(
			'missing_policy' => 'omit',
		)
	);
	if ( is_array( $rendered ) && array_key_exists( 'message', $rendered ) ) {
		$message = trim( (string) $rendered['message'] );
	}
	if ( '' === $message ) {
		$message = $default;
	}

	return sanitize_textarea_field( $message );
}

/**
 * Collect site context snippets for model prompts.
 *
 * @param array<string,mixed>      $settings      Variation settings.
 * @param string                   $user_question User question text.
 * @param array<string,mixed>|null $perf          Optional performance config.
 * @return string
 */
function quorlyx_pro_collect_site_context( $settings, $user_question, $perf = null ) {
	$user_question = is_string( $user_question ) ? trim( $user_question ) : '';
	if ( empty( $user_question ) ) {
		return '';
	}

	if ( ! is_array( $perf ) ) {
		$all_opts = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
		$perf     = $all_opts['performance'] ?? array();
	}

	$context_ttl           = max( 60, absint( $perf['context_cache_ttl'] ?? HOUR_IN_SECONDS ) );
	$detail_level          = in_array( ( $perf['context_detail_level'] ?? 'full' ), array( 'full', 'compact' ), true ) ? $perf['context_detail_level'] : 'full';
	$excerpt_words         = max( 10, absint( $perf['context_excerpt_words'] ?? 40 ) );
	$product_excerpt_words = max( 10, absint( $perf['context_product_excerpt_words'] ?? 35 ) );
	$include_behavior_patterns = ! empty( $settings['knowledge_base_include_behavior_patterns'] );
	$include_rendered_content  = ! array_key_exists( 'knowledge_base_include_rendered_content', $settings ) || ! empty( $settings['knowledge_base_include_rendered_content'] );
	$types                     = quorlyx_get_selected_knowledge_base_post_types( $settings );
	$file_ids                  = quorlyx_get_selected_knowledge_base_file_ids( $settings, true );
	$product_kb_enabled        = in_array( 'product', $types, true );

	$post_types_key = implode( ',', $types );
	$file_ids_key   = implode( ',', $file_ids );
	$cache_key      = 'quorlyx_ctx_' . md5( strtolower( $user_question ) . $post_types_key . '|files:' . $file_ids_key . '|bp:' . ( $include_behavior_patterns ? '1' : '0' ) . '|rendered:' . ( $include_rendered_content ? '1' : '0' ) . '|v:' . QUORLYX_KB_CONTEXT_VERSION );
	$cached_context = quorlyx_cache_get( $cache_key, $perf, 'quorlyx_ctx' );
	if ( false !== $cached_context ) {
		return $cached_context;
	}

	$sections = array();
	$qstr = strtolower( $user_question );

	$has_woo                  = class_exists( 'WooCommerce' );
	$product_post_type_exists = post_type_exists( 'product' );
	$product_count            = 0;
	if ( $product_post_type_exists ) {
		$counts = wp_count_posts( 'product' );
		if ( $counts && isset( $counts->publish ) ) {
			$product_count = (int) $counts->publish;
		}
	}

	$allow_product_search = ! isset( $perf['tool_calling_products_enabled'] ) || empty( $perf['tool_calling_products_enabled'] );

	// Detect product intent first to avoid irrelevant warnings.
	$looks_product_related = (bool) preg_match( '/\b(price|cost|how much|attributes?|sizes?|colors?|colour|material|variant|variations?|sku|dimensions?|weight|description|details)\b/i', $user_question );
	$looks_store_related   = (bool) preg_match( '/\b(products?|shop|store|pricing|plans|all products)\b/i', $qstr );
	$home_kb_enabled       = in_array( 'page', $types, true ) || ( 'posts' === get_option( 'show_on_front' ) && in_array( 'post', $types, true ) );

	if ( $product_kb_enabled && ( $looks_product_related || $looks_store_related ) ) {
		if ( ! $has_woo || ! $product_post_type_exists ) {
			$sections[] = "PRODUCTS\nWooCommerce is not active on this site. Do not invent products, prices, inventory, or product URLs. Do not generate product buttons or add-to-cart links.";
		} elseif ( 0 === $product_count ) {
			$sections[] = "PRODUCTS\nThere are 0 published products on this site. Do not invent product names/prices/URLs. Do not generate product buttons or add-to-cart links.";
		}
	}

	if ( ! empty( $file_ids ) ) {
		$file_context = quorlyx_get_uploaded_knowledge_base_files_context( $settings, $user_question, $perf );
		if ( '' !== $file_context ) {
			$sections[] = $file_context;
		}
	}

	if ( $include_rendered_content && $home_kb_enabled && quorlyx_should_include_rendered_home_context( $user_question ) ) {
		$rendered_home_context = quorlyx_get_rendered_public_url_context(
			home_url( '/' ),
			'Homepage / front page',
			'rendered active theme/front-page output',
			$perf,
			max( 1000, min( 30000, absint( $perf['rendered_context_max_chars'] ?? 12000 ) ) )
		);
		if ( '' !== $rendered_home_context ) {
			$sections[] = $rendered_home_context;
		}
	}

	// When WooCommerce exists, include real product details for matching products to avoid hallucinated prices/attributes.
	if ( $product_kb_enabled && $allow_product_search && $has_woo && $product_post_type_exists && ( $looks_product_related || $looks_store_related ) ) {
		// Improve search by stripping common conversational words to find the actual product name.
		// This solves "How much is HDMI Pro?" failing to match "HDMI Pro".
		$stop_regex     = '/\b(hi|hello|hey|please|can|you|tell|me|show|give|about|what|how|much|does|is|are|the|a|an|of|for|in|on|with|price|cost|attributes|specs|details|info|buy|get|purchase)\b/i';
		$cleaned_search = trim( preg_replace( $stop_regex, ' ', $user_question ) );
		$cleaned_search = trim( preg_replace( '/\s+/', ' ', $cleaned_search ) );

		// If cleaning left us with something substantial, use it. Otherwise fall back to original.
		$search_term = ( strlen( $cleaned_search ) >= 2 ) ? $cleaned_search : $user_question;

		$product_query = new WP_Query(
			array(
				's'              => $search_term,
				'post_type'      => 'product',
				'posts_per_page' => 5,
				'post_status'    => 'publish',
			)
		);

		// Fallback: If cleaned term found nothing, try original query.
		if ( ! $product_query->have_posts() && $search_term !== $user_question ) {
			$product_query = new WP_Query(
				array(
					's'              => $user_question,
					'post_type'      => 'product',
					'posts_per_page' => 5,
					'post_status'    => 'publish',
				)
			);
		}

		if ( $product_query->have_posts() ) {
			$rows            = array();
			$currency_code   = function_exists( 'get_woocommerce_currency' ) ? (string) get_woocommerce_currency() : '';
			$currency_symbol = function_exists( 'get_woocommerce_currency_symbol' ) ? (string) get_woocommerce_currency_symbol( '' !== $currency_code ? $currency_code : null ) : '';

			while ( $product_query->have_posts() ) {
				$product_query->the_post();
				$pid  = get_the_ID();
				$url  = get_permalink( $pid );
				$name = get_the_title( $pid );

				$line = "Title: {$name}\nURL: {$url}";

				if ( function_exists( 'wc_get_product' ) ) {
					$p = wc_get_product( $pid );
					if ( $p ) {
						$price_html = '';
						if ( method_exists( $p, 'get_price_html' ) ) {
							$price_html = (string) $p->get_price_html();
							$price_html = html_entity_decode( wp_strip_all_tags( $price_html ) );
						}
						$regular = (string) $p->get_regular_price();
						$sale    = (string) $p->get_sale_price();
						$current = (string) $p->get_price();

						// Provide both formatted and numeric values. AI must use the CONTEXT values.
						$price_bits = array();
						if ( $price_html ) {
							$price_bits[] = "Display Price: {$price_html}";
						}
						if ( '' !== $current ) {
							$price_bits[] = "Current Price: {$currency_symbol}{$current}" . ( $currency_code ? " {$currency_code}" : '' );
						}
						if ( '' !== $regular ) {
							$price_bits[] = "Regular Price: {$currency_symbol}{$regular}" . ( $currency_code ? " {$currency_code}" : '' );
						}
						if ( '' !== $sale ) {
							$price_bits[] = "Sale Price: {$currency_symbol}{$sale}" . ( $currency_code ? " {$currency_code}" : '' );
						}
						if ( ! empty( $price_bits ) ) {
							$line .= "\n" . implode( "\n", $price_bits );
						}

						$short_desc = '';
						if ( method_exists( $p, 'get_short_description' ) ) {
							$short_desc = trim( (string) $p->get_short_description() );
							$short_desc = wp_strip_all_tags( $short_desc );
						}
						if ( 'full' === $detail_level ) {
							if ( $short_desc ) {
								$line .= "\nShort Description: " . wp_trim_words( $short_desc, $product_excerpt_words );
							}

							// Attributes summary (taxonomy + custom).
							$attr_lines = array();
							if ( method_exists( $p, 'get_attributes' ) ) {
								$attrs = $p->get_attributes();
								if ( is_array( $attrs ) ) {
									foreach ( $attrs as $attr_key => $attr ) {
										if ( is_object( $attr ) && method_exists( $attr, 'get_name' ) ) {
											$attr_name = (string) $attr->get_name();
											$values    = array();
											if ( method_exists( $attr, 'is_taxonomy' ) && $attr->is_taxonomy() ) {
												$tax      = $attr_name;
												$term_ids = method_exists( $attr, 'get_options' ) ? (array) $attr->get_options() : array();
												if ( ! empty( $term_ids ) ) {
													$terms = get_terms(
														array(
															'taxonomy'   => $tax,
															'include'    => $term_ids,
															'hide_empty' => false,
														)
													);
													if ( ! is_wp_error( $terms ) ) {
														foreach ( $terms as $t ) {
															if ( isset( $t->name ) ) {
																$values[] = (string) $t->name;
															}
														}
													}
												}
											} else {
												$values = method_exists( $attr, 'get_options' ) ? (array) $attr->get_options() : array();
											}

											$values = array_values( array_filter( array_map( 'wp_strip_all_tags', array_map( 'strval', (array) $values ) ) ) );
											if ( $values ) {
												$label        = function_exists( 'wc_attribute_label' ) ? wc_attribute_label( $attr_name ) : $attr_name;
												$attr_lines[] = $label . ': ' . implode( ', ', array_slice( $values, 0, 12 ) );
											}
										}
									}
								}
							}
							if ( ! empty( $attr_lines ) ) {
								$line .= "\nAttributes: \n- " . implode( "\n- ", array_slice( $attr_lines, 0, 12 ) );
							}
						}
					}
				}

				$rows[] = $line;
			}

			wp_reset_postdata();

			if ( ! empty( $rows ) ) {
				$sections[] = "MATCHED PRODUCTS\n" . implode( "\n\n", $rows );
			}
		} else {
			wp_reset_postdata();
		}
	}

	if ( ! empty( $types ) ) {
		$query = new WP_Query(
			array(
				's'              => $user_question,
				'post_type'      => $types,
				'posts_per_page' => 5,
				'post_status'    => 'publish',
			)
		);
		if ( $query->have_posts() ) {
			$found = array();
			while ( $query->have_posts() ) {
				$query->the_post();
				$post_id          = get_the_ID();
				$url              = get_permalink( $post_id );
				$rendered_context = $include_rendered_content ? quorlyx_get_rendered_public_post_context( $post_id, $perf, 2200 ) : '';
				if ( '' !== $rendered_context ) {
					$found[] = $rendered_context;
				} else {
					$found[] = 'Title: ' . get_the_title( $post_id )
						. "\nExcerpt: " . wp_trim_words( wp_strip_all_tags( get_the_content( null, false, $post_id ) ), $excerpt_words )
						. "\nURL: " . $url;
				}
			}
			wp_reset_postdata();
			if ( ! empty( $found ) ) {
				$sections[] = "MATCHED CONTENT\n" . implode( "\n\n", $found );
			}
		} else {
			wp_reset_postdata();
		}
	}

	if ( $include_behavior_patterns ) {
		$behavior_settings = quorlyx_get_behavior_pattern_settings();
		$behavior_enabled  = quorlyx_behavior_patterns_are_enabled();
		if ( ! $behavior_enabled ) {
			quorlyx_behavior_log_event_once(
				'behavior_kb_engine_disabled',
				'warning',
				'Behavior Knowledge Base source is enabled, but Content Insights or the Behavior Pattern Engine is disabled',
				array(
					'component' => 'behavior_engine',
					'operation' => 'ai_context_collection',
					'phase'     => 'behavior_kb_settings',
				),
				3600
			);
			$behavior_source = '';
		} else {
			$behavior_source = quorlyx_get_behavior_knowledge_base_context();
		}

		if ( '' !== $behavior_source ) {
			$sections[] = $behavior_source;
		} elseif ( $behavior_enabled ) {
			quorlyx_behavior_log_event_once(
				'behavior_kb_context_empty',
				'warning',
				'Behavior Knowledge Base source is enabled but no behavior profiles are available yet',
				array(
					'component' => 'behavior_engine',
					'operation' => 'ai_context_collection',
					'phase'     => 'behavior_kb_append',
				),
				3600
			);
		}
	}

	$wants_posts    = in_array( 'post', $types, true ) && (bool) preg_match( '/\b(posts?|blog|articles?|all posts)\b/i', $qstr );
	$wants_pages    = in_array( 'page', $types, true ) && (bool) preg_match( '/\b(pages?|about|contact|policy|faq|help)\b/i', $qstr );
	$wants_products = in_array( 'product', $types, true ) && (bool) ( preg_match( '/\b(products?|shop|store|pricing|plans|all products)\b/i', $qstr ) && post_type_exists( 'product' ) );

	$add_recent = function ( $post_type, $label, $count = 5 ) {
		$part   = '';
		$total  = 0;
		$counts = wp_count_posts( $post_type );
		if ( $counts && isset( $counts->publish ) ) {
			$total = (int) $counts->publish;
		}

		$archive_link = get_post_type_archive_link( $post_type );
		if ( 'product' === $post_type && function_exists( 'wc_get_page_id' ) ) {
			$archive_link = get_permalink( wc_get_page_id( 'shop' ) );
		}
		if ( $archive_link ) {
			$part .= "Main {$label} Page: {$archive_link}\n";
		}

		$q    = new WP_Query(
			array(
				'post_type'      => $post_type,
				'posts_per_page' => $count,
				'post_status'    => 'publish',
				'orderby'        => 'date',
				'order'          => 'DESC',
			)
		);
		$rows = array();
		if ( $q->have_posts() ) {
			while ( $q->have_posts() ) {
				$q->the_post();
				$rows[] = '- ' . get_the_title() . ' - ' . get_permalink();
			}
			wp_reset_postdata();
		}

		if ( ! empty( $rows ) || $total > 0 ) {
			$part .= "RECENT {$label} (total: {$total})\n" . implode( "\n", $rows );
			return strtoupper( $label ) . "\n" . $part;
		}
		return '';
	};

	if ( $wants_posts ) {
		$sec = $add_recent( 'post', 'Posts' );
		if ( $sec ) {
			$sections[] = $sec;
		}
	}
	if ( $wants_pages ) {
		$sec = $add_recent( 'page', 'Pages' );
		if ( $sec ) {
			$sections[] = $sec;
		}
	}
	if ( $wants_products ) {
		$sec = $add_recent( 'product', 'Products' );
		if ( $sec ) {
			$sections[] = $sec;
		}
	}

	if ( empty( $sections ) && ! empty( $types ) ) {
		$fallback_types = array_values( array_unique( array_merge( array( 'page', 'post', 'product' ), $types ) ) );
		foreach ( $fallback_types as $fallback_type ) {
			if ( ! in_array( $fallback_type, $types, true ) ) {
				continue;
			}

			$post_type_object = get_post_type_object( $fallback_type );
			$label            = $post_type_object && ! empty( $post_type_object->label ) ? $post_type_object->label : ucfirst( $fallback_type );
			$sec              = $add_recent( $fallback_type, $label );
			if ( $sec ) {
				$sections[] = $sec;
				break;
			}
		}
	}

	$context_string = implode( "\n\n---\n\n", array_filter( $sections ) );
	quorlyx_cache_set( $cache_key, $context_string, $context_ttl, $perf, 'quorlyx_ctx' );

	return $context_string;
}

/**
 * Build OpenAI-compatible schema for product search tool calling.
 *
 * @return array<string,mixed>
 */
function quorlyx_pro_build_product_tool_schema() {
	return array(
		'type'     => 'function',
		'function' => array(
			'name'        => 'search_products',
			'description' => 'Search WooCommerce products and return compact facts (title, URL, price, optional details).',
			'parameters'  => array(
				'type'       => 'object',
				'properties' => array(
					'search_term' => array(
						'type'        => 'string',
						'description' => 'Product name or attribute to search for.',
					),
					'limit'       => array(
						'type'        => 'integer',
						'description' => 'Max number of results to return (1-10).',
					),
				),

				'required'   => array( 'search_term' ),
			),
		),
	);
}

/**
 * Execute a constrained WooCommerce product search for tool calling.
 *
 * @param string              $search_term Product search term.
 * @param array<string,mixed> $perf        Performance settings.
 * @param int                 $limit       Maximum result count.
 * @return string
 */
function quorlyx_pro_tool_search_products( $search_term, $perf, $limit = 5 ) {
	$search_term = is_string( $search_term ) ? trim( $search_term ) : '';
	if ( '' === $search_term ) {
		return 'NO_RESULTS';
	}

	if ( ! class_exists( 'WooCommerce' ) || ! post_type_exists( 'product' ) ) {
		return 'NO_RESULTS';
	}

	$limit                 = max( 1, min( 10, absint( $limit ) ) );
	$detail_level          = in_array( ( $perf['context_detail_level'] ?? 'full' ), array( 'full', 'compact' ), true ) ? $perf['context_detail_level'] : 'full';
	$product_excerpt_words = max( 10, absint( $perf['context_product_excerpt_words'] ?? 35 ) );
	$cache_ttl             = max( 60, absint( $perf['context_cache_ttl'] ?? HOUR_IN_SECONDS ) );

	$cache_key = 'quorlyx_tool_prod_' . md5( strtolower( $search_term ) . '|' . $detail_level . '|' . $limit );
	$cached    = quorlyx_cache_get( $cache_key, $perf, 'quorlyx_tool' );
	if ( false !== $cached ) {
		return $cached;
	}

	$product_query = new WP_Query(
		array(
			's'              => $search_term,
			'post_type'      => 'product',
			'posts_per_page' => $limit,
			'post_status'    => 'publish',
		)
	);

	if ( ! $product_query->have_posts() ) {
		wp_reset_postdata();
		return 'NO_RESULTS';
	}

	$rows            = array();
	$currency_code   = function_exists( 'get_woocommerce_currency' ) ? (string) get_woocommerce_currency() : '';
	$currency_symbol = function_exists( 'get_woocommerce_currency_symbol' ) ? (string) get_woocommerce_currency_symbol( $currency_code ? $currency_code : null ) : '';

	while ( $product_query->have_posts() ) {
		$product_query->the_post();
		$pid  = get_the_ID();
		$url  = get_permalink( $pid );
		$name = get_the_title( $pid );

		$line = "Title: {$name}\nURL: {$url}";

		if ( function_exists( 'wc_get_product' ) ) {
			$p = wc_get_product( $pid );
			if ( $p ) {
				$price_html = '';
				if ( method_exists( $p, 'get_price_html' ) ) {
					$price_html = (string) $p->get_price_html();
					$price_html = html_entity_decode( wp_strip_all_tags( $price_html ) );
				}
				$regular = (string) $p->get_regular_price();
				$sale    = (string) $p->get_sale_price();
				$current = (string) $p->get_price();

				$price_bits = array();
				if ( $price_html ) {
					$price_bits[] = "Display Price: {$price_html}";
				}
				if ( '' !== $current ) {
					$price_bits[] = "Current Price: {$currency_symbol}{$current}" . ( $currency_code ? " {$currency_code}" : '' );
				}
				if ( '' !== $regular ) {
					$price_bits[] = "Regular Price: {$currency_symbol}{$regular}" . ( $currency_code ? " {$currency_code}" : '' );
				}
				if ( '' !== $sale ) {
					$price_bits[] = "Sale Price: {$currency_symbol}{$sale}" . ( $currency_code ? " {$currency_code}" : '' );
				}
				if ( ! empty( $price_bits ) ) {
					$line .= "\n" . implode( "\n", $price_bits );
				}

				if ( 'full' === $detail_level ) {
					$short_desc = '';
					if ( method_exists( $p, 'get_short_description' ) ) {
						$short_desc = trim( (string) $p->get_short_description() );
						$short_desc = wp_strip_all_tags( $short_desc );
					}
					if ( $short_desc ) {
						$line .= "\nShort Description: " . wp_trim_words( $short_desc, $product_excerpt_words );
					}

					$attr_lines = array();
					if ( method_exists( $p, 'get_attributes' ) ) {
						$attrs = $p->get_attributes();
						if ( is_array( $attrs ) ) {
							foreach ( $attrs as $attr_key => $attr ) {
								if ( is_object( $attr ) && method_exists( $attr, 'get_name' ) ) {
									$attr_name = (string) $attr->get_name();
									$values    = array();
									if ( method_exists( $attr, 'is_taxonomy' ) && $attr->is_taxonomy() ) {
										$tax      = $attr_name;
										$term_ids = method_exists( $attr, 'get_options' ) ? (array) $attr->get_options() : array();
										if ( ! empty( $term_ids ) ) {
											$terms = get_terms(
												array(
													'taxonomy'   => $tax,
													'include'    => $term_ids,
													'hide_empty' => false,
												)
											);
											if ( ! is_wp_error( $terms ) ) {
												foreach ( $terms as $t ) {
													if ( isset( $t->name ) ) {
														$values[] = (string) $t->name;
													}
												}
											}
										}
									} else {
										$values = method_exists( $attr, 'get_options' ) ? (array) $attr->get_options() : array();
									}

									$values = array_values( array_filter( array_map( 'wp_strip_all_tags', array_map( 'strval', (array) $values ) ) ) );
									if ( $values ) {
										$label        = function_exists( 'wc_attribute_label' ) ? wc_attribute_label( $attr_name ) : $attr_name;
										$attr_lines[] = $label . ': ' . implode( ', ', array_slice( $values, 0, 12 ) );
									}
								}
							}
						}
					}
					if ( ! empty( $attr_lines ) ) {
						$line .= "\nAttributes:\n- " . implode( "\n- ", array_slice( $attr_lines, 0, 12 ) );
					}
				}
			}
		}

		$rows[] = $line;
	}
	wp_reset_postdata();

	$out = ! empty( $rows ) ? ( "MATCHED PRODUCTS\n" . implode( "\n\n", $rows ) ) : 'NO_RESULTS';
	quorlyx_cache_set( $cache_key, $out, $cache_ttl, $perf, 'quorlyx_tool' );
	return $out;
}

