/**
 * Render the runtime logs page.
 *
 * @return void
 */
function quorlyx_render_logs_page() {
	if ( isset( $_POST['quorlyx_clear_logs_nonce'] ) && wp_verify_nonce( sanitize_text_field( wp_unslash( $_POST['quorlyx_clear_logs_nonce'] ) ), 'quorlyx_clear_logs_action' ) ) {
		Quorlyx_Pro_Logger::clear_logs();
		echo '<div class="notice notice-success is-dismissible"><p>Logs cleared successfully.</p></div>';
	}

	if ( isset( $_POST['quorlyx_delete_selected_logs_nonce'] ) && wp_verify_nonce( sanitize_text_field( wp_unslash( $_POST['quorlyx_delete_selected_logs_nonce'] ) ), 'quorlyx_delete_selected_logs_action' ) ) {
		if ( ! empty( $_POST['log_ids'] ) && is_array( $_POST['log_ids'] ) ) {
			$ids_to_delete = array_map( 'sanitize_text_field', wp_unslash( $_POST['log_ids'] ) );
			Quorlyx_Pro_Logger::delete_logs( $ids_to_delete );
			echo '<div class="notice notice-success is-dismissible"><p>Selected logs deleted successfully.</p></div>';
		}
	}

	$logs = Quorlyx_Pro_Logger::get_logs();

	$types = array_unique( array_column( $logs, 'type' ) );
	sort( $types );

	$filter_types   = isset( $_GET['filter_types'] ) ? array_map( 'sanitize_key', (array) wp_unslash( $_GET['filter_types'] ) ) : array();
	$sort_by        = isset( $_GET['sort_by'] ) ? sanitize_key( wp_unslash( $_GET['sort_by'] ) ) : 'newest';
	$paged          = isset( $_GET['paged'] ) ? max( 1, absint( wp_unslash( $_GET['paged'] ) ) ) : 1;
	$items_per_page = 20;
	$allowed_sorts  = array( 'newest', 'oldest', 'type_asc', 'type_desc' );
	if ( ! in_array( $sort_by, $allowed_sorts, true ) ) {
		$sort_by = 'newest';
	}

	if ( ! empty( $filter_types ) ) {
		$logs = array_filter(
			$logs,
			function ( $log ) use ( $filter_types ) {
				return in_array( $log['type'], $filter_types, true );
			}
		);
	}

	usort(
		$logs,
		function ( $a, $b ) use ( $sort_by ) {
			switch ( $sort_by ) {
				case 'oldest':
					return $a['timestamp'] <=> $b['timestamp'];
				case 'type_asc':
					return strcmp( $a['type'], $b['type'] );
				case 'type_desc':
					return strcmp( $b['type'], $a['type'] );
				case 'newest':
				default:
					return $b['timestamp'] <=> $a['timestamp'];
			}
		}
	);

	$total_items  = count( $logs );
	$total_pages  = (int) ceil( $total_items / $items_per_page );
	$offset       = ( $paged - 1 ) * $items_per_page;
	$current_logs = array_slice( $logs, $offset, $items_per_page );

	$base_url = admin_url( 'admin.php?page=quorlyx-settings&tab=logs' );
	?>
	<div class="postbox quorlyx-card">
		<h2 class="hndle"><span><span class="dashicons dashicons-admin-tools"></span> Support Center & Event Logs</span></h2>
		<div class="inside">

			<div id="quorlyx_guide_panel" style="margin-top: 15px; padding: 15px; background: #fff; border: 1px solid #ccd0d4; border-left: 4px solid #198754; box-shadow: 0 1px 1px rgba(0,0,0,.04); width: 100%;">
				<h3><span class="dashicons dashicons-format-chat"></span> Chat with the Guide (Admin Only)</h3>
				<p style="margin-top:0;">Ask setup questions using the Pro guide, including any option or button that feels confusing, then continue with follow-up questions (for example: "Explain step 2 in detail"). Use Health Check/Frontend Probe to detect conflicts and errors.</p>
				<div id="quorlyx_guide_chat_log" style="max-height:260px; overflow:auto; background:#f8fafc; border:1px solid #d0d7de; padding:10px; margin-bottom:10px;"></div>
				<label for="quorlyx_guide_question" class="screen-reader-text">Guide question</label>
				<textarea id="quorlyx_guide_question" rows="3" class="large-text" placeholder="Example: How do I connect WooCommerce? Then ask follow-up details."></textarea>
				<div style="display:flex; gap:10px; margin-top:10px; align-items:center; flex-wrap:wrap;">
					<button type="button" class="button" id="quorlyx_guide_fetch_snapshot"><span class="dashicons dashicons-database-view"></span> Fetch Site Snapshot</button>
					<button type="button" class="button" id="quorlyx_guide_health_check"><span class="dashicons dashicons-yes-alt"></span> Run Health Check</button>
					<button type="button" class="button" id="quorlyx_guide_frontend_probe"><span class="dashicons dashicons-search"></span> Run Frontend Probe</button>
					<button type="button" class="button button-primary" id="quorlyx_guide_send_button"><span class="dashicons dashicons-format-chat"></span> Ask Guide</button>
					<button type="button" class="button button-secondary" id="quorlyx_analyze_logs_button"><span class="dashicons dashicons-admin-tools"></span> Analyze logs with AI</button>
					<button type="button" class="button" id="quorlyx_guide_clear_chat"><span class="dashicons dashicons-trash"></span> Clear Chat</button>
					<span class="spinner" id="quorlyx_guide_spinner"></span>
					<span class="spinner" id="quorlyx_analyze_logs_spinner"></span>
				</div>
				<div id="quorlyx_guide_findings_wrap" style="display:none; margin-top:12px;">
					<h4 style="margin:0 0 8px;">Technical Findings</h4>
					<div id="quorlyx_guide_findings" style="line-height:1.6; background:#f8f9fa; border:1px solid #e2e8f0; padding:10px;"></div>
				</div>
				<div id="quorlyx_guide_snapshot_wrap" style="display:none; margin-top:12px;">
					<h4 style="margin:0 0 8px;">Snapshot Data</h4>
					<pre id="quorlyx_guide_snapshot" style="margin:0; max-height:260px; overflow:auto; background:#f6f7f7; border:1px solid #dcdcde; padding:10px;"></pre>
				</div>
			</div>

			<h3 id="quorlyx_event_logs_heading" style="margin:16px 0 10px;"><span class="dashicons dashicons-list-view"></span> Event Logs</h3>

			<!-- Toolbar -->
			<div class="quorlyx-logs-toolbar" style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 15px; flex-wrap: wrap; gap: 10px;">

				<!-- Filter & Sort Form -->
				<form method="get" action="<?php echo esc_url( admin_url( 'admin.php' ) ); ?>" style="display: flex; gap: 10px; align-items: center;">
					<input type="hidden" name="page" value="quorlyx-settings">
					<input type="hidden" name="tab" value="logs">

					<!-- Filter Types (Multi-select) -->
					<div class="quorlyx-log-filters">
						<div class="quorlyx-multiselect" id="quorlyx-log-multiselect">
							<div class="selectBox quorlyx-select-display" onclick="quorlyxToggleCheckboxes()">
								<span class="quorlyx-select-value">
									<?php
									if ( empty( $filter_types ) ) {
										echo esc_html( 'Filter by Type' );
									} else {
										echo esc_html( number_format_i18n( count( $filter_types ) ) . ' Selected' );
									}
									?>
									<span class="dashicons dashicons-arrow-down-alt2"></span>
								</span>
							</div>
							<div id="quorlyx-checkboxes">
								<?php foreach ( $types as $type ) : ?>
									<label for="type-<?php echo esc_attr( $type ); ?>">
										<input type="checkbox" id="type-<?php echo esc_attr( $type ); ?>" name="filter_types[]" value="<?php echo esc_attr( $type ); ?>" <?php checked( in_array( $type, $filter_types, true ) ); ?> />
										<span class="quorlyx-log-type quorlyx-log-<?php echo esc_attr( $type ); ?>"><?php echo esc_html( strtoupper( $type ) ); ?></span>
									</label>
								<?php endforeach; ?>
							</div>
						</div>
					</div>

					<!-- Sort -->
					<select name="sort_by" class="quorlyx-select">
						<option value="newest" <?php selected( $sort_by, 'newest' ); ?>>Newest First</option>
						<option value="oldest" <?php selected( $sort_by, 'oldest' ); ?>>Oldest First</option>
						<option value="type_asc" <?php selected( $sort_by, 'type_asc' ); ?>>Type (A-Z)</option>
						<option value="type_desc" <?php selected( $sort_by, 'type_desc' ); ?>>Type (Z-A)</option>
					</select>

					<button type="submit" class="button">Apply</button>
					<?php if ( ! empty( $filter_types ) || 'newest' !== $sort_by ) : ?>
						<a href="<?php echo esc_url( $base_url ); ?>" class="button">Reset</a>
					<?php endif; ?>
				</form>

				<!-- Clear Logs Form -->
				<div style="display: flex; gap: 10px; align-items: center;">
					<button type="submit" form="quorlyx-logs-form" class="button" onclick="return confirm('Are you sure you want to delete the selected logs?');">Delete Selected</button>

					<form method="post" action="<?php echo esc_url( $base_url ); ?>" onsubmit="return confirm('Are you sure you want to clear all logs?');" id="tour-step-clear-logs">
						<?php wp_nonce_field( 'quorlyx_clear_logs_action', 'quorlyx_clear_logs_nonce' ); ?>
						<button type="submit" class="button button-danger"><span class="dashicons dashicons-trash"></span> Clear All Logs</button>
					</form>

				</div>

				<script>
				jQuery(document).ready(function($) {
					if ( typeof quorlyxAdmin === 'undefined' || ! quorlyxAdmin.restUrl || ! quorlyxAdmin.nonce ) {
						return;
					}

					var quorlyxGuideHistory = [];
					var quorlyxGuideStorageKey = 'quorlyx_pro_guide_chat_history_v1';

					function quorlyxGuideEscapeHtml(value) {
						return $('<div/>').text(value || '').html();
					}

					function quorlyxRenderGuideChat() {
						var $log = $('#quorlyx_guide_chat_log');
						if (!Array.isArray(quorlyxGuideHistory) || quorlyxGuideHistory.length === 0) {
							$log.html('<p style="margin:0;color:#475569;">Start a conversation with the guide. Follow-up questions are supported.</p>');
							return;
						}

						var html = '';
						quorlyxGuideHistory.forEach(function(item) {
							var role = item && item.role === 'assistant' ? 'assistant' : 'user';
							var label = role === 'assistant' ? 'Guide' : 'You';
							var bg = role === 'assistant' ? '#eef2ff' : '#ecfeff';
							var border = role === 'assistant' ? '#c7d2fe' : '#a5f3fc';
							var badge = item && item.badge ? quorlyxGuideEscapeHtml(item.badge) : '';
							var text = quorlyxGuideEscapeHtml(item && item.text ? item.text : '');
							if (badge === 'Frontend Probe' || badge === 'Health Check') {
								text = text.replace(
									/Status:\s*(PASS|WARNING|FAIL)/,
									function(match, level) {
										var color = '#334155';
										if (level === 'PASS') {
											color = '#15803d';
										} else if (level === 'WARNING') {
											color = '#b45309';
										} else if (level === 'FAIL') {
											color = '#b91c1c';
										}
										return 'Status: <strong style="color:' + color + ';">' + level + '</strong>';
									}
								);
								text = text.replace(/\[(PASS|WARNING|FAIL)\]/g, function(match, level) {
									var color = '#334155';
									if (level === 'PASS') {
										color = '#15803d';
									} else if (level === 'WARNING') {
										color = '#b45309';
									} else if (level === 'FAIL') {
										color = '#b91c1c';
									}
									return '[<strong style="color:' + color + ';">' + level + '</strong>]';
								});
							}
							text = text.replace(/\n/g, '<br>');
							html += '<div style="margin-bottom:8px;">';
							html += '<div style="font-size:12px;color:#334155;margin-bottom:4px;"><strong>' + label + '</strong>';
							if (badge) {
								html += ' <span style="display:inline-block;margin-left:6px;padding:1px 6px;border:1px solid #bfdbfe;border-radius:10px;background:#eff6ff;color:#1d4ed8;font-size:11px;line-height:1.4;">' + badge + '</span>';
							}
							html += '</div>';
							html += '<div style="background:' + bg + ';border:1px solid ' + border + ';padding:8px;line-height:1.5;white-space:pre-wrap;overflow-wrap:anywhere;word-break:break-word;max-width:100%;">' + text + '</div>';
							html += '</div>';
						});
						$log.html(html);
						$log.scrollTop($log[0].scrollHeight);
					}

					function quorlyxNormalizeHistory(history) {
						if (!Array.isArray(history)) {
							return [];
						}
						return history.filter(function(item) {
							return item && (item.role === 'user' || item.role === 'assistant') && typeof item.text === 'string' && item.text.trim() !== '';
						}).slice(-20);
					}

					function quorlyxSaveGuideHistory() {
						try {
							window.localStorage.setItem(quorlyxGuideStorageKey, JSON.stringify(quorlyxGuideHistory));
						} catch (e) {
						}
					}

					function quorlyxLoadGuideHistory() {
						try {
							var stored = window.localStorage.getItem(quorlyxGuideStorageKey);
							if (!stored) {
								return;
							}
							quorlyxGuideHistory = quorlyxNormalizeHistory(JSON.parse(stored));
						} catch (e) {
							quorlyxGuideHistory = [];
						}
					}

					function quorlyxRenderGuideFindings(findings) {
						var $findingsWrap = $('#quorlyx_guide_findings_wrap');
						var $findingsBox = $('#quorlyx_guide_findings');
						if (!Array.isArray(findings) || findings.length === 0) {
							$findingsWrap.hide();
							$findingsBox.empty();
							return;
						}

						var html = '<ul style="margin:0 0 0 18px;">';
						findings.forEach(function(item) {
							var title = quorlyxGuideEscapeHtml(item && item.title ? item.title : 'Issue');
							var details = quorlyxGuideEscapeHtml(item && item.details ? item.details : '');
							var action = quorlyxGuideEscapeHtml(item && item.action ? item.action : '');
							var severity = item && item.severity ? String(item.severity).toLowerCase() : 'warning';
							var severityLabel = 'WARNING';
							var severityColor = '#b45309';
							var severityBg = '#fffbeb';
							if (severity === 'error' || severity === 'critical') {
								severityLabel = 'ERROR';
								severityColor = '#b91c1c';
								severityBg = '#fef2f2';
							} else if (severity === 'success' || severity === 'pass') {
								severityLabel = 'SUCCESS';
								severityColor = '#15803d';
								severityBg = '#f0fdf4';
							}
							html += '<li><span style="display:inline-block;margin-right:6px;padding:1px 6px;border:1px solid ' + severityColor + ';border-radius:10px;background:' + severityBg + ';color:' + severityColor + ';font-size:11px;line-height:1.4;">' + severityLabel + '</span><strong>' + title + '</strong>';
							if (details) {
								html += ' - ' + details;
							}
							if (action) {
								html += '<br><em>Action:</em> ' + action;
							}
							html += '</li>';
						});
						html += '</ul>';
						$findingsBox.html(html);
						$findingsWrap.show();
					}

					function quorlyxAnalyzeLogs() {
						var $btn = $('#quorlyx_analyze_logs_button');
						var $spinner = $('#quorlyx_analyze_logs_spinner');

						$btn.prop('disabled', true);
						$spinner.addClass('is-active');

						$.ajax({
							url: quorlyxAdmin.restUrl + 'analyze-logs',
							method: 'POST',
							beforeSend: function(xhr) {
								xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce);
							},
							success: function(response) {
								if (response.success) {
									quorlyxGuideHistory.push({
										role: 'assistant',
										text: String(response.analysis || ''),
										badge: 'Logs Analysis'
									});
									quorlyxGuideHistory = quorlyxNormalizeHistory(quorlyxGuideHistory);
									quorlyxSaveGuideHistory();
									quorlyxRenderGuideChat();
								} else {
									alert('Analysis failed: ' + (response.message || 'Unknown error'));
								}
							},
							error: function(jqXHR) {
								var msg = jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'Network error';
								alert('Analysis failed: ' + msg);
							},
							complete: function() {
								$btn.prop('disabled', false);
								$spinner.removeClass('is-active');
							}
						});
					}

					function quorlyxRunGuideHealthCheck() {
						var $btn = $('#quorlyx_guide_health_check');
						var $spinner = $('#quorlyx_guide_spinner');

						$btn.prop('disabled', true);
						$spinner.addClass('is-active');

						$.ajax({
							url: quorlyxAdmin.restUrl + 'guide-health-check',
							method: 'POST',
							beforeSend: function(xhr) {
								xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce);
							},
							contentType: 'application/json',
							data: JSON.stringify({})
						}).done(function(response) {
							if (!response || !response.success) {
								alert('Health check failed.');
								return;
							}

							quorlyxGuideHistory.push({
								role: 'assistant',
								text: String(response.report || 'Health check completed.'),
								badge: 'Health Check'
							});
							quorlyxGuideHistory = quorlyxNormalizeHistory(quorlyxGuideHistory);
							quorlyxSaveGuideHistory();
							quorlyxRenderGuideChat();
							quorlyxRenderGuideFindings(response.findings || []);
						}).fail(function(jqXHR) {
							var msg = jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'Network error';
							alert('Health check failed: ' + msg);
						}).always(function() {
							$btn.prop('disabled', false);
							$spinner.removeClass('is-active');
						});
					}

					function quorlyxRunGuideFrontendProbe() {
						var $btn = $('#quorlyx_guide_frontend_probe');
						var $spinner = $('#quorlyx_guide_spinner');

						$btn.prop('disabled', true);
						$spinner.addClass('is-active');

						$.ajax({
							url: quorlyxAdmin.restUrl + 'guide-frontend-probe',
							method: 'POST',
							beforeSend: function(xhr) {
								xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce);
							},
							contentType: 'application/json',
							data: JSON.stringify({})
						}).done(function(response) {
							if (!response || !response.success || !response.probe) {
								alert('Frontend probe failed.');
								return;
							}

							var probe = response.probe || {};
							var metrics = probe.metrics || {};
							var lines = [];
							lines.push('Frontend Probe Result');
							lines.push('Status: ' + String(probe.status || 'unknown').toUpperCase());
							lines.push('Detail: ' + String(probe.detail || 'No details provided.'));
							if (probe.action) {
								lines.push('Action: ' + String(probe.action));
							}
							if (typeof metrics.http_code !== 'undefined') {
								lines.push('HTTP: ' + String(metrics.http_code));
							}
							lines.push('Frontend asset found: ' + (metrics.has_frontend_asset ? 'Yes' : 'No'));
							lines.push('Root container found: ' + (metrics.has_root_container ? 'Yes' : 'No'));
							lines.push('Trigger script found: ' + (metrics.has_trigger_script ? 'Yes' : 'No'));
							lines.push('Defer/minify hints: ' + (metrics.defer_hints ? 'Yes' : 'No'));

							quorlyxGuideHistory.push({
								role: 'assistant',
								text: lines.join('\n'),
								badge: 'Frontend Probe'
							});
							quorlyxGuideHistory = quorlyxNormalizeHistory(quorlyxGuideHistory);
							quorlyxSaveGuideHistory();
							quorlyxRenderGuideChat();
						}).fail(function(jqXHR) {
							var msg = jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'Network error';
							alert('Frontend probe failed: ' + msg);
						}).always(function() {
							$btn.prop('disabled', false);
							$spinner.removeClass('is-active');
						});
					}

					function quorlyxFetchGuideSnapshot() {
						var $btn = $('#quorlyx_guide_fetch_snapshot');
						var $spinner = $('#quorlyx_guide_spinner');

						$btn.prop('disabled', true);
						$spinner.addClass('is-active');

						$.ajax({
							url: quorlyxAdmin.restUrl + 'guide-site-snapshot',
							method: 'POST',
							beforeSend: function(xhr) {
								xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce);
							},
							contentType: 'application/json',
							data: JSON.stringify({})
						}).done(function(response) {
							if (!response || !response.success) {
								alert('Snapshot failed.');
								return;
							}
							var snapshotJson = JSON.stringify(response.snapshot || {}, null, 2);
							$('#quorlyx_guide_snapshot').text(snapshotJson);
							$('#quorlyx_guide_snapshot_wrap').show();
							quorlyxRenderGuideFindings(response.findings || []);

							quorlyxGuideHistory.push({
								role: 'assistant',
								text: snapshotJson,
								badge: 'Snapshot Data'
							});
							quorlyxGuideHistory = quorlyxNormalizeHistory(quorlyxGuideHistory);
							quorlyxSaveGuideHistory();
							quorlyxRenderGuideChat();
						}).fail(function(jqXHR) {
							var msg = jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'Network error';
							alert('Snapshot failed: ' + msg);
						}).always(function() {
							$btn.prop('disabled', false);
							$spinner.removeClass('is-active');
						});
					}

					function quorlyxAskGuide() {
						var question = ($('#quorlyx_guide_question').val() || '').trim();
						if (!question) {
							alert('Please enter a question first.');
							$('#quorlyx_guide_question').trigger('focus');
							return;
						}

						quorlyxGuideHistory.push({ role: 'user', text: question });
						quorlyxGuideHistory = quorlyxNormalizeHistory(quorlyxGuideHistory);
						quorlyxSaveGuideHistory();
						quorlyxRenderGuideChat();
						$('#quorlyx_guide_question').val('');

						var $btn = $('#quorlyx_guide_send_button');
						var $spinner = $('#quorlyx_guide_spinner');

						$btn.prop('disabled', true);
						$spinner.addClass('is-active');

						$.ajax({
							url: quorlyxAdmin.restUrl + 'guide-chat',
							method: 'POST',
							beforeSend: function(xhr) {
								xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce);
							},
							contentType: 'application/json',
							data: JSON.stringify({
								question: question,
								history: quorlyxGuideHistory
							})
						}).done(function(response) {
							if (!response || !response.success) {
								alert('Guide response failed.');
								return;
							}
							if (Array.isArray(response.history)) {
								quorlyxGuideHistory = quorlyxNormalizeHistory(response.history);
								var last = quorlyxGuideHistory.length ? quorlyxGuideHistory[quorlyxGuideHistory.length - 1] : null;
								var hasAssistantLast = !!(last && last.role === 'assistant' && typeof last.text === 'string' && last.text.trim() !== '');
								if (!hasAssistantLast && response.answer) {
									quorlyxGuideHistory.push({ role: 'assistant', text: String(response.answer || '') });
									quorlyxGuideHistory = quorlyxNormalizeHistory(quorlyxGuideHistory);
								}
							} else {
								quorlyxGuideHistory.push({ role: 'assistant', text: String(response.answer || '') });
								quorlyxGuideHistory = quorlyxNormalizeHistory(quorlyxGuideHistory);
							}
							quorlyxSaveGuideHistory();
							quorlyxRenderGuideChat();
							quorlyxRenderGuideFindings(response.findings || []);
						}).fail(function(jqXHR) {
							var msg = jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'Network error';
							quorlyxGuideHistory.push({ role: 'assistant', text: 'Request failed: ' + msg });
							quorlyxGuideHistory = quorlyxNormalizeHistory(quorlyxGuideHistory);
							quorlyxSaveGuideHistory();
							quorlyxRenderGuideChat();
							alert('Guide response failed: ' + msg);
						}).always(function() {
							$btn.prop('disabled', false);
							$spinner.removeClass('is-active');
						});
					}

					$('#quorlyx_analyze_logs_button').on('click', quorlyxAnalyzeLogs);
					$('#quorlyx_guide_health_check').on('click', quorlyxRunGuideHealthCheck);
					$('#quorlyx_guide_frontend_probe').on('click', quorlyxRunGuideFrontendProbe);
					$('#quorlyx_guide_fetch_snapshot').on('click', quorlyxFetchGuideSnapshot);
					$('#quorlyx_guide_send_button').on('click', quorlyxAskGuide);
					$('#quorlyx_guide_clear_chat').on('click', function() {
						quorlyxGuideHistory = [];
						try {
							window.localStorage.removeItem(quorlyxGuideStorageKey);
						} catch (e) {
						}
						quorlyxRenderGuideChat();
						$('#quorlyx_guide_question').trigger('focus');
					});
					$('#quorlyx_guide_question').on('keydown', function(e) {
						if (e.key === 'Enter' && !e.shiftKey) {
							e.preventDefault();
							quorlyxAskGuide();
						}
					});
					quorlyxLoadGuideHistory();
					quorlyxRenderGuideChat();
				});
				</script>
			</div>
			<style>
				select.quorlyx-select {
					border: 1px solid #c3c4c7;
					border-radius: 6px;
					padding: 6px 32px 6px 12px;
					font-size: 14px;
					min-width: 160px;
					background: #fff url(data:image/svg+xml;base64,) no-repeat right 10px center;
					background-size: 12px;
					appearance: none;
				}
				select.quorlyx-select:focus {
					outline: none;
					border-color: #2271b1;
					box-shadow: 0 0 0 1px #2271b1;
				}
				.quorlyx-multiselect { width: 220px; position: relative; }
				.quorlyx-select-display {
					border: 1px solid #c3c4c7;
					border-radius: 6px;
					padding: 6px 12px;
					background-color: #fff;
					cursor: pointer;
					transition: border-color 0.15s ease, box-shadow 0.15s ease;
				}
				.quorlyx-select-display:focus-within {
					border-color: #2271b1;
					box-shadow: 0 0 0 1px #2271b1;
				}
				.quorlyx-multiselect .selectBox {
					display: flex;
					align-items: center;
				}
				.quorlyx-select-display .quorlyx-select-value {
					display: flex;
					width: 100%;
					align-items: center;
					justify-content: space-between;
					color: #1d2327;
					font-size: 14px;
				}
				.quorlyx-select-display .quorlyx-select-value .dashicons {
					color: #6c737c;
				}
				.quorlyx-multiselect .overSelect { position: absolute; left: 0; right: 0; top: 0; bottom: 0; }
				.quorlyx-multiselect #quorlyx-checkboxes {
					display: none;
					border: 1px #dadada solid;
					position: absolute;
					background-color: #fff;
					z-index: 1000;
					width: 100%;
					max-height: 240px;
					overflow-y: auto;
					box-shadow: 0 12px 18px rgba(0,0,0,0.12);
					border-radius: 6px;
					margin-top: 6px;
				}
				.quorlyx-multiselect #quorlyx-checkboxes label {
					display: flex;
					align-items: center;
					gap: 8px;
					padding: 10px;
					cursor: pointer;
					border-bottom: 1px solid #f0f0f0;
				}
				.quorlyx-multiselect #quorlyx-checkboxes label:last-child {
					border-bottom: none;
				}
				.quorlyx-multiselect #quorlyx-checkboxes label:hover {
					background-color: #f8f9fb;
				}
			</style>
			<script>
			var quorlyxExpanded = false;
			function quorlyxToggleCheckboxes() {
				var checkboxes = document.getElementById("quorlyx-checkboxes");
				if (!quorlyxExpanded) {
					checkboxes.style.display = "block";
					quorlyxExpanded = true;
				} else {
					checkboxes.style.display = "none";
					quorlyxExpanded = false;
				}
			}
			document.addEventListener('click', function(e) {
				var container = document.getElementById('quorlyx-log-multiselect');
				if (container && !container.contains(e.target)) {
					document.getElementById("quorlyx-checkboxes").style.display = "none";
					quorlyxExpanded = false;
				}
			});
			</script>

			<!-- Table -->
			<form id="quorlyx-logs-form" method="post" action="<?php echo esc_url( $base_url ); ?>">
				<?php wp_nonce_field( 'quorlyx_delete_selected_logs_action', 'quorlyx_delete_selected_logs_nonce' ); ?>
				<table class="wp-list-table widefat striped">
					<thead>
						<tr>
							<td id="cb" class="manage-column column-cb check-column"><input type="checkbox" id="cb-select-all-1"></td>
							<th>Timestamp</th>
							<th>Type</th>
							<th>Message</th>
							<th>Details</th>
						</tr>
					</thead>
					<tbody>
						<?php if ( empty( $current_logs ) ) : ?>
							<tr><td colspan="5">No logs found.</td></tr>
						<?php else : ?>
							<?php foreach ( $current_logs as $log ) : ?>
							<tr>
								<th scope="row" class="check-column">
									<?php if ( isset( $log['id'] ) ) : ?>
										<input type="checkbox" name="log_ids[]" value="<?php echo esc_attr( $log['id'] ); ?>">
									<?php else : ?>
										<span class="dashicons dashicons-minus" title="Legacy log (cannot be deleted individually)"></span>
									<?php endif; ?>
								</th>
								<td style="white-space: nowrap;"><?php echo esc_html( date_i18n( 'Y-m-d H:i:s', (int) $log['timestamp'] ) ); ?></td>
								<td><span class="quorlyx-log-type quorlyx-log-<?php echo esc_attr( $log['type'] ); ?>"><?php echo esc_html( strtoupper( $log['type'] ) ); ?></span></td>
								<td><?php echo esc_html( $log['message'] ); ?></td>
								<td>
									<?php if ( ! empty( $log['details'] ) ) : ?>
									<details>
										<summary>View Details</summary>
										<?php
										$details_json = wp_json_encode( $log['details'], JSON_PRETTY_PRINT );
										$details_text = is_string( $details_json ) ? $details_json : '';
										?>
										<pre style="margin-top: 5px; overflow-x: auto;"><?php echo esc_html( $details_text ); ?></pre>
									</details>
									<?php endif; ?>
								</td>
							</tr>
							<?php endforeach; ?>
						<?php endif; ?>
					</tbody>
				</table>
			</form>

			<script>
			jQuery(document).ready(function($) {
				$('#cb-select-all-1').on('click', function() {
					var checked = this.checked;
					$('input[name="log_ids[]"]').prop('checked', checked);
				});
			});
			</script>

			<!-- Pagination -->
			<?php if ( $total_pages > 1 ) : ?>
			<div class="tablenav bottom">
				<div class="tablenav-pages">
					<?php
					$pagination_args = array(
						'paged' => '%#%',
					);
					if ( ! empty( $filter_types ) ) {
						$pagination_args['filter_types'] = $filter_types;
					}
					if ( ! empty( $sort_by ) ) {
						$pagination_args['sort_by'] = $sort_by;
					}
					echo wp_kses_post(
						paginate_links(
							array(
								'base'      => add_query_arg( $pagination_args ),
								'format'    => '',
								'prev_text' => '&laquo;',
								'next_text' => '&raquo;',
								'total'     => $total_pages,
								'current'   => $paged,
							)
						)
					);
					?>
				</div>
			</div>
			<?php endif; ?>

		</div>
	</div>
	<style>
		.quorlyx-log-type { padding: 2px 6px; border-radius: 4px; color: #fff; font-size: 0.8em; font-weight: bold; }
		.quorlyx-log-error, .quorlyx-log-critical { background-color: #dc3545; }
