							</details>
						<?php endif; ?>
					</div>
					<script>
					jQuery(document).ready(function($) {
						$('#quorlyx_reset_history_button').on('click', function() {
							if (!confirm('Are you sure you want to reset the generation history? This will allow previously used keywords and products to be used again.')) return;

							var $btn = $(this);
							$btn.prop('disabled', true).text('Resetting...');

							$.post(ajaxurl, {
								action: 'quorlyx_reset_history',
								_ajax_nonce: '<?php echo esc_attr( wp_create_nonce( 'quorlyx_reset_history' ) ); ?>'
							}, function(response) {
								if (response.success) {
									alert('History reset successfully.');
								} else {
									alert('Error: ' + (response.data || 'Unknown error'));
								}
								$btn.prop('disabled', false).text('Reset History');
							});
						});
					});
					</script>
				</td></tr>
				<tr><th scope="row">Generation Source</th><td>
					<select name="quorlyx_options[post_generator][source]" id="quorlyx_post_generator_source">
						<option value="keywords" <?php selected( ( $pg_opts['source'] ?? 'keywords' ), 'keywords' ); ?>>Topic Keywords Queue</option>
						<option value="products_all" <?php selected( ( $pg_opts['source'] ?? 'keywords' ), 'products_all' ); ?>>All Products (Discovery Mode)</option>
						<option value="products_specific" <?php selected( ( $pg_opts['source'] ?? 'keywords' ), 'products_specific' ); ?>>Specific Products</option>
