						<input type="text" name="quorlyx_options[post_generator][specific_product_ids]" value="<?php echo esc_attr( $pg_opts['specific_product_ids'] ?? '' ); ?>" class="large-text" placeholder="e.g. 123, 456, 789">
						<p class="description">Enter comma-separated Product IDs to generate content for. The engine will pick one from this list.</p>
