				<tr class="quorlyx-postgen-products-queue-row" style="<?php echo ( ( $pg_opts['source'] ?? 'keywords' ) === 'products_all' ) ? '' : 'display:none;'; ?>">
					<th scope="row">Products Queue</th>
					<td>
						<textarea id="quorlyx_post_generator_products_queue" name="quorlyx_options[post_generator][products_queue]" rows="8" class="large-text"><?php echo esc_textarea( $pg_opts['products_queue'] ?? '' ); ?></textarea>
						<p class="description">One Product ID per line. The engine works top-down and remembers used items.</p>
						<button type="button" class="button button-secondary" id="quorlyx_fetch_all_products_button" style="margin-top:5px;">Fetch All Products</button>
						<span class="spinner" id="quorlyx_fetch_products_spinner"></span>
					</td>
				</tr>
				<script>
				jQuery(document).ready(function($){
					function toggleSourceFields() {
						var source = $('#quorlyx_post_generator_source').val();
						$('.quorlyx-postgen-specific-products-row').hide();
						$('.quorlyx-postgen-products-queue-row').hide();
						$('#tour-step-content-keywords').hide();

						if(source === 'products_specific') {
							$('.quorlyx-postgen-specific-products-row').show();
						} else if(source === 'products_all') {
							$('.quorlyx-postgen-products-queue-row').show();
						} else {
							$('#tour-step-content-keywords').show();
						}
					}
					$('#quorlyx_post_generator_source').on('change', toggleSourceFields);
					toggleSourceFields(); // Run on load

					$('#quorlyx_fetch_all_products_button').on('click', function() {
						var $btn = $(this);
						var $spinner = $('#quorlyx_fetch_products_spinner');
						$btn.prop('disabled', true);
						$spinner.addClass('is-active');

						$.ajax({
							url: quorlyxAdmin.restUrl + 'fetch-products',
							method: 'POST',
							beforeSend: function(xhr) { xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce); },
							success: function(response) {

								if (response && response.success && Array.isArray(response.products) && response.products.length === 0) {
									alert('No new products found. All products appear to already have generated posts or are in the generation history.');
									return;
								}

								if (response && response.success && Array.isArray(response.products) && response.products.length > 0) {
									var currentVal = $('#quorlyx_post_generator_products_queue').val();
									var newVal = response.products.join('\n');
									if (currentVal.trim() !== '') {
										if (!confirm('Replace existing queue with all products?')) {
											$btn.prop('disabled', false);
											$spinner.removeClass('is-active');
											return;
										}
									}
									$('#quorlyx_post_generator_products_queue').val(newVal);
									return;
								}

								var msg = (response && response.data) ? response.data : 'Failed to fetch products.';
								alert(msg);
							},
							error: function() { alert('Error fetching products.'); },
							complete: function() {
								$btn.prop('disabled', false);
								$spinner.removeClass('is-active');
							}
						});
					});
				});
				</script>
				<tr id="tour-step-content-keywords" style="<?php echo ( ( $pg_opts['source'] ?? 'keywords' ) === 'keywords' ) ? '' : 'display:none;'; ?>">
					<th scope="row">Topic Keywords Queue</th>
