							}
							?>
						</select>
					</td>
				</tr>
				<tr>
					<th scope="row">Post Author</th>
					<td>
					<?php
					wp_dropdown_users(
						array(
							'name'     => 'quorlyx_options[post_generator][author_id]',
							'selected' => $pg_opts['author_id'],
						)
					);
					?>
						</td>
				</tr>
				<tr>
					<th scope="row">Post Status</th>
					<td>
						<select name="quorlyx_options[post_generator][post_status]">
							<option value="draft" <?php selected( $pg_opts['post_status'], 'draft' ); ?>>Save as Draft</option>
							<option value="publish" <?php selected( $pg_opts['post_status'], 'publish' ); ?>>Publish Immediately</option>
						</select>
						<p class="description">Choose whether to publish posts immediately or save them as drafts for review.</p>
					</td>
				</tr>
				</tbody>
			</table>
		</div>
