/**
 * Get selectable targets for SEO improvement analysis.
 *
 * @param int $limit Maximum number of targets.
 * @return array<int,array<string,mixed>>
 */
function quorlyx_get_seo_improvement_target_choices( $limit = 80 ) {
		$post_types = array( 'post', 'page' );
	if ( post_type_exists( 'product' ) ) {
			$post_types[] = 'product';
	}

		$posts = get_posts(
			array(
				'post_type'              => $post_types,
				'post_status'            => 'publish',
				'posts_per_page'         => max( 10, absint( $limit ) ),
				'orderby'                => 'date',
				'order'                  => 'DESC',
				'no_found_rows'          => true,
				'ignore_sticky_posts'    => true,
				'update_post_meta_cache' => false,
				'update_post_term_cache' => false,
			)
		);

	$choices = array();
	foreach ( $posts as $post ) {
		$post_type_object = get_post_type_object( $post->post_type );
		$type_label       = $post_type_object && ! empty( $post_type_object->labels->singular_name ) ? $post_type_object->labels->singular_name : ucfirst( $post->post_type );
		$is_generated     = '1' === (string) get_post_meta( $post->ID, '_quorlyx_generated', true );
		$is_improved      = quorlyx_is_content_improved( $post->ID );
		$choices[]        = array(
			'id'           => (int) $post->ID,
			'label'        => sprintf( '[%s] %s', $type_label, get_the_title( $post ) ),
			'post_type'    => sanitize_key( $post->post_type ),
			'is_generated' => $is_generated,
			'is_improved'  => $is_improved,
		);
	}

	return $choices;
}

/**
 * Determine whether a post is marked as SEO improved.
 *
 * @param int $post_id Post ID.
 * @return bool
 */
function quorlyx_is_content_improved( $post_id ) {
	return '1' === (string) get_post_meta( absint( $post_id ), '_quorlyx_seo_improved', true );
}

/**
 * Normalize a saved SEO suggestion record for persistent storage.
 *
 * @param mixed $item Raw suggestion item.
 * @return array<string,mixed>
 */
function quorlyx_normalize_saved_seo_suggestion( $item ) {
	$item = is_array( $item ) ? $item : array();

	$target_type = sanitize_key( $item['target_type'] ?? '' );
	if ( ! in_array( $target_type, array( 'post', 'scope' ), true ) ) {
		return array();
	}

	$post_id        = absint( $item['post_id'] ?? 0 );
		$target_key = 'post' === $target_type ? (string) $post_id : sanitize_key( $item['scope'] ?? '' );
	if ( '' === $target_key ) {
		return array();
	}

	$suggestion_id = sanitize_key( $item['id'] ?? '' );
	if ( '' === $suggestion_id ) {
		$suggestion_id = sanitize_key( wp_generate_uuid4() );
	}

	return array(
		'id'           => $suggestion_id,
		'storage_key'  => sanitize_key( $target_type . '_' . $target_key ),
		'target_type'  => $target_type,
		'post_id'      => $post_id,
		'post_type'    => sanitize_key( $item['post_type'] ?? '' ),
		'scope'        => sanitize_key( $item['scope'] ?? '' ),
		'title'        => sanitize_text_field( $item['title'] ?? '' ),
		'label'        => sanitize_text_field( $item['label'] ?? '' ),
		'url'          => esc_url_raw( $item['url'] ?? '' ),
		'analysis'     => quorlyx_pro_sanitize_guide_text( (string) ( $item['analysis'] ?? '' ), 5000 ),
		'is_generated' => ! empty( $item['is_generated'] ),
		'is_improved'  => ! empty( $item['is_improved'] ),
		'updated_at'   => absint( $item['updated_at'] ?? time() ),
	);
}

/**
 * Retrieve normalized saved SEO suggestions for a user.
 *
 * @param int $user_id User ID.
 * @return array<int,array<string,mixed>>
 */
function quorlyx_get_saved_seo_suggestions( $user_id = 0 ) {
	$user_id = absint( $user_id );
	if ( $user_id <= 0 ) {
		$user_id = get_current_user_id();
	}

	$stored = get_user_meta( $user_id, 'quorlyx_saved_seo_suggestions', true );
	if ( ! is_array( $stored ) ) {
		return array();
	}

	$normalized = array();
	foreach ( $stored as $item ) {
		$normalized_item = quorlyx_normalize_saved_seo_suggestion( $item );
		if ( ! empty( $normalized_item ) ) {
			$normalized[] = $normalized_item;
		}
	}

	usort(
		$normalized,
		static function ( $left, $right ) {
			return (int) ( $right['updated_at'] ?? 0 ) <=> (int) ( $left['updated_at'] ?? 0 );
		}
	);

	return array_values( $normalized );
}

/**
 * Replace saved SEO suggestions with a normalized list.
 *
 * @param array<int,array<string,mixed>> $suggestions Suggestion items.
 * @param int                            $user_id     User ID.
 * @return array<int,array<string,mixed>>
 */
function quorlyx_save_seo_suggestions( $suggestions, $user_id = 0 ) {
	$user_id = absint( $user_id );
	if ( $user_id <= 0 ) {
		$user_id = get_current_user_id();
	}

	$normalized = array();
	foreach ( (array) $suggestions as $item ) {
		$normalized_item = quorlyx_normalize_saved_seo_suggestion( $item );
		if ( ! empty( $normalized_item ) ) {
			$normalized[] = $normalized_item;
		}
	}

	update_user_meta( $user_id, 'quorlyx_saved_seo_suggestions', array_slice( array_values( $normalized ), 0, 40 ) );

	return quorlyx_get_saved_seo_suggestions( $user_id );
}

/**
 * Upsert one or more SEO suggestions into user storage.
 *
 * @param array<int,array<string,mixed>> $suggestions Suggestion items.
 * @param int                            $user_id     User ID.
 * @return array<int,array<string,mixed>>
 */
function quorlyx_upsert_saved_seo_suggestions( $suggestions, $user_id = 0 ) {
	$current = quorlyx_get_saved_seo_suggestions( $user_id );
	$indexed = array();

	foreach ( $current as $item ) {
		$indexed[ $item['storage_key'] ] = $item;
	}

	foreach ( (array) $suggestions as $item ) {
		$normalized_item = quorlyx_normalize_saved_seo_suggestion( $item );
		if ( empty( $normalized_item ) ) {
			continue;
		}

		$existing = $indexed[ $normalized_item['storage_key'] ] ?? array();
		if ( ! empty( $existing['id'] ) ) {
			$normalized_item['id'] = $existing['id'];
		}
		$indexed[ $normalized_item['storage_key'] ] = array_merge( $existing, $normalized_item );
	}

	return quorlyx_save_seo_suggestions( array_values( $indexed ), $user_id );
}

/**
 * Delete one saved SEO suggestion by ID.
 *
 * @param string $suggestion_id Suggestion ID.
 * @param int    $user_id       User ID.
 * @return array<int,array<string,mixed>>
 */
function quorlyx_delete_saved_seo_suggestion( $suggestion_id, $user_id = 0 ) {
	$suggestion_id = sanitize_key( $suggestion_id );
	$current       = quorlyx_get_saved_seo_suggestions( $user_id );
	$remaining     = array_values(
		array_filter(
			$current,
			static function ( $item ) use ( $suggestion_id ) {
				return sanitize_key( $item['id'] ?? '' ) !== $suggestion_id;
			}
		)
	);

	return quorlyx_save_seo_suggestions( $remaining, $user_id );
}

/**
 * Resolve post types included by a bulk SEO improvement scope.
 *
 * @param string $target_scope Scope slug.
 * @return array<int,string>
 */
function quorlyx_get_seo_improvement_scope_post_types( $target_scope ) {
	$target_scope = sanitize_key( $target_scope );

	if ( 'all_posts' === $target_scope ) {
		return array( 'post' );
	}

	if ( 'all_products' === $target_scope && post_type_exists( 'product' ) ) {
		return array( 'product' );
	}

	if ( 'all_posts_products' === $target_scope ) {
		$post_types = array( 'post' );
		if ( post_type_exists( 'product' ) ) {
			$post_types[] = 'product';
		}

		return $post_types;
	}

	return array();
}

/**
 * Build aggregate context for scope-level SEO improvement analysis.
 *
 * @param string $target_scope Scope slug.
 * @return array<string,mixed>
 */
function quorlyx_get_bulk_seo_improvement_context( $target_scope ) {
	$post_types = quorlyx_get_seo_improvement_scope_post_types( $target_scope );
	if ( empty( $post_types ) ) {
		return array();
	}

	$label_map = array(
		'all_posts'          => 'All Posts',
		'all_products'       => 'All Products',
		'all_posts_products' => 'All Posts and Products',
	);

	$posts = get_posts(
		array(
			'post_type'              => $post_types,
			'post_status'            => 'publish',
			'posts_per_page'         => 24,
			'orderby'                => 'date',
			'order'                  => 'DESC',
			'no_found_rows'          => true,
			'ignore_sticky_posts'    => true,
			'update_post_meta_cache' => true,
			'update_post_term_cache' => false,
		)
	);

	$total_published     = 0;
	$total_words         = 0;
	$total_schema        = 0;
	$short_content_count = 0;
	$item_summaries      = array();

	foreach ( $post_types as $post_type ) {
		$counts = wp_count_posts( $post_type );
		if ( $counts && isset( $counts->publish ) ) {
			$total_published += (int) $counts->publish;
		}
	}

	foreach ( $posts as $post ) {
		$content_words = str_word_count( trim( wp_strip_all_tags( (string) $post->post_content ) ) );
		$has_schema    = '' !== trim( (string) get_post_meta( $post->ID, '_quorlyx_generated_schema', true ) );
		$total_words  += $content_words;
		$total_schema += $has_schema ? 1 : 0;

		if ( $content_words > 0 && $content_words < 500 ) {
			++$short_content_count;
		}

		$item_summaries[] = sprintf(
			'- [%s] %s | %s words | %s',
			sanitize_text_field( ucfirst( $post->post_type ) ),
			sanitize_text_field( get_the_title( $post ) ),
			number_format_i18n( $content_words ),
			$has_schema ? 'schema present' : 'no schema'
		);
	}

	$sample_count       = count( $posts );
	$average_word_count = $sample_count > 0 ? (int) round( $total_words / $sample_count ) : 0;
	$schema_coverage    = $sample_count > 0 ? round( ( $total_schema / $sample_count ) * 100, 1 ) : 0;

	return array(
		'target_scope'        => sanitize_key( $target_scope ),
		'target_label'        => sanitize_text_field( $label_map[ $target_scope ] ?? 'Selected Content' ),
		'post_types'          => $post_types,
		'total_published'     => $total_published,
		'sample_count'        => $sample_count,
		'average_word_count'  => $average_word_count,
		'schema_coverage'     => $schema_coverage,
		'short_content_count' => $short_content_count,
		'item_summaries'      => implode( "\n", array_slice( $item_summaries, 0, 18 ) ),
	);
}

/**
 * Build aggregate context for selected post-level SEO analysis.
 *
 * @param array<int,int|string> $post_ids Post IDs.
 * @return array<string,mixed>
 */
function quorlyx_get_multi_seo_improvement_context( $post_ids ) {
	$post_ids = array_values( array_unique( array_filter( array_map( 'absint', (array) $post_ids ) ) ) );
	if ( empty( $post_ids ) ) {
		return array();
	}

	$posts = get_posts(
		array(
			'post_type'              => 'any',
			'post_status'            => 'publish',
			'post__in'               => $post_ids,
			'posts_per_page'         => count( $post_ids ),
			'orderby'                => 'post__in',
			'no_found_rows'          => true,
			'update_post_meta_cache' => true,
			'update_post_term_cache' => false,
		)
	);

	if ( empty( $posts ) ) {
		return array();
	}

	$total_words         = 0;
	$total_schema        = 0;
	$short_content_count = 0;
	$item_summaries      = array();
	$item_details        = array();
	$post_types          = array();

	foreach ( $posts as $post ) {
		$post_types[]    = $post->post_type;
		$content_words   = str_word_count( trim( wp_strip_all_tags( (string) $post->post_content ) ) );
		$has_schema      = '' !== trim( (string) get_post_meta( $post->ID, '_quorlyx_generated_schema', true ) );
		$age_days        = (int) max( 0, floor( ( time() - get_post_time( 'U', true, $post ) ) / DAY_IN_SECONDS ) );
		$excerpt_preview = trim( wp_strip_all_tags( (string) $post->post_excerpt ) );
		$total_words    += $content_words;
		$total_schema   += $has_schema ? 1 : 0;

		if ( $content_words > 0 && $content_words < 500 ) {
			++$short_content_count;
		}

		$item_summaries[] = sprintf(
			'- [%s] %s | %s words | %s | %s days old',
			sanitize_text_field( ucfirst( $post->post_type ) ),
			sanitize_text_field( get_the_title( $post ) ),
			number_format_i18n( $content_words ),
			$has_schema ? 'schema present' : 'no schema',
			number_format_i18n( $age_days )
		);

		$item_details[] = implode(
			"\n",
			array(
				'### ' . sanitize_text_field( get_the_title( $post ) ),
				'- Type: ' . sanitize_text_field( ucfirst( $post->post_type ) ),
				'- URL: ' . esc_url_raw( get_permalink( $post->ID ) ),
				'- Word count: ' . number_format_i18n( $content_words ),
				'- Schema: ' . ( $has_schema ? 'Present' : 'Missing' ),
				'- Age in days: ' . number_format_i18n( $age_days ),
				( '' !== $excerpt_preview ) ? '- Excerpt: ' . quorlyx_pro_sanitize_guide_text( $excerpt_preview, 220 ) : '- Excerpt: None',
			)
		);
	}

	$sample_count       = count( $posts );
	$average_word_count = $sample_count > 0 ? (int) round( $total_words / $sample_count ) : 0;
	$schema_coverage    = $sample_count > 0 ? round( ( $total_schema / $sample_count ) * 100, 1 ) : 0;

	return array(
		'post_ids'            => $post_ids,
		'post_types'          => array_values( array_unique( $post_types ) ),
		'sample_count'        => $sample_count,
		'average_word_count'  => $average_word_count,
		'schema_coverage'     => $schema_coverage,
		'short_content_count' => $short_content_count,
		'item_summaries'      => implode( "\n", array_slice( $item_summaries, 0, 20 ) ),
		'item_details'        => implode( "\n\n", array_slice( $item_details, 0, 8 ) ),
	);
}

/**
 * Render a compact admin question-mark help tooltip.
 *
 * @param string $text Help text.
 * @return void
 */
function quorlyx_admin_help_tip( $text ) {
	$text = trim( wp_strip_all_tags( (string) $text ) );
	if ( '' === $text ) {
		return;
	}

	printf(
		'<span class="quorlyx-help-tip" tabindex="0" role="button" aria-label="%1$s" data-tip="%1$s">?</span>',
		esc_attr( $text )
	);
}

/**
 * Render a setting label with optional question-mark help.
 *
 * @param string $label Label text.
 * @param string $help  Optional help text.
 * @return void
 */
function quorlyx_admin_setting_label( $label, $help = '' ) {
	echo esc_html( $label );
	if ( '' !== trim( (string) $help ) ) {
		quorlyx_admin_help_tip( $help );
	}
}

