/**
 * Render one quick-action repeater row for a variation.
 *
 * @param string              $variation   Variation key.
 * @param int|string          $index       Repeater index.
 * @param array<string,mixed> $action_data Action data.
 * @return void
 */
function quorlyx_render_action_fields( $variation, $index, $action_data ) {
	$v_name      = "quorlyx_options[variation_{$variation}]";
	$name_prefix = "{$v_name}[actions][{$index}]";

	$type    = $action_data['type'] ?? 'url';
	$target  = $action_data['target'] ?? '';
	$message = $action_data['message'] ?? '';
	$context = $action_data['context'] ?? '';
	$label   = $action_data['label'] ?? '';
	$id      = $action_data['id'] ?? 'action_' . uniqid();

	$initial_state = empty( $label ) ? 'edit' : 'view';
	?>
	<div class="quorlyx-repeater-item" data-id="<?php echo esc_attr( $id ); ?>" data-state="<?php echo esc_attr( $initial_state ); ?>">
		<strong class="quorlyx-item-label"><?php echo esc_html( $label ); ?></strong>

		<div class="quorlyx-item-editor">
			<input type="text" name="<?php echo esc_attr( $name_prefix ); ?>[label]" value="<?php echo esc_attr( $label ); ?>" placeholder="Button Label" class="quorlyx-action-label">
			<select name="<?php echo esc_attr( $name_prefix ); ?>[type]" class="quorlyx-action-type">
				<option value="url" <?php selected( $type, 'url' ); ?>>URL (Link)</option>
				<option value="message" <?php selected( $type, 'message' ); ?>>Send Message</option>
			</select>
			<input type="text" name="<?php echo esc_attr( $name_prefix ); ?>[target]" value="<?php echo esc_attr( $target ); ?>" placeholder="https://example.com" class="quorlyx-action-target" style="display:<?php echo ( 'url' === $type ) ? 'block' : 'none'; ?>;">
			<input type="text" name="<?php echo esc_attr( $name_prefix ); ?>[message]" value="<?php echo esc_attr( $message ); ?>" placeholder="Message to send" class="quorlyx-action-message" style="display:<?php echo ( 'message' === $type ) ? 'block' : 'none'; ?>;">
			<textarea name="<?php echo esc_attr( $name_prefix ); ?>[context]" rows="2" placeholder="Optional AI rule for this reply" class="quorlyx-action-context" style="display:<?php echo ( 'message' === $type ) ? 'block' : 'none'; ?>;"><?php echo esc_textarea( $context ); ?></textarea>
			<input type="hidden" name="<?php echo esc_attr( $name_prefix ); ?>[id]" value="<?php echo esc_attr( $id ); ?>" class="quorlyx-action-id">
		</div>

		<div class="quorlyx-item-controls">
			<button type="button" class="button button-secondary quorlyx-edit-item"><span class="dashicons dashicons-edit"></span> Edit</button>
			<button type="button" class="button button-primary quorlyx-done-item"><span class="dashicons dashicons-yes-alt"></span> Done</button>
			<button type="button" class="button quorlyx-remove-item"><span class="dashicons dashicons-trash"></span></button>
		</div>
	</div>
	<?php
}

/**
 * Render global plugin settings fields.
 *
 * @param array<string,mixed> $opts Plugin options.
 * @return void
 */
function quorlyx_render_global_fields( $opts ) {
	?>

	<?php
	$defaults = quorlyx_get_global_defaults();
	$perf     = isset( $opts['performance'] ) && is_array( $opts['performance'] )
		? array_replace( $defaults['performance'], $opts['performance'] )
		: $defaults['performance'];
	?>

	<div class="postbox quorlyx-card" id="tour-step-general-settings">
		<h2 class="hndle"><span><span class="dashicons dashicons-admin-settings"></span> General Settings</span></h2>
		<div class="inside">
			<table class="form-table">
				<tbody>
					<tr>
						<th scope="row"><?php quorlyx_admin_setting_label( 'API Timeout (seconds)', 'Timeout for AI provider requests such as OpenAI, Gemini, Anthropic, Grok, Mistral, or DeepSeek.' ); ?></th>
						<td>
							<input type="number" name="quorlyx_options[api_timeout]" value="<?php echo esc_attr( $opts['api_timeout'] ?? 60 ); ?>" class="small-text" min="10" max="300">
						</td>
					</tr>
				</tbody>
			</table>
		</div>
	</div>

	<div class="postbox quorlyx-card" id="tour-step-performance-controls">
		<h2 class="hndle quorlyx-collapsible-header" style="cursor:pointer;"><span><span class="dashicons dashicons-chart-area"></span> Performance &amp; Cost Controls</span> <span class="dashicons dashicons-arrow-down-alt2 toggle-arrow" style="float:right; margin-top:2px;"></span></h2>
		<div class="inside quorlyx-collapsible-content">
			<table class="form-table">
				<tbody>
	<tr>
		<th scope="row"><?php quorlyx_admin_setting_label( 'Response Cache', 'Cache AI responses for repeated questions with the same context.' ); ?></th>
		<td>
			<label class="switch">
				<input type="checkbox" name="quorlyx_options[performance][response_cache_enabled]" value="1" <?php checked( true, ! empty( $perf['response_cache_enabled'] ) ); ?>>
				<span class="slider round"></span>
			</label>
		</td>
	</tr>
	<tr>
		<th scope="row">Response Cache TTL (seconds)</th>
		<td>
			<input type="number" class="small-text" min="60" step="60" name="quorlyx_options[performance][response_cache_ttl]" value="<?php echo esc_attr( $perf['response_cache_ttl'] ); ?>">
		</td>
	</tr>
	<tr>
		<th scope="row"><?php quorlyx_admin_setting_label( 'Context Cache TTL (seconds)', 'How long to cache site context snippets for the same question.' ); ?></th>
		<td>
			<input type="number" class="small-text" min="60" step="60" name="quorlyx_options[performance][context_cache_ttl]" value="<?php echo esc_attr( $perf['context_cache_ttl'] ); ?>">
		</td>
	</tr>
	<tr id="tour-step-performance-use-object-cache">
		<th scope="row">Use Object Cache</th>
		<td>
			<label>
				<input type="checkbox" name="quorlyx_options[performance][use_object_cache]" value="1" <?php checked( true, ! empty( $perf['use_object_cache'] ) ); ?>>
				Use WordPress object cache (Redis/Memcached) when available.
			</label>
		</td>
	</tr>
	<tr>
		<th scope="row">Reuse Last Context (Session)</th>
		<td>
			<label>
				<input type="checkbox" name="quorlyx_options[performance][session_context_reuse]" value="1" <?php checked( true, ! empty( $perf['session_context_reuse'] ) ); ?>>
				Reuse the last context for short follow-up questions.
			</label>
		</td>
	</tr>
	<tr>
		<th scope="row"><?php quorlyx_admin_setting_label( 'Chat Debounce (ms)', 'Minimum time between user sends to prevent rapid repeat requests.' ); ?></th>
		<td>
			<input type="number" class="small-text" min="0" step="50" name="quorlyx_options[performance][chat_debounce_ms]" value="<?php echo esc_attr( $perf['chat_debounce_ms'] ); ?>">
