/**
 * Renders the Engagement Triggers settings UI.
 *
 * @param array $triggers           Saved trigger configurations.
 * @param bool  $ab_testing_enabled Whether A/B testing is enabled.
 * @param array $conversion_goals   Saved conversion goals.
 * @return void
 */
function quorlyx_render_triggers_ui( $triggers, $ab_testing_enabled = false, $conversion_goals = array() ) {
	?>
	<div class="notice notice-info inline" style="margin-bottom: 15px;">
		<p><strong>Please Note:</strong> By default, only the first trigger to meet its conditions will fire per session. You can allow a specific trigger (e.g., an exit-intent coupon) to still fire later by enabling <em>High priority (override)</em> for that trigger.</p>
	</div>
	<div id="quorlyx-triggers-container">
		<?php
		if ( ! empty( $triggers ) ) {
			foreach ( $triggers as $index => $trigger ) {
				if ( is_array( $trigger ) ) {
					quorlyx_render_trigger_fields( $index, $trigger, $ab_testing_enabled, $conversion_goals );
				}
			}
		}
		?>
	</div>
	<div id="quorlyx-trigger-order-preview" class="notice notice-info inline" style="margin-top:15px;">
		<p><strong>Trigger Order Preview:</strong> This simulates which trigger wins first based on <em>priority score &gt; specificity &gt; created date</em>.</p>
		<div style="display:flex; gap:10px; align-items:flex-end; flex-wrap:wrap; margin-top:8px;">
			<div>
				<label for="quorlyx-trigger-preview-url"><strong>Preview URL</strong></label><br>
				<input type="text" id="quorlyx-trigger-preview-url" class="regular-text" placeholder="https://example.com/pricing" value="<?php echo esc_attr( home_url( add_query_arg( array() ) ) ); ?>">
			</div>
			<button type="button" id="quorlyx-refresh-trigger-preview" class="button">Refresh Order</button>
		</div>
		<table class="widefat striped" style="margin-top:10px;">
			<thead>
				<tr>
					<th style="width:50px;">#</th>
					<th>Trigger</th>
					<th style="width:90px;">Priority</th>
					<th style="width:120px;">Specificity</th>
					<th style="width:120px;">Created</th>
					<th style="width:130px;">Eligibility</th>
				</tr>
			</thead>
			<tbody id="quorlyx-trigger-order-preview-body"></tbody>
		</table>
	</div>
	<button type="button" id="quorlyx-add-trigger" class="button"><span class="dashicons dashicons-plus-alt"></span> Add Trigger</button>
	<div id="quorlyx-trigger-template" style="display:none;">
		<?php quorlyx_render_trigger_fields( '__INDEX__', array(), $ab_testing_enabled, $conversion_goals ); ?>
	</div>
	<?php
}

/**
 * Renders one trigger card in the Engagement Triggers repeater.
 *
 * @param int|string $index              Trigger index used for field names.
 * @param array      $trigger            Trigger settings.
 * @param bool       $ab_testing_enabled Whether A/B testing is enabled.
 * @param array      $conversion_goals   Saved conversion goals.
 * @return void
 */
function quorlyx_render_trigger_fields( $index, $trigger, $ab_testing_enabled = false, $conversion_goals = array() ) {
	$name_prefix   = "quorlyx_options[triggers][{$index}]";
	$defaults      = quorlyx_get_trigger_defaults();
	$trigger       = array_merge( $defaults, $trigger );
	if ( 'section_view' === ( $trigger['type'] ?? '' ) ) {
		$trigger['type'] = 'behavior_pattern';
	}
	$selected_days = array_filter( array_map( 'trim', explode( ',', (string) ( $trigger['schedule_days'] ?? '' ) ) ) );
	$goal_names    = array();
	if ( is_array( $conversion_goals ) ) {
		foreach ( $conversion_goals as $goal ) {
			if ( is_array( $goal ) && ! empty( $goal['name'] ) ) {
				$goal_names[] = sanitize_text_field( $goal['name'] );
			}
		}
	}

	$coupon_codes = quorlyx_get_coupon_codes_for_trigger_ui( 500 );

	$cta_variant        = (string) ( $trigger['recovery_cta_variant'] ?? 'none' );
	$cta_offer_mode     = (string) ( $trigger['recovery_cta_offer_mode'] ?? 'coupon' );
	$show_offer_options = ( 'apply_offer' === $cta_variant );
	$show_coupon_field  = $show_offer_options && ( 'coupon' === $cta_offer_mode );
	$show_custom_fields = ( 'custom' === $cta_variant ) || ( $show_offer_options && ( 'custom_offer' === $cta_offer_mode ) );

	$initial_state = empty( $trigger['name'] ) ? 'edit' : 'view';
	?>
	<div class="quorlyx-trigger-item" data-state="<?php echo esc_attr( $initial_state ); ?>">

		<!-- View State -->
		<div class="quorlyx-repeater-view">
			<label class="quorlyx-switch-toggle">
				<input type="checkbox" name="<?php echo esc_attr( $name_prefix ); ?>[is_active]" value="1" <?php checked( $trigger['is_active'] ); ?>>
				<span class="quorlyx-toggle-slider"><span class="quorlyx-toggle-knob"></span></span>
			</label>
			<div class="quorlyx-trigger-summary">
				<strong class="quorlyx-trigger-summary-name"></strong>
				<span class="quorlyx-trigger-summary-details"></span>
			</div>
			<div class="quorlyx-repeater-controls">
				<button type="button" class="button button-secondary quorlyx-edit-item"><span class="dashicons dashicons-edit"></span> Edit</button>
				<button type="button" class="button quorlyx-remove-item"><span class="dashicons dashicons-trash"></span></button>
			</div>
		</div>

		<!-- Edit State -->
		<div class="quorlyx-repeater-editor">
			<input type="hidden" name="<?php echo esc_attr( $name_prefix ); ?>[id]" value="<?php echo esc_attr( $trigger['id'] ); ?>">
			<input type="hidden" name="<?php echo esc_attr( $name_prefix ); ?>[created_at]" value="<?php echo esc_attr( intval( $trigger['created_at'] ?? 0 ) ); ?>">
			<div class="quorlyx-repeater-header">
				<input type="text" name="<?php echo esc_attr( $name_prefix ); ?>[name]" value="<?php echo esc_attr( $trigger['name'] ); ?>" placeholder="Enter trigger name (e.g., Pricing Page Offer)" class="quorlyx-repeater-name-input">
				<div class="quorlyx-repeater-controls">
					<button type="button" class="button button-primary quorlyx-done-item"><span class="dashicons dashicons-yes-alt"></span> Done</button>
				</div>
			</div>
			<div class="quorlyx-repeater-body">
				<div class="quorlyx-repeater-grid">
					<div class="quorlyx-form-group">
						<label title="Select which user behavior or context should activate this trigger.">Trigger Type</label>
						<select name="<?php echo esc_attr( $name_prefix ); ?>[type]" class="quorlyx-trigger-type-select">
							<option value="time_on_page" <?php selected( $trigger['type'], 'time_on_page' ); ?>>Time on Page</option>
							<option value="scroll_depth" <?php selected( $trigger['type'], 'scroll_depth' ); ?>>Scroll Depth</option>
							<option value="inactivity" <?php selected( $trigger['type'], 'inactivity' ); ?>>Inactivity</option>
							<option value="click_intent" <?php selected( $trigger['type'], 'click_intent' ); ?>>Click Intent</option>
							<option value="cart_abandonment" <?php selected( $trigger['type'], 'cart_abandonment' ); ?>>Cart Abandonment</option>
							<option value="return_visitor" <?php selected( $trigger['type'], 'return_visitor' ); ?>>Return Visitor</option>
							<option value="page_depth" <?php selected( $trigger['type'], 'page_depth' ); ?>>Page Depth</option>
							<option value="utm_referrer" <?php selected( $trigger['type'], 'utm_referrer' ); ?>>UTM / Referrer</option>
							<option value="behavior_pattern" <?php selected( $trigger['type'], 'behavior_pattern' ); ?>>Condition (Instant)</option>
							<option value="exit_intent" <?php selected( $trigger['type'], 'exit_intent' ); ?>>Exit-Intent (PC only)</option>
						</select>
					</div>
					<div class="quorlyx-form-group quorlyx-trigger-option" data-type="time_on_page">
						<label>Delay (seconds)</label>
