/**
 * Sanitizes a CSS selector saved for conversion goal tracking.
 *
 * @param mixed $selector Raw selector.
 * @return string
 */
function quorlyx_sanitize_conversion_goal_selector( $selector ) {
	if ( is_array( $selector ) || is_object( $selector ) ) {
		return '';
	}

	$selector = trim( sanitize_text_field( wp_unslash( (string) $selector ) ) );
	if ( '' === $selector ) {
		return '';
	}

	return substr( $selector, 0, 300 );
}

/**
 * Renders the Conversion Goals settings UI.
 *
 * @param array $goals Saved conversion goals.
 * @return void
 */
function quorlyx_render_conversion_goals_ui( $goals ) {
	?>
	<div id="quorlyx-goals-container">
		<?php
		if ( ! empty( $goals ) ) {
			foreach ( $goals as $index => $goal ) {
				if ( is_array( $goal ) ) {
					quorlyx_render_goal_fields( $index, $goal );
				}
			}
		}
		?>
	</div>
	<button type="button" id="quorlyx-add-goal" class="button"><span class="dashicons dashicons-plus-alt"></span> Add Conversion Goal</button>
	<div id="quorlyx-goal-template" style="display:none;">
		<?php quorlyx_render_goal_fields( '__INDEX__', array() ); ?>
	</div>
	<p class="description">Track conversions by page URL, any detected payment success, CSS selector clicks, form submissions, popular WordPress actions, or WooCommerce product visits.</p>
	<?php
}

/**
 * Renders one conversion goal row in the goals repeater.
 *
 * @param int|string $index Goal index used for field names.
 * @param array      $goal  Goal settings.
 * @return void
 */
function quorlyx_render_goal_fields( $index, $goal ) {
	$name              = $goal['name'] ?? '';
	$is_ab_goal        = $goal['is_ab_goal'] ?? false;
	$method            = $goal['method'] ?? 'url';
	$url               = $goal['url'] ?? '';
	$selector          = $goal['selector'] ?? '';
	$wp_action         = $goal['wp_action'] ?? 'wp_button_click';
	$woo_product_scope = $goal['woo_product_scope'] ?? 'any';
	$woo_products      = $goal['woo_products'] ?? array();
	$has_woo           = class_exists( 'WooCommerce' );
	$common_presets    = quorlyx_get_common_conversion_goal_presets();

	$name      = ( is_array( $name ) || is_object( $name ) ) ? '' : (string) $name;
	$method    = ( is_array( $method ) || is_object( $method ) ) ? 'url' : sanitize_key( (string) $method );
	$url       = ( is_array( $url ) || is_object( $url ) ) ? '' : (string) $url;
	$selector  = quorlyx_sanitize_conversion_goal_selector( $selector );
	$wp_action = ( is_array( $wp_action ) || is_object( $wp_action ) ) ? 'wp_button_click' : sanitize_key( (string) $wp_action );

	if ( ! in_array( $method, array( 'url', 'global_conversion', 'selector_click', 'selector_submit', 'wp_common', 'woo_product_visit' ), true ) ) {
		$method = 'url';
	}
	if ( ! isset( $common_presets[ $wp_action ] ) ) {
		$wp_action = 'wp_button_click';
	}

	$initial_state = empty( $name ) ? 'edit' : 'view';

	$method_label = 'Unknown';
	switch ( $method ) {
		case 'url':
			$method_label = empty( $url ) ? 'Any Page Visit' : 'Specific Page Visit';
			break;
		case 'woo_product_visit':
			$method_label = 'WooCommerce Product Visit';
			break;
		case 'global_conversion':
			$method_label = 'Any Payment Success';
			break;
		case 'selector_click':
			$method_label = 'CSS Selector Click';
			break;
		case 'selector_submit':
			$method_label = 'Form Submit Selector';
			break;
		case 'wp_common':
			$method_label = $common_presets[ $wp_action ]['label'];
			break;
	}
	?>
	<div class="quorlyx-goal-item" data-state="<?php echo esc_attr( $initial_state ); ?>">
		<strong class="quorlyx-item-label"><?php echo esc_html( $name ); ?> <span class="quorlyx-goal-method-label">(<?php echo esc_html( $method_label ); ?>)</span></strong>
		<div class="quorlyx-item-editor">
			<input type="text" name="quorlyx_options[conversion_goals][<?php echo esc_attr( $index ); ?>][name]" value="<?php echo esc_attr( $name ); ?>" placeholder="Goal Name (e.g., 'Contact Page Visit')" class="quorlyx-goal-name regular-text">

			<select name="quorlyx_options[conversion_goals][<?php echo esc_attr( $index ); ?>][method]" class="quorlyx-goal-method">
				<option value="url" <?php selected( $method, 'url' ); ?>>URLs (Contains)</option>
				<option value="global_conversion" <?php selected( $method, 'global_conversion' ); ?>>Any Detected Conversion / Payment Success</option>
				<option value="selector_click" <?php selected( $method, 'selector_click' ); ?>>CSS Selector Click</option>
				<option value="selector_submit" <?php selected( $method, 'selector_submit' ); ?>>Form Submit Selector</option>
				<option value="wp_common" <?php selected( $method, 'wp_common' ); ?>>Popular WordPress Action</option>
				<?php if ( $has_woo ) : ?>
				<option value="woo_product_visit" <?php selected( $method, 'woo_product_visit' ); ?>>WooCommerce Product Visit</option>
				<?php endif; ?>
			</select>

			<div class="quorlyx-goal-field-wrapper quorlyx-goal-url-wrapper" style="<?php echo esc_attr( ( 'url' !== $method ) ? 'display:none;' : '' ); ?>">
				<input type="text" name="quorlyx_options[conversion_goals][<?php echo esc_attr( $index ); ?>][url]" value="<?php echo esc_attr( $url ); ?>" placeholder="/thank-you" class="quorlyx-goal-url regular-text">
				<p class="description">Enter a URL segment (e.g. <code>/thank-you</code>). Matches if the visited URL contains this string. Leave blank to match any visited URL.</p>
			</div>

			<div class="quorlyx-goal-field-wrapper quorlyx-goal-global-wrapper" style="<?php echo esc_attr( ( 'global_conversion' !== $method ) ? 'display:none;' : '' ); ?>">
				<p class="description">Counts real global conversion signals such as WooCommerce order success, third-party checkout overlay success, Behavior custom conversion rules, and external checkouts that call <code>window.Quorlyx.markConversion()</code> or a payment-success alias. Other configured goals are counted separately.</p>
			</div>

			<div class="quorlyx-goal-field-wrapper quorlyx-goal-selector-wrapper" style="<?php echo esc_attr( ( ! in_array( $method, array( 'selector_click', 'selector_submit' ), true ) ) ? 'display:none;' : '' ); ?>">
				<input type="text" name="quorlyx_options[conversion_goals][<?php echo esc_attr( $index ); ?>][selector]" value="<?php echo esc_attr( $selector ); ?>" placeholder=".pricing-button, #claim-starter, form.wpcf7-form" class="quorlyx-goal-selector regular-text">
				<p class="description">For click goals, target a button or link selector. For submit goals, target a form selector.</p>
			</div>

			<div class="quorlyx-goal-field-wrapper quorlyx-goal-common-wrapper" style="<?php echo esc_attr( ( 'wp_common' !== $method ) ? 'display:none;' : '' ); ?>">
				<select name="quorlyx_options[conversion_goals][<?php echo esc_attr( $index ); ?>][wp_action]" class="quorlyx-goal-wp-action">
					<?php foreach ( $common_presets as $preset_key => $preset ) : ?>
						<option value="<?php echo esc_attr( $preset_key ); ?>" <?php selected( $wp_action, $preset_key ); ?>><?php echo esc_html( $preset['label'] ); ?></option>
					<?php endforeach; ?>
				</select>
				<p class="description quorlyx-goal-common-description"><?php echo esc_html( $common_presets[ $wp_action ]['description'] ); ?></p>
			</div>

			<?php if ( $has_woo ) : ?>
			<div class="quorlyx-goal-field-wrapper quorlyx-goal-woocommerce-wrapper" style="<?php echo esc_attr( ( 'woo_product_visit' !== $method ) ? 'display:none;' : '' ); ?>">
				<select name="quorlyx_options[conversion_goals][<?php echo esc_attr( $index ); ?>][woo_product_scope]" class="quorlyx-goal-woo-scope">
					<option value="any" <?php selected( $woo_product_scope, 'any' ); ?>>Any Product</option>
					<option value="specific" <?php selected( $woo_product_scope, 'specific' ); ?>>Specific Products</option>
				</select>
				<div class="quorlyx-goal-woo-products" style="<?php echo ( 'specific' !== $woo_product_scope ) ? 'display:none;' : ''; ?>">
					<select
						class="quorlyx-product-search"
						name="quorlyx_options[conversion_goals][<?php echo esc_attr( $index ); ?>][woo_products][]"
						multiple="multiple"
						style="width: 100%;"
						data-placeholder="Search for and add products..."
					>
						<?php
						if ( ! empty( $woo_products ) ) {
							foreach ( $woo_products as $product_id ) {
								$product = wc_get_product( $product_id );
								if ( $product ) {
									echo '<option value="' . esc_attr( $product_id ) . '" selected="selected">' . esc_html( $product->get_name() ) . '</option>';
								}
							}
						}
						?>
					</select>
				</div>
			</div>
			<?php endif; ?>

			<label class="quorlyx-goal-ab-checkbox">
				<input type="checkbox" name="quorlyx_options[conversion_goals][<?php echo esc_attr( $index ); ?>][is_ab_goal]" value="1" <?php checked( $is_ab_goal ); ?>>
				Use for A/B test
			</label>
		</div>

		<div class="quorlyx-item-controls">
			<button type="button" class="button button-secondary quorlyx-edit-item"><span class="dashicons dashicons-edit"></span> Edit</button>
			<button type="button" class="button button-primary quorlyx-done-item"><span class="dashicons dashicons-yes-alt"></span> Done</button>
			<button type="button" class="button quorlyx-remove-item"><span class="dashicons dashicons-trash"></span></button>
		</div>
	</div>
	<?php
}

/**
 * Sanitizes the conversion goals list before saving options.
 *
 * @param array $raw_goals Raw conversion goals payload.
 * @return array
 */
function quorlyx_sanitize_conversion_goals_list( $raw_goals ) {
	$sanitized_goals = array();

	if ( ! is_array( $raw_goals ) ) {
		return $sanitized_goals;
	}

	foreach ( $raw_goals as $goal ) {
		if ( ! is_array( $goal ) ) {
			continue;
		}

		$goal_name_raw = $goal['name'] ?? '';
		if ( is_array( $goal_name_raw ) || is_object( $goal_name_raw ) ) {
			continue;
		}

		$goal_name = sanitize_text_field( (string) $goal_name_raw );
		if ( '' === $goal_name ) {
			continue;
		}

		$method_raw = $goal['method'] ?? 'url';
		$method     = ( is_array( $method_raw ) || is_object( $method_raw ) ) ? 'url' : sanitize_key( (string) $method_raw );
		if ( ! in_array( $method, array( 'url', 'global_conversion', 'selector_click', 'selector_submit', 'wp_common', 'woo_product_visit' ), true ) ) {
			$method = 'url';
		}

		$sanitized_goal = array(
			'name'       => $goal_name,
			'method'     => $method,
			'is_ab_goal' => ! empty( $goal['is_ab_goal'] ),
		);

		if ( 'url' === $method ) {
			$url_value = $goal['url'] ?? '';
			if ( is_array( $url_value ) || is_object( $url_value ) ) {
				$url_value = '';
			}
			$sanitized_goal['url'] = esc_url_raw( (string) $url_value );
			$sanitized_goals[]     = $sanitized_goal;
			continue;
		}

		if ( 'global_conversion' === $method ) {
			$sanitized_goals[] = $sanitized_goal;
			continue;
		}

		if ( in_array( $method, array( 'selector_click', 'selector_submit' ), true ) ) {
			$selector = quorlyx_sanitize_conversion_goal_selector( $goal['selector'] ?? '' );
			if ( '' === $selector ) {
				continue;
			}

			$sanitized_goal['selector'] = $selector;
			$sanitized_goals[]         = $sanitized_goal;
			continue;
		}

		if ( 'wp_common' === $method ) {
			$wp_action_raw = $goal['wp_action'] ?? 'wp_button_click';
			$wp_action     = ( is_array( $wp_action_raw ) || is_object( $wp_action_raw ) ) ? 'wp_button_click' : sanitize_key( (string) $wp_action_raw );
			if ( ! isset( quorlyx_get_common_conversion_goal_presets()[ $wp_action ] ) ) {
				$wp_action = 'wp_button_click';
			}

			$sanitized_goal['wp_action'] = $wp_action;
			$sanitized_goals[]          = $sanitized_goal;
			continue;
		}

		if ( 'woo_product_visit' === $method && class_exists( 'WooCommerce' ) ) {
			$scope_value = $goal['woo_product_scope'] ?? 'any';
			if ( is_array( $scope_value ) || is_object( $scope_value ) ) {
				$scope_value = 'any';
			}

			$sanitized_goal['woo_product_scope'] = ( 'specific' === $scope_value ) ? 'specific' : 'any';
			$sanitized_goal['woo_products']      = array();

			if ( 'specific' === $sanitized_goal['woo_product_scope'] && ! empty( $goal['woo_products'] ) && is_array( $goal['woo_products'] ) ) {
				foreach ( $goal['woo_products'] as $pid ) {
					$sanitized_goal['woo_products'][] = absint( $pid );
				}
			}

			$sanitized_goals[] = $sanitized_goal;
		}
	}

	return array_values( $sanitized_goals );
}

/**
 * Renders the media uploader field markup.
 *
 * @param array $args Media field arguments.
 * @return void
 */
function quorlyx_field_media( $args ) {
	$name  = $args['name'];
	$value = $args['value'] ?? '';
	?>
	<div class="quorlyx-media-uploader">
		<input type="hidden" name="<?php echo esc_attr( $name ); ?>" value="<?php echo esc_url( $value ); ?>" class="media-url"/>
		<button type="button" class="button upload-button">Upload</button>
		<button type="button" class="button remove-button" style="<?php echo empty( $value ) ? 'display:none;' : ''; ?>">Remove</button>
		<div class="image-preview-wrapper" style="margin-top:10px;">
			<?php if ( ! empty( $value ) ) : ?>
				<img src="<?php echo esc_url( $value ); ?>" style="max-width:64px;max-height:64px;border-radius:50%;"/>
			<?php endif; ?>
		</div>
	</div>
	<?php
}

/**
 * Render uploaded Knowledge Base file selector.
 *
 * @param string           $name     Field name.
 * @param array<int,int>   $file_ids Attachment IDs.
 * @return void
 */
function quorlyx_render_knowledge_base_file_uploader( $name, $file_ids ) {
	$file_ids = array_values( array_filter( array_map( 'absint', (array) $file_ids ) ) );
	?>
	<div class="quorlyx-kb-file-uploader">
		<input type="hidden" name="<?php echo esc_attr( $name ); ?>" value="<?php echo esc_attr( implode( ',', $file_ids ) ); ?>" class="quorlyx-kb-file-ids">
		<button type="button" class="button button-secondary quorlyx-kb-file-upload"><span class="dashicons dashicons-upload" style="vertical-align:text-bottom;"></span> Add / Upload Files</button>
		<ul class="quorlyx-kb-file-list" style="margin:10px 0 0;">
			<?php foreach ( $file_ids as $file_id ) : ?>
				<?php
				if ( 'attachment' !== get_post_type( $file_id ) ) {
					continue;
				}
				$mime = (string) get_post_mime_type( $file_id );
				if ( ! quorlyx_is_allowed_knowledge_base_file_mime( $mime ) ) {
					continue;
				}
				?>
				<li data-id="<?php echo esc_attr( $file_id ); ?>" style="display:flex; align-items:center; gap:8px; margin:4px 0;">
					<span class="dashicons dashicons-media-document"></span>
					<span class="quorlyx-kb-file-title"><?php echo esc_html( get_the_title( $file_id ) ); ?></span>
					<code><?php echo esc_html( $mime ); ?></code>
					<button type="button" class="button-link-delete quorlyx-kb-file-remove">Remove</button>
				</li>
			<?php endforeach; ?>
		</ul>
		<p class="description">Add files Quorlyx can use as private chat knowledge. Supported formats: PDF, TXT, Markdown, CSV, JSON, HTML, and XML.</p>
	</div>
	<?php
}

/**
 * Sanitizes and normalizes plugin options before persisting them.
 *
 * @param array $input Raw options submitted from the settings form.
 * @return array
 */
function quorlyx_sanitize_options( $input ) {
	$defaults = quorlyx_get_global_defaults();
	$output   = get_option( 'quorlyx_options', $defaults );
	$output   = quorlyx_merge_global_options( $output );
	unset( $output['conversion_goals_json'] );

	if ( isset( $output['fallback_provider'] ) || isset( $output['fallback_model'] ) || isset( $output['fallback_cooldown'] ) || isset( $output['fallback_cooldown_minutes'] ) ) {
		if ( ! isset( $output['performance'] ) || ! is_array( $output['performance'] ) ) {
			$output['performance'] = $defaults['performance'];
		}
		if ( empty( $output['performance']['fallback_provider'] ) && ! empty( $output['fallback_provider'] ) ) {
			$output['performance']['fallback_provider'] = sanitize_key( $output['fallback_provider'] );
		}
		if ( empty( $output['performance']['fallback_model'] ) && ! empty( $output['fallback_model'] ) ) {
			$output['performance']['fallback_model'] = sanitize_text_field( $output['fallback_model'] );
		}
		$legacy_cooldown = $output['fallback_cooldown_minutes'] ?? ( $output['fallback_cooldown'] ?? null );
		if ( empty( $output['performance']['fallback_cooldown_minutes'] ) && null !== $legacy_cooldown ) {
			$output['performance']['fallback_cooldown_minutes'] = max( 0, absint( $legacy_cooldown ) );
		}
		unset( $output['fallback_provider'], $output['fallback_model'], $output['fallback_cooldown'], $output['fallback_cooldown_minutes'] );
	}

	$output['ab_testing_enabled'] = ! empty( $input['ab_testing_enabled'] );
	$output['api_timeout']        = max( 10, min( 300, absint( $input['api_timeout'] ?? $output['api_timeout'] ) ) );

	if ( array_key_exists( 'triggers', $input ) && is_array( $input['triggers'] ) ) {
		$output['triggers'] = array();
		foreach ( $input['triggers'] as $trigger ) {
			if ( ! is_array( $trigger ) || empty( $trigger['name'] ) ) {
				continue;
			}

			$sanitized_trigger    = quorlyx_sanitize_trigger_settings( $trigger );
			$output['triggers'][] = $sanitized_trigger;
		}
		$output['triggers'] = quorlyx_normalize_trigger_ids( $output['triggers'] );
	}

	if ( isset( $input['post_generator'] ) && is_array( $input['post_generator'] ) ) {
		$pg_in = $input['post_generator'];

		$san_pg = isset( $output['post_generator'] ) && is_array( $output['post_generator'] )
			? array_replace_recursive( $defaults['post_generator'], $output['post_generator'] )
			: $defaults['post_generator'];

		$san_pg['enabled']       = ! empty( $pg_in['enabled'] );
		$san_pg['schedule']      = sanitize_text_field( $pg_in['schedule'] ?? $san_pg['schedule'] );
		$san_pg['posts_per_run'] = absint( $pg_in['posts_per_run'] ?? $san_pg['posts_per_run'] );
		$san_pg['keywords']      = sanitize_textarea_field( $pg_in['keywords'] ?? $san_pg['keywords'] );
		$san_pg['instructions']  = sanitize_textarea_field( $pg_in['instructions'] ?? $san_pg['instructions'] );
		$san_pg['post_type']     = sanitize_text_field( $pg_in['post_type'] ?? $san_pg['post_type'] );
		$san_pg['author_id']     = absint( $pg_in['author_id'] ?? $san_pg['author_id'] );
		$san_pg['post_status']   = in_array( ( $pg_in['post_status'] ?? $san_pg['post_status'] ), array( 'draft', 'publish' ), true ) ? $pg_in['post_status'] : $san_pg['post_status'];

		$san_pg['ai_provider_scope'] = in_array( ( $pg_in['ai_provider_scope'] ?? 'general' ), array( 'general', 'independent' ), true ) ? $pg_in['ai_provider_scope'] : 'general';
		$allowed_pg_providers        = array( 'gemini', 'openai', 'anthropic', 'grok', 'mistral', 'deepseek' );
		$raw_pg_provider             = sanitize_key( $pg_in['ai_provider'] ?? $san_pg['ai_provider'] );
		if ( ! in_array( $raw_pg_provider, $allowed_pg_providers, true ) ) {
			$raw_pg_provider = 'gemini';
		}
		$san_pg['ai_provider'] = $raw_pg_provider;
		$san_pg['ai_api_key']  = quorlyx_sanitize_secret_input( $pg_in['ai_api_key'] ?? null, $san_pg['ai_api_key'] ?? '' );
		$san_pg['ai_model']    = sanitize_text_field( $pg_in['ai_model'] ?? $san_pg['ai_model'] );

		$san_pg['source']               = in_array( ( $pg_in['source'] ?? 'keywords' ), array( 'keywords', 'products_all', 'products_specific' ), true ) ? ( $pg_in['source'] ?? 'keywords' ) : 'keywords';
		$san_pg['specific_product_ids'] = sanitize_text_field( $pg_in['specific_product_ids'] ?? '' );
		$san_pg['products_queue']       = sanitize_textarea_field( $pg_in['products_queue'] ?? '' );
		$san_pg['prevent_duplicates']   = ! empty( $pg_in['prevent_duplicates'] );

		if ( ! empty( $pg_in['recommendations'] ) && is_array( $pg_in['recommendations'] ) ) {
			$rec_in                                        = $pg_in['recommendations'];
			$san_pg['recommendations']['enabled']          = ! empty( $rec_in['enabled'] );
			$san_pg['recommendations']['include_products'] = ! empty( $rec_in['include_products'] );
			$san_pg['recommendations']['include_posts']    = ! empty( $rec_in['include_posts'] );
			$san_pg['recommendations']['include_services'] = ! empty( $rec_in['include_services'] );
			$san_pg['recommendations']['use_tax_relevance'] = ! empty( $rec_in['use_tax_relevance'] );
			$san_pg['recommendations']['max_items']         = absint( $rec_in['max_items'] ?? $san_pg['recommendations']['max_items'] );
		}
		$output['post_generator'] = $san_pg;
	}

	$output['performance']      = isset( $output['performance'] ) && is_array( $output['performance'] )
		? array_replace( $defaults['performance'], $output['performance'] )
		: $defaults['performance'];
	$output['content_insights'] = isset( $output['content_insights'] ) && is_array( $output['content_insights'] )
		? array_replace( $defaults['content_insights'], $output['content_insights'] )
		: $defaults['content_insights'];

	if ( isset( $input['performance'] ) && is_array( $input['performance'] ) ) {
		$perf_in = $input['performance'];
		$perf    = $defaults['performance'];

		$perf['response_cache_enabled'] = ! empty( $perf_in['response_cache_enabled'] );
		$perf['response_cache_ttl']     = max( 60, absint( $perf_in['response_cache_ttl'] ?? $perf['response_cache_ttl'] ) );
		$perf['context_cache_ttl']      = max( 60, absint( $perf_in['context_cache_ttl'] ?? $perf['context_cache_ttl'] ) );
		$perf['use_object_cache']       = ! empty( $perf_in['use_object_cache'] );
		$perf['session_context_reuse']  = ! empty( $perf_in['session_context_reuse'] );
		$perf['chat_debounce_ms']       = max( 0, absint( $perf_in['chat_debounce_ms'] ?? $perf['chat_debounce_ms'] ) );
		$perf['rate_limit_enabled']     = ! empty( $perf_in['rate_limit_enabled'] );
		$perf['rate_limit_requests']    = max( 1, absint( $perf_in['rate_limit_requests'] ?? $perf['rate_limit_requests'] ) );
		$perf['rate_limit_window']      = max( 60, absint( $perf_in['rate_limit_window'] ?? $perf['rate_limit_window'] ) );
		$perf['prompt_trim_enabled']    = ! empty( $perf_in['prompt_trim_enabled'] );
		$perf['prompt_trim_max_chars']  = max( 200, absint( $perf_in['prompt_trim_max_chars'] ?? $perf['prompt_trim_max_chars'] ) );

		$allowed_detail                        = array( 'full', 'compact' );
		$detail                                = sanitize_key( $perf_in['context_detail_level'] ?? $perf['context_detail_level'] );
		$perf['context_detail_level']          = in_array( $detail, $allowed_detail, true ) ? $detail : $perf['context_detail_level'];
		$perf['context_excerpt_words']         = max( 10, absint( $perf_in['context_excerpt_words'] ?? $perf['context_excerpt_words'] ) );
		$perf['context_product_excerpt_words'] = max( 10, absint( $perf_in['context_product_excerpt_words'] ?? $perf['context_product_excerpt_words'] ) );
		$perf['rendered_context_max_chars']    = max( 1000, min( 30000, absint( $perf_in['rendered_context_max_chars'] ?? $perf['rendered_context_max_chars'] ) ) );
		$perf['knowledge_file_context_limit']  = max( 1, min( 10, absint( $perf_in['knowledge_file_context_limit'] ?? $perf['knowledge_file_context_limit'] ) ) );
		$perf['knowledge_file_excerpt_chars']  = max( 500, min( 20000, absint( $perf_in['knowledge_file_excerpt_chars'] ?? $perf['knowledge_file_excerpt_chars'] ) ) );
		$perf['history_max_messages']          = max( 2, min( 100, absint( $perf_in['history_max_messages'] ?? $perf['history_max_messages'] ) ) );
		$perf['history_max_chars']             = max( 1000, min( 100000, absint( $perf_in['history_max_chars'] ?? $perf['history_max_chars'] ) ) );
		$perf['conversation_retention_days']   = max( 30, min( 3650, absint( $perf_in['conversation_retention_days'] ?? $perf['conversation_retention_days'] ) ) );
		$perf['submission_retention_days']     = max( 30, min( 3650, absint( $perf_in['submission_retention_days'] ?? $perf['submission_retention_days'] ) ) );
		$perf['local_greeting_enabled']        = ! empty( $perf_in['local_greeting_enabled'] );

		$perf['model_routing_enabled']           = ! empty( $perf_in['model_routing_enabled'] );
		$allowed_routing_providers               = array( 'gemini', 'openai', 'anthropic', 'grok', 'mistral', 'deepseek' );
		$raw_routing_provider                    = sanitize_key( $perf_in['model_routing_provider'] ?? $perf['model_routing_provider'] );
		$perf['model_routing_provider']          = in_array( $raw_routing_provider, $allowed_routing_providers, true ) ? $raw_routing_provider : '';
		$perf['model_routing_model']             = sanitize_text_field( $perf_in['model_routing_model'] ?? $perf['model_routing_model'] );
		$perf['model_routing_max_chars']         = max( 20, absint( $perf_in['model_routing_max_chars'] ?? $perf['model_routing_max_chars'] ) );
		$perf['model_routing_max_words']         = max( 3, absint( $perf_in['model_routing_max_words'] ?? $perf['model_routing_max_words'] ) );
		$perf['model_routing_include_greetings'] = ! empty( $perf_in['model_routing_include_greetings'] );
		$perf['tool_calling_products_enabled']   = ! empty( $perf_in['tool_calling_products_enabled'] );
		$perf['tool_calling_results_limit']      = max( 1, min( 10, absint( $perf_in['tool_calling_results_limit'] ?? $perf['tool_calling_results_limit'] ) ) );

		if ( empty( $perf['model_routing_provider'] ) || ( 'gemini' === $perf['model_routing_provider'] && quorlyx_google_model_requires_interactions_api( $perf['model_routing_model'] ) ) ) {
			$perf['model_routing_model'] = '';
		}
		if ( ! empty( $perf['model_routing_enabled'] ) && ( empty( $perf['model_routing_provider'] ) || empty( $perf['model_routing_model'] ) ) ) {
			$perf['model_routing_enabled'] = false;
		}

		$perf['fallback_enabled']          = ! empty( $perf_in['fallback_enabled'] );
		$allowed_fallback_providers        = array( 'gemini', 'openai', 'anthropic', 'grok', 'mistral', 'deepseek' );
		$raw_fallback_provider             = sanitize_key( $perf_in['fallback_provider'] ?? $perf['fallback_provider'] );
		$perf['fallback_provider']         = in_array( $raw_fallback_provider, $allowed_fallback_providers, true ) ? $raw_fallback_provider : '';
		$perf['fallback_model']            = sanitize_text_field( $perf_in['fallback_model'] ?? $perf['fallback_model'] );
		$perf['fallback_cooldown_minutes'] = max( 0, absint( $perf_in['fallback_cooldown_minutes'] ?? $perf['fallback_cooldown_minutes'] ) );

		// Guardrail: fallback must have both provider + model. Avoid "enabled but empty" broken state.
		if ( empty( $perf['fallback_provider'] ) || ( 'gemini' === $perf['fallback_provider'] && quorlyx_google_model_requires_interactions_api( $perf['fallback_model'] ) ) ) {
			$perf['fallback_model'] = '';
		}
		if ( ! empty( $perf['fallback_enabled'] ) && ( empty( $perf['fallback_provider'] ) || empty( $perf['fallback_model'] ) ) ) {
			$perf['fallback_enabled'] = false;
		}

		$output['performance'] = $perf;
	}

	if ( isset( $input['content_insights'] ) && is_array( $input['content_insights'] ) ) {
		$content_insights = $defaults['content_insights'];
		$insights_in      = $input['content_insights'];

		$content_insights['enabled']                     = ! empty( $insights_in['enabled'] );
		$content_insights['prefer_db_processing_global'] = ! empty( $insights_in['prefer_db_processing_global'] );
		$content_insights['tracking_mode']               = in_array( ( $insights_in['tracking_mode'] ?? 'all_public' ), array( 'all_public', 'post_types', 'specific_items' ), true ) ? $insights_in['tracking_mode'] : 'all_public';
		$conversion_tracking_mode                        = sanitize_key( $insights_in['conversion_tracking_mode'] ?? $content_insights['conversion_tracking_mode'] );
		$content_insights['conversion_tracking_mode']    = in_array( $conversion_tracking_mode, array( 'any', 'conversion_goals' ), true ) ? $conversion_tracking_mode : 'any';

		$allowed_post_types                              = array_keys( quorlyx_get_content_insights_post_types() );
		$content_insights['tracked_post_types']          = array_values(
			array_intersect(
				$allowed_post_types,
				array_map( 'sanitize_key', (array) ( $insights_in['tracked_post_types'] ?? array() ) )
			)
		);
		$content_insights['target_page_urls']            = quorlyx_sanitize_content_insights_rule_list( $insights_in['target_page_urls'] ?? array() );
		$content_insights['target_url_contains']         = quorlyx_sanitize_content_insights_rule_list( $insights_in['target_url_contains'] ?? array() );
		$content_insights['excluded_post_types']         = array_values(
			array_intersect(
				$allowed_post_types,
				array_map( 'sanitize_key', (array) ( $insights_in['excluded_post_types'] ?? array() ) )
			)
		);
		$content_insights['excluded_page_urls']          = quorlyx_sanitize_content_insights_rule_list( $insights_in['excluded_page_urls'] ?? array() );
		$content_insights['excluded_url_contains']       = quorlyx_sanitize_content_insights_rule_list( $insights_in['excluded_url_contains'] ?? array() );
		$allowed_sources                                 = array( 'any', 'ai_generated', 'manual' );
		$content_source                                  = sanitize_key( $insights_in['content_source'] ?? $content_insights['content_source'] );
		$content_insights['content_source']              = in_array( $content_source, $allowed_sources, true ) ? $content_source : $content_insights['content_source'];
		$allowed_improvement_status                      = array( 'any', 'improved', 'not_improved' );
		$improvement_status                              = sanitize_key( $insights_in['improvement_status'] ?? $content_insights['improvement_status'] );
		$content_insights['improvement_status']          = in_array( $improvement_status, $allowed_improvement_status, true ) ? $improvement_status : $content_insights['improvement_status'];
		$content_insights['opportunity_score_threshold'] = max( 0, min( 100, absint( $insights_in['opportunity_score_threshold'] ?? $content_insights['opportunity_score_threshold'] ) ) );
		$content_insights['top_opportunities_limit']     = max( 1, min( 20, absint( $insights_in['top_opportunities_limit'] ?? $content_insights['top_opportunities_limit'] ) ) );
		$content_insights['dataset_candidate_limit']     = max( 100, min( 5000, absint( $insights_in['dataset_candidate_limit'] ?? $content_insights['dataset_candidate_limit'] ?? 1000 ) ) );

		$behavior_defaults = is_array( $content_insights['behavior_patterns'] ?? null ) ? $content_insights['behavior_patterns'] : array();
		$behavior_in       = isset( $insights_in['behavior_patterns'] ) && is_array( $insights_in['behavior_patterns'] ) ? $insights_in['behavior_patterns'] : array();
		$metric_defaults      = is_array( $behavior_defaults['pattern_metrics'] ?? null ) ? $behavior_defaults['pattern_metrics'] : array(
			'visit_frequency' => true,
			'pages_viewed'    => true,
			'dwell_time_avg'  => true,
			'cart_activity'   => true,
			'scroll_depth'    => true,
			'started_chat'    => true,
			'checkout_flow'   => true,
			'traffic_source'  => true,
		);
		$has_metric_input    = isset( $behavior_in['pattern_metrics'] ) && is_array( $behavior_in['pattern_metrics'] );
		$metric_input        = $has_metric_input ? $behavior_in['pattern_metrics'] : array();
		$pattern_metrics     = array();
		$weight_defaults     = is_array( $behavior_defaults['pattern_metric_weights'] ?? null ) ? $behavior_defaults['pattern_metric_weights'] : array_fill_keys( array_keys( $metric_defaults ), 1.0 );
		$weight_input        = isset( $behavior_in['pattern_metric_weights'] ) && is_array( $behavior_in['pattern_metric_weights'] ) ? $behavior_in['pattern_metric_weights'] : array();
		$pattern_metric_weights = array();

		foreach ( $metric_defaults as $metric_key => $metric_default ) {
			if ( $has_metric_input ) {
				$pattern_metrics[ $metric_key ] = ! empty( $metric_input[ $metric_key ] );
			} else {
				$pattern_metrics[ $metric_key ] = ! empty( $metric_default );
			}

			$raw_weight = array_key_exists( $metric_key, $weight_input ) ? (float) $weight_input[ $metric_key ] : (float) ( $weight_defaults[ $metric_key ] ?? 1.0 );
			$pattern_metric_weights[ $metric_key ] = max( 0.1, min( 10.0, round( $raw_weight, 2 ) ) );
		}

		$legacy_action_type         = sanitize_key( (string) ( $behavior_in['conversion_action_type'] ?? ( $behavior_defaults['conversion_action_type'] ?? 'buy' ) ) );
		$legacy_form_selector       = sanitize_text_field( (string) ( $behavior_in['track_form_selector'] ?? ( $behavior_defaults['track_form_selector'] ?? 'form' ) ) );
		$legacy_form_selector       = '' !== trim( $legacy_form_selector ) ? trim( $legacy_form_selector ) : 'form';
		$track_woocommerce_purchase = ! empty( $behavior_in['track_woocommerce_purchase'] );
		if ( ! array_key_exists( 'track_woocommerce_purchase', $behavior_in ) ) {
			$track_woocommerce_purchase = ! in_array( $legacy_action_type, array( 'form_submit' ), true );
		}

		$custom_conversions = array();
		if ( isset( $behavior_in['custom_conversions_input'] ) ) {
			$custom_conversion_lines = preg_split( '/\r\n|\r|\n/', (string) $behavior_in['custom_conversions_input'] );
			if ( is_array( $custom_conversion_lines ) ) {
				foreach ( $custom_conversion_lines as $custom_conversion_line ) {
					$custom_conversion_line = trim( (string) $custom_conversion_line );
					if ( '' === $custom_conversion_line ) {
						continue;
					}

					$line_parts = explode( ':', $custom_conversion_line, 2 );
					if ( 2 !== count( $line_parts ) ) {
						continue;
					}

					$custom_conversions[] = array(
						'type'   => sanitize_key( (string) $line_parts[0] ),
						'target' => sanitize_text_field( (string) $line_parts[1] ),
					);
				}
			}
		} elseif ( isset( $behavior_in['custom_conversions'] ) && is_array( $behavior_in['custom_conversions'] ) ) {
			$custom_conversions = $behavior_in['custom_conversions'];
		}

		$custom_conversions = quorlyx_normalize_behavior_custom_conversions( $custom_conversions );

		if ( empty( $custom_conversions ) && in_array( $legacy_action_type, array( 'form_submit', 'buy_or_form' ), true ) ) {
			$custom_conversions[] = array(
				'type'   => 'form_submit',
				'target' => $legacy_form_selector,
			);
		}

		$content_insights['behavior_patterns'] = array(
			'enabled'                         => ! empty( $behavior_in['enabled'] ),
			'include_buyers'                  => ! empty( $behavior_in['include_buyers'] ),
			'include_non_converters'          => ! empty( $behavior_in['include_non_converters'] ),
			'prefer_db_processing'            => ! empty( $behavior_in['prefer_db_processing'] ),
			'track_woocommerce_purchase'      => $track_woocommerce_purchase,
			'custom_conversions'              => $custom_conversions,
			'include_checkout_flow'           => ! empty( $behavior_in['include_checkout_flow'] ),
			'use_reference_matching'          => ! empty( $behavior_in['use_reference_matching'] ),
			'reference_error_tolerance_pct'   => max( 0, min( 50, absint( $behavior_in['reference_error_tolerance_pct'] ?? ( $behavior_defaults['reference_error_tolerance_pct'] ?? 15 ) ) ) ),
			'reference_min_profiles'          => max( 5, min( 10000, absint( $behavior_in['reference_min_profiles'] ?? ( $behavior_defaults['reference_min_profiles'] ?? 20 ) ) ) ),
			'reference_min_pattern_samples'   => max( 1, min( 100, absint( $behavior_in['reference_min_pattern_samples'] ?? ( $behavior_defaults['reference_min_pattern_samples'] ?? 3 ) ) ) ),
			'reference_fallback_to_rules'     => ! empty( $behavior_in['reference_fallback_to_rules'] ),
			'pattern_metrics'                 => $pattern_metrics,
			'pattern_metric_weights'          => $pattern_metric_weights,
			'non_converter_sample_rate'       => 100,
			'min_sessions_for_classification' => max( 1, min( 20, absint( $behavior_in['min_sessions_for_classification'] ?? ( $behavior_defaults['min_sessions_for_classification'] ?? 1 ) ) ) ),
			'sync_interval_minutes'           => max( 1, min( 120, absint( $behavior_in['sync_interval_minutes'] ?? ( $behavior_defaults['sync_interval_minutes'] ?? 15 ) ) ) ),
			'batch_delay_ms'                  => max( 500, min( 10000, absint( $behavior_in['batch_delay_ms'] ?? ( $behavior_defaults['batch_delay_ms'] ?? 2000 ) ) ) ),
			'min_snapshot_gap_seconds'        => max( 2, min( 60, absint( $behavior_in['min_snapshot_gap_seconds'] ?? ( $behavior_defaults['min_snapshot_gap_seconds'] ?? 8 ) ) ) ),
			'server_min_snapshot_gap_seconds' => max( 2, min( 60, absint( $behavior_in['server_min_snapshot_gap_seconds'] ?? ( $behavior_defaults['server_min_snapshot_gap_seconds'] ?? 6 ) ) ) ),
			'profile_retention_days'          => max( 7, min( 365, absint( $behavior_in['profile_retention_days'] ?? ( $behavior_defaults['profile_retention_days'] ?? 90 ) ) ) ),
			'calibration_lookback_days'       => max( 1, min( 90, absint( $behavior_in['calibration_lookback_days'] ?? ( $behavior_defaults['calibration_lookback_days'] ?? 30 ) ) ) ),
			'min_profiles_calibration'        => max( 1, min( 500, absint( $behavior_in['min_profiles_calibration'] ?? ( $behavior_defaults['min_profiles_calibration'] ?? 10 ) ) ) ),
			'prediction_confidence'           => max( 10, min( 100, absint( $behavior_in['prediction_confidence'] ?? ( $behavior_defaults['prediction_confidence'] ?? 80 ) ) ) ),
		);
		$output['content_insights'] = $content_insights;
	}

	if ( isset( $input['variation_a'] ) ) {
		$output['enable_email_notifications']      = ! empty( $input['enable_email_notifications'] );
		$output['notification_email']              = sanitize_email( $input['notification_email'] ?? $defaults['notification_email'] );
		$output['enable_transcript_notifications'] = ! empty( $input['enable_transcript_notifications'] );
	}

	$conversion_goals_source   = null;
	$has_conversion_goals_json = false;
	if ( array_key_exists( 'conversion_goals_json', $input ) ) {
		$json_value = $input['conversion_goals_json'];
		if ( ! is_array( $json_value ) && ! is_object( $json_value ) ) {
			$json_value = trim( wp_unslash( (string) $json_value ) );
			if ( '' !== $json_value ) {
				$has_conversion_goals_json = true;
				$decoded_goals             = json_decode( $json_value, true );
				if ( JSON_ERROR_NONE === json_last_error() && is_array( $decoded_goals ) ) {
					$conversion_goals_source = $decoded_goals;
				}
			}
		}
	}

	if ( null === $conversion_goals_source && ! $has_conversion_goals_json && array_key_exists( 'conversion_goals', $input ) ) {
		$conversion_goals_source = $input['conversion_goals'];
	}

	if ( null !== $conversion_goals_source ) {
		$output['conversion_goals'] = quorlyx_sanitize_conversion_goals_list( $conversion_goals_source );
	}

	foreach ( array( 'a', 'b' ) as $v ) {
		if ( isset( $input[ "variation_{$v}" ] ) ) {
			$variation_input = $input[ "variation_{$v}" ];
			$v_defaults      = $defaults[ "variation_{$v}" ];

			$existing_v                  = isset( $output[ "variation_{$v}" ] ) && is_array( $output[ "variation_{$v}" ] ) ? $output[ "variation_{$v}" ] : array();
			$fallback                    = array_replace( $v_defaults, $existing_v );
			$sanitized_v                 = array();
			$sanitized_v['chat_enabled'] = ! empty( $variation_input['chat_enabled'] );

			$allowed_variation_providers = array( 'gemini', 'openai', 'anthropic', 'grok', 'mistral', 'deepseek' );
			$raw_variation_provider      = sanitize_key( $variation_input['ai_provider'] ?? $fallback['ai_provider'] );
			$sanitized_v['ai_provider']  = in_array( $raw_variation_provider, $allowed_variation_providers, true ) ? $raw_variation_provider : 'gemini';
			$sanitized_v['api_keys']    = array(
				'gemini'    => '',
				'openai'    => '',
				'anthropic' => '',
				'grok'      => '',
				'mistral'   => '',
				'deepseek'  => '',
			);
			$existing_api_keys          = isset( $fallback['api_keys'] ) && is_array( $fallback['api_keys'] ) ? $fallback['api_keys'] : array();
			$submitted_api_keys         = isset( $variation_input['api_keys'] ) && is_array( $variation_input['api_keys'] ) ? $variation_input['api_keys'] : array();
			foreach ( array_keys( $sanitized_v['api_keys'] ) as $provider ) {
				$sanitized_v['api_keys'][ $provider ] = quorlyx_sanitize_secret_input(
					$submitted_api_keys[ $provider ] ?? null,
					(string) ( $existing_api_keys[ $provider ] ?? '' )
				);
			}
			$sanitized_v['ai_model']        = sanitize_text_field( $variation_input['ai_model'] ?? $fallback['ai_model'] );
			$sanitized_v['bot_name']        = sanitize_text_field( $variation_input['bot_name'] ?? $fallback['bot_name'] );
			$sanitized_v['primary_color']   = sanitize_hex_color( $variation_input['primary_color'] ?? $fallback['primary_color'] );
			$sanitized_v['floating_logo']   = esc_url_raw( $variation_input['floating_logo'] ?? ( $fallback['floating_logo'] ?? '' ) );
			$sanitized_v['floating_label']  = sanitize_text_field( $variation_input['floating_label'] ?? $fallback['floating_label'] );
			$sanitized_v['welcome_message'] = sanitize_textarea_field( $variation_input['welcome_message'] ?? $fallback['welcome_message'] );
			$sanitized_v['loading_message'] = sanitize_text_field( $variation_input['loading_message'] ?? $fallback['loading_message'] );
			$sanitized_v['ai_persona']      = wp_kses_post( $variation_input['ai_persona'] ?? $fallback['ai_persona'] );
			$valid_chat_format_modes        = array( 'free_ai', 'template_locked', 'hybrid_required_tokens' );
			$valid_missing_policies         = array( 'use_fallback_message', 'hide', 'fallback_text' );
			$raw_chat_format_mode           = sanitize_key( $variation_input['chat_format_mode'] ?? $fallback['chat_format_mode'] ?? 'free_ai' );
			$raw_chat_missing_policy        = sanitize_key( $variation_input['chat_missing_placeholder_policy'] ?? $fallback['chat_missing_placeholder_policy'] ?? 'use_fallback_message' );
			$sanitized_v['chat_format_mode']                = in_array( $raw_chat_format_mode, $valid_chat_format_modes, true ) ? $raw_chat_format_mode : 'free_ai';
			$sanitized_v['chat_message_template']           = sanitize_textarea_field( $variation_input['chat_message_template'] ?? $fallback['chat_message_template'] ?? '' );
			$sanitized_v['chat_required_placeholders']      = sanitize_textarea_field( $variation_input['chat_required_placeholders'] ?? $fallback['chat_required_placeholders'] ?? '' );
			$sanitized_v['chat_slot_instructions']          = sanitize_textarea_field( $variation_input['chat_slot_instructions'] ?? $fallback['chat_slot_instructions'] ?? '' );
			$sanitized_v['chat_missing_placeholder_policy'] = in_array( $raw_chat_missing_policy, $valid_missing_policies, true ) ? $raw_chat_missing_policy : 'use_fallback_message';
			$sanitized_v['chat_template_max_words']         = max( 10, min( 800, absint( $variation_input['chat_template_max_words'] ?? $fallback['chat_template_max_words'] ?? 220 ) ) );
			$sanitized_v['chat_capture_enabled']            = ! empty( $variation_input['chat_capture_enabled'] );
			$sanitized_v['chat_capture_instructions']       = sanitize_textarea_field( $variation_input['chat_capture_instructions'] ?? $fallback['chat_capture_instructions'] ?? '' );
			$sanitized_v['chat_capture_purpose']            = sanitize_text_field( $variation_input['chat_capture_purpose'] ?? $fallback['chat_capture_purpose'] ?? 'General Chat Lead' );
			$sanitized_v['chat_capture_status']             = sanitize_text_field( $variation_input['chat_capture_status'] ?? $fallback['chat_capture_status'] ?? 'Captured' );
			$sanitized_v['chat_capture_tags']               = sanitize_text_field( $variation_input['chat_capture_tags'] ?? $fallback['chat_capture_tags'] ?? '' );

			$sanitized_v['knowledge_base_post_types'] = quorlyx_get_selected_knowledge_base_post_types(
				array(
					'knowledge_base_post_types' => isset( $variation_input['knowledge_base_post_types'] ) && is_array( $variation_input['knowledge_base_post_types'] )
						? $variation_input['knowledge_base_post_types']
						: array(),
				)
			);
			$sanitized_v['knowledge_base_include_behavior_patterns'] = ! empty( $variation_input['knowledge_base_include_behavior_patterns'] );
			$sanitized_v['knowledge_base_include_rendered_content'] = ! empty( $variation_input['knowledge_base_include_rendered_content'] );
			$sanitized_v['knowledge_base_file_ids'] = quorlyx_get_selected_knowledge_base_file_ids(
				array(
					'knowledge_base_file_ids' => $variation_input['knowledge_base_file_ids'] ?? array(),
				),
				true
			);
			$sanitized_v['knowledge_base_include_current_page'] = ! empty( $variation_input['knowledge_base_include_current_page'] );

			$sanitized_v['ai_generates_buttons'] = ! empty( $variation_input['ai_generates_buttons'] );
			$valid_quick_action_positions        = array( 'both', 'message', 'chat_bar' );
			$raw_quick_action_position           = sanitize_key( $variation_input['quick_actions_position'] ?? $fallback['quick_actions_position'] ?? 'both' );
			$sanitized_v['quick_actions_position'] = in_array( $raw_quick_action_position, $valid_quick_action_positions, true ) ? $raw_quick_action_position : 'both';

			$sanitized_v['floating_button_size']           = absint( $variation_input['floating_button_size'] ?? $fallback['floating_button_size'] );
			$sanitized_v['floating_logo_scale']            = absint( $variation_input['floating_logo_scale'] ?? $fallback['floating_logo_scale'] );
			$sanitized_v['floating_button_bg_color']       = sanitize_hex_color( $variation_input['floating_button_bg_color'] ?? $fallback['floating_button_bg_color'] );
			$sanitized_v['floating_button_bg_transparent'] = ! empty( $variation_input['floating_button_bg_transparent'] );
			$sanitized_v['floating_label_color']           = sanitize_hex_color( $variation_input['floating_label_color'] ?? $fallback['floating_label_color'] );
			$sanitized_v['floating_label_bg_color']        = sanitize_hex_color( $variation_input['floating_label_bg_color'] ?? $fallback['floating_label_bg_color'] );
			$sanitized_v['floating_label_bg_transparent']  = ! empty( $variation_input['floating_label_bg_transparent'] );
			$sanitized_v['floating_label_font_size']       = absint( $variation_input['floating_label_font_size'] ?? $fallback['floating_label_font_size'] );
			$sanitized_v['floating_label_width']           = absint( $variation_input['floating_label_width'] ?? $fallback['floating_label_width'] );
			$sanitized_v['floating_label_gap']             = max( 0, min( 80, absint( $variation_input['floating_label_gap'] ?? ( $fallback['floating_label_gap'] ?? 4 ) ) ) );
			$allowed_label_positions                       = array( 'left', 'right', 'above', 'below' );
			$raw_label_pos                                 = $variation_input['floating_label_position'] ?? ( $v_defaults['floating_label_position'] ?? 'left' );
			$sanitized_v['floating_label_position']        = in_array( $raw_label_pos, $allowed_label_positions, true ) ? $raw_label_pos : ( $fallback['floating_label_position'] ?? 'left' );
			$sanitized_v['floating_button_position']       = sanitize_key( $variation_input['floating_button_position'] ?? $fallback['floating_button_position'] );
			$sanitized_v['floating_button_custom_top']     = sanitize_text_field( $variation_input['floating_button_custom_top'] ?? $fallback['floating_button_custom_top'] );
			$sanitized_v['floating_button_custom_bottom']  = sanitize_text_field( $variation_input['floating_button_custom_bottom'] ?? $fallback['floating_button_custom_bottom'] );
			$sanitized_v['floating_button_custom_left']    = sanitize_text_field( $variation_input['floating_button_custom_left'] ?? $fallback['floating_button_custom_left'] );
			$sanitized_v['floating_button_custom_right']   = sanitize_text_field( $variation_input['floating_button_custom_right'] ?? $fallback['floating_button_custom_right'] );

			$sanitized_v['floating_button_size_mobile']     = absint( $variation_input['floating_button_size_mobile'] ?? $fallback['floating_button_size_mobile'] );
			$sanitized_v['floating_logo_scale_mobile']      = absint( $variation_input['floating_logo_scale_mobile'] ?? $fallback['floating_logo_scale_mobile'] );
			$sanitized_v['floating_button_mobile_bottom']   = absint( $variation_input['floating_button_mobile_bottom'] ?? $fallback['floating_button_mobile_bottom'] );
			$sanitized_v['floating_button_mobile_side']     = absint( $variation_input['floating_button_mobile_side'] ?? $fallback['floating_button_mobile_side'] );
			$sanitized_v['floating_label_show_mobile']      = ! empty( $variation_input['floating_label_show_mobile'] );
			$sanitized_v['floating_label_font_size_mobile'] = absint( $variation_input['floating_label_font_size_mobile'] ?? $fallback['floating_label_font_size_mobile'] );
			$raw_label_pos_mob                              = $variation_input['floating_label_position_mobile'] ?? ( $v_defaults['floating_label_position_mobile'] ?? 'above' );
			$sanitized_v['floating_label_position_mobile']  = in_array( $raw_label_pos_mob, $allowed_label_positions, true ) ? $raw_label_pos_mob : ( $fallback['floating_label_position_mobile'] ?? 'above' );

			$sanitized_v['chat_width']  = absint( $variation_input['chat_width'] ?? $fallback['chat_width'] );
			$sanitized_v['chat_height'] = absint( $variation_input['chat_height'] ?? $fallback['chat_height'] );
			$width_pct                  = isset( $variation_input['mobile_panel_width_percent'] ) ? floatval( $variation_input['mobile_panel_width_percent'] ) : ( $fallback['mobile_panel_width_percent'] ?? $v_defaults['mobile_panel_width_percent'] );
			if ( ! is_numeric( $variation_input['mobile_panel_width_percent'] ?? null ) ) {
				$width_pct = $fallback['mobile_panel_width_percent'] ?? $v_defaults['mobile_panel_width_percent'];
			}
			$sanitized_v['mobile_panel_width_percent'] = max( 50, min( 100, $width_pct ) );
			$full_width_pct                            = isset( $variation_input['mobile_panel_full_width_percent'] ) ? floatval( $variation_input['mobile_panel_full_width_percent'] ) : ( $fallback['mobile_panel_full_width_percent'] ?? $v_defaults['mobile_panel_full_width_percent'] );
			if ( ! is_numeric( $variation_input['mobile_panel_full_width_percent'] ?? null ) ) {
