			}
			if ( $full_width_pct < $sanitized_v['mobile_panel_width_percent'] ) {
				$full_width_pct = $sanitized_v['mobile_panel_width_percent'];
			}
			$sanitized_v['mobile_panel_full_width_percent'] = max( 50, min( 100, $full_width_pct ) );
			$sheet_height_pct                               = isset( $variation_input['mobile_panel_height_percent'] ) ? floatval( $variation_input['mobile_panel_height_percent'] ) : ( $fallback['mobile_panel_height_percent'] ?? $v_defaults['mobile_panel_height_percent'] );
			if ( ! is_numeric( $variation_input['mobile_panel_height_percent'] ?? null ) ) {
