			$full_height_pct                            = isset( $variation_input['mobile_panel_full_height_percent'] ) ? floatval( $variation_input['mobile_panel_full_height_percent'] ) : ( $fallback['mobile_panel_full_height_percent'] ?? $v_defaults['mobile_panel_full_height_percent'] );
			if ( ! is_numeric( $variation_input['mobile_panel_full_height_percent'] ?? null ) ) {
				$full_height_pct = $fallback['mobile_panel_full_height_percent'] ?? $v_defaults['mobile_panel_full_height_percent'];
			}
			$sanitized_v['mobile_panel_full_height_percent'] = max( 50, min( 100, $full_height_pct ) );
			$allowed_mobile_horizontal                       = array( 'full', 'right', 'left', 'center' );
			$raw_horizontal                                  = $variation_input['mobile_panel_horizontal_align'] ?? ( $fallback['mobile_panel_horizontal_align'] ?? $v_defaults['mobile_panel_horizontal_align'] );
			$sanitized_v['mobile_panel_horizontal_align']    = in_array( $raw_horizontal, $allowed_mobile_horizontal, true ) ? $raw_horizontal : 'full';
			$allowed_mobile_vertical                         = array( 'bottom', 'top' );
			$raw_vertical                                    = $variation_input['mobile_panel_vertical_align'] ?? ( $fallback['mobile_panel_vertical_align'] ?? $v_defaults['mobile_panel_vertical_align'] );
			$sanitized_v['mobile_panel_vertical_align']      = in_array( $raw_vertical, $allowed_mobile_vertical, true ) ? $raw_vertical : 'bottom';
			$sanitized_v['header_text_color']                = sanitize_hex_color( $variation_input['header_text_color'] ?? $fallback['header_text_color'] );
			$sanitized_v['user_message_bg_color']            = sanitize_hex_color( $variation_input['user_message_bg_color'] ?? $fallback['user_message_bg_color'] );
			$sanitized_v['user_message_text_color']          = sanitize_hex_color( $variation_input['user_message_text_color'] ?? $fallback['user_message_text_color'] );

			$sanitized_v['chat_font_family']   = sanitize_text_field( $variation_input['chat_font_family'] ?? $fallback['chat_font_family'] );
			$sanitized_v['chat_font_size']     = absint( $variation_input['chat_font_size'] ?? $fallback['chat_font_size'] );
			$sanitized_v['chat_line_height']   = floatval( $variation_input['chat_line_height'] ?? $fallback['chat_line_height'] );
			$sanitized_v['chat_bg_color']      = sanitize_hex_color( $variation_input['chat_bg_color'] ?? $fallback['chat_bg_color'] );
			$sanitized_v['chat_text_color']    = sanitize_hex_color( $variation_input['chat_text_color'] ?? $fallback['chat_text_color'] );
			$sanitized_v['chat_border_radius'] = absint( $variation_input['chat_border_radius'] ?? $fallback['chat_border_radius'] );
			$sanitized_v['chat_padding']       = absint( $variation_input['chat_padding'] ?? $fallback['chat_padding'] );

			$allowed_styles                     = array( 'filled', 'outline', 'subtle' );
			$allowed_shapes                     = array( 'pill', 'rounded', 'square' );
			$sanitized_v['quick_btn_style']     = in_array( $variation_input['quick_btn_style'] ?? ( $fallback['quick_btn_style'] ?? '' ), $allowed_styles, true ) ? ( $variation_input['quick_btn_style'] ?? $fallback['quick_btn_style'] ) : $fallback['quick_btn_style'];
			$sanitized_v['quick_btn_shape']     = in_array( $variation_input['quick_btn_shape'] ?? ( $fallback['quick_btn_shape'] ?? '' ), $allowed_shapes, true ) ? ( $variation_input['quick_btn_shape'] ?? $fallback['quick_btn_shape'] ) : $fallback['quick_btn_shape'];
			$sanitized_v['quick_btn_font_size'] = absint( $variation_input['quick_btn_font_size'] ?? $fallback['quick_btn_font_size'] );

			$sanitized_v['gen_btn_style']     = in_array( $variation_input['gen_btn_style'] ?? ( $fallback['gen_btn_style'] ?? '' ), $allowed_styles, true ) ? ( $variation_input['gen_btn_style'] ?? $fallback['gen_btn_style'] ) : $fallback['gen_btn_style'];
			$sanitized_v['gen_btn_shape']     = in_array( $variation_input['gen_btn_shape'] ?? ( $fallback['gen_btn_shape'] ?? '' ), $allowed_shapes, true ) ? ( $variation_input['gen_btn_shape'] ?? $fallback['gen_btn_shape'] ) : $fallback['gen_btn_shape'];
			$sanitized_v['gen_btn_font_size'] = absint( $variation_input['gen_btn_font_size'] ?? $fallback['gen_btn_font_size'] );

			$actions_source = null;
			if ( array_key_exists( 'actions_json', $variation_input ) ) {
				$json_value = $variation_input['actions_json'];
				if ( ! is_array( $json_value ) && ! is_object( $json_value ) ) {
					$json_value = trim( wp_unslash( (string) $json_value ) );
					if ( '' !== $json_value ) {
						$decoded_actions = json_decode( $json_value, true );
						if ( JSON_ERROR_NONE === json_last_error() && is_array( $decoded_actions ) ) {
							$actions_source = $decoded_actions;
						}
					}
				}
			}

			if ( null === $actions_source && isset( $variation_input['actions'] ) && is_array( $variation_input['actions'] ) ) {
				$actions_source = $variation_input['actions'];
			}

			if ( null === $actions_source ) {
				$actions_source = isset( $fallback['actions'] ) && is_array( $fallback['actions'] ) ? $fallback['actions'] : array();
			}

			$sanitized_v['actions'] = array();
			foreach ( $actions_source as $action ) {
				if ( ! is_array( $action ) || empty( $action['label'] ) ) {
					continue;
				}

				$action_label = sanitize_text_field( $action['label'] );
				if ( '' === $action_label ) {
					continue;
				}

				$action_type = sanitize_key( $action['type'] ?? 'url' );
				if ( ! in_array( $action_type, array( 'url', 'message' ), true ) ) {
					$action_type = 'url';
				}

				$sanitized_action         = array(
					'id'      => sanitize_text_field( $action['id'] ?? ( 'action_' . uniqid() ) ),
					'label'   => $action_label,
					'type'    => $action_type,
					'target'  => ( 'url' === $action_type ) ? esc_url_raw( $action['target'] ?? '' ) : '',
					'message' => ( 'message' === $action_type ) ? sanitize_text_field( $action['message'] ?? '' ) : '',
					'context' => ( 'message' === $action_type ) ? sanitize_textarea_field( $action['context'] ?? '' ) : '',
				);
				$sanitized_v['actions'][] = $sanitized_action;
			}

			$output[ "variation_{$v}" ] = $sanitized_v;
		}
	}

	if ( isset( $input['post_generator'] ) ) {
		$pg_input                                  = $input['post_generator'];
		$pg_defaults                               = $defaults['post_generator'];
		$output['post_generator']['enabled']       = ! empty( $pg_input['enabled'] );
		$output['post_generator']['keywords']      = sanitize_textarea_field( $pg_input['keywords'] ?? $pg_defaults['keywords'] );
		$output['post_generator']['instructions']  = sanitize_textarea_field( $pg_input['instructions'] ?? $pg_defaults['instructions'] );
		$output['post_generator']['schedule']      = sanitize_key( $pg_input['schedule'] ?? $pg_defaults['schedule'] );
		$output['post_generator']['posts_per_run'] = absint( $pg_input['posts_per_run'] ?? $pg_defaults['posts_per_run'] );
		$output['post_generator']['post_type']     = sanitize_key( $pg_input['post_type'] ?? $pg_defaults['post_type'] );
		$output['post_generator']['author_id']     = absint( $pg_input['author_id'] ?? $pg_defaults['author_id'] );
		$output['post_generator']['post_status']   = in_array( $pg_input['post_status'], array( 'draft', 'publish' ), true ) ? $pg_input['post_status'] : $pg_defaults['post_status'];

		$rec_in                                      = $pg_input['recommendations'] ?? array();
		$rec_def                                     = $pg_defaults['recommendations'];
		$labels_in                                   = $rec_in['labels'] ?? array();
		$labels_def                                  = $rec_def['labels'];
		$output['post_generator']['recommendations'] = array(
			'enabled'                       => ! empty( $rec_in['enabled'] ),
			'include_products'              => ! empty( $rec_in['include_products'] ),
			'include_posts'                 => ! empty( $rec_in['include_posts'] ),
			'include_services'              => ! empty( $rec_in['include_services'] ),
			'use_tax_relevance'             => ! empty( $rec_in['use_tax_relevance'] ),
			'max_items'                     => max( 1, min( 10, absint( $rec_in['max_items'] ?? $rec_def['max_items'] ) ) ),
			'cache_ttl'                     => max( 60, absint( $rec_in['cache_ttl'] ?? $rec_def['cache_ttl'] ) ),
			'use_custom_service_taxonomies' => ! empty( $rec_in['use_custom_service_taxonomies'] ),
			'service_taxonomies'            => isset( $rec_in['service_taxonomies'] ) ? implode( ', ', array_filter( array_map( 'sanitize_key', array_map( 'trim', explode( ',', $rec_in['service_taxonomies'] ) ) ) ) ) : $rec_def['service_taxonomies'],
			'labels'                        => array(
				'products' => sanitize_text_field( $labels_in['products'] ?? $labels_def['products'] ),
				'posts'    => sanitize_text_field( $labels_in['posts'] ?? $labels_def['posts'] ),
				'services' => sanitize_text_field( $labels_in['services'] ?? $labels_def['services'] ),
			),
		);
		quorlyx_reschedule_post_generation_event( $output['post_generator'] );
	}

	return $output;
}

/**
 * Inject runtime inline CSS for the frontend chat widget.
 *
 * @return void
 */
function quorlyx_add_frontend_inline_styles() {
	$options       = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$options       = array_replace_recursive( quorlyx_get_global_defaults(), $options );
	$variation_key = ( isset( $_COOKIE['quorlyx_ab_variation'] ) && 'b' === $_COOKIE['quorlyx_ab_variation'] && ! empty( $options['ab_testing_enabled'] ) ) ? 'b' : 'a';
	$s             = $options[ 'variation_' . $variation_key ];

	$pos_css       = '';
	$position_type = $s['floating_button_position'] ?? 'bottom-right';

	if ( 'custom' === $position_type ) {
		$top    = ( strlen( (string) $s['floating_button_custom_top'] ) ? intval( $s['floating_button_custom_top'] ) . 'px' : 'auto' );
		$bottom = ( strlen( (string) $s['floating_button_custom_bottom'] ) ? intval( $s['floating_button_custom_bottom'] ) . 'px' : 'auto' );
		$left   = ( strlen( (string) $s['floating_button_custom_left'] ) ? intval( $s['floating_button_custom_left'] ) . 'px' : 'auto' );
		$right  = ( strlen( (string) $s['floating_button_custom_right'] ) ? intval( $s['floating_button_custom_right'] ) . 'px' : 'auto' );

		$pos_css = "position: fixed !important; top: {$top} !important; bottom: {$bottom} !important; left: {$left} !important; right: {$right} !important; z-index: 999997 !important;";
	} else {
		$coords = array(
			'bottom' => '20px',
			'right'  => '20px',
		);
		if ( 'bottom-left' === $position_type ) {
			$coords = array(
				'bottom' => '20px',
				'left'   => '20px',
			);
		}
		if ( 'top-right' === $position_type ) {
			$coords = array(
				'top'   => '20px',
				'right' => '20px',
			);
		}
		if ( 'top-left' === $position_type ) {
			$coords = array(
				'top'  => '20px',
				'left' => '20px',
			);
		}

		$decls = array(
			'position: fixed !important',
			'z-index: 999997 !important',
		);
		foreach ( $coords as $prop => $value ) {
			$decls[] = "{$prop}: {$value} !important";
		}

		if ( ! isset( $coords['top'] ) ) {
			$decls[] = 'top: auto !important';
		}
		if ( ! isset( $coords['bottom'] ) ) {
			$decls[] = 'bottom: auto !important';
		}
		if ( ! isset( $coords['left'] ) ) {
			$decls[] = 'left: auto !important';
		}
		if ( ! isset( $coords['right'] ) ) {
			$decls[] = 'right: auto !important';
		}

		$pos_css = implode( '; ', $decls ) . ';';
	}

	$generate_button_css = function ( $button_class_group, $style, $shape, $primary_color, $chat_border_radius, $font_size ) {
		$bg_color     = 'transparent';
		$text_color   = $primary_color;
		$border_color = $primary_color;

		switch ( $style ) {
			case 'filled':
				$bg_color     = $primary_color;
				$text_color   = '#ffffff';
				$border_color = $primary_color;
				break;
			case 'outline':
				break;
			case 'subtle':
			default:
				$bg_color     = '#f1f5f9';
				$text_color   = '#374151';
				$border_color = '#e2e8f0';
				break;
		}

		$border_radius = '6px'; // Default for rounded.
		if ( 'pill' === $shape ) {
			$border_radius = '9999px';
		} elseif ( 'square' === $shape ) {
			$border_radius = '0px';
		} else { // Rounded.
			$border_radius = ( $chat_border_radius ?? 12 ) * 0.5 . 'px';
		}

		$font_size_css = is_numeric( $font_size ) ? "font-size: {$font_size}px !important;" : '';

		$selector = $button_class_group;

		return "
        {$selector} {
            background-color: {$bg_color} !important;
            color: {$text_color} !important;
            border: 1px solid {$border_color} !important;
            border-radius: {$border_radius} !important;
            {$font_size_css}
        }
        {$selector}:hover {
            filter: brightness(95%) !important;
        }";
	};

	$quick_btn_css = $generate_button_css(
		'.quorlyx-quick-action',
		$s['quick_btn_style'],
		$s['quick_btn_shape'],
		$s['primary_color'],
		$s['chat_border_radius'],
		$s['quick_btn_font_size']
	);

	$gen_btn_selector = '.quorlyx-ai-button, .quorlyx-chat-button, .quorlyx-search-button';
	$gen_btn_css      = $generate_button_css(
		$gen_btn_selector,
		$s['gen_btn_style'],
		$s['gen_btn_shape'],
		$s['primary_color'],
		$s['chat_border_radius'],
		$s['gen_btn_font_size']
	);

	$container_selectors = implode(
		', ',
		array(
			'.quorlyx-floating-button-container',
			'#quorlyx-root .quorlyx-floating-button-container',
			'#quorlyx-root .quorlyx-floating-button',
			'#quorlyx-root .quorlyx-launcher',
			'.quorlyx-fab-wrap',
		)
	);

	$panel_selector = '.quorlyx-chat-panel:not(.quorlyx-exit-intent-modal)';
	$panel_side_css = '';

	if ( 'custom' === $position_type ) {
		$top    = ( strlen( (string) $s['floating_button_custom_top'] ) ? intval( $s['floating_button_custom_top'] ) . 'px' : 'auto' );
		$bottom = ( strlen( (string) $s['floating_button_custom_bottom'] ) ? intval( $s['floating_button_custom_bottom'] ) . 'px' : '95px' );
		$left   = ( strlen( (string) $s['floating_button_custom_left'] ) ? intval( $s['floating_button_custom_left'] ) . 'px' : 'auto' );
		$right  = ( strlen( (string) $s['floating_button_custom_right'] ) ? intval( $s['floating_button_custom_right'] ) . 'px' : 'auto' );

		$panel_side_css = "position: fixed !important; top: {$top} !important; bottom: {$bottom} !important; left: {$left} !important; right: {$right} !important; z-index: 999999 !important;";
	} else {
		$coords = array(
			'bottom' => '95px',
		);
		if ( 'bottom-left' === $position_type || 'top-left' === $position_type ) {
			$coords['left'] = '20px';
		} else { // Right variants default.
			$coords['right'] = '20px';
		}

		$decls = array(
			'position: fixed !important',
			'z-index: 999999 !important',
		); // Panel sits above launcher.
		foreach ( $coords as $prop => $value ) {
			$decls[] = "{$prop}: {$value} !important";
		}
		if ( ! isset( $coords['top'] ) ) {
			$decls[] = 'top: auto !important';
		}
		if ( ! isset( $coords['bottom'] ) ) {
			$decls[] = 'bottom: auto !important';
		}
		if ( ! isset( $coords['left'] ) ) {
			$decls[] = 'left: auto !important';
		}
		if ( ! isset( $coords['right'] ) ) {
			$decls[] = 'right: auto !important';
		}
		$panel_side_css = implode( '; ', $decls ) . ';';
	}

	$label_text  = $s['floating_label'] ?? '';
	$label_color = $s['floating_label_color'] ?? '#1d2327';
	$label_width = intval( $s['floating_label_width'] ?? 120 );
	$label_gap   = max( 0, min( 80, intval( $s['floating_label_gap'] ?? 4 ) ) );

	$d_label_pos = $s['floating_label_position'] ?? 'left';
	if ( 'auto' === $d_label_pos ) {
		$d_label_pos = 'left';
	}
	$d_label_fs = intval( $s['floating_label_font_size'] ?? 14 );

	$m_label_show = ! empty( $s['floating_label_show_mobile'] );
	$m_label_fs   = intval( $s['floating_label_font_size_mobile'] ?? 12 );
	$m_label_pos  = $s['floating_label_position_mobile'] ?? 'above';

	if ( 'auto' === $m_label_pos ) {
		$is_top_aligned_check = ( false !== strpos( $position_type, 'top' ) );

		if ( 'custom' === $position_type && ! empty( $s['floating_button_custom_top'] ) ) {
			$is_top_aligned_check = true;
		}
		$m_label_pos = $is_top_aligned_check ? 'below' : 'above';
	}

	$label_bg_color       = $s['floating_label_bg_color'] ?? '';
	$label_bg_transparent = ! empty( $s['floating_label_bg_transparent'] );

	$generate_label_css = function ( $pos, $font_size, $color, $width, $gap, $bg_color, $is_transparent ) {
		$common = "color: {$color} !important; max-width: {$width}px !important; width: max-content !important; font-size: {$font_size}px !important; white-space: normal !important; line-height: 1.3 !important; display: inline-block !important;";

		if ( $is_transparent ) {
			$common .= 'background-color: transparent !important; padding: 0 !important; box-shadow: none !important;';
		} elseif ( ! empty( $bg_color ) ) {
			if ( 'auto' === $pos ) {
				$common .= "background-color: {$bg_color} !important; padding: 2px 6px !important; border-radius: 4px !important;";
			} else {
				$common .= "background-color: {$bg_color} !important; padding: 6px 10px !important; border-radius: 6px !important; box-shadow: 0 2px 8px rgba(0,0,0,0.15) !important;";
			}
		} elseif ( 'auto' === $pos ) {
			$common .= 'background-color: transparent !important; padding: 0 !important;';
		}

		$target = '.quorlyx-fab .quorlyx-fab-label, .quorlyx-fab-stage .quorlyx-fab-label, .quorlyx-fab-wrap .quorlyx-fab-label';

		$css = '';
		switch ( $pos ) {
			case 'left':
				$css = "$target{position:absolute !important; top:50% !important; right:100% !important; transform:translate(-{$gap}px,-50%) !important; left: auto !important; bottom: auto !important; {$common}}";
				break;
			case 'right':
				$css = "$target{position:absolute !important; top:50% !important; left:100% !important; transform:translate({$gap}px,-50%) !important; right: auto !important; bottom: auto !important; {$common}}";
				break;
			case 'above':
				$css = "$target{position:absolute !important; left:50% !important; bottom:100% !important; transform:translate(-50%,-{$gap}px) !important; top: auto !important; right: auto !important; text-align:center !important; {$common}}";
				break;
			case 'below':
				$css = "$target{position:absolute !important; left:50% !important; top:100% !important; transform:translate(-50%,{$gap}px) !important; bottom: auto !important; right: auto !important; text-align:center !important; {$common}}";
				break;
			case 'auto':
			default:
				$css = "$target{position:static !important; transform:none !important; text-align:center !important; {$common}}";
				break;
		}

		return $css;
	};

	$desktop_label_css = $generate_label_css( $d_label_pos, $d_label_fs, $label_color, $label_width, $label_gap, $label_bg_color, $label_bg_transparent );
	$mobile_label_css  = $generate_label_css( $m_label_pos, $m_label_fs, $label_color, $label_width, $label_gap, $label_bg_color, $label_bg_transparent );

	if ( ! $m_label_show ) {
		$mobile_label_css .= ' .quorlyx-fab .quorlyx-fab-label, .quorlyx-fab-wrap .quorlyx-fab-label { display: none !important; }';
	}

	$btn_bg_color       = $s['floating_button_bg_color'] ?? '';
	$btn_bg_transparent = ! empty( $s['floating_button_bg_transparent'] );

	$btn_bg_css = '';
	if ( $btn_bg_transparent ) {
		$btn_bg_css = 'background: transparent !important; box-shadow: none !important;';
	} elseif ( ! empty( $btn_bg_color ) ) {
		$btn_bg_css = "background: {$btn_bg_color} !important;";
	}

	$d_btn_size   = intval( $s['floating_button_size'] ?? 60 );
	$d_logo_scale = intval( $s['floating_logo_scale'] ?? 60 );

	$desktop_layout_css = "
    @media (min-width: 769px) {
        {$container_selectors} {
            {$pos_css}
        }
        .quorlyx-fab {
            width: {$d_btn_size}px !important;
            height: {$d_btn_size}px !important;
        }
        .quorlyx-fab {
            {$btn_bg_css}
        }
        .quorlyx-fab img {
            width: {$d_logo_scale}% !important; height: {$d_logo_scale}% !important; object-fit: contain !important; border-radius: 0 !important;
        }
        {$panel_selector} {
            {$panel_side_css}
        }
        {$desktop_label_css}
    }
    ";

	$mob_btn_size   = intval( $s['floating_button_size_mobile'] ?? 48 );
	$mob_logo_scale = intval( $s['floating_logo_scale_mobile'] ?? 60 );
	$mob_bottom     = intval( $s['floating_button_mobile_bottom'] ?? 20 );
	$mob_side       = intval( $s['floating_button_mobile_side'] ?? 20 );

	$is_left_aligned = ( false !== strpos( $position_type, 'left' ) );

	$mob_pos_css = "position: fixed !important; z-index: 999997 !important; bottom: {$mob_bottom}px !important; top: auto !important;";
	if ( $is_left_aligned ) {
		$mob_pos_css .= "left: {$mob_side}px !important; right: auto !important;";
	} else {
		$mob_pos_css .= "right: {$mob_side}px !important; left: auto !important;";
	}

	$mob_panel_w = intval( $s['mobile_panel_width_percent'] ?? 100 );
	$mob_panel_h = intval( $s['mobile_panel_height_percent'] ?? 40 );

	$mob_panel_full_w = intval( $s['mobile_panel_full_width_percent'] ?? 100 );
	$mob_panel_full_h = intval( $s['mobile_panel_full_height_percent'] ?? 100 );

	$mob_panel_h_align = $s['mobile_panel_horizontal_align'] ?? 'full';
	$mob_panel_v_align = $s['mobile_panel_vertical_align'] ?? 'bottom';

	$mob_panel_css = "width: {$mob_panel_w}% !important; height: {$mob_panel_h}% !important; max-width: 100% !important; max-height: 100% !important; border-radius: 0 !important;";

	if ( 'full' === $mob_panel_h_align ) {
		if ( $mob_panel_w >= 100 ) {
			$mob_panel_css .= 'left: 0 !important; right: 0 !important; width: 100% !important;';
		} else {

			$mob_panel_css .= 'left: 50% !important; transform: translateX(-50%) !important; right: auto !important;';
		}
	} elseif ( 'center' === $mob_panel_h_align ) {
		$mob_panel_css .= 'left: 50% !important; transform: translateX(-50%) !important; right: auto !important;';
	} elseif ( 'left' === $mob_panel_h_align ) {
		$mob_panel_css .= 'left: 0 !important; right: auto !important;';
	} elseif ( 'right' === $mob_panel_h_align ) {
		$mob_panel_css .= 'right: 0 !important; left: auto !important;';
	}

	if ( 'top' === $mob_panel_v_align ) {
		$mob_panel_css .= 'top: 0 !important; bottom: auto !important; border-bottom-left-radius: 12px !important; border-bottom-right-radius: 12px !important;';
	} else {
		$mob_panel_css .= 'bottom: 0 !important; top: auto !important; border-top-left-radius: 12px !important; border-top-right-radius: 12px !important;';
	}

	$mob_panel_expanded_css = "width: {$mob_panel_full_w}% !important; height: {$mob_panel_full_h}% !important;";
	if ( $mob_panel_full_w < 100 ) {
		$mob_panel_expanded_css .= 'left: 50% !important; transform: translateX(-50%) !important; right: auto !important;';
	} else {
		$mob_panel_expanded_css .= 'left: 0 !important; right: 0 !important;';
	}

	$mob_fab_css = "height: {$mob_btn_size}px !important;";
	$mob_img_css = '';

	if ( $m_label_show && 'auto' === $m_label_pos ) {

		$mob_fab_css .= "width: auto !important; min-width: {$mob_btn_size}px !important; height: auto !important; min-height: {$mob_btn_size}px !important; padding-left: 15px !important; padding-right: 15px !important; border-radius: 999px !important; box-sizing: border-box !important; flex-shrink: 0 !important;";

		$icon_px_h   = $mob_btn_size * ( $mob_logo_scale / 100 );
		$mob_img_css = "width: auto !important; height: {$icon_px_h}px !important; object-fit: contain !important; display: inline-block !important; vertical-align: middle !important; flex-shrink: 0 !important; border-radius: 0 !important;";
	} else {

		$mob_fab_css .= "width: {$mob_btn_size}px !important; min-width: {$mob_btn_size}px !important; min-height: {$mob_btn_size}px !important; padding: 0 !important; border-radius: 50% !important; box-sizing: border-box !important; flex-shrink: 0 !important;";

		$mob_img_css = "width: {$mob_logo_scale}% !important; height: {$mob_logo_scale}% !important; object-fit: contain !important; display: inline-block !important; vertical-align: middle !important; flex-shrink: 0 !important; border-radius: 0 !important;";
	}

	$mobile_layout_css = "
    @media (max-width: 768px) {
        {$container_selectors} {
            {$mob_pos_css}
        }
        .quorlyx-fab {
            {$mob_fab_css}
        }
        .quorlyx-fab {
            {$btn_bg_css}
        }
        .quorlyx-fab svg {
            width: 60% !important; height: 60% !important;
        }
        .quorlyx-fab img {
            {$mob_img_css}
        }
        {$panel_selector} {
            {$mob_panel_css}
        }
        {$panel_selector}.quorlyx-mobile-full {
            {$mob_panel_expanded_css}
        }
        {$mobile_label_css}
    }
    ";

	$relative_pos_css = '';
	if ( 'auto' !== $d_label_pos || 'auto' !== $m_label_pos ) {
		$relative_pos_css = '.quorlyx-fab,.quorlyx-fab-stage{position:relative !important;}.quorlyx-fab-stage{display:inline-flex !important;align-items:center !important;justify-content:center !important;overflow:visible !important;flex-shrink:0 !important;}.quorlyx-fab-wrap{overflow:visible !important;}';
	}

	$chat_radius       = intval( $s['chat_border_radius'] ?? 12 );
	$chat_padding      = intval( $s['chat_padding'] ?? 16 );
	$chat_bg           = $s['chat_bg_color'] ?? '#ffffff';
	$chat_font_size    = intval( $s['chat_font_size'] ?? 15 );
	$chat_line_height  = floatval( $s['chat_line_height'] ?? 1.6 );
	$chat_text_color   = $s['chat_text_color'] ?? '#1d2327';
	$chat_font_family  = $s['chat_font_family'] ?? 'inherit';
	$header_text_color = $s['header_text_color'] ?? '#ffffff';
	$user_msg_bg       = $s['user_message_bg_color'] ?? '#e0e7ff';
	$user_msg_text     = $s['user_message_text_color'] ?? '#1d2327';

	$chat_window_css = "
	#quorlyx-root,
	#quorlyx-root * {
		box-sizing: border-box !important;
	}

    .quorlyx-chat-panel {
        border-radius: {$chat_radius}px !important;
        background-color: {$chat_bg} !important;
        overflow: hidden !important;
        font-family: {$chat_font_family} !important;
        --quorlyx-header-text: {$header_text_color} !important;
        --quorlyx-user-bg: {$user_msg_bg} !important;
        --quorlyx-user-text: {$user_msg_text} !important;
    }
    .quorlyx-chat-body {
        padding: {$chat_padding}px !important;
        font-size: {$chat_font_size}px !important;
        line-height: {$chat_line_height} !important;
        color: {$chat_text_color} !important;
        background-color: {$chat_bg} !important;
    }

	.quorlyx-chat-form input,
	#quorlyx_chat_input {
		color: {$chat_text_color} !important;
		-webkit-text-fill-color: {$chat_text_color} !important;
		caret-color: {$chat_text_color} !important;
		background-color: #ffffff !important;
		text-transform: none !important;
		letter-spacing: normal !important;
		text-shadow: none !important;
		filter: none !important;
		opacity: 1 !important;
		font: inherit !important;
	}

	.quorlyx-chat-form input::placeholder,
	#quorlyx_chat_input::placeholder {
		color: #6b7280 !important;
		opacity: 1 !important;
	}

    .quorlyx-chat-header {
        border-top-left-radius: {$chat_radius}px !important;
        border-top-right-radius: {$chat_radius}px !important;
        color: {$header_text_color} !important;
    }

    .quorlyx-chat-body p, .quorlyx-chat-body div, .quorlyx-chat-body span {
        color: {$chat_text_color} !important;
        font-size: {$chat_font_size}px !important;
        line-height: {$chat_line_height} !important;
    }

    .quorlyx-message-user, .quorlyx-user-message {
        background-color: {$user_msg_bg} !important;
        color: {$user_msg_text} !important;
    }

	#quorlyx-root svg,
	#quorlyx-root .quorlyx-chat-panel svg,
	#quorlyx-root .quorlyx-fab svg {
		filter: none !important;
		-webkit-filter: none !important;
	}
    ";

	$css = $desktop_layout_css . $mobile_layout_css . "
    {$relative_pos_css}
    {$quick_btn_css}
    {$gen_btn_css}
    {$chat_window_css}

    .quorlyx-modal-overlay {
        position: fixed; top: 0; left: 0; width: 100%; height: 100%;
        background-color: rgba(0, 0, 0, 0.6); z-index: 999998;
        opacity: 0; visibility: hidden; transition: opacity 0.3s ease, visibility 0.3s ease;
    }
    .quorlyx-modal-overlay.quorlyx-visible { opacity: 1; visibility: visible; }
    .quorlyx-chat-panel.quorlyx-exit-intent-modal {
        top: 50%; left: 50%; bottom: auto; right: auto;
        transform: translate(-50%, -50%) scale(0.9); z-index: 999999;
        transition: transform 0.3s ease, opacity 0.3s ease;
    }
    .quorlyx-chat-panel.quorlyx-exit-intent-modal.quorlyx-open { transform: translate(-50%, -50%) scale(1); }
    ";
	wp_add_inline_style( 'quorlyx-style', $css );
}

add_action( 'wp_enqueue_scripts', 'quorlyx_enqueue_frontend_scripts', 10 );

/**
 * Print late launcher visibility CSS so page templates cannot accidentally hide the active widget.
 *
 * @param array|null $options Runtime options already loaded during frontend enqueue.
 * @return void
 */
function quorlyx_print_frontend_launcher_visibility_styles( $options = null ) {
	if ( null === $options ) {
		$options = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	}
	$options       = array_replace_recursive( quorlyx_get_global_defaults(), is_array( $options ) ? $options : array() );
	$variation_key = ( isset( $_COOKIE['quorlyx_ab_variation'] ) && 'b' === $_COOKIE['quorlyx_ab_variation'] && ! empty( $options['ab_testing_enabled'] ) ) ? 'b' : 'a';
	$settings      = $options[ 'variation_' . $variation_key ] ?? array();
	$settings      = array_replace( quorlyx_get_variation_defaults(), is_array( $settings ) ? $settings : array() );

	if ( empty( $settings['chat_enabled'] ) ) {
		return;
	}

	$has_label         = '' !== trim( (string) ( $settings['floating_label'] ?? '' ) );
	$show_mobile_label = ! empty( $settings['floating_label_show_mobile'] );

	$label_desktop_css = '';
	if ( $has_label ) {
		$label_desktop_css = '
		@media (min-width: 769px) {
			#quorlyx-root .quorlyx-fab-wrap.quorlyx-fab-wrap .quorlyx-fab-label.quorlyx-fab-label,
			#quorlyx-root .quorlyx-fab-stage.quorlyx-fab-stage .quorlyx-fab-label.quorlyx-fab-label,
			#quorlyx-root .quorlyx-fab.quorlyx-fab .quorlyx-fab-label.quorlyx-fab-label {
				display: inline-block !important;
				visibility: visible !important;
				opacity: 1 !important;
			}
		}';
	}

	$label_mobile_css = '';
	if ( $has_label && $show_mobile_label ) {
		$label_mobile_css = '
		@media (max-width: 768px) {
			#quorlyx-root .quorlyx-fab-wrap.quorlyx-fab-wrap .quorlyx-fab-label.quorlyx-fab-label,
			#quorlyx-root .quorlyx-fab-stage.quorlyx-fab-stage .quorlyx-fab-label.quorlyx-fab-label,
			#quorlyx-root .quorlyx-fab.quorlyx-fab .quorlyx-fab-label.quorlyx-fab-label {
				display: inline-block !important;
				visibility: visible !important;
				opacity: 1 !important;
			}
		}';
	}

	$css = '
	#quorlyx-root .quorlyx-fab-wrap.quorlyx-fab-wrap {
		display: flex !important;
		visibility: visible !important;
		opacity: 1 !important;
		pointer-events: auto !important;
	}
	#quorlyx-root .quorlyx-fab-stage.quorlyx-fab-stage {
		display: inline-flex !important;
		visibility: visible !important;
		opacity: 1 !important;
	}
	#quorlyx-root .quorlyx-fab.quorlyx-fab {
		display: flex !important;
		visibility: visible !important;
		opacity: 1 !important;
	}
	#quorlyx-root .quorlyx-fab-logo.quorlyx-fab-logo,
	#quorlyx-root .quorlyx-fab-icon.quorlyx-fab-icon {
		display: block !important;
		visibility: visible !important;
		opacity: 1 !important;
	}' . $label_desktop_css . $label_mobile_css;

	echo '<style id="quorlyx-frontend-launcher-visibility-css">' . $css . '</style>';
}

/**
 * Enqueue frontend scripts and localized runtime settings.
 *
 * @return void
 */
function quorlyx_enqueue_frontend_scripts() {
	$options                    = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$options                    = quorlyx_merge_global_options( $options );
	$options['trigger_roadmap'] = quorlyx_get_normalized_trigger_roadmap_settings( $options );
	$content_insights_enabled   = quorlyx_content_insights_is_enabled( $options['content_insights'] ?? array() );
		$version                    = '1.6.29';
	$has_woo                    = class_exists( 'WooCommerce' );

	if ( ! is_admin() ) {
		if ( $has_woo && $content_insights_enabled ) {
			quorlyx_maybe_track_checkout_visit_from_attribution();
		}

		$woo_ctx = array(
			'is_product_page'        => false,
			'product_id'             => null,
			'cart_count'             => 0,
			'is_order_received_page' => false,
		);
		if ( $has_woo ) {
			$woo_ctx['is_product_page'] = function_exists( 'is_product' ) ? is_product() : false;
			$woo_ctx['product_id']      = ( $woo_ctx['is_product_page'] ) ? get_the_ID() : null;
			if ( function_exists( 'WC' ) && WC() ) {
				$cart = WC()->cart;
				if ( $cart && method_exists( $cart, 'get_cart_contents_count' ) ) {
					$woo_ctx['cart_count'] = (int) $cart->get_cart_contents_count();
				}
			}
			$woo_ctx['is_order_received_page'] = function_exists( 'is_order_received_page' ) ? is_order_received_page() : false;
		}

		$host        = wp_parse_url( home_url(), PHP_URL_HOST );
		$request_uri = '/';
		if ( isset( $_SERVER['HTTP_HOST'] ) ) {
			$host = sanitize_text_field( wp_unslash( $_SERVER['HTTP_HOST'] ) );
		} else {
			$host = sanitize_text_field( $host );
		}
		if ( isset( $_SERVER['REQUEST_URI'] ) ) {
			$request_uri = sanitize_text_field( wp_unslash( $_SERVER['REQUEST_URI'] ) );
		} else {
			$request_uri = sanitize_text_field( $request_uri );
		}
		$current_url   = esc_url_raw( ( is_ssl() ? 'https://' : 'http://' ) . $host . $request_uri );
		$is_admin_user = quorlyx_current_user_can_manage();
		// phpcs:disable WordPress.Security.NonceVerification.Recommended -- Read-only preview/debug controls.
		$preview_trigger_id = isset( $_GET['quorlyx_preview_trigger'] ) ? sanitize_key( wp_unslash( $_GET['quorlyx_preview_trigger'] ) ) : '';
		$debug_trigger_ui   = isset( $_GET['quorlyx_trigger_debug'] );
		// phpcs:enable WordPress.Security.NonceVerification.Recommended
		$raw_triggers               = quorlyx_normalize_trigger_ids( is_array( $options['triggers'] ?? null ) ? $options['triggers'] : array() );
		$filtered_triggers          = array();
		$insights_gate_data_version = quorlyx_get_insights_gate_data_version();
		$page_message_context       = null;
		$get_page_message_context   = static function () use ( &$page_message_context, $current_url, $woo_ctx ) {
			if ( null === $page_message_context ) {
				$page_message_context = quorlyx_build_trigger_ai_message_context(
					array(),
					array(
						'url'        => $current_url,
						'product_id' => $woo_ctx['product_id'] ?? 0,
						'lang'       => get_locale(),
					)
				);
			}

			return $page_message_context;
		};
		foreach ( $raw_triggers as $t ) {
			if ( ! is_array( $t ) ) {
				continue;
			}

			$t = quorlyx_sanitize_trigger_settings( $t );

			if ( empty( $t['is_active'] ) ) {
				continue;
			}

			$trigger_id           = sanitize_key( (string) ( $t['id'] ?? '' ) );
			$is_force_preview_one = ( '' !== $preview_trigger_id && $trigger_id === $preview_trigger_id && $is_admin_user );

			$blocked = false;

			if ( ! $is_force_preview_one && ! $is_admin_user && ! empty( $t['qa_preview_only'] ) ) {
				$blocked = true;
			}

			if ( ! $blocked && ! $is_force_preview_one && ! empty( $t['exclude_page_urls'] ) ) {
				$exclusions = preg_split( '/[\r\n,]+/', (string) $t['exclude_page_urls'] );
				foreach ( $exclusions as $part ) {
					$part = trim( $part );
					if ( '' !== $part && false !== stripos( $current_url, $part ) ) {
						$blocked = true;
						break;
					}
				}
			}

			if ( ! $blocked && ! $is_force_preview_one && ! empty( $t['target_page_url'] ) ) {
				if ( false === stripos( $current_url, (string) $t['target_page_url'] ) ) {
					$blocked = true;
				}
			}

			if ( ! $blocked && ! $is_force_preview_one && ! empty( $t['only_if_cart_empty'] ) ) {
				$cart_count = intval( $woo_ctx['cart_count'] ?? 0 );
				if ( $cart_count > 0 ) {
					$blocked = true;
				}
			}

			if ( ! $blocked && ! $is_force_preview_one && ! empty( $t['require_cart_not_empty'] ) ) {
				$cart_count = intval( $woo_ctx['cart_count'] ?? 0 );
				if ( $cart_count <= 0 ) {
					$blocked = true;
				}
			}

			if ( ! $blocked && ! $is_force_preview_one && ! empty( $t['suppress_if_visited_url_contains'] ) ) {
				$parts = preg_split( '/[\r\n,]+/', (string) $t['suppress_if_visited_url_contains'] );
				foreach ( $parts as $p ) {
					$p = trim( $p );
					if ( '' === $p ) {
						continue;
					}

					$hash_int = 5381;
					$len      = strlen( $p );
					for ( $i = 0; $i < $len; $i++ ) {
						$hash_int = ( ( $hash_int << 5 ) + $hash_int ) + ord( $p[ $i ] );
						$hash_int = $hash_int & 0xFFFFFFFF;
					}
					$hash = str_pad( dechex( $hash_int ), 8, '0', STR_PAD_LEFT );

					$cookie_name = 'qu_v_' . $hash;
					if ( false !== stripos( $current_url, $p ) ) {

						if ( ! headers_sent() ) {
							setcookie( $cookie_name, '1', 0, '/' );
						}
						$blocked = true;
						break;
					}
					if ( ! empty( $_COOKIE[ $cookie_name ] ) ) {
						$blocked = true;
						break;
					}
				}
			}

			if ( ! $blocked && $content_insights_enabled && ! empty( $t['insights_gate_enabled'] ) ) {
				$whitelist = quorlyx_get_insights_gate_cached_urls( $t );

						// Ensure trailing slashes are consistent for comparison.
				$normalized_current = trailingslashit( explode( '?', $current_url )[0] );
				$is_whitelisted     = false;
				foreach ( $whitelist as $w_url ) {
					if ( trailingslashit( explode( '?', $w_url )[0] ) === $normalized_current ) {
						$is_whitelisted = true;
						break;
					}
				}

				if ( ! $is_whitelisted ) {
					$blocked = true;
				}
			}

			if ( ! $blocked ) {
				// We evaluated this in PHP, so disable it for JS to avoid duplicate checking/failure.
				if ( ! empty( $t['insights_gate_enabled'] ) ) {
					$t['insights_gate_enabled'] = false;
				}
				$trigger_message_keys              = array( 'proactive_message', 'ai_fallback_message' );
				$trigger_needs_placeholder_render = false;
				foreach ( $trigger_message_keys as $message_key ) {
					if ( ! empty( $t[ $message_key ] ) && ! empty( quorlyx_extract_ai_message_placeholders( (string) $t[ $message_key ] ) ) ) {
						$trigger_needs_placeholder_render = true;
						break;
					}
				}

				if ( $trigger_needs_placeholder_render ) {
					$trigger_context = array_replace(
						$get_page_message_context(),
						array(
							'trigger_name'        => sanitize_text_field( (string) ( $t['name'] ?? '' ) ),
							'trigger_type'        => ucwords( str_replace( '_', ' ', sanitize_key( (string) ( $t['type'] ?? '' ) ) ) ),
							'behavior_pattern'    => 'any' !== ( $t['segment_behavior_pattern'] ?? 'any' ) ? sanitize_text_field( (string) $t['segment_behavior_pattern'] ) : '',
							'predicted_next_step' => 'any' !== ( $t['segment_predicted_next_step'] ?? 'any' ) ? sanitize_text_field( (string) $t['segment_predicted_next_step'] ) : '',
							'traffic_source'      => 'any' !== ( $t['segment_traffic_source'] ?? 'any' ) ? sanitize_text_field( (string) $t['segment_traffic_source'] ) : '',
							'coupon_code'         => sanitize_text_field( (string) ( $t['recovery_cta_coupon_code'] ?? '' ) ),
						)
					);
					foreach ( $trigger_message_keys as $message_key ) {
						if ( empty( $t[ $message_key ] ) || empty( quorlyx_extract_ai_message_placeholders( (string) $t[ $message_key ] ) ) ) {
							continue;
						}
						$rendered_message = quorlyx_render_ai_message_template_text(
							(string) $t[ $message_key ],
							$trigger_context,
							array(),
							array(
								'missing_policy' => 'hide',
							)
						);
						$t[ $message_key ] = quorlyx_sanitize_ai_output( $rendered_message['message'], $trigger_context['button_url'] ?? $current_url );
					}
				}
				$t['insights_gate_data_version'] = $insights_gate_data_version;
				$t['quick_replies']              = quorlyx_get_public_trigger_quick_replies( $t['quick_replies'] ?? array() );
				unset( $t['chat_followup_instructions'] );
				$filtered_triggers[]             = $t;
			}
		}

		$woo_product_base_slug = '';
		if ( $has_woo ) {
			$permalinks = get_option( 'woocommerce_permalinks' );
			if ( is_array( $permalinks ) && ! empty( $permalinks['product_base'] ) ) {
				$product_base = trim( (string) $permalinks['product_base'], '/' );
				if ( $product_base ) {
					$segments = array_values( array_filter( explode( '/', $product_base ) ) );
					$last     = end( $segments );
					if ( $last && false === strpos( $last, '%' ) ) {
						$woo_product_base_slug = $last;
					}
				}
			}
		}

		$woo_cart_url     = '';
		$woo_checkout_url = '';
		if ( $has_woo ) {
			if ( function_exists( 'wc_get_cart_url' ) ) {
				$woo_cart_url = (string) wc_get_cart_url();
			}
			if ( function_exists( 'wc_get_checkout_url' ) ) {
				$woo_checkout_url = (string) wc_get_checkout_url();
			}
		}

		$published_product_count = 0;
		if ( $has_woo && post_type_exists( 'product' ) ) {
			$product_counts          = wp_count_posts( 'product' );
			$published_product_count = isset( $product_counts->publish ) ? (int) $product_counts->publish : 0;
		}

		$settings_to_pass = array(
			'ab_testing_enabled'         => $options['ab_testing_enabled'],
			'triggers'                   => $filtered_triggers, // Pass filtered triggers array.
			'trigger_roadmap'            => $options['trigger_roadmap'],
			'insights_gate_data_version' => $insights_gate_data_version,
			'site_name'                  => get_bloginfo( 'name' ),
			'site_url'                   => home_url( '/' ),
			'homepage_title'             => quorlyx_get_runtime_homepage_title(),
			'has_woo'                    => $has_woo,
			'woo_cart_url'               => $woo_cart_url,
			'woo_checkout_url'           => $woo_checkout_url,
			'woo_product_base'           => $woo_product_base_slug,
			'is_homepage'                => is_front_page(),
			'is_product_page'            => ( $has_woo && function_exists( 'is_product' ) ) ? is_product() : false,
			'is_post_page'               => is_singular( 'post' ),
			'is_static_page'             => is_page(),
			'product_count'              => $published_product_count,
			'site_lang'                  => get_locale(),
			'sticky_variation'           => true,
			'is_user_logged_in'          => is_user_logged_in(),
			'is_admin_user'              => $is_admin_user,
			'preview_trigger_id'         => $preview_trigger_id,
			'trigger_debug'              => $debug_trigger_ui,
			'performance'                => $options['performance'] ?? array(),
			'variations'                 => array(
				'a' => quorlyx_get_frontend_variation_settings( $options['variation_a'] ?? array() ),
				'b' => quorlyx_get_frontend_variation_settings( $options['variation_b'] ?? array() ),
			),
			'goals'                      => $options['conversion_goals'],
		);

		foreach ( array( 'a', 'b' ) as $variation_key_for_render ) {
			if ( empty( $settings_to_pass['variations'][ $variation_key_for_render ] ) || ! is_array( $settings_to_pass['variations'][ $variation_key_for_render ] ) ) {
				continue;
			}
			foreach ( array( 'welcome_message', 'floating_label' ) as $variation_message_key ) {
				if ( empty( $settings_to_pass['variations'][ $variation_key_for_render ][ $variation_message_key ] ) ) {
					continue;
				}
				if ( empty( quorlyx_extract_ai_message_placeholders( (string) $settings_to_pass['variations'][ $variation_key_for_render ][ $variation_message_key ] ) ) ) {
					continue;
				}
				$variation_message_context  = $get_page_message_context();
				$rendered_variation_message = quorlyx_render_ai_message_template_text(
					(string) $settings_to_pass['variations'][ $variation_key_for_render ][ $variation_message_key ],
					$variation_message_context,
					array(),
					array(
						'missing_policy' => 'hide',
					)
				);
				$settings_to_pass['variations'][ $variation_key_for_render ][ $variation_message_key ] = quorlyx_sanitize_ai_output( $rendered_variation_message['message'], $variation_message_context['button_url'] ?? $current_url );
			}
		}

		$chat_runtime_enabled = ! empty( $settings_to_pass['variations']['a']['chat_enabled'] )
			|| ( ! empty( $settings_to_pass['ab_testing_enabled'] ) && ! empty( $settings_to_pass['variations']['b']['chat_enabled'] ) );

		$goal_data_for_script = array(
			'restUrl'    => esc_url_raw( rest_url( 'quorlyx/v1/' ) ),
			'nonce'      => wp_create_nonce( 'wp_rest' ),
			'goals'      => $options['conversion_goals'],
			'has_woo'    => $has_woo,
			'woo'        => array(
				'is_product_page'        => $has_woo ? is_product() : false,
				'product_id'             => ( $has_woo && is_product() ) ? get_the_ID() : null,
				'is_order_received_page' => ( $has_woo && function_exists( 'is_order_received_page' ) ) ? is_order_received_page() : false,
			),
			'siteDomain' => wp_parse_url( home_url(), PHP_URL_HOST ),
		);

		if ( $chat_runtime_enabled ) {
			wp_enqueue_style( 'quorlyx-style', plugin_dir_url( __FILE__ ) . 'dist/style.min.css', array(), $version );
			quorlyx_add_frontend_inline_styles();
			wp_enqueue_script( 'quorlyx-frontend', plugin_dir_url( __FILE__ ) . 'dist/frontend.min.js', array(), $version, true );

			wp_localize_script(
				'quorlyx-frontend',
				'quorlyxVars',
				array(
					'restUrl'  => esc_url_raw( rest_url( 'quorlyx/v1/' ) ),
					'nonce'    => wp_create_nonce( 'wp_rest' ),
					'chatToken' => quorlyx_create_public_chat_token( 'chat' ),
					'settings' => $settings_to_pass,
					'woo'      => $woo_ctx,
				)
			);

			add_action(
				'wp_footer',
				function () {
					echo '<div id="quorlyx-root"></div>';
				}
			);
			add_action(
				'wp_footer',
				static function () use ( $options ) {
					quorlyx_print_frontend_launcher_visibility_styles( $options );
				},
				999
			);
		}
		quorlyx_add_goal_tracking_script( $goal_data_for_script );

		$analytics_post_id = 0;
		$analytics_key     = '';
		$should_track      = false;
		$behavior_source_post_id = 0;
		$behavior_source_key     = '';
		$content_insights_enabled_for_runtime = quorlyx_content_insights_is_enabled( $options['content_insights'] ?? array() );
		$behavior_tracking_settings          = quorlyx_get_behavior_pattern_settings( $options['content_insights'] ?? array() );

		$is_woo_system_page = false;
		if ( $has_woo ) {
			if ( function_exists( 'is_cart' ) && is_cart() ) {
				$is_woo_system_page = true;
			} elseif ( function_exists( 'is_checkout' ) && is_checkout() ) {
				$is_woo_system_page = true;
			} elseif ( function_exists( 'is_account_page' ) && is_account_page() ) {
				$is_woo_system_page = true;
			} elseif ( function_exists( 'is_order_received_page' ) && is_order_received_page() ) {
				$is_woo_system_page = true;
			}
		}

		if ( ! $is_woo_system_page ) {
			if ( is_front_page() || is_home() ) {
				if ( is_home() && ! is_front_page() ) {
					$analytics_post_id = (int) get_option( 'page_for_posts' );
				} else {
					$analytics_post_id = (int) get_option( 'page_on_front' );
				}

				$analytics_post_id = quorlyx_get_canonical_analytics_post_id( $analytics_post_id );

				if ( $analytics_post_id > 0 ) {
					$behavior_source_post_id = $analytics_post_id;
					$should_track            = quorlyx_content_insights_post_matches_settings( $analytics_post_id, $options['content_insights'] ?? array() );

					// Fallback: If the specific front page post is not tracked, track as virtual 'homepage'.
					if ( ! $should_track && quorlyx_content_insights_homepage_matches_settings( $options['content_insights'] ?? array() ) ) {
						$analytics_key           = 'homepage';
						$behavior_source_key     = 'homepage';
						$should_track            = true;
						$analytics_post_id       = 0;
						$behavior_source_post_id = 0;
					}
				} else {
					$behavior_source_key = 'homepage';
					if ( quorlyx_content_insights_homepage_matches_settings( $options['content_insights'] ?? array() ) ) {
						$analytics_key = 'homepage';
						$should_track  = true;
					}
				}
			} elseif ( is_singular() ) {
				$analytics_post_id       = quorlyx_get_canonical_analytics_post_id( get_queried_object_id() );
				$behavior_source_post_id = $analytics_post_id;
				$should_track            = $analytics_post_id && quorlyx_content_insights_post_matches_settings( $analytics_post_id, $options['content_insights'] ?? array() );
			}
		}

		if ( $behavior_source_post_id <= 0 && '' === $behavior_source_key ) {
			$attribution_source = quorlyx_get_attribution_source_from_request();
			$behavior_source_post_id = quorlyx_get_canonical_analytics_post_id( absint( $attribution_source['post_id'] ?? 0 ) );
			$behavior_source_key     = sanitize_key( (string) ( $attribution_source['content_key'] ?? '' ) );
		}

		if ( $should_track && ( $analytics_post_id > 0 || '' !== $analytics_key ) ) {
			wp_enqueue_script( 'quorlyx-analytics', plugin_dir_url( __FILE__ ) . 'dist/analytics.js', array( 'jquery' ), $version, true );
			wp_localize_script(
				'quorlyx-analytics',
				'quorlyxAnalytics',
				array(
					'ajax_url'                 => admin_url( 'admin-ajax.php' ),
					'nonce'                    => wp_create_nonce( 'quorlyx_analytics_nonce' ),
					'post_id'                  => $analytics_post_id,
					'content_key'              => $analytics_key,
					'conversion_tracking_mode' => quorlyx_get_content_insights_conversion_tracking_mode( $options['content_insights'] ?? array() ),
				)
			);
		}

		$allow_behavior_on_system_page = false;
		if ( $is_woo_system_page && $has_woo ) {
			if ( function_exists( 'is_cart' ) && is_cart() ) {
				$allow_behavior_on_system_page = true;
			} elseif ( function_exists( 'is_checkout' ) && is_checkout() && ( ! function_exists( 'is_order_received_page' ) || ! is_order_received_page() ) ) {
				$allow_behavior_on_system_page = true;
			}
		}

		$enqueue_behavior_tracker = $content_insights_enabled_for_runtime && ! empty( $behavior_tracking_settings['enabled'] ) && ( $behavior_source_post_id > 0 || '' !== $behavior_source_key ) && ( ! $is_woo_system_page || $allow_behavior_on_system_page );
		if ( $enqueue_behavior_tracker ) {
			$behavior_product_id      = 0;
			$behavior_content_type    = 'unknown';
			$behavior_tracker_path    = plugin_dir_path( __FILE__ ) . 'assets/behavior-tracker.js';
			$behavior_tracker_version = file_exists( $behavior_tracker_path ) ? (string) filemtime( $behavior_tracker_path ) : (string) $version;
			$behavior_dependencies    = array( 'jquery' );

			if ( wp_script_is( 'quorlyx-analytics', 'enqueued' ) ) {
				$behavior_dependencies[] = 'quorlyx-analytics';
			}

			if ( $has_woo && function_exists( 'is_product' ) && is_product() ) {
				$behavior_product_id = quorlyx_get_canonical_analytics_post_id( get_the_ID() );
			}

			if ( $behavior_product_id <= 0 && $behavior_source_post_id > 0 && 'product' === get_post_type( $behavior_source_post_id ) ) {
				$behavior_product_id = $behavior_source_post_id;
			}

			if ( 'homepage' === $behavior_source_key ) {
				$behavior_content_type = 'homepage';
			} elseif ( $behavior_product_id > 0 ) {
				$behavior_content_type = 'product';
			} elseif ( $behavior_source_post_id > 0 ) {
				$resolved_type         = get_post_type( $behavior_source_post_id );
				$behavior_content_type = is_string( $resolved_type ) && '' !== $resolved_type ? $resolved_type : 'unknown';
			} elseif ( $has_woo && function_exists( 'is_cart' ) && is_cart() ) {
				$behavior_content_type = 'cart';
			} elseif ( $has_woo && function_exists( 'is_checkout' ) && is_checkout() ) {
				$behavior_content_type = 'checkout';
			}

			wp_enqueue_script(
				'quorlyx-behavior-tracker',
				plugin_dir_url( __FILE__ ) . 'assets/behavior-tracker.js',
				$behavior_dependencies,
				$behavior_tracker_version,
				true
			);

			wp_localize_script(
				'quorlyx-behavior-tracker',
				'quorlyxBehaviorTracker',
				array(
					'ajax_url'     => admin_url( 'admin-ajax.php' ),
					'nonce'        => wp_create_nonce( 'quorlyx_analytics_nonce' ),
					'post_id'      => $behavior_source_post_id,
					'content_key'  => $behavior_source_key,
					'content_type' => $behavior_content_type,
					'product_id'   => $behavior_product_id,
					'settings'     => array(
						'enabled'                         => ! empty( $behavior_tracking_settings['enabled'] ),
						'include_buyers'                  => ! empty( $behavior_tracking_settings['include_buyers'] ),
						'include_non_converters'          => ! empty( $behavior_tracking_settings['include_non_converters'] ),
						'track_woocommerce_purchase'      => ! empty( $behavior_tracking_settings['track_woocommerce_purchase'] ),
						'custom_conversions'              => quorlyx_normalize_behavior_custom_conversions( $behavior_tracking_settings['custom_conversions'] ?? array() ),
						'include_checkout_flow'           => ! empty( $behavior_tracking_settings['include_checkout_flow'] ),
						'pattern_metrics'                 => is_array( $behavior_tracking_settings['pattern_metrics'] ?? null ) ? $behavior_tracking_settings['pattern_metrics'] : array(),
						'non_converter_sample_rate'       => 100,
						'min_sessions_for_classification' => max( 1, min( 20, absint( $behavior_tracking_settings['min_sessions_for_classification'] ?? 1 ) ) ),
						'sync_interval_minutes'           => max( 1, min( 120, absint( $behavior_tracking_settings['sync_interval_minutes'] ?? 15 ) ) ),
						'batch_delay_ms'                  => max( 500, min( 10000, absint( $behavior_tracking_settings['batch_delay_ms'] ?? 2000 ) ) ),
						'min_snapshot_gap_seconds'        => max( 2, min( 60, absint( $behavior_tracking_settings['min_snapshot_gap_seconds'] ?? 8 ) ) ),
					),
				)
			);
		}

		if ( $chat_runtime_enabled && ! empty( $filtered_triggers ) ) {
			add_action( 'wp_footer', 'quorlyx_add_trigger_controller_script', 1 );
		}
	}
}

/**
 * Print trigger controller bootstrap script in the frontend footer.
 *
 * @return void
 */
function quorlyx_add_trigger_controller_script() {
	?>
	<script type="text/javascript" id="quorlyx-trigger-controller-fix">
	( function() {
		document.dispatchEvent( new CustomEvent( 'quorlyx:prevent-default-triggers' ) );

		const ACTIVITY_KEY = 'quorlyx_session_has_activity';
		const THANKYOU_KEY = 'quorlyx_session_thankyou_reached';
		const THANKYOU_COOKIE = 'quorlyx_thankyou_reached';
		const CONVERSION_STATUS_KEY = 'quorlyx_customer_status';
		const CONVERSION_TIME_KEY = 'quorlyx_customer_converted_at';
		const CONVERSION_SESSION_KEY = 'quorlyx_converted_v1';
		const CONVERSION_COOKIE_MAX_AGE = 31536000;

		const getQuorlyxCookie = ( name ) => {
			const value = `; ${document.cookie}`;
			const parts = value.split( `; ${name}=` );
			if ( parts.length === 2 ) {
				return parts.pop().split( ';' ).shift();
			}
			return null;
		};

		const setQuorlyxCookie = ( name, value, maxAge ) => {
			try {
				let cookie = `${name}=${encodeURIComponent( value || '' )}; path=/; SameSite=Lax`;
				const seconds = Number( maxAge || 0 );
				if ( Number.isFinite( seconds ) && seconds > 0 ) {
					cookie += `; Max-Age=${Math.floor( seconds )}`;
				}
				document.cookie = cookie;
			} catch ( e ) {}
		};

		const emitQuorlyxEvent = ( name, detail ) => {
			try {
				document.dispatchEvent( new CustomEvent( name, { detail: detail || {} } ) );
				return;
			} catch ( e ) {}

			try {
				const event = document.createEvent( 'CustomEvent' );
				event.initCustomEvent( name, false, false, detail || {} );
				document.dispatchEvent( event );
			} catch ( e ) {}
		};

		window.Quorlyx = window.Quorlyx || {};
		window.Quorlyx.hasConverted = function() {
			try {
				if ( sessionStorage.getItem( THANKYOU_KEY ) === 'true' || sessionStorage.getItem( CONVERSION_SESSION_KEY ) === '1' || sessionStorage.getItem( CONVERSION_STATUS_KEY ) === 'converted' ) {
					return true;
				}
			} catch ( e ) {}
			try {
				if ( localStorage.getItem( CONVERSION_STATUS_KEY ) === 'converted' || localStorage.getItem( CONVERSION_TIME_KEY ) ) {
					return true;
				}
			} catch ( e ) {}
			return getQuorlyxCookie( THANKYOU_COOKIE ) === '1' || getQuorlyxCookie( CONVERSION_STATUS_KEY ) === 'converted';
		};
		window.Quorlyx.markConversion = function( detail ) {
			const payload = detail && typeof detail === 'object' ? detail : {};
			const convertedAt = String( Date.now() );
			try {
				sessionStorage.setItem( THANKYOU_KEY, 'true' );
				sessionStorage.setItem( CONVERSION_SESSION_KEY, '1' );
				sessionStorage.setItem( CONVERSION_STATUS_KEY, 'converted' );
			} catch ( e ) {}
			try {
				localStorage.setItem( CONVERSION_STATUS_KEY, 'converted' );
				localStorage.setItem( CONVERSION_TIME_KEY, convertedAt );
			} catch ( e ) {}
			setQuorlyxCookie( THANKYOU_COOKIE, '1', CONVERSION_COOKIE_MAX_AGE );
			setQuorlyxCookie( CONVERSION_STATUS_KEY, 'converted', CONVERSION_COOKIE_MAX_AGE );
			setQuorlyxCookie( CONVERSION_TIME_KEY, convertedAt, CONVERSION_COOKIE_MAX_AGE );
			emitQuorlyxEvent( 'quorlyx:conversion', payload );
			emitQuorlyxEvent( 'quorlyx:thankyou-reached', payload );
			return true;
		};
		window.Quorlyx.markAsPurchaser = window.Quorlyx.markConversion;
		window.Quorlyx.markPurchase = window.Quorlyx.markConversion;
		window.Quorlyx.markPaymentSuccess = window.Quorlyx.markConversion;
		window.Quorlyx.markCheckoutSuccess = window.Quorlyx.markConversion;
		window.Quorlyx.installGenericConversionBridge = function() {
			if ( window.__quorlyxGenericConversionBridgeInstalled ) {
				return true;
			}

			const bridgeEvents = [
				'quorlyx:payment-success',
				'quorlyx:purchase-success',
				'quorlyx:checkout-success',
				'quorlyx:order-completed',
				'quorlyx_payment_success',
				'payment_success',
				'purchase_success',
				'checkout_success',
			];

			const getSameOrigin = ( origin ) => {
				if ( ! origin ) {
					return '';
				}

				try {
					return new URL( origin ).origin;
				} catch ( e ) {
					return '';
				}
			};

			const isSameOriginMessage = ( origin ) => {
				return getSameOrigin( origin ) === window.location.origin;
			};

			const shouldAcceptGenericMessage = ( data ) => {
				if ( ! data || 'object' !== typeof data ) {
					return false;
				}

				const eventName = String( data.event || data.type || data.name || '' );
				return true === data.quorlyxConversion || true === data.quorlyx_conversion || bridgeEvents.indexOf( eventName ) !== -1;
			};

			const markFromBridge = ( detail ) => {
				if ( ! window.Quorlyx || typeof window.Quorlyx.markConversion !== 'function' ) {
					return false;
				}

				const payload = detail && 'object' === typeof detail ? detail : {};
				let signature = '';
				try {
					signature = JSON.stringify( {
						source: payload.source || '',
						provider: payload.provider || '',
						event: payload.event || '',
					} );
				} catch ( e ) {
					signature = '';
				}

				const now = Date.now();
				if ( signature && signature === window.__quorlyxGenericConversionLastSignature && now - Number( window.__quorlyxGenericConversionLastAt || 0 ) < 1000 ) {
					return false;
				}
				window.__quorlyxGenericConversionLastSignature = signature;
				window.__quorlyxGenericConversionLastAt = now;

				window.Quorlyx.markConversion( payload );
				return true;
			};

			window.__quorlyxGenericConversionBridgeInstalled = true;
			bridgeEvents.forEach( ( eventName ) => {
				const handler = ( event ) => {
					markFromBridge( {
						provider: 'custom',
						source: 'generic_conversion_event',
						event: eventName,
						detail: ( event && event.detail ) || {},
					} );
				};
				document.addEventListener( eventName, handler, true );
				window.addEventListener( eventName, handler, true );
			} );

			window.addEventListener( 'message', ( messageEvent ) => {
				const data = messageEvent && messageEvent.data;
				if ( ! isSameOriginMessage( messageEvent.origin ) || ! shouldAcceptGenericMessage( data ) ) {
					return;
				}

				markFromBridge( {
					provider: String( data.provider || 'custom' ),
					source: 'generic_same_origin_message',
					event: String( data.event || data.type || data.name || 'quorlyx_conversion_message' ),
					data: data,
				} );
			}, false );

			return true;
		};
		window.Quorlyx.installGenericConversionBridge();

		window.QuorlyxTriggerController = {
			init: function( triggers, fireCallback ) {
				const vars = window.quorlyxVars || {};
				const settings = vars.settings || {};
				this.runtimeSettings = settings;
				this.currentVariation = this.getCurrentVariation();
				this.triggers = this.sortTriggersByPriority( this.filterTriggersByVariation( triggers || [] ) );
				this.fireCallback = fireCallback;
				this.pageHasFired = false;
				this.sessionHasActivity = this.getActivityState();
				this.sessionThankyouReached = this.getThankyouState();
				this.lastFiredTrigger = null;
				this.conflictPairsTracked = {};
				this.listeners = []; // Store listeners to remove them later.
				this.initialScrollY = window.scrollY; // Store scroll position on load.
				this.cartMonitorHandle = null;
				this.cartItemsLast = null;
				this.activeTriggerId = '';
				this.activeTriggerAwaitingReply = false;
				this.activeTriggerPanelWasOpen = false;
				this.dismissMonitorHandle = null;
				this.isAdminUser = !! settings.is_admin_user;
				this.previewTriggerId = this.getPreviewTriggerId();
				this.previewForceActive = !! ( this.isAdminUser && this.previewTriggerId );
				this.previewConsumed = false;
				this.debugEnabled = !! ( this.isAdminUser && ( settings.trigger_debug || this.previewForceActive ) );
				this.wooAvailable = this.hasWooSupport();
				this.visitorProfile = this.refreshVisitorProfile();
				this.currentRouteSignature = this.getCurrentRouteSignature();
				this.behaviorPredictionState = this.getPersistedBehaviorPredictionState();
				this.pendingBehaviorSegmentTriggers = {};
				this.pendingSectionTriggers = {};
				this.pendingPanelTriggers = {};
				this.sessionPageDepth = this.incrementSessionPageDepth( this.currentRouteSignature );
				this.insightsGateEvalCache = {};
				this.insightsGateStateCache = {};
				this.insightsGateDataVersion = Math.max( 1, Number( settings.insights_gate_data_version || 1 ) );
				this.debugPanel = null;
				this.debugBody = null;
				this.debugRows = [];
				this.maxDebugRows = 30;
				this.initDebugPanel();
				if ( this.previewForceActive ) {
					this.logDebug( { id: this.previewTriggerId }, 'trigger_preview_forced', 'Force preview mode enabled for selected trigger' );
				}

				this.detectInitialActivity();
				this.startCartMonitor();
				this.setupActivityListeners();
				this.setupBehaviorPredictionListeners();
				this.initNavigationTracker();

				try {
					if ( this.isOnThankyouNow() ) {
						this.setThankyouState();
					}
				} catch ( e ) {}

				try {
					( this.triggers || [] ).forEach( ( t ) => this.markVisitedFromCurrentUrl( t ) );
				} catch ( e ) {}

				this.setupTriggers();
			},

			getCookie: function( name ) {
				const value = `; ${document.cookie}`;
				const parts = value.split( `; ${name}=` );
				if ( parts.length === 2 ) {
					return parts.pop().split( ';' ).shift();
				}
				return null;
			},

			setCookie: function( name, value, maxAge ) {
				try {
					let cookie = `${name}=${encodeURIComponent( value || '' )}; path=/; SameSite=Lax`;
					const seconds = Number( maxAge || 0 );
					if ( Number.isFinite( seconds ) && seconds > 0 ) {
						cookie += `; Max-Age=${Math.floor( seconds )}`;
					}
					document.cookie = cookie;
				} catch ( e ) {}
			},

			getSessionScopeId: function() {
				const key = 'quorlyx_trigger_session_scope_v3';
				try {
					let value = sessionStorage.getItem( key );
					if ( value ) {
						return String( value );
					}

					value = 'qts_' + String( Date.now() ) + '_' + String( Math.floor( Math.random() * 1000000000 ) );
					sessionStorage.setItem( key, value );
					return value;
				} catch ( e ) {
					const cookieValue = this.getCookie( key );
					if ( cookieValue ) {
						return String( cookieValue );
					}

					const fallback = 'qtc_' + String( Date.now() ) + '_' + String( Math.floor( Math.random() * 1000000000 ) );
					this.setCookie( key, fallback );
					return fallback;
				}
			},

			getSessionCookieStateKey: function( key ) {
				return String( key || '' ) + '_' + this.getSessionScopeId();
			},

			getPreviewTriggerId: function() {
				try {
					const params = new URLSearchParams( window.location.search || '' );
					const value = String( params.get( 'quorlyx_preview_trigger' ) || '' ).trim();
					if ( value ) {
						return value;
					}
				} catch ( e ) {}

				const settings = this.runtimeSettings || {};
				return String( settings.preview_trigger_id || '' ).trim();
			},

			initDebugPanel: function() {
				if ( ! this.debugEnabled ) {
					return;
				}

				try {
					if ( document.getElementById( 'quorlyx-trigger-debug-panel' ) ) {
						return;
					}

					const panel = document.createElement( 'div' );
					panel.id = 'quorlyx-trigger-debug-panel';
					panel.style.position = 'fixed';
					panel.style.right = '14px';
					panel.style.bottom = '14px';
					panel.style.zIndex = '1000000';
					panel.style.width = '360px';
					panel.style.maxWidth = '92vw';
					panel.style.maxHeight = '42vh';
					panel.style.overflow = 'hidden';
					panel.style.background = '#0f172a';
					panel.style.color = '#e2e8f0';
					panel.style.border = '1px solid #334155';
					panel.style.borderRadius = '10px';
					panel.style.boxShadow = '0 10px 30px rgba(0,0,0,.35)';

					const header = document.createElement( 'div' );
					header.style.padding = '8px 10px';
					header.style.fontSize = '12px';
					header.style.fontWeight = '700';
					header.style.borderBottom = '1px solid #334155';
					header.textContent = 'Quorlyx Trigger Debug';

					const body = document.createElement( 'div' );
					body.style.padding = '8px 10px';
					body.style.fontSize = '12px';
					body.style.lineHeight = '1.45';
					body.style.maxHeight = '34vh';
					body.style.overflow = 'auto';

					panel.appendChild( header );
					panel.appendChild( body );
					document.body.appendChild( panel );

					this.debugPanel = panel;
					this.debugBody = body;
					this.logDebug( null, 'debug', 'Trigger debug enabled' );
				} catch ( e ) {}
			},

			logDebug: function( trigger, eventName, message ) {
				if ( ! this.debugEnabled || ! this.debugBody ) {
					return;
				}

				const triggerId = trigger && trigger.id ? String( trigger.id ) : '-';
				const stamp = new Date().toLocaleTimeString();
