				cookieValue = Number( this.getCookie( key ) );

				const candidates = [ sessionValue, localValue, cookieValue ].filter( ( value ) => Number.isFinite( value ) );
				const resolved = candidates.length ? Math.max.apply( null, candidates ) : fallback;

				if ( Number.isFinite( resolved ) ) {
					try {
						sessionStorage.setItem( key, String( resolved ) );
					} catch ( e ) {}
					try {
						localStorage.setItem( key, String( resolved ) );
					} catch ( e ) {}
