			getCooldownMode: function( trigger ) {
				const mode = String( ( trigger && ( trigger.cooldown_mode || trigger.firing_frequency ) ) || 'once_per_session' );
				if ( 'unlimited' === mode ) {
					return 'disabled';
				}
				if ( [ 'disabled', 'once_per_session', 'once_per_page', 'once_per_day', 'once_per_n_days' ].indexOf( mode ) === -1 ) {
					return 'once_per_session';
				}
				return mode;
			},

			getCooldownDays: function( trigger ) {
				const days = Number( trigger && trigger.cooldown_days ? trigger.cooldown_days : 7 );
				if ( ! Number.isFinite( days ) ) {
					return 7;
				}
				return Math.max( 1, Math.min( 365, Math.floor( days ) ) );
