			isCooldownSuppressed: function( trigger ) {
				const mode = this.getCooldownMode( trigger );
				const nowSec = Math.floor( Date.now() / 1000 );

				if ( 'disabled' === mode ) {
					return false;
				}

				if ( 'once_per_page' === mode ) {
					const pageKey = this.getTriggerStateKey( trigger, 'page_seen_' + this.hash12( window.location.pathname || '' ) );
					return this.getSessionNumericStateValue( pageKey, 0 ) >= 1;
				}

				if ( 'once_per_session' === mode ) {
					const sessionKey = this.getTriggerStateKey( trigger, 'session_seen' );
					return this.getSessionNumericStateValue( sessionKey, 0 ) >= 1;
				}

				const lastFireKey = this.getTriggerStateKey( trigger, 'last_fire_ts' );
				const lastFireTs = this.getNumericStateValue( lastFireKey, 0 );
				if ( ! Number.isFinite( lastFireTs ) || lastFireTs <= 0 ) {
					return false;
				}

				const secondsSinceLastFire = nowSec - lastFireTs;
				if ( 'once_per_day' === mode ) {
