			trackTriggerEvent: function( trigger, eventName ) {
				try {
					if ( ! trigger || ! trigger.id || ! eventName ) {
						return;
					}

					const normalizedEventName = String( eventName );
					if ( [ 'trigger_fired', 'trigger_converted', 'trigger_suppressed' ].indexOf( normalizedEventName ) !== -1 ) {
						this.invalidateInsightsGateCacheForTrigger( trigger.id );
					}

					const analytics = window.quorlyxAnalytics || {};
					if ( ! analytics.ajax_url || ! analytics.nonce ) {
						return;
					}

					const payload = new URLSearchParams();
					payload.append( 'action', 'quorlyx_track_trigger_event' );
					payload.append( 'nonce', analytics.nonce );
					payload.append( 'trigger_id', String( trigger.id ) );
					payload.append( 'event_name', normalizedEventName );

					if ( analytics.post_id ) {
						payload.append( 'post_id', String( analytics.post_id ) );
					}
					if ( analytics.content_key ) {
						payload.append( 'content_key', String( analytics.content_key ) );
					}

					if ( navigator.sendBeacon ) {
						navigator.sendBeacon( analytics.ajax_url, payload );
						return;
					}

					fetch( analytics.ajax_url, {
						method: 'POST',
						headers: { 'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8' },
						body: payload.toString(),
						credentials: 'same-origin',
						keepalive: true,
					} ).then( ( response ) => response && response.ok ? response.json() : null ).then( ( data ) => {
						const nextVersion = Number( data && data.data && data.data.data_version ? data.data.data_version : 0 );
						if ( Number.isFinite( nextVersion ) && nextVersion > this.insightsGateDataVersion ) {
							this.insightsGateDataVersion = nextVersion;
							this.invalidateInsightsGateCacheForTrigger( trigger.id );
						}
