				} catch ( e ) {}
			},

			invalidateInsightsGateCacheForTrigger: function( triggerId ) {
				const normalizedTriggerId = String( triggerId || '' );
				if ( ! normalizedTriggerId ) {
					return;
				}

				const cachePrefix = 'qix_ig_' + normalizedTriggerId + '_';
				const statePrefix = 'qix_ig_state_' + normalizedTriggerId + '_';

				Object.keys( this.insightsGateEvalCache || {} ).forEach( ( key ) => {
					if ( key.indexOf( cachePrefix ) === 0 ) {
						delete this.insightsGateEvalCache[ key ];
					}
				} );

				Object.keys( this.insightsGateStateCache || {} ).forEach( ( key ) => {
					if ( key.indexOf( statePrefix ) === 0 ) {
						delete this.insightsGateStateCache[ key ];
					}
				} );

				try {
					for ( let i = sessionStorage.length - 1; i >= 0; i-- ) {
						const key = sessionStorage.key( i );
						if ( ! key ) {
							continue;
						}
						if ( key.indexOf( cachePrefix ) === 0 || key.indexOf( statePrefix ) === 0 ) {
