			setActiveTriggerContext: function( trigger ) {
				if ( ! trigger || ! trigger.id ) {
					return;
				}

				this.activeTriggerId = String( trigger.id );
				this.activeTriggerAwaitingReply = true;
				this.activeTriggerPanelWasOpen = false;
				window.quorlyxActiveTriggerId = this.activeTriggerId;
				this.setCookie( 'quorlyx_attribution_trigger_id', this.activeTriggerId );
				this.startDismissMonitor();
			},

			markActiveTriggerReplied: function() {
				if ( ! this.activeTriggerId || ! this.activeTriggerAwaitingReply ) {
					return;
				}

				this.trackTriggerEvent( { id: this.activeTriggerId }, 'trigger_replied' );
				this.activeTriggerAwaitingReply = false;
			},

			startDismissMonitor: function() {
				if ( this.dismissMonitorHandle ) {
					return;
				}

				this.dismissMonitorHandle = setInterval( () => {
					if ( ! this.activeTriggerId || ! this.activeTriggerAwaitingReply ) {
						return;
					}

					const panel = document.querySelector( '.quorlyx-chat-panel' );
					if ( ! panel ) {
						return;
					}

					const isOpen = panel.classList.contains( 'quorlyx-open' );
					if ( isOpen ) {
						this.activeTriggerPanelWasOpen = true;
						return;
					}

					if ( this.activeTriggerPanelWasOpen ) {
						const activeTrigger = this.triggers.find( ( t ) => t && String( t.id ) === String( this.activeTriggerId ) );
						if ( activeTrigger ) {
							this.incrementTriggerDismissCount( activeTrigger );
						}
						this.trackTriggerEvent( { id: this.activeTriggerId }, 'trigger_dismissed' );
						this.activeTriggerAwaitingReply = false;
					}
				}, 400 );
