			getCurrentVariation: function() {
				const vars = window.quorlyxVars || {};
				const settings = vars.settings || {};

				if ( ! settings.ab_testing_enabled ) {
					return 'all';
				}

				const variation = this.getCookie( 'quorlyx_ab_variation' );
				return ( 'b' === variation ) ? 'b' : 'a';
			},

			filterTriggersByVariation: function( triggers ) {
				if ( ! Array.isArray( triggers ) || 'all' === this.currentVariation ) {
					return Array.isArray( triggers ) ? triggers : [];
				}

				return triggers.filter( ( trigger ) => {
					const scope = ( trigger && trigger.ab_scope ) ? String( trigger.ab_scope ).toLowerCase() : 'all';
					return 'all' === scope || this.currentVariation === scope;
				} );
			},

			getTriggerPriorityScore: function( trigger ) {
				const score = Number( trigger && trigger.priority_score ? trigger.priority_score : 100 );
				if ( ! Number.isFinite( score ) ) {
					return 100;
				}

				return Math.max( 1, Math.min( 1000, Math.floor( score ) ) );
			},

			getTriggerSpecificityScore: function( trigger ) {
				if ( ! trigger ) {
					return 0;
				}

				const target = String( trigger.target_page_url || '' ).trim();
				const excludes = String( trigger.exclude_page_urls || '' ).split( /[\n,]+/ ).map( ( value ) => value.trim() ).filter( Boolean );
				let score = 0;

				if ( target ) {
					score += Math.min( 200, target.length * 4 );
				}
				score += Math.min( 120, excludes.length * 20 );
				if ( trigger.only_if_cart_empty ) {
					score += 20;
				}
				if ( trigger.require_cart_not_empty ) {
					score += 20;
				}
				if ( trigger.override_priority ) {
					score += 10;
				}

				return score;
			},

			getTriggerCreatedAt: function( trigger ) {
				const ts = Number( trigger && trigger.created_at ? trigger.created_at : 0 );
				if ( ! Number.isFinite( ts ) || ts <= 0 ) {
					return 0;
				}
				return Math.floor( ts );
			},

			compareTriggersForOrder: function( left, right ) {
				const priorityDiff = this.getTriggerPriorityScore( right ) - this.getTriggerPriorityScore( left );
				if ( 0 !== priorityDiff ) {
					return priorityDiff;
				}

				const specificityDiff = this.getTriggerSpecificityScore( right ) - this.getTriggerSpecificityScore( left );
				if ( 0 !== specificityDiff ) {
					return specificityDiff;
				}

				const createdAtDiff = this.getTriggerCreatedAt( left ) - this.getTriggerCreatedAt( right );
				if ( 0 !== createdAtDiff ) {
					return createdAtDiff;
				}

				const leftId = left && left.id ? String( left.id ) : '';
				const rightId = right && right.id ? String( right.id ) : '';
				return leftId.localeCompare( rightId );
			},

			sortTriggersByPriority: function( triggers ) {
				if ( ! Array.isArray( triggers ) ) {
					return [];
				}

				return triggers.slice().sort( ( left, right ) => this.compareTriggersForOrder( left, right ) );
