			isSuppressedByExistingWinner: function( trigger, isOverride ) {
				if ( ! this.lastFiredTrigger || ! trigger ) {
					return false;
				}

				const frequency = String( trigger.firing_frequency || 'once_per_session' );
				if ( 'unlimited' === frequency ) {
					return false;
				}
				if ( isOverride ) {
					return 'once_per_page' !== frequency && this.hasOverrideFiredForTrigger( trigger );
				}

				if ( this.pageHasFired ) {
					return true;
				}

				return 'once_per_page' !== frequency && this.hasNormalFiredForTrigger( trigger );
			},

			trackConflictOutcome: function( winner, loser ) {
				if ( ! winner || ! loser || ! winner.id || ! loser.id ) {
					return;
				}

				const winnerId = String( winner.id );
				const loserId = String( loser.id );
				if ( winnerId === loserId ) {
					return;
				}

				const pairKey = winnerId + '::' + loserId;
				if ( this.conflictPairsTracked[ pairKey ] ) {
					return;
				}

				this.conflictPairsTracked[ pairKey ] = true;
				this.trackTriggerEvent( winner, 'trigger_conflict_won' );
				this.trackTriggerEvent( loser, 'trigger_conflict_lost' );
			},

			isForcedPreviewTrigger: function( trigger ) {
				if ( ! this.previewForceActive || ! trigger || ! trigger.id ) {
					return false;
				}

				return String( trigger.id ) === String( this.previewTriggerId );
			},

			parseScheduleTimeMinutes: function( raw ) {
				const value = String( raw || '' ).trim();
				if ( ! value || value.indexOf( ':' ) === -1 ) {
					return null;
				}

				const parts = value.split( ':' );
				const hour = parseInt( parts[0], 10 );
				const minute = parseInt( parts[1], 10 );
				if ( ! Number.isFinite( hour ) || ! Number.isFinite( minute ) ) {
					return null;
				}
				if ( hour < 0 || hour > 23 || minute < 0 || minute > 59 ) {
					return null;
				}

				return ( hour * 60 ) + minute;
			},

			isScheduledNow: function( trigger ) {
				if ( ! trigger || ! trigger.schedule_enabled ) {
					return true;
				}

				const now = new Date();
				const todayString = [
					now.getFullYear(),
					String( now.getMonth() + 1 ).padStart( 2, '0' ),
					String( now.getDate() ).padStart( 2, '0' ),
				].join( '-' );

				const startDate = String( trigger.schedule_start_date || '' ).trim();
				if ( startDate && todayString < startDate ) {
					this.logDebug( trigger, 'trigger_suppressed', 'Suppressed by schedule start date' );
					return false;
				}

				const endDate = String( trigger.schedule_end_date || '' ).trim();
				if ( endDate && todayString > endDate ) {
					this.logDebug( trigger, 'trigger_suppressed', 'Suppressed by schedule end date' );
					return false;
				}

				const daysRaw = String( trigger.schedule_days || '' ).trim();
				if ( daysRaw ) {
					const allowedDays = daysRaw.split( ',' ).map( ( value ) => value.trim() ).filter( ( value ) => /^\d$/.test( value ) );
					if ( allowedDays.length && allowedDays.indexOf( String( now.getDay() ) ) === -1 ) {
						this.logDebug( trigger, 'trigger_suppressed', 'Suppressed by schedule day-of-week' );
						return false;
					}
				}

				const currentMinutes = ( now.getHours() * 60 ) + now.getMinutes();
				const startMinutes = this.parseScheduleTimeMinutes( trigger.schedule_time_start );
				const endMinutes = this.parseScheduleTimeMinutes( trigger.schedule_time_end );

				if ( null !== startMinutes && null !== endMinutes ) {
					if ( startMinutes <= endMinutes ) {
						if ( currentMinutes < startMinutes || currentMinutes > endMinutes ) {
							this.logDebug( trigger, 'trigger_suppressed', 'Suppressed by schedule time window' );
							return false;
						}
					} else {
						if ( currentMinutes > endMinutes && currentMinutes < startMinutes ) {
							this.logDebug( trigger, 'trigger_suppressed', 'Suppressed by overnight schedule time window' );
							return false;
						}
					}
				} else if ( null !== startMinutes && currentMinutes < startMinutes ) {
					this.logDebug( trigger, 'trigger_suppressed', 'Suppressed by schedule start time' );
					return false;
				} else if ( null !== endMinutes && currentMinutes > endMinutes ) {
					this.logDebug( trigger, 'trigger_suppressed', 'Suppressed by schedule end time' );
					return false;
				}

				return true;
			},

			forcePreviewTrigger: function( trigger ) {
				if ( ! this.isForcedPreviewTrigger( trigger ) || this.previewConsumed ) {
					return;
				}

				this.previewConsumed = true;
