			refreshVisitorProfile: function() {
				const today = [
					new Date().getFullYear(),
					String( new Date().getMonth() + 1 ).padStart( 2, '0' ),
					String( new Date().getDate() ).padStart( 2, '0' ),
				].join( '-' );

				const lastVisitKey = 'quorlyx_last_visit_day';
				const visitCountKey = 'quorlyx_visit_count';

				const lastVisitDay = String( this.getVisitorStorage( lastVisitKey, '' ) || '' );
				let visitCount = Number( this.getVisitorStorage( visitCountKey, '0' ) );
				if ( ! Number.isFinite( visitCount ) || visitCount < 0 ) {
					visitCount = 0;
				}

				if ( today !== lastVisitDay ) {
					visitCount += 1;
					this.setVisitorStorage( lastVisitKey, today );
					this.setVisitorStorage( visitCountKey, String( visitCount ) );
				}

				const count = Math.max( 1, Math.floor( visitCount ) );
				return {
					count,
					isFirstVisit: count <= 1,
					isReturning: count > 1,
				};
			},

			sanitizeBehaviorPatternValue: function( value ) {
				const normalized = String( value || '' ).toLowerCase().replace( /[^a-z0-9_]/g, '' );
				if ( [ 'fast_leaver', 'medium_leaver', 'slow_leaver', 'comparison_shopper', 'fast_closer', 'discoverer_closer', 'unknown' ].indexOf( normalized ) !== -1 ) {
					return normalized;
				}

				return 'unknown';
			},

			sanitizeBehaviorNextStepValue: function( value ) {
				const normalized = String( value || '' ).toLowerCase().replace( /[^a-z0-9_]/g, '' );
				if ( [ 'likely_take_action', 'likely_leave', 'continue_browsing', 'checkout_dropout_risk', 'unknown' ].indexOf( normalized ) !== -1 ) {
					return normalized;
				}

				return 'unknown';
			},

			normalizeBehaviorPredictionState: function( state ) {
				const payload = ( state && 'object' === typeof state ) ? state : {};
				const confidence = Number( payload.prediction_confidence || 0 );
				const updatedAt = Number( payload.updated_at || 0 );
				const confidenceMet = ! Object.prototype.hasOwnProperty.call( payload, 'confidence_met' ) || false !== payload.confidence_met;

				return {
					pattern_tag: this.sanitizeBehaviorPatternValue( payload.pattern_tag || '' ),
					next_step: this.sanitizeBehaviorNextStepValue( payload.next_step || '' ),
