				if ( ! eligible ) {
					const windowLabel = String( trigger.insights_gate_window || '30d' );
					this.logDebug( trigger, 'trigger_suppressed', 'Suppressed by insights gate (' + windowLabel + ', phase=' + evaluationPhase + '): views=' + String( views ) + ' ' + String( viewsOp ) + ' ' + String( minViewsThreshold ) + ' failed or conversions=' + String( conversions ) + ' ' + String( conversionsOp ) + ' ' + String( maxConversionsThreshold ) + ' failed or conversion_rate=' + String( rate.toFixed( 2 ) ) + '% ' + String( rateOp ) + ' ' + String( maxRateThreshold.toFixed( 2 ) ) + '% failed' );
				}

				return eligible;
			},
			isCartEmptyNow: function() {
				const envWoo = this.getEnvWoo();

				const cookieCount = this.getCartCount();
				return ( parseInt( envWoo.cart_count || 0, 10 ) <= 0 ) && ( cookieCount <= 0 );
			},

			isOnThankyouNow: function() {
				const envWoo = this.getEnvWoo();
				if ( envWoo.is_order_received_page ) {
					return true;
				}
				const href = window.location.href;
				const path = window.location.pathname || '';
				if ( /order-received/i.test( href ) ) {
					return true;
				}
				if ( /\/order-received(\/?|\b)/i.test( path ) ) {
					return true;
				}
				if ( /thank-?you/i.test( href ) ) {
					return true;
				}
				return false;
			},

			getTriggerNormalSessionKey: function( trigger ) {
				const triggerId = ( trigger && trigger.id ) ? String( trigger.id ) : 'unknown';
				return 'quorlyx_session_v3_trigger_fired_' + triggerId;
			},

			hasNormalFiredForTrigger: function( trigger ) {
				const key = this.getTriggerNormalSessionKey( trigger );
				const cookieKey = this.getSessionCookieStateKey( key );
				try {
					if ( sessionStorage.getItem( key ) === 'true' ) {
						return true;
					}
				} catch ( e ) {}
				return this.getCookie( cookieKey ) === 'true';
			},

			setSessionFiredState: function( trigger ) {
				const key = this.getTriggerNormalSessionKey( trigger );
				try {
					sessionStorage.setItem( key, 'true' );
				} catch ( e ) {}
				this.setCookie( this.getSessionCookieStateKey( key ), 'true' );
			},

			getTriggerOverrideSessionKey: function( trigger ) {
				const triggerId = ( trigger && trigger.id ) ? String( trigger.id ) : 'unknown';
				return 'quorlyx_session_v3_override_fired_' + triggerId;
			},

			hasOverrideFiredForTrigger: function( trigger ) {
				const key = this.getTriggerOverrideSessionKey( trigger );
				const cookieKey = this.getSessionCookieStateKey( key );
				try {
					if ( sessionStorage.getItem( key ) === 'true' ) {
						return true;
					}
				} catch ( e ) {}
				return this.getCookie( cookieKey ) === 'true';
			},

			setSessionOverrideFiredState: function( trigger ) {
				const key = this.getTriggerOverrideSessionKey( trigger );
				try {
					sessionStorage.setItem( key, 'true' );
				} catch ( e ) {}
				this.setCookie( this.getSessionCookieStateKey( key ), 'true' );
			},

			getActivityState: function() {
				try {
					return sessionStorage.getItem( ACTIVITY_KEY ) === 'true';
				} catch ( e ) {
					return false;
				}
			},

			setActivityState: function() {
				this.sessionHasActivity = true;
				try {
					sessionStorage.setItem( ACTIVITY_KEY, 'true' );
				} catch ( e ) {}
			},

			getThankyouState: function() {
				try {
					if ( window.Quorlyx && typeof window.Quorlyx.hasConverted === 'function' && window.Quorlyx.hasConverted() ) {
						return true;
					}
				} catch ( e ) {}
				try {
					if ( sessionStorage.getItem( THANKYOU_KEY ) === 'true' ) {
						return true;
					}
					if ( sessionStorage.getItem( CONVERSION_SESSION_KEY ) === '1' || sessionStorage.getItem( CONVERSION_STATUS_KEY ) === 'converted' ) {
						return true;
					}
					if ( localStorage.getItem( CONVERSION_STATUS_KEY ) === 'converted' || localStorage.getItem( CONVERSION_TIME_KEY ) ) {
						return true;
					}
				} catch ( e ) {}
				const c = this.getCookie( THANKYOU_COOKIE );
				return c === '1' || this.getCookie( CONVERSION_STATUS_KEY ) === 'converted';
			},

			setThankyouState: function() {
				this.sessionThankyouReached = true;
				try {
					sessionStorage.setItem( THANKYOU_KEY, 'true' );
					sessionStorage.setItem( CONVERSION_SESSION_KEY, '1' );
					sessionStorage.setItem( CONVERSION_STATUS_KEY, 'converted' );
					localStorage.setItem( CONVERSION_STATUS_KEY, 'converted' );
					localStorage.setItem( CONVERSION_TIME_KEY, String( Date.now() ) );
					
					const c = this.getCookie('quorlyx_attribution_trigger_id') || this.activeTriggerId;
					if ( c ) {
						const convKey = 'quorlyx_tc_' + c;
						if ( ! sessionStorage.getItem( convKey ) ) {
							this.trackTriggerEvent( { id: c }, 'trigger_converted' );
							sessionStorage.setItem( convKey, '1' );
						}
					}
				} catch ( e ) {}
				this.setCookie( THANKYOU_COOKIE, '1', CONVERSION_COOKIE_MAX_AGE );
				this.setCookie( CONVERSION_STATUS_KEY, 'converted', CONVERSION_COOKIE_MAX_AGE );
			},

			isConversionSuppressionEnabled: function( trigger ) {
				return ! trigger || false !== trigger.suppress_after_conversion;
			},

			shouldSuppressAfterConversion: function( trigger ) {
				if ( ! this.isConversionSuppressionEnabled( trigger ) ) {
					return false;
				}
				return !! ( this.sessionThankyouReached || this.isOnThankyouNow() );
			},

			getVisitedHashesFromTrigger: function( trigger ) {
				const raw = ( trigger && trigger.suppress_if_visited_url_contains ) ? String( trigger.suppress_if_visited_url_contains ) : '';
				if ( ! raw.trim() ) {
					return [];
				}
				const lines = raw.split( /\r?\n|,/ ).map( ( s ) => s.trim() ).filter( Boolean );
				return lines.map( ( s ) => this.hash12( s ) );
			},
			hash12: function( s ) {
				let h = 5381;
				for ( let i = 0; i < s.length; i++ ) {
					h = ( ( h << 5 ) + h ) + s.charCodeAt( i );
					h &= 0xffffffff;
				}
				return ( h >>> 0 ).toString( 16 ).padStart( 8, '0' );
			},
			setVisitedHash: function( hash ) {
				try {
					sessionStorage.setItem( 'qu_v_' + hash, '1' );
				} catch ( e ) {}
				this.setCookie( 'qu_v_' + hash, '1' );
			},
			hasVisitedHash: function( hash ) {
				try {
					if ( sessionStorage.getItem( 'qu_v_' + hash ) === '1' ) {
						return true;
					}
				} catch ( e ) {}
				return this.getCookie( 'qu_v_' + hash ) === '1';
			},
			markVisitedFromCurrentUrl: function( trigger ) {
				if ( ! trigger ) {
					return;
				}
				const raw = ( trigger.suppress_if_visited_url_contains || '' ).toString();
				if ( ! raw.trim() ) {
					return;
				}
				const href = window.location.href;
				raw.split( /\r?\n|,/ ).map( ( s ) => s.trim() ).filter( Boolean ).forEach( ( part ) => {
					if ( href.indexOf( part ) !== -1 ) {
						const hash = this.hash12( part );
						this.setVisitedHash( hash );
					}
				} );
			},

			hasActivity: function() {
				if ( this.sessionHasActivity ) {
					return true;
				}
				const count = this.getCartCount();
				if ( count > 0 ) {
					this.setActivityState();
					return true;
				}
				return false;
			},

			setupActivityListeners: function() {
				document.addEventListener( 'quorlyx:activity', () => this.setActivityState(), { passive: true } );
				document.addEventListener( 'quorlyx:conversion', () => {
					this.setActivityState();
					this.setThankyouState();
					this.cleanupListeners( true );
					this.cleanupListeners( false );
					const c = this.getCookie('quorlyx_attribution_trigger_id') || this.activeTriggerId;
					if ( c ) {
						const convKey = 'quorlyx_tc_' + c;
						if ( ! sessionStorage.getItem( convKey ) ) {
							this.trackTriggerEvent( { id: c }, 'trigger_converted' );
							sessionStorage.setItem( convKey, '1' );
						}
					}
				}, { passive: true } );
				document.addEventListener( 'quorlyx:thankyou-reached', () => this.setThankyouState(), { passive: true } );
				document.addEventListener( 'click', ( e ) => {
					const chatSel = '.quorlyx-quick-action, .quorlyx-quick-btn, .quorlyx-gen-btn, .quorlyx-cta, .quorlyx-chat-send, .quorlyx-send-btn, .quorlyx-open-chat, .quorlyx-convert';
					const replySel = '.quorlyx-quick-action, .quorlyx-quick-reply, .quorlyx-quick-btn, .quorlyx-gen-btn, .quorlyx-cta, .quorlyx-chat-send, .quorlyx-send-btn';
					const wooSel = 'button.single_add_to_cart_button, a.add_to_cart_button, form.cart [type="submit"], a.checkout-button, button#place_order';
					if ( e.target && e.target.closest ) {
						if ( e.target.closest( chatSel ) || e.target.closest( wooSel ) ) {
							this.setActivityState();
						}
						
						if ( e.target.closest( '.quorlyx-convert' ) || e.target.closest( wooSel ) ) {
							const c = this.getCookie('quorlyx_attribution_trigger_id') || this.activeTriggerId;
							if ( c ) {
								const convKey = 'quorlyx_tc_' + c;
								if ( ! sessionStorage.getItem( convKey ) ) {
									this.trackTriggerEvent( { id: c }, 'trigger_converted' );
									sessionStorage.setItem( convKey, '1' );
								}
							}
						}

						if ( e.target.closest( replySel ) ) {
							this.markActiveTriggerReplied();
						}
					}
				}, { capture: true } );

				document.addEventListener( 'submit', ( e ) => {
					if ( ! e.target || ! e.target.matches ) {
						return;
					}
					if ( e.target.matches( 'form.cart, form.checkout, form.woocommerce-cart-form' ) ) {
						this.setActivityState();
					}
				}, true );

				if ( window.jQuery && jQuery.fn && jQuery( document ).on ) {
					try {
						jQuery( document.body ).on( 'added_to_cart cart_page_refreshed updated_wc_div wc_cart_button_updated checkout_place_order wc_fragments_loaded wc_fragments_refreshed', () => {
							this.setActivityState();
						} );
					} catch ( e ) {}
				}
			},

			isMobileDevice: function() {
				try {
					if ( window.matchMedia && window.matchMedia( '(pointer:coarse)' ).matches ) {
						return true;
					}
				} catch ( e ) {}

				try {
					return /Mobi|Android|iPhone|iPad|iPod|Mobile/i.test( navigator.userAgent || '' );
				} catch ( e ) {
					return false;
				}
			},

			getCurrentPageTypeSegment: function() {
				const path = String( window.location.pathname || '/' ).toLowerCase();
				const runtime = this.runtimeSettings || {};
				const wooBase = String( runtime.woo_product_base || 'product' ).toLowerCase();
				const normalizePath = ( value ) => {
					try {
						const parsed = new URL( String( value || '/' ), window.location.href );
						let parsedPath = String( parsed.pathname || '/' ).toLowerCase().replace( /\/+$/, '' );
						return parsedPath || '/';
					} catch ( e ) {
						let fallbackPath = String( value || '/' ).split( '?' )[0].split( '#' )[0].toLowerCase().replace( /\/+$/, '' );
						return fallbackPath || '/';
					}
				};

				if ( runtime.is_homepage || normalizePath( window.location.href ) === normalizePath( runtime.site_url || '/' ) ) {
					return 'homepage';
				}

				if ( runtime.is_product_page ) {
					return 'product';
				}
				if ( runtime.is_post_page ) {
					return 'post';
				}
				if ( runtime.is_static_page ) {
					return 'page';
				}

				if ( wooBase && path.indexOf( '/' + wooBase + '/' ) !== -1 ) {
					return 'product';
				}
				if ( path.indexOf( '/blog' ) !== -1 || path.indexOf( '/category/' ) !== -1 || path.indexOf( '/tag/' ) !== -1 || path.indexOf( '/author/' ) !== -1 ) {
					return 'post';
				}

				return 'page';
			},

			normalizeSegmentPageTypeRule: function( rule ) {
				const normalized = String( rule || '' ).toLowerCase();

				if ( 'product' === normalized ) {
					return 'product';
				}
				if ( 'post' === normalized || 'blog' === normalized ) {
					return 'post';
				}
				if ( 'homepage' === normalized || 'home' === normalized ) {
					return 'homepage';
				}
				if ( 'page' === normalized || 'cart_checkout' === normalized || 'content' === normalized || 'other' === normalized ) {
					return 'page';
				}
				if ( 'any' === normalized ) {
					return 'any';
				}

				return 'any';
			},

			getCurrentTrafficSourceSegment: function() {
				let url;
				try {
					url = new URL( window.location.href );
				} catch ( e ) {
					return 'direct';
				}

				const source = String( url.searchParams.get( 'utm_source' ) || '' ).toLowerCase();
				const medium = String( url.searchParams.get( 'utm_medium' ) || '' ).toLowerCase();
				const hasPaidClickId = !! ( url.searchParams.get( 'gclid' ) || url.searchParams.get( 'fbclid' ) || url.searchParams.get( 'msclkid' ) );

				if ( hasPaidClickId || /(cpc|ppc|paid|display|retargeting)/.test( medium ) ) {
					return 'paid';
				}
				if ( /(email|newsletter)/.test( medium ) || /(email|mail|newsletter)/.test( source ) ) {
					return 'email';
				}
				if ( /(social|social-media)/.test( medium ) || /(facebook|instagram|twitter|x\.com|linkedin|tiktok|pinterest|youtube)/.test( source ) ) {
					return 'social';
				}

				const ref = String( document.referrer || '' );
				if ( ! ref ) {
					return 'direct';
				}

				try {
					const refHost = String( new URL( ref ).hostname || '' ).toLowerCase();
					const currentHost = String( window.location.hostname || '' ).toLowerCase();
					if ( refHost && currentHost && refHost !== currentHost ) {
						if ( /(google\.|bing\.|yahoo\.|duckduckgo\.|baidu\.|yandex\.)/.test( refHost ) ) {
							return 'search';
						}
						return 'referral';
					}
				} catch ( e ) {}

				return 'direct';
			},

			parseScopePatternList: function( raw ) {
				return String( raw || '' ).split( /\r?\n|,/ ).map( ( value ) => value.trim().toLowerCase() ).filter( Boolean );
			},

			matchesSegmentScope: function( trigger, allowUnknownBehavior ) {
				const pageTypeRule = this.normalizeSegmentPageTypeRule( trigger && trigger.segment_page_type ? trigger.segment_page_type : 'any' );
				if ( 'any' !== pageTypeRule ) {
					const currentPageType = this.getCurrentPageTypeSegment();
					if ( currentPageType !== pageTypeRule ) {
						this.logDebug( trigger, 'trigger_suppressed', 'Suppressed by segment page type: ' + currentPageType + ' != ' + pageTypeRule );
						return false;
					}
				}

				const deviceRule = String( ( trigger && trigger.segment_device ) || 'any' );
				if ( 'any' !== deviceRule ) {
					const currentDevice = this.isMobileDevice() ? 'mobile' : 'desktop';
					if ( currentDevice !== deviceRule ) {
						this.logDebug( trigger, 'trigger_suppressed', 'Suppressed by segment device: ' + currentDevice + ' != ' + deviceRule );
						return false;
					}
				}

				const trafficRule = String( ( trigger && trigger.segment_traffic_source ) || 'any' );
				if ( 'any' !== trafficRule ) {
					const currentTraffic = this.getCurrentTrafficSourceSegment();
					if ( currentTraffic !== trafficRule ) {
						this.logDebug( trigger, 'trigger_suppressed', 'Suppressed by segment traffic source: ' + currentTraffic + ' != ' + trafficRule );
						return false;
					}
				}

				const currentUrl = String( window.location.href || '' ).toLowerCase();
				const includePatterns = this.parseScopePatternList( trigger && trigger.segment_include_url_patterns ? trigger.segment_include_url_patterns : '' );
				if ( includePatterns.length ) {
					const anyIncluded = includePatterns.some( ( part ) => currentUrl.indexOf( part ) !== -1 );
					if ( ! anyIncluded ) {
						this.logDebug( trigger, 'trigger_suppressed', 'Suppressed by segment include URL scope rules' );
						return false;
					}
				}

				const excludePatterns = this.parseScopePatternList( trigger && trigger.segment_exclude_url_patterns ? trigger.segment_exclude_url_patterns : '' );
				if ( excludePatterns.length ) {
					const anyExcluded = excludePatterns.some( ( part ) => currentUrl.indexOf( part ) !== -1 );
					if ( anyExcluded ) {
						this.logDebug( trigger, 'trigger_suppressed', 'Suppressed by segment exclude URL scope rules' );
						return false;
					}
				}

				if ( ! this.matchesBehaviorSegmentRules( trigger, !! allowUnknownBehavior ) ) {
					return false;
				}

				return true;
			},

			getInactivityDelayMs: function( trigger ) {
				const sec = Number( trigger && trigger.inactivity_seconds ? trigger.inactivity_seconds : 45 );
				const safeSec = Number.isFinite( sec ) ? Math.max( 5, Math.min( 3600, Math.floor( sec ) ) ) : 45;
				return safeSec * 1000;
			},

			getInactivityExclusionSelectors: function( trigger ) {
				const raw = String( ( trigger && trigger.inactivity_exclude_selectors ) || '' );
				if ( ! raw.trim() ) {
					return [];
				}

				return raw.split( /\r?\n|,/ ).map( ( value ) => value.trim() ).filter( Boolean );
			},

			isIgnoredInactivityEventTarget: function( event, selectors ) {
				if ( ! event || ! event.target || ! selectors || ! selectors.length ) {
					return false;
				}

				const target = event.target;
				if ( ! target.closest ) {
					return false;
				}

				for ( const selector of selectors ) {
					try {
						if ( selector && target.closest( selector ) ) {
							return true;
						}
					} catch ( e ) {}
				}

				return false;
			},

			registerInactivityTrigger: function( trigger, listenerId, isOverride ) {
				const mobileEnabled = !! ( trigger && trigger.inactivity_mobile_enabled );
				if ( ! mobileEnabled && this.isMobileDevice() ) {
					this.logDebug( trigger, 'trigger_suppressed', 'Inactivity trigger disabled on mobile' );
					return;
				}

				const delayMs = this.getInactivityDelayMs( trigger );
				const selectors = this.getInactivityExclusionSelectors( trigger );
				let timeoutHandle = null;
				let lastActivityTick = 0;

				const armTimeout = () => {
					if ( timeoutHandle ) {
						clearTimeout( timeoutHandle );
					}
					timeoutHandle = setTimeout( () => this.executeTrigger( trigger ), delayMs );
				};

				const activityHandler = ( event ) => {
					const now = Date.now();
					if ( now - lastActivityTick < 350 ) {
						return;
					}
					lastActivityTick = now;

					if ( this.isIgnoredInactivityEventTarget( event, selectors ) ) {
						return;
					}

					armTimeout();
				};

				const events = [
					{ target: document, name: 'mousemove', options: { passive: true } },
					{ target: document, name: 'keydown', options: false },
					{ target: window, name: 'scroll', options: { passive: true } },
					{ target: document, name: 'touchstart', options: { passive: true } },
					{ target: document, name: 'pointerdown', options: { passive: true } },
					{ target: document, name: 'click', options: { passive: true } },
					{ target: document, name: 'focusin', options: false },
				];

				events.forEach( ( entry ) => {
					entry.target.addEventListener( entry.name, activityHandler, entry.options );
				} );

				armTimeout();
				this.logDebug( trigger, 'trigger_listener_registered', 'Inactivity listener armed (delay=' + String( Math.floor( delayMs / 1000 ) ) + 's, exclusions=' + String( selectors.length ) + ')' );
				this.listeners.push( {
					id: listenerId + '_inactivity',
					triggerId: String( ( trigger && trigger.id ) || '' ),
					type: 'inactivity',
					isOverride,
					events,
					activityHandler,
					getTimeoutHandle: () => timeoutHandle,
				} );
			},

			getClickIntentMode: function( trigger ) {
				const mode = String( ( trigger && trigger.click_intent_match_mode ) || 'url_contains' );
				if ( [ 'url_contains', 'css_selector', 'button_id' ].indexOf( mode ) === -1 ) {
					return 'url_contains';
				}
				return mode;
			},

			getClickIntentDebounceMs: function( trigger ) {
				const raw = Number( trigger && trigger.click_intent_debounce_ms ? trigger.click_intent_debounce_ms : 1200 );
				if ( ! Number.isFinite( raw ) ) {
					return 1200;
				}
				return Math.max( 100, Math.min( 10000, Math.floor( raw ) ) );
			},

			isClickIntentDebounced: function( trigger ) {
				const key = this.getTriggerStateKey( trigger, 'click_intent_last_ts' );
				const nowMs = Date.now();
				const lastMs = this.getNumericStateValue( key, 0 );
				if ( Number.isFinite( lastMs ) && lastMs > 0 && ( nowMs - lastMs ) < this.getClickIntentDebounceMs( trigger ) ) {
					return true;
				}

				this.setNumericStateValue( key, nowMs );
				return false;
			},

			isClickIntentMatch: function( trigger, event ) {
				if ( ! event || ! event.target || ! event.target.closest ) {
					return false;
				}

				const targetValue = String( ( trigger && trigger.click_intent_target ) || '' ).trim();
				if ( ! targetValue ) {
					return true;
				}

				const mode = this.getClickIntentMode( trigger );
				const node = event.target;

				if ( 'css_selector' === mode ) {
					try {
						return !! node.closest( targetValue );
					} catch ( e ) {
						return false;
					}
				}

				if ( 'button_id' === mode ) {
					const normalizedId = targetValue.replace( /^#/, '' );
					if ( ! normalizedId ) {
						return false;
					}
					try {
						return !! node.closest( '#' + CSS.escape( normalizedId ) );
					} catch ( e ) {
						return !! node.closest( '#' + normalizedId );
					}
				}

				const clickable = node.closest( 'a[href], button, [data-href], [data-url]' );
				if ( ! clickable ) {
					return false;
				}

				const href = String( clickable.getAttribute( 'href' ) || clickable.getAttribute( 'data-href' ) || clickable.getAttribute( 'data-url' ) || '' );
				return href.indexOf( targetValue ) !== -1;
			},

			registerClickIntentTrigger: function( trigger, listenerId, isOverride ) {
				const mode = this.getClickIntentMode( trigger );
				const targetValue = String( ( trigger && trigger.click_intent_target ) || '' ).trim();
				this.logDebug( trigger, 'trigger_listener_registered', 'Click-intent listener armed (mode=' + mode + ', target=' + ( targetValue || 'any-clickable' ) + ')' );

				const clickHandler = ( event ) => {
					if ( ! this.isClickIntentMatch( trigger, event ) ) {
						return;
					}

					if ( this.isClickIntentDebounced( trigger ) ) {
						this.logDebug( trigger, 'trigger_suppressed', 'Click-intent debounced duplicate click' );
						return;
					}

					this.executeTrigger( trigger );
				};

				document.addEventListener( 'click', clickHandler, true );
				this.listeners.push( { id: listenerId + '_click_intent', triggerId: String( ( trigger && trigger.id ) || '' ), type: 'event', name: 'click', func: clickHandler, target: document, options: true, isOverride } );
			},

			canFireNormal: function( trigger ) {
				const freq = trigger.firing_frequency || 'once_per_session';
				if ( this.shouldSuppressAfterConversion( trigger ) ) {
					this.logDebug( trigger, 'trigger_suppressed', 'Suppressed because thank-you state is active' );
					return false;
				}

				if ( this.pageHasFired ) {
					if ( 'unlimited' === freq ) {
						return true;
