					this.logDebug( trigger, 'trigger_suppressed', 'Suppressed because thank-you state is active' );
					return false;
				}

				if ( this.isDismissSuppressed( trigger ) || this.isCooldownSuppressed( trigger ) ) {
					this.logDebug( trigger, 'trigger_suppressed', 'Suppressed by dismiss/cooldown anti-fatigue rules' );
					return false;
				}

				const freq = trigger.firing_frequency || 'once_per_session';
				if ( 'once_per_page' !== freq && 'unlimited' !== freq && this.hasOverrideFiredForTrigger( trigger ) ) {
					this.logDebug( trigger, 'trigger_suppressed', 'Suppressed because this override trigger already fired this session' );
