								this.logDebug( trigger, 'trigger_listener_registered', 'Cart-abandonment listener armed (delay=' + String( Math.max( 1, Number( trigger.cart_abandonment_delay || 12 ) ) ) + 's)' );
								this.listeners.push( { id: listenerId + '_cart_abandonment', triggerId, type: 'timeout', handle: listener, isOverride } );
								break;

							case 'return_visitor':
								listener = setTimeout( () => this.executeTrigger( trigger ), Math.max( 1, Number( trigger.return_visitor_delay || 8 ) ) * 1000 );
								this.logDebug( trigger, 'trigger_listener_registered', 'Return-visitor listener armed (delay=' + String( Math.max( 1, Number( trigger.return_visitor_delay || 8 ) ) ) + 's)' );
								this.listeners.push( { id: listenerId + '_return_visitor', triggerId, type: 'timeout', handle: listener, isOverride } );
								break;

