								}
							}
						} );
					}
				} );
			},

			meetsStaticConditions: function( trigger ) {
				if ( this.previewForceActive && this.isForcedPreviewTrigger( trigger ) ) {
					return true;
				}

				if ( this.previewForceActive && ! this.isForcedPreviewTrigger( trigger ) ) {
					return false;
				}

				if ( trigger.qa_preview_only && ! this.isAdminUser ) {
					this.logDebug( trigger, 'trigger_suppressed', 'Suppressed because QA preview is admin-only' );
					return false;
				}

