				this.listeners = this.listeners.filter( ( l ) => {
					const isOverride = !! l.isOverride;
					if ( ( overrideOnly && isOverride ) || ( ! overrideOnly && ! isOverride ) ) {
						this.disposeListener( l );
						return false; // removed
					}
					return true; // keep
				} );
			}
		};

		window.quorlyxInitTriggers = ( triggers, fireCallback ) => {
			const hasRecoveryCtaVariant = ( trigger ) => {
				if ( ! trigger ) {
					return false;
				}

				const value = String( trigger.recovery_cta_variant || '' ).trim().toLowerCase();
				return !! value && 'none' !== value && 'n/a' !== value;
			};

			const getRecoveryCtaMeta = ( trigger ) => {
				const ctaKey = String( trigger && trigger.recovery_cta_variant ? trigger.recovery_cta_variant : 'none' );
				const ctas = {
					resume_checkout: { label: 'Resume checkout', action: 'resume_checkout' },
					view_cart: { label: 'View cart', action: 'view_cart' },
					apply_offer: { label: 'Apply offer', action: 'apply_offer' },
					custom: { label: 'Custom action', action: 'custom' },
				};

				const selected = ctas[ ctaKey ];
				if ( ! selected ) {
					return null;
				}

				const customLabel = String( trigger && trigger.recovery_cta_custom_label ? trigger.recovery_cta_custom_label : '' ).trim();
				const customUrl = String( trigger && trigger.recovery_cta_custom_url ? trigger.recovery_cta_custom_url : '' ).trim();
				const offerMode = String( trigger && trigger.recovery_cta_offer_mode ? trigger.recovery_cta_offer_mode : 'coupon' ).trim();
				const couponCode = String( trigger && trigger.recovery_cta_coupon_code ? trigger.recovery_cta_coupon_code : '' ).trim();
				const meta = {
					label: selected.label,
					action: selected.action,
					offer_mode: offerMode,
					coupon_code: couponCode,
				};

				if ( 'custom' === ctaKey || ( 'apply_offer' === ctaKey && 'custom_offer' === offerMode ) ) {
					if ( customLabel ) {
						meta.label = customLabel;
					}
					if ( customUrl ) {
						meta.custom_url = customUrl;
					}
				}

				return meta;
			};

			const getRecoveryUrls = () => {
				const vars = window.quorlyxVars || {};
				const settings = vars.settings || {};
				const fallbackBase = String( settings.site_url || ( window.location.origin + '/' ) );

				const resolveUrl = ( candidate, fallbackPath ) => {
					try {
						const raw = String( candidate || '' ).trim();
						if ( raw ) {
							return new URL( raw, fallbackBase ).toString();
						}
						return new URL( fallbackPath, fallbackBase ).toString();
					} catch ( e ) {
						return fallbackBase;
					}
				};

				return {
					cart: resolveUrl( settings.woo_cart_url, 'cart/' ),
					checkout: resolveUrl( settings.woo_checkout_url, 'checkout/' ),
				};
			};

			const applyRecoveryCtaButton = ( trigger ) => {
				const panel = document.querySelector( '.quorlyx-chat-panel' );
				if ( ! panel ) {
					return;
				}

				const actionsBar = panel.querySelector( '.quorlyx-chat-actions-bar' );
				if ( ! actionsBar ) {
					return;
				}

				actionsBar.querySelectorAll( '.quorlyx-recovery-cta' ).forEach( ( node ) => {
					node.remove();
				} );

				if ( ! hasRecoveryCtaVariant( trigger ) ) {
					return;
				}

				const ctaMeta = getRecoveryCtaMeta( trigger );
				if ( ! ctaMeta ) {
					return;
				}

				const urls = getRecoveryUrls();
				if ( 'custom' === ctaMeta.action && ! String( ctaMeta.custom_url || '' ).trim() ) {
					return;
				}

				const button = document.createElement( 'button' );
				button.type = 'button';
				button.className = 'quorlyx-quick-action quorlyx-recovery-cta';
				button.textContent = ctaMeta.label;
				button.addEventListener( 'click', () => {
					const customUrl = String( ctaMeta.custom_url || '' ).trim();
					if ( customUrl ) {
						try {
							window.location.href = new URL( customUrl, window.location.href ).toString();
						} catch ( e ) {
							window.location.href = customUrl;
						}
						return;
					}

					switch ( ctaMeta.action ) {
						case 'view_cart':
							window.location.href = urls.cart;
							break;

						case 'apply_offer': {
							if ( 'coupon' === String( ctaMeta.offer_mode || '' ) ) {
								const code = String( ctaMeta.coupon_code || '' ).trim();
								if ( code ) {
									try {
										const couponUrl = new URL( urls.checkout );
										couponUrl.searchParams.set( 'quorlyx_coupon', code );
										window.location.href = couponUrl.toString();
									} catch ( e ) {
										window.location.href = urls.checkout;
									}
									break;
								}
							}
							window.location.href = urls.checkout;
							break;
						}

						case 'custom': {
							if ( customUrl ) {
								window.location.href = customUrl;
							}
							break;
						}

						case 'resume_checkout':
						default:
							window.location.href = urls.checkout;
					}
				} );
				actionsBar.appendChild( button );
			};

			const scheduleRecoveryCtaRender = ( trigger ) => {
				let attempts = 0;
				const maxAttempts = 15;
				const handle = setInterval( () => {
					attempts += 1;
					applyRecoveryCtaButton( trigger );

					const panel = document.querySelector( '.quorlyx-chat-panel' );
					const actionsBar = panel ? panel.querySelector( '.quorlyx-chat-actions-bar' ) : null;
					const rendered = !! ( actionsBar && actionsBar.querySelector( '.quorlyx-recovery-cta' ) );
					if ( rendered || attempts >= maxAttempts ) {
						clearInterval( handle );
					}
				}, 200 );
			};

			const wrappedCallback = ( trigger ) => {
				const effectiveTrigger = trigger;
				const applyStyle = () => {
					const panel = document.querySelector( '.quorlyx-chat-panel' );
					const overlay = document.querySelector( '.quorlyx-modal-overlay' );
					if ( panel && effectiveTrigger ) {
						const style = effectiveTrigger.open_style || 'normal';
						if ( 'center' === style ) {
							panel.classList.add( 'quorlyx-exit-intent-modal' );
							if ( overlay ) {
								overlay.classList.add( 'quorlyx-visible' );
							}
						} else {
							panel.classList.remove( 'quorlyx-exit-intent-modal' );
							if ( overlay ) {
								overlay.classList.remove( 'quorlyx-visible' );
							}
						}
					}
				};

				applyStyle(); // Apply before.

				if ( typeof fireCallback === 'function' ) {
					fireCallback( effectiveTrigger );
				}

				scheduleRecoveryCtaRender( effectiveTrigger );

				applyStyle(); // Apply after to be sure.

				setTimeout( applyStyle, 10 );
				setTimeout( applyStyle, 50 );
			};
			window.QuorlyxTriggerController.init( triggers, wrappedCallback );
		};
	} )();
	</script>
	<?php
}

add_action( 'template_redirect', 'quorlyx_maybe_apply_coupon_from_query', 20 );

/**
 * Apply coupon codes from query params and redirect to a clean URL.
 *
 * @return void
 */
function quorlyx_maybe_apply_coupon_from_query() {
	if ( is_admin() || wp_doing_ajax() || wp_doing_cron() ) {
		return;
	}

	if ( ! function_exists( 'WC' ) || ! class_exists( 'WooCommerce' ) || ! function_exists( 'wc_load_cart' ) ) {
		return;
	}

	$coupon_code = '';
	// phpcs:disable WordPress.Security.NonceVerification.Recommended -- Read-only coupon prefill from URL.
	if ( isset( $_GET['quorlyx_coupon'] ) ) {
		$raw_coupon = sanitize_text_field( wp_unslash( $_GET['quorlyx_coupon'] ) );
		if ( function_exists( 'wc_format_coupon_code' ) ) {
			$coupon_code = wc_format_coupon_code( $raw_coupon );
		} else {
			$coupon_code = $raw_coupon;
		}
	}
	// phpcs:enable WordPress.Security.NonceVerification.Recommended

	if ( '' === $coupon_code ) {
		return;
	}

	if ( null === WC()->cart ) {
		wc_load_cart();
	}

	if ( WC()->cart && ! WC()->cart->has_discount( $coupon_code ) ) {
		WC()->cart->apply_coupon( $coupon_code );
		WC()->cart->calculate_totals();
	}

	$redirect_url = remove_query_arg( 'quorlyx_coupon' );
	if ( $redirect_url ) {
		wp_safe_redirect( $redirect_url );
		exit;
	}
}

/**
 * Enqueue goal-tracking JavaScript for referred sessions.
 *
 * @param array<string,mixed> $data Goal tracking payload.
 * @return void
 */
function quorlyx_add_goal_tracking_script( $data ) {
	$goals = $data['goals'] ?? array();
	if ( empty( $goals ) ) {
		return;
	}
	$goal_tracker_path    = plugin_dir_path( __FILE__ ) . 'assets/goal-tracker.js';
	$goal_tracker_version = file_exists( $goal_tracker_path ) ? (string) filemtime( $goal_tracker_path ) : '1.6.17';

	wp_enqueue_script(
		'quorlyx-goal-tracker',
		plugin_dir_url( __FILE__ ) . 'assets/goal-tracker.js',
		array(),
		$goal_tracker_version,
		true
	);
	wp_localize_script( 'quorlyx-goal-tracker', 'quorlyxGoalTrackerData', $data );
}

add_action( 'admin_enqueue_scripts', 'quorlyx_enqueue_admin_scripts' );

/**
 * Enqueue scripts and localized data for plugin admin pages.
 *
 * @param string $hook Current admin screen hook.
 * @return void
 */
function quorlyx_enqueue_admin_scripts( $hook ) {

	$version         = '1.6.15';
	$is_quorlyx_page = false !== strpos( $hook, 'quorlyx-' ) || 'toplevel_page_quorlyx-dashboard' === $hook;

	if ( 'post.php' === $hook || 'post-new.php' === $hook ) {
		wp_enqueue_script( 'quorlyx-post-editor', plugin_dir_url( __FILE__ ) . 'dist/post-editor.min.js', array( 'jquery' ), $version, true );
		wp_localize_script(
			'quorlyx-post-editor',
			'quorlyxEditor',
			array(
				'restUrl' => esc_url_raw( rest_url( 'quorlyx/v1/' ) ),
				'nonce'   => wp_create_nonce( 'wp_rest' ),
				'postId'  => get_the_ID(),
			)
		);
	}

	if ( ! $is_quorlyx_page ) {
		return;
	}

	if ( 'quorlyx_page_quorlyx-settings' === $hook && class_exists( 'WooCommerce' ) ) {
		wp_enqueue_style( 'select2', plugin_dir_url( __FILE__ ) . 'dist/vendor/select2/select2.min.css', array(), '4.1.0-rc.0' );
		wp_enqueue_script( 'select2', plugin_dir_url( __FILE__ ) . 'dist/vendor/select2/select2.min.js', array( 'jquery' ), '4.1.0-rc.0', true );
	}

	wp_enqueue_media();
	wp_enqueue_style( 'quorlyx-admin-css', plugin_dir_url( __FILE__ ) . 'dist/admin.min.css', array(), $version );
	wp_enqueue_script( 'quorlyx-admin', plugin_dir_url( __FILE__ ) . 'dist/admin.min.js', array( 'jquery' ), $version, true );

	$dashboard_url            = admin_url( 'admin.php?page=quorlyx-dashboard' );
	$dashboard_url_start_tour = add_query_arg( 'start_tour', 'true', $dashboard_url );
	wp_localize_script(
		'quorlyx-admin',
		'quorlyxAdmin',
		array(
			'nonce'                    => wp_create_nonce( 'wp_rest' ),
			'restUrl'                  => esc_url_raw( rest_url( 'quorlyx/v1/' ) ),
			'restFallbackUrl'          => esc_url_raw( add_query_arg( 'rest_route', '/quorlyx/v1/', home_url( '/' ) ) ),
			'dashboard_url'            => $dashboard_url,
			'dashboard_url_start_tour' => $dashboard_url_start_tour,
			'ajax_url'                 => admin_url( 'admin-ajax.php' ),
			'dismissNonce'             => wp_create_nonce( 'quorlyx_dismiss_notice' ),
			'seoSuggestions'           => quorlyx_get_saved_seo_suggestions( get_current_user_id() ),
			'defaultTriggerMessages'   => quorlyx_get_trigger_default_messages(),
		)
	);

	$admin_js  = "
    (function($){
        $(function() {            const contentInsightsToggle = $('#quorlyx-content-insights-enabled');
            if (contentInsightsToggle.length) {
                contentInsightsToggle.prop('checked', String(contentInsightsToggle.data('savedEnabled')) === '1');
            }
            function quorlyxPlainText(str) {
					return String(str || '').replace(/\s+/g, ' ').trim();
				}
				function quorlyxAddHelpTip(target, text, placement) {
					const clean = quorlyxPlainText(text);
					if (!clean || !target || !target.length) {
						return false;
					}

					let existingSame = false;
					let existingAny = false;
					const existingTips = placement === 'after'
						? target.nextAll('.quorlyx-help-tip').first()
						: target.children('.quorlyx-help-tip');

					existingTips.each(function() {
						const existingText = quorlyxPlainText($(this).attr('data-tip'));
						if (existingText) {
							existingAny = true;
						}
						if (existingText === clean) {
							existingSame = true;
						}
					});
					if (existingAny) {
						return existingSame;
					}

					const tip = $('<span/>', {
						class: 'quorlyx-help-tip',
						tabindex: 0,
						role: 'button',
						'aria-label': clean,
						'data-tip': clean,
						text: '?'
					});

					if (placement === 'after') {
						tip.insertAfter(target);
					} else {
						tip.appendTo(target);
					}

					return true;
				}
				function quorlyxFindPreviousHelpTarget(container, desc, selector) {
					const descNode = desc && desc[0] ? desc[0] : null;
					if (!descNode || !container || !container.length) {
						return $();
					}

					const matches = container.find(selector).filter(function() {
						return this !== descNode && !!(this.compareDocumentPosition(descNode) & Node.DOCUMENT_POSITION_FOLLOWING);
					}).toArray();

					return matches.length ? $(matches[matches.length - 1]) : $();
				}
				function quorlyxHelpTargetReady(target, placement) {
					return target && target.length && (placement === 'after' || !!quorlyxPlainText(target.text()));
				}
				function quorlyxConvertDescriptionsToHelp(scope) {
					const root = scope ? $(scope) : $('#quorlyx-settings-page');
					root.find('label[title], th[title], legend[title], strong[title], h4[title]').not('.quorlyx-title-as-help').each(function() {
						const target = $(this);
						const clean = quorlyxPlainText(target.attr('title'));
						target.removeAttr('title').addClass('quorlyx-title-as-help');
						if (clean) {
							quorlyxAddHelpTip(target, clean);
						}
					});
					root.find('p.description').not('.quorlyx-description-preserved, .quorlyx-description-as-help').each(function() {
						const desc = $(this);
						if (desc.find('input, select, textarea, button, a').length) {
							return;
						}

						const clean = quorlyxPlainText(desc.text());
						if (!clean || clean.length < 8 || /:\s*$/.test(clean)) {
							return;
						}

						let target = $();
						let placement = 'inside';
						const cell = desc.closest('td');
						const row = desc.closest('tr');
						if (cell.length) {
							target = quorlyxFindPreviousHelpTarget(cell, desc, 'label, .quorlyx-field-label, strong, legend, h1, h2, h3, h4, h5');
							if (!target.length || !quorlyxPlainText(target.text())) {
								target = quorlyxFindPreviousHelpTarget(cell, desc, 'input:not([type=hidden]), select, textarea, button');
								placement = target.length ? 'after' : 'inside';
							}
						}
						if (!quorlyxHelpTargetReady(target, placement) && desc.closest('.quorlyx-form-group').length) {
							target = desc.closest('.quorlyx-form-group').children('label, .quorlyx-field-label').first();
							placement = 'inside';
						}
						if (!quorlyxHelpTargetReady(target, placement) && desc.prevAll('label, strong, h1, h2, h3, h4, h5').length) {
							target = desc.prevAll('label, strong, h1, h2, h3, h4, h5').first();
							placement = 'inside';
						}
						if (!quorlyxHelpTargetReady(target, placement) && row.length && row.find('td p.description').not('.quorlyx-description-preserved, .quorlyx-description-as-help').length <= 1) {
							target = row.children('th').first();
							placement = 'inside';
						}
						if (!quorlyxHelpTargetReady(target, placement)) {
							return;
						}

						if (quorlyxAddHelpTip(target, clean, placement)) {
							desc.addClass('quorlyx-description-as-help').attr('aria-hidden', 'true').hide();
						}
					});
				}
				let quorlyxDescriptionHelpTimer = null;
				function quorlyxScheduleDescriptionHelp() {
					window.clearTimeout(quorlyxDescriptionHelpTimer);
					quorlyxDescriptionHelpTimer = window.setTimeout(function() {
						quorlyxConvertDescriptionsToHelp();
					}, 80);
				}
				quorlyxConvertDescriptionsToHelp();
				const quorlyxHelpRoots = document.querySelectorAll('#quorlyx-settings-page');
				if (window.MutationObserver && quorlyxHelpRoots.length) {
					quorlyxHelpRoots.forEach(function(rootNode) {
						new MutationObserver(quorlyxScheduleDescriptionHelp).observe(rootNode, { childList: true, subtree: true });
					});
				}
				$('body').on('click', '.quorlyx-help-tip', function(e) {
					e.preventDefault();
					e.stopPropagation();
				});
				function quorlyxUpdateKbFileInput(wrapper) {
					const ids = [];
					wrapper.find('.quorlyx-kb-file-list li[data-id]').each(function() {
						const id = parseInt($(this).attr('data-id'), 10);
						if (id && ids.indexOf(id) === -1) {
							ids.push(id);
						}
					});
					wrapper.find('.quorlyx-kb-file-ids').val(ids.join(','));
				}
				$('body').on('click', '.quorlyx-kb-file-upload', function(e) {
					e.preventDefault();
					if (typeof wp === 'undefined' || !wp.media) {
						return;
					}

					const wrapper = $(this).closest('.quorlyx-kb-file-uploader');
					const frame = wp.media({
						title: 'Select Knowledge Base files',
						button: { text: 'Use selected files' },
						multiple: true,
						library: {
							type: [
								'application/pdf',
								'text/plain',
								'text/markdown',
								'text/csv',
								'application/csv',
								'application/json',
								'text/html',
								'application/xml',
								'text/xml'
							]
						}
					});

					frame.on('select', function() {
						const selection = frame.state().get('selection');
						selection.each(function(attachment) {
							const file = attachment.toJSON();
							const id = parseInt(file.id, 10);
							if (!id || wrapper.find('.quorlyx-kb-file-list li[data-id=\"' + id + '\"]').length) {
								return;
							}
							const title = file.title || file.filename || ('Attachment #' + id);
							const mime = file.mime || file.subtype || '';
							const item = $('<li/>', {
								'data-id': id,
								style: 'display:flex; align-items:center; gap:8px; margin:4px 0;'
							});
							item.append('<span class=\"dashicons dashicons-media-document\"></span>');
							item.append($('<span/>', { class: 'quorlyx-kb-file-title', text: title }));
							if (mime) {
								item.append($('<code/>', { text: mime }));
							}
							item.append($('<button/>', { type: 'button', class: 'button-link-delete quorlyx-kb-file-remove', text: 'Remove' }));
							wrapper.find('.quorlyx-kb-file-list').append(item);
						});
						quorlyxUpdateKbFileInput(wrapper);
					});

					frame.open();
				});
				$('body').on('click', '.quorlyx-kb-file-remove', function(e) {
					e.preventDefault();
					const wrapper = $(this).closest('.quorlyx-kb-file-uploader');
					$(this).closest('li').remove();
					quorlyxUpdateKbFileInput(wrapper);
				});
            $('body').on('change', '.quorlyx-position-select', function() {
                const variation = $(this).data('variation');
                const customFields = $('.quorlyx-custom-position-fields[data-variation=\"' + variation + '\"]');
                if ($(this).val() === 'custom') {
                    customFields.slideDown();
                } else {
                    customFields.slideUp();
                }
            });

            $('#tour-step-clear-logs').on('click', function(e) {
                if (!confirm('Are you sure you want to clear all logs?')) return;

            });

            function initProductSearch(element) {
                const \$el = $(element);
                if (typeof $.fn.select2 !== 'function' || \$el.data('quorlyxSelect2Inited')) return;

                if (\$el.hasClass('select2-hidden-accessible')) {
                    try { \$el.select2('destroy'); } catch(e) {}
                    \$el.siblings('.select2').remove();
                }

                \$el.select2({
                    ajax: {
                        url: quorlyxAdmin.restUrl + 'search-products',
                        method: 'POST', dataType: 'json', delay: 300, cache: true,
                        beforeSend: function(xhr) { xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce); },
                        data: function (params) { return { search: params.term || '', page: params.page || 1 }; },
                        processResults: function (data, params) {
                            params.page = params.page || 1;
                            return { results: (data && data.results) ? data.results : [], pagination: { more: !!(data && data.more) } };
                        }
                    },
                    width: '100%', multiple: true, allowClear: true, minimumInputLength: 3,
                    placeholder: \$el.data('placeholder') || 'Search for and add products...',
                    language: {
                        inputTooShort: function() { return 'Type at least 3 characters'; },
                        noResults: function() { return 'No products found'; },
                        searching: function() { return 'Searching\u2026'; },
                        errorLoading: function() { return 'Unable to load results'; }
                    }
                });
                \$el.data('quorlyxSelect2Inited', true);
            }

            function initVisibleProductSearches(context) {
                $(context).find('.quorlyx-product-search:visible').not('#quorlyx-goal-template .quorlyx-product-search').each(function(){ initProductSearch(this); });
            }

            const commonGoalDescriptions = {
                wp_button_click: 'Tracks common WordPress, block editor, Elementor, Divi, and button-style CTA clicks.',
                contact_form_7_submit: 'Tracks Contact Form 7 form submits and successful mail sent events.',
                wpforms_submit: 'Tracks WPForms form submissions.',
                gravity_forms_submit: 'Tracks Gravity Forms form submissions.',
                elementor_form_submit: 'Tracks Elementor Pro form submissions.',
                fluent_forms_submit: 'Tracks Fluent Forms submissions.',
                ninja_forms_submit: 'Tracks Ninja Forms submissions.',
                formidable_forms_submit: 'Tracks Formidable Forms submissions.',
                woocommerce_add_to_cart: 'Tracks product add-to-cart button clicks.',
                woocommerce_checkout_action: 'Tracks checkout, proceed-to-checkout, and place-order button clicks.',
                phone_link_click: 'Tracks clicks on tel: links.',
                email_link_click: 'Tracks clicks on mailto: links.',
                download_link_click: 'Tracks common downloadable file links and links with a download attribute.'
            };

            function updateCommonGoalDescription(item) {
                const action = String(item.find('.quorlyx-goal-wp-action').val() || 'wp_button_click');
                item.find('.quorlyx-goal-common-description').text(commonGoalDescriptions[action] || commonGoalDescriptions.wp_button_click);
            }

            function toggleGoalFields(item) {
                const method = item.find('.quorlyx-goal-method').val();
                item.find('.quorlyx-goal-url-wrapper').toggle(method === 'url');
                item.find('.quorlyx-goal-global-wrapper').toggle(method === 'global_conversion');
                item.find('.quorlyx-goal-selector-wrapper').toggle(method === 'selector_click' || method === 'selector_submit');
                item.find('.quorlyx-goal-common-wrapper').toggle(method === 'wp_common');
                if (method === 'wp_common') {
                    updateCommonGoalDescription(item);
                }
                const wooWrap = item.find('.quorlyx-goal-woocommerce-wrapper').toggle(method === 'woo_product_visit');
                if (method === 'woo_product_visit') {
                    const scope = item.find('.quorlyx-goal-woo-scope').val();
                    const productsWrap = item.find('.quorlyx-goal-woo-products').toggle(scope === 'specific');
                    if (scope === 'specific') { initVisibleProductSearches(productsWrap); }
                }
            }

            $('#quorlyx-goals-container').on('change', '.quorlyx-goal-method, .quorlyx-goal-woo-scope, .quorlyx-goal-wp-action', function() {
                toggleGoalFields($(this).closest('.quorlyx-goal-item'));
            });

