			function collectConversionGoalsSnapshot() {
				const goals = [];
				$('#quorlyx-goals-container .quorlyx-goal-item').each(function() {
					const item = $(this);
					const name = String(item.find('.quorlyx-goal-name').val() || '').trim();
					if (!name) {
						return;
					}

					const rawMethod = String(item.find('.quorlyx-goal-method').val() || 'url');
					const allowedMethods = ['url', 'global_conversion', 'selector_click', 'selector_submit', 'wp_common', 'woo_product_visit'];
					const method = allowedMethods.indexOf(rawMethod) !== -1 ? rawMethod : 'url';
					const goal = {
						name: name,
						method: method,
						is_ab_goal: item.find('input[name*=\"[is_ab_goal]\"]').is(':checked') ? 1 : 0
					};

					if (method === 'woo_product_visit') {
						const scopeRaw = String(item.find('.quorlyx-goal-woo-scope').val() || 'any');
						goal.woo_product_scope = (scopeRaw === 'specific') ? 'specific' : 'any';
						goal.woo_products = [];
						if (goal.woo_product_scope === 'specific') {
							item.find('.quorlyx-product-search option:selected').each(function() {
								const value = String($(this).val() || '').trim();
								if (value) {
									goal.woo_products.push(value);
								}
							});
						}
					} else if (method === 'global_conversion') {
						// No additional fields needed.
					} else if (method === 'selector_click' || method === 'selector_submit') {
						goal.selector = String(item.find('.quorlyx-goal-selector').val() || '').trim();
					} else if (method === 'wp_common') {
						goal.wp_action = String(item.find('.quorlyx-goal-wp-action').val() || 'wp_button_click').trim();
					} else {
						goal.url = String(item.find('.quorlyx-goal-url').val() || '').trim();
					}

					goals.push(goal);
				});
				return goals;
			}

			function syncConversionGoalsSnapshot() {
				const snapshotField = $('#quorlyx-conversion-goals-json');
				if (!snapshotField.length) {
					return;
				}
				try {
					snapshotField.val(JSON.stringify(collectConversionGoalsSnapshot()));
				} catch (err) {
					snapshotField.val('');
				}
			}

			function collectQuickActionsSnapshot(itemsEl) {
				const actions = [];
				itemsEl.find('.quorlyx-repeater-item').each(function() {
					const item = $(this);
					const label = String(item.find('.quorlyx-action-label').val() || '').trim();
					if (!label) {
						return;
					}

					let type = String(item.find('.quorlyx-action-type').val() || 'url').trim().toLowerCase();
					type = (type === 'message') ? 'message' : 'url';

					const action = {
						id: String(item.find('.quorlyx-action-id').val() || ''),
						label: label,
						type: type,
						target: '',
						message: '',
						context: ''
					};

					if (type === 'message') {
						action.message = String(item.find('.quorlyx-action-message').val() || '').trim();
						action.context = String(item.find('.quorlyx-action-context').val() || '').trim();
					} else {
						action.target = String(item.find('.quorlyx-action-target').val() || '').trim();
					}

					actions.push(action);
				});

				return actions;
			}

			function syncQuickActionsSnapshot(scope) {
				const root = scope ? $(scope) : $(document);
				root.find('.quorlyx-repeater-items').each(function() {
					const itemsEl = $(this);
					const variation = String(itemsEl.data('variation') || '').trim().toLowerCase();
					if (!variation) {
						return;
					}

					const fieldName = 'quorlyx_options[variation_' + variation + '][actions_json]';
					const container = itemsEl.closest('.quorlyx-repeater-container');
					let field = container.find('.quorlyx-actions-json-field[name=\"' + fieldName + '\"]').first();

					if (!field.length) {
						field = $('<input>', {
							type: 'hidden',
							'class': 'quorlyx-actions-json-field',
							name: fieldName
						});
						container.append(field);
					}

					try {
						field.val(JSON.stringify(collectQuickActionsSnapshot(itemsEl)));
					} catch (err) {
						field.val('[]');
					}
				});
			}

