            const defaultMessages = (typeof quorlyxAdmin !== 'undefined' && quorlyxAdmin.defaultTriggerMessages) ? quorlyxAdmin.defaultTriggerMessages : {};

            function toggleTriggerFields(item) {
                const type = item.find('.quorlyx-trigger-type-select').val();
                item.find('.quorlyx-trigger-option').hide();
                item.find('.quorlyx-trigger-option[data-type=\"' + type + '\"]').show();
