            function updateTriggerSummary(item) {
                const name = item.find('[name*=\"[name]\"]').val() || 'Unnamed Trigger';
                const type = item.find('[name*=\"[type]\"]').val();
                const typeText = item.find('[name*=\"[type]\"] option:selected').text();
				const priority = parseInt(item.find('[name*=\'[priority_score]\']').val() || '100', 10);
				const abTestingEnabled = $('#ab_testing_enabled_toggle').is(':checked');
				const abScopeField = item.find('[name*=\"[ab_scope]\"]');
                let details = '';

                if (type === 'time_on_page') {
                    details = item.find('[name*=\"[time_delay]\"]').val() + 's delay';
                } else if (type === 'scroll_depth') {
                    details = item.find('[name*=\"[scroll_depth]\"]').val() + '% scroll';
				} else if (type === 'inactivity') {
					details = item.find('[name*=\"[inactivity_seconds]\"]').val() + 's idle';
				} else if (type === 'click_intent') {
					details = 'click intent: ' + (item.find('[name*=\"[click_intent_target]\"]').val() || 'any target');
				} else if (type === 'cart_abandonment') {
					details = 'cart recovery after ' + (item.find('[name*=\"[cart_abandonment_delay]\"]').val() || '12') + 's';
				} else if (type === 'return_visitor') {
					details = (item.find('[name*=\"[return_visitor_segment]\"] option:selected').text() || 'visitor segment') + ' | ' + (item.find('[name*=\"[return_visitor_delay]\"]').val() || '8') + 's delay';
				} else if (type === 'section_view') {
					details = 'when section appears';
				} else if (type === 'page_depth') {
					details = 'after ' + (item.find('[name*=\"[page_depth_min_pages]\"]').val() || '3') + ' pages viewed';
				} else if (type === 'utm_referrer') {
					details = 'utm/referrer rules';
				} else if (type === 'behavior_pattern') {
					details = 'instant fire when conditions match';
				} else {
					details = 'on exit intent';
                }

				const pageTypeField = item.find('[name*=\"[segment_page_type]\"]');
				const pageType = pageTypeField.length ? pageTypeField.val() : 'any';
				const pageTypeLabel = pageTypeField.length ? pageTypeField.find('option:selected').text() : '';
                const url = item.find('[name*=\"[target_page_url]\"]').val();
				if (url) {
					details += ' on pages with \"' + url + '\"';
				} else if (pageType && pageType !== 'any') {
					details += ' on ' + String(pageTypeLabel || pageType).toLowerCase();
				} else {
					details += ' on all pages';
				}
				const sectionSelector = item.find('[name*=\"[target_section_selector]\"]').val();
				if (sectionSelector) {
					details += ' | section \"' + sectionSelector + '\"';
				}
				if (abTestingEnabled && abScopeField.length && abScopeField.val() && abScopeField.val() !== 'all') {
					details += ' | ' + abScopeField.find('option:selected').text();
				}
				if (item.find('.quorlyx-schedule-enabled').is(':checked')) {
					details += ' | scheduled';
				}
				details += ' | priority ' + (isNaN(priority) ? 100 : priority);

                item.find('.quorlyx-trigger-summary-name').text(name);
                item.find('.quorlyx-trigger-summary-details').text(typeText + ': ' + details);
            }

			function syncScheduleDaysHidden(item) {
