					syncScheduleDaysHidden(item);
				}
			}

			let quorlyxCouponCodesCache = null;
			let quorlyxCouponCodesRequest = null;

			function normalizeCouponCodes(couponCodes) {
				if (!Array.isArray(couponCodes)) {
					return [];
				}

				const seen = {};
				const normalized = [];
				couponCodes.forEach((code) => {
					const value = String(code || '').trim();
					if (!value) {
						return;
					}

					const key = value.toLowerCase();
					if (seen[key]) {
						return;
					}

					seen[key] = true;
					normalized.push(value);
				});

				normalized.sort((left, right) => left.localeCompare(right));
				return normalized;
			}

			function populateCouponSelect(selectElement, couponCodes) {
				const selectEl = $(selectElement);
				if (!selectEl.length) {
					return;
				}

				const currentValue = String(selectEl.val() || selectEl.attr('data-current-coupon') || '').trim();
				const normalized = normalizeCouponCodes(couponCodes);

				selectEl.empty();
				selectEl.append($('<option>').val('').text(normalized.length ? 'Select coupon' : 'No coupons found'));

				normalized.forEach((code) => {
					selectEl.append($('<option>').val(code).text(code));
				});

				if (currentValue) {
					const hasCurrent = normalized.some((code) => code.toLowerCase() === currentValue.toLowerCase());
					if (!hasCurrent) {
						selectEl.append($('<option>').val(currentValue).text(currentValue));
					}
					selectEl.val(currentValue);
				} else {
					selectEl.val('');
				}

				selectEl.prop('disabled', normalized.length === 0 && !currentValue);
				selectEl.attr('data-coupon-loaded', '1');
			}

			function fetchCouponCodes(forceRefresh) {
				const shouldRefresh = !!forceRefresh;
				if (!shouldRefresh && Array.isArray(quorlyxCouponCodesCache)) {
					const deferred = $.Deferred();
					deferred.resolve(quorlyxCouponCodesCache);
					return deferred.promise();
				}

				if (quorlyxCouponCodesRequest) {
					return quorlyxCouponCodesRequest;
				}

				const ajaxEndpoint = (quorlyxAdmin && quorlyxAdmin.ajax_url)
					? quorlyxAdmin.ajax_url
					: (typeof ajaxurl !== 'undefined' ? ajaxurl : window.ajaxurl);

				if (!ajaxEndpoint) {
					const missingEndpoint = $.Deferred();
					missingEndpoint.resolve([]);
					return missingEndpoint.promise();
				}

				const deferred = $.Deferred();
				quorlyxCouponCodesRequest = deferred.promise();

				$.ajax({
					url: ajaxEndpoint,
					method: 'POST',
					dataType: 'json',
					data: {
						action: 'quorlyx_fetch_coupon_codes',
						_ajax_nonce: (quorlyxAdmin && quorlyxAdmin.nonce) ? quorlyxAdmin.nonce : ''
					}
				}).done(function(response) {
					const payload = (response && response.success && response.data) ? response.data : {};
					quorlyxCouponCodesCache = normalizeCouponCodes(payload.coupon_codes || []);
					deferred.resolve(quorlyxCouponCodesCache);
				}).fail(function() {
					quorlyxCouponCodesCache = [];
					deferred.resolve([]);
				}).always(function() {
					quorlyxCouponCodesRequest = null;
				});

				return quorlyxCouponCodesRequest;
			}

			function ensureCouponSelectLoaded(item, forceRefresh) {
				const selectEl = item.find('.quorlyx-cta-coupon-select');
				if (!selectEl.length) {
					return;
				}

				if (!forceRefresh && selectEl.attr('data-coupon-loaded') === '1' && selectEl.find('option').length > 1) {
					return;
				}

				selectEl.prop('disabled', true);
				selectEl.empty().append($('<option>').val('').text('Loading coupons...'));

				fetchCouponCodes(forceRefresh).done(function(codes) {
					populateCouponSelect(selectEl, codes);
				});
			}

			function toggleTriggerCtaFields(item) {
				const ctaVariant = String(item.find('.quorlyx-cta-variant-select').val() || 'resume_checkout');
				const offerMode = String(item.find('.quorlyx-cta-offer-mode-select').val() || 'coupon');

				const showOfferOptions = ctaVariant === 'apply_offer';
				const showCouponField = showOfferOptions && offerMode === 'coupon';
				const showCustomFields = ctaVariant === 'custom' || (showOfferOptions && offerMode === 'custom_offer');

				item.find('.quorlyx-cta-offer-options').toggle(showOfferOptions);
				item.find('.quorlyx-cta-coupon-options').toggle(showCouponField);
				item.find('.quorlyx-cta-custom-options').toggle(showCustomFields);
				if (showCouponField) {
					ensureCouponSelectLoaded(item, false);
				}
			}

			function parseMultilineList(rawValue) {
				return String(rawValue || '')
					.split(/\\r?\\n|,/) 
					.map((value) => value.trim())
					.filter(Boolean);
			}

			function normalizePreviewUrl(rawValue) {
				const source = String(rawValue || '').trim();
				if (!source) {
					return window.location.href;
				}

				if (/^https?:\/\//i.test(source)) {
					return source;
				}

				if (source.charAt(0) === '/') {
					return window.location.origin + source;
				}

				return window.location.origin + '/' + source;
			}

			function getPreviewSpecificity(trigger, previewUrl) {
				let score = 0;
				const target = String(trigger.target_page_url || '').trim();
				const sectionSelector = String(trigger.target_section_selector || '').trim();
				const excludes = parseMultilineList(trigger.exclude_page_urls);

				if (target) {
					score += Math.min(200, target.length * 4);
					if (previewUrl.indexOf(target) !== -1) {
						score += 80;
					}
				}

				if (sectionSelector) {
					score += Math.min(160, sectionSelector.length * 8);
				}
				score += Math.min(120, excludes.length * 20);
				if (trigger.only_if_cart_empty) {
					score += 20;
				}
				if (trigger.require_cart_not_empty) {
					score += 20;
				}

				return score;
			}

			function getPreviewPriority(trigger) {
				const value = parseInt(trigger.priority_score, 10);
				if (isNaN(value)) {
					return 100;
				}
				return Math.max(1, Math.min(1000, value));
			}

			function getPreviewCreatedAt(trigger) {
				const value = parseInt(trigger.created_at, 10);
				if (isNaN(value) || value <= 0) {
					return Number.MAX_SAFE_INTEGER;
				}
				return value;
			}

			function extractTriggerForPreview(item, index, previewUrl) {
				const name = item.find('[name*=\'[name]\']').val() || 'Unnamed Trigger';
				const target = String(item.find('[name*=\'[target_page_url]\']').val() || '').trim();
				const sectionSelector = String(item.find('[name*=\'[target_section_selector]\']').val() || '').trim();
				const excludes = parseMultilineList(item.find('[name*=\'[exclude_page_urls]\']').val());
				const excludedNow = excludes.some((part) => previewUrl.indexOf(part) !== -1);
				const active = item.find('[name*=\'[is_active]\']').is(':checked');

				let eligible = active;
				if (eligible && target && previewUrl.indexOf(target) === -1) {
					eligible = false;
				}
				if (eligible && excludedNow) {
					eligible = false;
				}

				const model = {
					index,
					name,
					id: item.find('[name*=\'[id]\']').val() || '',
					priority_score: item.find('[name*=\'[priority_score]\']').val() || '100',
					created_at: item.find('[name*=\'[created_at]\']').val() || '0',
					target_page_url: target,
					target_section_selector: sectionSelector,
					exclude_page_urls: excludes.join('\\n'),
					only_if_cart_empty: item.find('[name*=\'[only_if_cart_empty]\']').is(':checked'),
					require_cart_not_empty: item.find('[name*=\'[require_cart_not_empty]\']').is(':checked'),
					specificity_score: 0,
					eligible,
				};

				model.specificity_score = getPreviewSpecificity(model, previewUrl);
				return model;
			}

			function sortPreviewTriggers(triggers) {
				return triggers.sort((left, right) => {
					if (left.eligible !== right.eligible) {
						return left.eligible ? -1 : 1;
					}

					const priorityDiff = getPreviewPriority(right) - getPreviewPriority(left);
					if (priorityDiff !== 0) {
						return priorityDiff;
					}

					const specificityDiff = right.specificity_score - left.specificity_score;
					if (specificityDiff !== 0) {
						return specificityDiff;
					}

					const createdAtDiff = getPreviewCreatedAt(left) - getPreviewCreatedAt(right);
					if (createdAtDiff !== 0) {
						return createdAtDiff;
					}

					return left.index - right.index;
				});
			}

			function renderTriggerOrderPreview() {
				const body = $('#quorlyx-trigger-order-preview-body');
				if (!body.length) {
					return;
				}

				const previewUrl = normalizePreviewUrl($('#quorlyx-trigger-preview-url').val());
				const rows = [];
				$('#quorlyx-triggers-container .quorlyx-trigger-item').each(function(index) {
					rows.push(extractTriggerForPreview($(this), index, previewUrl));
				});

				sortPreviewTriggers(rows);
				body.empty();

				if (!rows.length) {
					body.append('<tr><td colspan=\'6\'>No triggers configured yet.</td></tr>');
					return;
				}

				rows.forEach((row, idx) => {
					const createdAt = getPreviewCreatedAt(row);
					const createdText = createdAt === Number.MAX_SAFE_INTEGER ? 'n/a' : new Date(createdAt * 1000).toLocaleString();
					const eligibility = row.eligible ? 'Eligible' : 'Suppressed';
					const escapedName = $('<div>').text(row.name).html();
					const escapedId = $('<div>').text(row.id || '').html();
					body.append(
						'<tr>' +
							'<td>' + (idx + 1) + '</td>' +
							'<td><strong>' + escapedName + '</strong><br><code>' + escapedId + '</code></td>' +
							'<td>' + getPreviewPriority(row) + '</td>' +
							'<td>' + row.specificity_score + '</td>' +
							'<td>' + $('<div>').text(createdText).html() + '</td>' +
							'<td>' + eligibility + '</td>' +
						'</tr>'
					);
				});
			}

			function toggleTriggerAbScopeFields() {
				const isEnabled = $('#ab_testing_enabled_toggle').is(':checked');
				$('.quorlyx-trigger-ab-scope-toggle').toggle(isEnabled);
			}

            $('#quorlyx-triggers-container').on('change', '.quorlyx-trigger-type-select', function() {
                const item = $(this).closest('.quorlyx-trigger-item');
                const newType = $(this).val();
                const messageTextarea = item.find('.quorlyx-proactive-message');
                const currentMessage = messageTextarea.val();

                const isDefaultOrEmpty = Object.values(defaultMessages).includes(currentMessage) || currentMessage.trim() === '';
                if (isDefaultOrEmpty) {
					const nextMessage = defaultMessages[newType] || defaultMessages.time_on_page || '';
                    messageTextarea.val(nextMessage);
                }

                toggleTriggerFields(item);
            });

			$('#quorlyx-triggers-container').on('change', '.quorlyx-schedule-enabled', function() {
				const item = $(this).closest('.quorlyx-trigger-item');
				toggleTriggerScheduleFields(item);
				updateTriggerSummary(item);
			});

			$('#quorlyx-triggers-container').on('change', '.quorlyx-schedule-day', function() {
				const item = $(this).closest('.quorlyx-trigger-item');
				syncScheduleDaysHidden(item);
				updateTriggerSummary(item);
			});

			$('#quorlyx-triggers-container').on('change', '.quorlyx-cta-variant-select, .quorlyx-cta-offer-mode-select', function() {
				const item = $(this).closest('.quorlyx-trigger-item');
				toggleTriggerCtaFields(item);
				updateTriggerSummary(item);
			});

            $('#quorlyx-triggers-container .quorlyx-trigger-item').each(function() {
                const item = $(this);
                toggleTriggerFields(item);
				toggleTriggerScheduleFields(item);
				toggleTriggerCtaFields(item);
                updateTriggerSummary(item);
            });
			renderTriggerOrderPreview();

			$('#ab_testing_enabled_toggle').on('change.quorlyxTriggerScope', function() {
				toggleTriggerAbScopeFields();
				$('#quorlyx-triggers-container .quorlyx-trigger-item').each(function() {
					updateTriggerSummary($(this));
				});
				renderTriggerOrderPreview();
			});
			toggleTriggerAbScopeFields();

            $('#quorlyx-add-trigger').on('click', function() {
                const container = $('#quorlyx-triggers-container');
                const template = $('#quorlyx-trigger-template').html();
                const index = new Date().getTime(); // Unique index
                const newItem = $(template.replace(/__INDEX__/g, index));
				const randomPart = window.crypto && window.crypto.getRandomValues
					? Array.from(window.crypto.getRandomValues(new Uint32Array(2))).map((value) => value.toString(36)).join('')
					: Math.random().toString(36).slice(2, 12);

				newItem.find('input[type=hidden]').filter(function() {
					return this.name && this.name.endsWith('[id]');
				}).val('trigger_' + index + '_' + randomPart);
				newItem.find('input[type=hidden]').filter(function() {
					return this.name && this.name.endsWith('[created_at]');
				}).val(Math.floor(index / 1000));
                newItem.find('.quorlyx-proactive-message').val(defaultMessages.time_on_page || '');

                container.append(newItem);
                toggleTriggerFields(newItem);
				toggleTriggerScheduleFields(newItem);
				toggleTriggerCtaFields(newItem);
                updateTriggerSummary(newItem);
				renderTriggerOrderPreview();
                newItem.find('.quorlyx-repeater-name-input').focus();
            });

            $('#quorlyx-triggers-container').on('click', '.quorlyx-remove-item', function(e) {
                e.stopPropagation();
                if (confirm('Are you sure you want to remove this trigger?')) {
                    $(this).closest('.quorlyx-trigger-item').remove();
					renderTriggerOrderPreview();
                }
            });

            $('#quorlyx-triggers-container').on('click', '.quorlyx-edit-item', function(e) {
                e.stopPropagation();
                $(this).closest('.quorlyx-trigger-item').attr('data-state', 'edit').find('.quorlyx-repeater-name-input').focus();
            });

            $('#quorlyx-triggers-container').on('click', '.quorlyx-done-item', function(e) {
                e.stopPropagation();
                const item = $(this).closest('.quorlyx-trigger-item');
                const nameInput = item.find('.quorlyx-repeater-name-input');
                if (!nameInput.val().trim()) {
                    alert('Trigger Name is required.');
                    nameInput.focus();
                    return;
                }
                updateTriggerSummary(item);
                item.attr('data-state', 'view');
                renderTriggerOrderPreview();
            });

			$('#quorlyx-refresh-trigger-preview').on('click', function() {
				renderTriggerOrderPreview();
			});

			$('#quorlyx-trigger-preview-url').on('input change', function() {
				renderTriggerOrderPreview();
			});

			$('#quorlyx-triggers-container').on('input change', 'input, select, textarea', function() {
				const item = $(this).closest('.quorlyx-trigger-item');
				if (item.length) {
					updateTriggerSummary(item);
				}
				renderTriggerOrderPreview();
			});

            $('body').on('click', '.quorlyx-collapsible-header, .quorlyx-collapsible-header-plain', function(e) {
                 e.preventDefault();
                 const header = $(this);
                 const content = header.is('tr') 
                     ? header.closest('tbody').next('tbody.quorlyx-collapsible-content') 
                     : header.next('.quorlyx-collapsible-content');
                 content.slideToggle(200);
                 header.find('.toggle-arrow').toggleClass('dashicons-arrow-down-alt2 dashicons-arrow-up-alt2');
            });
            $('.quorlyx-collapsible-header, .quorlyx-collapsible-header-plain').each(function() {
                const header = $(this);
                const content = header.is('tr') 
                    ? header.closest('tbody').next('tbody.quorlyx-collapsible-content') 
                    : header.next('.quorlyx-collapsible-content');
                if (header.attr('id') === 'quorlyx-advanced-triggers-header' || header.attr('id') === 'tour-step-advanced-appearance') {

                }
            });

            const modal = $('#quorlyx-reset-modal');
            $('#quorlyx-manage-data-btn').on('click', function() { modal.show(); });
            $('#quorlyx-reset-cancel').on('click', function() { modal.hide(); });

            const confirmBtn = $('#quorlyx-reset-confirm');
            const confirmInput = $('#quorlyx-reset-confirm-text');
            const confirmDiv = $('#quorlyx-reset-confirmation');
			const destructiveCheckbox = $('#quorlyx-reset-options label.destructive input[type=\"checkbox\"]');

            function updateConfirmButtonState() {
                const isDestructive = destructiveCheckbox.is(':checked');
                const isConfirmed = confirmInput.val() === 'RESET';
                confirmBtn.prop('disabled', isDestructive && !isConfirmed);
            }

            $('#quorlyx-reset-options input[type=\"checkbox\"]').on('change', function() {
                if (destructiveCheckbox.is(':checked')) {
                    confirmDiv.slideDown();
                } else {
                    confirmDiv.slideUp();
                }
                updateConfirmButtonState();
            });

            confirmInput.on('keyup', updateConfirmButtonState);

            confirmBtn.on('click', function() {
                const spinner = $('#quorlyx-reset-actions .spinner');
                const statusDiv = $('#quorlyx-reset-status');

                let dataToReset = {};
                $('#quorlyx-reset-options input:checked').each(function() {
					const fieldName = $(this).attr('name');
					if (fieldName !== 'delete_data_on_uninstall') {
						dataToReset[fieldName] = true;
					}
                });
				const uninstallCleanup = $('#quorlyx-delete-data-on-uninstall');
				if (uninstallCleanup.length) {
					const savedState = uninstallCleanup.attr('data-saved') === '1';
					const currentState = uninstallCleanup.is(':checked');
					if (savedState !== currentState) {
						dataToReset.delete_data_on_uninstall_state = currentState ? '1' : '0';
					}
				}
				dataToReset.confirmation = confirmInput.val();

                if (Object.keys(dataToReset).filter(function(key) { return key !== 'confirmation'; }).length === 0) {
                    statusDiv.text('Please select at least one option to reset.').addClass('notice notice-warning').show();
                    setTimeout(() => statusDiv.fadeOut(), 3000);
                    return;
                }

                spinner.addClass('is-active');
                confirmBtn.prop('disabled', true);

                $.ajax({
                    url: quorlyxAdmin.restUrl + 'reset-data',
                    method: 'POST',
                    beforeSend: (xhr) => xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce),
                    data: JSON.stringify(dataToReset),
                    contentType: 'application/json',
                }).done(function(response) {
                    statusDiv.text((response && response.message) ? response.message + ' Reloading dashboard...' : 'Data reset successfully. Reloading dashboard...').addClass('notice notice-success').show();
                    setTimeout(() => window.location.reload(), 1500);
                }).fail(function() {
                    statusDiv.text('An error occurred. Please try again.').addClass('notice notice-error').show();
                }).always(function() {
                    spinner.removeClass('is-active');
                });
            });

            function fetchPostGenModels() {
                const provider = $('.quorlyx-postgen-provider-select').val();
                const apiKey = $('.quorlyx-postgen-api-key-input').val();
                const modelSelect = $('.quorlyx-postgen-model-select');
                const spinner = $('.quorlyx-postgen-model-spinner');
                const savedModel = modelSelect.data('saved-model');

                if (!provider || !apiKey) return;

                spinner.addClass('is-active');
                modelSelect.prop('disabled', true);

                $.ajax({
                    url: quorlyxAdmin.restUrl + 'fetch-models',
                    method: 'POST',
                    beforeSend: function(xhr) { xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce); },
                    data: JSON.stringify({ provider: provider, api_key: apiKey, mode: 'chat' }),
                    contentType: 'application/json',
                    dataType: 'json'
                }).done(function(response) {
                    modelSelect.empty();
                    if (response.success && response.models && response.models.length > 0) {
                        $.each(response.models, function(i, model) {
                            const isSelected = (savedModel && savedModel === model.id) ? 'selected' : '';
                            modelSelect.append('<option value=\"' + model.id + '\" ' + isSelected + '>' + model.name + '</option>');
                        });
                        if (!savedModel && response.models.length > 0) {
                            modelSelect.val(response.models[0].id);
                        }
                    } else {
                        modelSelect.append('<option value=\"\">No models found</option>');
                    }
                }).fail(function() {
                    modelSelect.empty().append('<option value=\"\">Error fetching models</option>');
                    if (savedModel) {
                        modelSelect.append('<option value=\"' + savedModel + '\" selected>' + savedModel + '</option>');
                    }
                }).always(function() {
                    spinner.removeClass('is-active');
                    modelSelect.prop('disabled', false);
                });
            }

			function getFallbackApiKey(provider) {
				const selectors = [
					'.api-key-wrapper[data-variation=\"a\"] .api-key-input[data-provider=\"' + provider + '\"] .quorlyx-api-key-input',
					'.api-key-wrapper[data-variation=\"b\"] .api-key-input[data-provider=\"' + provider + '\"] .quorlyx-api-key-input'
				];
				for (let i = 0; i < selectors.length; i++) {
					const apiKeyInput = $(selectors[i]);
					if (apiKeyInput.length && apiKeyInput.val()) {
						return apiKeyInput.val().trim();
					}
				}
				return '';
			}

			function fetchModelsForFallback(provider, apiKey) {
				const fallbackModelSelect = $('.quorlyx-fallback-model-select');
				const fallbackSpinner = $('.quorlyx-fallback-model-spinner');
				const savedModel = fallbackModelSelect.data('saved-model');

				if (!fallbackModelSelect.length || !provider || !apiKey) return;

				fallbackSpinner.addClass('is-active');
				fallbackModelSelect.prop('disabled', true).empty().append('<option>Fetching models...</option>');

				$.ajax({
					url: quorlyxAdmin.restUrl + 'fetch-models',
					method: 'POST',
					beforeSend: function(xhr) { xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce); },
					data: JSON.stringify({ provider: provider, api_key: apiKey, mode: 'chat' }),
					contentType: 'application/json',
					dataType: 'json'
				}).done(function(response) {
					fallbackModelSelect.empty();
					if (response.success && response.models && response.models.length > 0) {
						$.each(response.models, function(i, model) {
							const isSelected = (savedModel && savedModel === model.id) ? 'selected' : '';
							fallbackModelSelect.append('<option value=\"' + model.id + '\" ' + isSelected + '>' + model.name + '</option>');
						});
						if (!savedModel && response.models.length > 0) {
							fallbackModelSelect.val(response.models[0].id);
						}
					} else {
						fallbackModelSelect.append('<option value=\"\">No models found</option>');
					}
				}).fail(function() {
					fallbackModelSelect.empty().append('<option value=\"\">Error fetching models</option>');
					if (savedModel) {
						fallbackModelSelect.append('<option value=\"' + savedModel + '\" selected>' + savedModel + '</option>');
					}
				}).always(function() {
					fallbackSpinner.removeClass('is-active');
					fallbackModelSelect.prop('disabled', false);
				});
			}

			function initFallbackModelFetch() {
				const provider = $('.quorlyx-fallback-provider-select').val();
				if (!provider) return;
				const apiKey = getFallbackApiKey(provider);
				if (!apiKey) return;
				fetchModelsForFallback(provider, apiKey);
			}

            function debounce(func, wait, immediate) {
                var timeout;
                return function() {
                    var context = this, args = arguments;
                    var later = function() {
                        timeout = null;
                        if (!immediate) func.apply(context, args);
                    };
                    var callNow = immediate && !timeout;
                    clearTimeout(timeout);
                    timeout = setTimeout(later, wait);
                    if (callNow) func.apply(context, args);
                };
            }

            $('body').on('change', '.quorlyx-postgen-provider-select', fetchPostGenModels);
            $('body').on('input', '.quorlyx-postgen-api-key-input', debounce(fetchPostGenModels, 800));

			$('body').on('change', '.quorlyx-fallback-provider-select', function() {
				initFallbackModelFetch();
			});
			$('body').on('input', '.quorlyx-api-key-input', debounce(function() {
				const provider = $('.quorlyx-fallback-provider-select').val();
				if (!provider) return;
				const apiKey = getFallbackApiKey(provider);
				if (!apiKey) return;
				initFallbackModelFetch();
			}, 800));

            $('#quorlyx_post_generator_ai_mode').on('change', function() {
                const isIndependent = $(this).val() === 'independent';
                $('.quorlyx-postgen-independent-row').toggle(isIndependent);
                $('.quorlyx-postgen-required').each(function() {
                    const field = $(this);
                    const storedKeyFlag = field.data('has-stored-key');
                    const hasStoredKey = field.hasClass('quorlyx-postgen-api-key-input') && (storedKeyFlag === 1 || storedKeyFlag === '1');
                    field.prop('required', isIndependent && !(hasStoredKey && !field.val()));
                });
                if (isIndependent) {
                    fetchPostGenModels();
                }
            });

            if ($('.quorlyx-postgen-provider-select').length && $('.quorlyx-postgen-api-key-input').val()) {
                 fetchPostGenModels();
            }

			  if ($('.quorlyx-fallback-provider-select').length) {
				  initFallbackModelFetch();
			  }

        });
    })(jQuery);
    ";
	$admin_js .= <<<'QUORLYX_SETTINGS_HELP_JS'
(function($){
	$(function(){
		const $roots = $('#quorlyx-settings-page');
		if (!$roots.length) {
			return;
		}

		function plainText(value) {
			return String(value || '').replace(/\s+/g, ' ').trim();
		}

		function addHelpTip($target, text, placement) {
			const clean = plainText(text);
			if (!clean || !$target || !$target.length) {
				return false;
			}

			let existingSame = false;
			let existingAny = false;
			const $existingTips = placement === 'after'
				? $target.nextAll('.quorlyx-help-tip').first()
				: $target.children('.quorlyx-help-tip');

			$existingTips.each(function(){
				const existingText = plainText($(this).attr('data-tip'));
				if (existingText) {
					existingAny = true;
				}
				if (existingText === clean) {
					existingSame = true;
				}
			});
			if (existingAny) {
				return existingSame;
			}

			const $tip = $('<span/>', {
				class: 'quorlyx-help-tip',
				tabindex: 0,
				role: 'button',
				'aria-label': clean,
				'data-tip': clean,
				text: '?'
			});

			if (placement === 'after') {
				$tip.insertAfter($target);
			} else {
				$tip.appendTo($target);
			}

			return true;
		}

		function findPreviousHelpTarget($container, $desc, selector) {
			const descNode = $desc && $desc[0] ? $desc[0] : null;
			if (!descNode || !$container || !$container.length) {
				return $();
			}

			const matches = $container.find(selector).filter(function(){
				return this !== descNode && !!(this.compareDocumentPosition(descNode) & Node.DOCUMENT_POSITION_FOLLOWING);
			}).toArray();

			return matches.length ? $(matches[matches.length - 1]) : $();
		}

		function helpTargetReady($target, placement) {
			return $target && $target.length && (placement === 'after' || !!plainText($target.text()));
		}

		function convertDescriptionsToHelp(scope) {
			const $root = scope ? $(scope) : $roots;

			$root.find('label[title], th[title], legend[title], strong[title], h4[title]').not('.quorlyx-title-as-help').each(function(){
				const $target = $(this);
				const clean = plainText($target.attr('title'));
				$target.removeAttr('title').addClass('quorlyx-title-as-help');
				if (clean) {
					addHelpTip($target, clean);
				}
			});

			$root.find('p.description').not('.quorlyx-description-preserved, .quorlyx-description-as-help').each(function(){
				const $desc = $(this);
				if ($desc.find('input, select, textarea, button, a').length) {
					return;
				}

				const clean = plainText($desc.text());
				if (!clean || clean.length < 8 || /:\s*$/.test(clean)) {
					return;
				}

				let $target = $();
				let placement = 'inside';
				const $cell = $desc.closest('td');
				const $row = $desc.closest('tr');
				if ($cell.length) {
					$target = findPreviousHelpTarget($cell, $desc, 'label, .quorlyx-field-label, strong, legend, h1, h2, h3, h4, h5');
					if (!$target.length || !plainText($target.text())) {
						$target = findPreviousHelpTarget($cell, $desc, 'input:not([type="hidden"]), select, textarea, button');
						placement = $target.length ? 'after' : 'inside';
					}
				}
				if (!helpTargetReady($target, placement) && $desc.closest('.quorlyx-form-group').length) {
					$target = $desc.closest('.quorlyx-form-group').children('label, .quorlyx-field-label').first();
					placement = 'inside';
				}
				if (!helpTargetReady($target, placement) && $desc.prevAll('label, strong, h1, h2, h3, h4, h5').length) {
					$target = $desc.prevAll('label, strong, h1, h2, h3, h4, h5').first();
					placement = 'inside';
				}
				if (!helpTargetReady($target, placement) && $row.length && $row.find('td p.description').not('.quorlyx-description-preserved, .quorlyx-description-as-help').length <= 1) {
					$target = $row.children('th').first();
					placement = 'inside';
				}
				if (!helpTargetReady($target, placement)) {
					return;
				}

				if (addHelpTip($target, clean, placement)) {
					$desc.addClass('quorlyx-description-as-help').attr('aria-hidden', 'true').hide();
				}
			});
		}

		let helpTimer = null;
		function scheduleHelpConversion() {
			window.clearTimeout(helpTimer);
			helpTimer = window.setTimeout(function(){
				convertDescriptionsToHelp();
			}, 80);
		}

		convertDescriptionsToHelp();
		$('body').addClass('quorlyx-help-popovers-enabled');
		let activeHelpTip = null;
		let helpPopover = null;

		function hideHelpPopover() {
			activeHelpTip = null;
			if (helpPopover) {
				helpPopover.remove();
				helpPopover = null;
			}
		}

		function positionHelpPopover() {
			if (!activeHelpTip || !helpPopover) {
				return;
			}

			const rect = activeHelpTip.getBoundingClientRect();
			const margin = 12;
			helpPopover.css({ left: 0, top: 0 });
			const width = helpPopover.outerWidth();
			const height = helpPopover.outerHeight();
			let left = rect.left + (rect.width / 2) - (width / 2);
			left = Math.max(margin, Math.min(left, window.innerWidth - width - margin));
			let top = rect.bottom + 8;
			if (top + height + margin > window.innerHeight) {
				top = rect.top - height - 8;
			}
			top = Math.max(margin, Math.min(top, window.innerHeight - height - margin));
			helpPopover.css({ left: left + 'px', top: top + 'px' });
		}

		function showHelpPopover(target) {
			const text = plainText($(target).attr('data-tip'));
			if (!text) {
				hideHelpPopover();
				return;
			}

			activeHelpTip = target;
			if (!helpPopover) {
				helpPopover = $('<div/>', { class: 'quorlyx-help-popover', role: 'tooltip' }).appendTo('body');
			}
			helpPopover.text(text);
			positionHelpPopover();
		}

		$('body').off('mouseenter.quorlyxHelpTip focusin.quorlyxHelpTip mouseleave.quorlyxHelpTip focusout.quorlyxHelpTip', '.quorlyx-help-tip');
		$('body').on('mouseenter.quorlyxHelpTip focusin.quorlyxHelpTip', '.quorlyx-help-tip', function(){
			showHelpPopover(this);
		});
		$('body').on('mouseleave.quorlyxHelpTip focusout.quorlyxHelpTip', '.quorlyx-help-tip', hideHelpPopover);
		$(window).off('scroll.quorlyxHelpTip resize.quorlyxHelpTip');
		$(window).on('scroll.quorlyxHelpTip resize.quorlyxHelpTip', positionHelpPopover);
		if (window.MutationObserver) {
			$roots.each(function(){
				new MutationObserver(scheduleHelpConversion).observe(this, { childList: true, subtree: true });
			});
		}

		$('body').off('click', '.quorlyx-help-tip');
		$('body').on('click.quorlyxHelpTip', '.quorlyx-help-tip', function(e){
			e.preventDefault();
			e.stopPropagation();
		});

		function updateKbFileInput($wrapper) {
			const ids = [];
			$wrapper.find('.quorlyx-kb-file-list li[data-id]').each(function(){
				const id = parseInt($(this).attr('data-id'), 10);
				if (id && ids.indexOf(id) === -1) {
					ids.push(id);
				}
			});
			$wrapper.find('.quorlyx-kb-file-ids').val(ids.join(','));
		}

		$('body').off('click', '.quorlyx-kb-file-upload');
		$('body').on('click.quorlyxKbFiles', '.quorlyx-kb-file-upload', function(e){
			e.preventDefault();
			e.stopPropagation();
			if (typeof wp === 'undefined' || !wp.media) {
				window.alert('WordPress media uploader is not available on this screen. Refresh the settings page and try again.');
				return;
			}

			const $wrapper = $(this).closest('.quorlyx-kb-file-uploader');
			const frame = wp.media({
				title: 'Select Knowledge Base files',
				button: { text: 'Use selected files' },
				multiple: true,
				library: {
					type: [
						'application/pdf',
						'text/plain',
						'text/markdown',
						'text/x-markdown',
						'text/csv',
						'application/csv',
						'application/json',
						'text/html',
						'application/xml',
						'text/xml'
					]
				}
			});

			frame.on('select', function(){
				const selection = frame.state().get('selection');
				selection.each(function(attachment){
					const file = attachment.toJSON();
					const id = parseInt(file.id, 10);
					if (!id || $wrapper.find('.quorlyx-kb-file-list li[data-id="' + id + '"]').length) {
						return;
					}

					const title = file.title || file.filename || ('Attachment #' + id);
					const mime = file.mime || file.subtype || '';
					const $item = $('<li/>', {
						'data-id': id,
						style: 'display:flex; align-items:center; gap:8px; margin:4px 0;'
					});
					$item.append('<span class="dashicons dashicons-media-document"></span>');
					$item.append($('<span/>', { class: 'quorlyx-kb-file-title', text: title }));
					if (mime) {
						$item.append($('<code/>', { text: mime }));
					}
					$item.append($('<button/>', { type: 'button', class: 'button-link-delete quorlyx-kb-file-remove', text: 'Remove' }));
					$wrapper.find('.quorlyx-kb-file-list').append($item);
				});
				updateKbFileInput($wrapper);
			});

			frame.open();
		});

		$('body').off('click', '.quorlyx-kb-file-remove');
		$('body').on('click.quorlyxKbFiles', '.quorlyx-kb-file-remove', function(e){
			e.preventDefault();
			const $wrapper = $(this).closest('.quorlyx-kb-file-uploader');
			$(this).closest('li').remove();
			updateKbFileInput($wrapper);
		});
	});
})(jQuery);
QUORLYX_SETTINGS_HELP_JS;
	$admin_js .= <<<'QUORLYX_JS'
(function($){

			const $page = $('#quorlyx-content-insights-page');
			if (!$page.length) {
				return;
			}

			const getAjaxNonce = () => {
				if (typeof quorlyxAdmin !== 'undefined' && quorlyxAdmin && quorlyxAdmin.nonce) {
					return String(quorlyxAdmin.nonce);
				}
				if (typeof quorlyx_local !== 'undefined' && quorlyx_local && quorlyx_local.nonce) {
					return String(quorlyx_local.nonce);
				}
				return '';
			};

			const getCsvAjaxErrorMessage = (response, fallbackMessage) => {
				if (!response) {
					return fallbackMessage;
				}

				const data = typeof response.data !== 'undefined' ? response.data : response;
				if (typeof data === 'string' && data.trim()) {
					return data;
				}
				if (data && typeof data.message === 'string' && data.message.trim()) {
					return data.message;
				}

				return fallbackMessage;
			};

			let csvImportRequestId = '';
			const updateCsvRequestId = (response) => {
				if (!response || !response.data) {
					return;
				}

				let requestId = '';
				if (response.data.request_id) {
					requestId = String(response.data.request_id || '').trim();
				} else if (response.data.details && response.data.details.request_id) {
					requestId = String(response.data.details.request_id || '').trim();
				}

				if (requestId) {
					csvImportRequestId = requestId;
				}
			};

			const logClientIssue = (type, message, details) => {
				const safeDetails = Object.assign({
					page: 'content_insights'
				}, details || {});

				let operation = 'client_issue';
				if (typeof safeDetails.operation === 'string' && safeDetails.operation.trim()) {
					operation = safeDetails.operation.trim();
					delete safeDetails.operation;
				}

				const payload = {
					action: 'quorlyx_log_client_issue',
					type: String(type || 'error'),
					message: String(message || 'Client issue'),
					component: 'content_insights_import',
					operation: operation,
					request_id: csvImportRequestId,
					details: JSON.stringify(safeDetails),
					_ajax_nonce: getAjaxNonce()
				};

				$.ajax({
					url: (typeof ajaxurl !== "undefined" ? ajaxurl : window.ajaxurl),
					type: 'POST',
					data: payload
				});
			};

			// Handle CSV Upload for Historical Data Import
			$('#quorlyx-csv-upload-btn').on('click', function(e) {
				e.preventDefault();
				const $btn = $(this);
				const fileInput = document.getElementById('quorlyx-csv-file');

				if (!fileInput.files.length) {
					alert('Please select a CSV file first.');
					return;
				}

				const file = fileInput.files[0];
				if (file.type !== 'text/csv' && !file.name.endsWith('.csv')) {
					alert('Please upload a valid CSV file.');
					return;
				}

				$btn.prop('disabled', true).text('Uploading...');

				const formData = new FormData();
				formData.append('action', 'quorlyx_import_csv');
				formData.append('quorlyx_csv', file);
				formData.append('_ajax_nonce', getAjaxNonce());

				$.ajax({
					url: (typeof ajaxurl !== "undefined" ? ajaxurl : window.ajaxurl),
					type: 'POST',
					data: formData,
					processData: false,
					contentType: false,
					success: function(response) {
						updateCsvRequestId(response);
						if (response.success && response.data && response.data.headers) {
							const headers = response.data.headers;
							const fields = {
								'ignore': '-- Ignore --',
								'identifier': 'Post / Product URL or ID (Required)',
								'views': 'Page Views / Product Views',
								'add_to_cart': 'Add to Cart product',
								'checkout_flow': 'Checkout Flow (Auto-detect by header)',
								'checkout_visits': 'Checkout Visits',
								'checkout_success': 'Checkout Success',
								'cart_drop_off': 'Cart Drop-Off',
								'checkout_drop_off': 'Checkout Drop-Off',
								'conversions': 'Conversions product/Posts',
								'time': 'Avg. Time on Page',
								'scroll': 'Avg. Scroll Depth (%)'
							};
							
							let rowsHtml = '';
							$.each(headers, function(index, header) {
								let optionsHtml = '';
								$.each(fields, function(val, label) {
									optionsHtml += '<option value="' + val + '">' + label + '</option>';
								});
								
								rowsHtml += '<tr>';
								rowsHtml += '<th scope="row"><label>Column: <strong>' + header + '</strong></label></th>';
								rowsHtml += '<td><select class="quorlyx-csv-column-map" data-col-index="' + index + '">' + optionsHtml + '</select></td>';
								rowsHtml += '</tr>';
							});
							
							$('#quorlyx-csv-mapping-rows').html(rowsHtml);
							$('#quorlyx-csv-import-form').slideUp('fast', function() {
								$('#quorlyx-csv-mapping-ui').slideDown('fast');
							});
						} else {
							const errorMessage = getCsvAjaxErrorMessage(response, 'Failed to parse CSV.');
							alert('Error: ' + errorMessage);
						}
					},
					error: function(jqXHR, textStatus, errorThrown) {
						updateCsvRequestId(jqXHR && jqXHR.responseJSON ? jqXHR.responseJSON : null);
						const errorMessage = getCsvAjaxErrorMessage(
							jqXHR && jqXHR.responseJSON ? jqXHR.responseJSON : null,
							'Server request failed. Please check the network tab.'
						);
						logClientIssue('error', 'content_insights_csv_upload_request_failed', {
							phase: 'upload',
							operation: 'csv_upload',
							status: jqXHR ? jqXHR.status : 0,
							text_status: textStatus || '',
							error: errorThrown || ''
						});
						alert(errorMessage);
					},
					complete: function() {
						$btn.prop('disabled', false).text('Upload and Map Columns');
					}
				});
			});

						// Handle Finalize CSV Import
			$('#quorlyx-csv-mapping-ui').on('click', '#quorlyx-csv-finalize-btn', function(e) {
				e.preventDefault();
				const $btn = $(this);
				const mappings = {};
				
				$('.quorlyx-csv-column-map').each(function() {
					const val = $(this).val();
					if (val !== 'ignore') {
						mappings[$(this).data('col-index')] = val;
					}
				});
				
				let hasIdentifier = false;
				for (let key in mappings) {
					if (mappings[key] === 'identifier') hasIdentifier = true;
				}
				
				if (!hasIdentifier) {
					alert('You must map at least one column as the Post / Product URL or ID.');
					return;
				}
				
				$btn.prop('disabled', true).text('Importing Data...');
				
				// Now actually send it
				const fileInput = $('#quorlyx-csv-file')[0];
				if (!fileInput || !fileInput.files.length) {
					alert('File missing. Please try uploading again.');
					logClientIssue('error', 'content_insights_csv_file_missing', {
						phase: 'finalize',
						operation: 'csv_finalize',
						selector: '#quorlyx-csv-file'
					});
					$btn.prop('disabled', false).text('Finalize Import');
					return;
				}
				const file = fileInput.files[0];
				
				const formData = new FormData();
				formData.append('action', 'quorlyx_process_csv');
				formData.append('mappings', JSON.stringify(mappings));
				formData.append('data_type', String($('#quorlyx-csv-data-type').val() || 'post'));
				formData.append('quorlyx_csv', file);
				formData.append('request_id', csvImportRequestId);
				formData.append('_ajax_nonce', getAjaxNonce());
				
				$.ajax({
					url: (typeof ajaxurl !== "undefined" ? ajaxurl : window.ajaxurl),
					type: 'POST',
					data: formData,
					processData: false,
					contentType: false,
					success: function(response) {
						updateCsvRequestId(response);
						if (response.success) {
							const importedCount = Number(response.data && response.data.count ? response.data.count : 0);
							const skippedCount = Number(response.data && response.data.skipped ? response.data.skipped : 0);
							let successMessage = '<div class="notice notice-success inline" style="margin:0;"><p><strong>Success!</strong> Historical data (' + importedCount + ' rows) imported. Dashboard insights will now reflect this data.';
							if (skippedCount > 0) {
								successMessage += ' ' + skippedCount + ' rows were skipped. See the Logs tab for row-level details.';
							}
							successMessage += '</p></div>';
							$('#quorlyx-csv-mapping-ui').html(successMessage);
						} else {
							const errorMessage = getCsvAjaxErrorMessage(response, 'Unknown processing error.');
							alert('Processing error: ' + errorMessage);
							$btn.prop('disabled', false).text('Finalize Import');
						}
					},
					error: function(jqXHR, textStatus, errorThrown) {
						updateCsvRequestId(jqXHR && jqXHR.responseJSON ? jqXHR.responseJSON : null);
						const errorMessage = getCsvAjaxErrorMessage(
							jqXHR && jqXHR.responseJSON ? jqXHR.responseJSON : null,
							'Server request failed. Please check network logs.'
						);
						logClientIssue('error', 'content_insights_csv_finalize_request_failed', {
							phase: 'finalize',
							operation: 'csv_finalize',
							status: jqXHR ? jqXHR.status : 0,
							text_status: textStatus || '',
							error: errorThrown || ''
						});
						alert(errorMessage);
						$btn.prop('disabled', false).text('Finalize Import');
					}
				});
			});

			// Handle Native Integrations Scan
			$('#quorlyx-native-scan-btn').on('click', function(e) {
				e.preventDefault();
				const $btn = $(this);
				$btn.prop('disabled', true).html('<span class="dashicons dashicons-update" style="animation: spin 2s linear infinite;"></span> Scanning...');

				$.ajax({
					url: (typeof ajaxurl !== "undefined" ? ajaxurl : window.ajaxurl),
					type: 'POST',
					data: {
						action: 'quorlyx_native_scan',
						_ajax_nonce: getAjaxNonce()
					},
					success: function(response) {
						if (response.success) {
							alert('Scan Complete! Found data from: ' + response.data.sources.join(', ') + '. Synced ' + response.data.count + ' records.');
						} else {
							const errorMessage = getCsvAjaxErrorMessage(response, 'Scan finished. No external analytics table or historical orders found to import.');
							alert(errorMessage);
						}
					},
					error: function(jqXHR, textStatus, errorThrown) {
						const errorMessage = getCsvAjaxErrorMessage(
							jqXHR && jqXHR.responseJSON ? jqXHR.responseJSON : null,
							'Server request failed.'
						);
						logClientIssue('error', 'content_insights_native_scan_request_failed', {
							phase: 'native_scan',
							operation: 'native_scan',
							status: jqXHR ? jqXHR.status : 0,
							text_status: textStatus || '',
							error: errorThrown || ''
						});
						alert(errorMessage);
					},
					complete: function() {
						$btn.prop('disabled', false).html('<span class="dashicons dashicons-plugins-checked"></span> Scan Local Data Sources');
					}
				});
			});

			const getGlobalSortKeyForArrow = ($table, index, dir) => {
				const direction = dir === 'asc' ? 'asc' : 'desc';
				const hasCheckoutFlow = $table.find('thead th').filter(function() {
					return String($(this).text() || '').toLowerCase().indexOf('checkout flow') !== -1;
				}).length > 0;

				if (index === 1) {
					return 'source_' + direction;
				}
				if (index === 2) {
					return 'type_' + direction;
				}
				if (index === 3) {
					return 'views_' + direction;
				}
				if (index === 4) {
					return 'time_' + direction;
				}
				if (index === 5) {
					return 'scroll_' + direction;
				}
				if (hasCheckoutFlow && index === 6) {
					return 'add_to_cart_' + direction;
				}
				if (hasCheckoutFlow && index === 7) {
					return 'checkout_flow_' + direction;
				}
				if ((!hasCheckoutFlow && index === 6) || (hasCheckoutFlow && index === 8)) {
					return 'conversions_' + direction;
				}
				if ((!hasCheckoutFlow && index === 7) || (hasCheckoutFlow && index === 9)) {
					return 'conversion_rate_' + direction;
				}

				return '';
			};

			$page.on('click', '.quorlyx-sort-arrow', function(e) {
				e.preventDefault();
				const $btn = $(this);
				const index = parseInt(String($btn.data('sort-index') || ''), 10);
				const dir = String($btn.data('sort-dir') || 'asc');
				const $table = $btn.closest('table');

				if ($table.length === 0 || Number.isNaN(index)) {
					return;
				}

				const sortKey = getGlobalSortKeyForArrow($table, index, dir);
				if (!sortKey) {
					return;
				}

				let nextUrl = null;
				try {
					nextUrl = new URL(window.location.href);
					nextUrl.searchParams.set('page', 'quorlyx-content-insights');
					nextUrl.searchParams.set('insights_sort', sortKey);
					nextUrl.searchParams.set('insights_paged', '1');
					window.location.assign(nextUrl.toString());
					return;
				} catch (err) {
					// Fallback below for older environments.
				}

				const activeTab = String($('input[name="insight_tab"]').first().val() || 'products');
				window.location.search = '?page=quorlyx-content-insights&insight_tab=' + encodeURIComponent(activeTab) + '&insights_sort=' + encodeURIComponent(sortKey) + '&insights_paged=1';
			});

			$page.on('click', '.quorlyx-insight-ai-button', function() {
				const $button = $(this);
				const $cell = $button.closest('.quorlyx-insight-ai-cell');
				const $output = $cell.find('.quorlyx-insight-ai-output');
				const postId = parseInt($button.data('post-id'), 10) || 0;
				const contentKey = String($button.data('content-key') || '');

				if (typeof quorlyxAdmin === 'undefined' || !quorlyxAdmin.restUrl || !quorlyxAdmin.nonce) {
					$output.addClass('notice-error').text('AI suggestion is unavailable right now. Please reload the page and try again.');
					return;
				}

				if ($button.prop('disabled')) {
					return;
				}

				$button.prop('disabled', true).text('Suggesting...');
				$output.removeClass('notice-error').text('Generating AI suggestion...');

				$.ajax({
					url: quorlyxAdmin.restUrl + 'content-insight-suggestion',
					method: 'POST',
					contentType: 'application/json',
					data: JSON.stringify({
						post_id: postId,
						content_key: contentKey
					}),
					beforeSend: function(xhr) {
						xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce);
					}
				}).done(function(response) {
					if (response && response.success && response.suggestion) {
						$output.removeClass('notice-error').text(response.suggestion);
						$button.text('Suggest Again');
						return;
					}

					$output.addClass('notice-error').text('No AI suggestion was returned.');
					$button.text('Try Again');
				}).fail(function(jqXHR) {
					const message = jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'Could not generate AI suggestion right now.';
					$output.addClass('notice-error').text(message);
					$button.text('Try Again');
				}).always(function() {
					$button.prop('disabled', false);
				});
			});

			$page.on('click', '.quorlyx-insight-details-button', function() {
				const $button = $(this);
				const $panel = $button.closest('.quorlyx-insight-ai-cell').find('.quorlyx-insight-details-panel').first();
				if (!$panel.length) {
					return;
				}
				$panel.slideToggle(120, function() {
					$button.text($panel.is(':visible') ? 'Hide details' : 'View details');
				});
			});
		
})(jQuery);
QUORLYX_JS;

	wp_add_inline_script( 'quorlyx-admin', $admin_js );

	$brand_css = '

    .hndle .dashicons, .nav-tab .dashicons, .button .dashicons, .quorlyx-page-header .dashicons, h3 .dashicons, h4 .dashicons, .quorlyx-collapsible-header-plain .dashicons, #add_meta_boxes-post #quorlyx_seo_tools .hndle .dashicons {
