    #quorlyx-settings-page .form-table th { width: 200px; }
    #quorlyx-settings-page .form-table { margin-top: 0; }
    #quorlyx-settings-page .postbox,
    #quorlyx-content-insights-page .postbox { overflow: visible; }
    #quorlyx-settings-page .quorlyx-description-as-help,
    #quorlyx-content-insights-page .quorlyx-description-as-help { display: none !important; }
    #quorlyx-settings-page .quorlyx-help-tip,
    #quorlyx-content-insights-page .quorlyx-help-tip {
        position: relative;
        display: inline-flex;
        align-items: center;
        justify-content: center;
        width: 18px;
        height: 18px;
        margin-left: 6px;
        border: 1px solid #c3c4c7;
        border-radius: 50%;
        background: #fff;
        color: #5b21b6;
        font-size: 12px;
        font-weight: 700;
        line-height: 1;
        cursor: help;
        vertical-align: middle;
    }
    #quorlyx-settings-page .quorlyx-help-tip:focus,
    #quorlyx-content-insights-page .quorlyx-help-tip:focus {
        outline: 2px solid #7c3aed;
        outline-offset: 2px;
    }
    #quorlyx-settings-page .quorlyx-help-tip:before,
    #quorlyx-settings-page .quorlyx-help-tip:after,
    #quorlyx-content-insights-page .quorlyx-help-tip:before,
    #quorlyx-content-insights-page .quorlyx-help-tip:after {
        opacity: 0;
        pointer-events: none;
        position: absolute;
        transition: opacity 0.12s ease, transform 0.12s ease;
        visibility: hidden;
        z-index: 100001;
    }
    #quorlyx-settings-page .quorlyx-help-tip:after,
    #quorlyx-content-insights-page .quorlyx-help-tip:after {
        content: attr(data-tip);
        top: 24px;
        left: 50%;
        width: max-content;
        max-width: 300px;
        padding: 8px 10px;
        border-radius: 6px;
        background: #1f2937;
        box-shadow: 0 8px 24px rgba(15, 23, 42, 0.18);
        color: #fff;
        font-size: 12px;
        font-weight: 400;
        line-height: 1.4;
        text-align: left;
        transform: translate(-50%, -4px);
        white-space: normal;
    }
    #quorlyx-settings-page .quorlyx-help-tip:before,
    #quorlyx-content-insights-page .quorlyx-help-tip:before {
        content: "";
        top: 18px;
        left: 50%;
        border: 6px solid transparent;
        border-bottom-color: #1f2937;
        transform: translate(-50%, -4px);
    }
    #quorlyx-settings-page .quorlyx-help-tip:hover:before,
    #quorlyx-settings-page .quorlyx-help-tip:hover:after,
    #quorlyx-settings-page .quorlyx-help-tip:focus:before,
    #quorlyx-settings-page .quorlyx-help-tip:focus:after,
    #quorlyx-content-insights-page .quorlyx-help-tip:hover:before,
    #quorlyx-content-insights-page .quorlyx-help-tip:hover:after,
    #quorlyx-content-insights-page .quorlyx-help-tip:focus:before,
    #quorlyx-content-insights-page .quorlyx-help-tip:focus:after {
        opacity: 1;
        transform: translate(-50%, 0);
        visibility: visible;
    }
    body.quorlyx-help-popovers-enabled #quorlyx-settings-page .quorlyx-help-tip:before,
    body.quorlyx-help-popovers-enabled #quorlyx-settings-page .quorlyx-help-tip:after,
    body.quorlyx-help-popovers-enabled #quorlyx-content-insights-page .quorlyx-help-tip:before,
    body.quorlyx-help-popovers-enabled #quorlyx-content-insights-page .quorlyx-help-tip:after {
