    #quorlyx-settings-page label.switch {
        position: relative;
        display: inline-block;
        width: 52px;
        height: 28px;
        margin: 0;
        vertical-align: middle;
    }
    #quorlyx-settings-page label.switch input[type="checkbox"] {
        position: absolute !important;
        opacity: 0 !important;
        width: 100% !important;
        height: 100% !important;
        margin: 0 !important;
        inset: 0;
        cursor: pointer;
        z-index: 2;
    }
    #quorlyx-settings-page label.switch .slider {
        position: absolute;
        cursor: pointer;
        inset: 0;
        background-color: #c4c7c5;
        border-radius: 999px;
        transition: background-color 0.18s ease, box-shadow 0.18s ease;
        pointer-events: none;
        z-index: 1;
    }
    #quorlyx-settings-page label.switch .slider:before {
        content: "";
        position: absolute;
        width: 22px;
        height: 22px;
        left: 3px;
        bottom: 3px;
        background-color: #fff;
        border-radius: 50%;
        box-shadow: 0 1px 3px rgba(15, 23, 42, 0.2);
        transition: transform 0.18s ease;
    }
    #quorlyx-settings-page label.switch input[type="checkbox"]:checked ~ .slider {
        background-color: #22c55e;
    }
    #quorlyx-settings-page label.switch input[type="checkbox"]:checked ~ .slider:before {
        transform: translateX(24px);
    }
    #quorlyx-settings-page label.switch input[type="checkbox"]:focus-visible ~ .slider {
        box-shadow: 0 0 0 3px rgba(34, 197, 94, 0.24);
    }

    .quorlyx-repeater-item, .quorlyx-goal-item { display: flex; justify-content: space-between; align-items: center; padding: 10px; margin-bottom: 8px; border-radius: 8px; background: #f9f9f9; border: 1px solid #e0e0e0; transition: background-color 0.3s; }
