    .quorlyx-switch-toggle { position: relative; display: inline-block; width: 44px; height: 24px; flex-shrink: 0; }
    .quorlyx-switch-toggle input { opacity: 0; width: 0; height: 0; }
    .quorlyx-toggle-slider { position: absolute; cursor: pointer; top: 0; left: 0; right: 0; bottom: 0; background-color: #ccc; transition: .4s; border-radius: 24px; }
    .quorlyx-toggle-knob { position: absolute; content: ""; height: 18px; width: 18px; left: 3px; bottom: 3px; background-color: white; transition: .4s; border-radius: 50%; }
    .quorlyx-switch-toggle input:checked + .quorlyx-toggle-slider { background-color: #22c55e; }
    .quorlyx-switch-toggle input:not(:checked) + .quorlyx-toggle-slider { background-color: #ef4444; }
    .quorlyx-switch-toggle input:focus + .quorlyx-toggle-slider { box-shadow: 0 0 1px #22c55e; }
    .quorlyx-switch-toggle input:checked + .quorlyx-toggle-slider .quorlyx-toggle-knob { transform: translateX(20px); }
    .quorlyx-toggle-slider:after { content: "\2714"; font-size: 12px; color: white; position: absolute; top: 50%; left: 5px; transform: translateY(-50%); opacity: 0; transition: opacity 0.2s; }
    .quorlyx-toggle-slider:before { content: "\2716"; font-size: 12px; font-weight: bold; color: white; position: absolute; top: 50%; right: 5px; transform: translateY(-50%); opacity: 1; transition: opacity 0.2s; }
    .quorlyx-switch-toggle input:checked + .quorlyx-toggle-slider:after { opacity: 1; }
    .quorlyx-switch-toggle input:checked + .quorlyx-toggle-slider:before { opacity: 0; }

