	wp_add_inline_style( 'quorlyx-admin-css', $brand_css );

	if ( $is_quorlyx_page ) {

		wp_enqueue_style( 'shepherd-css', plugin_dir_url( __FILE__ ) . 'dist/vendor/shepherd/shepherd.css', array(), '11.2.0' );
		wp_add_inline_style(
			'shepherd-css',
			'.shepherd-modal-overlay-container{z-index:1000000 !important;}.shepherd-element{z-index:1000001 !important;}.quorlyx-shepherd-tour-modern .shepherd-header{position:relative;z-index:2;}'
		);
		wp_enqueue_script( 'shepherd-js', plugin_dir_url( __FILE__ ) . 'dist/vendor/shepherd/shepherd.min.js', array(), '11.2.0', true );

		wp_enqueue_script( 'quorlyx-tour', plugin_dir_url( __FILE__ ) . 'dist/tour.js', array( 'shepherd-js', 'jquery' ), $version, true );

		// phpcs:disable WordPress.Security.NonceVerification.Recommended -- Read-only routing context.
		$active_tab         = isset( $_GET['tab'] ) ? sanitize_key( wp_unslash( $_GET['tab'] ) ) : ( 'toplevel_page_quorlyx-dashboard' === $hook ? null : 'chatbot' );
		$current_admin_page = isset( $_GET['page'] ) ? sanitize_key( wp_unslash( $_GET['page'] ) ) : '';
		// phpcs:enable WordPress.Security.NonceVerification.Recommended

		$settings_url         = admin_url( 'admin.php?page=quorlyx-settings' );
		$tour_dashboard_url   = admin_url( 'admin.php?page=quorlyx-dashboard' );
		$content_insights_url = admin_url( 'admin.php?page=quorlyx-content-insights' );
		$tour_current_page    = 'settings';
		if ( 'toplevel_page_quorlyx-dashboard' === $hook ) {
			$tour_current_page = 'dashboard';
		} elseif ( 'quorlyx-content-insights' === $current_admin_page || false !== strpos( (string) $hook, 'quorlyx-content-insights' ) ) {
			$tour_current_page = 'content_insights';
		}
		wp_localize_script(
			'quorlyx-tour',
			'quorlyxTourData',
			array(
				'settings_url'             => $settings_url,
				'dashboard_url'            => $tour_dashboard_url,
				'content_insights_url'     => $content_insights_url,
				'tour_audio_base_url'      => plugin_dir_url( __FILE__ ) . 'assets/tour-audio/',
				'dashboard_url_start_tour' => add_query_arg( 'start_tour', 'true', $tour_dashboard_url ),
				'currentPage'              => $tour_current_page,
				'activeTab'                => $active_tab,
			)
		);
	}
}

add_action(
	'rest_api_init',
	function () {
		register_rest_route(
			'quorlyx/v1',
			'/ask-ai',
			array(
				'methods'             => 'POST',
				'callback'            => 'quorlyx_proxy_handler',
				'permission_callback' => 'quorlyx_verify_public_rest_request',
			)
		);
		register_rest_route(
			'quorlyx/v1',
			'/get-history',
			array(
				'methods'             => 'POST',
				'callback'            => 'quorlyx_get_history_handler',
				'permission_callback' => 'quorlyx_verify_public_rest_request',
			)
		);
		register_rest_route(
			'quorlyx/v1',
			'/track-view',
			array(
				'methods'             => 'POST',
				'callback'            => 'quorlyx_track_ab_view',
				'permission_callback' => 'quorlyx_verify_public_rest_request',
			)
		);
		register_rest_route(
			'quorlyx/v1',
			'/track-conversion',
			array(
				'methods'             => 'POST',
				'callback'            => 'quorlyx_track_ab_conversion',
				'permission_callback' => 'quorlyx_verify_public_rest_request',
			)
		);
		register_rest_route(
			'quorlyx/v1',
			'/track-action-click',
			array(
				'methods'             => 'POST',
				'callback'            => 'quorlyx_track_action_click',
				'permission_callback' => 'quorlyx_verify_public_rest_request',
			)
		);
		register_rest_route(
			'quorlyx/v1',
			'/generate-keywords',
			array(
				'methods'             => 'POST',
				'callback'            => 'quorlyx_rest_generate_keywords',
				'permission_callback' => function () {
					return quorlyx_current_user_can_manage();
				},
			)
		);
		register_rest_route(
			'quorlyx/v1',
			'/fetch-products',
			array(
				'methods'             => 'POST',
				'callback'            => 'quorlyx_rest_fetch_products',
				'permission_callback' => function () {
					return quorlyx_current_user_can_manage();
				},
			)
		);
		register_rest_route(
			'quorlyx/v1',
			'/generate-post-now',
			array(
				'methods'             => 'POST',
				'callback'            => 'quorlyx_rest_generate_post_now',
				'permission_callback' => function () {
					return quorlyx_current_user_can_manage();
				},
			)
		);
		register_rest_route(
			'quorlyx/v1',
			'/analyze-topic',
			array(
				'methods'             => 'POST',
				'callback'            => 'quorlyx_rest_analyze_topic',
				'permission_callback' => function () {
					return quorlyx_current_user_can_manage();
				},
			)
		);
		register_rest_route(
			'quorlyx/v1',
			'/generate-schema',
			array(
				'methods'             => 'POST',
				'callback'            => 'quorlyx_rest_generate_schema',
				'permission_callback' => function () {
					return current_user_can( 'edit_posts' );
				},
			)
		);
		register_rest_route(
			'quorlyx/v1',
			'/suggest-links',
			array(
				'methods'             => 'POST',
				'callback'            => 'quorlyx_rest_suggest_links',
				'permission_callback' => function () {
					return current_user_can( 'edit_posts' );
				},
			)
		);
		$seo_improvement_callback = 'quorlyx_rest_suggest_seo_improvements';
		if ( ! is_callable( $seo_improvement_callback ) ) {
			Quorlyx_Pro_Logger::log(
				'error',
				'SEO improvement REST route callback is not callable during registration',
				array(
					'route'    => '/suggest-seo-improvements',
					'callback' => $seo_improvement_callback,
				)
			);
		} else {
