/**
 * REST endpoint: search WooCommerce products for select fields.
 *
 * @param WP_REST_Request $request REST request.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_rest_search_products( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		return $nonce_ok;
	}

	$search_term = sanitize_text_field( $request->get_param( 'search' ) );
	$page_param  = $request->get_param( 'page' );
	$page        = absint( $page_param ? $page_param : 1 );

	$args = array(
		'post_type'      => 'product',
		'post_status'    => 'publish',
		'posts_per_page' => 20,
		's'              => $search_term,
		'paged'          => $page,
	);

	$query    = new WP_Query( $args );
	$products = array();
	if ( $query->have_posts() ) {
		while ( $query->have_posts() ) {
			$query->the_post();
			$products[] = array(
				'id'   => get_the_ID(),
				'text' => get_the_title(),
			);
		}
	}
	wp_reset_postdata();

	return new WP_REST_Response(
		array(
			'results' => $products,
			'more'    => $page < $query->max_num_pages,
		),
		200
	);
}

/**
 * REST endpoint: generate an AI proactive trigger message.
 *
 * @param WP_REST_Request $request REST request.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_rest_generate_trigger_message( WP_REST_Request $request ) {
	$token_ok = quorlyx_verify_public_chat_token( $request, 'chat' );
	if ( is_wp_error( $token_ok ) ) {
		return $token_ok;
	}

	$params        = $request->get_json_params();
	$trigger_id    = sanitize_text_field( $params['trigger_id'] ?? '' );
	$url           = esc_url_raw( $params['url'] ?? '' );
	$product_id    = absint( $params['product_id'] ?? 0 );
	$variation_key = sanitize_key( $params['variation'] ?? 'a' );
	$lang          = sanitize_text_field( $params['lang'] ?? get_locale() );
	$debug_mode    = quorlyx_current_user_can_manage();

	if ( ! $trigger_id ) {
		return new WP_Error( 'invalid_trigger', 'Missing trigger_id.', array( 'status' => 400 ) );
	}

	$defaults = quorlyx_get_global_defaults();
	$options  = get_option( 'quorlyx_options', $defaults );
	$options  = quorlyx_merge_global_options( $options );
	$triggers = quorlyx_normalize_trigger_ids( is_array( $options['triggers'] ?? null ) ? $options['triggers'] : array() );
	$trigger  = null;
	foreach ( $triggers as $t ) {
		if ( isset( $t['id'] ) && $t['id'] === $trigger_id ) {
			$trigger = $t;
			break; }
	}
	if ( ! $trigger || empty( $trigger['use_ai_message'] ) ) {
		return new WP_Error( 'ai_off', 'AI generation disabled for this trigger.', array( 'status' => 400 ) );
	}

	$variation = ( 'b' === $variation_key && ! empty( $options['ab_testing_enabled'] ) )
		? ( $options['variation_b'] ?? $options['variation_a'] )
		: $options['variation_a'];
	$variation = array_replace( quorlyx_get_variation_defaults(), is_array( $variation ) ? $variation : array() );
	if ( empty( $variation['chat_enabled'] ) ) {
		return new WP_Error( 'chat_disabled', 'Chat is currently disabled.', array( 'status' => 403 ) );
	}

	$allowed_providers = array( 'gemini', 'openai', 'anthropic', 'grok', 'mistral', 'deepseek' );
	$provider          = sanitize_key( $variation['ai_provider'] ?? 'gemini' );
	if ( ! in_array( $provider, $allowed_providers, true ) ) {
		$provider = 'gemini';
	}

	$model       = ! empty( $variation['ai_model'] ) ? sanitize_text_field( $variation['ai_model'] ) : '';
	$api_keys    = is_array( $variation['api_keys'] ?? null ) ? $variation['api_keys'] : array();
	$api_key_raw = $api_keys[ $provider ] ?? ( $variation['ai_api_key'] ?? '' );
	$api_key     = sanitize_text_field( $api_key_raw );
	$debug_info  = array(
		'trigger_id'     => $trigger_id,
		'variation'      => $variation_key,
		'provider'       => $provider,
		'model'          => $model,
		'has_model'      => ! empty( $model ),
		'has_api_key'    => ! empty( $api_key ),
		'product_id'     => $product_id,
		'has_url'        => ! empty( $url ),
		'cache_ttl_min'  => max( 0, absint( $trigger['ai_cache_ttl'] ?? 60 ) ),
		'is_admin_debug' => $debug_mode,
	);
	$perf        = is_array( $options['performance'] ?? null ) ? array_replace( $defaults['performance'], $options['performance'] ) : $defaults['performance'];
	$temperature = isset( $trigger['ai_temperature'] ) ? floatval( $trigger['ai_temperature'] ) : 0.5;
	$max_tokens  = absint( $trigger['ai_max_tokens'] ?? 120 );
	$cache_ttl   = max( 0, absint( $trigger['ai_cache_ttl'] ?? 60 ) );
	$persona     = trim( (string) ( $trigger['ai_persona'] ?? 'You are a helpful, concise product assistant. Keep messages under 45 words.' ) );

	$persistent_user_id = quorlyx_get_persistent_user_id( $request );
	if ( ! $persistent_user_id ) {
		$remote_addr = '';
		if ( isset( $_SERVER['REMOTE_ADDR'] ) ) {
			$remote_addr = sanitize_text_field( wp_unslash( $_SERVER['REMOTE_ADDR'] ) );
		}
		$persistent_user_id = 'guest_' . substr( hash( 'sha256', (string) $remote_addr ), 0, 12 );
	}
	$rate_limit_identity = quorlyx_get_rate_limit_identity( $request, 'gen_trigger' );
	$trigger_limit       = max( 1, absint( $perf['rate_limit_requests'] ?? QUORLYX_RATE_LIMIT_REQUESTS ) );
	$trigger_window      = max( 60, absint( $perf['rate_limit_window'] ?? QUORLYX_RATE_LIMIT_WINDOW ) );
	$trigger_burst_limit = max( 1, min( $trigger_limit, 5, (int) ceil( $trigger_limit / 3 ) ) );
	if ( quorlyx_rate_limited( $rate_limit_identity, 'gen_trigger_burst', $trigger_burst_limit, MINUTE_IN_SECONDS ) ) {
		return new WP_Error( 'rate_limit_exceeded', 'Please slow down.', array( 'status' => 429 ) );
	}
	if ( quorlyx_rate_limited( $rate_limit_identity, 'gen_trigger', $trigger_limit, $trigger_window ) ) {
		return new WP_Error( 'rate_limit_exceeded', 'Please slow down.', array( 'status' => 429 ) );
	}

	$format_mode       = sanitize_key( (string) ( $trigger['ai_format_mode'] ?? 'free_ai' ) );
	$valid_modes       = array( 'free_ai', 'template_locked', 'hybrid_required_tokens' );
	$format_mode       = in_array( $format_mode, $valid_modes, true ) ? $format_mode : 'free_ai';
	$message_template  = trim( (string) ( $trigger['ai_message_template'] ?? '' ) );
	$missing_policy    = sanitize_key( (string) ( $trigger['ai_missing_placeholder_policy'] ?? 'use_fallback_message' ) );
	$missing_policy    = in_array( $missing_policy, array( 'hide', 'fallback_text', 'use_fallback_message' ), true ) ? $missing_policy : 'use_fallback_message';
	$template_max_words = max( 5, min( 120, absint( $trigger['ai_template_max_words'] ?? 45 ) ) );
	$placeholder_context = quorlyx_build_trigger_ai_message_context(
		$trigger,
		array(
			'url'        => $url,
			'product_id' => $product_id,
			'lang'       => $lang,
			'referrer'   => $params['referrer'] ?? '',
		)
	);
	$default_button_url  = ! empty( $placeholder_context['button_url'] ) ? $placeholder_context['button_url'] : ( $url ? $url : home_url( '/' ) );
	$page_source         = $url ? $url : (string) home_url( add_query_arg( array() ) );
	$page_hash           = substr( md5( $page_source ), 0, 12 );
	$template_key_parts  = array(
		$format_mode,
		$message_template,
		(string) ( $trigger['ai_required_placeholders'] ?? '' ),
		(string) ( $trigger['ai_slot_instructions'] ?? '' ),
		$persona,
		$missing_policy,
		(string) $template_max_words,
		$provider,
		$model,
		empty( $api_key ) ? 'no_key' : 'has_key',
	);
	$template_hash       = substr( md5( implode( '|', $template_key_parts ) ), 0, 12 );
	$context_hash        = substr( md5( (string) wp_json_encode( $placeholder_context ) ), 0, 12 );
	$cache_key           = 'quorlyx_trigger_v3_' . $trigger_id . 'page' . $page_hash . 'ctx' . $context_hash . 'tpl' . $template_hash . 'lang' . strtolower( $lang ) . 'var' . $variation_key;
	$cached              = get_transient( $cache_key );
	$debug_info['render_mode'] = $format_mode;
	if ( false !== $cached ) {
		$payload = array(
			'message'     => $cached['message'],
			'cache_hit'   => true,
			'provider'    => $cached['provider'] ?? '',
			'time_ms'     => 0,
			'render_mode' => $cached['render_mode'] ?? $format_mode,
			'chatToken'   => quorlyx_create_public_chat_token( 'chat' ),
		);
		if ( $debug_mode ) {
			$payload['debug'] = $debug_info;
		}
		return new WP_REST_Response(
			$payload,
			200
		);
	}

	$site_context         = '';
	$fake_question        = 'Generate a short proactive tip for the current page to encourage engagement.';
	$trigger_context_perf = $perf;
	$trigger_context_perf['tool_calling_products_enabled'] = false;
	$site_context         = quorlyx_pro_collect_site_context( $variation, $fake_question, $trigger_context_perf );
	$page_title           = $placeholder_context['page_title'] ?? '';
	$context_for_prompt   = wp_json_encode(
		array_filter(
			$placeholder_context,
			function ( $value ) {
				return '' !== trim( (string) $value );
			}
		),
		JSON_UNESCAPED_SLASHES
	);
	$ctx_block            = "CONTEXT:\nTitle: {$page_title}\nURL: {$url}\nTemplate context JSON: {$context_for_prompt}\n" . ( $site_context ? ( "\n" . $site_context ) : '' );
	$rules                = "Output format: Plain text with at most one button encoded as [BUTTON: Label](https://url). Never output bare BUTTON: text without a URL. No HTML. Max {$max_tokens} tokens or ~45 words.";
	$elapsed              = 0;
	$message              = '';
	$used_fallback        = false;

	if ( 'template_locked' === $format_mode && '' !== $message_template ) {
		$template_placeholders = quorlyx_extract_ai_message_placeholders( $message_template );
		$slot_registry         = quorlyx_get_ai_message_slot_registry();
		$slot_names            = array_values(
			array_filter(
				$template_placeholders,
				function ( $placeholder ) use ( $slot_registry ) {
					return ! empty( $slot_registry[ $placeholder ] );
				}
			)
		);
		$slot_values           = array();

		if ( ! empty( $slot_names ) ) {
			if ( empty( $api_key ) || empty( $model ) ) {
				$message       = quorlyx_get_trigger_ai_message_fallback( $trigger, $placeholder_context, $default_button_url );
				$used_fallback = true;
			} else {
				$t0         = microtime( true );
				$slot_values = quorlyx_generate_ai_message_slots( $provider, $api_key, $model, $persona, $placeholder_context, $slot_names, (string) ( $trigger['ai_slot_instructions'] ?? '' ), $site_context, $temperature );
				$elapsed    = (int) round( ( microtime( true ) - $t0 ) * 1000 );
				if ( is_wp_error( $slot_values ) ) {
					$debug_info['api_error'] = $slot_values->get_error_code();
					$message                 = quorlyx_get_trigger_ai_message_fallback( $trigger, $placeholder_context, $default_button_url );
					$used_fallback           = true;
					$slot_values             = array();
				}
			}
		}

		if ( ! $used_fallback ) {
			$rendered   = quorlyx_render_ai_message_template_text(
				$message_template,
				$placeholder_context,
				$slot_values,
				array(
					'missing_policy'        => $missing_policy,
					'missing_fallback_text' => 'this page',
				)
			);
			$message    = quorlyx_sanitize_ai_output( $rendered['message'], $default_button_url );
			$validation = quorlyx_validate_ai_message_template_output( $message, $rendered, $template_max_words, $missing_policy );

			if ( empty( $validation['valid'] ) && ! empty( $slot_names ) && ! empty( $api_key ) && ! empty( $model ) ) {
				$t0          = microtime( true );
				$slot_values = quorlyx_generate_ai_message_slots( $provider, $api_key, $model, $persona, $placeholder_context, $slot_names, (string) ( $trigger['ai_slot_instructions'] ?? '' ), $site_context, $temperature, 'Previous render failed validation: ' . implode( ', ', (array) $validation['errors'] ) . '. Make every slot shorter and safer.' );
				$elapsed    += (int) round( ( microtime( true ) - $t0 ) * 1000 );
				if ( ! is_wp_error( $slot_values ) ) {
					$rendered   = quorlyx_render_ai_message_template_text(
						$message_template,
						$placeholder_context,
						$slot_values,
						array(
							'missing_policy'        => $missing_policy,
							'missing_fallback_text' => 'this page',
						)
					);
					$message    = quorlyx_sanitize_ai_output( $rendered['message'], $default_button_url );
					$validation = quorlyx_validate_ai_message_template_output( $message, $rendered, $template_max_words, $missing_policy );
				}
			}

			if ( empty( $validation['valid'] ) ) {
				$debug_info['template_validation_errors'] = $validation['errors'] ?? array();
				$message                                 = quorlyx_get_trigger_ai_message_fallback( $trigger, $placeholder_context, $default_button_url );
				$used_fallback                           = true;
			}
		}
	} else {
		if ( empty( $api_key ) || empty( $model ) ) {
			return new WP_Error(
				'no_provider',
				'AI model not configured.',
				array(
					'status' => 400,
					'debug'  => $debug_mode ? $debug_info : null,
				)
			);
		}

		$required_context_lines = array();
		if ( 'hybrid_required_tokens' === $format_mode ) {
			foreach ( quorlyx_parse_ai_message_placeholder_list( (string) ( $trigger['ai_required_placeholders'] ?? '' ) ) as $required_placeholder ) {
				$value = trim( (string) ( $placeholder_context[ $required_placeholder ] ?? '' ) );
				if ( '' !== $value ) {
					$required_context_lines[] = $required_placeholder . ': ' . $value;
				}
			}
			if ( ! empty( $required_context_lines ) ) {
				$rules .= "\nHybrid required values: include these exact resolved context values when natural:\n- " . implode( "\n- ", $required_context_lines );
			}
		}

		$system_prompt = $persona . "\n\n" . $ctx_block . "\n\n" . $rules;
		$history       = array(
			array(
				'role'  => 'user',
				'parts' => array(
					array(
						'text' => 'Create the proactive message now.',
					),
				),
			),
		);
		$t0            = microtime( true );
		$resp          = quorlyx_call_ai_api_with_retry( $provider, $api_key, $model, $system_prompt, $history, $temperature );
		$elapsed       = (int) round( ( microtime( true ) - $t0 ) * 1000 );
		if ( is_wp_error( $resp ) ) {
			$fallback = quorlyx_get_trigger_ai_message_fallback( $trigger, $placeholder_context, $default_button_url );
			$payload  = array(
				'message'     => $fallback,
				'cache_hit'   => false,
				'provider'    => $provider,
				'time_ms'     => $elapsed,
				'fallback'    => true,
				'render_mode' => $format_mode,
			);
			if ( $debug_mode ) {
				$debug_info['api_error'] = $resp->get_error_code();
				$payload['debug']        = $debug_info;
			}
			return new WP_REST_Response(
				$payload,
				200
			);
		}
		$message = quorlyx_sanitize_ai_output( $resp, $default_button_url );

		if ( 'hybrid_required_tokens' === $format_mode && ! empty( $required_context_lines ) ) {
			$missing_required_values = array();
			foreach ( quorlyx_parse_ai_message_placeholder_list( (string) ( $trigger['ai_required_placeholders'] ?? '' ) ) as $required_placeholder ) {
				$value = trim( (string) ( $placeholder_context[ $required_placeholder ] ?? '' ) );
				if ( '' !== $value && false === stripos( wp_strip_all_tags( $message ), $value ) ) {
					$missing_required_values[] = $required_placeholder;
				}
			}
			if ( ! empty( $missing_required_values ) ) {
				$debug_info['missing_required_placeholders'] = $missing_required_values;
				$message                                    = quorlyx_get_trigger_ai_message_fallback( $trigger, $placeholder_context, $default_button_url );
				$used_fallback                              = true;
			}
		}
	}

	$message = preg_replace_callback(
		'/\[(BUTTON|SEARCH):[^\]]+\]\(([^)]+)\)/',
		function ( $m ) {
			$u  = $m[2];
			$nu = add_query_arg( 'quorlyx_ref', 'true', $u );
			return str_replace( $u, $nu, $m[0] );
		},
		$message
	);

	if ( $cache_ttl > 0 ) {
		set_transient(
			$cache_key,
			array(
				'message'     => $message,
				'provider'    => $provider,
				'render_mode' => $format_mode,
			),
			$cache_ttl * MINUTE_IN_SECONDS
		);
	}

	if ( ! empty( $trigger['ai_audit_save'] ) ) {
		try {
			$conv_id = quorlyx_find_recent_conversation_post_id( $persistent_user_id, '' );
			if ( ! $conv_id ) {
				$q = new WP_Query(
					array(
						'post_type'              => 'quorlyx_conversation',
						'post_status'            => 'private',
						'posts_per_page'         => 1,
						'orderby'                => 'date',
						'order'                  => 'DESC',
						'fields'                 => 'ids',
						'no_found_rows'          => true,
						'update_post_meta_cache' => false,
						'update_post_term_cache' => false,
						// phpcs:ignore WordPress.DB.SlowDBQuery.slow_db_query_meta_query -- Legacy fallback for installs before the custom conversation table exists.
						'meta_query'             => array(
							array(
								'key'   => 'quorlyx_persistent_user_id',
								'value' => $persistent_user_id,
							),
						),
					)
				);
				if ( ! empty( $q->posts[0] ) ) {
					$conv_id = (int) $q->posts[0];
				}
			}
			if ( ! $conv_id ) {
				$conv_id = wp_insert_post(
					array(
						'post_type'   => 'quorlyx_conversation',
						'post_title'  => 'Proactive Message ' . current_time( 'mysql' ),
						'post_status' => 'private',
					)
				);
				if ( $conv_id && ! is_wp_error( $conv_id ) ) {
					update_post_meta( $conv_id, 'quorlyx_persistent_user_id', $persistent_user_id );
					update_post_meta( $conv_id, 'quorlyx_ab_variation', $variation_key );
					update_post_meta( $conv_id, 'quorlyx_message_count', 0 );
					update_post_meta( $conv_id, 'quorlyx_source', 'trigger' );
				}
			}
			if ( $conv_id && ! is_wp_error( $conv_id ) ) {
				quorlyx_upsert_conversation_record(
					$conv_id,
					array(
						'persistent_user_id' => $persistent_user_id,
						'variation'          => $variation_key,
						'source'             => 'trigger',
						'trigger_id'         => sanitize_key( (string) ( $trigger['id'] ?? '' ) ),
						'trigger_name'       => sanitize_text_field( (string) ( $trigger['name'] ?? '' ) ),
						'trigger_type'       => sanitize_key( (string) ( $trigger['type'] ?? '' ) ),
					)
				);
				$hist   = quorlyx_get_conversation_history( $conv_id );
				$hist[] = array(
					'role'  => 'model',
					'parts' => array( array( 'text' => $message ) ),
				);
				$hist   = quorlyx_truncate_history( $hist );
				quorlyx_store_conversation_history( $conv_id, $hist );
			}
		} catch ( Exception $e ) {
			// Ignore message persistence errors to avoid blocking the response.
			unset( $e );
		}
	}

	$payload = array(
		'message'     => $message,
		'cache_hit'   => false,
		'provider'    => $provider,
		'time_ms'     => $elapsed,
		'fallback'    => $used_fallback,
		'render_mode' => $format_mode,
		'chatToken'   => quorlyx_create_public_chat_token( 'chat' ),
	);
	if ( $debug_mode ) {
		$payload['debug'] = $debug_info;
	}

	return new WP_REST_Response( $payload, 200 );
}

/**
 * REST endpoint: reset selected dashboard and analytics data.
 *
 * @param WP_REST_Request $request REST request.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_rest_reset_data( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		return $nonce_ok;
	}

	$params = $request->get_json_params();
	$params = is_array( $params ) ? $params : array();

	if ( ! empty( $params['delete_all_plugin_data'] ) ) {
		if ( 'RESET' !== (string) ( $params['confirmation'] ?? '' ) ) {
			return new WP_Error( 'quorlyx_reset_confirmation_required', 'Type RESET to confirm deleting all Quorlyx plugin data.', array( 'status' => 400 ) );
		}

		$result = quorlyx_delete_all_plugin_data();

		return new WP_REST_Response(
			array(
				'success' => true,
				'message' => sprintf(
					'All Quorlyx plugin data has been deleted (%d tables dropped, %d private records removed).',
					(int) ( $result['tables'] ?? 0 ),
					(int) ( $result['posts'] ?? 0 )
				),
				'deleted' => $result,
			),
			200
		);
	}

	if ( array_key_exists( 'delete_data_on_uninstall_state', $params ) ) {
		update_option( 'quorlyx_delete_data_on_uninstall', '1' === (string) $params['delete_data_on_uninstall_state'], false );
	}

	if ( ! empty( $params['reset_ab_stats'] ) ) {
		update_option(
			'quorlyx_ab_stats',
			array(
				'a' => array(
					'views'       => 0,
					'conversions' => 0,
				),
				'b' => array(
					'views'       => 0,
					'conversions' => 0,
				),
			)
		);
	}
	if ( ! empty( $params['reset_goal_counters'] ) ) {
		delete_option( 'quorlyx_conversion_goal_stats' );
	}
	if ( ! empty( $params['reset_action_counters'] ) ) {
		delete_option( 'quorlyx_action_click_stats' );
	}
	if ( ! empty( $params['reset_trigger_analytics'] ) ) {
		quorlyx_reset_trigger_analytics_data();
	}
	$content_insights_reset = false;
	if ( ! empty( $params['reset_product_insights'] ) ) {
		quorlyx_reset_content_insight_post_metrics_by_type( array( 'product', 'product_variation' ) );
		$content_insights_reset = true;
	}
	if ( ! empty( $params['reset_content_insights'] ) ) {
		$content_post_types = array_values(
			array_diff(
				array_keys( quorlyx_get_content_insights_post_types() ),
				array( 'product', 'product_variation' )
			)
		);

		quorlyx_reset_content_insight_post_metrics_by_type( $content_post_types );
		quorlyx_reset_virtual_content_insight_metrics();
		$content_insights_reset = true;
	}
	if ( $content_insights_reset ) {
		quorlyx_touch_content_analytics_updated_at();
	}
	if ( ! empty( $params['reset_behavior_patterns'] ) ) {
		global $wpdb;
		$table_name = quorlyx_get_behavior_engine_table_name();

		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Explicit admin reset operation for behavior pattern data.
		// phpcs:disable WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Table name comes from trusted helper with wpdb prefix.
		$wpdb->query( "DELETE FROM {$table_name}" );
		// phpcs:enable WordPress.DB.PreparedSQL.InterpolatedNotPrepared

		delete_option( 'quorlyx_behavior_engine_last_prune' );
		quorlyx_touch_content_analytics_updated_at();
	}
	if ( ! empty( $params['delete_conversations'] ) ) {
		global $wpdb;
		if ( quorlyx_conversation_messages_table_exists() ) {
			$messages_table = quorlyx_get_conversation_messages_table_name();
			// phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Explicit destructive reset of plugin-owned table.
			$wpdb->query( "DELETE FROM {$messages_table}" );
		}
		if ( quorlyx_conversations_table_exists() ) {
			$conversations_table = quorlyx_get_conversations_table_name();
			// phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Explicit destructive reset of plugin-owned table.
			$wpdb->query( "DELETE FROM {$conversations_table}" );
		}

		do {
			$query = new WP_Query(
				array(
					'post_type'              => 'quorlyx_conversation',
					'posts_per_page'         => 500,
					'fields'                 => 'ids',
					'no_found_rows'          => true,
					'update_post_meta_cache' => false,
					'update_post_term_cache' => false,
				)
			);
			foreach ( $query->posts as $post_id ) {
				wp_delete_post( $post_id, true ); // true to force delete.
			}
			$has_more = 500 === count( $query->posts );
			wp_reset_postdata();
		} while ( $has_more );

		update_option(
			'quorlyx_conversation_stats',
			array(
				'a' => array(
					'total'        => 0,
					'avg_messages' => 0,
				),
				'b' => array(
					'total'        => 0,
					'avg_messages' => 0,
				),
			),
			false
		);
	}

	quorlyx_calculate_conversation_stats();

	return new WP_REST_Response(
		array(
			'success' => true,
			'message' => 'Selected data has been reset.',
		),
		200
	);
}

/**
 * Validate REST nonce header or fallback nonce field.
 *
 * @param WP_REST_Request $request REST request.
 * @return true|WP_Error
 */
function quorlyx_verify_rest_nonce( WP_REST_Request $request ) {
	$nonce = $request->get_header( 'X-WP-Nonce' );
	if ( ! $nonce ) {
		$nonce = $request->get_param( '_wpnonce' );
	}
	if ( ! $nonce || ! wp_verify_nonce( $nonce, 'wp_rest' ) ) {
		return new WP_Error(
			'invalid_nonce',
			'Security check failed. Please refresh and try again.',
			array( 'status' => 403 )
		);
	}
	return true;
}

/**
 * Validate public REST requests with the normal nonce plus same-origin headers.
 *
 * @param WP_REST_Request $request REST request.
 * @return true|WP_Error
 */
function quorlyx_verify_public_rest_request( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		return $nonce_ok;
	}

	if ( ! quorlyx_public_rest_request_has_same_origin( $request ) ) {
		return new WP_Error(
			'invalid_origin',
			'Security check failed. Please refresh and try again.',
			array( 'status' => 403 )
		);
	}

	return true;
}

/**
 * Check Origin/Referer when browsers provide them for public endpoints.
 *
 * @param WP_REST_Request $request REST request.
 * @return bool
 */
function quorlyx_public_rest_request_has_same_origin( WP_REST_Request $request ) {
	$site_host = wp_parse_url( home_url(), PHP_URL_HOST );
	$site_host = is_string( $site_host ) ? strtolower( $site_host ) : '';
	if ( '' === $site_host ) {
		return true;
	}

	$headers_to_check = array(
		$request->get_header( 'origin' ),
		$request->get_header( 'referer' ),
	);
	$has_origin_header = false;

	foreach ( $headers_to_check as $header_value ) {
		$header_value = is_string( $header_value ) ? trim( $header_value ) : '';
		if ( '' === $header_value ) {
			continue;
		}

		$has_origin_header = true;
		$request_host      = wp_parse_url( $header_value, PHP_URL_HOST );
		$request_host      = is_string( $request_host ) ? strtolower( $request_host ) : '';
		if ( $request_host === $site_host ) {
			return true;
		}
	}

	return ! $has_origin_header;
}

/**
 * Encode a string using URL-safe base64.
 *
 * @param string $data Raw data.
 * @return string
 */
function quorlyx_base64url_encode( $data ) {
	return rtrim( strtr( base64_encode( (string) $data ), '+/', '-_' ), '=' );
}

/**
 * Decode a URL-safe base64 string.
 *
 * @param string $data Encoded data.
 * @return string|false
 */
function quorlyx_base64url_decode( $data ) {
	$data      = strtr( (string) $data, '-_', '+/' );
	$remainder = strlen( $data ) % 4;
	if ( $remainder ) {
		$data .= str_repeat( '=', 4 - $remainder );
	}

	return base64_decode( $data, true );
}

/**
 * Secret used to sign public chat tokens.
 *
 * @return string
 */
function quorlyx_get_public_chat_token_secret() {
	return wp_salt( 'auth' ) . '|' . wp_salt( 'secure_auth' ) . '|' . home_url( '/' );
}

/**
 * Create a short-lived token for public chat/trigger AI requests.
 *
 * @param string $scope Token scope.
 * @return string
 */
function quorlyx_create_public_chat_token( $scope = 'chat' ) {
	$scope = sanitize_key( (string) $scope );
	if ( '' === $scope ) {
		$scope = 'chat';
	}

	$now = time();
	$ttl = max( 300, absint( apply_filters( 'quorlyx_public_chat_token_ttl', QUORLYX_PUBLIC_CHAT_TOKEN_TTL, $scope ) ) );

	$payload = array(
		'v'     => 1,
		'scope' => $scope,
		'site'  => hash( 'sha256', home_url( '/' ) ),
		'iat'   => $now,
		'exp'   => $now + $ttl,
	);

	$json = wp_json_encode( $payload );
	if ( ! is_string( $json ) || '' === $json ) {
		return '';
	}

	$encoded   = quorlyx_base64url_encode( $json );
	$signature = hash_hmac( 'sha256', $encoded, quorlyx_get_public_chat_token_secret(), true );

	return $encoded . '.' . quorlyx_base64url_encode( $signature );
}

/**
 * Verify the public chat token supplied with AI requests.
 *
 * @param WP_REST_Request $request REST request.
 * @param string          $scope Expected token scope.
 * @return true|WP_Error
 */
function quorlyx_verify_public_chat_token( WP_REST_Request $request, $scope = 'chat' ) {
	$scope = sanitize_key( (string) $scope );
	if ( '' === $scope ) {
		$scope = 'chat';
	}

	$token = $request->get_header( 'X-Quorlyx-Chat-Token' );
	if ( ! $token ) {
		$token = $request->get_param( 'chatToken' );
	}
	$token = is_string( $token ) ? trim( $token ) : '';
	if ( '' === $token || strlen( $token ) > 2048 ) {
		return new WP_Error( 'invalid_chat_token', 'Security check failed. Please refresh and try again.', array( 'status' => 403 ) );
	}

	$parts = explode( '.', $token );
	if ( 2 !== count( $parts ) ) {
		return new WP_Error( 'invalid_chat_token', 'Security check failed. Please refresh and try again.', array( 'status' => 403 ) );
	}

	list( $encoded_payload, $encoded_signature ) = $parts;
	$expected_signature = quorlyx_base64url_encode( hash_hmac( 'sha256', $encoded_payload, quorlyx_get_public_chat_token_secret(), true ) );
	if ( ! hash_equals( $expected_signature, $encoded_signature ) ) {
		return new WP_Error( 'invalid_chat_token', 'Security check failed. Please refresh and try again.', array( 'status' => 403 ) );
	}

	$decoded = quorlyx_base64url_decode( $encoded_payload );
	if ( ! is_string( $decoded ) || '' === $decoded ) {
		return new WP_Error( 'invalid_chat_token', 'Security check failed. Please refresh and try again.', array( 'status' => 403 ) );
	}

	$payload = json_decode( $decoded, true );
	if ( ! is_array( $payload ) ) {
		return new WP_Error( 'invalid_chat_token', 'Security check failed. Please refresh and try again.', array( 'status' => 403 ) );
	}

	$now = time();
	if (
		$scope !== sanitize_key( (string) ( $payload['scope'] ?? '' ) )
		|| hash( 'sha256', home_url( '/' ) ) !== (string) ( $payload['site'] ?? '' )
		|| absint( $payload['exp'] ?? 0 ) < $now
		|| absint( $payload['iat'] ?? 0 ) > ( $now + 300 )
	) {
		return new WP_Error( 'invalid_chat_token', 'Security check failed. Please refresh and try again.', array( 'status' => 403 ) );
	}

	return true;
}

/**
 * Normalize a public chat request body and enforce size/message budgets.
 *
 * @param WP_REST_Request $request REST request.
 * @return array<string,mixed>|WP_Error
 */
function quorlyx_get_public_chat_request_payload( WP_REST_Request $request ) {
	$raw_body = (string) $request->get_body();
	$max_body = max( 1024, absint( apply_filters( 'quorlyx_public_chat_max_body_bytes', QUORLYX_PUBLIC_CHAT_MAX_BODY_BYTES ) ) );
	if ( strlen( $raw_body ) > $max_body ) {
		return new WP_Error( 'payload_too_large', 'Message is too large. Please shorten it and try again.', array( 'status' => 413 ) );
	}

	$body = json_decode( $raw_body, true );
	if ( ! is_array( $body ) ) {
		return new WP_Error( 'invalid_payload', 'Invalid chat request.', array( 'status' => 400 ) );
	}

	$raw_text = $body['contents'][0]['parts'][0]['text'] ?? '';
	$raw_text = is_scalar( $raw_text ) ? (string) $raw_text : '';
	$text     = trim( sanitize_textarea_field( $raw_text ) );
	$max_chars = max( 100, absint( apply_filters( 'quorlyx_public_chat_max_message_chars', QUORLYX_PUBLIC_CHAT_MAX_MESSAGE_CHARS ) ) );
	$text_len  = function_exists( 'mb_strlen' ) ? mb_strlen( $text ) : strlen( $text );

	if ( '' === $text ) {
		return new WP_Error( 'empty_message', 'Please enter a message.', array( 'status' => 400 ) );
	}
	if ( $text_len > $max_chars ) {
		return new WP_Error( 'message_too_long', 'Message is too long. Please shorten it and try again.', array( 'status' => 413 ) );
	}

	$body['contents'] = array(
		array(
			'role'  => 'user',
			'parts' => array(
				array(
					'text' => $text,
				),
			),
		),
	);

	return array(
		'body'    => $body,
		'message' => $body['contents'][0],
		'text'    => $text,
	);
}

/**
 * Derive a daily chat quota from the admin-controlled per-window quota.
 *
 * @param int $limit Admin configured request limit.
 * @param int $window_seconds Admin configured window.
 * @return int
 */
function quorlyx_get_public_chat_daily_limit( $limit, $window_seconds ) {
	$limit          = max( 1, absint( $limit ) );
	$window_seconds = max( 60, absint( $window_seconds ) );
	$natural_cap    = max( $limit, (int) ceil( $limit * DAY_IN_SECONDS / $window_seconds ) );
	$aggressive_cap = max( $limit, $limit * 6 );

	return max( 1, min( $natural_cap, $aggressive_cap ) );
}

/**
 * Resolve persistent user ID for REST chat/session requests.
 *
 * @param WP_REST_Request $request REST request.
 * @return string|null
 */
function quorlyx_get_persistent_user_id( WP_REST_Request $request ) {
	$user_id = get_current_user_id();
	if ( $user_id ) {
		return 'wp_user_' . $user_id;
	}
	$params   = $request->get_json_params();
	$guest_id = sanitize_text_field( $params['persistentUserId'] ?? '' );
	if ( $guest_id && 0 === strpos( $guest_id, 'guest_' ) ) {
		return $guest_id;
	}
	return null;
}

/**
 * Build a stable server-side identity for public endpoint rate limits.
 *
 * The frontend guest ID remains useful for chat history, but it is client
 * controlled. Rate limiting must use server-observed request traits so a
 * visitor cannot bypass quotas by rotating local storage.
 *
 * @param WP_REST_Request $request REST request.
 * @param string          $bucket  Rate limit bucket.
 * @return string
 */
function quorlyx_get_rate_limit_identity( WP_REST_Request $request, $bucket = 'public' ) {
	$user_id = get_current_user_id();
	if ( $user_id ) {
		return 'wp_user_' . $user_id;
	}

	$remote_addr = '';
	if ( isset( $_SERVER['REMOTE_ADDR'] ) ) {
		$remote_addr = sanitize_text_field( wp_unslash( $_SERVER['REMOTE_ADDR'] ) );
	}
	$remote_addr = (string) apply_filters( 'quorlyx_rate_limit_remote_addr', $remote_addr, $request );
	$remote_addr = sanitize_text_field( $remote_addr );

	$user_agent = $request->get_header( 'user-agent' );
	if ( ! $user_agent && isset( $_SERVER['HTTP_USER_AGENT'] ) ) {
		$user_agent = sanitize_text_field( wp_unslash( $_SERVER['HTTP_USER_AGENT'] ) );
	}
	$user_agent = substr( sanitize_text_field( (string) $user_agent ), 0, 255 );

	$fingerprint = array(
		'bucket' => sanitize_key( (string) $bucket ),
		'site'   => home_url( '/' ),
		'ip'     => $remote_addr,
		'ua'     => $user_agent,
	);

	$encoded = wp_json_encode( $fingerprint );
	if ( ! is_string( $encoded ) || '' === $encoded ) {
		$encoded = implode( '|', array_map( 'strval', $fingerprint ) );
	}

	return 'public_' . hash( 'sha256', $encoded );
}

/**
 * REST endpoint: fetch most recent conversation history for a user.
 *
 * @param WP_REST_Request $request REST request.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_get_history_handler( WP_REST_Request $request ) {

	$persistent_user_id = quorlyx_get_persistent_user_id( $request );
	$response           = array(
		'history'          => null,
		'persistentUserId' => $persistent_user_id,
	);

	if ( ! $persistent_user_id ) {
		$response['persistentUserId'] = 'guest_' . wp_generate_password( 24, false );
		return new WP_REST_Response( $response, 200 );
	}

	global $wpdb;
	$recent_threshold     = time() - DAY_IN_SECONDS;
	$conversation_post_id = quorlyx_find_recent_conversation_post_id( $persistent_user_id, '' );
	if ( ! $conversation_post_id ) {
		$conversation_post_id = $wpdb->get_var(
			$wpdb->prepare(
				"SELECT p.ID FROM {$wpdb->posts} p
				INNER JOIN {$wpdb->postmeta} pm_user ON p.ID = pm_user.post_id AND pm_user.meta_key = 'quorlyx_persistent_user_id'
				INNER JOIN {$wpdb->postmeta} pm_last ON p.ID = pm_last.post_id AND pm_last.meta_key = 'quorlyx_last_activity'
				WHERE p.post_type = 'quorlyx_conversation'
				AND p.post_status = 'private'
				AND pm_user.meta_value = %s
				AND CAST(pm_last.meta_value AS UNSIGNED) > %d
				ORDER BY p.post_date DESC
				LIMIT 1",
				$persistent_user_id,
				$recent_threshold
			)
		);
	}

	if ( $conversation_post_id ) {
		$history             = quorlyx_get_conversation_history( $conversation_post_id );
		$response['history'] = is_array( $history ) ? $history : null;
	}

	return new WP_REST_Response( $response, 200 );
}

/**
 * REST endpoint: clear plugin runtime logs.
 *
 * @param WP_REST_Request $request REST request.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_rest_clear_logs( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		return $nonce_ok;
	}

	Quorlyx_Pro_Logger::clear_logs();

	return new WP_REST_Response(
		array(
			'success' => true,
			'message' => 'Logs cleared successfully.',
		),
		200
	);
}

/**
 * REST endpoint: fetch provider model lists for admin selects.
 *
 * @param WP_REST_Request $request REST request.
 * @return WP_REST_Response|WP_Error
 * @throws Exception When provider model fetching fails.
 */
function quorlyx_rest_fetch_models( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		return $nonce_ok;
	}

	$params   = $request->get_json_params();
	$provider = sanitize_key( $params['provider'] ?? '' );
	$api_key  = sanitize_text_field( $params['api_key'] ?? '' );
	$mode     = sanitize_key( $params['mode'] ?? ( $params['type'] ?? 'chat' ) );

	if ( empty( $provider ) || empty( $api_key ) ) {
		return new WP_Error( 'missing_params', 'Provider and API key are required.', array( 'status' => 400 ) );
	}

	$models   = array();
	$fallback = false;

	try {
		switch ( $provider ) {
			case 'openai':
				$response = wp_remote_get(
					'https://api.openai.com/v1/models',
					array(
						'headers' => array(
							'Authorization' => 'Bearer ' . $api_key,
						),
						'timeout' => QUORLYX_API_TIMEOUT,
					)
				);
				if ( is_wp_error( $response ) || wp_remote_retrieve_response_code( $response ) >= 400 ) {
					throw new Exception( 'OpenAI API request failed.' );
				}

				$body = json_decode( wp_remote_retrieve_body( $response ), true );
				if ( isset( $body['data'] ) ) {
					foreach ( $body['data'] as $model ) {
						$models[] = array(
							'id'   => $model['id'],
							'name' => $model['id'],
						);
					}
					usort(
						$models,
						function ( $a, $b ) {
							return strcmp( $b['id'], $a['id'] );
						}
					);
				}
				if ( empty( $models ) ) {
					throw new Exception( 'No compatible OpenAI models found.' );
				}
				break;

			case 'gemini':
				$response = wp_remote_get(
					"https://generativelanguage.googleapis.com/v1beta/models?key={$api_key}",
					array(
						'headers' => quorlyx_get_gemini_request_headers(),
						'timeout' => QUORLYX_API_TIMEOUT,
					)
				);
				if ( is_wp_error( $response ) || wp_remote_retrieve_response_code( $response ) >= 400 ) {
					throw new Exception( 'Gemini API request failed.' );
				}

				$body = json_decode( wp_remote_retrieve_body( $response ), true );
				if ( isset( $body['models'] ) ) {
					foreach ( $body['models'] as $model ) {
						$supported_methods = isset( $model['supportedGenerationMethods'] ) && is_array( $model['supportedGenerationMethods'] ) ? $model['supportedGenerationMethods'] : array();
						if ( ! empty( $supported_methods ) && ! in_array( 'generateContent', $supported_methods, true ) ) {
							continue;
						}

						$model_id = (string) ( $model['name'] ?? '' );
						if ( '' === $model_id || quorlyx_google_model_requires_interactions_api( $model_id ) ) {
							continue;
						}

						$models[] = array(
							'id'   => $model_id,
							'name' => $model['displayName'] ?? $model_id,
						);
					}
					usort(
						$models,
						function ( $a, $b ) {
							return strcmp( $a['name'], $b['name'] );
						}
					);
				}
				if ( empty( $models ) ) {
					throw new Exception( 'No compatible Gemini models found.' );
				}
				break;

			case 'anthropic':
				$response = wp_remote_get(
					'https://api.anthropic.com/v1/models',
					array(
						'headers' => array(
							'x-api-key'         => $api_key,
							'anthropic-version' => '2023-06-01',
						),
						'timeout' => QUORLYX_API_TIMEOUT,
					)
				);

				if ( is_wp_error( $response ) || wp_remote_retrieve_response_code( $response ) >= 400 ) {
					$fallback = true;
				} else {
					$body = json_decode( wp_remote_retrieve_body( $response ), true );
					$model_rows = isset( $body['data'] ) && is_array( $body['data'] ) ? $body['data'] : ( $body['models'] ?? array() );
					if ( is_array( $model_rows ) ) {
						foreach ( $model_rows as $model ) {
							$models[] = array(
								'id'   => $model['id'],
								'name' => $model['display_name'] ?? $model['id'],
							);
						}
					}
				}
				if ( empty( $models ) ) {
					$fallback = true;
				}
				break;

			case 'grok':
				$response = wp_remote_get(
					'https://api.x.ai/v1/models',
					array(
						'headers' => array(
							'Authorization' => 'Bearer ' . $api_key,
						),
						'timeout' => QUORLYX_API_TIMEOUT,
					)
				);
				if ( is_wp_error( $response ) || wp_remote_retrieve_response_code( $response ) >= 400 ) {
					throw new Exception( 'Grok API request failed.' );
				}

				$body = json_decode( wp_remote_retrieve_body( $response ), true );
				if ( isset( $body['data'] ) ) {
					foreach ( $body['data'] as $model ) {
						$models[] = array(
							'id'   => $model['id'],
							'name' => $model['id'],
						);
					}
				}
				if ( empty( $models ) ) {
					$fallback = true;
				}
				break;

			case 'mistral':
				$response = wp_remote_get(
					'https://api.mistral.ai/v1/models',
					array(
						'headers' => array(
							'Authorization' => 'Bearer ' . $api_key,
						),
						'timeout' => QUORLYX_API_TIMEOUT,
					)
				);
				if ( is_wp_error( $response ) || wp_remote_retrieve_response_code( $response ) >= 400 ) {
					throw new Exception( 'Mistral API request failed.' );
				}

				$body = json_decode( wp_remote_retrieve_body( $response ), true );
				if ( isset( $body['data'] ) ) {
					foreach ( $body['data'] as $model ) {
						$models[] = array(
							'id'   => $model['id'],
							'name' => $model['id'],
						);
					}
				}
				if ( empty( $models ) ) {
					$fallback = true;
				}
				break;

			case 'deepseek':
				$response = wp_remote_get(
					'https://api.deepseek.com/v1/models',
					array(
						'headers' => array(
							'Authorization' => 'Bearer ' . $api_key,
						),
						'timeout' => QUORLYX_API_TIMEOUT,
					)
				);
				if ( is_wp_error( $response ) || wp_remote_retrieve_response_code( $response ) >= 400 ) {
					throw new Exception( 'DeepSeek API request failed.' );
				}

				$body = json_decode( wp_remote_retrieve_body( $response ), true );
				if ( isset( $body['data'] ) ) {
					foreach ( $body['data'] as $model ) {
						$models[] = array(
							'id'   => $model['id'],
							'name' => $model['id'],
						);
					}
				}
				if ( empty( $models ) ) {
					$fallback = true;
				}
				break;

			default:
				return new WP_Error( 'unsupported_provider', 'Unsupported provider.', array( 'status' => 400 ) );
		}
	} catch ( Exception $e ) {
		Quorlyx_Pro_Logger::log(
			'warning',
			'Failed to fetch models dynamically',
			array(
				'provider' => $provider,
				'error'    => $e->getMessage(),
			)
		);
		$fallback = true;
	}

	if ( $fallback ) {
		switch ( $provider ) {
			case 'openai':
				$models = array(
					array(
						'id'   => 'gpt-4o',
						'name' => 'GPT-4o (Fallback)',
					),
					array(
						'id'   => 'gpt-4-turbo',
						'name' => 'GPT-4 Turbo (Fallback)',
					),
					array(
						'id'   => 'gpt-3.5-turbo',
						'name' => 'GPT-3.5 Turbo (Fallback)',
					),
				);
				break;
			case 'gemini':
				$models = array(
					array(
						'id'   => 'models/gemini-2.0-flash',
						'name' => 'Gemini 2.0 Flash (Recommended)',
					),
					array(
						'id'   => 'models/gemini-pro',
						'name' => 'Gemini Pro (Fallback)',
					),
					array(
						'id'   => 'models/gemini-1.5-flash-latest',
						'name' => 'Gemini 1.5 Flash (Fallback)',
					),
					array(
						'id'   => 'models/gemini-1.5-pro-latest',
						'name' => 'Gemini 1.5 Pro (Fallback)',
					),
				);
				break;
			case 'anthropic':
				$models = array(
					array(
						'id'   => 'claude-opus-4-1-20250805',
						'name' => 'Claude Opus 4.1',
					),
					array(
						'id'   => 'claude-sonnet-4-20250514',
						'name' => 'Claude Sonnet 4 (Recommended)',
					),
					array(
						'id'   => 'claude-3-5-haiku-20241022',
						'name' => 'Claude 3.5 Haiku',
					),
				);
				break;
			case 'grok':
				$models = array(
					array(
						'id'   => 'grok-beta',
						'name' => 'Grok Beta (Fallback)',
					),
				);
				break;
			case 'mistral':
				$models = array(
					array(
						'id'   => 'mistral-large',
						'name' => 'Mistral Large',
					),
					array(
						'id'   => 'mistral-medium',
						'name' => 'Mistral Medium',
					),
					array(
						'id'   => 'mistral-small',
						'name' => 'Mistral Small',
					),
				);
				break;
			case 'deepseek':
				$models = array(
					array(
						'id'   => 'deepseek-chat',
						'name' => 'DeepSeek Chat',
					),
					array(
						'id'   => 'deepseek-coder',
						'name' => 'DeepSeek Coder',
					),
				);
				break;
		}
	}

	if ( empty( $models ) ) {
		return new WP_Error( 'no_models_found', 'Could not retrieve any models for the selected provider.', array( 'status' => 404 ) );
	}

	return new WP_REST_Response(
		array(
			'success' => true,
			'models'  => $models,
		),
		200
	);
}

/**
 * REST endpoint: generate JSON-LD schema for a post.
 *
 * @param WP_REST_Request $request REST request.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_rest_generate_schema( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		return $nonce_ok;
	}
	$post_id = absint( $request->get_param( 'post_id' ) );
	$post    = get_post( $post_id );
	if ( ! $post ) {
		return new WP_Error( 'not_found', 'Post not found', array( 'status' => 404 ) );
	}
	if ( ! current_user_can( 'edit_post', $post_id ) ) {
		return new WP_Error( 'forbidden', 'You are not allowed to edit this post.', array( 'status' => 403 ) );
	}

	$options     = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$variation_a = $options['variation_a'];
	$provider    = $variation_a['ai_provider'];
	$api_key     = $variation_a['api_keys'][ $provider ] ?? '';
	if ( empty( $api_key ) ) {
		return new WP_Error( 'no_api_key', 'API key for Variation A is not set.', array( 'status' => 400 ) );
	}

	$content       = wp_strip_all_tags( $post->post_title . "\n\n" . $post->post_content );
	$system_prompt = 'You are an SEO expert. Analyze the following text and generate the most appropriate JSON-LD schema. '
		. "Choose between 'Article' or 'FAQPage'. If it's an article, provide a concise, compelling description. "
		. 'If it\'s a FAQ, list the questions and answers. Respond ONLY with the raw JSON-LD code, nothing else. Ensure the JSON is valid.';
	$history       = array(
		array(
			'role'  => 'user',
			'parts' => array(
				array(
					'text' => $content,
				),
			),
		),
	);

	$schema = quorlyx_call_ai_api( $provider, $api_key, $variation_a['ai_model'], $system_prompt, $history );
	if ( is_wp_error( $schema ) ) {
		return $schema;
	}

	$cleaned_schema = preg_replace( '/^```json\s*|\s*```$/', '', trim( $schema ) );
	$cleaned_schema = preg_replace( '/^```\s*|\s*```$/', '', trim( $cleaned_schema ) );

	$json_decoded = json_decode( $cleaned_schema, true );
	if ( JSON_ERROR_NONE !== json_last_error() ) {
		Quorlyx_Pro_Logger::log(
			'error',
			'Schema Generation Failed: Invalid JSON',
			array(
				'raw_response' => $schema,
				'json_error'   => json_last_error_msg(),
			)
		);
		return new WP_Error(
			'invalid_json',
			'AI returned invalid JSON for schema.',
			array(
				'status'   => 500,
				'response' => $schema,
			)
		);
	}

	update_post_meta( $post_id, '_quorlyx_generated_schema', $cleaned_schema );
	return new WP_REST_Response(
		array(
			'success' => true,
			'schema'  => $cleaned_schema,
		),
		200
	);
}

/**
 * REST endpoint: fetch WooCommerce products for generation queueing.
 *
 * @param WP_REST_Request $request REST request.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_rest_fetch_products( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		return $nonce_ok;
	}
	if ( ! class_exists( 'WooCommerce' ) ) {
		return new WP_Error( 'no_wc', 'WooCommerce is not active.', array( 'status' => 400 ) );
	}

	$options            = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$prevent_duplicates = ! empty( $options['post_generator']['prevent_duplicates'] );

	$products = get_posts(
		array(
			'post_type'      => 'product',
			'posts_per_page' => 1000,
			'post_status'    => 'publish',
			'fields'         => 'ids',
			'orderby'        => 'ID',
			'order'          => 'ASC',
		)
	);

	if ( empty( $products ) ) {
		return new WP_REST_Response(
			array(
				'success'  => true,
				'products' => array(),
			),
			200
		);
	}

	if ( $prevent_duplicates ) {
		$history          = get_option(
			'quorlyx_generated_history',
			array(
				'products' => array(),
				'keywords' => array(),
			)
		);
		$history_products = array_map( 'intval', (array) ( $history['products'] ?? array() ) );

		$filtered = array();
		foreach ( $products as $pid ) {
			if ( in_array( (int) $pid, $history_products, true ) ) {
				continue;
			}

			$gen = get_post_meta( $pid, '_quorlyx_content_generated', true );
			if ( '1' === $gen || 1 === $gen ) {
				continue;
			}

			$filtered[] = $pid;
		}

		$products = array_values( $filtered );
	}

	return new WP_REST_Response(
		array(
			'success'  => true,
			'products' => $products,
		),
		200
	);
}

/**
 * REST endpoint: suggest internal links for a post.
 *
 * @param WP_REST_Request $request REST request.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_rest_suggest_links( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		return $nonce_ok;
	}
	$post_id = absint( $request->get_param( 'post_id' ) );
	$post    = get_post( $post_id );
	if ( ! $post ) {
		return new WP_Error( 'not_found', 'Post not found', array( 'status' => 404 ) );
	}
	if ( ! current_user_can( 'edit_post', $post_id ) ) {
		return new WP_Error( 'forbidden', 'You are not allowed to edit this post.', array( 'status' => 403 ) );
	}

	$options     = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$variation_a = $options['variation_a'];
	$provider    = $variation_a['ai_provider'];
	$api_key     = $variation_a['api_keys'][ $provider ] ?? '';
	if ( empty( $api_key ) ) {
		return new WP_Error( 'no_api_key', 'API key for Variation A is not set.', array( 'status' => 400 ) );
	}

	$content = wp_strip_all_tags( $post->post_title . "\n\n" . $post->post_content );

	$all_posts    = get_posts(
		array(
			'post_type'   => 'post',
			'numberposts' => -1,
			'exclude'     => $post_id,
		)
	);
	$all_pages    = get_pages(
		array(
			'exclude' => $post_id,
		)
	);
	$site_content = "Available internal pages to link to:\n";
	foreach ( array_merge( $all_posts, $all_pages ) as $p ) {
		$site_content .= '- ' . get_the_title( $p ) . ' | ' . get_permalink( $p ) . "\n";
	}

	$system_prompt = 'You are an SEO expert. Below is a blog post and a list of available pages on the same site. '
		. 'Identify 3-5 relevant internal linking opportunities from the blog post content to the available pages. '
		. 'For each suggestion, provide the exact phrase from the blog post to use as anchor text and the corresponding URL. '
		. 'Format your response as a simple list, like: `Anchor Text -> URL`. Respond ONLY with the list.';
	$full_prompt   = "BLOG POST CONTENT:\n{$content}\n\n---\n\nAVAILABLE PAGES:\n{$site_content}";
	$history       = array(
		array(
			'role'  => 'user',
			'parts' => array(
				array(
					'text' => $full_prompt,
				),
			),
		),
	);

	$suggestions = quorlyx_call_ai_api( $provider, $api_key, $variation_a['ai_model'], $system_prompt, $history );
	if ( is_wp_error( $suggestions ) ) {
		return $suggestions;
	}

	return new WP_REST_Response(
		array(
			'success'     => true,
			'suggestions' => $suggestions,
		),
		200
	);
}

/**
 * REST endpoint: analyze a topic for SEO planning.
