		return $nonce_ok;
	}
	$topic = sanitize_text_field( $request->get_param( 'topic' ) );
	if ( empty( $topic ) ) {
		return new WP_Error( 'no_topic', 'Topic is required.', array( 'status' => 400 ) );
	}

	$options     = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$variation_a = $options['variation_a'];
	$provider    = $variation_a['ai_provider'];
	$api_key     = $variation_a['api_keys'][ $provider ] ?? '';
	if ( empty( $api_key ) ) {
		return new WP_Error( 'no_api_key', 'API key for Variation A is not set.', array( 'status' => 400 ) );
	}

	$system_prompt = 'You are an expert SEO and Content Strategist. Analyze the following topic and provide a detailed report. '
		. 'The report must be in Markdown format and include these exact sections:' . "\n\n"
