			'high'
		);
	}
}
/**
 * Render the conversation details meta box.
 *
 * @param WP_Post $post Conversation post object.
 * @return void
 */
function quorlyx_render_conversation_meta_box( $post ) {
	$conversation_record = quorlyx_get_conversation_record_by_post_id( $post->ID );
	$conv_count          = (int) ( $conversation_record['conversions_count'] ?? get_post_meta( $post->ID, 'quorlyx_conversions_count', true ) );
	$conv_details        = get_post_meta( $post->ID, 'quorlyx_conversions', true );
	if ( ! is_array( $conv_details ) && ! empty( $conversation_record['conversion_details'] ) ) {
		$decoded = json_decode( (string) $conversation_record['conversion_details'], true );
		if ( is_array( $decoded ) ) {
			$conv_details = $decoded;
		}
	}
	$origin       = quorlyx_get_conversation_origin_details( $post->ID );
	if ( $conv_count > 0 ) {
		$goals = array();
		if ( is_array( $conv_details ) ) {
			foreach ( $conv_details as $detail ) {
				if ( ! empty( $detail['goal_name'] ) ) {
					$goals[] = sanitize_text_field( $detail['goal_name'] );
				}
			}
		}
		$goals = array_unique( array_filter( $goals ) );
		echo '<p><span class="qux-badge qux-badge-conv">' . esc_html( $conv_count ) . " \xE2\x80\x94 " . esc_html( implode( ', ', array_slice( $goals, 0, 5 ) ) ) . '</span></p>';
	} else {
		echo '<p><span class="qux-badge qux-badge-conv">0</span></p>';
	}
	echo '<p><strong>Source:</strong> ' . esc_html( $origin['source_label'] ) . '</p>';
	if ( 'trigger' === (string) $origin['source'] ) {
		$trigger_name = (string) $origin['trigger_name'];
		$trigger_id   = (string) $origin['trigger_id'];
		$trigger_type = (string) $origin['trigger_type'];

		if ( '' === $trigger_name && '' !== $trigger_id ) {
			$trigger_name = $trigger_id;
		}

		echo '<p><strong>Trigger:</strong> ' . esc_html( '' !== $trigger_name ? $trigger_name : 'Unknown Trigger' );
		if ( '' !== $trigger_id ) {
			echo ' <small>(' . esc_html( $trigger_id ) . ')</small>';
		}
		if ( '' !== $trigger_type ) {
			echo '<br><small>Type: ' . esc_html( ucwords( str_replace( '_', ' ', $trigger_type ) ) ) . '</small>';
		}
		echo '</p>';
	}
	$submission_records = quorlyx_get_submission_records_for_conversation( $post->ID );
	if ( ! empty( $submission_records ) ) {
		echo '<p><strong>Linked Submissions:</strong></p><ul>';
		foreach ( $submission_records as $submission_record ) {
			$submission_id = absint( $submission_record['post_id'] ?? 0 );
			$email         = sanitize_email( (string) ( $submission_record['email'] ?? '' ) );
			$interest      = sanitize_text_field( (string) ( $submission_record['interest'] ?? '' ) );
			$urgency       = sanitize_text_field( (string) ( $submission_record['urgency'] ?? '' ) );
			$link          = $submission_id > 0 ? admin_url( 'post.php?post=' . $submission_id . '&action=edit' ) : '';
			echo '<li>';
			if ( $link ) {
				echo '<a href="' . esc_url( $link ) . '">' . esc_html( $interest ? $interest : get_the_title( $submission_id ) ) . '</a>';
			} else {
				echo esc_html( $interest ? $interest : 'Submission' );
			}
			if ( $email ) {
				echo ' <small>' . esc_html( $email ) . '</small>';
			}
			if ( $urgency ) {
				echo ' <span class="qux-badge qux-badge-conv">' . esc_html( $urgency ) . '</span>';
			}
			echo '</li>';
		}
		echo '</ul>';
	}
	$submission_ids = get_post_meta( $post->ID, 'quorlyx_submission_ids', true );
	if ( ! is_array( $submission_ids ) ) {
		$submission_ids = get_post_meta( $post->ID, 'quorlyx_waitlist_submission_ids', true );
	}
	if ( empty( $submission_records ) && is_array( $submission_ids ) && ! empty( $submission_ids ) ) {
		echo '<p><strong>Linked Submissions:</strong></p><ul>';
		foreach ( array_values( array_unique( array_map( 'absint', $submission_ids ) ) ) as $submission_id ) {
			if ( $submission_id <= 0 || 'quorlyx_submission' !== get_post_type( $submission_id ) ) {
				continue;
			}
			$email    = sanitize_email( (string) get_post_meta( $submission_id, 'quorlyx_email', true ) );
			$interest = sanitize_text_field( (string) get_post_meta( $submission_id, 'quorlyx_interest', true ) );
			$urgency  = sanitize_text_field( (string) get_post_meta( $submission_id, 'quorlyx_urgency', true ) );
			$link     = admin_url( 'post.php?post=' . $submission_id . '&action=edit' );
			echo '<li><a href="' . esc_url( $link ) . '">' . esc_html( $interest ? $interest : get_the_title( $submission_id ) ) . '</a>';
			if ( $email ) {
				echo ' <small>' . esc_html( $email ) . '</small>';
			}
			if ( $urgency ) {
				echo ' <span class="qux-badge qux-badge-conv">' . esc_html( $urgency ) . '</span>';
			}
			echo '</li>';
		}
		echo '</ul>';
	}
	$history = quorlyx_get_conversation_history( $post->ID );
	if ( empty( $history ) || ! is_array( $history ) ) {
		echo '<p>No conversation history found.</p>';
		return;
	}
	echo '<div class="quorlyx-chat-log-backend">';
	foreach ( $history as $message ) {
		$role       = $message['role'] ?? 'unknown';
		$text       = $message['parts'][0]['text'] ?? '[empty message]';
		$role_label = ucfirst( 'model' === $role ? 'AI' : 'User' );
		if ( 'model' === $role && ! empty( $message['routing'] ) ) {
			$role_label .= ' (routing mode)';
		}
		printf(
			'<div class="quorlyx-msg-backend quorlyx-%s"><div class="quorlyx-role">%s</div><div class="quorlyx-text">%s</div></div>',
			esc_attr( 'model' === $role ? 'ai' : 'user' ),
			esc_html( $role_label ),
			wp_kses_post( nl2br( esc_html( $text ) ) )
		);
	}
	echo '</div>';
	echo '<style>
		.quorlyx-chat-log-backend { background:#f9fafb; border:1px solid #e5e7eb; padding:10px; max-height:500px; overflow-y:auto; }
		.quorlyx-msg-backend { margin-bottom:10px; padding:8px 12px; border-radius:8px; max-width:90%; }
		.quorlyx-msg-backend .quorlyx-role { font-weight:bold; margin-bottom:4px; color:#333; }
		.quorlyx-user { background:#e0e7ff; margin-left:auto; }
		.quorlyx-ai { background:#fff; border:1px solid #e5e7eb; margin-right:auto; }
	</style>';
}

/**
 * Render the submission details meta box.
 *
 * @param WP_Post $post Submission post object.
 * @return void
 */
function quorlyx_render_submission_meta_box( $post ) {
	$email           = sanitize_email( (string) get_post_meta( $post->ID, 'quorlyx_email', true ) );
	$interest        = sanitize_text_field( (string) get_post_meta( $post->ID, 'quorlyx_interest', true ) );
	$status          = sanitize_text_field( (string) get_post_meta( $post->ID, 'quorlyx_status', true ) );
	$urgency         = sanitize_text_field( (string) get_post_meta( $post->ID, 'quorlyx_urgency', true ) );
	$tags            = get_post_meta( $post->ID, 'quorlyx_tags', true );
	$conversation_id = absint( get_post_meta( $post->ID, 'quorlyx_conversation_id', true ) );
	$trigger_name    = sanitize_text_field( (string) get_post_meta( $post->ID, 'quorlyx_trigger_name', true ) );
	$trigger_type    = sanitize_key( (string) get_post_meta( $post->ID, 'quorlyx_trigger_type', true ) );
	$source_url      = esc_url( (string) get_post_meta( $post->ID, 'quorlyx_source_url', true ) );

	$rows = array(
		'Email'    => $email,
		'Phone'    => sanitize_text_field( (string) get_post_meta( $post->ID, 'quorlyx_phone', true ) ),
		'Purpose'  => sanitize_text_field( (string) get_post_meta( $post->ID, 'quorlyx_capture_purpose', true ) ),
		'Interest' => $interest,
		'Status'   => $status,
		'Urgency'  => $urgency,
		'Tags'     => is_array( $tags ) ? implode( ', ', array_map( 'sanitize_text_field', $tags ) ) : sanitize_text_field( (string) $tags ),
		'Trigger'  => trim( $trigger_name . ( $trigger_type ? ' (' . ucwords( str_replace( '_', ' ', $trigger_type ) ) . ')' : '' ) ),
	);

	echo '<table class="widefat striped"><tbody>';
	foreach ( $rows as $label => $value ) {
		echo '<tr><th style="width:160px;">' . esc_html( $label ) . '</th><td>' . ( '' !== (string) $value ? esc_html( (string) $value ) : '&mdash;' ) . '</td></tr>';
	}
	if ( $conversation_id && 'quorlyx_conversation' === get_post_type( $conversation_id ) ) {
		echo '<tr><th>Conversation</th><td><a href="' . esc_url( admin_url( 'post.php?post=' . $conversation_id . '&action=edit' ) ) . '">' . esc_html( get_the_title( $conversation_id ) ) . '</a></td></tr>';
	}
	if ( $source_url ) {
		echo '<tr><th>Source URL</th><td><a href="' . esc_url( $source_url ) . '" target="_blank" rel="noopener noreferrer">' . esc_html( $source_url ) . '</a></td></tr>';
	}
	echo '</tbody></table>';
}
