/**
 * Persist dismissal state for a Quorlyx admin notice.
 *
 * @param WP_REST_Request $request REST request instance.
 * @return WP_REST_Response
 */
function quorlyx_rest_dismiss_notice( $request ) {
	$params    = $request->get_json_params();
	$notice_id = isset( $params['notice_id'] ) ? sanitize_key( $params['notice_id'] ) : '';
	if ( ! $notice_id ) {
		return new WP_REST_Response(
			array(
				'success' => false,
				'message' => 'Missing notice_id',
			),
			400
		);
	}

	$dismissed = get_option( 'quorlyx_dismissed_notices', array() );
	if ( ! is_array( $dismissed ) ) {
		$dismissed = array();
	}
	$dismissed[ $notice_id ] = time();
	update_option( 'quorlyx_dismissed_notices', $dismissed );

	return new WP_REST_Response(
		array(
			'success'   => true,
			'notice_id' => $notice_id,
		),
		200
	);
}

/**
 * Load README context used by the admin guide assistant.
 *
 * @return string
 */
function quorlyx_pro_get_guide_readme_context() {
	$readme_path = plugin_dir_path( __FILE__ ) . 'README.md';
	if ( ! file_exists( $readme_path ) ) {
		return '';
	}

	// phpcs:ignore WordPress.WP.AlternativeFunctions.file_get_contents_file_get_contents -- Reading local plugin README context.
	$raw = file_get_contents( $readme_path );
	if ( false === $raw || '' === trim( $raw ) ) {
		return '';
	}

	$raw = wp_strip_all_tags( $raw );
	$raw = preg_replace( "/\r\n?|\n/", "\n", $raw );
	if ( ! is_string( $raw ) ) {
		return '';
	}

	if ( strlen( $raw ) > 18000 ) {
		$raw = substr( $raw, 0, 18000 );
	}

	return trim( $raw );
}

/**
 * Collect a recent published content snapshot for a post type.
 *
 * @param string $post_type Post type slug.
 * @param int    $limit Maximum number of items.
 * @return array<int,array<string,string>>
 */
function quorlyx_pro_collect_recent_content_snapshot( $post_type, $limit = 8 ) {
	$items = array();
	$query = new WP_Query(
		array(
			'post_type'              => $post_type,
			'post_status'            => 'publish',
			'posts_per_page'         => max( 1, absint( $limit ) ),
			'orderby'                => 'date',
			'order'                  => 'DESC',
			'no_found_rows'          => true,
			'ignore_sticky_posts'    => true,
			'update_post_meta_cache' => false,
			'update_post_term_cache' => false,
		)
	);

	if ( $query->have_posts() ) {
		while ( $query->have_posts() ) {
			$query->the_post();
			$items[] = array(
				'title' => get_the_title(),
				'url'   => get_permalink(),
			);
		}
	}
	wp_reset_postdata();

	return $items;
}

/**
 * Build a high-level site snapshot used by guide tooling.
 *
 * @return array<string,mixed>
 */
function quorlyx_pro_get_site_snapshot() {
	if ( ! function_exists( 'get_plugins' ) ) {
		require_once ABSPATH . 'wp-admin/includes/plugin.php';
	}

	$theme          = wp_get_theme();
	$all_plugins    = get_plugins();
	$active_plugins = get_option( 'active_plugins', array() );
	$plugin_names   = array();

	foreach ( $active_plugins as $plugin_file ) {
		if ( isset( $all_plugins[ $plugin_file ] ) ) {
			$plugin_names[] = $all_plugins[ $plugin_file ]['Name'];
		}
	}

	$options     = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$variation_a = $options['variation_a'] ?? array();
	$provider    = sanitize_key( $variation_a['ai_provider'] ?? 'gemini' );
	$api_key     = sanitize_text_field( $variation_a['api_keys'][ $provider ] ?? '' );
	$model       = sanitize_text_field( $variation_a['ai_model'] ?? '' );

	$counts = array(
		'posts'    => (int) wp_count_posts( 'post' )->publish,
		'pages'    => (int) wp_count_posts( 'page' )->publish,
		'products' => post_type_exists( 'product' ) ? (int) wp_count_posts( 'product' )->publish : 0,
	);

	$snapshot = array(
		'wp_version'          => get_bloginfo( 'version' ),
		'php_version'         => phpversion(),
		'site_url'            => home_url(),
		'admin_email'         => get_option( 'admin_email' ),
		'permalink_structure' => (string) get_option( 'permalink_structure', '' ),
		'theme'               => $theme->get( 'Name' ) . ' v' . $theme->get( 'Version' ),
		'active_plugins'      => array_slice( $plugin_names, 0, 40 ),
		'woocommerce'         => array(
			'installed' => class_exists( 'WooCommerce' ),
			'active'    => class_exists( 'WooCommerce' ),
		),
		'quorlyx_chatbot'     => array(
			'provider'       => $provider,
			'model'          => $model,
			'api_key_set'    => ! empty( $api_key ),
			'chat_enabled_a' => ! empty( $variation_a['chat_enabled'] ),
		),
		'content_counts'      => $counts,
		'recent_content'      => array(
			'pages'    => quorlyx_pro_collect_recent_content_snapshot( 'page', 8 ),
			'posts'    => quorlyx_pro_collect_recent_content_snapshot( 'post', 8 ),
			'products' => post_type_exists( 'product' ) ? quorlyx_pro_collect_recent_content_snapshot( 'product', 8 ) : array(),
		),
	);

	return $snapshot;
}

/**
 * Detect technical findings from a site snapshot.
 *
 * @param array<string,mixed> $snapshot Site snapshot data.
 * @return array<int,array<string,string>>
 */
function quorlyx_pro_detect_technical_findings( $snapshot ) {
	$findings = array();

	if ( empty( $snapshot['woocommerce']['active'] ) ) {
		$findings[] = array(
			'severity' => 'warning',
			'title'    => 'WooCommerce is not active',
			'details'  => 'Install and activate WooCommerce before enabling WooCommerce-focused chatbot workflows.',
			'action'   => 'Go to Plugins, activate WooCommerce, then verify Shop/Product pages exist.',
		);
	}

	if ( empty( $snapshot['quorlyx_chatbot']['api_key_set'] ) || empty( $snapshot['quorlyx_chatbot']['model'] ) ) {
		$findings[] = array(
			'severity' => 'error',
			'title'    => 'AI provider setup is incomplete',
			'details'  => 'Variation A is missing an API key or model.',
			'action'   => 'Open Quorlyx â†’ Settings â†’ Chatbot and set provider API key and model in Variation A.',
		);
	}

	if ( empty( $snapshot['permalink_structure'] ) ) {
		$findings[] = array(
			'severity' => 'warning',
			'title'    => 'Plain permalinks detected',
			'details'  => 'Plain permalinks can reduce clean URL behavior for content links.',
			'action'   => 'Go to Settings â†’ Permalinks and choose a friendly structure (for example, Post name).',
		);
	}

	$recent_logs      = Quorlyx_Pro_Logger::get_logs();
	$recent_logs      = array_slice( $recent_logs, 0, 200 );
	$error_log_count  = 0;
	$warn_log_count   = 0;
	$critical_samples = array();

	foreach ( $recent_logs as $entry ) {
		$type = sanitize_key( $entry['type'] ?? '' );
		if ( in_array( $type, array( 'error', 'critical' ), true ) ) {
			++$error_log_count;
			if ( count( $critical_samples ) < 3 && ! empty( $entry['message'] ) ) {
				$critical_samples[] = sanitize_text_field( $entry['message'] );
			}
		} elseif ( 'warning' === $type ) {
			++$warn_log_count;
		}
	}

	if ( $error_log_count > 0 ) {
		$findings[] = array(
			'severity' => 'error',
			'title'    => 'Recent error logs detected',
			'details'  => 'Found ' . number_format_i18n( $error_log_count ) . ' recent error/critical log entries.',
			'action'   => ! empty( $critical_samples ) ? 'Review logs and prioritize: ' . implode( '; ', $critical_samples ) : 'Review Logs tab and address recurring API/provider failures first.',
		);
	} elseif ( $warn_log_count > 0 ) {
		$findings[] = array(
			'severity' => 'warning',
			'title'    => 'Recent warning logs detected',
			'details'  => 'Found ' . number_format_i18n( $warn_log_count ) . ' warning entries in recent logs.',
			'action'   => 'Review warning patterns in Logs and resolve repeated warnings.',
		);
	}

	if ( empty( $findings ) ) {
		$findings[] = array(
			'severity' => 'success',
			'title'    => 'No critical technical issues found',
			'details'  => 'Current snapshot and recent logs show no critical failures.',
			'action'   => 'Continue monitoring with Analyze Logs and run a frontend chatbot test.',
		);
	}

	return $findings;
}

/**
 * Return fallback guide copy when the AI provider is unavailable.
 *
 * @param string              $question User question.
 * @param array<string,mixed> $snapshot Site snapshot data.
 * @param array<int,mixed>    $findings Technical findings.
 * @return string
 */
function quorlyx_pro_guide_fallback_answer( $question, $snapshot, $findings ) {
	$question_lc = strtolower( (string) $question );

	if ( false !== strpos( $question_lc, 'woocommerce' ) || false !== strpos( $question_lc, 'connect woo' ) ) {
		$answer_lines = array(
			'Here is the fastest way to connect WooCommerce with Quorlyx:',
			'1) Install and activate WooCommerce in WordPress.',
			'2) In Quorlyx Pro, go to Settings â†’ Chatbot and configure Variation A provider API key + model.',
			'3) Keep chat enabled for Variation A and save settings.',
			'4) Add product-focused persona/knowledge instructions so answers can reference products.',
			'5) Test on a product page and then review the Logs tab for warnings/errors.',
		);

		if ( empty( $snapshot['woocommerce']['active'] ) ) {
			$answer_lines[] = 'Current check: WooCommerce is not active on this site yet.';
		}
		if ( empty( $snapshot['quorlyx_chatbot']['api_key_set'] ) || empty( $snapshot['quorlyx_chatbot']['model'] ) ) {
			$answer_lines[] = 'Current check: Quorlyx Variation A provider setup is incomplete (missing API key or model).';
		}

		if ( ! empty( $findings ) ) {
			$answer_lines[] = 'Top technical findings:';
			foreach ( array_slice( $findings, 0, 2 ) as $finding ) {
				$answer_lines[] = '- ' . sanitize_text_field( $finding['title'] ?? '' ) . ': ' . sanitize_text_field( $finding['action'] ?? '' );
			}
		}

		return implode( "\n", array_filter( $answer_lines ) );
	}

	return 'I could not reach the AI provider right now. Please try again, or click "Fetch Site Snapshot" and use "Analyze with AI" in Logs for a deeper technical diagnosis.';
}

/**
 * Sanitize and truncate guide text payloads.
 *
 * @param string $text Raw text.
 * @param int    $max_chars Maximum allowed characters.
 * @return string
 */
function quorlyx_pro_sanitize_guide_text( $text, $max_chars = 12000 ) {
	$clean = is_string( $text ) ? wp_check_invalid_utf8( $text ) : '';
	$clean = str_replace( array( "\r\n", "\r" ), "\n", $clean );
	$clean = trim( $clean );

	if ( '' === $clean ) {
		return '';
	}

	$max_chars = max( 1000, absint( $max_chars ) );
	if ( function_exists( 'mb_strlen' ) && function_exists( 'mb_substr' ) ) {
		if ( mb_strlen( $clean ) > $max_chars ) {
			$clean = mb_substr( $clean, 0, $max_chars ) . "\n\n[Response truncated due to size]";
		}
	} elseif ( strlen( $clean ) > $max_chars ) {
		$clean = substr( $clean, 0, $max_chars ) . "\n\n[Response truncated due to size]";
	}

	return $clean;
}

/**
 * Normalize guide history payload into provider-ready message format.
 *
 * @param mixed $raw_history Raw history payload.
 * @param int   $max_items Maximum number of messages.
 * @return array<int,array<string,mixed>>
 */
function quorlyx_pro_normalize_guide_history( $raw_history, $max_items = 20 ) {
	$normalized = array();
	if ( ! is_array( $raw_history ) ) {
		return $normalized;
	}

	foreach ( $raw_history as $item ) {
		if ( ! is_array( $item ) ) {
			continue;
		}
		$role_raw = sanitize_key( $item['role'] ?? '' );
		$role     = 'assistant' === $role_raw ? 'model' : 'user';
		$text     = quorlyx_pro_sanitize_guide_text( $item['text'] ?? '', 12000 );
		if ( '' === $text ) {
			continue;
		}

		$normalized[] = array(
			'role'  => $role,
			'parts' => array(
				array(
					'text' => $text,
				),
			),
		);
	}

	if ( count( $normalized ) > $max_items ) {
		$normalized = array_slice( $normalized, -1 * absint( $max_items ) );
	}

	return $normalized;
}

/**
 * Flatten normalized guide history for REST responses.
 *
 * @param mixed $history Normalized history payload.
 * @return array<int,array<string,string>>
 */
function quorlyx_pro_flatten_guide_history_for_response( $history ) {
	$flat = array();
	if ( ! is_array( $history ) ) {
		return $flat;
	}

	foreach ( $history as $item ) {
		$text = '';
		if ( isset( $item['parts'][0]['text'] ) && is_string( $item['parts'][0]['text'] ) ) {
			$text = $item['parts'][0]['text'];
		}
		$text = quorlyx_pro_sanitize_guide_text( $text, 12000 );
		if ( '' === $text ) {
			continue;
		}

		$flat[] = array(
			'role' => ( isset( $item['role'] ) && 'model' === $item['role'] ) ? 'assistant' : 'user',
			'text' => $text,
		);
	}

	return $flat;
}

/**
 * Build runtime log counters for guide health checks.
 *
 * @param int $limit Maximum number of logs to inspect.
 * @return array<string,int>
 */
function quorlyx_pro_get_runtime_log_metrics( $limit = 300 ) {
	$logs    = Quorlyx_Pro_Logger::get_logs();
	$logs    = array_slice( (array) $logs, 0, max( 50, absint( $limit ) ) );
	$metrics = array(
		'critical' => 0,
		'error'    => 0,
		'warning'  => 0,
		'info'     => 0,
	);

	foreach ( $logs as $entry ) {
		$type = sanitize_key( (string) ( $entry['type'] ?? '' ) );
		if ( isset( $metrics[ $type ] ) ) {
			++$metrics[ $type ];
		}
	}

	return $metrics;
}

/**
 * Detect common plugin and theme conflict signals.
 *
 * @param array<string,mixed> $snapshot Site snapshot data.
 * @return array<string,mixed>
 */
function quorlyx_pro_detect_conflict_signals( $snapshot ) {
	$active_plugins = array_map( 'strtolower', (array) ( $snapshot['active_plugins'] ?? array() ) );
	$theme_name     = strtolower( (string) ( $snapshot['theme'] ?? '' ) );
	$issues         = array();

	$optimization_plugins = array(
		'wp rocket',
		'litespeed cache',
		'autoptimize',
		'perfmatters',
		'asset clean',
		'nitropack',
		'flyingpress',
	);

	$other_chat_plugins = array(
		'tidio',
		'tawk',
		'crisp',
		'chaty',
		'hubspot',
		'chatbot',
	);

	$optimization_found = array();
	$chat_plugins_found = array();

	foreach ( $active_plugins as $plugin_name ) {
		foreach ( $optimization_plugins as $probe ) {
			if ( false !== strpos( $plugin_name, $probe ) ) {
				$optimization_found[] = $plugin_name;
			}
		}
		foreach ( $other_chat_plugins as $probe ) {
			if ( false !== strpos( $plugin_name, $probe ) ) {
				$chat_plugins_found[] = $plugin_name;
			}
		}
	}

	$optimization_found = array_values( array_unique( $optimization_found ) );
	$chat_plugins_found = array_values( array_unique( $chat_plugins_found ) );

	if ( ! empty( $optimization_found ) ) {
		$issues[] = array(
			'severity' => 'warning',
			'detail'   => 'Optimization/caching plugins detected that can defer or alter chatbot scripts: ' . implode( ', ', array_slice( $optimization_found, 0, 4 ) ) . '.',
			'action'   => 'Exclude Quorlyx scripts from JS delay/defer/combine rules, then retest trigger opening.',
		);
	}

	if ( ! empty( $chat_plugins_found ) ) {
		$issues[] = array(
			'severity' => 'warning',
			'detail'   => 'Other chat plugins detected: ' . implode( ', ', array_slice( $chat_plugins_found, 0, 4 ) ) . '.',
			'action'   => 'Avoid running multiple chat widgets together on the same pages to reduce script conflicts.',
		);
	}

	if ( false !== strpos( $theme_name, 'elementor' ) || false !== strpos( $theme_name, 'divi' ) ) {
		$issues[] = array(
			'severity' => 'warning',
			'detail'   => 'Page-builder-heavy themes can alter DOM timing for trigger execution.',
			'action'   => 'Test with a simple time trigger and verify that optimization plugins are not delaying Quorlyx assets.',
		);
	}

	if ( count( $active_plugins ) >= 35 ) {
		$issues[] = array(
			'severity' => 'warning',
			'detail'   => 'High plugin count detected (' . number_format_i18n( count( $active_plugins ) ) . ' active plugins).',
			'action'   => 'Temporarily disable non-essential plugins and retest if conflicts are suspected.',
		);
	}

	if ( empty( $issues ) ) {
		return array(
			'has_warning' => false,
			'detail'      => 'No obvious plugin/theme conflict signals detected.',
			'action'      => '',
		);
	}

	$primary = $issues[0];

	return array(
		'has_warning' => true,
		'detail'      => sanitize_text_field( (string) $primary['detail'] ),
		'action'      => sanitize_text_field( (string) $primary['action'] ),
	);
}

/**
 * Probe frontend runtime markers for health diagnostics.
 *
 * @return array<string,mixed>
 */
function quorlyx_pro_probe_frontend_runtime() {
	$target_url = esc_url_raw( home_url( '/' ) );
	$response   = wp_remote_get(
		$target_url,
		array(
			'timeout'     => 15,
			'redirection' => 3,
		)
	);

	if ( is_wp_error( $response ) ) {
		return array(
			'status'  => 'warning',
			'detail'  => 'Frontend probe could not fetch homepage (' . sanitize_text_field( $response->get_error_message() ) . ').',
			'action'  => 'Check site accessibility/firewall rules from server to self and rerun Health Check.',
			'metrics' => array(
				'http_code'          => 0,
				'has_frontend_asset' => false,
				'has_root_container' => false,
				'has_trigger_script' => false,
			),
		);
	}

	$http_code    = absint( wp_remote_retrieve_response_code( $response ) );
	$body         = (string) wp_remote_retrieve_body( $response );
	$scan_content = strtolower( substr( $body, 0, 300000 ) );

	$has_frontend_asset = ( false !== strpos( $scan_content, 'dist/frontend.min.js' ) ) || ( false !== strpos( $scan_content, 'quorlyxvars' ) ) || ( false !== strpos( $scan_content, 'quorlyx-frontend' ) );
	$has_root_container = ( false !== strpos( $scan_content, 'id="quorlyx-root"' ) ) || ( false !== strpos( $scan_content, "id='quorlyx-root'" ) );
	$has_trigger_script = ( false !== strpos( $scan_content, 'quorlyx-trigger-controller-fix' ) ) || ( false !== strpos( $scan_content, 'quorlyxtriggercontroller' ) );

	$defer_hints = array(
		'rocket-loader',
		'data-cfasync',
		'wprocket',
		'litespeed',
		'delay_js',
		'autoptimize',
	);

	$defer_detected = false;
	foreach ( $defer_hints as $hint ) {
		if ( false !== strpos( $scan_content, $hint ) ) {
			$defer_detected = true;
			break;
		}
	}

	$status = 'pass';
	$detail = 'Frontend probe found Quorlyx assets and trigger markers on homepage.';
	$action = '';

	if ( $http_code < 200 || $http_code >= 400 ) {
		$status = 'warning';
		$detail = 'Frontend probe received HTTP ' . number_format_i18n( $http_code ) . ' from homepage.';
		$action = 'Verify homepage availability and caching layer response rules.';
	} elseif ( ! $has_frontend_asset || ! $has_root_container ) {
		$status = 'warning';
		$detail = 'Frontend probe did not find all expected Quorlyx markers on homepage (asset/root missing).';
		$action = 'Exclude Quorlyx scripts from optimization delay/combine settings, then rerun Health Check.';
	} elseif ( $defer_detected ) {
		$status = 'warning';
		$detail = 'Frontend probe detected optimization/defer hints that can delay chatbot initialization.';
		$action = 'Exclude Quorlyx frontend scripts from delay/defer/minify rules and retest trigger timing.';
	}

	if ( ! $has_trigger_script && 'pass' === $status ) {
		$status = 'warning';
		$detail = 'Frontend probe found core assets but trigger controller marker is missing.';
		$action = 'Review trigger settings and optimization plugins that may strip inline trigger scripts.';
	}

	return array(
		'status'  => $status,
		'detail'  => $detail,
		'action'  => $action,
		'metrics' => array(
			'http_code'          => $http_code,
			'has_frontend_asset' => (bool) $has_frontend_asset,
			'has_root_container' => (bool) $has_root_container,
			'has_trigger_script' => (bool) $has_trigger_script,
			'defer_hints'        => (bool) $defer_detected,
		),
	);
}

/**
 * Run guide health checks and aggregate status results.
 *
 * @param array<string,mixed>      $snapshot Site snapshot data.
 * @param array<int,mixed>         $findings Technical findings.
 * @param array<string,mixed>|null $frontend_probe Optional frontend probe result.
 * @return array<string,mixed>
 */
function quorlyx_pro_run_guide_health_check( $snapshot, $findings, $frontend_probe = null ) {
	$checks = array();

	$provider_set = ! empty( $snapshot['quorlyx_chatbot']['provider'] );
	$model_set    = ! empty( $snapshot['quorlyx_chatbot']['model'] );
	$api_key_set  = ! empty( $snapshot['quorlyx_chatbot']['api_key_set'] );
	$config_ok    = $provider_set && $model_set && $api_key_set;
	$checks[]     = array(
		'key'    => 'provider_config',
		'label'  => 'Variation A provider setup',
		'status' => $config_ok ? 'pass' : 'fail',
		'detail' => $config_ok ? 'Provider, API key, and model are configured.' : 'Provider setup is incomplete (provider/API key/model).',
		'action' => $config_ok ? '' : 'Go to Quorlyx â†’ Settings â†’ Chatbot and complete Variation A provider, key, and model.',
	);

	$chat_enabled = ! empty( $snapshot['quorlyx_chatbot']['chat_enabled_a'] );
	$checks[]     = array(
		'key'    => 'chat_enabled',
		'label'  => 'Variation A chat enabled',
		'status' => $chat_enabled ? 'pass' : 'warning',
		'detail' => $chat_enabled ? 'Chat is enabled in Variation A.' : 'Chat is currently disabled in Variation A.',
		'action' => $chat_enabled ? '' : 'Enable chat in Quorlyx â†’ Settings â†’ Chatbot â†’ Variation A.',
	);

	$permalink_ok = ! empty( $snapshot['permalink_structure'] );
	$checks[]     = array(
		'key'    => 'permalinks',
		'label'  => 'Permalink structure',
		'status' => $permalink_ok ? 'pass' : 'warning',
		'detail' => $permalink_ok ? 'Friendly permalink structure is set.' : 'Plain permalink structure is active.',
		'action' => $permalink_ok ? '' : 'Open Settings â†’ Permalinks and select Post name (or similar).',
	);

	$woo_active = ! empty( $snapshot['woocommerce']['active'] );
	$checks[]   = array(
		'key'    => 'woocommerce',
		'label'  => 'WooCommerce integration',
		'status' => $woo_active ? 'pass' : 'warning',
		'detail' => $woo_active ? 'WooCommerce is active.' : 'WooCommerce is not active.',
		'action' => $woo_active ? '' : 'Activate WooCommerce if you need product-aware chat and trigger rules.',
	);

	$conflicts = quorlyx_pro_detect_conflict_signals( $snapshot );
	$checks[]  = array(
		'key'    => 'conflict_scan',
		'label'  => 'Plugin/theme conflict scan',
		'status' => ! empty( $conflicts['has_warning'] ) ? 'warning' : 'pass',
		'detail' => sanitize_text_field( (string) ( $conflicts['detail'] ?? '' ) ),
		'action' => sanitize_text_field( (string) ( $conflicts['action'] ?? '' ) ),
	);

	$runtime_metrics = quorlyx_pro_get_runtime_log_metrics( 300 );
	$error_total     = absint( $runtime_metrics['critical'] ?? 0 ) + absint( $runtime_metrics['error'] ?? 0 );
	$warn_total      = absint( $runtime_metrics['warning'] ?? 0 );
	$info_total      = absint( $runtime_metrics['info'] ?? 0 );
	$runtime_status  = 'pass';
	$runtime_detail  = 'No runtime error signals found in recent logs.';
	$runtime_action  = '';

	if ( $error_total > 0 ) {
		$runtime_status = 'fail';
		$runtime_detail = 'Recent runtime errors detected (' . number_format_i18n( $error_total ) . ' error/critical entries).';
		$runtime_action = 'Open Quorlyx â†’ Logs and fix recurring error/critical entries first.';
	} elseif ( $warn_total > 0 ) {
		$runtime_status = 'warning';
		$runtime_detail = 'Recent runtime warnings detected (' . number_format_i18n( $warn_total ) . ' warning entries).';
		$runtime_action = 'Review warnings in Quorlyx â†’ Logs to prevent failures.';
	}

	if ( $info_total > 0 ) {
		$runtime_detail .= ' Info entries (' . number_format_i18n( $info_total ) . ') are excluded from error scoring.';
	}

	$checks[] = array(
		'key'    => 'runtime_logs',
		'label'  => 'Runtime error scan',
		'status' => $runtime_status,
		'detail' => $runtime_detail,
		'action' => $runtime_action,
	);

	if ( ! is_array( $frontend_probe ) ) {
		$frontend_probe = quorlyx_pro_probe_frontend_runtime();
	}

	$checks[] = array(
		'key'    => 'frontend_probe',
		'label'  => 'Frontend runtime probe',
		'status' => sanitize_key( (string) ( $frontend_probe['status'] ?? 'warning' ) ),
		'detail' => sanitize_text_field( (string) ( $frontend_probe['detail'] ?? '' ) ),
		'action' => sanitize_text_field( (string) ( $frontend_probe['action'] ?? '' ) ),
	);

	$has_error_finding = false;
	$has_warn_finding  = false;
	if ( is_array( $findings ) ) {
		foreach ( $findings as $finding ) {
			$severity = sanitize_key( (string) ( $finding['severity'] ?? '' ) );
			if ( 'error' === $severity ) {
				$has_error_finding = true;
			} elseif ( 'warning' === $severity ) {
				$has_warn_finding = true;
			}
		}
	}

	$log_health_status = 'pass';
	$log_health_detail = 'No severe technical findings detected.';
	$log_health_action = '';

	if ( $has_error_finding ) {
		$log_health_status = 'fail';
		$log_health_detail = 'Critical technical findings were detected.';
		$log_health_action = 'Open Quorlyx â†’ Logs and resolve error-level findings first.';
	} elseif ( $has_warn_finding ) {
		$log_health_status = 'warning';
		$log_health_detail = 'Warning-level findings were detected.';
		$log_health_action = 'Review warnings in Quorlyx â†’ Logs to prevent recurring support issues.';
	}

	$checks[] = array(
		'key'    => 'technical_findings',
		'label'  => 'Technical findings health',
		'status' => $log_health_status,
		'detail' => $log_health_detail,
		'action' => $log_health_action,
	);

	$summary = array(
		'pass'    => 0,
		'warning' => 0,
		'fail'    => 0,
	);

	foreach ( $checks as $check ) {
		$status = sanitize_key( (string) ( $check['status'] ?? '' ) );
		if ( isset( $summary[ $status ] ) ) {
			++$summary[ $status ];
		}
	}

	return array(
		'checks'  => $checks,
		'summary' => $summary,
	);
}

/**
 * Build a plain-text health report from health check data.
 *
 * @param array<string,mixed> $health Health check payload.
 * @return string
 */
function quorlyx_pro_build_guide_health_report( $health ) {
	$lines      = array();
	$checks     = is_array( $health['checks'] ?? null ) ? $health['checks'] : array();
	$summary    = is_array( $health['summary'] ?? null ) ? $health['summary'] : array();
	$pass_count = absint( $summary['pass'] ?? 0 );
	$warn_count = absint( $summary['warning'] ?? 0 );
	$fail_count = absint( $summary['fail'] ?? 0 );

	$lines[] = 'Health Check Summary';
	$lines[] = 'Pass: ' . number_format_i18n( $pass_count ) . ' | Warnings: ' . number_format_i18n( $warn_count ) . ' | Fails: ' . number_format_i18n( $fail_count );
	$lines[] = '';

	foreach ( $checks as $check ) {
		$label  = sanitize_text_field( (string) ( $check['label'] ?? 'Check' ) );
		$status = strtoupper( sanitize_key( (string) ( $check['status'] ?? 'warning' ) ) );
		$detail = sanitize_text_field( (string) ( $check['detail'] ?? '' ) );
		$action = sanitize_text_field( (string) ( $check['action'] ?? '' ) );

		$lines[] = '- [' . $status . '] ' . $label . ': ' . $detail;
		if ( '' !== $action ) {
			$lines[] = '  Action: ' . $action;
		}
	}

	return quorlyx_pro_sanitize_guide_text( implode( "\n", $lines ), 12000 );
}

/**
 * REST endpoint for returning guide snapshot and findings.
 *
 * @param WP_REST_Request $request REST request instance.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_rest_guide_site_snapshot( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		return $nonce_ok;
	}

	$snapshot = quorlyx_pro_get_site_snapshot();
	$findings = quorlyx_pro_detect_technical_findings( $snapshot );

	Quorlyx_Pro_Logger::log(
		'info',
		'Guide site snapshot generated',
		array(
			'woocommerce_active' => ! empty( $snapshot['woocommerce']['active'] ),
			'findings_count'     => count( $findings ),
		)
	);

	return new WP_REST_Response(
		array(
			'success'  => true,
			'snapshot' => $snapshot,
			'findings' => $findings,
		),
		200
	);
}

/**
 * Build per-post SEO improvement context.
 *
 * @param int $post_id Post ID.
 * @return array<string,mixed>
 */
function quorlyx_get_seo_improvement_context( $post_id ) {
	$post_id = absint( $post_id );
	$post    = get_post( $post_id );
	if ( ! $post instanceof WP_Post ) {
		return array();
	}

	$plain_content       = trim( wp_strip_all_tags( $post->post_title . "\n\n" . $post->post_content ) );
	$excerpt             = trim( wp_strip_all_tags( (string) $post->post_excerpt ) );
	$schema              = (string) get_post_meta( $post_id, '_quorlyx_generated_schema', true );
	$seo_status          = quorlyx_get_content_insight_seo_status( $post_id );
	$post_type_object    = get_post_type_object( $post->post_type );
	$type_label          = $post_type_object && ! empty( $post_type_object->labels->singular_name ) ? $post_type_object->labels->singular_name : ucfirst( $post->post_type );
	$recent_content      = array_merge(
		quorlyx_pro_collect_recent_content_snapshot( 'page', 6 ),
		quorlyx_pro_collect_recent_content_snapshot( 'post', 6 ),
		post_type_exists( 'product' ) ? quorlyx_pro_collect_recent_content_snapshot( 'product', 6 ) : array()
	);
	$recent_content_list = array();

	foreach ( array_slice( $recent_content, 0, 12 ) as $content_item ) {
		$recent_content_list[] = '- ' . sanitize_text_field( (string) ( $content_item['title'] ?? '' ) ) . ' | ' . esc_url_raw( (string) ( $content_item['url'] ?? '' ) );
	}

	return array(
		'post'          => $post,
		'seo_status'    => $seo_status,
		'content'       => quorlyx_pro_sanitize_guide_text( $plain_content, 4000 ),
		'excerpt'       => quorlyx_pro_sanitize_guide_text( $excerpt, 400 ),
		'type_label'    => sanitize_text_field( $type_label ),
		'public_url'    => esc_url_raw( get_permalink( $post_id ) ),
		'schema_status' => '' !== trim( $schema ) ? 'Schema markup already exists.' : 'No saved schema markup exists yet.',
		'schema'        => quorlyx_pro_sanitize_guide_text( trim( $schema ), 1200 ),
		'recent_links'  => implode( "\n", $recent_content_list ),
	);
}

/**
 * Resolve AI credentials for SEO improvement analysis.
 *
 * @return array<string,string>
 */
function quorlyx_get_seo_improvement_ai_credentials() {
	$options     = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$variation_a = $options['variation_a'];
	$provider    = $variation_a['ai_provider'];
	$api_key     = $variation_a['api_keys'][ $provider ] ?? '';
	$model       = $variation_a['ai_model'];

	return array(
		'provider' => sanitize_key( $provider ),
		'api_key'  => (string) $api_key,
		'model'    => sanitize_text_field( $model ),
	);
}

/**
 * Request SEO improvement analysis for a single post.
 *
 * @param string $provider AI provider slug.
 * @param string $api_key AI provider API key.
 * @param string $model AI model name.
 * @param int    $post_id Target post ID.
 * @return array<string,mixed>|WP_Error
 */
function quorlyx_request_single_seo_improvement_analysis( $provider, $api_key, $model, $post_id ) {
	$context = quorlyx_get_seo_improvement_context( $post_id );
	if ( empty( $context['post'] ) ) {
		return new WP_Error( 'not_found', 'Content item not found.', array( 'status' => 404 ) );
	}

	$seo_status = (array) $context['seo_status'];
	$prompt     = array(
		'Quorlyx SEO tools available:',
		'- Generate Schema Markup',
		'- Suggest Internal Links',
		'- Generate Keyword Ideas with AI',
		'- Analyze a Topic for SEO',
		'',
		'Content to improve:',
		'- Title: ' . sanitize_text_field( get_the_title( $post_id ) ),
		'- Type: ' . sanitize_text_field( $context['type_label'] ?? '' ),
		'- URL: ' . esc_url_raw( $context['public_url'] ?? '' ),
		'- Age in days: ' . number_format_i18n( (int) ( $seo_status['age_days'] ?? 0 ) ),
		'- Word count: ' . number_format_i18n( (int) ( $seo_status['word_count'] ?? 0 ) ),
		'- Internal links found in content: ' . number_format_i18n( (int) ( $seo_status['internal_link_count'] ?? 0 ) ),
		'- Schema status: ' . sanitize_text_field( $context['schema_status'] ?? '' ),
	);

	if ( ! empty( $context['excerpt'] ) ) {
		$prompt[] = '- Excerpt: ' . (string) $context['excerpt'];
	}

	$prompt[] = '';
	$prompt[] = 'Main content:';
	$prompt[] = (string) $context['content'];

	if ( ! empty( $context['recent_links'] ) ) {
		$prompt[] = '';
		$prompt[] = 'Recent internal linking candidates on the same site:';
		$prompt[] = (string) $context['recent_links'];
	}

	if ( ! empty( $context['schema'] ) ) {
		$prompt[] = '';
		$prompt[] = 'Existing schema snippet:';
		$prompt[] = (string) $context['schema'];
	}

	$system_prompt = 'You are an expert SEO content refresh strategist for Quorlyx. Analyze this existing page, post, or product and produce a concise improvement brief. Prioritize practical actions that a site owner can apply immediately. When relevant, explicitly point to Quorlyx tools such as Generate Schema Markup, Suggest Internal Links, Generate Keyword Ideas with AI, and Analyze a Topic for SEO.';
	$prompt[]      = '';
	$prompt[]      = 'Response format requirements:';
	$prompt[]      = '### Priority Actions';
	$prompt[]      = '3 to 5 short bullets.';
	$prompt[]      = '### Related Keywords';
	$prompt[]      = 'List 8 to 12 keyword ideas or semantic phrases.';
	$prompt[]      = '### Schema Markup';
	$prompt[]      = 'State whether to generate or refine schema and why.';
	$prompt[]      = '### Internal Links';
	$prompt[]      = 'State whether to generate or refine internal links and why.';
	$prompt[]      = '### Extra SEO Opportunities';
	$prompt[]      = 'Mention any title, meta description, FAQ, heading, snippet, or product-specific SEO fixes.';
	$prompt[]      = 'Keep the full answer under 350 words.';

	$history  = array(
		array(
			'role'  => 'user',
			'parts' => array(
				array(
					'text' => implode( "\n", $prompt ),
				),
			),
		),
	);
	$response = quorlyx_call_ai_api_with_retry( $provider, $api_key, $model, $system_prompt, $history, 0.4 );
	if ( is_wp_error( $response ) ) {
		return $response;
	}

	return array(
		'context'  => $context,
		'analysis' => quorlyx_pro_sanitize_guide_text( (string) $response, 5000 ),
	);
}

/**
 * Request SEO improvement analysis for a selected scope.
 *
 * @param string              $provider AI provider slug.
 * @param string              $api_key AI provider API key.
 * @param string              $model AI model name.
 * @param array<string,mixed> $scope_context Scope context payload.
 * @return array<string,string>|WP_Error
 */
function quorlyx_request_scope_seo_improvement_analysis( $provider, $api_key, $model, $scope_context ) {
	if ( empty( $scope_context['post_types'] ) ) {
		return new WP_Error( 'invalid_scope', 'Invalid bulk analysis scope.', array( 'status' => 400 ) );
	}

	$prompt = array(
		'Quorlyx SEO tools available:',
		'- Generate Schema Markup',
		'- Suggest Internal Links',
		'- Generate Keyword Ideas with AI',
		'- Analyze a Topic for SEO',
		'',
		'Bulk content group to improve:',
		'- Scope: ' . sanitize_text_field( $scope_context['target_label'] ?? '' ),
		'- Post types included: ' . sanitize_text_field( implode( ', ', (array) ( $scope_context['post_types'] ?? array() ) ) ),
		'- Total published items: ' . number_format_i18n( (int) ( $scope_context['total_published'] ?? 0 ) ),
		'- Recent sample analyzed: ' . number_format_i18n( (int) ( $scope_context['sample_count'] ?? 0 ) ),
		'- Average word count in sample: ' . number_format_i18n( (int) ( $scope_context['average_word_count'] ?? 0 ) ),
		'- Schema coverage in sample (%): ' . number_format_i18n( (float) ( $scope_context['schema_coverage'] ?? 0 ), 1 ),
		'- Short-content items in sample: ' . number_format_i18n( (int) ( $scope_context['short_content_count'] ?? 0 ) ),
		'',
		'Recent sample items:',
		(string) ( $scope_context['item_summaries'] ?? '' ),
	);

	$system_prompt = 'You are an expert SEO content refresh strategist for Quorlyx. Analyze this existing content group and produce a concise improvement brief. Prioritize practical actions that a site owner can apply immediately. When relevant, explicitly point to Quorlyx tools such as Generate Schema Markup, Suggest Internal Links, Generate Keyword Ideas with AI, and Analyze a Topic for SEO.';
	$prompt[]      = '';
	$prompt[]      = 'Response format requirements:';
	$prompt[]      = '### Priority Actions';
	$prompt[]      = '3 to 5 short bullets.';
	$prompt[]      = '### Related Keywords';
	$prompt[]      = 'List 8 to 12 keyword clusters or semantic themes for this selected group.';
	$prompt[]      = '### Schema Markup';
	$prompt[]      = 'State whether to generate or refine schema and why.';
	$prompt[]      = '### Internal Links';
	$prompt[]      = 'State whether to generate or refine internal links and why.';
	$prompt[]      = '### Extra SEO Opportunities';
	$prompt[]      = 'Mention any title, meta description, FAQ, heading, snippet, or product-specific SEO fixes.';
	$prompt[]      = 'Keep the full answer under 350 words.';

	$history  = array(
		array(
			'role'  => 'user',
			'parts' => array(
				array(
					'text' => implode( "\n", $prompt ),
				),
			),
		),
	);
	$response = quorlyx_call_ai_api_with_retry( $provider, $api_key, $model, $system_prompt, $history, 0.4 );
	if ( is_wp_error( $response ) ) {
		return $response;
	}

	return array(
		'analysis' => quorlyx_pro_sanitize_guide_text( (string) $response, 5000 ),
	);
}

/**
 * REST endpoint to delete a saved SEO suggestion.
 *
 * @param WP_REST_Request $request REST request instance.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_rest_delete_saved_seo_suggestion( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		return $nonce_ok;
	}

	$suggestion_id = sanitize_key( $request->get_param( 'suggestion_id' ) );
	if ( '' === $suggestion_id ) {
		return new WP_Error( 'missing_suggestion_id', 'Missing saved suggestion ID.', array( 'status' => 400 ) );
	}

	$suggestions = quorlyx_delete_saved_seo_suggestion( $suggestion_id, get_current_user_id() );

	Quorlyx_Pro_Logger::log(
		'info',
		'SEO suggestion deleted',
		array(
			'suggestion_id' => $suggestion_id,
			'user_id'       => get_current_user_id(),
		)
	);

	return new WP_REST_Response(
		array(
			'success'     => true,
			'suggestions' => $suggestions,
		),
		200
	);
}

/**
 * REST endpoint to mark SEO improved state for a post.
 *
 * @param WP_REST_Request $request REST request instance.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_rest_set_seo_improved_status( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		return $nonce_ok;
	}

	$post_id  = absint( $request->get_param( 'post_id' ) );
	$improved = rest_sanitize_boolean( $request->get_param( 'improved' ) );

	if ( $post_id <= 0 || ! current_user_can( 'edit_post', $post_id ) ) {
		return new WP_Error( 'invalid_post', 'Content item not found or not editable.', array( 'status' => 404 ) );
	}

	if ( $improved ) {
		update_post_meta( $post_id, '_quorlyx_seo_improved', '1' );
	} else {
		delete_post_meta( $post_id, '_quorlyx_seo_improved' );
	}

	$suggestions = quorlyx_get_saved_seo_suggestions( get_current_user_id() );
	foreach ( $suggestions as &$suggestion ) {
		if ( absint( $suggestion['post_id'] ?? 0 ) === $post_id ) {
			$suggestion['is_improved'] = $improved;
			$suggestion['updated_at']  = time();
		}
	}
	unset( $suggestion );
	$suggestions = quorlyx_save_seo_suggestions( $suggestions, get_current_user_id() );

	Quorlyx_Pro_Logger::log(
		'info',
		'SEO improved status updated',
		array(
			'post_id'  => $post_id,
			'improved' => $improved,
			'user_id'  => get_current_user_id(),
		)
	);

	return new WP_REST_Response(
		array(
			'success'     => true,
			'post_id'     => $post_id,
			'improved'    => $improved,
			'suggestions' => $suggestions,
		),
		200
	);
}

/**
 * REST endpoint to generate SEO improvement suggestions.
 *
 * @param WP_REST_Request $request REST request instance.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_rest_suggest_seo_improvements( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		Quorlyx_Pro_Logger::log(
			'error',
			'SEO improvement request failed nonce verification',
			array(
				'post_id'      => absint( $request->get_param( 'post_id' ) ),
				'target_scope' => sanitize_key( $request->get_param( 'target_scope' ) ),
			)
		);
		return $nonce_ok;
	}

	$request_params = $request->get_params();
	$post_id        = absint( $request->get_param( 'post_id' ) );
	$target_scope   = sanitize_key( $request->get_param( 'target_scope' ) );
	$post_ids       = $request->get_param( 'post_ids' );
	$target_scopes  = $request->get_param( 'target_scopes' );

	if ( empty( $post_ids ) && isset( $request_params['post_ids'] ) ) {
		$post_ids = $request_params['post_ids'];
	} elseif ( empty( $post_ids ) && isset( $request_params['post_ids[]'] ) ) {
		$post_ids = $request_params['post_ids[]'];
	}

	if ( empty( $target_scopes ) && isset( $request_params['target_scopes'] ) ) {
		$target_scopes = $request_params['target_scopes'];
	} elseif ( empty( $target_scopes ) && isset( $request_params['target_scopes[]'] ) ) {
		$target_scopes = $request_params['target_scopes[]'];
	}

	$post_ids      = array_values( array_unique( array_filter( array_map( 'absint', (array) $post_ids ) ) ) );
	$target_scopes = array_values( array_unique( array_filter( array_map( 'sanitize_key', (array) $target_scopes ) ) ) );

	if ( $post_id > 0 ) {
		$post_ids[] = $post_id;
	}
	if ( '' !== $target_scope ) {
		$target_scopes[] = $target_scope;
	}

	$post_ids      = array_values( array_unique( array_filter( array_map( 'absint', $post_ids ) ) ) );
	$target_scopes = array_values( array_unique( array_filter( array_map( 'sanitize_key', $target_scopes ) ) ) );

	if ( empty( $post_ids ) && empty( $target_scopes ) ) {
		Quorlyx_Pro_Logger::log(
			'error',
			'SEO improvement request missing target',
			array(
				'post_ids'      => $post_ids,
				'target_scopes' => $target_scopes,
			)
		);
		return new WP_Error( 'missing_target', 'Select a content item or a bulk scope first.', array( 'status' => 400 ) );
	}

	$allowed_post_ids = array();
	foreach ( $post_ids as $candidate_post_id ) {
		if ( current_user_can( 'edit_post', $candidate_post_id ) ) {
			$allowed_post_ids[] = $candidate_post_id;
		}
	}

	if ( ! empty( $post_ids ) && empty( $allowed_post_ids ) ) {
			Quorlyx_Pro_Logger::log(
				'error',
				'SEO improvement request denied for all selected posts',
				array(
					'post_ids'      => $post_ids,
					'target_scopes' => $target_scopes,
				)
			);
			return new WP_Error( 'not_found', 'Content item not found or not editable.', array( 'status' => 404 ) );
	}

	$scope_contexts = array();

	foreach ( $target_scopes as $scope ) {
		$scope_context = quorlyx_get_bulk_seo_improvement_context( $scope );
		if ( empty( $scope_context['post_types'] ) ) {
			Quorlyx_Pro_Logger::log(
				'error',
				'SEO improvement request used invalid bulk scope',
				array(
					'post_ids'      => $allowed_post_ids,
					'target_scopes' => $target_scopes,
					'invalid_scope' => $scope,
				)
			);
			return new WP_Error( 'invalid_scope', 'Invalid bulk analysis scope.', array( 'status' => 400 ) );
		}
		$scope_contexts[] = $scope_context;
	}

	$credentials = quorlyx_get_seo_improvement_ai_credentials();
	$provider    = $credentials['provider'];
	$api_key     = $credentials['api_key'];
	$model       = $credentials['model'];

	if ( empty( $api_key ) || empty( $model ) ) {
		Quorlyx_Pro_Logger::log(
			'error',
			'SEO improvement request missing AI configuration',
			array(
				'post_ids'      => $allowed_post_ids,
				'target_scopes' => $target_scopes,
				'provider'      => sanitize_key( $provider ),
			)
		);
		return new WP_Error( 'no_api_key_or_model', 'API key and model for Variation A must be set.', array( 'status' => 400 ) );
	}

	$generated_suggestions = array();
	$combined_analysis     = array();

	foreach ( $allowed_post_ids as $selected_post_id ) {
		$analysis_result = quorlyx_request_single_seo_improvement_analysis( $provider, $api_key, $model, $selected_post_id );
		if ( is_wp_error( $analysis_result ) ) {
			Quorlyx_Pro_Logger::log(
				'error',
				'SEO improvement AI request failed for post',
				array(
					'post_id'  => $selected_post_id,
					'provider' => sanitize_key( $provider ),
					'model'    => sanitize_text_field( $model ),
					'error'    => sanitize_text_field( $analysis_result->get_error_message() ),
				)
			);
			return $analysis_result;
		}

		$context                 = (array) $analysis_result['context'];
		$generated_suggestions[] = array(
			'target_type'  => 'post',
			'post_id'      => $selected_post_id,
			'post_type'    => sanitize_key( $context['post']->post_type ?? '' ),
			'title'        => sanitize_text_field( get_the_title( $selected_post_id ) ),
			'label'        => sanitize_text_field( $context['type_label'] ?? 'Content' ),
			'url'          => esc_url_raw( $context['public_url'] ?? '' ),
			'analysis'     => (string) $analysis_result['analysis'],
			'is_generated' => '1' === (string) get_post_meta( $selected_post_id, '_quorlyx_generated', true ),
			'is_improved'  => quorlyx_is_content_improved( $selected_post_id ),
			'updated_at'   => time(),
		);

		$combined_analysis[] = '### ' . sanitize_text_field( get_the_title( $selected_post_id ) ) . "\n" . (string) $analysis_result['analysis'];
	}

	foreach ( $scope_contexts as $scope_context ) {
		$scope_result = quorlyx_request_scope_seo_improvement_analysis( $provider, $api_key, $model, $scope_context );
		if ( is_wp_error( $scope_result ) ) {
			Quorlyx_Pro_Logger::log(
				'error',
				'SEO improvement AI request failed for scope',
				array(
					'target_scope' => sanitize_key( $scope_context['target_scope'] ?? '' ),
					'provider'     => sanitize_key( $provider ),
					'model'        => sanitize_text_field( $model ),
					'error'        => sanitize_text_field( $scope_result->get_error_message() ),
				)
			);
			return $scope_result;
		}

		$generated_suggestions[] = array(
			'target_type'  => 'scope',
			'scope'        => sanitize_key( $scope_context['target_scope'] ?? '' ),
			'title'        => sanitize_text_field( $scope_context['target_label'] ?? 'Selected Content' ),
			'label'        => 'Bulk Scope',
			'url'          => '',
			'analysis'     => (string) $scope_result['analysis'],
			'is_generated' => false,
			'is_improved'  => false,
			'updated_at'   => time(),
		);

		$combined_analysis[] = '### ' . sanitize_text_field( $scope_context['target_label'] ?? 'Selected Content' ) . "\n" . (string) $scope_result['analysis'];
	}

	$saved_suggestions = quorlyx_upsert_saved_seo_suggestions( $generated_suggestions, get_current_user_id() );

	Quorlyx_Pro_Logger::log(
		'info',
		'SEO improvement analysis generated',
		array(
			'post_ids'      => $allowed_post_ids,
			'target_scopes' => $target_scopes,
			'provider'      => sanitize_key( $provider ),
			'model'         => sanitize_text_field( $model ),
		)
	);

	return new WP_REST_Response(
		array(
			'success'         => true,
			'analysis'        => quorlyx_pro_sanitize_guide_text( implode( "\n\n", $combined_analysis ), 5000 ),
			'suggestions'     => $saved_suggestions,
			'generated_count' => count( $generated_suggestions ),
		),
		200
	);
}

/**
 * REST endpoint to run guide health checks.
 *
 * @param WP_REST_Request $request REST request instance.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_rest_guide_health_check( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		return $nonce_ok;
	}

	$snapshot = quorlyx_pro_get_site_snapshot();
	$findings = quorlyx_pro_detect_technical_findings( $snapshot );
	$probe    = quorlyx_pro_probe_frontend_runtime();
	$health   = quorlyx_pro_run_guide_health_check( $snapshot, $findings, $probe );
	$report   = quorlyx_pro_build_guide_health_report( $health );

	return new WP_REST_Response(
		array(
			'success'  => true,
			'summary'  => $health['summary'],
			'checks'   => $health['checks'],
			'report'   => $report,
			'findings' => $findings,
			'probe'    => $probe,
		),
		200
	);
}

/**
 * REST endpoint to run a lightweight frontend probe.
 *
 * @param WP_REST_Request $request REST request instance.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_rest_guide_frontend_probe( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		return $nonce_ok;
	}

	$probe = quorlyx_pro_probe_frontend_runtime();

	return new WP_REST_Response(
		array(
			'success' => true,
			'probe'   => $probe,
		),
		200
	);
}

/**
 * REST endpoint for admin guide chat responses.
 *
 * @param WP_REST_Request $request REST request instance.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_rest_guide_chat( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		return $nonce_ok;
	}

	$params   = $request->get_json_params();
	$question = sanitize_textarea_field( $params['question'] ?? '' );
	if ( '' === trim( $question ) ) {
		return new WP_Error( 'missing_question', 'Please enter a question for the guide.', array( 'status' => 400 ) );
	}
	$history_in = $params['history'] ?? array();

	$snapshot      = quorlyx_pro_get_site_snapshot();
	$findings      = quorlyx_pro_detect_technical_findings( $snapshot );
	$readme_source = quorlyx_pro_get_guide_readme_context();

	$options     = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$variation_a = $options['variation_a'] ?? array();
	$provider    = sanitize_key( $variation_a['ai_provider'] ?? 'gemini' );
	$api_key     = sanitize_text_field( $variation_a['api_keys'][ $provider ] ?? '' );
	$model       = sanitize_text_field( $variation_a['ai_model'] ?? '' );

	$used_fallback = false;
	$answer        = '';
	$chat_history  = quorlyx_pro_normalize_guide_history( $history_in, 20 );

	if ( empty( $chat_history ) || ! isset( $chat_history[ count( $chat_history ) - 1 ]['parts'][0]['text'] ) || trim( $question ) !== $chat_history[ count( $chat_history ) - 1 ]['parts'][0]['text'] ) {
		$chat_history[] = array(
			'role'  => 'user',
			'parts' => array(
				array(
					'text' => trim( $question ),
				),
			),
		);
	}

	if ( ! empty( $api_key ) && ! empty( $model ) ) {
		$prompt_lines  = array(
			'Latest admin question: ' . $question,
			'',
			'PLUGIN GUIDE CONTEXT (README.md):',
			$readme_source,
			'',
			'SITE SNAPSHOT:',
			wp_json_encode( $snapshot ),
			'',
			'TECHNICAL FINDINGS:',
			wp_json_encode( $findings ),
			'',
			'Instructions:',
			'1) Answer as Quorlyx admin guide. Be practical, accurate, and step-by-step.',
			'2) Base guidance primarily on README context and current site snapshot.',
			'3) If WooCommerce is asked, explicitly include connection/setup checks.',
			'4) Treat this as a multi-turn chat: use previous messages to resolve follow-up requests such as "explain step 2".',
			'5) When user asks for deeper explanation, break down into: Goal, Why, Exact Steps, Validation Checks, Common mistakes.',
			'6) Include a short "Technical Checks" section based on findings.',
			'7) This is admin-only support. Do not suggest public-site chat UI changes.',
		);
		$system_prompt = 'You are Quorlyx Pro admin setup assistant. Give clear, deep, actionable steps and handle follow-up clarification requests precisely.';

		$history = array_merge(
			array(
				array(
					'role'  => 'user',
					'parts' => array(
						array(
							'text' => implode( "\n", $prompt_lines ),
						),
					),
				),
			),
			$chat_history
		);

		$ai_response = quorlyx_call_ai_api_with_retry(
			$provider,
			$api_key,
			$model,
			$system_prompt,
			$history,
			0.2
		);

		if ( is_wp_error( $ai_response ) ) {
			$used_fallback = true;
			$answer        = quorlyx_pro_guide_fallback_answer( $question, $snapshot, $findings );
		} else {
			$answer = (string) $ai_response;
		}
	} else {
		$used_fallback = true;
		$answer        = quorlyx_pro_guide_fallback_answer( $question, $snapshot, $findings );
	}

	$chat_history[] = array(
		'role'  => 'model',
		'parts' => array(
			array(
				'text' => quorlyx_pro_sanitize_guide_text( (string) $answer, 12000 ),
			),
		),
	);
	if ( count( $chat_history ) > 20 ) {
		$chat_history = array_slice( $chat_history, -20 );
	}

	return new WP_REST_Response(
		array(
			'success'       => true,
			'answer'        => $answer,
			'used_fallback' => $used_fallback,
			'findings'      => $findings,
			'history'       => quorlyx_pro_flatten_guide_history_for_response( $chat_history ),
		),
		200
	);
}

/**
 * Resolve AI configuration for Content Insights suggestion requests.
 *
 * @param array<string,mixed> $options Plugin options.
 * @return array<string,string>|WP_Error
 */
function quorlyx_get_content_insights_ai_config( $options ) {
	$variation_a = $options['variation_a'] ?? array();
	$provider    = sanitize_key( $variation_a['ai_provider'] ?? '' );
	$api_key     = sanitize_text_field( $variation_a['api_keys'][ $provider ] ?? '' );
	$model       = sanitize_text_field( $variation_a['ai_model'] ?? '' );

	if ( '' !== $provider && '' !== $api_key && '' !== $model ) {
		return array(
			'provider' => $provider,
			'api_key'  => $api_key,
			'model'    => $model,
			'source'   => 'variation_a',
		);
	}

	$post_generator = $options['post_generator'] ?? array();
	if ( 'independent' === ( $post_generator['ai_provider_scope'] ?? 'general' ) ) {
		$provider = sanitize_key( $post_generator['ai_provider'] ?? '' );
		$api_key  = sanitize_text_field( $post_generator['ai_api_key'] ?? ( $post_generator['api_keys'][ $provider ] ?? '' ) );
		$model    = sanitize_text_field( $post_generator['ai_model'] ?? '' );

		if ( '' !== $provider && '' !== $api_key && '' !== $model ) {
			return array(
				'provider' => $provider,
				'api_key'  => $api_key,
				'model'    => $model,
				'source'   => 'content_engine',
			);
		}
	}

	return new WP_Error(
		'missing_ai_config',
		'Configure Variation A AI provider, API key, and model before requesting AI suggestions.',
		array( 'status' => 400 )
	);
}

/**
 * Build feature context text for Content Insights AI prompts.
 *
 * @param array<string,mixed> $options Plugin options.
 * @param array<string,mixed> $settings Content Insights settings.
 * @return string
 */
function quorlyx_get_content_insights_feature_context( $options, $settings ) {
	$trigger_lines = array();
	$behavior_settings = quorlyx_get_behavior_pattern_settings( $settings );
	$behavior_enabled  = quorlyx_behavior_patterns_are_enabled( $settings );
	foreach ( (array) ( $options['triggers'] ?? array() ) as $trigger ) {
		$trigger_type = sanitize_key( $trigger['type'] ?? '' );
		if ( '' === $trigger_type ) {
			continue;
		}

		$type_label      = str_replace( '_', ' ', $trigger_type );
		$scope           = sanitize_key( $trigger['ab_scope'] ?? 'all' );
		$target          = sanitize_text_field( $trigger['target_page_url'] ?? '' );
		$target          = '' !== $target ? $target : 'all pages';
		$trigger_lines[] = sprintf( '%1$s trigger targeting %2$s (A/B scope: %3$s)', $type_label, $target, $scope );
	}

	if ( empty( $trigger_lines ) ) {
		$trigger_lines[] = 'No proactive triggers are configured yet.';
	}

	$lines = array(
		'Quorlyx features available for recommendation:',
		'- Settings > Chatbot > Triggers supports time-on-page, scroll-depth, and exit-intent triggers.',
		'- Each trigger can target page URLs, exclude URL patterns, and use a proactive message.',
		'- If A/B testing is enabled, triggers can be limited to variation A, variation B, or all variations.',
		'- Settings > Chatbot > Variation A and Variation B can change opening copy, welcome behavior, and overall chat experience.',
		'- Quorlyx SEO tools include Generate Keyword Ideas with AI, Analyze a Topic for SEO, Generate Schema Markup, Suggest Internal Links, and the SEO improvement planner for existing content.',
		'- Content Insights can track all public content, selected post types, or target page URLs with include and exclude rules.',
		'- Content Insights can filter by any content, AI-generated content, or manual content.',
		'- Behavior Pattern Engine can classify tracked profiles into fast/medium/slow leaver, comparison shopper, fast closer, and discoverer closer segments.',
		'- WooCommerce/add-to-cart signals can justify exit-intent reassurance or cart-focused prompts.',
		'- Recommend only actions that can be configured inside Quorlyx. Do not suggest external tools, custom code, or features Quorlyx does not have.',
		'',
		'Current Quorlyx state:',
		'- A/B testing enabled: ' . ( ! empty( $options['ab_testing_enabled'] ) ? 'yes' : 'no' ),
		'- Content Insights tracking mode: ' . sanitize_text_field( str_replace( '_', ' ', $settings['tracking_mode'] ?? 'all_public' ) ),
		'- Content Insights content source filter: ' . sanitize_text_field( str_replace( '_', ' ', $settings['content_source'] ?? 'any' ) ),
		'- Content Insights conversion counting: ' . sanitize_text_field( 'conversion_goals' === quorlyx_get_content_insights_conversion_tracking_mode( $settings ) ? 'only configured Conversion Goals' : 'any conversion signal' ),
		'- Global DB-first data mode: ' . ( ! empty( $settings['prefer_db_processing_global'] ) ? 'yes' : 'no' ),
		'- Behavior Pattern Engine enabled: ' . ( $behavior_enabled ? 'yes' : 'no' ),
		'- Behavior non-converter sample rate: ' . number_format_i18n( (int) ( $behavior_settings['non_converter_sample_rate'] ?? 100 ) ) . '%',
		'- Active trigger summary: ' . implode( '; ', $trigger_lines ),
		'- WooCommerce active: ' . ( class_exists( 'WooCommerce' ) ? 'yes' : 'no' ),
	);

	return implode( "\n", $lines );
}

/**
 * Build content context text for a Content Insights item.
 *
 * @param int    $post_id Post ID.
 * @param string $content_key Content key.
 * @return string
 */
function quorlyx_get_content_insight_content_context( $post_id, $content_key = '' ) {
	$post_id     = absint( $post_id );
	$content_key = sanitize_key( $content_key );

	if ( $post_id > 0 ) {
		$post = get_post( $post_id );
		if ( ! $post instanceof WP_Post ) {
			return 'No content context available.';
		}

		$lines = array(
			'Content context:',
			'- Title: ' . sanitize_text_field( get_the_title( $post_id ) ),
			'- Type: ' . sanitize_text_field( $post->post_type ),
		);

		$excerpt = trim( wp_strip_all_tags( (string) $post->post_excerpt ) );
		if ( '' !== $excerpt ) {
			$lines[] = '- Excerpt: ' . quorlyx_pro_sanitize_guide_text( $excerpt, 400 );
		}

		$content = trim( wp_strip_all_tags( (string) $post->post_content ) );
		if ( '' !== $content ) {
			$lines[] = '- Main content summary: ' . quorlyx_pro_sanitize_guide_text( $content, 1800 );
		}

		if ( 'product' === $post->post_type && function_exists( 'wc_get_product' ) ) {
			$product = wc_get_product( $post_id );
			if ( $product ) {
				$short_description = trim( wp_strip_all_tags( (string) $product->get_short_description() ) );
				$price_html        = trim( wp_strip_all_tags( (string) $product->get_price_html() ) );
				if ( '' !== $short_description ) {
					$lines[] = '- Product short description: ' . quorlyx_pro_sanitize_guide_text( $short_description, 500 );
				}
				if ( '' !== $price_html ) {
					$lines[] = '- Product price info: ' . sanitize_text_field( $price_html );
				}
			}
		}

		return implode( "\n", $lines );
	}

	if ( 'homepage' === $content_key ) {
		$recent_posts = get_posts(
			array(
				'post_type'              => 'post',
				'post_status'            => 'publish',
				'posts_per_page'         => 5,
				'orderby'                => 'date',
				'order'                  => 'DESC',
				'ignore_sticky_posts'    => true,
				'no_found_rows'          => true,
				'update_post_meta_cache' => false,
				'update_post_term_cache' => false,
			)
		);

		$lines = array(
			'Content context:',
			'- This is the site homepage/blog index.',
			'- Site title: ' . sanitize_text_field( get_bloginfo( 'name' ) ),
			'- Site tagline: ' . sanitize_text_field( get_bloginfo( 'description' ) ),
		);

		if ( ! empty( $recent_posts ) ) {
			$post_summaries = array();
			foreach ( $recent_posts as $post ) {
				$post_summaries[] = sanitize_text_field( get_the_title( $post ) );
			}
			$lines[] = '- Recent posts shown on homepage: ' . implode( '; ', array_slice( $post_summaries, 0, 5 ) );
		}

		return implode( "\n", $lines );
	}

	return 'No content context available.';
}

/**
 * Determine AI recommendation guardrails for an insight item.
 *
 * @param array<string,mixed> $row Insight row data.
 * @return array<string,mixed>
 */
function quorlyx_get_content_insight_ai_rule_set( $row ) {
	$views       = absint( $row['views'] ?? 0 );
	$avg_time    = absint( $row['avg_time'] ?? 0 );
	$scroll      = absint( $row['scroll_depth'] ?? 0 );
	$add_to_cart = absint( $row['add_to_cart'] ?? 0 );
	$post_id     = absint( $row['post_id'] ?? 0 );
	$seo_status  = (array) ( $row['seo_status'] ?? array() );
	$seo_only    = $post_id > 0 && $views < 50 && ! empty( $seo_status['eligible'] );

	$allowed   = array();
	$forbidden = array();
	$notes     = array();

	if ( $seo_only ) {
		$allowed[]   = 'seo_improvement_plan';
		$allowed[]   = 'schema_markup';
		$allowed[]   = 'internal_links';
		$allowed[]   = 'related_keywords';
		$forbidden[] = 'scroll_depth_trigger';
		$forbidden[] = 'time_on_page_trigger';
		$forbidden[] = 'exit_intent_trigger';
		$forbidden[] = 'major_trigger_change';
		$forbidden[] = 'welcome_message_rewrite';
		$forbidden[] = 'chat_setting_change';
		$notes[]     = 'This item does not have enough traffic yet, so recommend only SEO improvement actions such as related keywords, schema markup, internal links, or refreshing older content.';
		$notes[]     = 'Do not recommend chatbot copy changes, welcome-message tweaks, or trigger changes before the content has real visit data.';

		return array(
			'allowed'   => array_values( array_unique( $allowed ) ),
			'forbidden' => array_values( array_unique( $forbidden ) ),
			'notes'     => $notes,
			'seo_only'  => true,
		);
	}

	if ( $scroll >= 60 ) {
		$allowed[] = 'scroll_depth_trigger';
		$notes[]   = 'Scroll-depth trigger is valid only because users already reach meaningful scroll depth.';
	} else {
		$forbidden[] = 'scroll_depth_trigger';
		$notes[]     = 'Do not recommend a scroll-depth trigger when observed scroll depth is low because users are not reaching that threshold.';
	}

	if ( $avg_time >= 30 ) {
		$allowed[] = 'time_on_page_trigger';
		$notes[]   = 'A time-on-page opener is valid only when users stay long enough to see it.';
	} else {
		$forbidden[] = 'time_on_page_trigger';
		$notes[]     = 'Do not recommend a time-on-page trigger when average time is too short for a delayed opener to appear consistently.';
	}

	if ( $add_to_cart > 0 ) {
		$allowed[] = 'exit_intent_trigger';
		$notes[]   = 'Exit-intent reassurance is strongest when buying intent already exists.';
	}

	if ( $views < 50 ) {
		$forbidden[] = 'major_trigger_change';
		$notes[]     = 'Traffic is still thin, so avoid confident major trigger changes and focus on collecting more data first.';
	}

	if ( $scroll < 15 && $avg_time < 15 ) {
		$allowed[] = 'shorter_opening_message';
		$allowed[] = 'welcome_message_rewrite';
		$notes[]   = 'When both scroll and time are weak, prefer a shorter welcome message or clearer first CTA rather than delayed triggers.';
	}

	return array(
		'allowed'   => array_values( array_unique( $allowed ) ),
		'forbidden' => array_values( array_unique( $forbidden ) ),
		'notes'     => $notes,
		'seo_only'  => false,
	);
}

/**
 * Check whether an AI suggestion violates guardrail rules.
 *
 * @param string              $response Suggested response text.
 * @param array<string,mixed> $rule_set Rule set payload.
 * @return bool
 */
function quorlyx_content_insight_response_violates_rules( $response, $rule_set ) {
	$text = strtolower( (string) $response );
	if ( '' === trim( $text ) ) {
		return true;
	}

	$forbidden_map = array(
		'scroll_depth_trigger'    => '/scroll[- ]depth|scroll trigger/',
		'time_on_page_trigger'    => '/time[- ]on[- ]page|delay(?:ed)? trigger|trigger chat after/',
		'exit_intent_trigger'     => '/exit[- ]intent/',
		'major_trigger_change'    => '/create a new trigger|configure .* trigger|add .* trigger/',
		'welcome_message_rewrite' => '/welcome message|opening copy|welcome behavior|first message/',
		'chat_setting_change'     => '/settings > chatbot > variation|chatbot\'s welcome|chat setting|opening copy|welcome behavior/',
	);

	foreach ( (array) ( $rule_set['forbidden'] ?? array() ) as $forbidden_key ) {
		if ( isset( $forbidden_map[ $forbidden_key ] ) && preg_match( $forbidden_map[ $forbidden_key ], $text ) ) {
			return true;
		}
	}

	return false;
}

/**
 * Build a deterministic fallback suggestion for an insight row.
 *
 * @param array<string,mixed> $row Insight row data.
 * @return string
 */
function quorlyx_get_content_insight_safe_fallback_suggestion( $row ) {
	$views          = absint( $row['views'] ?? 0 );
	$avg_time       = absint( $row['avg_time'] ?? 0 );
	$scroll_depth   = absint( $row['scroll_depth'] ?? 0 );
	$add_to_cart    = absint( $row['add_to_cart'] ?? 0 );
	$post_id        = absint( $row['post_id'] ?? 0 );
	$decision_label = sanitize_text_field( (string) ( $row['decision']['label'] ?? 'Watch' ) );

	if ( $views < 50 ) {
		if ( $post_id > 0 ) {
			return "Primary action: Run an SEO improvement refresh before changing triggers.\nWhy: This content is underexposed, so stronger keywords, schema, and internal links are more important than a new chatbot trigger right now.\nHow to apply in Quorlyx:\n1. Open SEO & Content Tools and use Improve Existing Content for this item.\n2. Generate related keywords and refresh the copy around the strongest search terms.\n3. Use Generate Schema Markup if no schema exists yet.\n4. Use Suggest Internal Links to support discovery from related pages.\nWatch next: Views";
		}

		return "Primary action: Keep this page under observation until it gathers more traffic.\nWhy: The page does not yet have enough visits to justify a reliable trigger or chat-setting change.\nHow to apply in Quorlyx:\n1. Keep Content Insights tracking enabled for this page or URL rule.\n2. Leave trigger settings unchanged for now instead of adding a new trigger too early.\n3. Recheck this item after it accumulates more views and clearer engagement data.\nWatch next: Views";
	}

	if ( $add_to_cart > 0 && 0 === absint( $row['conversions'] ?? 0 ) ) {
		return "Primary action: Add exit-intent reassurance for this product or product-related page.\nWhy: Visitors show buying intent through add-to-cart activity but still drop off before converting.\nHow to apply in Quorlyx:\n1. Go to Settings > Chatbot > Triggers.\n2. Create an Exit Intent trigger for this page URL.\n3. Use a proactive message that answers pricing, shipping, returns, or trust concerns.\n4. If A/B testing is enabled, test the reassurance message in one variation first.\nWatch next: Conversions";
	}

	if ( $scroll_depth < 15 && $avg_time < 15 ) {
		return "Primary action: Shorten the first message and make the opening CTA clearer.\nWhy: Visitors leave before they scroll or stay long enough for a delayed trigger, so a scroll-based recommendation would not be logical here.\nHow to apply in Quorlyx:\n1. Go to Settings > Chatbot > Variation A.\n2. Rewrite the welcome message so it is shorter and focused on one clear next step.\n3. If A/B testing is enabled, test a tighter opener in Variation B against the current copy.\n4. Keep trigger timing simple until engagement improves.\nWatch next: Avg. Time";
	}

	if ( $avg_time >= 30 && $scroll_depth < 60 ) {
		$delay_seconds = max( 10, min( 30, (int) round( $avg_time * 0.5 ) ) );
		return "Primary action: Use a time-on-page opener instead of a scroll trigger.\nWhy: Visitors stay on the page long enough to see a timed opener, but they do not scroll deeply enough for a scroll-based trigger to be reliable.\nHow to apply in Quorlyx:\n1. Go to Settings > Chatbot > Triggers.\n2. Create a Time on Page trigger for this page URL.\n3. Set the delay to about {$delay_seconds} seconds.\n4. Use a proactive message that summarizes the page and offers help with the next step.\nWatch next: Avg. Time";
	}

	if ( $scroll_depth >= 60 ) {
		$trigger_depth = max( 50, min( 90, $scroll_depth - 5 ) );
		return "Primary action: Test a scroll-depth trigger tied to the lower part of the page.\nWhy: Visitors already reach meaningful depth, so a scroll-based prompt can appear at a point users actually reach.\nHow to apply in Quorlyx:\n1. Go to Settings > Chatbot > Triggers.\n2. Create a Scroll Depth trigger for this page URL.\n3. Set the depth near {$trigger_depth}%.\n4. Use a proactive message that matches the page content and asks about the next likely question.\nWatch next: Conversion Rate";
	}

	return "Primary action: Keep the current setup and monitor one more traffic cycle.\nWhy: The current signals are mixed and do not strongly support a new trigger type yet.\nHow to apply in Quorlyx:\n1. Keep this page inside Content Insights tracking.\n2. Review the existing welcome message in Settings > Chatbot > Variation A.\n3. Make only small copy improvements instead of adding a new trigger immediately.\n4. Recheck the item after more engagement data is collected.\nWatch next: {$decision_label}";
}

/**
 * REST endpoint to generate a Content Insights AI suggestion.
 *
 * @param WP_REST_Request $request REST request instance.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_rest_content_insight_suggestion( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		return $nonce_ok;
	}

	$params      = $request->get_json_params();
	$post_id     = absint( $params['post_id'] ?? 0 );
	$content_key = sanitize_key( $params['content_key'] ?? '' );

	if ( 0 === $post_id && '' === $content_key ) {
		return new WP_Error( 'missing_item', 'Insight item is required.', array( 'status' => 400 ) );
	}

	$options  = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$options  = array_replace_recursive( quorlyx_get_global_defaults(), $options );
	$settings = $options['content_insights'] ?? array();
	$row      = quorlyx_get_content_insight_row( $settings, $post_id, $content_key );

	if ( ! is_array( $row ) ) {
		return new WP_Error( 'insight_not_found', 'Could not resolve this insight item from current tracking rules.', array( 'status' => 404 ) );
	}

	$ai_config = quorlyx_get_content_insights_ai_config( $options );
	if ( is_wp_error( $ai_config ) ) {
		return $ai_config;
	}

	$feature_context = quorlyx_get_content_insights_feature_context( $options, $settings );
	$content_context = quorlyx_get_content_insight_content_context( $post_id, $content_key );
	$rule_set        = quorlyx_get_content_insight_ai_rule_set( $row );
	$seo_only_mode   = ! empty( $rule_set['seo_only'] );
	$behavior_snapshot = is_array( $row['behavior_snapshot'] ?? null ) ? $row['behavior_snapshot'] : array();
	$heuristics      = array();
	foreach ( (array) ( $row['recommendations'] ?? array() ) as $recommendation ) {
		$heuristics[] = '- ' . sanitize_text_field( (string) ( $recommendation['label'] ?? '' ) ) . ': ' . sanitize_text_field( (string) ( $recommendation['details'] ?? '' ) );
	}

	$system_prompt = 'You are Quorlyx Pro Content Insights strategist. Recommend only actions that can actually be configured inside Quorlyx. Map each suggestion to exact Quorlyx areas such as Settings > Chatbot > Triggers, Settings > Chatbot > Variation A, Settings > Chatbot > Variation B, SEO & Content Tools, or Content Insights tracking rules. Use both the metrics and the actual page content. If an action family is marked as forbidden, never recommend it.';
	$prompt_lines  = array(
		$feature_context,
		'',
		$content_context,
		'',
		'Insight item data:',
		'- Title: ' . sanitize_text_field( (string) ( $row['title'] ?? '' ) ),
		'- Public URL: ' . esc_url_raw( (string) ( $row['public_url'] ?? '' ) ),
		'- Content type: ' . sanitize_text_field( (string) ( $row['post_type'] ?? '' ) ),
		'- Source: ' . sanitize_text_field( (string) ( $row['source_label'] ?? '' ) ),
		'- Views: ' . absint( $row['views'] ?? 0 ),
		'- Avg time on page (seconds): ' . absint( $row['avg_time'] ?? 0 ),
		'- Scroll depth (%): ' . absint( $row['scroll_depth'] ?? 0 ),
		'- Add to cart: ' . absint( $row['add_to_cart'] ?? 0 ),
		'- Checkout visits: ' . absint( $row['checkout_visits'] ?? 0 ),
		'- Checkout success: ' . absint( $row['checkout_success'] ?? 0 ),
		'- Cart drop-off (cart to checkout): ' . absint( $row['cart_drop_off'] ?? 0 ),
		'- Checkout drop-off (checkout to purchase): ' . absint( $row['checkout_drop_off'] ?? 0 ),
		'- Conversions: ' . absint( $row['conversions'] ?? 0 ),
		'- Conversion rate (%): ' . number_format( (float) ( $row['conversion_rate'] ?? 0 ), 2, '.', '' ),
		'- Current decision: ' . sanitize_text_field( (string) ( $row['decision']['label'] ?? '' ) ),
		'- Decision reason: ' . sanitize_text_field( (string) ( $row['decision']['reason'] ?? '' ) ),
		'- SEO-priority mode: ' . ( $seo_only_mode ? 'yes' : 'no' ),
		'- Behavior data available: ' . ( ! empty( $behavior_snapshot['has_data'] ) ? 'yes' : 'no' ),
		'- Behavior top pattern: ' . sanitize_text_field( (string) ( $behavior_snapshot['top_pattern_label'] ?? 'Unknown' ) ),
		'- Behavior total profiles: ' . absint( $behavior_snapshot['total_profiles'] ?? 0 ),
		'- Behavior closers: ' . absint( $behavior_snapshot['closers'] ?? ( $behavior_snapshot['buyers'] ?? 0 ) ),
		'- Behavior non-converters: ' . absint( $behavior_snapshot['non_converters'] ?? 0 ),
		'',
		'Current heuristic signals:',
		empty( $heuristics ) ? '- No heuristic recommendation available.' : implode( "\n", $heuristics ),
		'',
		'AI guardrails for this item:',
		'- Allowed action families: ' . ( ! empty( $rule_set['allowed'] ) ? implode( ', ', array_map( 'sanitize_text_field', $rule_set['allowed'] ) ) : 'none specifically preferred' ),
		'- Forbidden action families: ' . ( ! empty( $rule_set['forbidden'] ) ? implode( ', ', array_map( 'sanitize_text_field', $rule_set['forbidden'] ) ) : 'none' ),
		empty( $rule_set['notes'] ) ? '' : implode(
			"\n",
			array_map(
				static function ( $note ) {
					return '- ' . sanitize_text_field( (string) $note );
				},
				$rule_set['notes']
			)
		),
		'',
		'Response format requirements:',
		'1. Start with "Primary action:" and one sentence only.',
		'2. Add a "Why:" line tied to the metrics.',
		'3. Add "How to apply in Quorlyx:" with 2 to 4 numbered steps that name exact Quorlyx settings areas and features.',
		'4. End with "Watch next:" and one metric to monitor after the change.',
		'5. Do not mention code changes, external plugins, or features Quorlyx does not have.',
		'6. Keep the full answer under 180 words.',
		'7. Do not recommend a trigger that users are unlikely to reach based on the observed scroll depth or time on page.',
	);

	if ( $seo_only_mode ) {
		$prompt_lines[] = '8. Because this item has too little traffic, recommend only SEO improvements and do not suggest chatbot copy changes, welcome-message tweaks, or trigger changes.';
		$prompt_lines[] = '9. Prioritize actions such as refreshing older content, generating related keywords, generating schema markup, and suggesting internal links.';
	}

	$history = array(
		array(
			'role'  => 'user',
			'parts' => array(
				array(
					'text' => implode( "\n", $prompt_lines ),
				),
			),
		),
	);

	$response = quorlyx_call_ai_api_with_retry(
		$ai_config['provider'],
		$ai_config['api_key'],
		$ai_config['model'],
		$system_prompt,
		$history,
		0.2
	);

	if ( is_wp_error( $response ) ) {
		return new WP_Error(
			'insight_ai_failed',
			'AI suggestion could not be generated right now: ' . $response->get_error_message(),
			array( 'status' => 500 )
		);
	}

	$suggestion = quorlyx_pro_sanitize_guide_text( (string) $response, 2000 );
	if ( quorlyx_content_insight_response_violates_rules( $suggestion, $rule_set ) ) {
		$suggestion = quorlyx_get_content_insight_safe_fallback_suggestion( $row );
	}

	return new WP_REST_Response(
		array(
			'success'    => true,
			'suggestion' => $suggestion,
			'provider'   => $ai_config['provider'],
			'model'      => $ai_config['model'],
		),
		200
	);
}

/**
 * REST endpoint to analyze recent plugin logs with AI.
 *
 * @param WP_REST_Request $request REST request instance.
 * @return WP_REST_Response|WP_Error
 */
function quorlyx_rest_analyze_logs( WP_REST_Request $request ) {
	$nonce_ok = quorlyx_verify_rest_nonce( $request );
	if ( is_wp_error( $nonce_ok ) ) {
		return $nonce_ok;
	}

	$logs        = Quorlyx_Pro_Logger::get_logs();
	$recent_logs = array_slice( $logs, 0, 50 );

	if ( ! function_exists( 'get_plugins' ) ) {
		require_once ABSPATH . 'wp-admin/includes/plugin.php';
	}

	$active_plugins_paths = get_option( 'active_plugins', array() );
	$active_plugins_names = array();
	$all_plugins          = get_plugins();

	foreach ( $active_plugins_paths as $plugin_path ) {
		if ( isset( $all_plugins[ $plugin_path ] ) ) {
			$active_plugins_names[] = $all_plugins[ $plugin_path ]['Name'] . ' v' . $all_plugins[ $plugin_path ]['Version'];
		} else {
			$active_plugins_names[] = $plugin_path;
		}
	}

	$theme           = wp_get_theme();
	$server_software = isset( $_SERVER['SERVER_SOFTWARE'] )
		? sanitize_text_field( wp_unslash( $_SERVER['SERVER_SOFTWARE'] ) )
		: 'Unknown';

	$sys_info = array(
		'wp_version'      => get_bloginfo( 'version' ),
		'php_version'     => phpversion(),
		'server_software' => $server_software,
		'theme'           => $theme->get( 'Name' ) . ' v' . $theme->get( 'Version' ),
		'active_plugins'  => $active_plugins_names,
	);

	$prompt_lines = array(
		'You are an expert WordPress technical support engineer for the Quorlyx plugin. Your task is to analyze the provided system information and recent error logs to diagnose issues.',
		'',
		'System Info: ' . wp_json_encode( $sys_info ),
		'',
		'Recent Logs: ' . wp_json_encode( $recent_logs ),
		'',
		'Instructions:',
		'1. **Analyze Deeply**: Look for patterns in the logs (e.g., repeated API failures, database errors, conflicts with other plugins).',
		'2. **Structure Your Response**:',
		'   - **Summary**: A brief overview of the health of the system.',
		'   - **Identified Issues**: List specific problems found (e.g., \'API Key Invalid\', \'Memory Limit Exhausted\').',
		'   - **Root Cause Analysis**: Explain *why* these issues are happening based on the logs and system info.',
		'   - **Actionable Steps**: Provide clear, numbered instructions for the user to fix the issues (e.g., \'Go to Settings > Quorlyx and update the API key\', \'Deactivate Plugin X to test for conflicts\').',
		'3. **CRITICAL**: If the error indicates a bug in the plugin\'s source code (e.g., PHP fatal errors, undefined functions, syntax errors in the plugin files), DO NOT suggest editing the code. Instead, explicitly state: \'This appears to be an internal issue with the plugin. Please contact Quorlyx support for assistance.\'',
		'4. Do not provide PHP code snippets or instructions to modify plugin files.',
		'5. If there are no errors, simply say \'No critical errors found.\'',
	);
	$prompt       = implode( "\n", $prompt_lines );

	$options     = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$variation_a = $options['variation_a'];
	$provider    = $variation_a['ai_provider'];
	$api_key     = $variation_a['api_keys'][ $provider ] ?? '';

	if ( empty( $api_key ) ) {
		return new WP_REST_Response(
			array(
				'success' => false,
				'message' => 'AI Provider not configured. Please set up Variation A API key.',
			),
			400
		);
	}

	$history  = array(
		array(
			'role'  => 'user',
			'parts' => array(
				array(
					'text' => $prompt,
				),
			),
		),
	);
	$analysis = quorlyx_call_ai_api(
		$provider,
		$api_key,
		$variation_a['ai_model'],
		'You are a helpful technical support assistant.',
		$history
	);

	if ( is_wp_error( $analysis ) ) {
		return $analysis;
	}

	return new WP_REST_Response(
		array(
			'success'  => true,
			'analysis' => $analysis,
		),
		200
	);
}

add_action( 'wp_ajax_quorlyx_fetch_coupon_codes', 'quorlyx_ajax_fetch_coupon_codes' );
/**
 * AJAX handler returning coupon codes for trigger UI.
 *
 * @return void
 */
function quorlyx_ajax_fetch_coupon_codes() {
	$nonce_ok = quorlyx_verify_admin_ajax_nonce();
	if ( is_wp_error( $nonce_ok ) ) {
		wp_send_json_error( array( 'message' => $nonce_ok->get_error_message() ), 403 );
	}

	if ( ! quorlyx_current_user_can_manage() ) {
		wp_send_json_error( array( 'message' => 'Unauthorized' ), 403 );
	}

	wp_send_json_success(
		array(
			'coupon_codes' => quorlyx_get_coupon_codes_for_trigger_ui( 500 ),
		)
	);
}

add_action( 'wp_ajax_quorlyx_dismiss_notice', 'quorlyx_ajax_dismiss_notice' );
/**
 * AJAX handler to dismiss admin notices.
 *
 * @return void
 */
function quorlyx_ajax_dismiss_notice() {
	check_ajax_referer( 'quorlyx_dismiss_notice', 'nonce' );
	if ( ! quorlyx_current_user_can_manage() ) {
		wp_send_json_error( array( 'message' => 'Unauthorized' ), 403 );
	}
	$notice_id = isset( $_POST['notice_id'] ) ? sanitize_key( wp_unslash( $_POST['notice_id'] ) ) : '';
	if ( ! $notice_id ) {
		wp_send_json_error( array( 'message' => 'Missing notice_id' ), 400 );
	}
	$dismissed = get_option( 'quorlyx_dismissed_notices', array() );
	if ( ! is_array( $dismissed ) ) {
		$dismissed = array();
	}
	$dismissed[ $notice_id ] = time();
	update_option( 'quorlyx_dismissed_notices', $dismissed );
	wp_send_json_success( array( 'notice_id' => $notice_id ) );
}

add_action( 'wp_head', 'quorlyx_inject_schema' );
/**
 * Inject saved schema markup on singular frontend pages.
 *
 * @return void
 */
function quorlyx_inject_schema() {
	if ( is_singular() ) {
		$schema = get_post_meta( get_the_ID(), '_quorlyx_generated_schema', true );
		if ( $schema && is_string( $schema ) ) {
			$decoded = json_decode( $schema, true );
			if ( JSON_ERROR_NONE === json_last_error() && is_array( $decoded ) ) {
				wp_print_inline_script_tag(
					wp_json_encode( $decoded ),
					array(
						'type' => 'application/ld+json',
					)
				);
			}
		}
	}
}

add_action( 'admin_init', 'quorlyx_handle_export_requests' );
/**
 * Handle admin export requests and dispatch CSV exports.
 *
 * @return void
 */
function quorlyx_handle_export_requests() {
	if ( ! isset( $_GET['quorlyx_export'] ) || ! quorlyx_current_user_can_manage() ) {
		return;
	}
	$export_type = sanitize_key( wp_unslash( $_GET['quorlyx_export'] ) );
	$nonce       = isset( $_GET['_wpnonce'] ) ? sanitize_text_field( wp_unslash( $_GET['_wpnonce'] ) ) : '';
	if ( empty( $nonce ) || ! wp_verify_nonce( $nonce, 'quorlyx_export_' . $export_type ) ) {
		wp_die( esc_html__( 'Invalid nonce.', 'quorlyx' ) );
	}

	switch ( $export_type ) {
		case 'ab_results':
			quorlyx_export_ab_results_csv();
			break;
		case 'trigger_analytics':
			quorlyx_export_trigger_analytics_csv();
			break;
		case 'submissions':
			quorlyx_export_submissions_csv();
			break;
		case 'conversations':
			quorlyx_export_conversations_csv();
			break;
	}
	exit;
}

add_action( 'admin_footer-edit.php', 'quorlyx_add_export_button' );
add_filter( 'views_edit-quorlyx_submission', 'quorlyx_add_export_view_link' );
add_filter( 'views_edit-quorlyx_conversation', 'quorlyx_add_export_view_link' );

/**
 * Build export metadata for supported list screens.
 *
 * @param string $post_type Post type slug.
 * @return array<string,string>
 */
function quorlyx_get_export_link_data_for_post_type( $post_type ) {
	$post_type = sanitize_key( (string) $post_type );
	if ( ! in_array( $post_type, array( 'quorlyx_submission', 'quorlyx_conversation' ), true ) ) {
		return array();
	}

	$export_type = ( 'quorlyx_submission' === $post_type ) ? 'submissions' : 'conversations';

	return array(
		'type'  => $export_type,
		'label' => ( 'submissions' === $export_type ) ? __( 'Export Submissions CSV', 'quorlyx' ) : __( 'Export Conversations CSV', 'quorlyx' ),
		'url'   => add_query_arg(
			array(
				'quorlyx_export' => $export_type,
				'_wpnonce'       => wp_create_nonce( 'quorlyx_export_' . $export_type ),
			),
			admin_url( 'admin.php' )
		),
	);
}

/**
 * Add a reliable export link to the native list-table views row.
 *
 * @param array<string,string> $views List-table view links.
 * @return array<string,string>
 */
function quorlyx_add_export_view_link( $views ) {
	$screen = function_exists( 'get_current_screen' ) ? get_current_screen() : null;
	if ( ! $screen || empty( $screen->post_type ) || ! quorlyx_current_user_can_manage() ) {
		return $views;
	}

	$link_data = quorlyx_get_export_link_data_for_post_type( $screen->post_type );
	if ( empty( $link_data['url'] ) ) {
		return $views;
	}

	$views['quorlyx_export_csv'] = '<a href="' . esc_url( $link_data['url'] ) . '"><span class="dashicons dashicons-download" style="vertical-align:text-bottom;"></span> ' . esc_html( $link_data['label'] ) . '</a>';

	return $views;
}

/**
 * Add export button to supported admin list tables.
 *
 * @return void
 */
function quorlyx_add_export_button() {
	global $typenow;
	$link_data = quorlyx_get_export_link_data_for_post_type( $typenow );
	if ( ! empty( $link_data['url'] ) && quorlyx_current_user_can_manage() ) {
		$export_html = '<a href="' . esc_url( $link_data['url'] ) . '" class="page-title-action"><span class="dashicons dashicons-download"></span> ' . esc_html( $link_data['label'] ) . '</a>';
		$inline_js   = 'jQuery(function($){var $heading=$(".wrap h1.wp-heading-inline"); if($heading.length && !$(".quorlyx-export-title-action").length){var html=' . wp_json_encode( $export_html ) . '; html=html.replace("page-title-action", "page-title-action quorlyx-export-title-action"); $heading.after(html);}});';
		wp_enqueue_script( 'jquery' );
		wp_add_inline_script( 'jquery', $inline_js );
	}
}

/**
 * Export A/B testing and conversation metrics as CSV.
 *
 * @return void
 */
function quorlyx_export_ab_results_csv() {
	$filename = 'quorlyx_ab_test_results_' . gmdate( 'Y-m-d' ) . '.csv';
	header( 'Content-Type: text/csv' );
	header( 'Content-Disposition: attachment; filename="' . $filename . '"' );
	$output = fopen( 'php://output', 'w' );
	fputcsv( $output, array( 'Variation', 'Metric', 'Value' ) );

	$ab_stats   = array_replace_recursive(
		array(
			'a' => array(
				'views'       => 0,
				'conversions' => 0,
			),
			'b' => array(
				'views'       => 0,
				'conversions' => 0,
			),
		),
		get_option( 'quorlyx_ab_stats', array() )
	);
	$conv_stats = array_replace_recursive(
		array(
			'a' => array(
				'total'          => 0,
				'avg_messages'   => 0,
				'source_trigger' => 0,
				'source_normal'  => 0,
			),
			'b' => array(
				'total'          => 0,
				'avg_messages'   => 0,
				'source_trigger' => 0,
				'source_normal'  => 0,
			),
		),
		get_option( 'quorlyx_conversation_stats', array() )
	);

	foreach ( array( 'a', 'b' ) as $v ) {
		$rate = ( $ab_stats[ $v ]['views'] > 0 ) ? ( $ab_stats[ $v ]['conversions'] / $ab_stats[ $v ]['views'] ) * 100 : 0;
		fputcsv( $output, array( 'Variation ' . strtoupper( $v ), 'Views', $ab_stats[ $v ]['views'] ) );
		fputcsv( $output, array( 'Variation ' . strtoupper( $v ), 'Conversions', $ab_stats[ $v ]['conversions'] ) );
		fputcsv( $output, array( 'Variation ' . strtoupper( $v ), 'Conversion Rate (%)', number_format( $rate, 2 ) ) );
		fputcsv( $output, array( 'Variation ' . strtoupper( $v ), 'Total Conversations', $conv_stats[ $v ]['total'] ?? 0 ) );
		fputcsv( $output, array( 'Variation ' . strtoupper( $v ), 'Avg Messages per Conversation', number_format( $conv_stats[ $v ]['avg_messages'] ?? 0, 2 ) ) );
		fputcsv( $output, array( 'Variation ' . strtoupper( $v ), 'Trigger Conversations', $conv_stats[ $v ]['source_trigger'] ?? 0 ) );
		fputcsv( $output, array( 'Variation ' . strtoupper( $v ), 'Normal Conversations', $conv_stats[ $v ]['source_normal'] ?? 0 ) );
	}
	fclose( $output ); // phpcs:ignore WordPress.WP.AlternativeFunctions.file_system_operations_fclose
}

/**
 * Export trigger analytics summary CSV.
 *
 * @return void
 */
function quorlyx_export_trigger_analytics_csv() {
	$filename = 'quorlyx_trigger_analytics_' . gmdate( 'Y-m-d' ) . '.csv';
	header( 'Content-Type: text/csv' );
	header( 'Content-Disposition: attachment; filename="' . $filename . '"' );

	$output = fopen( 'php://output', 'w' );
	fputcsv(
		$output,
		array(
			'Trigger ID',
			'Trigger Name',
			'Trigger Type',
			'Fired (7d)',
			'Fired (30d)',
			'Fired (Lifetime)',
			'Replied (7d)',
			'Replied (30d)',
			'Replied (Lifetime)',
			'Dismissed (7d)',
			'Dismissed (30d)',
			'Dismissed (Lifetime)',
			'Converted (7d)',
			'Converted (30d)',
			'Converted (Lifetime)',
		)
	);

	$rows = quorlyx_get_trigger_analytics_rows();
	foreach ( $rows as $row ) {
		$w7  = is_array( $row['windows']['7d'] ?? null ) ? $row['windows']['7d'] : array();
		$w30 = is_array( $row['windows']['30d'] ?? null ) ? $row['windows']['30d'] : array();
		$wl  = is_array( $row['windows']['lifetime'] ?? null ) ? $row['windows']['lifetime'] : array();

		fputcsv(
			$output,
			array(
				(string) ( $row['id'] ?? '' ),
				(string) ( $row['name'] ?? '' ),
				(string) ( $row['type'] ?? '' ),
				(int) ( $w7['trigger_fired'] ?? 0 ),
				(int) ( $w30['trigger_fired'] ?? 0 ),
				(int) ( $wl['trigger_fired'] ?? 0 ),
				(int) ( $w7['trigger_replied'] ?? 0 ),
				(int) ( $w30['trigger_replied'] ?? 0 ),
				(int) ( $wl['trigger_replied'] ?? 0 ),
				(int) ( $w7['trigger_dismissed'] ?? 0 ),
				(int) ( $w30['trigger_dismissed'] ?? 0 ),
				(int) ( $wl['trigger_dismissed'] ?? 0 ),
				(int) ( $w7['trigger_converted'] ?? 0 ),
				(int) ( $w30['trigger_converted'] ?? 0 ),
				(int) ( $wl['trigger_converted'] ?? 0 ),
			)
		);
	}

	fclose( $output ); // phpcs:ignore WordPress.WP.AlternativeFunctions.file_system_operations_fclose
}


/**
 * Export captured submissions as CSV, preferring the compact submissions table.
 *
 * @return void
 */
function quorlyx_export_submissions_csv() {
	if ( ! quorlyx_submissions_table_exists() ) {
		quorlyx_export_cpt_csv( 'quorlyx_submission' );
		return;
	}

	$filename = 'quorlyx_submissions_' . gmdate( 'Y-m-d' ) . '.csv';
	header( 'Content-Type: text/csv' );
	header( 'Content-Disposition: attachment; filename="' . $filename . '"' );
	$output = fopen( 'php://output', 'w' );
	fputcsv( $output, array( 'ID', 'Title', 'Email', 'Phone', 'Purpose', 'Interest', 'Status', 'Urgency', 'Tags', 'Conversation ID', 'Trigger ID', 'Trigger Name', 'Trigger Type', 'Source URL', 'Content', 'Date' ) );

	global $wpdb;
	$table_name = quorlyx_get_submissions_table_name();
	$limit      = 500;
	$offset     = 0;

	do {
		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Paged export over compact Quorlyx submissions table.
		$rows = $wpdb->get_results(
			$wpdb->prepare(
				"SELECT * FROM {$table_name} ORDER BY id ASC LIMIT %d OFFSET %d",
				$limit,
				$offset
			),
			ARRAY_A
		);

		foreach ( (array) $rows as $row ) {
			$post_id              = absint( $row['post_id'] ?? 0 );
			$conversation_post_id = absint( $row['conversation_post_id'] ?? 0 );
			$tags                 = json_decode( (string) ( $row['tags'] ?? '' ), true );
			$tags                 = is_array( $tags ) ? implode( ', ', array_map( 'sanitize_text_field', $tags ) ) : '';
			$title                = $post_id > 0 ? get_the_title( $post_id ) : '';
			if ( '' === $title ) {
				$title = trim( (string) ( $row['purpose'] ?? '' ) . ' - ' . (string) ( $row['interest'] ?? '' ) );
			}
			$content = $post_id > 0 ? get_post_field( 'post_content', $post_id ) : '';
			if ( '' === trim( (string) $content ) ) {
				$content = sprintf(
					"Email: %s\nPhone: %s\nInterest: %s\nPurpose: %s\nStatus: %s\nUrgency: %s\nConversation: %s",
					(string) ( $row['email'] ?? '' ),
					(string) ( $row['phone'] ?? '' ),
					(string) ( $row['interest'] ?? '' ),
					(string) ( $row['purpose'] ?? '' ),
					(string) ( $row['status'] ?? '' ),
					(string) ( $row['urgency'] ?? '' ),
					$conversation_post_id > 0 ? admin_url( 'post.php?post=' . $conversation_post_id . '&action=edit' ) : ''
				);
			}

			fputcsv(
				$output,
				array(
					$post_id > 0 ? $post_id : absint( $row['id'] ?? 0 ),
					$title,
					(string) ( $row['email'] ?? '' ),
					(string) ( $row['phone'] ?? '' ),
					(string) ( $row['purpose'] ?? '' ),
					(string) ( $row['interest'] ?? '' ),
					(string) ( $row['status'] ?? '' ),
					(string) ( $row['urgency'] ?? '' ),
					$tags,
					$conversation_post_id,
					(string) ( $row['trigger_id'] ?? '' ),
					(string) ( $row['trigger_name'] ?? '' ),
					(string) ( $row['trigger_type'] ?? '' ),
					(string) ( $row['source_url'] ?? '' ),
					$content,
					(string) ( $row['created_at'] ?? '' ),
				)
			);
		}

		$offset += $limit;
	} while ( is_array( $rows ) && count( $rows ) === $limit );

	fclose( $output ); // phpcs:ignore WordPress.WP.AlternativeFunctions.file_system_operations_fclose
}

/**
 * Export a CPT list as CSV.
 *
 * @param string $post_type Post type slug.
 * @return void
 */
function quorlyx_export_cpt_csv( $post_type ) {
	$filename = 'quorlyx_' . $post_type . '_' . gmdate( 'Y-m-d-m' ) . '.csv';
	header( 'Content-Type: text/csv' );
	header( 'Content-Disposition: attachment; filename="' . $filename . '"' );
	$output = fopen( 'php://output', 'w' );
	if ( 'quorlyx_submission' === $post_type ) {
		fputcsv( $output, array( 'ID', 'Title', 'Email', 'Phone', 'Purpose', 'Interest', 'Status', 'Urgency', 'Tags', 'Conversation ID', 'Trigger ID', 'Trigger Name', 'Trigger Type', 'Source URL', 'Content', 'Date' ) );
	} else {
		fputcsv( $output, array( 'ID', 'Title', 'Content', 'Date' ) );
	}

	$paged = 1;
	do {
		$query = new WP_Query(
			array(
				'post_type'              => $post_type,
				'posts_per_page'         => 500,
				'paged'                  => $paged,
				'post_status'            => 'publish',
				'orderby'                => 'ID',
				'order'                  => 'ASC',
				'no_found_rows'          => true,
				'update_post_meta_cache' => true,
				'update_post_term_cache' => false,
			)
		);

		while ( $query->have_posts() ) {
			$query->the_post();
			if ( 'quorlyx_submission' === $post_type ) {
				$post_id = get_the_ID();
				$tags    = get_post_meta( $post_id, 'quorlyx_tags', true );
				if ( is_array( $tags ) ) {
					$tags = implode( ', ', array_map( 'sanitize_text_field', $tags ) );
				}
				fputcsv(
					$output,
					array(
						$post_id,
						get_the_title(),
						get_post_meta( $post_id, 'quorlyx_email', true ),
						get_post_meta( $post_id, 'quorlyx_phone', true ),
						get_post_meta( $post_id, 'quorlyx_capture_purpose', true ),
						get_post_meta( $post_id, 'quorlyx_interest', true ),
						get_post_meta( $post_id, 'quorlyx_status', true ),
						get_post_meta( $post_id, 'quorlyx_urgency', true ),
						$tags,
						get_post_meta( $post_id, 'quorlyx_conversation_id', true ),
						get_post_meta( $post_id, 'quorlyx_trigger_id', true ),
						get_post_meta( $post_id, 'quorlyx_trigger_name', true ),
						get_post_meta( $post_id, 'quorlyx_trigger_type', true ),
						get_post_meta( $post_id, 'quorlyx_source_url', true ),
						get_the_content(),
						get_the_date(),
					)
				);
			} else {
				fputcsv( $output, array( get_the_ID(), get_the_title(), get_the_content(), get_the_date() ) );
			}
		}
		$has_more = 500 === count( $query->posts );
		wp_reset_postdata();
		++$paged;
	} while ( $has_more );
	fclose( $output ); // phpcs:ignore WordPress.WP.AlternativeFunctions.file_system_operations_fclose
}

/**
 * Export conversation history rows as CSV.
 *
 * @return void
 */
function quorlyx_export_conversations_csv() {
	$filename = 'quorlyx_conversations_' . gmdate( 'Y-m-d' ) . '.csv';
	header( 'Content-Type: text/csv' );
	header( 'Content-Disposition: attachment; filename="' . $filename . '"' );
	$output = fopen( 'php://output', 'w' );
	fputcsv( $output, array( 'Conversation ID', 'Conversation Date', 'A/B Variation', 'Source', 'Trigger ID', 'Trigger Name', 'Trigger Type', 'Message Timestamp', 'Sender', 'Message' ) );

	if ( quorlyx_conversation_store_available() ) {
		global $wpdb;
		$conversations_table = quorlyx_get_conversations_table_name();
		$messages_table      = quorlyx_get_conversation_messages_table_name();
		$limit               = 250;
		$offset              = 0;

		do {
			// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Paged export over compact Quorlyx table.
			$rows = $wpdb->get_results(
				$wpdb->prepare(
					"SELECT * FROM {$conversations_table} ORDER BY id ASC LIMIT %d OFFSET %d",
					$limit,
					$offset
				),
				ARRAY_A
			);

			foreach ( (array) $rows as $row ) {
				$convo_id           = absint( $row['post_id'] ?? 0 );
				$convo_date         = sanitize_text_field( (string) ( $row['created_at'] ?? '' ) );
				$variation          = sanitize_key( (string) ( $row['variation'] ?? 'a' ) );
				$source             = 'trigger' === sanitize_key( (string) ( $row['source'] ?? 'normal' ) ) ? 'Trigger' : 'Normal';
				$trigger_id         = sanitize_key( (string) ( $row['trigger_id'] ?? '' ) );
				$trigger_name       = sanitize_text_field( (string) ( $row['trigger_name'] ?? '' ) );
				$trigger_type       = sanitize_key( (string) ( $row['trigger_type'] ?? '' ) );
				$trigger_type_label = '' !== $trigger_type ? ucwords( str_replace( '_', ' ', $trigger_type ) ) : '';
				if ( '' === $trigger_name && '' !== $trigger_id ) {
					$trigger_name = $trigger_id;
				}

				// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Indexed export of one conversation's messages.
				$messages = $wpdb->get_results(
					$wpdb->prepare(
						"SELECT role, message_text, created_at FROM {$messages_table} WHERE conversation_post_id = %d ORDER BY sequence_num ASC",
						$convo_id
					),
					ARRAY_A
				);

				foreach ( (array) $messages as $message ) {
					$sender = sanitize_key( (string) ( $message['role'] ?? 'unknown' ) );
					fputcsv(
						$output,
						array(
							$convo_id,
							$convo_date,
							strtoupper( $variation ),
							$source,
							$trigger_id,
							$trigger_name,
							$trigger_type_label,
							sanitize_text_field( (string) ( $message['created_at'] ?? '' ) ),
							ucfirst( 'model' === $sender ? 'ai' : 'user' ),
							(string) ( $message['message_text'] ?? '' ),
						)
					);
				}
			}

			$offset += $limit;
		} while ( is_array( $rows ) && count( $rows ) === $limit );

		fclose( $output ); // phpcs:ignore WordPress.WP.AlternativeFunctions.file_system_operations_fclose
		return;
	}

	$paged = 1;
	do {
		$query = new WP_Query(
			array(
				'post_type'              => 'quorlyx_conversation',
				'posts_per_page'         => 250,
				'paged'                  => $paged,
				'post_status'            => 'private',
				'orderby'                => 'ID',
				'order'                  => 'ASC',
				'no_found_rows'          => true,
				'update_post_meta_cache' => true,
				'update_post_term_cache' => false,
			)
		);

		while ( $query->have_posts() ) {
			$query->the_post();
			$convo_id     = get_the_ID();
			$convo_date   = get_the_date();
			$variation    = get_post_meta( $convo_id, 'quorlyx_ab_variation', true );
			$variation    = $variation ? $variation : 'N/A';
			$origin       = quorlyx_get_conversation_origin_details( $convo_id );
			$source       = (string) ( $origin['source_label'] ?? 'Normal' );
			$trigger_id   = (string) ( $origin['trigger_id'] ?? '' );
			$trigger_name = (string) ( $origin['trigger_name'] ?? '' );
			$trigger_type = (string) ( $origin['trigger_type'] ?? '' );
			if ( '' === $trigger_name && '' !== $trigger_id ) {
				$trigger_name = $trigger_id;
			}
			$trigger_type_label = '' !== $trigger_type ? ucwords( str_replace( '_', ' ', $trigger_type ) ) : '';
			$history            = quorlyx_get_conversation_history( $convo_id );

			if ( ! empty( $history ) && is_array( $history ) ) {
				foreach ( $history as $message ) {
					$sender = $message['role'] ?? 'unknown';
					$text   = $message['parts'][0]['text'] ?? '';
					fputcsv(
						$output,
						array(
							$convo_id,
							$convo_date,
							strtoupper( $variation ),
							$source,
							$trigger_id,
							$trigger_name,
							$trigger_type_label,
							'',
							ucfirst( 'model' === $sender ? 'ai' : 'user' ),
							$text,
						)
					);
				}
			}
		}
		$has_more = 250 === count( $query->posts );
		wp_reset_postdata();
		++$paged;
	} while ( $has_more );
	fclose( $output ); // phpcs:ignore WordPress.WP.AlternativeFunctions.file_system_operations_fclose
}

add_action( 'quorlyx_check_finished_conversations', 'quorlyx_send_finished_conversation_transcripts' );
add_action( 'init', 'quorlyx_maybe_schedule_finished_conversation_check' );

/**
 * Schedule transcript checks only when transcript notifications can run.
 *
 * @return void
 */
function quorlyx_maybe_schedule_finished_conversation_check() {
	$options   = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$scheduled = wp_next_scheduled( 'quorlyx_check_finished_conversations' );
	$enabled   = ! empty( $options['enable_transcript_notifications'] ) && ! empty( $options['notification_email'] );

	if ( $enabled && ! $scheduled ) {
		wp_schedule_event( time(), 'hourly', 'quorlyx_check_finished_conversations' );
		return;
	}

	if ( ! $enabled && $scheduled ) {
		wp_unschedule_event( $scheduled, 'quorlyx_check_finished_conversations' );
	}
}

/**
 * Email transcripts for inactive finished conversations.
 *
 * @return void
 */
function quorlyx_send_finished_conversation_transcripts() {
	$options = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	if ( empty( $options['enable_transcript_notifications'] ) || empty( $options['notification_email'] ) ) {
		return;
	}

	$inactive_threshold = 30 * 60;
	$args               = array(
		'post_type'              => 'quorlyx_conversation',
		'post_status'            => 'private',
		'posts_per_page'         => 100,
		'fields'                 => 'ids',
		'no_found_rows'          => true,
		'update_post_meta_cache' => false,
		'update_post_term_cache' => false,
		// phpcs:ignore WordPress.DB.SlowDBQuery.slow_db_query_meta_query
		'meta_query'     => array(
			'relation' => 'AND',
			array(
				'key'     => 'quorlyx_last_activity',
				'value'   => time() - $inactive_threshold,
				'compare' => '<',
				'type'    => 'NUMERIC',
			),
			array(
				'key'     => 'quorlyx_transcript_sent',
				'compare' => 'NOT EXISTS',
			),
		),
	);

	$query = new WP_Query( $args );
	if ( $query->have_posts() ) {
		$email_to = $options['notification_email'];
		foreach ( $query->posts as $convo_id ) {
			$convo_id = absint( $convo_id );
			$history  = quorlyx_get_conversation_history( $convo_id );

			if ( is_array( $history ) && count( $history ) > 1 ) {
				$subject      = 'Finished Conversation Transcript from ' . get_bloginfo( 'name' );
				$conversation = esc_url( admin_url( 'post.php?post=' . $convo_id . '&action=edit' ) );
				$message_body = "A conversation on your website appears to have finished.\n\nView the original conversation: {$conversation}\n\n--- TRANSCRIPT ---\n\n";
				foreach ( $history as $message ) {
					$sender        = ucfirst( 'model' === ( $message['role'] ?? 'user' ) ? 'AI' : 'User' );
					$text          = $message['parts'][0]['text'] ?? '';
					$message_body .= "{$sender}:\n" . $text . "\n\n";
				}
				wp_mail( $email_to, $subject, $message_body );
				update_post_meta( $convo_id, 'quorlyx_transcript_sent', 'yes' );
			}
		}
	}
	wp_reset_postdata();
}

add_action( 'init', 'quorlyx_maybe_schedule_retention_cleanup' );
add_action( 'quorlyx_retention_cleanup_event', 'quorlyx_run_retention_cleanup' );

/**
 * Schedule daily cleanup for table-backed conversation and submission data.
 *
 * @return void
 */
function quorlyx_maybe_schedule_retention_cleanup() {
	if ( ! wp_next_scheduled( 'quorlyx_retention_cleanup_event' ) ) {
		wp_schedule_event( time() + HOUR_IN_SECONDS, 'daily', 'quorlyx_retention_cleanup_event' );
	}
}

/**
 * Delete old conversation/submission rows and mirrored posts in small batches.
 *
 * @return void
 */
function quorlyx_run_retention_cleanup() {
	$options = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$options = quorlyx_merge_global_options( is_array( $options ) ? $options : array() );
	$perf    = is_array( $options['performance'] ?? null ) ? $options['performance'] : array();

	$conversation_days = max( 30, min( 3650, absint( $perf['conversation_retention_days'] ?? 180 ) ) );
	$submission_days   = max( 30, min( 3650, absint( $perf['submission_retention_days'] ?? 365 ) ) );
	$conversation_cut  = time() - ( $conversation_days * DAY_IN_SECONDS );
	$submission_cut    = gmdate( 'Y-m-d H:i:s', time() - ( $submission_days * DAY_IN_SECONDS ) );

	global $wpdb;

	if ( quorlyx_conversation_store_available() ) {
		$conversations_table = quorlyx_get_conversations_table_name();
		$messages_table      = quorlyx_get_conversation_messages_table_name();

		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Bounded retention query over plugin table.
		$old_conversations = $wpdb->get_results(
			$wpdb->prepare(
				"SELECT id, post_id FROM {$conversations_table} WHERE last_activity > 0 AND last_activity < %d ORDER BY last_activity ASC LIMIT 250",
				$conversation_cut
			),
			ARRAY_A
		);
		$post_ids          = array_values( array_filter( array_map( 'absint', wp_list_pluck( (array) $old_conversations, 'post_id' ) ) ) );

		if ( ! empty( $post_ids ) ) {
			$placeholders = implode( ',', array_fill( 0, count( $post_ids ), '%d' ) );
			// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Placeholder list is generated from integer post IDs.
			$wpdb->query( $wpdb->prepare( "DELETE FROM {$messages_table} WHERE conversation_post_id IN ({$placeholders})", $post_ids ) );
			// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Placeholder list is generated from integer post IDs.
			$wpdb->query( $wpdb->prepare( "DELETE FROM {$conversations_table} WHERE post_id IN ({$placeholders})", $post_ids ) );
			foreach ( $post_ids as $post_id ) {
				if ( 'quorlyx_conversation' === get_post_type( $post_id ) ) {
					wp_delete_post( $post_id, true );
				}
			}
		}
	}

	if ( quorlyx_submissions_table_exists() ) {
		$submissions_table = quorlyx_get_submissions_table_name();
		// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching,WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Bounded retention query over plugin table.
		$old_submission_ids = $wpdb->get_col(
			$wpdb->prepare(
				"SELECT post_id FROM {$submissions_table} WHERE created_at < %s ORDER BY created_at ASC LIMIT 250",
				$submission_cut
			)
		);
		$old_submission_ids = array_values( array_filter( array_map( 'absint', (array) $old_submission_ids ) ) );
		if ( ! empty( $old_submission_ids ) ) {
			$placeholders = implode( ',', array_fill( 0, count( $old_submission_ids ), '%d' ) );
			// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Placeholder list is generated from integer post IDs.
			$wpdb->query( $wpdb->prepare( "DELETE FROM {$submissions_table} WHERE post_id IN ({$placeholders})", $old_submission_ids ) );
			foreach ( $old_submission_ids as $post_id ) {
				if ( 'quorlyx_submission' === get_post_type( $post_id ) ) {
					wp_delete_post( $post_id, true );
				}
			}
		}
	}
}

/**
 * Content generator for keyword and product-driven article creation.
 */
class Quorlyx_Content_Generator {
	/**
	 * Full plugin options.
	 *
	 * @var array<string,mixed>
	 */
	private $options;

	/**
	 * Post generator options.
	 *
	 * @var array<string,mixed>
	 */
	private $pg_opts;

	/**
	 * Variation A options.
	 *
	 * @var array<string,mixed>
	 */
	private $var_a_opts;

	/**
	 * Discover an eligible WooCommerce product candidate.
	 *
	 * @return int|null
	 */
	public function discover_candidate() {
		if ( ! class_exists( 'WooCommerce' ) ) {
			return null;
		}

		$args = array(
			'post_type'      => 'product',
			'posts_per_page' => 10, // Check a batch.
			'post_status'    => 'publish',
			'fields'         => 'ids',
			// phpcs:ignore WordPress.DB.SlowDBQuery.slow_db_query_meta_query
			'meta_query'     => array(
				array(
					'key'     => '_quorlyx_content_generated',
					'compare' => 'NOT EXISTS',
				),
			),
		);

		$products = get_posts( $args );
		if ( ! empty( $products ) ) {
			return $products[0];
		}
		return null;
	}

	/**
	 * Collect source context for a product-based generation candidate.
	 *
	 * @param int $candidate_id Product ID candidate.
	 * @return array<string,mixed>
	 */
	private function collect_context( $candidate_id ) {
		$product = wc_get_product( $candidate_id );
		if ( ! $product ) {
			return array();
		}

		$cats = wc_get_product_category_list( $candidate_id );
		$tags = wc_get_product_tag_list( $candidate_id );

		return array(
			'id'                => $candidate_id,
			'title'             => $product->get_name(),
			'description'       => $product->get_description(),
			'short_description' => $product->get_short_description(),
			'price'             => $product->get_price_html(),
			'sku'               => $product->get_sku(),
			'categories'        => wp_strip_all_tags( $cats ),
			'tags'              => wp_strip_all_tags( $tags ),
			'url'               => $product->get_permalink(),
		);
	}

	/**
	 * Build the AI prompt for a generated content request.
	 *
	 * @param array<string,mixed> $context Source context.
	 * @param string              $template_type Template type slug.
	 * @return string
	 */
	private function build_prompt( $context, $template_type ) {
		$prompt  = "Write a 'Feature Spotlight' blog post for the following product:\n\n";
		$prompt .= 'Template Type: ' . $template_type . "\n";
		$prompt .= 'Product Name: ' . $context['title'] . "\n";
		$prompt .= 'Product URL: ' . $context['url'] . "\n";
		$prompt .= 'Price: ' . $context['price'] . "\n";
		$prompt .= 'Categories: ' . $context['categories'] . "\n";
		$prompt .= 'Description: ' . wp_strip_all_tags( $context['description'] ) . "\n";
		$prompt .= 'Short Description: ' . wp_strip_all_tags( $context['short_description'] ) . "\n\n";

		$prompt .= "Instructions:\n";
		$prompt .= "1. Write an engaging, SEO-optimized blog post highlighting the features and benefits of this product.\n";
		$prompt .= "2. Use a professional but persuasive tone.\n";
		$prompt .= "3. Include a catchy title.\n";
		$prompt .= "4. Structure the content with H2 and H3 headings.\n";
		$prompt .= "5. Mention the product name naturally throughout the text.\n";
		$prompt .= "6. Include a Call to Action at the end with a link to the product using the provided Product URL.\n";
		$prompt .= "7. Return the result in the following JSON format. Ensure the response is valid JSON. Newlines in the content string must be escaped as \\n.\n";
		$prompt .= "```json\n{\n  \"title\": \"Post Title\",\n  \"content_markdown\": \"Post content in Markdown format\",\n  \"meta_title\": \"SEO Meta Title\",\n  \"meta_description\": \"SEO Meta Description\"\n}\n```";

		return $prompt;
	}

	/**
	 * Initialize generator options from plugin settings.
	 *
	 * @return void
	 */
	public function __construct() {
		$this->options    = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
		$this->pg_opts    = $this->options['post_generator'];
		$this->var_a_opts = $this->options['variation_a'];
	}

	/**
	 * Generate a new post from a candidate product or keyword queue.
	 *
	 * @param int|null $candidate_id Optional candidate product ID.
	 * @param string   $template_type Template type slug.
	 * @return int|WP_Error
	 * @throws Exception When generation prerequisites are not met.
	 */
	public function generate_post( $candidate_id = null, $template_type = 'feature_spotlight' ) {
		try {
			$scope = $this->pg_opts['ai_provider_scope'] ?? 'general';
			if ( 'independent' === $scope ) {
				$provider = $this->pg_opts['ai_provider'] ?? 'gemini';
				$api_key  = $this->pg_opts['ai_api_key'] ?? '';
				$model    = $this->pg_opts['ai_model'] ?? '';
				if ( empty( $api_key ) || empty( $model ) ) {
					throw new Exception( 'Independent mode requires both an API key and a model for the Content Engine provider.', 400 );
				}
			} else {
				$provider = $this->var_a_opts['ai_provider'];
				$api_key  = $this->var_a_opts['api_keys'][ $provider ] ?? '';
				$model    = $this->var_a_opts['ai_model'] ?? '';
				if ( empty( $api_key ) || empty( $model ) ) {
					throw new Exception( 'The API Key and Model for ' . ucfirst( $provider ? $provider : 'the selected provider' ) . ' in Variation A must be set.', 400 );
				}
			}

			if ( $candidate_id ) {
				$context = $this->collect_context( $candidate_id );
				if ( empty( $context ) ) {
					throw new Exception( 'Could not collect context for candidate ID: ' . $candidate_id );
				}

				$system_prompt = 'You are an expert content writer for this site.';
				$user_prompt   = $this->build_prompt( $context, $template_type );
				$keyword       = $context['title']; // For logging/meta.
			} else {
				$keyword = $this->get_next_keyword();

				$system_prompt = $this->pg_opts['instructions'];
				$user_prompt   = 'Keyword: ' . $keyword;
			}

			$history     = array(
				array(
					'role'  => 'user',
					'parts' => array(
						array(
							'text' => $user_prompt,
						),
					),
				),
			);
			$ai_response = quorlyx_call_ai_api_with_retry( $provider, $api_key, $model, $system_prompt, $history );

			if ( is_wp_error( $ai_response ) || empty( $ai_response ) ) {
				throw new Exception( 'The AI API returned an empty or invalid response.', 500 );
			}

			if ( $candidate_id ) {
				$parsed = $this->parse_structured_response( $ai_response );
				if ( empty( $parsed['title'] ) ) {
					$parsed['title'] = 'Spotlight: ' . $keyword;
				}
			} else {
				$parsed = $this->parse_ai_response( $ai_response, $keyword );
			}

			$post_id = $this->create_post( $parsed, $this->pg_opts, $keyword );
			if ( is_wp_error( $post_id ) ) {
				throw $post_id;
			}

			update_post_meta( $post_id, '_quorlyx_generated_keyword', $keyword );

			if ( ! $candidate_id && ! empty( $this->pg_opts['prevent_duplicates'] ) ) {
				$history = get_option(
					'quorlyx_generated_history',
					array(
						'products' => array(),
						'keywords' => array(),
					)
				);
				if ( ! in_array( $keyword, $history['keywords'] ?? array(), true ) ) {
					$history['keywords'][] = $keyword;
					update_option( 'quorlyx_generated_history', $history, false );
				}
			}

			if ( $candidate_id ) {
				update_post_meta( $post_id, '_quorlyx_source_product_id', $candidate_id );
				update_post_meta( $post_id, '_quorlyx_template_type', $template_type );
			}

			return $post_id;
		} catch ( Exception $e ) {
			return new WP_Error( 'generation_failed', $e->getMessage() );
		}
	}

	/**
	 * Parse structured JSON responses from the AI provider.
	 *
	 * @param string $response Raw AI response.
	 * @return array<string,string>
	 */
	private function parse_structured_response( $response ) {
		$json = null;

		if ( preg_match( '/```json\s*(\{.*?\})\s*```/s', $response, $m ) ) {
			$json_str = $m[1];
			$json     = json_decode( $json_str, true );

			if ( ! $json ) {
				$json_str_fixed = preg_replace( '/(?<!\\)\n/', '\\n', $json_str );
				$json_str_fixed = preg_replace( '/[\x00-\x1F\x7F]/', '', $json_str_fixed );
				$json           = json_decode( $json_str_fixed, true );
			}
		}

		if ( ! $json ) {
			$json = json_decode( $response, true );
			if ( ! $json ) {
				$json_str_fixed = preg_replace( '/(?<!\\)\n/', '\\n', $response );
				$json_str_fixed = preg_replace( '/[\x00-\x1F\x7F]/', '', $json_str_fixed );
				$json           = json_decode( $json_str_fixed, true );
			}
		}

		if ( $json ) {
			$content = $json['content_markdown'] ?? '';
			return array(
				'title'            => $json['title'] ?? '',
				'content'          => $content,
				'meta_title'       => $json['meta_title'] ?? '',
				'meta_description' => $json['meta_description'] ?? '',
			);
		}

		$clean_response = preg_replace( '/^```json\s*/i', '', trim( $response ) );
		$clean_response = preg_replace( '/^```\s*/i', '', $clean_response );
		$clean_response = preg_replace( '/\s*```$/', '', $clean_response );

		return array(
			'title'   => '',
			'content' => $clean_response,
		);
	}

	/**
	 * Select the next available keyword from queue and history.
	 *
	 * @return string
	 * @throws Exception When no keyword is available.
	 */
	private function get_next_keyword() {
		if ( empty( $this->pg_opts['keywords'] ) ) {
			throw new Exception( 'The Topic Keywords Queue is empty.' );
		}

		$all = array_values(
			array_filter(
				array_map(
					'trim',
					explode( "\n", $this->pg_opts['keywords'] )
				)
			)
		);
		if ( empty( $all ) ) {
			throw new Exception( 'The Topic Keywords Queue is empty.' );
		}

		$prevent_duplicates = ! empty( $this->pg_opts['prevent_duplicates'] );
		$used               = array();

		$used_ids = get_posts(
			array(
				'post_type'      => $this->pg_opts['post_type'],
				'posts_per_page' => 5000,
				'fields'         => 'ids',
				// phpcs:ignore WordPress.DB.SlowDBQuery.slow_db_query_meta_query
				'meta_query'     => array(
					array(
						'key'     => '_quorlyx_generated_keyword',
						'compare' => 'EXISTS',
					),
				),
			)
		);

		foreach ( $used_ids as $pid ) {
			$k = get_post_meta( $pid, '_quorlyx_generated_keyword', true );
			if ( $k ) {
				$used[] = $k;
			}
		}

		if ( $prevent_duplicates ) {
			$history          = get_option(
				'quorlyx_generated_history',
				array(
					'products' => array(),
					'keywords' => array(),
				)
			);
			$history_keywords = $history['keywords'] ?? array();
			$used             = array_unique( array_merge( $used, $history_keywords ) );
		}

		foreach ( $all as $k ) {
			if ( ! in_array( $k, $used, true ) ) {
				return $k;
			}
		}

		throw new Exception( 'All keywords in the queue have already been used.' );
	}

	/**
	 * Parse unstructured AI responses into title/content fields.
	 *
	 * @param string $response Raw AI response.
	 * @param string $fallback_keyword Fallback keyword for generated title.
	 * @return array<string,string>
	 */
	private function parse_ai_response( $response, $fallback_keyword ) {
		$title   = 'AI Post: ' . $fallback_keyword;
		$content = trim( $response );

		if ( preg_match( '/^\s*Title\s*:\s*(.+)$/im', $response, $m ) ) {
			$title   = trim( $m[1] );
			$content = trim( str_replace( $m[0], '', $response ) );
		}

		$content = preg_replace( '/^\s*```[a-z0-9-]*\s*/i', '', $content );
		$content = preg_replace( '/\s*```\s*$/', '', $content );

		return array(
			'title'   => $title,
			'content' => $content,
		);
	}

	/**
	 * Convert markdown-like output into sanitized HTML.
	 *
	 * @param string $markdown Markdown text.
	 * @return string
	 */
	private function convert_markdown_to_html( $markdown ) {
		$markdown = htmlspecialchars( $markdown, ENT_QUOTES, 'UTF-8' );

		$markdown = preg_replace( '/^####\s*\d+[\.\)]*\s*(.*$)/m', '<h4>$1</h4>', $markdown );
		$markdown = preg_replace( '/^###\s*\d+[\.\)]*\s*(.*$)/m', '<h3>$1</h3>', $markdown );
		$markdown = preg_replace( '/^##\s*\d+[\.\)]*\s*(.*$)/m', '<h2>$1</h2>', $markdown );
		$markdown = preg_replace( '/^#\s*\d+[\.\)]*\s*(.*$)/m', '<h1>$1</h1>', $markdown );

		$markdown = preg_replace( '/^#### (.*$)/m', '<h4>$1</h4>', $markdown );
		$markdown = preg_replace( '/^### (.*$)/m', '<h3>$1</h3>', $markdown );
		$markdown = preg_replace( '/^## (.*$)/m', '<h2>$1</h2>', $markdown );
		$markdown = preg_replace( '/^# (.*$)/m', '<h1>$1</h1>', $markdown );

		$markdown = preg_replace( '/\*\*(.*?)\*\*/s', '<strong>$1</strong>', $markdown );
		$markdown = preg_replace( '/_(.*?)_/', '<em>$1</em>', $markdown ); // Also handle underscores for italics.
		$markdown = preg_replace( '/\*(.*?)\*/s', '<em>$1</em>', $markdown );

		$markdown = preg_replace( '/\[([^\]]+)\]\(([^)]+)\)/', '<a href="$2">$1</a>', $markdown );

		$markdown = preg_replace( '/^\* (.*$)/m', '<ul><li>$1</li></ul>', $markdown );
		$markdown = preg_replace( '/^(\d+)\. (.*$)/m', '<ol><li>$2</li></ol>', $markdown );

		$markdown = str_replace( "</ul>\n<ul>", '', $markdown );
		$markdown = str_replace( "</ol>\n<ol>", '', $markdown );

		$markdown = wpautop( $markdown );

		return $markdown;
	}

	/**
	 * Create and initialize a generated post entry.
	 *
	 * @param array<string,string> $parsed Parsed generation payload.
	 * @param array<string,mixed>  $pg_opts Post generator options.
	 * @param string               $keyword Source keyword.
	 * @return int
	 * @throws Exception When post creation fails.
	 */
	private function create_post( $parsed, $pg_opts, $keyword = '' ) {
		$html_content = $this->convert_markdown_to_html( $parsed['content'] );

		if ( is_string( $keyword ) && strlen( trim( $keyword ) ) > 0 ) {
			$recs_html = quorlyx_build_recommendations_html( $keyword );
			if ( ! empty( $recs_html ) ) {
				$html_content .= "\n\n" . $recs_html;
			}
		}
		$html_content = wp_kses_post( $html_content );

		$post_data = array(
			'post_title'   => sanitize_text_field( $parsed['title'] ),
			'post_content' => $html_content,
			'post_status'  => $pg_opts['post_status'] ?? 'draft',
			'post_author'  => $pg_opts['author_id'] ? $pg_opts['author_id'] : get_current_user_id(),
			'post_type'    => $pg_opts['post_type'] ? $pg_opts['post_type'] : 'post',
		);

		$post_id = wp_insert_post( wp_slash( $post_data ), true );
		if ( is_wp_error( $post_id ) ) {
			throw new Exception( 'Failed to create post: ' . esc_html( $post_id->get_error_message() ) );
		}

		update_post_meta( $post_id, '_quorlyx_generated', '1' );
		update_post_meta( $post_id, '_quorlyx_analytics_views', 0 );
		update_post_meta( $post_id, '_quorlyx_analytics_time_on_page', 0 ); // Total seconds.
		update_post_meta( $post_id, '_quorlyx_analytics_scroll_depth', 0 ); // Average depth (stored as total / count in logic).
		update_post_meta( $post_id, '_quorlyx_analytics_scroll_depth_total', 0 );
		update_post_meta( $post_id, '_quorlyx_analytics_scroll_depth_count', 0 );
		update_post_meta( $post_id, '_quorlyx_analytics_add_to_cart', 0 );
		update_post_meta( $post_id, '_quorlyx_analytics_checkout_visits', 0 );
		update_post_meta( $post_id, '_quorlyx_analytics_checkout_success', 0 );
		update_post_meta( $post_id, '_quorlyx_analytics_conversions', 0 );
		return $post_id;
	}
}

/**
 * Persist confirmed conversion state in browser cookies when the server can identify it.
 *
 * @return bool Whether cookies were queued.
 */
function quorlyx_mark_frontend_conversion_cookie() {
	if ( headers_sent() ) {
		return false;
	}

	$expires   = time() + ( defined( 'YEAR_IN_SECONDS' ) ? YEAR_IN_SECONDS : 31536000 );
	$path      = defined( 'COOKIEPATH' ) && COOKIEPATH ? COOKIEPATH : '/';
	$domain    = defined( 'COOKIE_DOMAIN' ) ? COOKIE_DOMAIN : '';
	$secure    = is_ssl();
	$timestamp = (string) time();

	setcookie( 'quorlyx_thankyou_reached', '1', $expires, $path, $domain, $secure, false );
	setcookie( 'quorlyx_customer_status', 'converted', $expires, $path, $domain, $secure, false );
	setcookie( 'quorlyx_customer_converted_at', $timestamp, $expires, $path, $domain, $secure, false );

	$_COOKIE['quorlyx_thankyou_reached']     = '1';
	$_COOKIE['quorlyx_customer_status']      = 'converted';
	$_COOKIE['quorlyx_customer_converted_at'] = $timestamp;

	return true;
}

add_action( 'template_redirect', 'quorlyx_mark_woocommerce_order_received_conversion_cookie', 1 );
/**
 * Mark WooCommerce order-received visits as confirmed conversions before output starts.
 *
 * @return void
 */
function quorlyx_mark_woocommerce_order_received_conversion_cookie() {
	if ( is_admin() || ! class_exists( 'WooCommerce' ) || ! function_exists( 'is_order_received_page' ) || ! is_order_received_page() ) {
		return;
	}

	quorlyx_mark_frontend_conversion_cookie();
}

add_action( 'woocommerce_thankyou', 'quorlyx_track_woocommerce_conversion', 10, 1 );
/**
 * Attribute WooCommerce conversion events back to Content Insights rows.
 *
 * @param int $order_id WooCommerce order ID.
 * @return void
 */
function quorlyx_track_woocommerce_conversion( $order_id ) {
	$options                  = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$options                  = quorlyx_merge_global_options( $options );
	$content_insights_settings = is_array( $options['content_insights'] ?? null ) ? $options['content_insights'] : array();

	if (
		! class_exists( 'WooCommerce' )
		|| ! quorlyx_content_insights_is_enabled( $content_insights_settings )
		|| ! quorlyx_content_insights_tracks_any_conversions( $content_insights_settings )
	) {
		return;
	}

	$order_id = absint( $order_id );
	if ( $order_id <= 0 ) {
		return;
	}

	$order = function_exists( 'wc_get_order' ) ? wc_get_order( $order_id ) : null;
	if ( ! $order ) {
		return;
	}

	$source      = quorlyx_get_attribution_source_from_request();
	$post_id     = absint( $source['post_id'] ?? 0 );
	$content_key = sanitize_key( $source['content_key'] ?? '' );

	if ( $post_id <= 0 && '' === $content_key ) {
		return;
	}

	$source_token = $post_id > 0 ? 'p_' . $post_id : 'k_' . $content_key;
	$track_key    = '_quorlyx_conversion_tracked_' . substr( md5( $source_token ), 0, 16 );
	if ( $order->get_meta( $track_key, true ) ) {
		return;
	}

	quorlyx_increment_analytics_metric( $post_id, '_quorlyx_analytics_conversions', 1, $content_key );

	$order->update_meta_data( $track_key, 1 );
	$order->save();

	if ( class_exists( 'Quorlyx_Pro_Logger' ) ) {
		Quorlyx_Pro_Logger::log(
			'info',
			'woocommerce_conversion_attributed',
			array(
				'post_id'     => $post_id,
				'content_key' => $content_key,
				'order_id'    => $order_id,
			)
		);
	}
}

add_action( 'woocommerce_thankyou', 'quorlyx_track_woocommerce_checkout_success', 10, 1 );
/**
 * Track checkout success attribution for Content Insights.
 *
 * @param int $order_id WooCommerce order ID.
 * @return void
 */
function quorlyx_track_woocommerce_checkout_success( $order_id ) {
	if ( ! class_exists( 'WooCommerce' ) ) {
		return;
	}

	if ( ! quorlyx_content_insights_is_enabled() ) {
		return;
	}

	$order_id = absint( $order_id );
	if ( $order_id <= 0 ) {
		return;
	}

	$order = function_exists( 'wc_get_order' ) ? wc_get_order( $order_id ) : null;
	if ( ! $order ) {
		return;
	}

	$source      = quorlyx_get_attribution_source_from_request();
	$post_id     = absint( $source['post_id'] ?? 0 );
	$content_key = sanitize_key( $source['content_key'] ?? '' );

	if ( $post_id <= 0 && '' === $content_key ) {
		return;
	}

	$source_token = $post_id > 0 ? 'p_' . $post_id : 'k_' . $content_key;
	$track_key    = '_quorlyx_checkout_tracked_' . substr( md5( $source_token ), 0, 16 );
	if ( $order->get_meta( $track_key, true ) ) {
		return;
	}

	quorlyx_increment_analytics_metric( $post_id, '_quorlyx_analytics_checkout_success', 1, $content_key );

	$order->update_meta_data( $track_key, 1 );
	$order->save();
}

add_filter( 'cron_schedules', 'quorlyx_add_cron_schedules' );
/**
 * Register custom cron schedules used by Quorlyx.
 *
 * @param array<string,mixed> $schedules Existing schedules.
 * @return array<string,mixed>
 */
function quorlyx_add_cron_schedules( $schedules ) {
	$schedules['twice_daily'] = array(
		'interval' => 43200,
		'display'  => esc_html__( 'Twice Daily' ),
	);
	$schedules['weekly']      = array(
		'interval' => 604800,
		'display'  => esc_html__( 'Once Weekly' ),
	);
	return $schedules;
}

/**
 * Reschedule automated post generation based on current settings.
 *
 * @param array<string,mixed>|null $pg_opts Optional post generator options.
 * @return void
 */
function quorlyx_reschedule_post_generation_event( $pg_opts = null ) {
	$hook = 'quorlyx_generate_posts_event';
	wp_clear_scheduled_hook( $hook );

	if ( null === $pg_opts ) {
		$options = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
		$pg_opts = $options['post_generator'];
	}

	$is_enabled = $pg_opts['enabled'] ?? false;
	$schedule   = $pg_opts['schedule'] ?? 'disabled';

	if ( $is_enabled && 'disabled' !== $schedule ) {
		wp_schedule_event( time(), $schedule, $hook );
	}
}

add_action( 'quorlyx_generate_posts_event', 'quorlyx_run_post_generation' );
/**
 * Run scheduled post generation jobs.
 *
 * @return void
 */
function quorlyx_run_post_generation() {
	$options = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$pg_opts = $options['post_generator'];
	if ( empty( $pg_opts['enabled'] ) || 'disabled' === $pg_opts['schedule'] ) {
		return;
	}

	$generator          = new Quorlyx_Content_Generator();
	$posts_to_run       = absint( $pg_opts['posts_per_run'] );
	$source             = $pg_opts['source'] ?? 'keywords';
	$prevent_duplicates = ! empty( $pg_opts['prevent_duplicates'] );
	$history            = get_option(
		'quorlyx_generated_history',
		array(
			'products' => array(),
			'keywords' => array(),
		)
	);

	for ( $i = 0; $i < $posts_to_run; $i++ ) {
		$result       = null;
		$candidate_id = null;

		try {
			if ( 'products_specific' === $source ) {
				$ids_str = $pg_opts['specific_product_ids'] ?? '';
				$ids     = array_filter( array_map( 'trim', explode( ',', $ids_str ) ) );

				if ( $prevent_duplicates ) {
					$ids = array_filter(
						$ids,
						function ( $id ) use ( $history ) {
							return ! in_array( $id, $history['products'] ?? array(), true )
								&& ! get_post_meta( $id, '_quorlyx_content_generated', true );
						}
					);
				}

				if ( ! empty( $ids ) ) {
					$candidate_id = $ids[ array_rand( $ids ) ];
				} else {
					break;
				}
			} elseif ( 'products_all' === $source ) {
				$queue_str = $pg_opts['products_queue'] ?? '';
				$queue_ids = array_filter( array_map( 'trim', explode( "\n", $queue_str ) ) );

				if ( empty( $queue_ids ) ) {
					break;
				}

				$candidate_id = array_shift( $queue_ids );

				if ( $prevent_duplicates ) {
					while ( $candidate_id && ( in_array( $candidate_id, $history['products'] ?? array(), true ) || get_post_meta( $candidate_id, '_quorlyx_content_generated', true ) ) ) {
						$candidate_id = array_shift( $queue_ids );
					}
				}

				if ( ! $candidate_id ) {
					$pg_opts['products_queue'] = '';
					$options['post_generator'] = $pg_opts;
					update_option( 'quorlyx_options', $options );
					break;
				}

				$pg_opts['products_queue'] = implode( "\n", $queue_ids );
				$options['post_generator'] = $pg_opts;
				update_option( 'quorlyx_options', $options );
			}

			if ( $candidate_id ) {
				$result = $generator->generate_post( $candidate_id, 'feature_spotlight' );

				if ( ! is_wp_error( $result ) ) {
					update_post_meta( $candidate_id, '_quorlyx_content_generated', 1 );
					if ( $prevent_duplicates ) {
						$history = get_option(
							'quorlyx_generated_history',
							array(
								'products' => array(),
								'keywords' => array(),
							)
						);
						if ( ! in_array( $candidate_id, $history['products'] ?? array(), true ) ) {
							$history['products'][] = $candidate_id;
							update_option( 'quorlyx_generated_history', $history, false );
						}
					}
				}
			} else {
				$result = $generator->generate_post();
			}
		} catch ( Exception $e ) {
			$result = new WP_Error( 'generation_error', $e->getMessage() );
		}

		if ( is_wp_error( $result ) ) {
			update_option(
				'quorlyx_last_generation',
				array(
					'status'  => 'error',
					'message' => $result->get_error_message(),
					'time'    => time(),
				)
			);
			break;
		}

		$post_title = get_the_title( $result );
		update_option(
			'quorlyx_last_generation',
			array(
				'status'  => 'success',
				'message' => 'Created: ' . ( $post_title ? $post_title : 'post' ),
				'time'    => time(),
			)
		);

		if ( $i < $posts_to_run - 1 ) {
			sleep( 3 );
		}
	}
}

/**
 * Build related recommendation HTML for generated content.
 *
 * @param string $keyword Keyword to match recommendations.
 * @return string
 */
function quorlyx_build_recommendations_html( $keyword ) {
	$keyword = is_string( $keyword ) ? trim( $keyword ) : '';
	if ( '' === $keyword ) {
		return '';
	}

	$options = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$pg      = $options['post_generator'] ?? array();
	$rec     = $pg['recommendations'] ?? array(
		'enabled'          => true,
		'include_products' => true,
		'include_posts'    => true,
		'include_services' => true,
		'cache_ttl'        => 900,
	);

	if ( empty( $rec['enabled'] ) ) {
		return '';
	}

	$include_products       = ! empty( $rec['include_products'] );
	$include_posts          = ! empty( $rec['include_posts'] );
	$include_services       = ! empty( $rec['include_services'] );
	$use_tax                = ! empty( $rec['use_tax_relevance'] );
	$max_items              = max( 1, min( 10, absint( $rec['max_items'] ?? 3 ) ) );
	$cache_ttl              = max( 60, absint( $rec['cache_ttl'] ?? 900 ) );
	$use_custom_service_tax = ! empty( $rec['use_custom_service_taxonomies'] );
	$service_taxonomies     = isset( $rec['service_taxonomies'] )
		? array_filter( array_map( 'sanitize_key', array_map( 'trim', explode( ',', $rec['service_taxonomies'] ) ) ) )
		: array();
	$labels                 = is_array( $rec['labels'] ?? null )
		? $rec['labels']
		: array(
			'products' => 'Recommended products',
			'posts'    => 'Related posts',
			'services' => 'Services',
		);

	$cache_key_payload = wp_json_encode(
		array(
			'k'  => strtolower( $keyword ),
			'p'  => (int) $include_products,
			'o'  => (int) $include_posts,
			's'  => (int) $include_services,
			't'  => (int) $use_tax,
			'm'  => $max_items,
			'ct' => implode( ',', $service_taxonomies ),
			'l'  => $labels,
		)
	);
	$cache_key         = 'quorlyx_recs_' . md5( $cache_key_payload );

	$cached = get_transient( $cache_key );
	if ( false !== $cached && is_string( $cached ) ) {
		return $cached;
	}

	$sections = array();

	$push_section = function ( $title, $ids ) use ( &$sections ) {
		$items = array();
		foreach ( $ids as $pid ) {
			$title_text = get_the_title( $pid );
			if ( '' === $title_text ) {
				continue;
			}
			$items[] = sprintf(
				'<li><a href="%s" rel="noopener" target="_blank">%s</a></li>',
				esc_url( get_permalink( $pid ) ),
				esc_html( $title_text )
			);
		}
		if ( ! empty( $items ) ) {
			$sections[] = '<h3>' . esc_html( $title ) . '</h3><ul>' . implode( '', $items ) . '</ul>';
		}
	};

	$tax_matches_for = function ( $taxonomies, $search ) {
		$term_ids = array();
		foreach ( $taxonomies as $tax ) {
			if ( ! taxonomy_exists( $tax ) ) {
				continue;
			}
			$terms = get_terms(
				array(
					'taxonomy'   => $tax,
					'search'     => $search,
					'hide_empty' => true,
					'fields'     => 'ids',
					'number'     => 10,
				)
			);
			if ( ! is_wp_error( $terms ) && ! empty( $terms ) ) {
				$term_ids[ $tax ] = $terms;
			}
		}
		return $term_ids;
	};

	if ( $include_products && class_exists( 'WooCommerce' ) ) {
		$tax_query = array();
		if ( $use_tax ) {
			$tax_ids = $tax_matches_for( array( 'product_cat', 'product_tag' ), $keyword );
			if ( ! empty( $tax_ids ) ) {
				$tax_query['relation'] = 'OR';
				foreach ( $tax_ids as $tax => $ids ) {
					if ( ! empty( $ids ) ) {
						$tax_query[] = array(
							'taxonomy'         => $tax,
							'field'            => 'term_id',
							'terms'            => $ids,
							'include_children' => true,
						);
					}
				}
			}
		}
		$args = array(
			'post_type'        => 'product',
			's'                => $keyword,
			'posts_per_page'   => $max_items,
			'post_status'      => 'publish',
			'fields'           => 'ids',
			'no_found_rows'    => true,
			'orderby'          => 'date',
			'order'            => 'DESC',
			'suppress_filters' => true,
		);
		if ( ! empty( $tax_query ) ) {
			// phpcs:ignore WordPress.DB.SlowDBQuery.slow_db_query_tax_query
			$args['tax_query'] = $tax_query;
		}
		$q = new WP_Query( $args );
		if ( $q->have_posts() ) {
			$push_section( $labels['products'] ?? 'Recommended products', $q->posts );
		}
		wp_reset_postdata();
	}

	if ( $include_posts ) {
		$tax_query = array();
		if ( $use_tax ) {
			$tax_ids = $tax_matches_for( array( 'category', 'post_tag' ), $keyword );
			if ( ! empty( $tax_ids ) ) {
				$tax_query['relation'] = 'OR';
				foreach ( $tax_ids as $tax => $ids ) {
					if ( ! empty( $ids ) ) {
						$tax_query[] = array(
							'taxonomy'         => $tax,
							'field'            => 'term_id',
							'terms'            => $ids,
							'include_children' => true,
						);
					}
				}
			}
		}
		$args = array(
			'post_type'        => 'post',
			's'                => $keyword,
			'posts_per_page'   => $max_items,
			'post_status'      => 'publish',
			'fields'           => 'ids',
			'no_found_rows'    => true,
			'orderby'          => 'date',
			'order'            => 'DESC',
			'suppress_filters' => true,
		);
		if ( ! empty( $tax_query ) ) {
			// phpcs:ignore WordPress.DB.SlowDBQuery.slow_db_query_tax_query
			$args['tax_query'] = $tax_query;
		}
		$q_posts = new WP_Query( $args );
		if ( $q_posts->have_posts() ) {
			$push_section( $labels['posts'] ?? 'Related posts', $q_posts->posts );
		}
		wp_reset_postdata();
	}

	if ( $include_services ) {
		$service_types = array_values( array_filter( array( 'service', 'services' ), 'post_type_exists' ) );
		if ( ! empty( $service_types ) ) {
			$tax_query = array();
			if ( $use_tax && $use_custom_service_tax && ! empty( $service_taxonomies ) ) {
				$tax_ids = $tax_matches_for( $service_taxonomies, $keyword );
				if ( ! empty( $tax_ids ) ) {
					$tax_query['relation'] = 'OR';
					foreach ( $tax_ids as $tax => $ids ) {
						if ( ! empty( $ids ) ) {
							$tax_query[] = array(
								'taxonomy'         => $tax,
								'field'            => 'term_id',
								'terms'            => $ids,
								'include_children' => true,
							);
						}
					}
				}
			}
			$args = array(
				'post_type'        => $service_types,
				's'                => $keyword,
				'posts_per_page'   => $max_items,
				'post_status'      => 'publish',
				'fields'           => 'ids',
				'no_found_rows'    => true,
				'orderby'          => 'date',
				'order'            => 'DESC',
				'suppress_filters' => true,
			);
			if ( ! empty( $tax_query ) ) {
				// phpcs:ignore WordPress.DB.SlowDBQuery.slow_db_query_tax_query
				$args['tax_query'] = $tax_query;
			}
			$q_services = new WP_Query( $args );
			if ( $q_services->have_posts() ) {
				$push_section( $labels['services'] ?? 'Services', $q_services->posts );
			}
			wp_reset_postdata();
		}
	}

	if ( empty( $sections ) ) {
		return '';
	}
	$html = '<div class="quorlyx-recommendations">' . implode( "\n", $sections ) . '</div>';
	set_transient( $cache_key, $html, $cache_ttl );
	return $html;
}

/**
 * Parse a provider Retry-After header into seconds.
 *
 * @param mixed $retry_after Raw Retry-After header value.
 * @return int
 */
function quorlyx_parse_retry_after_header( $retry_after ) {
	if ( is_array( $retry_after ) ) {
		$retry_after = reset( $retry_after );
	}

	$retry_after = is_scalar( $retry_after ) ? trim( (string) $retry_after ) : '';
	if ( '' === $retry_after ) {
		return 0;
	}

	if ( ctype_digit( $retry_after ) ) {
		return max( 1, absint( $retry_after ) );
	}

	$retry_at = strtotime( $retry_after );
	if ( false === $retry_at ) {
		return 0;
	}

	return max( 1, $retry_at - time() );
}

/**
 * Call AI API with retry logic for transient failures.
 *
 * @param string $provider Provider slug.
 * @param string $api_key Provider API key.
 * @param string $model Model name.
 * @param string $system_prompt System prompt text.
 * @param array  $history Message history.
 * @param float  $temp Sampling temperature.
 * @return string|WP_Error
 */
function quorlyx_call_ai_api_with_retry( $provider, $api_key, $model, $system_prompt, $history, $temp = 0.7 ) {
	$response = quorlyx_call_ai_api( $provider, $api_key, $model, $system_prompt, $history, $temp );

	if ( is_wp_error( $response ) ) {
		$error_data  = $response->get_error_data();
		$status_code = $error_data['status'] ?? 0;

		if ( 429 === $status_code ) {
			$delay = ! empty( $error_data['retry_after'] ) ? absint( $error_data['retry_after'] ) : QUORLYX_RATELIMIT_RETRY_DELAY;
			Quorlyx_Pro_Logger::log(
				'warning',
				'API rate limit hit. Returning error for client-side retry.',
				array( 'provider' => $provider, 'delay' => $delay )
			);
			$error_data['delay'] = $delay;
			$response->add_data( $error_data );
		} elseif ( $status_code >= 500 ) {
			$delay = ! empty( $error_data['retry_after'] ) ? absint( $error_data['retry_after'] ) : QUORLYX_RETRY_DELAY_BASE;
			Quorlyx_Pro_Logger::log(
				'warning',
				'API server error. Returning error for client-side retry.',
				array( 'provider' => $provider, 'delay' => $delay )
			);
			$error_data['delay'] = $delay;
			$response->add_data( $error_data );
		}

		Quorlyx_Pro_Logger::log(
			'error',
			'AI API call failed.',
			array(
				'error_code'    => $response->get_error_code(),
				'error_message' => $response->get_error_message(),
				'error_data'    => $response->get_error_data(),
			)
		);
	}

	return $response;
}

/**
 * Call tool-enabled AI API with retry logic.
 *
 * @param string $provider Provider slug.
 * @param string $api_key Provider API key.
 * @param string $model Model name.
 * @param string $system_prompt System prompt text.
 * @param array  $history Message history.
 * @param float  $temp Sampling temperature.
 * @param array  $tools Tool declarations.
 * @param array  $perf Performance options.
 * @return string|WP_Error
 */
function quorlyx_call_ai_api_with_tools_with_retry( $provider, $api_key, $model, $system_prompt, $history, $temp, $tools, $perf ) {
	$response = quorlyx_call_ai_api_with_tools( $provider, $api_key, $model, $system_prompt, $history, $temp, $tools, $perf );

	if ( is_wp_error( $response ) ) {
		$error_data  = $response->get_error_data();
		$status_code = $error_data['status'] ?? 0;

		if ( 429 === $status_code ) {
			$delay = ! empty( $error_data['retry_after'] ) ? absint( $error_data['retry_after'] ) : QUORLYX_RATELIMIT_RETRY_DELAY;
			Quorlyx_Pro_Logger::log(
				'warning',
				'API rate limit hit (tools). Returning error for client-side retry.',
				array( 'provider' => $provider, 'delay' => $delay )
			);
			$error_data['delay'] = $delay;
			$response->add_data( $error_data );
		} elseif ( $status_code >= 500 ) {
			$delay = ! empty( $error_data['retry_after'] ) ? absint( $error_data['retry_after'] ) : QUORLYX_RETRY_DELAY_BASE;
			Quorlyx_Pro_Logger::log(
				'warning',
				'API server error (tools). Returning error for client-side retry.',
				array( 'provider' => $provider, 'delay' => $delay )
			);
			$error_data['delay'] = $delay;
			$response->add_data( $error_data );
		}

		Quorlyx_Pro_Logger::log(
			'error',
			'AI API call (tools) failed.',
			array(
				'error_code'    => $response->get_error_code(),
				'error_message' => $response->get_error_message(),
				'error_data'    => $response->get_error_data(),
			)
		);
	}

	return $response;
}

/**
 * Dispatch a tool-enabled AI API request.
 *
 * @param string $provider Provider slug.
 * @param string $api_key Provider API key.
 * @param string $model Model name.
 * @param string $system_prompt System prompt text.
 * @param array  $history Message history.
 * @param float  $temp Sampling temperature.
 * @param array  $tools Tool declarations.
 * @param array  $perf Performance options.
 * @return string|WP_Error
 */
function quorlyx_call_ai_api_with_tools( $provider, $api_key, $model, $system_prompt, $history, $temp, $tools, $perf ) {
	try {
		if ( empty( $provider ) || empty( $api_key ) || empty( $model ) ) {
			return new WP_Error( 'missing_params', 'Provider, API key, and model are required.' );
		}

		if ( 'gemini' === $provider ) {
			return quorlyx_call_gemini_with_tools( $api_key, $model, $system_prompt, $history, $temp, $tools, $perf );
		}

		$supported = array( 'openai', 'grok', 'mistral', 'deepseek' );
		if ( ! in_array( $provider, $supported, true ) ) {
			return quorlyx_call_ai_api( $provider, $api_key, $model, $system_prompt, $history, $temp );
		}

		$url      = '';
		$headers  = array( 'Content-Type' => 'application/json' );
		$messages = quorlyx_format_history_for_openai( $history, $system_prompt );

		switch ( $provider ) {
			case 'openai':
				$url = 'https://api.openai.com/v1/chat/completions';

				$headers['Authorization'] = 'Bearer ' . $api_key;

				break;
			case 'grok':
				$url = 'https://api.x.ai/v1/chat/completions';

				$headers['Authorization'] = 'Bearer ' . $api_key;

				break;
			case 'mistral':
				$url = 'https://api.mistral.ai/v1/chat/completions';

				$headers['Authorization'] = 'Bearer ' . $api_key;

				break;
			case 'deepseek':
				$url = 'https://api.deepseek.com/v1/chat/completions';

				$headers['Authorization'] = 'Bearer ' . $api_key;

				break;
		}

		$body = array(
			'model'       => $model,
			'messages'    => $messages,
			'temperature' => $temp,
			'tools'       => $tools,
			'tool_choice' => 'auto',
		);

		$response = wp_remote_post(
			$url,
			array(
				'headers' => 'gemini' === $provider ? quorlyx_get_gemini_request_headers( $headers ) : $headers,
				'body'    => wp_json_encode( $body ),
				'timeout' => QUORLYX_API_TIMEOUT,
			)
		);
		if ( is_wp_error( $response ) ) {
			return new WP_Error( 'api_http_error', $response->get_error_message() );
		}

		$response_body = json_decode( wp_remote_retrieve_body( $response ), true );
		$response_code = wp_remote_retrieve_response_code( $response );
		if ( $response_code >= 400 ) {
			$error_details = isset( $response_body['error']['message'] ) ? $response_body['error']['message'] : wp_remote_retrieve_body( $response );
			return new WP_Error(
				'api_response_error',
				"API returned status {$response_code}",
				array(
					'status'      => $response_code,
					'details'     => $error_details,
					'retry_after' => quorlyx_parse_retry_after_header( wp_remote_retrieve_header( $response, 'retry-after' ) ),
				)
			);
		}

		$message    = $response_body['choices'][0]['message'] ?? array();
		$tool_calls = $message['tool_calls'] ?? array();
		$content    = $message['content'] ?? '';

		if ( ! empty( $tool_calls ) ) {
			$messages[] = array(
				'role'       => 'assistant',
				'tool_calls' => $tool_calls,
			);

			foreach ( $tool_calls as $call ) {
				$fn        = $call['function']['name'] ?? '';
				$args_json = $call['function']['arguments'] ?? '{}';
				$args      = json_decode( $args_json, true );
				if ( ! is_array( $args ) ) {
					$args = array();
				}

				if ( 'search_products' === $fn ) {
					$term        = isset( $args['search_term'] ) ? (string) $args['search_term'] : '';
					$limit       = isset( $args['limit'] ) ? absint( $args['limit'] ) : (int) ( $perf['tool_calling_results_limit'] ?? 5 );
					$tool_result = quorlyx_pro_tool_search_products( $term, $perf, $limit );
				} else {
					$tool_result = 'UNSUPPORTED_TOOL';
				}

				$messages[] = array(
					'role'         => 'tool',
					'tool_call_id' => $call['id'] ?? '',
					'content'      => $tool_result,
				);
			}

			$body['messages'] = $messages;
			$second           = wp_remote_post(
				$url,
				array(
					'headers' => $headers,
					'body'    => wp_json_encode( $body ),
					'timeout' => QUORLYX_API_TIMEOUT,
				)
			);
			if ( is_wp_error( $second ) ) {
				return new WP_Error( 'api_http_error', $second->get_error_message() );
			}

			$second_body = json_decode( wp_remote_retrieve_body( $second ), true );
			$second_code = wp_remote_retrieve_response_code( $second );
			if ( $second_code >= 400 ) {
				$error_details = isset( $second_body['error']['message'] ) ? $second_body['error']['message'] : wp_remote_retrieve_body( $second );
				return new WP_Error(
					'api_response_error',
					"API returned status {$second_code}",
					array(
						'status'      => $second_code,
						'details'     => $error_details,
						'retry_after' => quorlyx_parse_retry_after_header( wp_remote_retrieve_header( $second, 'retry-after' ) ),
					)
				);
			}

			return $second_body['choices'][0]['message']['content'] ?? '';
		}

		return $content;
	} catch ( Exception $e ) {
		return new WP_Error( 'api_exception', $e->getMessage() );
	}
}

/**
 * Execute a Gemini tool-calling request flow.
 *
 * @param string $api_key Provider API key.
 * @param string $model Model name.
 * @param string $system_prompt System prompt text.
 * @param array  $history Message history.
 * @param float  $temp Sampling temperature.
 * @param array  $tools Tool declarations.
 * @param array  $perf Performance options.
 * @return string|WP_Error
 */
function quorlyx_call_gemini_with_tools( $api_key, $model, $system_prompt, $history, $temp, $tools, $perf ) {
	try {
		if ( quorlyx_google_model_requires_interactions_api( $model ) ) {
			return quorlyx_google_interactions_model_error();
		}

		$url      = quorlyx_get_google_gemini_generate_content_url( $api_key, $model );

		$function_decls = array();
		foreach ( (array) $tools as $tool ) {
			if ( ! empty( $tool['function'] ) ) {
				$function_decls[] = $tool['function'];
			}
		}

		$body = array(
			'contents'          => quorlyx_format_history_for_gemini( $history ),
			'systemInstruction' => array(
				'parts' => array(
					array(
						'text' => $system_prompt,
					),
				),
			),
			'generationConfig'  => array(
				'temperature' => $temp,
			),
		);

		if ( ! empty( $function_decls ) ) {
			$body['tools']      = array(
				array(
					'functionDeclarations' => $function_decls,
				),
			);
			$body['toolConfig'] = array(
				'functionCallingConfig' => array(
					'mode' => 'AUTO',
				),
			);
		}

		$response = wp_remote_post(
			$url,
			array(
				'headers' => quorlyx_get_gemini_request_headers(
					array(
						'Content-Type' => 'application/json',
					)
				),
				'body'    => wp_json_encode( $body ),
				'timeout' => QUORLYX_API_TIMEOUT,
			)
		);

		if ( is_wp_error( $response ) ) {
			return new WP_Error( 'api_http_error', $response->get_error_message() );
		}

		$response_body = json_decode( wp_remote_retrieve_body( $response ), true );
		$response_code = wp_remote_retrieve_response_code( $response );
		if ( $response_code >= 400 ) {
			$error_details = $response_body['error']['message'] ?? wp_remote_retrieve_body( $response );
			return new WP_Error(
				'api_response_error',
				"API returned status {$response_code}",
				array(
					'status'      => $response_code,
					'details'     => $error_details,
					'retry_after' => quorlyx_parse_retry_after_header( wp_remote_retrieve_header( $response, 'retry-after' ) ),
				)
			);
		}

		$parts         = $response_body['candidates'][0]['content']['parts'] ?? array();
		$function_call = null;
		foreach ( $parts as $part ) {
			if ( isset( $part['functionCall'] ) ) {
				$function_call = $part['functionCall'];
				break;
			}
		}

		if ( ! $function_call ) {
			return $response_body['candidates'][0]['content']['parts'][0]['text'] ?? '';
		}

		$fn   = $function_call['name'] ?? '';
		$args = $function_call['args'] ?? array();
		if ( is_string( $args ) ) {
			$decoded = json_decode( $args, true );
			if ( is_array( $decoded ) ) {
				$args = $decoded;
			}
		}

		if ( 'search_products' === $fn ) {
			$term        = isset( $args['search_term'] ) ? (string) $args['search_term'] : '';
			$limit       = isset( $args['limit'] ) ? absint( $args['limit'] ) : (int) ( $perf['tool_calling_results_limit'] ?? 5 );
			$tool_result = quorlyx_pro_tool_search_products( $term, $perf, $limit );
		} else {
			$tool_result = 'UNSUPPORTED_TOOL';
		}

		$follow_contents   = quorlyx_format_history_for_gemini( $history );
		$follow_contents[] = array(
			'role'  => 'model',
			'parts' => array(
				array(
					'functionCall' => array(
						'name' => $fn,
						'args' => $args,
					),
				),
			),
		);
		$follow_contents[] = array(
			'role'  => 'user',
			'parts' => array(
				array(
					'functionResponse' => array(
						'name'     => $fn,
						'response' => array(
							'content' => $tool_result,
						),
					),
				),
			),
		);

		$body['contents'] = $follow_contents;

		$second = wp_remote_post(
			$url,
			array(
				'headers' => quorlyx_get_gemini_request_headers(
					array(
						'Content-Type' => 'application/json',
					)
				),
				'body'    => wp_json_encode( $body ),
				'timeout' => QUORLYX_API_TIMEOUT,
			)
		);

		if ( is_wp_error( $second ) ) {
			return new WP_Error( 'api_http_error', $second->get_error_message() );
		}

		$second_body = json_decode( wp_remote_retrieve_body( $second ), true );
		$second_code = wp_remote_retrieve_response_code( $second );
		if ( $second_code >= 400 ) {
			$error_details = $second_body['error']['message'] ?? wp_remote_retrieve_body( $second );
			return new WP_Error(
				'api_response_error',
				"API returned status {$second_code}",
				array(
					'status'      => $second_code,
					'details'     => $error_details,
					'retry_after' => quorlyx_parse_retry_after_header( wp_remote_retrieve_header( $second, 'retry-after' ) ),
				)
			);
		}

		return $second_body['candidates'][0]['content']['parts'][0]['text'] ?? '';
	} catch ( Exception $e ) {
		return new WP_Error( 'api_exception', $e->getMessage() );
	}
}

/**
 * Dispatch a provider-specific AI API request.
 *
 * @param string $provider Provider slug.
 * @param string $api_key Provider API key.
 * @param string $model Model name.
 * @param string $system_prompt System prompt text.
 * @param array  $history Message history.
 * @param float  $temp Sampling temperature.
 * @return string|WP_Error
 */
function quorlyx_call_ai_api( $provider, $api_key, $model, $system_prompt, $history, $temp = 0.7 ) {
	try {
		if ( empty( $provider ) || empty( $api_key ) || empty( $model ) ) {
			return new WP_Error( 'missing_params', 'Provider, API key, and model are required.' );
		}
		if ( 'gemini' === $provider && quorlyx_google_model_requires_interactions_api( $model ) ) {
			return quorlyx_google_interactions_model_error();
		}

		$url     = '';
		$headers = array( 'Content-Type' => 'application/json' );
		$body    = array();

		switch ( $provider ) {
			case 'openai':
				$url = 'https://api.openai.com/v1/chat/completions';

				$headers['Authorization'] = 'Bearer ' . $api_key;

				$body = array(
					'model'       => $model,
					'messages'    => quorlyx_format_history_for_openai( $history, $system_prompt ),
					'temperature' => $temp,
				);
				break;
			case 'anthropic':
				$url = 'https://api.anthropic.com/v1/messages';

				$headers['x-api-key']         = $api_key;
				$headers['anthropic-version'] = '2023-06-01';

				$body = array(
					'model'       => $model,
					'system'      => $system_prompt,
					'messages'    => quorlyx_format_history_for_anthropic( $history ),
					'max_tokens'  => 4096,
					'temperature' => $temp,
				);
				break;
			case 'gemini':
				$url             = quorlyx_get_google_gemini_generate_content_url( $api_key, $model );

				$body = array(
					'contents'          => quorlyx_format_history_for_gemini( $history ),
					'systemInstruction' => array(
						'parts' => array(
							array(
								'text' => $system_prompt,
							),
						),
					),
					'generationConfig'  => array(
						'temperature' => $temp,
					),
				);
				break;
			case 'grok':
				$url = 'https://api.x.ai/v1/chat/completions';

				$headers['Authorization'] = 'Bearer ' . $api_key;

				$body = array(
					'model'       => $model,
					'messages'    => quorlyx_format_history_for_openai( $history, $system_prompt ),
					'temperature' => $temp,
				);
				break;
			case 'mistral':
				$url = 'https://api.mistral.ai/v1/chat/completions';

				$headers['Authorization'] = 'Bearer ' . $api_key;

				$body = array(
					'model'       => $model,
					'messages'    => quorlyx_format_history_for_openai( $history, $system_prompt ),
					'temperature' => $temp,
				);
				break;
			case 'deepseek':
				$url = 'https://api.deepseek.com/v1/chat/completions';

				$headers['Authorization'] = 'Bearer ' . $api_key;

				$body = array(
					'model'       => $model,
					'messages'    => quorlyx_format_history_for_openai( $history, $system_prompt ),
					'temperature' => $temp,
				);
				break;
			default:
				return new WP_Error( 'unsupported_provider', 'Unsupported provider.' );
		}

		if ( empty( $url ) || empty( $body ) ) {
			return new WP_Error( 'unsupported_provider', 'Unsupported provider.' );
		}

		$response = wp_remote_post(
			$url,
			array(
				'headers' => 'gemini' === $provider ? quorlyx_get_gemini_request_headers( $headers ) : $headers,
				'body'    => wp_json_encode( $body ),
				'timeout' => QUORLYX_API_TIMEOUT,
			)
		);

		if ( is_wp_error( $response ) ) {
			return new WP_Error( 'api_http_error', $response->get_error_message() );
		}

		$response_body = json_decode( wp_remote_retrieve_body( $response ), true );
		$response_code = wp_remote_retrieve_response_code( $response );

		if ( $response_code >= 400 ) {
			$error_details = isset( $response_body['error']['message'] ) ? $response_body['error']['message'] : wp_remote_retrieve_body( $response );
			return new WP_Error(
				'api_response_error',
				"API returned status {$response_code}",
				array(
					'status'      => $response_code,
					'details'     => $error_details,
					'retry_after' => quorlyx_parse_retry_after_header( wp_remote_retrieve_header( $response, 'retry-after' ) ),
				)
			);
		}

		switch ( $provider ) {
			case 'openai':
			case 'grok':
			case 'mistral':
			case 'deepseek':
				return $response_body['choices'][0]['message']['content'] ?? '';
			case 'anthropic':
				return $response_body['content'][0]['text'] ?? '';
			case 'gemini':
				return $response_body['candidates'][0]['content']['parts'][0]['text'] ?? '';
			default:
				return '';
		}
	} catch ( Exception $e ) {
		return new WP_Error( 'api_exception', $e->getMessage() );
	}

	return '';
}

/**
 * Convert conversation history to OpenAI-style messages.
 *
 * @param array  $history Conversation history.
 * @param string $system_prompt System prompt text.
 * @return array<int,array<string,string>>
 */
function quorlyx_format_history_for_openai( $history, $system_prompt ) {
	$messages = array(
		array(
			'role'    => 'system',
			'content' => $system_prompt,
		),
	);
	foreach ( $history as $item ) {
		if ( empty( $item['parts'][0]['text'] ) ) {
			continue;
		}
		$role       = ( 'model' === $item['role'] ? 'assistant' : 'user' );
		$messages[] = array(
			'role'    => $role,
			'content' => $item['parts'][0]['text'],
		);
	}
	return $messages;
}

/**
 * Convert conversation history to Anthropic-style messages.
 *
 * @param array $history Conversation history.
 * @return array<int,array<string,string>>
 */
function quorlyx_format_history_for_anthropic( $history ) {
	$messages = array();
	foreach ( $history as $item ) {
		if ( empty( $item['parts'][0]['text'] ) ) {
			continue;
		}
		$role       = ( 'model' === $item['role'] ? 'assistant' : 'user' );
		$messages[] = array(
			'role'    => $role,
			'content' => $item['parts'][0]['text'],
		);
	}
	return $messages;
}

/**
 * Normalize conversation history for Gemini requests.
 *
 * @param array $history Conversation history.
 * @return array<int,mixed>
 */
function quorlyx_format_history_for_gemini( $history ) {
	$formatted_history = array();
	foreach ( $history as $item ) {
		if ( empty( $item['parts'][0]['text'] ) ) {
			continue;
		}
		$formatted_history[] = $item;
	}
	return $formatted_history;
}

/**
 * Return allowed trigger analytics event names.
 *
 * @return array<int,string>
 */
function quorlyx_get_trigger_analytics_events() {
	return array(
		'trigger_eligible',
		'trigger_fired',
		'trigger_dismissed',
		'trigger_replied',
		'trigger_converted',
		'trigger_suppressed',
		'trigger_conflict_won',
		'trigger_conflict_lost',
		'trigger_preview_forced',
	);
}

/**
 * Return an initialized trigger metrics row.
 *
 * @return array<string,int>
 */
function quorlyx_get_empty_trigger_metrics_row() {
	$row = array();
	foreach ( quorlyx_get_trigger_analytics_events() as $event_name ) {
		$row[ $event_name ] = 0;
	}
	return $row;
}

/**
 * Load trigger analytics store.
 *
 * @return array<string,mixed>
 */
function quorlyx_get_trigger_analytics_store() {
	$default_store = array(
		'schema_version' => 1,
		'updated_at'     => 0,
		'totals'         => array(),
		'daily'          => array(),
	);

	if ( quorlyx_should_use_global_db_processing() && quorlyx_trigger_analytics_events_table_exists() ) {
		quorlyx_migrate_trigger_analytics_option_to_table();

		global $wpdb;
		$table_name     = quorlyx_get_trigger_analytics_events_table_name();
		$allowed_events = quorlyx_get_trigger_analytics_events();
		$empty_row      = quorlyx_get_empty_trigger_metrics_row();
		$store          = $default_store;

		// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Full read used to reconstruct compatibility analytics payload.
		$rows = $wpdb->get_results( "SELECT trigger_id, event_name, event_date, event_count, updated_at FROM {$table_name}", ARRAY_A );

		foreach ( (array) $rows as $row ) {
			$trigger_id = sanitize_key( (string) ( $row['trigger_id'] ?? '' ) );
			$event_name = sanitize_key( (string) ( $row['event_name'] ?? '' ) );
			$date_key   = sanitize_text_field( (string) ( $row['event_date'] ?? '' ) );
			$count      = max( 0, (int) ( $row['event_count'] ?? 0 ) );

			if ( '' === $trigger_id || '' === $date_key || ! in_array( $event_name, $allowed_events, true ) ) {
				continue;
			}

			if ( ! isset( $store['totals'][ $trigger_id ] ) || ! is_array( $store['totals'][ $trigger_id ] ) ) {
				$store['totals'][ $trigger_id ] = $empty_row;
			}

			if ( ! isset( $store['daily'][ $date_key ] ) || ! is_array( $store['daily'][ $date_key ] ) ) {
				$store['daily'][ $date_key ] = array();
			}

			if ( ! isset( $store['daily'][ $date_key ][ $trigger_id ] ) || ! is_array( $store['daily'][ $date_key ][ $trigger_id ] ) ) {
				$store['daily'][ $date_key ][ $trigger_id ] = $empty_row;
			}

			$store['totals'][ $trigger_id ][ $event_name ]                += $count;
			$store['daily'][ $date_key ][ $trigger_id ][ $event_name ]    += $count;
			$store['updated_at'] = max( $store['updated_at'], strtotime( (string) ( $row['updated_at'] ?? '' ) ) ?: 0 );
		}

		return $store;
	}

	$store = get_option( 'quorlyx_trigger_analytics', array() );
	if ( ! is_array( $store ) ) {
		$store = array();
	}

	$store = wp_parse_args( $store, $default_store );

	if ( ! is_array( $store['totals'] ) ) {
		$store['totals'] = array();
	}
	if ( ! is_array( $store['daily'] ) ) {
		$store['daily'] = array();
	}

	return $store;
}

/**
 * Persist trigger analytics store.
 *
 * @param array<string,mixed> $store Store data.
 * @return bool
 */
function quorlyx_update_trigger_analytics_store( $store ) {
	if ( ! is_array( $store ) ) {
		return false;
	}

	$next_updated_at = time();
	$previous_value  = absint( $store['updated_at'] ?? 0 );
	if ( $next_updated_at <= $previous_value ) {
		$next_updated_at = $previous_value + 1;
	}

	$store['updated_at'] = $next_updated_at;
	quorlyx_touch_content_analytics_updated_at();

	return (bool) update_option( 'quorlyx_trigger_analytics', $store, false );
}

/**
 * Reset trigger analytics from both legacy option storage and DB-first storage.
 *
 * @return int Deleted DB rows.
 */
function quorlyx_reset_trigger_analytics_data() {
	$deleted_rows = 0;

	if ( quorlyx_trigger_analytics_events_table_exists() ) {
		global $wpdb;
		$table_name = quorlyx_get_trigger_analytics_events_table_name();

		// phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Table name comes from trusted helper with wpdb prefix.
		$result = $wpdb->query( "DELETE FROM {$table_name}" );
		if ( false !== $result ) {
			$deleted_rows = (int) $result;
		}
	}

	delete_option( 'quorlyx_trigger_analytics' );
	quorlyx_touch_content_analytics_updated_at();

	return max( 0, $deleted_rows );
}

/**
 * Track a trigger analytics event using the dedicated DB table.
 *
 * @param string $trigger_id Trigger identifier.
 * @param string $event_name Event name.
 * @return bool
 */
function quorlyx_track_trigger_analytics_event_in_db( $trigger_id, $event_name ) {
	quorlyx_migrate_trigger_analytics_option_to_table();

	global $wpdb;

	$table_name = quorlyx_get_trigger_analytics_events_table_name();
	$event_date = gmdate( 'Y-m-d' );
	$now        = gmdate( 'Y-m-d H:i:s' );

	// phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared,WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- Atomic upsert for trigger analytics event counters.
	$result = $wpdb->query(
		$wpdb->prepare(
			"INSERT INTO {$table_name} (trigger_id, event_name, event_date, event_count, created_at, updated_at)
			VALUES (%s, %s, %s, 1, %s, %s)
			ON DUPLICATE KEY UPDATE
				event_count = event_count + 1,
				updated_at = VALUES(updated_at)",
			$trigger_id,
			$event_name,
			$event_date,
			$now,
			$now
		)
	);

	if ( false === $result ) {
		return false;
	}

	quorlyx_touch_content_analytics_updated_at();

	return true;
}

/**
 * Increment trigger analytics counters for an event.
 *
 * @param string $trigger_id Trigger identifier.
 * @param string $event_name Event name.
 * @return bool
 */
function quorlyx_track_trigger_analytics_event( $trigger_id, $event_name ) {
	$trigger_id = sanitize_key( (string) $trigger_id );
	$event_name = sanitize_key( (string) $event_name );

	if ( '' === $trigger_id || ! in_array( $event_name, quorlyx_get_trigger_analytics_events(), true ) ) {
		return false;
	}

	if ( quorlyx_should_use_global_db_processing() && quorlyx_trigger_analytics_events_table_exists() ) {
		return quorlyx_track_trigger_analytics_event_in_db( $trigger_id, $event_name );
	}

	$store     = quorlyx_get_trigger_analytics_store();
	$empty_row = quorlyx_get_empty_trigger_metrics_row();
	$date_key  = gmdate( 'Y-m-d' );

	if ( ! isset( $store['totals'][ $trigger_id ] ) || ! is_array( $store['totals'][ $trigger_id ] ) ) {
		$store['totals'][ $trigger_id ] = $empty_row;
	}

	$store['totals'][ $trigger_id ]                = wp_parse_args( $store['totals'][ $trigger_id ], $empty_row );
	$store['totals'][ $trigger_id ][ $event_name ] = (int) $store['totals'][ $trigger_id ][ $event_name ] + 1;

	if ( ! isset( $store['daily'][ $date_key ] ) || ! is_array( $store['daily'][ $date_key ] ) ) {
		$store['daily'][ $date_key ] = array();
	}

	if ( ! isset( $store['daily'][ $date_key ][ $trigger_id ] ) || ! is_array( $store['daily'][ $date_key ][ $trigger_id ] ) ) {
		$store['daily'][ $date_key ][ $trigger_id ] = $empty_row;
	}

	$store['daily'][ $date_key ][ $trigger_id ]                = wp_parse_args( $store['daily'][ $date_key ][ $trigger_id ], $empty_row );
	$store['daily'][ $date_key ][ $trigger_id ][ $event_name ] = (int) $store['daily'][ $date_key ][ $trigger_id ][ $event_name ] + 1;

	return quorlyx_update_trigger_analytics_store( $store );
}

/**
 * Retrieves or generates the cached whitelist of URLs for Insights Gate.
 *
 * @param array $trigger Trigger settings array.
 * @return array Processed whitelist of URLs.
 */
function quorlyx_get_insights_gate_cached_urls( $trigger ) {
	$trigger_id = sanitize_key( $trigger['id'] ?? '' );
	if ( empty( $trigger_id ) ) {
		return array();
	}

	if ( ! quorlyx_content_insights_is_enabled() ) {
		return array();
	}

	// Use MD5 of the trigger settings that matter, so if they change, it breaks cache automatically.
	$hash = md5(
		wp_json_encode(
			array(
				'cache_rev' => 2,
				'id'        => $trigger_id,
				'op'        => $trigger['insights_gate_views_op'] ?? '>=',
				'min_v'     => $trigger['insights_gate_min_views'] ?? 150,
				'c_op'      => $trigger['insights_gate_conversions_op'] ?? '<=',
				'max_c'     => $trigger['insights_gate_max_conversions'] ?? 3,
				'cr_op'     => $trigger['insights_gate_conversion_rate_op'] ?? '<=',
				'max_cr'    => $trigger['insights_gate_max_conversion_rate'] ?? 2.0,
				'at_op'     => $trigger['insights_gate_avg_time_op'] ?? 'any',
				'min_at'    => $trigger['insights_gate_min_avg_time'] ?? 0,
				's_op'      => $trigger['insights_gate_scroll_op'] ?? 'any',
				'min_s'     => $trigger['insights_gate_min_scroll_depth'] ?? 0,
				'atc_op'    => $trigger['insights_gate_add_to_cart_op'] ?? 'any',
				'min_atc'   => $trigger['insights_gate_min_add_to_cart'] ?? 0,
				'cf_op'     => $trigger['insights_gate_checkout_flow_op'] ?? 'any',
				'min_cf'    => $trigger['insights_gate_min_checkout_flow'] ?? 0,
				'interval'  => $trigger['insights_gate_refresh_interval'] ?? '7d',
			)
		)
	);

	$transient_key    = 'quorlyx_ig_cache_' . substr( $hash, 0, 16 );
	$refresh_interval = $trigger['insights_gate_refresh_interval'] ?? '7d';

	$cached = get_transient( $transient_key );
	if ( is_array( $cached ) ) {
		return $cached;
	}

	$valid_urls = array();
	$settings   = array(
		'enabled'        => true,
		'tracking_mode'  => 'all_public',
		'content_source' => 'any',
	);

	// Add home page.
	$home_row = quorlyx_get_content_insight_row( $settings, 0, 'homepage' );
	if ( $home_row && quorlyx_insights_gate_rules_pass( $trigger, $home_row ) ) {
		$valid_urls[] = home_url( '/' );
	}

	// Evaluate posts.
	$post_types = quorlyx_get_content_insights_post_types();
	$post_limit = max( 100, min( 5000, absint( $settings['dataset_candidate_limit'] ?? 1000 ) ) );
	$posts      = get_posts(
		array(
			'post_type'              => array_keys( $post_types ),
			'post_status'            => 'publish',
			'posts_per_page'         => $post_limit,
			'fields'                 => 'ids',
			'update_post_meta_cache' => false,
			'update_post_term_cache' => false,
		)
	);

	foreach ( $posts as $post_id ) {
		$row = quorlyx_get_content_insight_row( $settings, $post_id, '' );
		if ( ! $row ) {
			continue;
		}
		if ( quorlyx_insights_gate_rules_pass( $trigger, $row ) ) {
			$valid_urls[] = get_permalink( $post_id );
		}
	}

	$expiration = 7 * DAY_IN_SECONDS;
	if ( '1d' === $refresh_interval ) {
		$expiration = DAY_IN_SECONDS;
	} elseif ( '30d' === $refresh_interval ) {
		$expiration = 30 * DAY_IN_SECONDS;
	} elseif ( 'never' === $refresh_interval ) {
		$expiration = 10 * YEAR_IN_SECONDS;
	}

	set_transient( $transient_key, $valid_urls, $expiration );
	return $valid_urls;
}

/**
 * Checks if a specific post's metrics satisfy the trigger's Insights Gate rules.
 *
 * @param array<string,mixed> $trigger Trigger settings.
 * @param array<string,mixed> $row Content insight row.
 * @return bool
 */
function quorlyx_insights_gate_rules_pass( $trigger, $row ) {
	$views            = (int) ( $row['views'] ?? 0 );
	$conversions      = (int) ( $row['conversions'] ?? 0 );
	$conversion_rate  = (float) ( $row['conversion_rate'] ?? 0 );
	$avg_time         = (int) ( $row['avg_time'] ?? 0 );
	$scroll_depth     = (int) ( $row['scroll_depth'] ?? 0 );
	$add_to_cart      = (int) ( $row['add_to_cart'] ?? 0 );
	$checkout_visits  = (int) ( $row['checkout_visits'] ?? 0 );
	$checkout_success = (int) ( $row['checkout_success'] ?? 0 );
	$checkout_flow    = $checkout_visits > 0 ? ( ( $checkout_success / $checkout_visits ) * 100 ) : 0;
	$is_product       = 'product' === sanitize_key( (string) ( $row['post_type'] ?? '' ) );

	$v_pass      = quorlyx_metric_passes_evaluation( $views, $trigger['insights_gate_min_views'] ?? 150, $trigger['insights_gate_views_op'] ?? '>=' );
	$c_pass      = quorlyx_metric_passes_evaluation( $conversions, $trigger['insights_gate_max_conversions'] ?? 3, $trigger['insights_gate_conversions_op'] ?? '<=' );
	$r_pass      = quorlyx_metric_passes_evaluation( $conversion_rate, $trigger['insights_gate_max_conversion_rate'] ?? 2.0, $trigger['insights_gate_conversion_rate_op'] ?? '<=' );
	$at_pass     = quorlyx_metric_passes_evaluation( $avg_time, $trigger['insights_gate_min_avg_time'] ?? 0, $trigger['insights_gate_avg_time_op'] ?? 'any' );
	$scroll_pass = quorlyx_metric_passes_evaluation( $scroll_depth, $trigger['insights_gate_min_scroll_depth'] ?? 0, $trigger['insights_gate_scroll_op'] ?? 'any' );
	$atc_pass    = true;
	$flow_pass   = true;

	if ( $is_product ) {
		$atc_pass  = quorlyx_metric_passes_evaluation( $add_to_cart, $trigger['insights_gate_min_add_to_cart'] ?? 0, $trigger['insights_gate_add_to_cart_op'] ?? 'any' );
		$flow_pass = quorlyx_metric_passes_evaluation( $checkout_flow, $trigger['insights_gate_min_checkout_flow'] ?? 0, $trigger['insights_gate_checkout_flow_op'] ?? 'any' );
	}

	return $v_pass && $c_pass && $r_pass && $at_pass && $scroll_pass && $atc_pass && $flow_pass;
}

/**
 * Generic comparison evaluation.
 *
 * @param float|int|string $actual Observed value.
 * @param float|int|string $threshold Threshold value.
 * @param string           $op Comparison operator.
 * @return bool
 */
function quorlyx_metric_passes_evaluation( $actual, $threshold, $op ) {
	$actual    = (float) $actual;
	$threshold = (float) $threshold;
	if ( 'any' === $op ) {
		return true;
	}
	if ( '>=' === $op ) {
		return $actual >= $threshold;
	}
	if ( '<=' === $op ) {
		return $actual <= $threshold;
	}
	return true;
}

/**
 * Get aggregated trigger analytics by date window.
 *
 * @param string $trigger_id Trigger ID.
 * @return array<string,mixed>
 */
function quorlyx_get_trigger_analytics_windows( $trigger_id ) {
	$trigger_id = sanitize_key( (string) $trigger_id );
	$store      = quorlyx_get_trigger_analytics_store();
	$empty_row  = quorlyx_get_empty_trigger_metrics_row();

	$windows = array(
		'lifetime' => $empty_row,
		'30d'      => $empty_row,
		'7d'       => $empty_row,
	);

	if ( '' === $trigger_id ) {
		return $windows;
	}

	if ( isset( $store['totals'][ $trigger_id ] ) && is_array( $store['totals'][ $trigger_id ] ) ) {
		$windows['lifetime'] = wp_parse_args( $store['totals'][ $trigger_id ], $empty_row );
	}

	$today = gmdate( 'Y-m-d' );
	foreach ( $store['daily'] as $date_key => $rows ) {
		if ( ! is_array( $rows ) || empty( $rows[ $trigger_id ] ) || ! is_array( $rows[ $trigger_id ] ) ) {
			continue;
		}

		$diff_days = (int) floor( ( strtotime( $today ) - strtotime( (string) $date_key ) ) / DAY_IN_SECONDS );
		if ( $diff_days < 0 ) {
			continue;
		}

		foreach ( $rows[ $trigger_id ] as $event_name => $value ) {
			if ( ! isset( $empty_row[ $event_name ] ) ) {
				continue;
			}

			$int_value = (int) $value;
			if ( $diff_days <= 30 ) {
				$windows['30d'][ $event_name ] += $int_value;
			}
			if ( $diff_days <= 7 ) {
				$windows['7d'][ $event_name ] += $int_value;
			}
		}
	}

	return $windows;
}

/**
 * Build trigger analytics rows for dashboard and export.
 *
 * @param array<string,mixed> $options Plugin options.
 * @return array<int,array<string,mixed>>
 */
function quorlyx_get_trigger_analytics_rows( $options = array() ) {
	if ( ! is_array( $options ) || empty( $options ) ) {
		$options = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	}

	$configured_triggers = is_array( $options['triggers'] ?? null ) ? $options['triggers'] : array();
	$trigger_map         = array();
	$trigger_ids         = array();

	foreach ( $configured_triggers as $trigger ) {
		if ( ! is_array( $trigger ) ) {
			continue;
		}

		$trigger_id = sanitize_key( (string) ( $trigger['id'] ?? '' ) );
		if ( '' === $trigger_id ) {
			continue;
		}

		$trigger_map[ $trigger_id ] = array(
			'name' => sanitize_text_field( (string) ( $trigger['name'] ?? $trigger_id ) ),
			'type' => sanitize_key( (string) ( $trigger['type'] ?? 'unknown' ) ),
		);
		$trigger_ids[]              = $trigger_id;
	}

	$store = quorlyx_get_trigger_analytics_store();
	if ( ! empty( $store['totals'] ) && is_array( $store['totals'] ) ) {
		$trigger_ids = array_merge( $trigger_ids, array_map( 'sanitize_key', array_keys( $store['totals'] ) ) );
	}

	$trigger_ids = array_values( array_unique( array_filter( $trigger_ids ) ) );

	$rows = array();
	foreach ( $trigger_ids as $trigger_id ) {
		$windows = quorlyx_get_trigger_analytics_windows( $trigger_id );
		$meta    = $trigger_map[ $trigger_id ] ?? array(
			'name' => $trigger_id,
			'type' => 'unknown',
		);

		$rows[] = array(
			'id'       => $trigger_id,
			'name'     => $meta['name'],
			'type'     => $meta['type'],
			'windows'  => $windows,
			'fired_30' => (int) ( $windows['30d']['trigger_fired'] ?? 0 ),
		);
	}

	usort(
		$rows,
		static function ( $left, $right ) {
			$left_fired  = (int) ( $left['fired_30'] ?? 0 );
			$right_fired = (int) ( $right['fired_30'] ?? 0 );

			if ( $left_fired === $right_fired ) {
				$left_name  = sanitize_text_field( (string) ( $left['name'] ?? '' ) );
				$right_name = sanitize_text_field( (string) ( $right['name'] ?? '' ) );

				return strcmp( $left_name, $right_name );
			}

			return $right_fired <=> $left_fired;
		}
	);

	return $rows;
}

add_action( 'wp_ajax_quorlyx_track_trigger_event', 'quorlyx_ajax_track_trigger_event' );
add_action( 'wp_ajax_nopriv_quorlyx_track_trigger_event', 'quorlyx_ajax_track_trigger_event' );
/**
 * AJAX handler to track trigger analytics events.
 *
 * @return void
 */
function quorlyx_ajax_track_trigger_event() {
	check_ajax_referer( 'quorlyx_analytics_nonce', 'nonce' );

	$trigger_id = isset( $_POST['trigger_id'] ) ? sanitize_key( wp_unslash( $_POST['trigger_id'] ) ) : '';
	$event_name = isset( $_POST['event_name'] ) ? sanitize_key( wp_unslash( $_POST['event_name'] ) ) : '';

	if ( '' === $trigger_id || '' === $event_name ) {
		wp_send_json_error(
			array(
				'message' => 'Missing trigger_id or event_name.',
			)
		);
	}

	if ( ! in_array( $event_name, quorlyx_get_trigger_analytics_events(), true ) ) {
		wp_send_json_error(
			array(
				'message' => 'Unsupported trigger event.',
			)
		);
	}

	$ok = quorlyx_track_trigger_analytics_event( $trigger_id, $event_name );

	if ( ! $ok ) {
		wp_send_json_error(
			array(
				'message' => 'Could not store trigger analytics event.',
			)
		);
	}

	wp_send_json_success(
		array(
			'trigger_id'   => $trigger_id,
			'event_name'   => $event_name,
			'data_version' => quorlyx_get_insights_gate_data_version(),
		)
	);
}

/**
 * Process one lightweight content analytics event payload.
 *
 * @param array<string,mixed> $event Event payload.
 * @return bool Whether an event was processed.
 */
function quorlyx_process_content_analytics_event( $event ) {
	if ( ! is_array( $event ) ) {
		return false;
	}

	$type        = sanitize_key( (string) ( $event['type'] ?? $event['event'] ?? '' ) );
	$post_id     = isset( $event['post_id'] ) ? absint( $event['post_id'] ) : 0;
	$post_id     = quorlyx_get_canonical_analytics_post_id( $post_id );
	$content_key = isset( $event['content_key'] ) ? sanitize_key( (string) $event['content_key'] ) : '';

	if ( $post_id > 0 ) {
		$content_key = '';
	}

	switch ( $type ) {
		case 'view':
			if ( quorlyx_content_insights_is_enabled() && ( $post_id || $content_key ) ) {
				quorlyx_increment_analytics_metric( $post_id, '_quorlyx_analytics_views', 1, $content_key );
				return true;
			}
			break;

		case 'time':
			$seconds = isset( $event['seconds'] ) ? absint( $event['seconds'] ) : 0;
			if ( quorlyx_content_insights_is_enabled() && ( $post_id || $content_key ) && $seconds > 0 ) {
				quorlyx_increment_analytics_metric( $post_id, '_quorlyx_analytics_time_on_page', $seconds, $content_key );
				return true;
			}
			break;

		case 'scroll':
			$depth = isset( $event['depth'] ) ? absint( $event['depth'] ) : 0;
			if ( quorlyx_content_insights_is_enabled() && ( $post_id || $content_key ) && $depth > 0 ) {
				$total   = quorlyx_increment_analytics_metric( $post_id, '_quorlyx_analytics_scroll_depth_total', $depth, $content_key );
				$count   = quorlyx_increment_analytics_metric( $post_id, '_quorlyx_analytics_scroll_depth_count', 1, $content_key );
				$new_avg = $count > 0 ? round( $total / $count ) : 0;
				quorlyx_update_analytics_metric( $post_id, '_quorlyx_analytics_scroll_depth', $new_avg, $content_key );
				return true;
			}
			break;

		case 'atc':
			if ( quorlyx_content_insights_is_enabled() && ( $post_id || $content_key ) ) {
				quorlyx_increment_analytics_metric( $post_id, '_quorlyx_analytics_add_to_cart', 1, $content_key );
				return true;
			}
			break;

		case 'conversion':
			$content_insights_settings = quorlyx_get_content_insights_settings();
			$track_generic_conversion  = quorlyx_content_insights_is_enabled( $content_insights_settings ) && quorlyx_content_insights_tracks_any_conversions( $content_insights_settings );
			$trigger_id                = isset( $event['trigger_id'] ) ? sanitize_key( (string) $event['trigger_id'] ) : '';

			if ( $post_id <= 0 && '' === $content_key ) {
				$attribution_source = quorlyx_get_attribution_source_from_request();
				$post_id            = quorlyx_get_canonical_analytics_post_id( absint( $attribution_source['post_id'] ?? 0 ) );
				$content_key        = sanitize_key( (string) ( $attribution_source['content_key'] ?? '' ) );
			}
			if ( $post_id > 0 ) {
				$content_key = '';
			}
			if ( '' === $trigger_id && ! empty( $_COOKIE['quorlyx_attribution_trigger_id'] ) ) {
				$trigger_id = sanitize_key( wp_unslash( $_COOKIE['quorlyx_attribution_trigger_id'] ) );
			}

			$processed = false;
			if ( $track_generic_conversion && ( $post_id || $content_key ) ) {
				quorlyx_increment_content_insights_attributed_conversion( $post_id, $content_key );
				$processed = true;
			}
			if ( '' !== $trigger_id ) {
				quorlyx_track_trigger_analytics_event( $trigger_id, 'trigger_converted' );
				$processed = true;
			}

			return $processed;
	}

	return false;
}

add_action( 'wp_ajax_quorlyx_track_analytics_batch', 'quorlyx_ajax_track_analytics_batch' );
add_action( 'wp_ajax_nopriv_quorlyx_track_analytics_batch', 'quorlyx_ajax_track_analytics_batch' );
/**
 * AJAX handler to process batched content analytics events.
 *
 * @return void
 */
function quorlyx_ajax_track_analytics_batch() {
	check_ajax_referer( 'quorlyx_analytics_nonce', 'nonce' );

	$raw_events = isset( $_POST['events'] ) ? wp_unslash( $_POST['events'] ) : array();
	if ( is_string( $raw_events ) ) {
		$decoded = json_decode( $raw_events, true );
		$events  = is_array( $decoded ) ? $decoded : array();
	} else {
		$events = is_array( $raw_events ) ? $raw_events : array();
	}

	$events    = array_slice( array_values( $events ), 0, 25 );
	$processed = 0;
	foreach ( $events as $event ) {
		if ( quorlyx_process_content_analytics_event( is_array( $event ) ? $event : array() ) ) {
			++$processed;
		}
	}

	wp_send_json_success(
		array(
			'processed' => $processed,
		)
	);
}

