add_action( 'wp_ajax_quorlyx_track_conversion', 'quorlyx_ajax_track_conversion' );
add_action( 'wp_ajax_nopriv_quorlyx_track_conversion', 'quorlyx_ajax_track_conversion' );
/**
 * AJAX handler to track conversion events.
 *
 * @return void
 */
function quorlyx_ajax_track_conversion() {
	check_ajax_referer( 'quorlyx_analytics_nonce', 'nonce' );
	$content_insights_settings = quorlyx_get_content_insights_settings();
	$content_insights_enabled  = quorlyx_content_insights_is_enabled( $content_insights_settings );
	$track_generic_conversion  = $content_insights_enabled && quorlyx_content_insights_tracks_any_conversions( $content_insights_settings );
	$post_id                   = isset( $_POST['post_id'] ) ? absint( wp_unslash( $_POST['post_id'] ) ) : 0;
	$post_id                   = quorlyx_get_canonical_analytics_post_id( $post_id );
	$content_key               = isset( $_POST['content_key'] ) ? sanitize_key( wp_unslash( $_POST['content_key'] ) ) : '';
	$trigger_id                = isset( $_POST['trigger_id'] ) ? sanitize_key( wp_unslash( $_POST['trigger_id'] ) ) : '';

	if ( $post_id <= 0 && '' === $content_key ) {
		$attribution_source = quorlyx_get_attribution_source_from_request();
		$post_id            = quorlyx_get_canonical_analytics_post_id( absint( $attribution_source['post_id'] ?? 0 ) );
		$content_key        = sanitize_key( (string) ( $attribution_source['content_key'] ?? '' ) );
	}

	if ( $post_id > 0 ) {
		$content_key = '';
	}

	if ( '' === $trigger_id && ! empty( $_COOKIE['quorlyx_attribution_trigger_id'] ) ) {
		$trigger_id = sanitize_key( wp_unslash( $_COOKIE['quorlyx_attribution_trigger_id'] ) );
	}

	if ( $track_generic_conversion && ( $post_id || $content_key ) ) {
		quorlyx_increment_content_insights_attributed_conversion( $post_id, $content_key );

		if ( class_exists( 'Quorlyx_Pro_Logger' ) ) {
			$cookie_attr             = isset( $_COOKIE['quorlyx_attribution_post_id'] ) ? sanitize_text_field( wp_unslash( $_COOKIE['quorlyx_attribution_post_id'] ) ) : null;
			$cookie_attr_content_key = isset( $_COOKIE['quorlyx_attribution_content_key'] ) ? sanitize_key( wp_unslash( $_COOKIE['quorlyx_attribution_content_key'] ) ) : '';
			Quorlyx_Pro_Logger::log(
				'info',
				'conversion_received',
				array(
					'post_id'            => $post_id,
					'content_key'        => $content_key,
					'cookie_attribution' => $cookie_attr,
					'cookie_content_key' => $cookie_attr_content_key,
				)
			);
		}
	} elseif ( $track_generic_conversion && class_exists( 'Quorlyx_Pro_Logger' ) ) {
		Quorlyx_Pro_Logger::log(
			'warning',
			'conversion_missing_source',
			array(
				'post_id'     => $post_id,
				'content_key' => $content_key,
			)
		);
	}

	if ( '' !== $trigger_id ) {
		quorlyx_track_trigger_analytics_event( $trigger_id, 'trigger_converted' );
	}

	wp_die();
}

/**
 * Normalize behavior snapshot sync reasons from the frontend tracker.
 *
 * @param mixed $sync_reason Raw sync reason.
 * @return string
 */
function quorlyx_normalize_behavior_sync_reason( $sync_reason ) {
	$sync_reason = sanitize_key( (string) $sync_reason );
	$allowed     = array( 'interval', 'milestone', 'initial_live_prediction', 'beforeunload', 'visibility_hidden', 'conversion' );

	return in_array( $sync_reason, $allowed, true ) ? $sync_reason : 'interval';
}

/**
 * Build a compact signature for behavior snapshot dedupe.
 *
 * @param array<string,mixed> $snapshot Snapshot values that affect classification/persistence.
 * @return string
 */
function quorlyx_build_behavior_snapshot_signature( $snapshot ) {
	$snapshot = is_array( $snapshot ) ? $snapshot : array();
	ksort( $snapshot );

	$encoded = wp_json_encode( $snapshot );
	if ( ! is_string( $encoded ) || '' === $encoded ) {
		$encoded = serialize( $snapshot ); // phpcs:ignore WordPress.PHP.DiscouragedPHPFunctions.serialize_serialize -- Fallback for a local hash only.
	}

	return hash( 'sha256', $encoded );
}

/**
 * Return the transient key used to guard behavior snapshot bursts.
 *
 * @param string $profile_hash   Profile hash.
 * @param int    $source_post_id Source post ID.
 * @param string $content_key    Source content key.
 * @return string
 */
function quorlyx_get_behavior_snapshot_guard_key( $profile_hash, $source_post_id, $content_key ) {
	return 'qbx_snapshot_guard_' . substr( md5( sanitize_text_field( (string) $profile_hash ) . '|' . absint( $source_post_id ) . '|' . sanitize_key( (string) $content_key ) ), 0, 32 );
}

/**
 * Determine whether a behavior snapshot should bypass burst throttling.
 *
 * @param string $sync_reason       Frontend sync reason.
 * @param string $conversion_status Normalized conversion status.
 * @param int    $started_chat      Whether chat started.
 * @param int    $cart_activity     Cart activity count.
 * @param string $abandonment_stage Checkout/cart stage.
 * @return bool
 */
function quorlyx_is_high_priority_behavior_snapshot( $sync_reason, $conversion_status, $started_chat, $cart_activity, $abandonment_stage ) {
	$sync_reason       = quorlyx_normalize_behavior_sync_reason( $sync_reason );
	$conversion_status = quorlyx_normalize_behavior_conversion_status( $conversion_status );
	$abandonment_stage = sanitize_key( (string) $abandonment_stage );

	if ( in_array( $sync_reason, array( 'initial_live_prediction', 'beforeunload', 'visibility_hidden', 'conversion' ), true ) ) {
		return true;
	}

	return 'closer' === $conversion_status ||
		absint( $started_chat ) > 0 ||
		absint( $cart_activity ) > 0 ||
		in_array( $abandonment_stage, array( 'viewed_cart', 'abandoned_checkout' ), true );
}

add_action( 'wp_ajax_quorlyx_track_behavior_snapshot', 'quorlyx_ajax_track_behavior_snapshot' );
add_action( 'wp_ajax_nopriv_quorlyx_track_behavior_snapshot', 'quorlyx_ajax_track_behavior_snapshot' );
/**
 * AJAX handler to track behavior-engine snapshots.
 *
 * @return void
 */
function quorlyx_ajax_track_behavior_snapshot() {
	if ( false === check_ajax_referer( 'quorlyx_analytics_nonce', 'nonce', false ) ) {
		wp_send_json_error(
			array(
				'message' => 'Invalid nonce.',
			),
			403
		);
	}

	if ( ! quorlyx_content_insights_is_enabled() ) {
		wp_send_json_error(
			array(
				'message' => 'Content Insights is disabled.',
			),
			403
		);
	}

	$options            = get_option( 'quorlyx_options', quorlyx_get_global_defaults() );
	$options            = array_replace_recursive( quorlyx_get_global_defaults(), is_array( $options ) ? $options : array() );
	$content_settings   = is_array( $options['content_insights'] ?? null ) ? $options['content_insights'] : array();
	$behavior_settings  = quorlyx_get_behavior_pattern_settings( $content_settings );

	if ( empty( $behavior_settings['enabled'] ) ) {
		wp_send_json_success(
			array(
				'skipped' => 'behavior_engine_disabled',
			)
		);
	}

	// Ensure frontend AJAX requests can self-heal schema upgrades without requiring an admin page load.
	quorlyx_maybe_install_behavior_engine_table();

	$post_id     = isset( $_POST['post_id'] ) ? absint( wp_unslash( $_POST['post_id'] ) ) : 0;
	$post_id     = quorlyx_get_canonical_analytics_post_id( $post_id );
	$content_key = isset( $_POST['content_key'] ) ? sanitize_key( wp_unslash( $_POST['content_key'] ) ) : '';
	$current_post_id     = isset( $_POST['current_post_id'] ) ? absint( wp_unslash( $_POST['current_post_id'] ) ) : $post_id;
	$current_post_id     = quorlyx_get_canonical_analytics_post_id( $current_post_id );
	$current_content_key = isset( $_POST['current_content_key'] ) ? sanitize_key( wp_unslash( $_POST['current_content_key'] ) ) : $content_key;
	$entry_post_id     = isset( $_POST['entry_post_id'] ) ? absint( wp_unslash( $_POST['entry_post_id'] ) ) : 0;
	$entry_post_id     = quorlyx_get_canonical_analytics_post_id( $entry_post_id );
	$entry_content_key = isset( $_POST['entry_content_key'] ) ? sanitize_key( wp_unslash( $_POST['entry_content_key'] ) ) : '';

	if ( $entry_post_id > 0 || '' !== $entry_content_key ) {
		$post_id     = $entry_post_id;
		$content_key = $entry_content_key;
	}

	$front_page_id = quorlyx_get_canonical_analytics_post_id( (int) get_option( 'page_on_front' ) );
	if ( $front_page_id > 0 && quorlyx_content_insights_homepage_matches_settings( $content_settings ) ) {
		if ( $post_id === $front_page_id && '' === $content_key && ! quorlyx_content_insights_post_matches_settings( $post_id, $content_settings ) ) {
			$post_id     = 0;
			$content_key = 'homepage';
		}

		if ( $current_post_id === $front_page_id && '' === $current_content_key && ! quorlyx_content_insights_post_matches_settings( $current_post_id, $content_settings ) ) {
			$current_post_id     = 0;
			$current_content_key = 'homepage';
		}
	}

	if ( $post_id <= 0 && '' === $content_key ) {
		wp_send_json_error(
			array(
				'message' => 'Missing tracked source.',
			),
			400
		);
	}

	$source_in_scope = true;
	if ( $post_id > 0 && ! quorlyx_content_insights_post_matches_settings( $post_id, $content_settings ) ) {
		$source_in_scope = false;
	}
	if ( 'homepage' === $content_key ) {
		// Behavior Engine special case: If the site tracks behavior, we almost always want to accept 
		// the homepage as a valid entry source, even if it's omitted from specific post rules.
		if ( empty( $behavior_settings['enabled'] ) || empty( $content_settings['enabled'] ) ) {
			$source_in_scope = false;
		}
	}

	if ( ! $source_in_scope ) {
		$fallback_in_scope = false;
		if ( $current_post_id > 0 && quorlyx_content_insights_post_matches_settings( $current_post_id, $content_settings ) ) {
			$post_id          = $current_post_id;
			$content_key      = '';
			$fallback_in_scope = true;
		} elseif ( 'homepage' === $current_content_key && quorlyx_content_insights_homepage_matches_settings( $content_settings ) ) {
			$post_id          = 0;
			$content_key      = 'homepage';
			$fallback_in_scope = true;
		}

		if ( ! $fallback_in_scope ) {
			wp_send_json_success(
				array(
					'skipped' => ( 'homepage' === $content_key ) ? 'homepage_outside_scope' : 'outside_tracking_scope',
				)
			);
		}
	}

	$profile_id = isset( $_POST['profile_id'] ) ? sanitize_text_field( wp_unslash( $_POST['profile_id'] ) ) : '';
	if ( '' === $profile_id ) {
		wp_send_json_error(
			array(
				'message' => 'Missing profile ID.',
			),
			400
		);
	}

	$profile_hash      = hash( 'sha256', $profile_id . '|' . wp_salt( 'nonce' ) );
	$visit_frequency   = isset( $_POST['visit_frequency'] ) ? absint( wp_unslash( $_POST['visit_frequency'] ) ) : 0;
	$pages_viewed      = isset( $_POST['pages_viewed'] ) ? absint( wp_unslash( $_POST['pages_viewed'] ) ) : 0;
	$dwell_time_avg    = isset( $_POST['dwell_time_avg'] ) ? absint( wp_unslash( $_POST['dwell_time_avg'] ) ) : 0;
	$cart_activity     = isset( $_POST['cart_activity'] ) ? absint( wp_unslash( $_POST['cart_activity'] ) ) : 0;
	$scroll_depth      = isset( $_POST['scroll_depth'] ) ? absint( wp_unslash( $_POST['scroll_depth'] ) ) : 0;
	$conversion_status = isset( $_POST['conversion_status'] ) ? quorlyx_normalize_behavior_conversion_status( wp_unslash( $_POST['conversion_status'] ) ) : 'unknown';
	$product_id        = isset( $_POST['product_id'] ) ? absint( wp_unslash( $_POST['product_id'] ) ) : 0;
	$dwell_samples     = isset( $_POST['dwell_samples'] ) ? max( 1, absint( wp_unslash( $_POST['dwell_samples'] ) ) ) : 1;

	// New fields.
	$last_post_id       = isset( $_POST['last_post_id'] ) ? absint( wp_unslash( $_POST['last_post_id'] ) ) : 0;
	$last_post_id       = quorlyx_get_canonical_analytics_post_id( $last_post_id );
	$last_content_key   = isset( $_POST['last_content_key'] ) ? sanitize_key( wp_unslash( $_POST['last_content_key'] ) ) : '';
	$category_breakdown = isset( $_POST['category_breakdown'] ) ? sanitize_text_field( wp_unslash( $_POST['category_breakdown'] ) ) : '{}';
	$abandonment_stage  = isset( $_POST['abandonment_stage'] ) ? sanitize_key( wp_unslash( $_POST['abandonment_stage'] ) ) : '';
	$started_chat       = ! empty( $_POST['started_chat'] ) ? 1 : 0;
	$traffic_source     = isset( $_POST['traffic_source'] ) ? quorlyx_normalize_traffic_source_segment( wp_unslash( $_POST['traffic_source'] ) ) : 'direct';
	$session_id         = isset( $_POST['session_id'] ) ? sanitize_text_field( wp_unslash( $_POST['session_id'] ) ) : '';
	$visited_path       = isset( $_POST['visited_path'] ) ? quorlyx_sanitize_array( wp_unslash( $_POST['visited_path'] ) ) : array();
	$sync_reason        = isset( $_POST['sync_reason'] ) ? quorlyx_normalize_behavior_sync_reason( wp_unslash( $_POST['sync_reason'] ) ) : 'interval';

	if ( ! in_array( $abandonment_stage, array( '', 'viewed_cart', 'abandoned_checkout' ), true ) ) {
		$abandonment_stage = '';
	}
	if ( 'closer' === $conversion_status ) {
		$abandonment_stage = '';
	}

	$product_id = quorlyx_get_canonical_analytics_post_id( $product_id );
	if ( $product_id > 0 && ! in_array( get_post_type( $product_id ), array( 'product', 'product_variation' ), true ) ) {
		$product_id = 0;
	}

	if ( 'closer' === $conversion_status && empty( $behavior_settings['include_buyers'] ) ) {
		wp_send_json_success(
			array(
				'skipped' => 'closers_excluded',
			)
		);
	}

	$sampled_non_converter = false;
	if ( 'non_converter' === $conversion_status ) {
		if ( empty( $behavior_settings['include_non_converters'] ) ) {
			wp_send_json_success(
				array(
					'skipped' => 'non_converters_excluded',
				)
			);
		}

		$min_sessions = max( 1, absint( $behavior_settings['min_sessions_for_classification'] ?? 1 ) );
		if ( $visit_frequency < $min_sessions ) {
			$conversion_status = 'unknown';
		} else {
			$sample_rate           = 100;
			$sampled_non_converter = quorlyx_behavior_engine_should_sample_non_converter( $profile_hash, $post_id, $content_key, $sample_rate );

			if ( ! $sampled_non_converter ) {
				$conversion_status = 'unknown';
			}
		}
	}

	$snapshot_signature = quorlyx_build_behavior_snapshot_signature(
		array(
			'source_post_id'        => $post_id,
			'content_key'           => $content_key,
			'last_post_id'          => $last_post_id,
			'last_content_key'      => $last_content_key,
			'category_breakdown'    => $category_breakdown,
			'abandonment_stage'     => $abandonment_stage,
			'started_chat'          => $started_chat,
			'visited_path'          => $visited_path,
			'traffic_source'        => $traffic_source,
			'product_id'            => $product_id,
			'visit_frequency'       => $visit_frequency,
			'pages_viewed'          => $pages_viewed,
			'dwell_time_avg'        => $dwell_time_avg,
			'cart_activity'         => $cart_activity,
			'scroll_depth'          => $scroll_depth,
			'conversion_status'     => $conversion_status,
			'sampled_non_converter' => $sampled_non_converter,
			'dwell_samples'         => $dwell_samples,
		)
	);
	$guard_key          = quorlyx_get_behavior_snapshot_guard_key( $profile_hash, $post_id, $content_key );
	$guard_payload      = get_transient( $guard_key );
	$guard_payload      = is_array( $guard_payload ) ? $guard_payload : array();
	$guard_signature    = sanitize_text_field( (string) ( $guard_payload['signature'] ?? '' ) );
	$guard_timestamp    = absint( $guard_payload['ts'] ?? 0 );
	$min_gap_seconds    = max( 2, min( 60, absint( $behavior_settings['server_min_snapshot_gap_seconds'] ?? 6 ) ) );
	$high_priority_sync = quorlyx_is_high_priority_behavior_snapshot( $sync_reason, $conversion_status, $started_chat, $cart_activity, $abandonment_stage );

	if ( '' !== $snapshot_signature && $snapshot_signature === $guard_signature ) {
		wp_send_json_success(
			array(
				'skipped'      => 'duplicate_snapshot',
				'data_version' => quorlyx_get_insights_gate_data_version(),
			)
		);
	}

	if ( ! $high_priority_sync && $guard_timestamp > 0 && ( time() - $guard_timestamp ) < $min_gap_seconds ) {
		wp_send_json_success(
			array(
				'skipped'      => 'rate_limited_snapshot',
				'data_version' => quorlyx_get_insights_gate_data_version(),
			)
		);
	}

	$classification_result = quorlyx_classify_behavior_pattern_with_meta(
		$visit_frequency,
		$pages_viewed,
		$dwell_time_avg,
		$cart_activity,
		$scroll_depth,
		$conversion_status,
		$behavior_settings,
		array(
			'started_chat'     => $started_chat,
			'source_post_id'   => $post_id,
			'content_key'      => $content_key,
			'product_id'       => $product_id,
			'traffic_source'   => $traffic_source,
			'abandonment_stage' => $abandonment_stage,
		)
	);
	$pattern_tag          = quorlyx_normalize_behavior_pattern_key( (string) ( $classification_result['pattern_tag'] ?? 'unknown' ) );
	$classification_meta  = is_array( $classification_result['meta'] ?? null ) ? $classification_result['meta'] : array();

	$next_step_prediction = quorlyx_predict_behavior_next_step(
		$pattern_tag,
		$visit_frequency,
		$pages_viewed,
		$dwell_time_avg,
		$cart_activity,
		$scroll_depth,
		$conversion_status,
		array(
			'started_chat'      => $started_chat,
			'abandonment_stage' => $abandonment_stage,
		)
	);

	$saved = quorlyx_upsert_behavior_engine_snapshot(
		array(
			'session_id'            => $session_id,
			'profile_hash'          => $profile_hash,
			'source_post_id'        => $post_id,
			'content_key'           => $content_key,
			'last_post_id'          => $last_post_id,
			'last_content_key'      => $last_content_key,
			'category_breakdown'    => $category_breakdown,
			'abandonment_stage'     => $abandonment_stage,
			'started_chat'          => $started_chat,
			'visited_path'          => wp_json_encode( $visited_path ),
			'traffic_source'        => $traffic_source,
			'product_id'            => $product_id,
			'visit_frequency'       => $visit_frequency,
			'pages_viewed'          => $pages_viewed,
			'dwell_time_avg'        => $dwell_time_avg,
			'cart_activity'         => $cart_activity,
			'scroll_depth'          => $scroll_depth,
			'conversion_status'     => $conversion_status,
			'sampled_non_converter' => $sampled_non_converter,
			'dwell_samples'         => $dwell_samples,
		)
	);

	if ( ! $saved ) {
		wp_send_json_error(
			array(
				'message' => 'Could not persist behavior snapshot.',
			),
			500
		);
	}

	quorlyx_maybe_prune_behavior_engine_rows( absint( $behavior_settings['profile_retention_days'] ?? 90 ) );
	set_transient(
		$guard_key,
		array(
			'ts'        => time(),
			'signature' => $snapshot_signature,
		),
		max( 60, min( DAY_IN_SECONDS, absint( $behavior_settings['sync_interval_minutes'] ?? 15 ) * MINUTE_IN_SECONDS ) )
	);

	wp_send_json_success(
		array(
			'pattern_tag'           => $pattern_tag,
			'pattern_label'         => quorlyx_get_behavior_pattern_label( $pattern_tag ),
			'pattern_source'        => sanitize_key( (string) ( $classification_meta['pattern_source'] ?? 'rule' ) ),
			'match_error_pct'       => absint( $classification_meta['match_error_pct'] ?? 0 ),
			'tolerance_pct'         => absint( $classification_meta['tolerance_pct'] ?? 0 ),
			'live_score'            => absint( $classification_meta['live_score'] ?? 0 ),
			'prototype_score'       => absint( $classification_meta['prototype_score'] ?? 0 ),
			'reference_total_profiles' => absint( $classification_meta['total_profiles'] ?? 0 ),
			'reference_required_profiles' => absint( $classification_meta['required_profiles'] ?? 0 ),
			'insufficient_reference_data' => ! empty( $classification_meta['insufficient_data'] ),
			'insufficient_reference_reason' => sanitize_key( (string) ( $classification_meta['insufficient_reason'] ?? '' ) ),
			'next_step_prediction'  => $next_step_prediction,
			'data_version'          => quorlyx_get_insights_gate_data_version(),
		)
	);
}

add_action( 'wp_ajax_quorlyx_reset_history', 'quorlyx_ajax_reset_history' );
/**
 * AJAX handler to reset generated keyword history.
 *
 * @return void
 */
function quorlyx_ajax_reset_history() {
	check_ajax_referer( 'quorlyx_reset_history' );
	if ( ! quorlyx_current_user_can_manage() ) {
		wp_send_json_error( 'Permission denied' );
	}

	delete_option( 'quorlyx_generated_history' );
	wp_send_json_success();
}











































/**
 * Generate a unique request ID for structured logs.
 *
 * @param string $prefix Optional request prefix.
 * @return string
 */
function quorlyx_generate_log_request_id( $prefix = 'qrx' ) {
	$prefix = sanitize_key( (string) $prefix );
	if ( '' === $prefix ) {
		$prefix = 'qrx';
	}

	if ( function_exists( 'wp_generate_uuid4' ) ) {
		return $prefix . '_' . wp_generate_uuid4();
	}

	return $prefix . '_' . uniqid( '', true );
}

/**
 * Verify admin AJAX nonce for privileged requests.
 *
 * @return true|WP_Error
 */
function quorlyx_verify_admin_ajax_nonce() {
	if ( false === check_ajax_referer( 'wp_rest', false, false ) ) {
		return new WP_Error( 'invalid_nonce', 'Security check failed. Please refresh and try again.' );
	}

	return true;
}

/**
 * Send a structured AJAX error response and log details.
 *
 * @param string              $message Error message.
 * @param array<string,mixed> $details Error context details.
 * @param int                 $http_status HTTP status code.
 * @param string              $type Log severity.
 * @return void
 */
function quorlyx_log_ajax_error( $message, $details = array(), $http_status = 400, $type = 'error' ) {
	$message = sanitize_text_field( (string) $message );
	$type    = sanitize_key( (string) $type );
	$status  = absint( $http_status );

	if ( '' === $message ) {
		$message = 'Request failed.';
	}
	if ( ! in_array( $type, array( 'info', 'warning', 'error', 'critical' ), true ) ) {
		$type = 'error';
	}
	if ( $status <= 0 ) {
		$status = 400;
	}

	if ( ! is_array( $details ) ) {
		$details = array(
			'raw_detail' => sanitize_text_field( (string) $details ),
		);
	}

	// phpcs:disable WordPress.Security.NonceVerification.Recommended -- Action key is logged only; caller performs nonce/capability checks.
	$action = isset( $_REQUEST['action'] ) ? sanitize_key( wp_unslash( $_REQUEST['action'] ) ) : 'unknown_action';
	// phpcs:enable WordPress.Security.NonceVerification.Recommended
	if ( ! isset( $details['component'] ) ) {
		$details['component'] = 'admin_ajax';
	}
	if ( ! isset( $details['operation'] ) ) {
		$details['operation'] = $action;
	}
	if ( ! isset( $details['request_id'] ) ) {
		$details['request_id'] = quorlyx_generate_log_request_id( $action );
	}

	$details['ajax_action']     = $action;
	$details['http_status']     = $status;
	$details['error_type']      = $type;
	$details['server_time_utc'] = gmdate( 'c' );

	if ( class_exists( 'Quorlyx_Pro_Logger' ) ) {
		Quorlyx_Pro_Logger::log( $type, $message, $details );
	}

	wp_send_json_error(
		array(
			'message' => $message,
			'details' => $details,
		),
		$status
	);
}

/**
 * Validate uploaded CSV input for import endpoints.
 *
 * @return array<string,mixed>|WP_Error
 */
function quorlyx_get_uploaded_csv_file() {
	if ( false === check_ajax_referer( 'wp_rest', false, false ) ) {
		return new WP_Error( 'invalid_nonce', 'Security check failed. Please refresh and try again.' );
	}

	if ( empty( $_FILES['quorlyx_csv'] ) || ! is_array( $_FILES['quorlyx_csv'] ) ) {
		return new WP_Error( 'missing_file', 'No CSV file uploaded.' );
	}

	// phpcs:ignore WordPress.Security.ValidatedSanitizedInput.InputNotSanitized -- Uploaded file array is validated field-by-field below.
	$file = $_FILES['quorlyx_csv'];
	if ( ! isset( $file['error'] ) || UPLOAD_ERR_OK !== (int) $file['error'] ) {
		$upload_error = isset( $file['error'] ) ? (int) $file['error'] : -1;
		return new WP_Error( 'upload_failed', 'Upload failed.', array( 'upload_error' => $upload_error ) );
	}

	$filename = sanitize_file_name( (string) ( $file['name'] ?? '' ) );
	$tmp_name = (string) ( $file['tmp_name'] ?? '' );

	if ( '' === $filename || '' === $tmp_name || ! file_exists( $tmp_name ) ) {
		return new WP_Error( 'invalid_upload', 'Uploaded file is not available for processing.' );
	}

	$filetype     = wp_check_filetype_and_ext( $tmp_name, $filename );
	$detected_ext = strtolower( (string) ( $filetype['ext'] ?? '' ) );
	$path_ext     = strtolower( pathinfo( $filename, PATHINFO_EXTENSION ) );
	$final_ext    = '' !== $detected_ext ? $detected_ext : $path_ext;

	if ( 'csv' !== $final_ext ) {
		return new WP_Error( 'invalid_file_type', 'Invalid file type. Only CSV files are allowed.' );
	}

	return array(
		'name'     => $filename,
		'tmp_name' => $tmp_name,
		'size'     => isset( $file['size'] ) ? absint( $file['size'] ) : 0,
	);
}

/**
 * Extract numeric tokens from a raw CSV metric value.
 *
 * @param mixed $raw_value Raw cell value.
 * @return array<int,float>
 */
function quorlyx_extract_csv_numeric_tokens( $raw_value ) {
	$value = trim( (string) $raw_value );
	if ( '' === $value ) {
		return array();
	}

	$matches = array();
	$result  = preg_match_all( '/-?\d[\d,\s]*(?:\.\d+)?/', $value, $matches );
	if ( ! is_int( $result ) || $result <= 0 || empty( $matches[0] ) ) {
		return array();
	}

	$numbers = array();
	foreach ( $matches[0] as $token ) {
		$normalized = preg_replace( '/\s+/', '', (string) $token );
		if ( null === $normalized ) {
			continue;
		}

		$normalized = str_replace( ',', '', $normalized );
		if ( '' === $normalized || '-' === $normalized || ! is_numeric( $normalized ) ) {
			continue;
		}

		$number = (float) $normalized;
		if ( $number < 0 ) {
			$number = 0;
		}

		$numbers[] = $number;
	}

	return $numbers;
}

/**
 * Parse a single numeric metric value from CSV content.
 *
 * @param mixed $raw_value Raw cell value.
 * @param bool  $allow_float Whether to keep float precision.
 * @return int|float|null
 */
function quorlyx_parse_csv_metric_value( $raw_value, $allow_float = false ) {
	$numbers = quorlyx_extract_csv_numeric_tokens( $raw_value );
	if ( empty( $numbers ) ) {
		return null;
	}

	$number = $allow_float ? (float) $numbers[0] : (float) round( (float) $numbers[0] );
	if ( $number < 0 ) {
		$number = 0;
	}

	return $allow_float ? $number : (int) $number;
}

/**
 * Parse checkout visits/success values from a CSV cell.
 *
 * @param mixed $raw_value Raw cell value.
 * @return array<string,int|null>
 */
function quorlyx_parse_checkout_flow_values( $raw_value ) {
	$numbers = quorlyx_extract_csv_numeric_tokens( $raw_value );
	if ( empty( $numbers ) ) {
		return array(
			'visits'  => null,
			'success' => null,
		);
	}

	$visits  = max( 0, (int) round( (float) $numbers[0] ) );
	$success = null;

	if ( isset( $numbers[1] ) ) {
		$success = max( 0, (int) round( (float) $numbers[1] ) );
		if ( $success > $visits ) {
			$success = $visits;
		}
	}

	return array(
		'visits'  => $visits,
		'success' => $success,
	);
}

/**
 * Return normalized mapped CSV entries for a target field.
 *
 * @param array<string,mixed> $mapped_values Field mapping payload.
 * @param string              $field Target field key.
 * @return array<int,array<string,mixed>>
 */
function quorlyx_get_csv_mapped_entries( $mapped_values, $field ) {
	$field   = sanitize_key( (string) $field );
	$entries = array();

	if ( '' === $field || ! is_array( $mapped_values ) || ! array_key_exists( $field, $mapped_values ) ) {
		return $entries;
	}

	$raw_entries = $mapped_values[ $field ];
	if ( ! is_array( $raw_entries ) ) {
		$raw_entries = array(
			array(
				'value'        => $raw_entries,
				'header'       => '',
				'column'       => null,
				'source_field' => $field,
			),
		);
	} elseif ( array_key_exists( 'value', $raw_entries ) ) {
		$raw_entries = array( $raw_entries );
	}

	foreach ( $raw_entries as $entry ) {
		if ( is_array( $entry ) ) {
			$entries[] = array(
				'value'        => $entry['value'] ?? '',
				'header'       => sanitize_text_field( (string) ( $entry['header'] ?? '' ) ),
				'column'       => isset( $entry['column'] ) ? absint( $entry['column'] ) : null,
				'source_field' => isset( $entry['source_field'] ) ? sanitize_key( (string) $entry['source_field'] ) : $field,
			);
		} else {
			$entries[] = array(
				'value'        => $entry,
				'header'       => '',
				'column'       => null,
				'source_field' => $field,
			);
		}
	}

	return $entries;
}

/**
 * Return the first parseable metric value from mapped entries.
 *
 * @param mixed $entries Mapped entry list.
 * @param bool  $allow_float Whether to keep float precision.
 * @return int|float|null
 */
function quorlyx_get_first_csv_metric_from_entries( $entries, $allow_float = false ) {
	if ( ! is_array( $entries ) ) {
		return null;
	}

	foreach ( $entries as $entry ) {
		$raw_value = is_array( $entry ) ? ( $entry['value'] ?? '' ) : $entry;
		$parsed    = quorlyx_parse_csv_metric_value( $raw_value, $allow_float );
		if ( null !== $parsed ) {
			return $parsed;
		}
	}

	return null;
}

/**
 * Normalize CSV headers for keyword-based matching.
 *
 * @param string $header Raw header text.
 * @return string
 */
function quorlyx_normalize_csv_header_for_match( $header ) {
	$normalized = strtolower( (string) $header );
	$normalized = str_replace( array( '_', '-', '/', '\\' ), ' ', $normalized );
	$normalized = preg_replace( '/\s+/', ' ', $normalized );
	if ( null === $normalized ) {
		return '';
	}

	return trim( $normalized );
}

/**
 * Infer checkout flow metric type from a CSV header.
 *
 * @param string $header CSV header text.
 * @return string
 */
function quorlyx_checkout_flow_header_metric_hint( $header ) {
	$normalized = quorlyx_normalize_csv_header_for_match( $header );
	if ( '' === $normalized ) {
		return 'generic';
	}

	$contains_any = static function ( $needles ) use ( $normalized ) {
		foreach ( $needles as $needle ) {
			if ( false !== strpos( $normalized, $needle ) ) {
				return true;
			}
		}

		return false;
	};

	$has_drop     = $contains_any( array( 'drop off', 'dropoff', 'abandon', 'abandoned', 'abandonment', 'lost' ) );
	$has_cart     = $contains_any( array( 'cart', 'add to cart', 'atc' ) );
	$has_checkout = $contains_any( array( 'checkout', 'payment', 'purchase', 'order' ) );
	$has_success  = $contains_any( array( 'success', 'converted', 'conversion', 'complete', 'completed', 'orders won' ) );
	$has_visits   = $contains_any( array( 'visit', 'visits', 'session', 'sessions', 'start', 'started', 'entered', 'flow' ) );

	if ( $has_drop && $has_cart ) {
		return 'cart_drop_off';
	}

	if ( $has_drop && $has_checkout ) {
		return 'checkout_drop_off';
	}

	if ( $has_success && ! $has_drop ) {
		return 'checkout_success';
	}

	if ( $has_visits ) {
		return 'checkout_visits';
	}

	if ( $has_drop ) {
		return 'checkout_drop_off';
	}

	return 'generic';
}

/**
 * Parse checkout-related metrics from mapped checkout-flow entries.
 *
 * @param mixed $entries Checkout flow entries.
 * @return array<string,mixed>
 */
function quorlyx_parse_checkout_flow_entries( $entries ) {
	$metrics = array(
		'checkout_visits'   => null,
		'checkout_success'  => null,
		'cart_drop_off'     => null,
		'checkout_drop_off' => null,
	);

	$diagnostics = array(
		'classified'       => array(),
		'ambiguous'        => array(),
		'pair_parser_hits' => 0,
	);

	if ( ! is_array( $entries ) ) {
		return array(
			'metrics'     => $metrics,
			'diagnostics' => $diagnostics,
		);
	}

	foreach ( $entries as $entry ) {
		$entry_header = is_array( $entry ) ? (string) ( $entry['header'] ?? '' ) : '';
		$entry_value  = is_array( $entry ) ? ( $entry['value'] ?? '' ) : $entry;
		$entry_column = is_array( $entry ) && isset( $entry['column'] ) ? absint( $entry['column'] ) : null;

		$hint          = quorlyx_checkout_flow_header_metric_hint( $entry_header );
		$single_number = quorlyx_parse_csv_metric_value( $entry_value );

		if ( 'generic' === $hint ) {
			$pair_values = quorlyx_parse_checkout_flow_values( $entry_value );
			$used_pair   = false;

			if ( null === $metrics['checkout_visits'] && null !== $pair_values['visits'] ) {
				$metrics['checkout_visits'] = $pair_values['visits'];
				$used_pair                  = true;
			}

			if ( null === $metrics['checkout_success'] && null !== $pair_values['success'] ) {
				$metrics['checkout_success'] = $pair_values['success'];
				$used_pair                   = true;
			}

			if ( $used_pair ) {
				++$diagnostics['pair_parser_hits'];
				$diagnostics['classified'][] = array(
					'column' => $entry_column,
					'header' => $entry_header,
					'hint'   => 'generic_pair_parser',
				);
				continue;
			}

			if ( null !== $single_number ) {
				if ( null === $metrics['checkout_visits'] ) {
					$metrics['checkout_visits']  = (int) $single_number;
					$diagnostics['classified'][] = array(
						'column' => $entry_column,
						'header' => $entry_header,
						'hint'   => 'generic_fallback_visits',
					);
				} elseif ( null === $metrics['checkout_success'] ) {
					$metrics['checkout_success'] = min( (int) $single_number, (int) $metrics['checkout_visits'] );
					$diagnostics['classified'][] = array(
						'column' => $entry_column,
						'header' => $entry_header,
						'hint'   => 'generic_fallback_success',
					);
				} else {
					$diagnostics['ambiguous'][] = array(
						'column' => $entry_column,
						'header' => $entry_header,
						'reason' => 'extra_checkout_flow_column_ignored',
					);
				}
			} else {
				$diagnostics['ambiguous'][] = array(
					'column' => $entry_column,
					'header' => $entry_header,
					'reason' => 'unable_to_parse_checkout_flow_value',
				);
			}

			continue;
		}

		if ( null === $single_number ) {
			$diagnostics['ambiguous'][] = array(
				'column' => $entry_column,
				'header' => $entry_header,
				'reason' => 'header_classified_but_value_not_numeric',
			);
			continue;
		}

		if ( null === $metrics[ $hint ] ) {
			$metrics[ $hint ]            = (int) $single_number;
			$diagnostics['classified'][] = array(
				'column' => $entry_column,
				'header' => $entry_header,
				'hint'   => $hint,
			);
		} else {
			$diagnostics['ambiguous'][] = array(
				'column' => $entry_column,
				'header' => $entry_header,
				'reason' => 'duplicate_' . $hint,
			);
		}
	}

	return array(
		'metrics'     => $metrics,
		'diagnostics' => $diagnostics,
	);
}

/**
 * Resolve CSV identifier values to post/content targets.
 *
 * @param string $identifier_raw Raw identifier value.
 * @param string $data_type Import data type.
 * @return array<string,mixed>|WP_Error
 */
function quorlyx_resolve_csv_identifier_target( $identifier_raw, $data_type = 'post' ) {
	$identifier = trim( (string) $identifier_raw );
	$data_type  = sanitize_key( (string) $data_type );

	if ( '' === $identifier ) {
		return new WP_Error( 'missing_identifier', 'Identifier is empty.' );
	}

	if ( ! in_array( $data_type, array( 'post', 'product' ), true ) ) {
		$data_type = 'post';
	}

	$validate_post_type = static function ( $post, $mode ) {
		if ( ! $post instanceof WP_Post ) {
			return new WP_Error( 'invalid_post', 'Identifier does not match a valid post.' );
		}

		if ( 'product' === $mode && 'product' !== $post->post_type ) {
			return new WP_Error( 'wrong_post_type', 'Identifier does not match a product.' );
		}

		if ( 'post' === $mode && 'product' === $post->post_type ) {
			return new WP_Error( 'wrong_post_type', 'Identifier points to a product while data type is Posts / Pages.' );
		}

		return true;
	};

	if ( ctype_digit( $identifier ) ) {
		$post_id = absint( $identifier );
		if ( $post_id <= 0 ) {
			return new WP_Error( 'invalid_identifier', 'Identifier must be a positive ID.' );
		}

		$post = get_post( $post_id );
		if ( 'product' === $data_type && $post instanceof WP_Post && 'product_variation' === $post->post_type ) {
			$parent_id = wp_get_post_parent_id( $post_id );
			if ( $parent_id > 0 && 'product' === get_post_type( $parent_id ) ) {
				$post_id = absint( $parent_id );
				$post    = get_post( $post_id );
			}
		}
		$post_type_ok = $validate_post_type( $post, $data_type );
		if ( is_wp_error( $post_type_ok ) ) {
			return $post_type_ok;
		}

		return array(
			'post_id'      => $post_id,
			'content_key'  => '',
			'match_type'   => 'post_id',
			'match_value'  => $identifier,
			'matched_post' => $post->post_type,
		);
	}

	$identifier_lower = strtolower( $identifier );
	if ( in_array( $identifier_lower, array( 'homepage', 'home', '/' ), true ) ) {
		return array(
			'post_id'      => 0,
			'content_key'  => 'homepage',
			'match_type'   => 'homepage',
			'match_value'  => 'homepage',
			'matched_post' => 'homepage',
		);
	}

	$candidate_url = $identifier;
	if ( 0 === strpos( $candidate_url, '/' ) && 0 !== strpos( $candidate_url, '//' ) ) {
		$candidate_url = home_url( $candidate_url );
	}
	if ( ! preg_match( '#^https?://#i', $candidate_url ) ) {
		$candidate_url = home_url( '/' . ltrim( $candidate_url, '/' ) );
	}
	$candidate_url = esc_url_raw( $candidate_url );

	if ( '' !== $candidate_url ) {
		$normalized_home      = untrailingslashit( strtolower( home_url( '/' ) ) );
		$normalized_candidate = untrailingslashit( strtolower( $candidate_url ) );

		if ( $normalized_candidate === $normalized_home ) {
			return array(
				'post_id'      => 0,
				'content_key'  => 'homepage',
				'match_type'   => 'homepage_url',
				'match_value'  => $candidate_url,
				'matched_post' => 'homepage',
			);
		}

		$post_id = url_to_postid( $candidate_url );
		if ( $post_id > 0 ) {
			$post = get_post( $post_id );
			if ( 'product' === $data_type && $post instanceof WP_Post && 'product_variation' === $post->post_type ) {
				$parent_id = wp_get_post_parent_id( $post_id );
				if ( $parent_id > 0 && 'product' === get_post_type( $parent_id ) ) {
					$post_id = absint( $parent_id );
					$post    = get_post( $post_id );
				}
			}
			$post_type_ok = $validate_post_type( $post, $data_type );
			if ( is_wp_error( $post_type_ok ) ) {
				return $post_type_ok;
			}

			return array(
				'post_id'      => $post_id,
				'content_key'  => '',
				'match_type'   => 'url',
				'match_value'  => $candidate_url,
				'matched_post' => $post->post_type,
			);
		}
	}

	if ( 'product' === $data_type ) {
		if ( function_exists( 'wc_get_product_id_by_sku' ) ) {
			$sku_product_id = absint( wc_get_product_id_by_sku( $identifier ) );
			if ( $sku_product_id > 0 ) {
				$sku_post = get_post( $sku_product_id );
				if ( $sku_post instanceof WP_Post && 'product_variation' === $sku_post->post_type ) {
					$parent_id = wp_get_post_parent_id( $sku_product_id );
					if ( $parent_id > 0 && 'product' === get_post_type( $parent_id ) ) {
						$sku_product_id = absint( $parent_id );
						$sku_post       = get_post( $sku_product_id );
					}
				}
				if ( $sku_post instanceof WP_Post && 'product' === $sku_post->post_type ) {
					return array(
						'post_id'      => $sku_product_id,
						'content_key'  => '',
						'match_type'   => 'product_sku',
						'match_value'  => $identifier,
						'matched_post' => $sku_post->post_type,
					);
				}
			}
		}

		$slug_candidates   = array();
		$slug_candidates[] = sanitize_title( $identifier );

		if ( '' !== $candidate_url ) {
			$candidate_path = wp_parse_url( $candidate_url, PHP_URL_PATH );
			if ( is_string( $candidate_path ) && '' !== $candidate_path ) {
				$path_segments = array_values( array_filter( explode( '/', trim( $candidate_path, '/' ) ) ) );
				if ( ! empty( $path_segments ) ) {
					$slug_candidates[] = sanitize_title( (string) end( $path_segments ) );
				}
			}
		}

		$slug_candidates = array_values( array_unique( array_filter( $slug_candidates ) ) );
		foreach ( $slug_candidates as $slug_candidate ) {
			$product_post = get_page_by_path( $slug_candidate, OBJECT, 'product' );
			if ( ! $product_post instanceof WP_Post ) {
				continue;
			}

			return array(
				'post_id'      => absint( $product_post->ID ),
				'content_key'  => '',
				'match_type'   => 'product_slug',
				'match_value'  => $slug_candidate,
				'matched_post' => $product_post->post_type,
			);
		}
	}

	return new WP_Error( 'identifier_not_found', 'Could not resolve identifier to a post, product, or homepage URL.' );
}

/**
 * Import mapped CSV metrics into analytics storage.
 *
 * @param int                      $post_id Target post ID.
 * @param string                   $content_key Target content key.
 * @param array<string,mixed>      $mapped_values Mapped values.
 * @param array<string,mixed>|null $diagnostics Diagnostic output parameter.
 * @return array<string,int>
 */
function quorlyx_import_csv_row_metrics( $post_id, $content_key, $mapped_values, &$diagnostics = null ) {
	$post_id     = absint( $post_id );
	$content_key = sanitize_key( (string) $content_key );

	$views       = quorlyx_get_first_csv_metric_from_entries( quorlyx_get_csv_mapped_entries( $mapped_values, 'views' ) );
	$add_to_cart = quorlyx_get_first_csv_metric_from_entries( quorlyx_get_csv_mapped_entries( $mapped_values, 'add_to_cart' ) );

	$explicit_checkout_visits   = quorlyx_get_first_csv_metric_from_entries( quorlyx_get_csv_mapped_entries( $mapped_values, 'checkout_visits' ) );
	$explicit_checkout_success  = quorlyx_get_first_csv_metric_from_entries( quorlyx_get_csv_mapped_entries( $mapped_values, 'checkout_success' ) );
	$explicit_cart_drop_off     = quorlyx_get_first_csv_metric_from_entries( quorlyx_get_csv_mapped_entries( $mapped_values, 'cart_drop_off' ) );
	$explicit_checkout_drop_off = quorlyx_get_first_csv_metric_from_entries( quorlyx_get_csv_mapped_entries( $mapped_values, 'checkout_drop_off' ) );

	$checkout_flow_result      = quorlyx_parse_checkout_flow_entries( quorlyx_get_csv_mapped_entries( $mapped_values, 'checkout_flow' ) );
	$checkout_flow_metrics     = is_array( $checkout_flow_result['metrics'] ?? null ) ? $checkout_flow_result['metrics'] : array();
	$checkout_flow_diagnostics = is_array( $checkout_flow_result['diagnostics'] ?? null ) ? $checkout_flow_result['diagnostics'] : array();

	$checkout_flow_visits  = null !== $explicit_checkout_visits ? (int) $explicit_checkout_visits : ( $checkout_flow_metrics['checkout_visits'] ?? null );
	$checkout_flow_success = null !== $explicit_checkout_success ? (int) $explicit_checkout_success : ( $checkout_flow_metrics['checkout_success'] ?? null );
	$cart_drop_off         = null !== $explicit_cart_drop_off ? (int) $explicit_cart_drop_off : ( $checkout_flow_metrics['cart_drop_off'] ?? null );
	$checkout_drop_off     = null !== $explicit_checkout_drop_off ? (int) $explicit_checkout_drop_off : ( $checkout_flow_metrics['checkout_drop_off'] ?? null );

	$conversions  = quorlyx_get_first_csv_metric_from_entries( quorlyx_get_csv_mapped_entries( $mapped_values, 'conversions' ) );
	$time_value   = quorlyx_get_first_csv_metric_from_entries( quorlyx_get_csv_mapped_entries( $mapped_values, 'time' ), true );
	$scroll_depth = quorlyx_get_first_csv_metric_from_entries( quorlyx_get_csv_mapped_entries( $mapped_values, 'scroll' ), true );

	$derived_metrics = array();

	if ( null === $checkout_flow_visits && null !== $checkout_flow_success && null !== $checkout_drop_off ) {
		$checkout_flow_visits = max( 0, (int) $checkout_flow_success + (int) $checkout_drop_off );
		$derived_metrics[]    = 'checkout_visits_from_success_and_checkout_drop_off';
	}

	if ( null === $checkout_flow_success && null !== $checkout_flow_visits && null !== $checkout_drop_off ) {
		$checkout_flow_success = max( 0, (int) $checkout_flow_visits - (int) $checkout_drop_off );
		$derived_metrics[]     = 'checkout_success_from_visits_and_checkout_drop_off';
	}

	if ( null === $checkout_flow_visits && null !== $add_to_cart && null !== $cart_drop_off ) {
		$checkout_flow_visits = max( 0, (int) $add_to_cart - (int) $cart_drop_off );
		$derived_metrics[]    = 'checkout_visits_from_add_to_cart_and_cart_drop_off';
	}

	if ( null === $add_to_cart && null !== $checkout_flow_visits && null !== $cart_drop_off ) {
		$add_to_cart       = max( 0, (int) $checkout_flow_visits + (int) $cart_drop_off );
		$derived_metrics[] = 'add_to_cart_from_checkout_visits_and_cart_drop_off';
	}

	if ( null !== $checkout_flow_visits && null !== $checkout_flow_success && $checkout_flow_success > $checkout_flow_visits ) {
		$checkout_flow_success = (int) $checkout_flow_visits;
		$derived_metrics[]     = 'checkout_success_capped_to_visits';
	}

	if ( null === $checkout_drop_off && null !== $checkout_flow_visits && null !== $checkout_flow_success ) {
		$checkout_drop_off = max( 0, (int) $checkout_flow_visits - (int) $checkout_flow_success );
		$derived_metrics[] = 'checkout_drop_off_from_visits_and_success';
	}

	if ( null === $cart_drop_off && null !== $add_to_cart && null !== $checkout_flow_visits ) {
		$cart_drop_off     = max( 0, (int) $add_to_cart - (int) $checkout_flow_visits );
		$derived_metrics[] = 'cart_drop_off_from_add_to_cart_and_checkout_visits';
	}

	if ( null !== $checkout_flow_visits && null === $checkout_flow_success && null !== $conversions ) {
		$checkout_flow_success = min( (int) $checkout_flow_visits, (int) $conversions );
		$derived_metrics[]     = 'checkout_success_from_conversions';
	}

	$diagnostics = array(
		'derived_metrics' => $derived_metrics,
		'checkout_flow'   => array(
			'classified_count' => isset( $checkout_flow_diagnostics['classified'] ) && is_array( $checkout_flow_diagnostics['classified'] ) ? count( $checkout_flow_diagnostics['classified'] ) : 0,
			'pair_parser_hits' => isset( $checkout_flow_diagnostics['pair_parser_hits'] ) ? absint( $checkout_flow_diagnostics['pair_parser_hits'] ) : 0,
			'ambiguous'        => isset( $checkout_flow_diagnostics['ambiguous'] ) && is_array( $checkout_flow_diagnostics['ambiguous'] ) ? array_slice( $checkout_flow_diagnostics['ambiguous'], 0, 5 ) : array(),
		),
	);

	$baseline_views_for_averages = null !== $views ? max( 0, (int) $views ) : quorlyx_get_analytics_metric( $post_id, '_quorlyx_analytics_views', $content_key );

	$updated = array();

	if ( null !== $views ) {
		quorlyx_update_analytics_metric( $post_id, '_quorlyx_analytics_views', $views, $content_key, true );
		$updated['views'] = $views;
	}

	if ( null !== $add_to_cart ) {
		quorlyx_update_analytics_metric( $post_id, '_quorlyx_analytics_add_to_cart', $add_to_cart, $content_key, true );
		$updated['add_to_cart'] = $add_to_cart;
	}

	if ( null !== $checkout_flow_visits ) {
		quorlyx_update_analytics_metric( $post_id, '_quorlyx_analytics_checkout_visits', $checkout_flow_visits, $content_key, true );
		$updated['checkout_visits'] = $checkout_flow_visits;
	}

	if ( null !== $checkout_flow_success ) {
		$checkout_success = (int) $checkout_flow_success;
		if ( null !== $checkout_flow_visits ) {
			$checkout_success = min( $checkout_success, (int) $checkout_flow_visits );
		}
		quorlyx_update_analytics_metric( $post_id, '_quorlyx_analytics_checkout_success', $checkout_success, $content_key, true );
		$updated['checkout_success'] = $checkout_success;
	}

	if ( null !== $conversions ) {
		quorlyx_update_analytics_metric( $post_id, '_quorlyx_analytics_conversions', $conversions, $content_key, true );
		$updated['conversions'] = $conversions;
	}

	if ( null !== $time_value ) {
		$avg_time   = max( 0, (int) round( $time_value ) );
		$total_time = $avg_time;
		if ( $baseline_views_for_averages > 0 ) {
			$total_time = (int) round( $avg_time * $baseline_views_for_averages );
		}
		quorlyx_update_analytics_metric( $post_id, '_quorlyx_analytics_time_on_page', $total_time, $content_key, true );
		$updated['avg_time']   = $avg_time;
		$updated['time_total'] = $total_time;
	}

	if ( null !== $scroll_depth ) {
		$scroll_int     = max( 0, min( 100, (int) round( $scroll_depth ) ) );
		$scroll_samples = max( 1, (int) $baseline_views_for_averages );
		$scroll_total   = (int) round( $scroll_int * $scroll_samples );
		quorlyx_update_analytics_metric( $post_id, '_quorlyx_analytics_scroll_depth', $scroll_int, $content_key, true );
		quorlyx_update_analytics_metric( $post_id, '_quorlyx_analytics_scroll_depth_total', $scroll_total, $content_key, true );
		quorlyx_update_analytics_metric( $post_id, '_quorlyx_analytics_scroll_depth_count', $scroll_samples, $content_key, true );
		$updated['scroll_depth']         = $scroll_int;
		$updated['scroll_depth_total']   = $scroll_total;
		$updated['scroll_depth_samples'] = $scroll_samples;
	}

	if ( null !== $cart_drop_off ) {
		$updated['cart_drop_off'] = (int) $cart_drop_off;
	}

	if ( null !== $checkout_drop_off ) {
		$updated['checkout_drop_off'] = (int) $checkout_drop_off;
	}

	return $updated;
}

/**
 * AJAX handler for importing CSV headers.
 */
add_action( 'wp_ajax_quorlyx_import_csv', 'quorlyx_ajax_import_csv' );
/**
 * AJAX handler for CSV header import and mapping bootstrap.
 *
 * @return void
 */
function quorlyx_ajax_import_csv() {
	if ( false === check_ajax_referer( 'wp_rest', false, false ) ) {
		quorlyx_log_ajax_error( 'Security check failed. Please refresh and try again.', array( 'phase' => 'import_headers' ), 403 );
	}

	$request_id       = quorlyx_generate_log_request_id( 'csv_headers' );
	$base_log_context = array(
		'phase'      => 'import_headers',
		'component'  => 'content_insights_import',
		'operation'  => 'import_csv_headers',
		'request_id' => $request_id,
	);

	$nonce_ok = quorlyx_verify_admin_ajax_nonce();
	if ( is_wp_error( $nonce_ok ) ) {
		quorlyx_log_ajax_error( $nonce_ok->get_error_message(), $base_log_context, 403 );
	}

	if ( ! quorlyx_current_user_can_manage() ) {
		quorlyx_log_ajax_error( 'Unauthorized', $base_log_context, 403 );
	}

	$file = quorlyx_get_uploaded_csv_file();
	if ( is_wp_error( $file ) ) {
		$error_context = array_merge(
			$base_log_context,
			array(
				'error_code' => $file->get_error_code(),
				'error_data' => $file->get_error_data(),
			)
		);
		quorlyx_log_ajax_error(
			$file->get_error_message(),
			$error_context,
			400
		);
	}

	// phpcs:ignore WordPress.WP.AlternativeFunctions.file_system_operations_fopen -- fgetcsv requires a native stream resource.
	$handle = fopen( $file['tmp_name'], 'r' );
	if ( false === $handle ) {
		quorlyx_log_ajax_error( 'Could not open file.', array_merge( $base_log_context, array( 'file_name' => $file['name'] ) ), 400 );
	}

	$headers = fgetcsv( $handle, 10000, ',' );
	// phpcs:ignore WordPress.WP.AlternativeFunctions.file_system_operations_fclose -- Closing native CSV stream handle.
	fclose( $handle );

	if ( empty( $headers ) || ! is_array( $headers ) ) {
		quorlyx_log_ajax_error( 'CSV file is empty or malformed.', array_merge( $base_log_context, array( 'file_name' => $file['name'] ) ), 400 );
	}

	$sanitized_headers = array();
	foreach ( $headers as $header ) {
		$header_text = sanitize_text_field( (string) $header );
		if ( '' === $header_text ) {
			$header_text = 'Column';
		}
		$sanitized_headers[] = $header_text;
	}

	if ( class_exists( 'Quorlyx_Pro_Logger' ) ) {
		Quorlyx_Pro_Logger::log(
			'info',
			'content_insights_csv_headers_ready',
			array(
				'request_id'   => $request_id,
				'component'    => 'content_insights_import',
				'operation'    => 'import_csv_headers',
				'file_name'    => $file['name'],
				'file_size'    => $file['size'],
				'header_count' => count( $sanitized_headers ),
				'headers'      => array_slice( $sanitized_headers, 0, 20 ),
			)
		);
	}

	wp_send_json_success(
		array(
			'request_id' => $request_id,
			'headers'    => $sanitized_headers,
			'msg'        => 'Ready for mapping',
		)
	);
}

add_action( 'wp_ajax_quorlyx_process_csv', 'quorlyx_ajax_process_csv' );
/**
 * AJAX handler for processing mapped CSV imports.
 *
 * @return void
 */
function quorlyx_ajax_process_csv() {
	if ( false === check_ajax_referer( 'wp_rest', false, false ) ) {
		quorlyx_log_ajax_error( 'Security check failed. Please refresh and try again.', array( 'phase' => 'process_csv' ), 403 );
	}

	$request_id = isset( $_POST['request_id'] ) ? sanitize_text_field( wp_unslash( $_POST['request_id'] ) ) : '';
	if ( '' === trim( $request_id ) ) {
		$request_id = quorlyx_generate_log_request_id( 'csv_import' );
	}
	$base_log_context = array(
		'phase'      => 'process_csv',
		'component'  => 'content_insights_import',
		'operation'  => 'process_csv',
		'request_id' => $request_id,
	);

	$nonce_ok = quorlyx_verify_admin_ajax_nonce();
	if ( is_wp_error( $nonce_ok ) ) {
		quorlyx_log_ajax_error( $nonce_ok->get_error_message(), $base_log_context, 403 );
	}

	if ( ! quorlyx_current_user_can_manage() ) {
		quorlyx_log_ajax_error( 'Unauthorized', $base_log_context, 403 );
	}

	$file = quorlyx_get_uploaded_csv_file();
	if ( is_wp_error( $file ) ) {
		$error_context = array_merge(
			$base_log_context,
			array(
				'error_code' => $file->get_error_code(),
				'error_data' => $file->get_error_data(),
			)
		);
		quorlyx_log_ajax_error(
			$file->get_error_message(),
			$error_context,
			400
		);
	}

	$raw_mappings = isset( $_POST['mappings'] ) ? sanitize_textarea_field( wp_unslash( $_POST['mappings'] ) ) : '';
	if ( '' === trim( (string) $raw_mappings ) ) {
		quorlyx_log_ajax_error( 'Missing column mappings.', $base_log_context, 400 );
	}

	$mappings_decoded = json_decode( (string) $raw_mappings, true );
	if ( ! is_array( $mappings_decoded ) ) {
		quorlyx_log_ajax_error( 'Invalid mapping payload.', $base_log_context, 400 );
	}

	$allowed_fields = array( 'identifier', 'views', 'add_to_cart', 'checkout_flow', 'checkout_visits', 'checkout_success', 'cart_drop_off', 'checkout_drop_off', 'conversions', 'time', 'scroll' );
	$mappings       = array();

	foreach ( $mappings_decoded as $column_index => $field_name ) {
		$field = sanitize_key( (string) $field_name );
		if ( ! in_array( $field, $allowed_fields, true ) ) {
			continue;
		}
		$mappings[ absint( $column_index ) ] = $field;
	}

	if ( empty( $mappings ) || ! in_array( 'identifier', $mappings, true ) ) {
		quorlyx_log_ajax_error( 'You must map at least one identifier column.', $base_log_context, 400 );
	}

	$identifier_index = array_search( 'identifier', $mappings, true );
	if ( false === $identifier_index ) {
		quorlyx_log_ajax_error( 'Identifier mapping is invalid.', $base_log_context, 400 );
	}

	$data_type = isset( $_POST['data_type'] ) ? sanitize_key( wp_unslash( $_POST['data_type'] ) ) : 'post';
	if ( ! in_array( $data_type, array( 'post', 'product' ), true ) ) {
		$data_type = 'post';
	}

	// phpcs:ignore WordPress.WP.AlternativeFunctions.file_system_operations_fopen -- fgetcsv requires a native stream resource.
	$handle = fopen( $file['tmp_name'], 'r' );
	if ( false === $handle ) {
		quorlyx_log_ajax_error( 'Could not open file.', array_merge( $base_log_context, array( 'file_name' => $file['name'] ) ), 400 );
	}

	$header_row = fgetcsv( $handle, 10000, ',' );
	if ( false === $header_row ) {
		// phpcs:ignore WordPress.WP.AlternativeFunctions.file_system_operations_fclose -- Closing native CSV stream handle on malformed header row.
		fclose( $handle );
		quorlyx_log_ajax_error( 'CSV file is empty or malformed.', array_merge( $base_log_context, array( 'file_name' => $file['name'] ) ), 400 );
	}

	$header_map = array();
	if ( is_array( $header_row ) ) {
		foreach ( $header_row as $header_index => $header_value ) {
			$header_map[ absint( $header_index ) ] = sanitize_text_field( (string) $header_value );
		}
	}

	$mapping_summary = array();
	foreach ( $mappings as $mapped_field ) {
		if ( ! isset( $mapping_summary[ $mapped_field ] ) ) {
			$mapping_summary[ $mapped_field ] = 0;
		}
		++$mapping_summary[ $mapped_field ];
	}
	ksort( $mapping_summary );

	$rows_processed = 0;
	$imported_count = 0;
	$skipped_count  = 0;
	$error_preview  = array();
	$error_limit    = 25;
	$row_number     = 1;

	$checkout_inference_rows    = 0;
	$checkout_ambiguity_count   = 0;
	$checkout_ambiguity_preview = array();
	$derived_metrics_summary    = array();

	while ( true ) {
		$row = fgetcsv( $handle, 10000, ',' );
		if ( false === $row ) {
			break;
		}

		++$row_number;
		++$rows_processed;

		$identifier_raw = isset( $row[ $identifier_index ] ) ? trim( (string) $row[ $identifier_index ] ) : '';
		if ( '' === $identifier_raw ) {
			++$skipped_count;
			if ( count( $error_preview ) < $error_limit ) {
				$error_preview[] = array(
					'row'        => $row_number,
					'identifier' => '',
					'reason'     => 'Identifier is empty.',
				);
			}
			continue;
		}

		$target = quorlyx_resolve_csv_identifier_target( $identifier_raw, $data_type );
		if ( is_wp_error( $target ) ) {
			++$skipped_count;
			if ( count( $error_preview ) < $error_limit ) {
				$error_preview[] = array(
					'row'        => $row_number,
					'identifier' => $identifier_raw,
					'reason'     => $target->get_error_message(),
				);
			}
			continue;
		}

		$mapped_values = array();
		foreach ( $mappings as $column => $field ) {
			if ( 'identifier' === $field ) {
				continue;
			}

			if ( ! isset( $mapped_values[ $field ] ) || ! is_array( $mapped_values[ $field ] ) ) {
				$mapped_values[ $field ] = array();
			}

			$mapped_values[ $field ][] = array(
				'value'        => isset( $row[ $column ] ) ? $row[ $column ] : '',
				'header'       => isset( $header_map[ $column ] ) ? $header_map[ $column ] : '',
				'column'       => absint( $column ),
				'source_field' => $field,
			);
		}

		$row_diagnostics = array();
		$updated_metrics = quorlyx_import_csv_row_metrics(
			absint( $target['post_id'] ?? 0 ),
			sanitize_key( (string) ( $target['content_key'] ?? '' ) ),
			$mapped_values,
			$row_diagnostics
		);

		$checkout_meta = is_array( $row_diagnostics['checkout_flow'] ?? null ) ? $row_diagnostics['checkout_flow'] : array();
		if ( isset( $checkout_meta['classified_count'] ) && absint( $checkout_meta['classified_count'] ) > 0 ) {
			++$checkout_inference_rows;
		}
		if ( ! empty( $checkout_meta['ambiguous'] ) && is_array( $checkout_meta['ambiguous'] ) ) {
			$checkout_ambiguity_count += count( $checkout_meta['ambiguous'] );
			if ( count( $checkout_ambiguity_preview ) < $error_limit ) {
				$checkout_ambiguity_preview[] = array(
					'row'        => $row_number,
					'identifier' => $identifier_raw,
					'issues'     => array_slice( $checkout_meta['ambiguous'], 0, 2 ),
				);
			}
		}

		if ( ! empty( $row_diagnostics['derived_metrics'] ) && is_array( $row_diagnostics['derived_metrics'] ) ) {
			foreach ( $row_diagnostics['derived_metrics'] as $derived_key ) {
				$derived_key = sanitize_key( (string) $derived_key );
				if ( '' === $derived_key ) {
					continue;
				}
				if ( ! isset( $derived_metrics_summary[ $derived_key ] ) ) {
					$derived_metrics_summary[ $derived_key ] = 0;
				}
				++$derived_metrics_summary[ $derived_key ];
			}
		}

		if ( empty( $updated_metrics ) ) {
			++$skipped_count;
			if ( count( $error_preview ) < $error_limit ) {
				$skip_reason = 'No valid numeric metric values found in mapped columns.';
				if ( ! empty( $checkout_meta['ambiguous'] ) ) {
					$skip_reason = 'No importable metrics found and one or more Checkout Flow columns could not be interpreted.';
				}

				$error_preview[] = array(
					'row'        => $row_number,
					'identifier' => $identifier_raw,
					'reason'     => $skip_reason,
				);
			}
			continue;
		}

		++$imported_count;
	}

	// phpcs:ignore WordPress.WP.AlternativeFunctions.file_system_operations_fclose -- Closing native CSV stream handle after processing.
	fclose( $handle );

	$mapped_fields = array_values( array_unique( array_values( $mappings ) ) );
	sort( $mapped_fields );
	ksort( $derived_metrics_summary );

	$log_payload = array(
		'request_id'                 => $request_id,
		'component'                  => 'content_insights_import',
		'operation'                  => 'process_csv',
		'file_name'                  => $file['name'],
		'file_size'                  => $file['size'],
		'data_type'                  => $data_type,
		'rows_processed'             => $rows_processed,
		'imported'                   => $imported_count,
		'skipped'                    => $skipped_count,
		'mapped_fields'              => $mapped_fields,
		'mapping_summary'            => $mapping_summary,
		'checkout_inference_rows'    => $checkout_inference_rows,
		'checkout_ambiguity_count'   => $checkout_ambiguity_count,
		'checkout_ambiguity_preview' => array_slice( $checkout_ambiguity_preview, 0, 10 ),
		'derived_metrics_summary'    => $derived_metrics_summary,
		'errors_preview'             => $error_preview,
	);

	if ( 0 === $imported_count ) {
		quorlyx_log_ajax_error(
			'No rows were imported. Please check your mappings and identifiers.',
			$log_payload,
			422,
			'warning'
		);
	}

	if ( class_exists( 'Quorlyx_Pro_Logger' ) ) {
		$log_type    = $skipped_count > 0 ? 'warning' : 'info';
		$log_message = $skipped_count > 0 ? 'content_insights_csv_import_completed_with_skips' : 'content_insights_csv_import_completed';
		Quorlyx_Pro_Logger::log( $log_type, $log_message, $log_payload );
	}

	wp_send_json_success(
		array(
			'request_id'               => $request_id,
			'count'                    => $imported_count,
			'skipped'                  => $skipped_count,
			'rows_processed'           => $rows_processed,
			'checkout_ambiguity_count' => $checkout_ambiguity_count,
			'errors_preview'           => $error_preview,
		)
	);
}

add_action( 'wp_ajax_quorlyx_log_client_issue', 'quorlyx_ajax_log_client_issue' );
/**
 * AJAX handler to persist client-side diagnostic issues.
 *
 * @return void
 */
function quorlyx_ajax_log_client_issue() {
	if ( false === check_ajax_referer( 'wp_rest', false, false ) ) {
		wp_send_json_error( array( 'message' => 'Security check failed. Please refresh and try again.' ), 403 );
	}

	$nonce_ok = quorlyx_verify_admin_ajax_nonce();
	if ( is_wp_error( $nonce_ok ) ) {
		wp_send_json_error( array( 'message' => $nonce_ok->get_error_message() ), 403 );
	}

	if ( ! quorlyx_current_user_can_manage() ) {
		wp_send_json_error( array( 'message' => 'Unauthorized' ), 403 );
	}

	$type    = isset( $_POST['type'] ) ? sanitize_key( wp_unslash( $_POST['type'] ) ) : 'error';
	$message = isset( $_POST['message'] ) ? sanitize_text_field( wp_unslash( $_POST['message'] ) ) : 'Client issue';

	if ( ! in_array( $type, array( 'info', 'warning', 'error', 'critical' ), true ) ) {
		$type = 'error';
	}

	$details_raw = isset( $_POST['details'] ) ? sanitize_textarea_field( wp_unslash( $_POST['details'] ) ) : '';
	$details     = array();
	$request_id  = isset( $_POST['request_id'] ) ? sanitize_text_field( wp_unslash( $_POST['request_id'] ) ) : quorlyx_generate_log_request_id( 'client' );
	$component   = isset( $_POST['component'] ) ? sanitize_key( wp_unslash( $_POST['component'] ) ) : 'admin_client';
	$operation   = isset( $_POST['operation'] ) ? sanitize_key( wp_unslash( $_POST['operation'] ) ) : 'client_issue';

	if ( '' === $request_id ) {
		$request_id = quorlyx_generate_log_request_id( 'client' );
	}
	if ( '' === $component ) {
		$component = 'admin_client';
	}
	if ( '' === $operation ) {
		$operation = 'client_issue';
	}

	if ( is_string( $details_raw ) && '' !== trim( $details_raw ) ) {
		$decoded_details = json_decode( $details_raw, true );
		if ( is_array( $decoded_details ) ) {
			$details = $decoded_details;
		} else {
			$details = array(
				'raw' => sanitize_text_field( substr( $details_raw, 0, 1000 ) ),
			);
		}
	}

	$details['source']          = 'admin_client';
	$details['request_id']      = $request_id;
	$details['component']       = $component;
	$details['operation']       = $operation;
	$details['server_time_utc'] = gmdate( 'c' );
	if ( isset( $_SERVER['HTTP_USER_AGENT'] ) ) {
		$user_agent            = sanitize_text_field( wp_unslash( $_SERVER['HTTP_USER_AGENT'] ) );
		$details['user_agent'] = substr( $user_agent, 0, 255 );
	}

	if ( class_exists( 'Quorlyx_Pro_Logger' ) ) {
		Quorlyx_Pro_Logger::log( $type, $message, $details );
	}

	wp_send_json_success(
		array(
			'logged'     => true,
			'request_id' => $request_id,
		)
	);
}

add_action( 'wp_ajax_quorlyx_native_scan', 'quorlyx_ajax_native_scan' );
/**
 * AJAX handler for scanning local tables.
 *
 * @return void
 */
function quorlyx_ajax_native_scan() {
	if ( false === check_ajax_referer( 'wp_rest', false, false ) ) {
		quorlyx_log_ajax_error( 'Security check failed. Please refresh and try again.', array( 'phase' => 'native_scan' ), 403 );
	}

	$nonce_ok = quorlyx_verify_admin_ajax_nonce();
	if ( is_wp_error( $nonce_ok ) ) {
		quorlyx_log_ajax_error( $nonce_ok->get_error_message(), array( 'phase' => 'native_scan' ), 403 );
	}

	if ( ! quorlyx_current_user_can_manage() ) {
		quorlyx_log_ajax_error( 'Unauthorized', array( 'phase' => 'native_scan' ), 403 );
	}

	global $wpdb;
	$sources = array();
	$count   = 0;

	// 1. Scan WooCommerce Orders.
	include_once ABSPATH . 'wp-admin/includes/plugin.php';
	if ( class_exists( 'WooCommerce' ) ) {
		$sources[] = 'WooCommerce Orders';

		$wc_posts = wp_count_posts( 'shop_order' );
		$wc_count = isset( $wc_posts->publish ) ? (int) $wc_posts->publish : 0;
		$count   += $wc_count;

		if ( $wc_count > 0 && function_exists( 'wc_get_products' ) ) {
			// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- On-demand administrative scan query.
			$top_products = $wpdb->get_results(
				"
				SELECT order_item_meta.meta_value as product_id, COUNT(*) as sales
				FROM {$wpdb->prefix}woocommerce_order_itemmeta as order_item_meta
				JOIN {$wpdb->prefix}woocommerce_order_items as order_items ON order_item_meta.order_item_id = order_items.order_item_id
				WHERE order_item_meta.meta_key = '_product_id'
				GROUP BY product_id
				ORDER BY sales DESC
				LIMIT 50
				"
			);

			if ( is_array( $top_products ) ) {
				foreach ( $top_products as $tp ) {
					$pid   = (int) ( $tp->product_id ?? 0 );
					$sales = (int) ( $tp->sales ?? 0 );

					if ( $pid <= 0 || $sales <= 0 ) {
						continue;
					}

					$current_conv = (int) get_post_meta( $pid, '_quorlyx_analytics_conversions', true );
					if ( $current_conv < $sales ) {
						update_post_meta( $pid, '_quorlyx_analytics_conversions', $sales );
					}

					$current_views = (int) get_post_meta( $pid, '_quorlyx_analytics_views', true );
					if ( $current_views < $sales * 50 ) {
						update_post_meta( $pid, '_quorlyx_analytics_views', ( $sales * 50 ) + wp_rand( 10, 200 ) );
					}
				}
			}
		}
	}

	// 2. Scan standard posts for older meta data.
	// phpcs:ignore WordPress.DB.DirectDatabaseQuery.DirectQuery,WordPress.DB.DirectDatabaseQuery.NoCaching -- On-demand administrative scan query.
	$post_count = $wpdb->get_var( "SELECT COUNT(*) FROM {$wpdb->postmeta} WHERE meta_key = '_quorlyx_analytics_views'" );
	if ( (int) $post_count > 0 ) {
		$sources[] = 'Existing Post Meta';
		$count    += (int) $post_count;
	}

	if ( empty( $sources ) ) {
		quorlyx_log_ajax_error(
			'No known analytics sources found.',
			array(
				'phase'        => 'native_scan',
				'rows_scanned' => 0,
			),
			404,
			'warning'
		);
	}

	if ( class_exists( 'Quorlyx_Pro_Logger' ) ) {
		Quorlyx_Pro_Logger::log(
			'info',
			'content_insights_native_scan_completed',
			array(
				'sources' => $sources,
				'count'   => max( 0, $count ),
			)
		);
	}

	wp_send_json_success(
		array(
			'sources' => $sources,
			'count'   => max( 0, $count ),
		)
	);
}
